window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["he"]={"ICON-0001":{"nm":"טביעת רגל","de":"כתם אדמה בודד שנותר על רצפת העץ. מישהו פסע הלוך ושוב זמן רב, ולבסוף העז לעשות עוד צעד אחד קדימה. מה שטביעת הרגל חורטת אינו הזמן שחלף בהיסוס, אלא אותו רגע יחיד שבו הוחלט ללכת."},"ICON-0002":{"nm":"פנס","de":"כשהלהבה נוגעת בפתילה, החושך נסוג בשקט, סנטימטר אחר סנטימטר. בחום הקטן המחמם את קצות האצבעות, בני אדם מן העבר נהגו לכתוב את משאלותיהם ולשגר אותן לדרכן. הפנס אינו נדלק כדי להאיר, אלא כדי להיות לצדך."},"ICON-0003":{"nm":"סרט","de":"בקשר אחד נעטף הלב בעדינות. יד הנותן קושרת אותו כך שיהיה קל להתיר, ויד המקבל מבקשת להתיר אותו לאט. מה שהסרט קושר אינו את הקופסה, אלא את הפעימה הנרגשת רגע לפני המסירה."},"ICON-0004":{"nm":"תיבת דואר","de":"היא עומדת בפתח הסמטה, פיה האדום פעור לרווחה. גם בעידן שבו מכתבים בכתב יד הפכו נדירים, התיבה הקטנה הזאת ממתינה עד הסוף לבשורה של מישהו. כלי חביב שזוהר ביותר ברגע שהוא מתרוקן."},"ICON-0005":{"nm":"מיני-מפת האי הפרטי","de":"דף נייר אחד: כשהוא מקופל - נכנס לכיס, וכשהוא נפרש - הים ורכס ההרים שוכבים זה לצד זה. עבור מי שמגיע לראשונה, כל פינה היא הבטחה שטרם נפתחה. ברגע שהוא נפתח, גם אי קטן הופך לעולם רחב."},"ICON-0006":{"nm":"מיקרופון","de":"חצי הפעימה של עצירת נשימה רגע לפני הצליל הראשון. הידיעה שעיני הקהל ממתינות למילה אחת שלך גורמת לקצות האצבעות לרעוד. המיקרופון אינו מגביר את הקול, אלא מלווה את הרעד הזה עד הסוף."},"ICON-0007":{"nm":"שעון","de":"מחוג השניות אינו נח לרגע, אך איש אינו מזרז אותך. כמה לילות עד ההופעה, כמה דקות עד העלייה לבמה - על גבי חוגת השעון, הציפייה וההתרגשות מסתובבות באותה מהירות. להביט בזמן פירושו להרגיע את הלב."},"ICON-0008":{"nm":"מחברת","de":"החפץ עם רוב החללים הריקים ביותר. תנועות הריקוד, ההחלטות של שעות השחר, המילים שלעולם לא נשלחו - כולן נערמות כאן. ברגע שהיא נפתחת, האני של אתמול פונה בשקט אל האני של היום."},"ICON-0009":{"nm":"חותמת","de":"כשהיא טובלת בדיו אדום ונלחצת פעם אחת בתקיפות, ההבטחה נחרתת בבירור. סימן כבד יותר מכתב, ברור יותר ממילים. בסוף כל מסמך אנשים הפקידו את ליבם בחותמת הקטנה הזאת, במקום בשמם."},"ICON-0010":{"nm":"מעמד","de":"הוא משפיל את עצמו ככל האפשר כדי לתמוך במשהו אחר. במקום הנמוך ביותר, הוא נושא את המשא בשתיקה כדי שמה שמונח למעלה לא יתנדנד. גם בלי לזהור, כאן שוכנת האדיבות שמונעת קריסה."},"ICON-0011":{"nm":"בול","de":"ציור קטן שנהגו ללקק בפינתו האחת ולהדביקו בלחיצה חזקה. המחיר הכן ביותר שנקבע ללב הנשלח למרחקים. פיסת נוף מרובעת אחת אוחזת בידה של המכתב ולוקחת אותה עד מעבר לים."},"ICON-0012":{"nm":"סיכת דגל","de":"כשתוקעים אותה במפה, זה אומר: ”הגעתי עד הנה”. לא כיבוש אלא תיעוד, ועידוד למי שיבוא אחריך. סימן שדוחף בשתיקה את הגב קדימה - עוד צעד אחד, למראה הדגל הזה."},"ICON-0013":{"nm":"ענף","de":"ענף שהתכופף פעם אחת שוכח כיצד להישבר. בכל מקום שבו נכנע לרוח, מתהווה קשר עץ מוצק וקשה, והיער העתיק לוחש ברוח שהחוזק האמיתי נולד מסימני ההתמדה."},"ICON-0014":{"nm":"כפתור","de":"הוא נפתח ונסגר שוב ושוב, ואוסף את דש הצווארון. עיגול קטן אחד עוצר בשקט הן את הקור של שעות השחר והן את הביישנות שעולה לפתע. רק כשהוא נושר, מבינים כמה גדול היה מקומו."},"ICON-0015":{"nm":"מעטפה","de":"ברגע שפיה נחתם, היא הופכת סוף-סוף לסוד. רק המקבל יודע מה טמון בפנים. שכבת נייר אחת המונחת בין הלב לעולם - הדלת הדקה והחביבה מכולן."},"ICON-0016":{"nm":"קופסה","de":"פינותיה הישרות מאפשרות לה לחבק הכול בנדיבות. זיכרונות בעונת המעבר, מתנות בחגים, פריטים שונים ומשונים בשגרה. מתחת למכסה הסגור, היא תמיד מלאה ב”מאוחר יותר” של מישהו."},"ICON-0017":{"nm":"ידית","de":"בין דלת לאדם, היא הראשונה להושיט יד. רק כשמושכים אותה פעם אחת, הפנים והחוץ מתחברים סוף-סוף. כל החלטה להיכנס או לצאת אוחזת לרגע ביד הקרה הזאת."},"ICON-0018":{"nm":"כף","de":"בפיה השקוע היא מרימה בשקט מרק חם. כלי שזוכר את החום של הכפית הראשונה שאמא נפחה לקירור והושיטה ראשונה. על השולחן, זו היד העדינה ביותר - זו שנוגעת בשפתיים הכי הרבה פעמים."},"ICON-0019":{"nm":"כפכפי בית","de":"ברגע שחוצים את הסף, הרגליים נושמות לרווחה ראשונות. צליל הערב, המחליף את הקול השורק של היום בצעדים רכים ומתפתלים. זוג שמונח מסודר בכניסה אומר לך: ”הגעת הביתה”."},"ICON-0020":{"nm":"מפתח","de":"לומדים איך לפתוח לפני שלומדים איך לנעול. פיסת מתכת קטנה שמתחממת בכף היד, ולפתע ביום מסוים נעצרת בשקט מול דלת חדשה וזרה. החפץ ששומר הכי הרבה זמן על החום של מי שעזב."},"ICON-0021":{"nm":"כוס","de":"מסודרת כשהיא ריקה, חמה מכל דבר כשהיא מלאה. בצליל הצלול של שתי כוסות שמתנשקות זו בזו, נחתמת הבטחה חסרת מילים. כלי שנולד לזרוח בשניים, לא לבד."},"ICON-0022":{"nm":"צלחת","de":"בתוך שוליה העגולים מונח מלוא מסירותו של יום שלם. מתרוקנת, נשטפת, ומתמלאת מחדש לאורך חיים שלמים - חפץ הבית שזוהר הכי הרבה, ונשכח הכי הרבה. במת השולחן תמיד ערוכה עליה."},"ICON-0023":{"nm":"מנורה","de":"מתג אחד ומבע החדר משתנה. כשהיא בהירה - זו השגרה; כשהיא רכה - זו נחמה. נקודת אור בודדת שהושארה דלוקה עד הסוף למישהו שחזר מאוחר, הופכת לקבלת הפנים החמה ביותר בעולם."},"ICON-0024":{"nm":"כפית תה","de":"כשמסובבים אותה פעם אחת לאט מעל התה, העלים והמים חודרים זה לתוך זה. תנועה חסרת מנוחה, המתנה קצרה עד שהניחוח מתפשט. יד כסופה אחת מאטה בעדינות את קצב אחר הצהריים."},"ICON-0025":{"nm":"סימנייה","de":"הבטחה שמוכנסת בשקט למקום שבו הקריאה נעצרה. השבועה ”עצרתי כאן, ואחזור בוודאות” נרדמת בין הדפים. הסיפור עשוי להיסגר, אך הלב מסומן בבירור על אותה שורה אחת."},"ICON-0026":{"nm":"כרית נוי","de":"היא מקבלת בשתיקה את הגב והברכיים הזקוקים למשען. שוקעת עמוק ואז מתנפחת לאט, סופגת את עייפותו של היום. החפץ שמתיר בנדיבות הרבה ביותר את התנוחה העצלה ביותר."},"ICON-0027":{"nm":"מסגרת","de":"מסגרת מרובעת קושרת נוף אחד לנצח. לרגע ההוא בלבד שנלכד בתוכה, הזמן לא יידהה, לא משנה כמה יחלוף. בחירה חביבה שפחות עוסקת במה להכיל, ויותר במה שהוחלט להנציח."},"ICON-0028":{"nm":"מפה","de":"בכל קפל שוכנות עקבות של ללכת לאיבוד ולמצוא שוב את הדרך. פורשים אותה, ואפשר לפסוע גם במקומות שמעולם לא ביקרת בהם, בקצות האצבעות תחילה. כל הרפתקה מתחילה באומץ הקטן של פתיחת הדף האחד הזה."},"ICON-0029":{"nm":"גלויה","de":"חצי מגבה הוא תמונה, חצי - חלל ריק. מי שנסע רחוק שולח את המילים ”אני בסדר” לצד נוף המקום ההוא. הדף הכן ביותר - שם הבשורה אינה זקוקה למעטפה כדי שלא להתבייש."},"ICON-0030":{"nm":"תג כניסה","de":"ברגע שתולים אותו על הצוואר, נכנסים סוף-סוף אל העולם הפנימי. שמך על הכרטיס הקטן מעניק בשקט אישור: ”כאן, זה מקומך”. לא הסמכה למעבר, אלא הוכחה שאתה שייך למקום כלשהו."},"ICON-0031":{"nm":"האות B","de":"האות שנקראת הכי הרבה פעמים באמצע מילה. צריך לסגור את השפתיים פעם אחת ולפתוח אותן בפתאומיות כדי שהצליל ייוולד. לא ההתחלה ולא הסוף, אלא מקום שני איתן ששומר את הקצב."},"ICON-0032":{"nm":"כרטיס ביקור","de":"מוגש בשתי ידיים, מתקבל תוך מגע עיניים. יומו וגאוותו של אדם אחד דחוסים בשקט לתוך דף נייר בודד. ברווח הצר שבין השם לתפקיד, מתיישב בעדינות הרושם הראשוני של אותו יום."},"ICON-0033":{"nm":"כריכה","de":"בשוליים החיצוניים ביותר של הסיפור, היא הראשונה לפגוש רוח וגשם. תוך שהיא מגנה על האותיות שבפנים, היא נשחקת מפינותיה שלה. הרטט הקצר של ציפייה רגע לפני הפתיחה תמיד מתחיל בדף האחד הזה."},"ICON-0034":{"nm":"ספר לימוד","de":"מאבקו של אדם אחד כתוב בצפיפות בקווים תחתונים ובטקסט מודגש בצבע. מבהיל כשהוא חדש, הופך לחבר הנאמן ביותר כשמסיימים אותו. עקבות ההבנה של מה שהיה לא ידוע מקופלים בעדינות בכל עמוד."},"ICON-0035":{"nm":"כרטיס אולפן ריקוד","de":"דף בודד אחד פותח לרווחה את דלת אולפן החזרות. חדר מלא מראות, קול רקיעת רגליים, שמונה הפעימות הראשונות שנלמדו אי פעם. זה בסדר אם הריקוד עדיין מגושם - פיסת נייר קטנה דוחפת בעדינות גב רועד קדימה."},"ICON-0036":{"nm":"תיקיית מסמכים","de":"דפים בודדים שנדדו ללא סדר נתפרים כעת בשורה מסודרת על שדרה אחת, וסוף-סוף זוכים בסדר. עם הסדר בא סיפור, וככל שהתיקייה מתעבה, כך היא עדות חביבה יותר לכך שמישהו חי את חייו בקפדנות, עמוד אחר עמוד."},"ICON-0037":{"nm":"דף מבחן","de":"קצות אצבעות רועדות לרגע מעל השורות הריקות. מפחיד יותר מתשובה שגויה הוא לעמוד פנים אל פנים מול מה שאינך יודע. כשהבדיקה מסתיימת, בכל מקום שגוי נותר בשקט מרווח לצמיחה בפעם הבאה."},"ICON-0038":{"nm":"האות A","de":"הצליל הראשון שנולד רק כשפותחים את הפה לרווחה. היא ניצבת לעיתים קרובות בראש השורה, בתחילת השם. כל התחלה מתחילה באות הזאת - ולכן היא תמיד קצת יותר אמיצה."},"ICON-0039":{"nm":"האות D","de":"בגבה המעוקל בעדינות, היא תומכת ברכות במילה. צדה העגול תלוי מסודר בסוף שמו של מישהו. לא ראוותנית, אך כשהיא נעדרת - חסרה - חברה שקטה בין האותיות."},"ICON-0040":{"nm":"דף תרגול","de":"הנייר היחיד בעולם שבו טעויות זה בסדר. הוא מאפשר לכתוב את אותה תנועה, את אותו משפט, עשרות פעמים מחדש. על כל דף מקומט שהושלך, מישהו בוודאי הפך טוב יותר במעט."},"ICON-0041":{"nm":"דף תווים לחיבור","de":"שתיים בלילה, המהום אחד מעיר אותך משינה. העיפרון מהסס מעל חמשת הקווים כי המנגינה מהירה מהיד. בכל סימן שנמחק ונכתב מחדש, שיר עדיין חסר-שם גדל לאט לאט."},"ICON-0042":{"nm":"תג גישה","de":"ברגע שתולים אותו על הצוואר, מסדרון רגיל הופך לעולם אחר. כבלים מתפתלים בחשכה כמו נחשים, ומעבר לבמה מתחילה ספירה לאחור שאיש אינו שומע. זכות הכניסה לכאן - הדף האחד הזה מדבר במקומך."},"ICON-0043":{"nm":"גיליון מגע","de":"בכל משבצת קטנה קפוא מבע אחר - לצחוק, להביט לאחור, לעצום עיניים. מצביעים על תמונה אחת בכל פעם, וריגוש לחיצת הצמצם של אותו יום שב אל קצות האצבעות. אפילו בחירת תמונה אחת היא כבר תיעוד."},"ICON-0044":{"nm":"לוח צילומים","de":"מחר באיזו שעה, היכן, ומה. דף בודד משרטט מראש את מסלול היום. בין המשבצות הדחוסות דקה אחר דקה, מישהו הולך צעד אחר צעד לעבר החלום, בעקבות הסדר הרשום כאן."},"ICON-0045":{"nm":"תווית","de":"מאחורי תווית המחיר תלוי בשקט הזמן של מי שיצר. רק בתנועת היד הקצרה של קריעתה, הנייר הקטן הופך סוף-סוף לשלך. מה שנשאר במקום החיתוך הוא ריח של דבר חדש, וקורט של התרגשות."},"ICON-0046":{"nm":"תיק עבודות","de":"פותחים את הכריכה והדרך שעברת נפרשת כולה בבת אחת. לצד עמוד שאתה גאה בו, ניצב בביישנות ניסיון ראשון ומגושם. כשמושיטים את עצמך למישהו בפעם הראשונה, אין הצגה עצמית כנה מזו."},"ICON-0047":{"nm":"יומן תכנון","de":"כותבים את היום, משרטטים את השבוע הבא, ומדי פעם צובעים משבצת אחת בשחור. גם אם דבר לא הלך לפי התכנית, היד שממלאת את המשבצות אינה נעצרת. מעין טקס קטן של לחיות את העתיד מראש, פעם אחת."},"ICON-0048":{"nm":"רשימת השמעה","de":"בין שירים איטיים לקצב מהיר, מסדרים שירים בשורה אחת בהתאם למזג האוויר של הלב באותו יום. אם חושבים שיומו של מישהו זורם בדיוק בסדר הזה, אפילו הדממה שבין השירים הופכת חמה."},"ICON-0049":{"nm":"תעודת תלמיד","de":"שם, תמונה, וכמה מספרים. כרטיס בודד שמעיד על התקופה שבה נעו בין הכיתה לאולם החזרות. בכרטיס ששחוק בפינותיו מהיציאה והכניסה לכיס, חרוטים ימי יום-יום רעננים שלא ישובו עוד."},"ICON-0050":{"nm":"צמיד","de":"זוכר את הרגע שבו קשרת את צבע היום סביב פרק כף היד? הקריאה שהרימו יחד, ליל הקונצרט שהירטב יחד. גם כשהרצועה נשחקת והצבע דוהה, לא מתירים אותה - כי רוצים שאותו קיץ ימשיך לחיות על פרק כף היד."},"ICON-0051":{"nm":"סרט זרוע","de":"ברגע שכורכים אותו סביב הזרוע, נוסף בשקט משקל שנקרא אחריות. סימנו של מי שעומד בראש השורה, ומי שעוזב את מקומו אחרון. פיסת בד אחת מגדילה מישהו בכמה סנטימטרים."},"ICON-0052":{"nm":"טבעת","de":"קו אחד שנסגר במעגל, ללא הפסקה. מכיוון שהתחלתו וסופו נוגעים זה בזה, אנשים רואים בו את צורת הנצח. כשמצמידים בשקט שתי כפות ידיים, ההבטחה נותרת כצורה, עוד לפני המילים."},"ICON-0053":{"nm":"מדליה","de":"בפיסת המתכת הקטנה הנעוצה על החזה חרוטים הימים שהוחזקו מעמד. מה שנוצץ אינו המתכת, אלא לילות התרגול הרבים המסתתרים מאחוריה. מה שעולה לפני הגאווה הוא, משום מה, הכרת תודה."},"ICON-0054":{"nm":"סינר","de":"כשקושרים את הרצועות סביב הצוואר, שתי הידיים משתחררות. סימן לכך שאתה מוכן לצלול בראש אל תוך משהו - קמח או צבע, לא משנה מה. ככל שהכתמים נערמים אחד אחד, כך גם המסירות שהושקעה באותו יום מעמיקה."},"ICON-0055":{"nm":"חמם אוזניים","de":"כשעוטפים את האוזניים בחוזק, קולות החוץ נסוגים צעד אחד. בדרך לבית הספר ברוח חותכת כסכין, מקלט קטן שאפשר להתחבא בו בפנים הרכים. חום החורף מתחיל לפעמים, ממש כך, מקצות האוזניים."},"ICON-0056":{"nm":"תלבושת במה","de":"לפני עליית המסך, תלבושת אחת תלויה על הקולב, עוצרת נשימה. כוריאוגרפיה מקופלת בכל תפר. ברגע שהזרוע חולפת דרך השרוול, אדם הופך לדמות, והבמה הופכת לעורה השני של התלבושת."},"ICON-0057":{"nm":"כתר","de":"ברגע שהוא מונח על הראש, גב כפוף מתיישר מעצמו. הזוהר הזהוב לוחש על אחריות עוד לפני שלטון. המשקל הצונן הנוגע במצח אומר הכול: ככל שהמקום זוהר יותר, כך הוא כבד יותר."},"ICON-0058":{"nm":"גלימה","de":"עוטפים את הכתפיים והרוח מתנופפת מאחורי הגב. אותה תחושה של כנף בד אחת רודפת אחריך בכל ריצה. פחות סמל של גיבור, יותר לבו הפשוט של ילד שרצה פשוט להיראות מגניב."},"ICON-0059":{"nm":"מסכה","de":"מסתירים את הפנים, ודווקא אז נעשים כנים יותר. כמו במחזות החצר הישנים, שבהם צחקו ובכו בחופשיות מאחורי המסכה. מעבר למבע המוסתר, הקול האמיתי שרגיל להיבלע נמלט החוצה בקול רם עוד יותר."},"ICON-0060":{"nm":"שפתון","de":"מסובבים את המכסה, מותחים קו אחד, ונחישות קטנה מתיישבת על השפתיים. בדיקה אחרונה מול המראה, קו אדום שנמרח מעל ההיסוס. באותו רגע קצר שבו הצבע נמרח, הפחד נסוג בשקט הצידה."},"ICON-0061":{"nm":"ג'קט","de":"כשקו הכתפיים יושב בדיוק במקום, האדם נעשה מעט איתן יותר. מגלגלים את השרוולים - לב עובד; מרימים את הצווארון - לב שיוצא לדרך. פריט לבוש אחד קובע בשקט את הלך הרוח של היום."},"ICON-0062":{"nm":"חגורת טאקוונדו","de":"בכל פעם שהצבע עולה דרגה, כמות הזיעה שנצברה מתחתיו משתנה גם היא. בוקר הדוג'אנג של הידוק הקשר וקידה עמוקה. דרך קצות האצבעות שקושרות את החגורה, הרוח המפוזרת מתכנסת מחדש."},"ICON-0063":{"nm":"משקפי מגן","de":"מרכיבים אותן, והעולם מתחדד גוון אחד. מעבר למגן העגול שחוסם רוח ואבק כאחד, אפילו השביל הרגיל שתמיד הולכים בו נוצץ משום מה כמו קו זינוק."},"ICON-0064":{"nm":"כפפה","de":"לובשים אותה ועולה אומץ לאחוז בכל דבר בחוזק. אצבעות שהתכווצו מפחד להפיל משהו, נפתחות סוף-סוף לרווחה. היד היא זו שמוגנת, אך מה שבאמת נשמר הוא האתגר שיבוא אחר כך."},"ICON-0065":{"nm":"מסיכה","de":"מכסים את התחתית של הפנים, והעיניים מדברות יותר. ברחוב הומה אדם, חירות קטנה של אלמוניות שנהנים ממנה מאחורי כיסוי קל. ולכן, החיוך שנותר במקום שממנו היא מוסרת כולה, נפרש בהיר עוד יותר."},"ICON-0066":{"nm":"כובע","de":"מורידים את המצחייה במעט, והשמש והמבטים חולפים הצידה. מתחת לגג הקטן שעל הראש, מותר היום ללכת עם הבעה נינוחה. השינוי הקל ביותר תמיד מתחיל כאן."},"ICON-0067":{"nm":"חולצה","de":"רשרוש קל, וריח הבוקר עולה מהצווארון שזה עתה גוהץ. תוך כדי סגירת הכפתורים אחד אחד מלמעלה, גם הלב המפוזר מתארגן משבצת אחר משבצת. דף לבן אחד פותח את המשפט הראשון של היום."},"ICON-0068":{"nm":"צעיף","de":"כורכים סביב הצוואר פעם אחת ומעבר הרוח נחסם. בעוד הקצוות מתנדנדים בעדינות על הכתף, הקור כבר לא מגיע פנימה. פיסת בד אחת המונחת אי שם בין סגנון לחום."},"ICON-0069":{"nm":"כפפות","de":"כשעוטפות היטב עד קצות האצבעות, גם דברים קרים לא מפחידים. מותרות קטנה של החורף, כשידיים שנשפו עליהן בחום הופכות בשקט חמימות. גם כפפה אחת שמוסרים ומעניקים למישהו יכולה לחמם יד אחרת."},"ICON-0070":{"nm":"דיסקיות זיהוי","de":"שתי לוחיות דקות ניצבות זו מול זו בשקט. שלוש אותיות של שם וכמה מספרים - זה מה שגורם למישהו להיזכר עד הסוף. מתכת קרה, ובכל זאת, משום מה, היא דומה להבטחה החמה ביותר."},"ICON-0071":{"nm":"טבעת אחיזה","de":"תוחבים אצבע דרכה והחשש מנפילה נמס לו בשקט. ביטחון קטן שמאפשר להחזיק ולנופף גם ביד אחת בלבד. כשמותחים את הזרוע רחוק כדי להנציח תמונה אחת, היא תומכת בשקט בכף היד."},"ICON-0072":{"nm":"כתר פרחים","de":"מניחים אותו על הראש וחיק שלם של אביב מגיע איתו. פרחים שנקטפו בשדה ונקלעו לעיגול מקיפים בעדינות את המצח. מעל החיוך הבהיר בתמונה, ריח דשא עדין נשאר לאורך זמן רב."},"ICON-0073":{"nm":"מסכת שינה","de":"מכסים את העיניים ואור ורעש נסוגים בבת אחת. כשלא רואים, כל מה שנשמע הוא נשימתך שלך. מכבים לרגע את העולם ונכנסים אל השקט הפנימי, ודלת קטנה נסגרת בשקט מאחורי הגב."},"ICON-0074":{"nm":"צעיף צמר","de":"היקף אחד, שני היקפים - בכל סיבוב סביב הצוואר, החורף מתרכך מעט. איפשהו בין חוטי הצמר אולי משוזר גם ליבו של מישהו שסרג אותו. טומנים בו את האף ממש, והעולם נעשה נעים בהרבה."},"ICON-0075":{"nm":"מסכת חצי-ירח","de":"כשמכסים רק חצי מהפנים, מתחיל ליל הנשף המחופש. השפתיים החשופות מחייכות, העיניים המוסתרות שומרות סוד. הרווח הצר ההוא של כמעט-לדעת-מי, מרטיט את אוויר חצות הלילה."},"ICON-0076":{"nm":"כומתה","de":"מניחים אותה בזווית והיום הרגיל קונה לעצמו בשקט קורטוב של אווירה. פיסת בד עגולה ושטוחה אחת מלבישה בעדינות את הכתפיים בדמות אמן. אפילו הרגע הקצר של בחירת הזווית מול המראה הוא כבר הנאה."},"ICON-0077":{"nm":"צ'וקר","de":"כשמהדקים אותו בדיוק סביב הצוואר, המבט נאסף מעצמו כלפי מעלה. רצועה דקה אחת משנה את כל האווירה. קטנה אך ברורה, כמו אבזם שממלא את הביטחון העצמי של היום הזה."},"ICON-0078":{"nm":"פארקה","de":"מעלים את הרוכסן עד הסוף ואפילו סופת השלגים נסוגה צעד אחד. תוחבים את הידיים עמוק אל תוככי הבטנה העבה, וכל המהומה של העולם משתתקת. בית קטן אחד שנשאר חם עד הסוף גם ברוח הפראית ביותר."},"ICON-0079":{"nm":"מכנסיים","de":"תוחבים את הרגליים ומהדקים את המותניים, וסוף-סוף ההכנה ליציאה הושלמה. בכל צעד, הבד נע ברכות לאורך הסיב שלו. איפשהו בין נוחות להידור, היום מתחיל."},"ICON-0080":{"nm":"פירסינג","de":"אפילו להוסיף נקודה קטנה אחת דורש קצת אומץ. נצנוץ מתכת בודד שם נקודה ברורה על תנוך אוזן רגיל. קטן מאוד, ובכל זאת אור שמשקף אני של היום שוודאי השתנה."},"ICON-0081":{"nm":"צורת גל","de":"עבור המהנדס, השיר לא נשמע - הוא נראה. מתוך קו הרכס העולה ויורד על המסך, הוא קורא היכן רעדה הנשימה באותו יום. קול שהיה בלתי נראה שוכב עכשיו כמו רכס הרים, ופורש את נופו של רצועת שיר אחת."},"ICON-0082":{"nm":"מכוון","de":"רגע לפני ההופעה, מלטפים את ששת המיתרים בזה אחר זה, ומיישבים למקומם צלילים שסטו. גם סטייה של חצי טון והקהל קולט אותה כמו רוח רפאים. לכוון בדיוק כזה שאיש לא יבחין - זו אדיבות כלפי הבמה."},"ICON-0083":{"nm":"רצועה","de":"כורכים פעם אחת סביב פרק כף היד והחשש מנפילה מתפוגג בשקט. הדבר המפחיד ביותר על הבמה הוא לאבד אחיזה במשהו, ולכן רצועה קטנה אחת זו סוף-סוף מרגיעה את הלב."},"ICON-0084":{"nm":"מצילתיים","de":"ברגע הפגיעה הבודד, מוצבת נקודה ברורה על המשפט האחרון של השיר. הדיסק הזהוב יודע לצלצל הכי קצר, ולהשאיר את ההד הכי ארוך. כך, אומרים לך, סוף חייב להיסגר בבהירות שכזו."},"ICON-0085":{"nm":"גיטרה","de":"כשהאצבעות מחליקות על ששת המיתרים, חדר קטן הופך כולו לבמה. המנגינה הראשונה של מישהו, המלמול לעצמו בשעת שחר חסרת שינה - כולם שאבו נשימה ראשונה בתוך הגוף העגול העשוי עץ הזה."},"ICON-0086":{"nm":"ענן צלילים","de":"בצד אחד של השמיים, תווים מתקבצים כמו צמר גפן ונעים בריחוף. אומרים שכשהרוח חולפת פעם אחת, יורדות מנגינות במקום טיפות גשם - ולכן ילדי האי יוצאים לקבל את פניה בלי אפילו מטרייה."},"ICON-0087":{"nm":"צעד","de":"תנועת הבמה היא חשבון שנפתר בקצות האצבעות. צעד אחד כאן, חצי פעימה שם - זה בסדר לטעות, אז לאט. המשבצות שנדרכו מאות פעמים ונחרתו בגוף מתאספות יחד, ורק אז מושלמת מפתו של שיר אחד."},"ICON-0088":{"nm":"מגבר","de":"קופסה שהופכת לחישה לשאגה. ובכל זאת, לפני שמעלים את עוצמת הקול משבצת אחת, היד תמיד עוצרת לרגע. שקול מדויק יותר, לא רועש יותר, מגיע עד השורה האחרונה באולם - את זה הקופסה הזאת יודעת."},"ICON-0089":{"nm":"צמר תווים","de":"כשראשי התווים העגולים מתקבצים לכדור צמר גפן, הוא רך כמו כרית. שוכבים עליו בשקט, ואומרים שנשמעת ממנו שיר ערש בקושי נשמע - השמועה החביבה ביותר באי."},"ICON-0090":{"nm":"קלטת","de":"לוחצים על כפתור ההרצה לאחור וחריקה - הסרט חוזר לאט אל השיר הראשון של אותו קיץ. בתוך הקופסה הקטנה שתקופה שלמה כרוכה בה, ישן לו בשלמותו זמן שאי אפשר לגעת בו עוד."},"ICON-0091":{"nm":"מזלג כוונון","de":"מקישים קלות על שתי שיני המתכת, וצליל ייחוס אחד נולד באוויר. לרעד הקטן הזה כל הכלים מרכינים ראש בשקט, מתואמים. כל התחלה מגיעה מרטט עדין כזה."},"ICON-0092":{"nm":"שבב צליל","de":"פיסת קול נכלאת בעדינות בתוך שבב בגודל ציפורן. קריאת ביניים שמעולם לא הוקלטה בכוונה, צחוק של מישהו שחשבת שנעלם - כאן, בפנים, הם עדיין חיים ונושמים בחום כתמיד."},"ICON-0093":{"nm":"תקליט LP","de":"כשהמחט עושה את צעדה הראשון לאורך החריץ, נשמעת תחילה נשימה דקה ורוחשת. אוהבים אפילו את הרעש הקטן הזה, ולכן יש מי שלעולם, עד הסוף ממש, לא יכול להניח מהיד את הדיסק השחור הזה."},"ICON-0094":{"nm":"כיס","de":"את הדבר היקר ביותר תמיד שומרים הכי קרוב ללב. שקיק בד אחד בגודל כף יד הופך יום אחד לחממת יד, יום אחר לקמע, ויום נוסף למחסן של סודות."},"ICON-0095":{"nm":"פלסטר","de":"בלילות שבהם התרגול מתמשך, מדבקת ”מדליה” קטנה אחת נדבקת לכל עקב. פלסטר שהודבק כדי לבלוע את המילה ”כואב” - הבטחה שקטה שאיש אינו יודע עליה, לרקוד שוב מחר בכל מחיר."},"ICON-0096":{"nm":"כרית","de":"המקום שבו מניחים בסופו של דבר את כל במת היום הוא, בסופו של דבר, הריבוע הרך הזה. משכיבים עליו את הראש בעדינות, וקול המחיאות שנותר באוזניים דועך לאט, וגם על האי, סוף-סוף, יורד הלילה."},"ICON-0097":{"nm":"פעמון","de":"צלצול קצר אחד, ומישהו דוחף את הדלת ונכנס. אות לכך שאורח הגיע, ברכת שלום לכך שהיום נפתח. פיסת מתכת קטנה אחת מצלצלת כל היום דבר אחד בלבד - שמחה לקראתך."},"ICON-0098":{"nm":"נרתיק","de":"ככל שדבר יקר יותר, כך בונים לו בית איתן משלו. הידיים שפותחות וסוגרות אותו נעשות זהירות בכל פעם, כי מה שמונח בפנים אינו סתם חפץ, אלא לב שאי אפשר לשאת לאבד."},"ICON-0099":{"nm":"מברשת","de":"מטאטאים לאורך הסיב עד לשערה האחרונה, והאבק שנדבק בפינות נסוג בשקט. הודות ליד שלא נרתעת אפילו מהמקומות הבלתי נראים, החדר פוגש בוקר חדש בכל יום."},"ICON-0100":{"nm":"סקיצה","de":"קווים לפני ההשלמה אינם טורחים להסתיר את היסוסם. בכל סימן שנמחק ונמשך מחדש, נותר ללא שקר מה שרצה להיות. ככל שההתחלה מגושמת יותר, כך היא הכנה ביותר."},"ICON-0101":{"nm":"בובה","de":"יש ישויות שמנחמות רק בכך שמחבקים אותן, בלי מילה. את החברה המרופדת בכותנה שרעדה איתך ליד הכרית, בלילות שבהם ידיך רעדו מאחורי הקלעים — כל אחד שומר כזו איפשהו בלב."},"ICON-0102":{"nm":"פעמון","de":"פעמון מקדש ההרים מצלצל פעם אחת וחוצה עמק שלם. זהו ליבו של המתכת, הכמה להגיע רחוק ועוד רחוק יותר, בוכה בקול ארוך — כך שהצליל שוקע לאט בחזהו של השומע."},"ICON-0103":{"nm":"מטרייה","de":"כששניים חולקים מטרייה, כתף אחת תמיד תירטב. מתחת למטרייה המוטה קלות, הכתף הרטובה היא ההוכחה הברורה ביותר לחום אנושי. הדרך הקצרה תחת גג אחד נשארת זמן רב בלב."},"ICON-0104":{"nm":"מזרן","de":"לפרוש אחד על הרצפה החשופה — והמקום הזה הופך מיד לחדר חזרות. מקום שקולט בלי מילה כשמתגלגלים ונופלים — אינספור תנועות למדו כאן לראשונה את דרכן אל הגוף."},"ICON-0105":{"nm":"פעמונית","de":"מנענעים בעדינות והנה, צליל צלול מתגלגל מתוך כף היד. השמחה הקטנה והעגולה שילדים בעבר תלו בקצה חצאיותיהם הצבעוניות ורצו איתה בחצר, מתעוררת מחדש על כף היד."},"ICON-0106":{"nm":"נחש צעצוע","de":"צורתו הארוכה והמשתלשלת מפחידה אנשים בשובבות. פחד, בריחה, ולבסוף פרץ צחוק — גם תעלול כזה הוא בסופו של דבר ענף אחד של חיבה הדדית."},"ICON-0107":{"nm":"צעצוע","de":"לכל אחד יש קופסה אחת שקשה לו להיפרד ממנה, גם כשגדל. בתוכה, הצחוק של הימים הזוהרים ביותר עדיין כרוך חזק כמו קפיץ שלא נפרס."},"ICON-0108":{"nm":"שולחן אוכל מתקפל","de":"פותחים את רגליו המקופלות וכל מקום הופך מיד למקום המשפחה. קול הכפות הנוקשות זו בזו כשכולם מתכנסים סביב — התזמורת הצנועה הזאת מצלצלת בחום מכל שירי היום."},"ICON-0109":{"nm":"סבון","de":"מתקטן בהדרגה בתוך היד, ובשקט מנקה מישהו. לשחוק את עצמו כדי לרחוץ אחר — רק זמן רב אחרי שהקצף דעך כולו, מתגלה סוף סוף הלב השקט הזה."},"ICON-0110":{"nm":"מסרק","de":"כשם שהוא מתיר שיער סבוך חוט אחר חוט, כך גם יום מקומט הולך ומסתדר. מגע קצר אחד מול המראה מתקן בשקט, מעבר לשיער, גם את הופעת הלב."},"ICON-0111":{"nm":"כלוב ציפורים","de":"יש ציפור ששרה בלי לעזוב, גם כשהדלת פתוחה לרווחה. לב שנשאר לא כי הוא כלוא אלא כי הוא רוצה להישאר — את ההבדל הדק הזה, הכלוב הזה חש לפני כולם."},"ICON-0112":{"nm":"מחמם כפות ידיים","de":"בתור ההמתנה החורפי מחוץ לאולם, חום קטן בכיס מפשיר בעדינות אצבעות קפואות. חום בגודל כף יד שמישהו ניער וחימם מראש, בחשבו עליך רועד בקור."},"ICON-0113":{"nm":"ממחטה","de":"פיסת בד אחת שקולטת דמעות וזיעה בלי תלונה. הרקמה הקטנה שבפינתה נשארת שם ביופיה, כמו פרידה אחרונה שהשאיר מי שהלך ראשון, ואמר אל תשכחי."},"ICON-0114":{"nm":"תרסיס","de":"ריסוס אחד קצר, ומרקם האוויר משתנה ברגע. הערפל שמתפשט מעל הבמה, הצמח ליד חלון הבוקר — בתוך הטיפות הדקיקות הללו, לרגע הם הופכים לעולם אחר ומנצנצים."},"ICON-0115":{"nm":"רצועת ריח","de":"בחירת בושם דומה, איכשהו, ממש לבחירת זיכרון. חוט דק אחד של ניחוח שנוגע בקצה נייר צר, מביא בעדינות אל האף עונה ששכחת שהיא בכלל קיימת."},"ICON-0116":{"nm":"שולחן אוכל","de":"בכל סיב עץ שחוק חרוט בשקט מספר הארוחות שנחלקו יחד. הערבים הרועשים, הלילות המאוחרים שהתקבלו לבד — הריבוע הזה קלט את כולם בלי מילה, והבריק."},"ICON-0117":{"nm":"פקעת חוט","de":"מושכים קצה אחד בעדינות, והוא נפתח בקלות; תפר אחד, והוא מתחבר שוב. תיקון של דבר שנקרע תמיד מתחיל בשקט, בדיוק ככה, מחוט דק אחד."},"ICON-0118":{"nm":"מעיל גשם","de":"גם ביום של גשם שוטף, הבגד היחיד הזה הוא שמוציא אותך סוף סוף מהבית. רק מי שמכיר את השמחה בהתזה במים בגשם, מסרב להשתמש בגשם כתירוץ להישאר בבית."},"ICON-0119":{"nm":"כיס שקיק","de":"קושרים את הפתח לעיגול, וכל מה שבפנים סוף סוף מובטח. בתוך שקיק קטן ושחוק, מטבעות, זיכרון של יום כלשהו, ומילים שמעולם לא נאמרו נעים יחד."},"ICON-0120":{"nm":"כוננית ספרים","de":"מעבירים אצבע לאט לאורך שדרות הספרים המסודרות, וניתן לחוש בקצות האצבעות את העונות שחלפו. הסיבה שקשה לזרוק ספר שסיימת היא שהאני של אז עדיין חי שם."},"ICON-0121":{"nm":"מגדל ספרים","de":"ספרים שקראת שוכבים בצד; ספרים שלא קראת נערמים כלפי מעלה. גם כשההבטחה לקרוא את כולם יום אחד מתנדנדת קלות קרוב לתקרה, אתה אוהב אפילו את הרעד הזה, ולכן היום אתה מוסיף עוד כרך אחד."},"ICON-0122":{"nm":"גלגל ריצה","de":"נדמה שגם כשרצים בכל הכוח נשארים במקום, אבל הרגליים הקטנות לומדות תחילה את קצב האצבעות. אתמולים שלא נעצרו מצטברים, ויום אחד זורחים בבהירות על כביש אמיתי."},"ICON-0123":{"nm":"כיסוי","de":"כדי שאבק לא ישקע, כדי שהשמש לא תדהה — גם מעשה הכיסוי דורש קפידה מקצות האצבעות. ככל שדבר יקר יותר, כך הוא מוגן ביתר עדינות במקומות שאינם נראים."},"ICON-0124":{"nm":"חוט צמר","de":"חוט אחד שהתגלגל והתפתח מברכי סבתא. הוא עשוי להיראות סבוך, אבל מציאת הקצה ומשיכה עדינה מביאים אותו בעקבותיך ללא כשל. כך התארכו לילות החורף, תפר אחר תפר."},"ICON-0125":{"nm":"תיק קוסמטיקה","de":"שפתון, גומייה לשיער, מכתב מקופל בקפידה — נראה קטן, אבל בתוכו טמון לב של יום שלם. עם קול הרוכסן שנסגר, כל הפרטים היקרים ניצלים בבת אחת."},"ICON-0126":{"nm":"משענת יד","de":"אחר צהריים שנרדם באמצע קריאה, ערב שנשקד בו הלוך ושוב בזמן שיחת טלפון. במקום שמעמיק עם השימוש הממושך, כל מנוחה שהמרפק זוכר מצטברת בשקט, ברוחב כף יד."},"ICON-0127":{"nm":"חבילה אטומה","de":"עד שנפתחת, היא עדיין לא שייכת לאף אחד. שקית אטומה גדושה בציפייה שטרם נפתחה, כך שקצות האצבעות שאוחזות בפינתה רועדות קלות. זו התרגשות הפתיחה."},"ICON-0128":{"nm":"נייר עטיפה","de":"לב שמגיע צעד אחד לפני המתנה עצמה. בזמן שמקפלים את הפינות בדיוק וקושרים בסרט, פניו המחייכות של מי שיקבל אותה נפרשות מראש בבהירות בתוך הידיים."},"ICON-0129":{"nm":"ג'ויסטיק","de":"כפתורים שהאגודלים זוכרים לפני שהראש זוכר. הפסדת, אבל עוד סיבוב אחד — וסיבוב אחד זה מסתיים בליל שינה שלם. המשקל שמתאים בול ליד מרים בשקט את הרפתקת הלילה."},"ICON-0130":{"nm":"רמזור","de":"אדום — עצור לרגע, ירוק — עכשיו אפשר ללכת. הבטחה פשוטה אחת גורמת לאינספור דרכים לזרום בלי להסתבך. שגם להמתנה יש תור, האור המהבהב מודיע בעדינות."},"ICON-0131":{"nm":"חץ","de":"הצורה העדינה ביותר עבור מי שאיבד את דרכו. כשלא ברור לאן ללכת, כיוון אחד שמישהו סימן מראש מחזק מחדש את הצעדים שנעצרו."},"ICON-0132":{"nm":"קואורדינטות","de":"שני מספרים בלבד, ואפשר להצביע על כל מקום בעולם. המקום שסוכם להיפגש בו, חוף החול שבו נטמן האוצר. כדי שהבטחה לא תאבד את דרכה, נקודה קטנה אחת מחזיקה בה עד הסוף."},"ICON-0133":{"nm":"אריח","de":"לבדו, הוא רק פיסה מרובעת. ברגע ששוכבים כתף אל כתף זה לצד זה, הם הופכים לרצפה ולקיר. דברים קטנים מתאספים כדי ליצור מקום שמישהו יוכל להניח בו את כף רגלו בבטחה."},"ICON-0134":{"nm":"שעון חול","de":"כשהתא העליון מתרוקן, התחתון מתמלא לאט. בצפייה בחול הנשפך בעדינות, אנו מאמינים שהזמן זורם. הופכים אותו — וזו שוב ההתחלה. זהו השקר החביב של החול."},"ICON-0135":{"nm":"כדור","de":"זורקים והוא חוזר; בועטים והוא מתגלגל. היותו עגול, כשלא יודעים לאן הוא יקפוץ, הוא קסמו הגדול ביותר. באמצע המגרש, הצחוק תמיד התחיל עגול, מתוך הכדור הקטן הזה."},"ICON-0136":{"nm":"מתג","de":"קליק — נדלק בלחיצה אחת, נכבה בלחיצה אחת. הצליל הקטן הזה, שנשמע בכניסה לחדר חשוך, מחלק את תחילתו וסופו המפוזרים של היום לקו ברור אחד."},"ICON-0137":{"nm":"סימן שאלה","de":"לא לדעת את התשובה אינו דבר מביש. זו ההוכחה המשמחת שהסקרנות עדיין חיה. כשהווו הקטן הזה מקיש בעדינות על הראש, הלמידה סוף סוף עושה את צעדה הראשון."},"ICON-0138":{"nm":"גפרור","de":"מקל אחד ששורף את עצמו כדי להעביר אש הלאה. הוא בוער זמן קצר ונעלם בשקט, אך באותו רגע קצר נר נדלק ואח מתחממת. נתינה קטנה הופכת לכפתור הראשון של החום."},"ICON-0139":{"nm":"שרפרף מדרגה","de":"עולים עליו רק צעד אחד, והיד מגיעה גם למדף שלא היה בהישג יד. מלאכה של הארכת גובהו של מישהו לרגע. הנה מקום עדין שכורע נמוך כדי להרים אותנו בעדינות גבוה יותר."},"ICON-0140":{"nm":"שעון יד","de":"הדבר הראשון שנקשר לפרק כף היד ביום שהחלטת להתחיל להתאמן. מאמן קטן שסופר דפיקות לב וצעדים, מקיש בעדינות ומודיע שהיום הלכת קצת יותר מאתמול."},"ICON-0141":{"nm":"שעון מעורר","de":"החבר הנאמן ביותר, השנוא מדי בוקר מחדש. הודות לו שנלחם כל פעם במקומך בפיתוי של עוד חמש דקות מתחת לשמיכה, לא ההבטחות ולא החלומות מאחרים. הצליל הזה שמצלצל בעקשנות הוא, למעשה, עידוד."},"ICON-0142":{"nm":"ליבה","de":"החלק הפנימי ביותר שנשאר עד הסוף אחרי שקולפים את כל מה שבחוץ. הגרעין של התפוח, האמת שבלב — מה שלא יהיה, בדיוק במרכזו נמצא הדבר החזק ביותר. הנקודה האחת שנשארת בסוף, גם כשמנערים."},"ICON-0143":{"nm":"עט","de":"הכתם שנמרח על צד היד לפני שהדיו התייבש. בין אם הכתיבה זורמת ובין אם לא, המשיכה הראשונה שנמתחת מול דף לבן תמיד דורשת אומץ קטן. זהו הגשר שדרכו המחשבה חוצה אל קצות האצבעות."},"ICON-0144":{"nm":"מכחול","de":"כשהוא סופג דיו וחולף מעל נייר הנג'י, אפילו רעד אחד של היסוס נשאר שלם. מי שמנסה לכתוב מהר מתוך תאוות בצע, נחשף מיד. המכחול הוא הראשון שיודע את היושר השוכן בקצות האצבעות."},"ICON-0145":{"nm":"בועת דיבור","de":"המקום שצץ עגול מעל הראש עוד לפני שהמילים הספיקו לצאת מהפה. המשפט האחד שרוצים לומר נשמר כאן. כשהיא ריקה, היא באמצע הבחירה מה למלא בתוכה."},"ICON-0146":{"nm":"תיבת סימון","de":"מציירים שני קווים בריבוע הריק, והלב נעשה קל יותר. אות כבוד קטן שמעניקים לעצמכם על משימה שהושלמה. בסוף היום, כשמביטים בתיבות המלאות, אנו מרגיעים את עצמנו שגם היום חיינו היטב."},"ICON-0147":{"nm":"טאבלט","de":"ציורים מתפשטים ואותיות זורמות בכל מקום שהאצבעות נוגעות בו. מניחים אותו בשקט על הברכיים, ועולם שלם נדלק בבהירות. הוא קל, אך האפשרויות הטמונות בו אינן דקות כלל."},"ICON-0148":{"nm":"שלט רחוק","de":"יש לו כישרון טבעי להיעלם בסדקי הספה. הכוח לשנות ערוץ תמיד שייך למי שמחזיק בו. המריבה הקטנה והחביבה ביותר במשפחה מתרחשת מעל פיסת יד אחת זו."},"ICON-0149":{"nm":"משקולת איזון","de":"משקל שירד בעצמו אל הנקודה הנמוכה ביותר כדי להחזיק את מה שמתנדנד. יהיה החלק העליון סוער ככל שיהיה, אם התחתון כבד, הוא לא יקרוס בסוף. איזון תמיד מחזיק מעמד במקומות שאינם נראים."},"ICON-0150":{"nm":"פאזל","de":"הלילה שמיששת אפילו מתחת לספה בחיפוש אחר החתיכה האחרונה החסרה. העונג חסר הקול של הרגע שבו היא נכנסת בול למקומה. כשדברים מפוזרים מוצאים את מקומם, התמונה סוף סוף שלמה."},"ICON-0151":{"nm":"סרגל","de":"מדידת אורך היא גם דרך לשמור הבטחה. כדי שכל טווח יד יהיה זהה עבור כולם, הסימונים מסתדרים ביושר. קו ישר אחד יכול אפילו ליישר לב עקום."},"ICON-0152":{"nm":"קנבס","de":"משטח לבן ריק הוא המפחיד ביותר, וגם המרגש ביותר. עד שהנקודה הראשונה מונחת, הוא יכול להפוך לכל דבר. ריקנות אינה סוף, אלא שם נוסף להתחלה."},"ICON-0153":{"nm":"קוביה","de":"לא מעטים הם אלה שנשארו ערים כל הלילה בניסיון ליישר את כל שש הפאות. עקשנות קצות האצבעות שמסובבות שוב ושוב. ברגע שהצבעים המעורבבים מוצאים את מקומם, יקום קטן מסתדר בסדר מופתי."},"ICON-0154":{"nm":"קונסולת משחקים ניידת","de":"מסך קטן שבני דודים היו מתכנסים סביבו בזמן חופשות בית הספר. עולם הרפתקאות שנכנס בול לתוך כף היד. די בתו אחת של מנגינת ההדלקה, וקיץ שלם ההוא חוזר בשטף."},"ICON-0155":{"nm":"אחיזה","de":"התחושה של ההתכנסות ביד כשלוחצים חזק מעניקה בעדינות ביטחון עצמי. כדי לא להחליק, כדי לא לאבד את האחיזה. ברגע הקריטי ביותר, זו נקודת החיבור שקושרת יד וכלי לגוף מוצק אחד."},"ICON-0156":{"nm":"עט נובע","de":"בזמן הכתיבה עם דיו שהתמלא מחדש, אפילו כתב היד נעשה מסודר יותר במקצת. מיישבים את הלב לצליל החריקה של הציפורן, בדומה שקט לקפידה של תחילת השורה הראשונה במכתב כתוב יד."},"ICON-0157":{"nm":"פלטת צבעים","de":"אדום לצד כחול, ירוק מעל צהוב. על הלוח הקטן הזה שבו הצבעים שוכבים מסודרים זה לצד זה, הציור סוף סוף מקבל את הבעתו. כל הרפתקה של ערבוב ושכבות מתחילה כאן את צעדה הראשון."},"ICON-0158":{"nm":"סט","de":"כל חלק לחוד עשוי להיות פשוט, אך כשהם מתכנסים יחד הם הופכים לסיפור אחד. הביטחון הזה כשכלום לא חסר וכל דבר במקומו. באיסוף דברים מפוזרים למקום אחד שוכנת שמחת השלמה קטנה."},"ICON-0159":{"nm":"כדורנוצה","de":"קול הרוח הרך שהנוצות מפיקות כשהיא ממריאה מעל המחבט. נדמה שהיא קלה מכדי לעוף רחוק, אך כשמכים בכוונה, היא טסה ישר עד קצה המגרש. גם קלילות היא צורת עוצמה ראויה."},"ICON-0160":{"nm":"אנטנה","de":"היא עומדת בשקט אל מול השמיים, מנסה ללכוד אותות בלתי נראים. הסבלנות למשוך אליה גם קולות רחוקים בסוף. בימים שהקליטה חלשה, מספיק להטות מעט את הזווית והיא מתבהרת שוב."},"ICON-0161":{"nm":"סטטוסקופ","de":"הקצה העגול הקר על החזה, ונשימה שנעצרת לרגע. אוספים את האוזן אל פעימה קטנה אחת, והקצב העתיק ביותר של החיים עובר אל קצות האצבעות. כלי שבו ההקשבה קודמת לכל."},"ICON-0162":{"nm":"רגלי שחמט","de":"חייל קטן שצעד רק משבצת אחת לאט בכל פעם. ובכל זאת, ברגע שהוא מגיע לשורה האחרונה, הוא יכול להפוך לכל דבר. לוח השחמט הישן צופה בשקט במהלך האחד ההוא, שבצעד מגושם הופך את כל המשחק."},"ICON-0163":{"nm":"בקר משחק","de":"זוכר את הלילות שנדדת ביקום עם שני אגודלים? האחיזה השחוקה שהשלכת בכעס אחרי הפסד, ואז אספת בהתחשק שוב. השיחה הארוכה והחמה ביותר שחלקת בלי מילה עם מישהו מעבר למסך."},"ICON-0164":{"nm":"קונסולה","de":"מדליקים את המתח, וצליל אתחול קטן מצלצל כמו ברכת שלום. הקופסה המרובעת שהדלקת וכיבית מתחת לשמיכה לאורך כל החופשה, ההרפתקה הראשונה של ילדות תמיד החלה באור הבוהק של המסך הזה."},"ICON-0165":{"nm":"ציר זמן","de":"הקצה השמאלי הוא ההתחלה, הקצה הימני יום שטרם הגיע. גוררים נקודה אחת לכל מקום ביניהם, ורגע ששכחת שהוא קיים נפרש שוב. מקום שבו הזמן מונח שכוב בשורה אחת."},"ICON-0166":{"nm":"מנסרה","de":"מי היה מאמין שאור שנראה צלול לגמרי החזיק בתוכו שבעה צבעים כל הזמן. הסוד שנפרש לקשת ברגע שהוא חוצה שביב זכוכית. ככל שדבר נראה מסודר יותר מבחוץ, כך צבעים רבים יותר מסתתרים בפנימו."},"ICON-0167":{"nm":"טי גולף","de":"משטח קטן אחד להניח עליו את הכדור בעדינות. ככל שרוצים לשלוח אותו רחוק יותר, כך צריך תחילה משהו שיתמוך בו איתן. היתד הקטן הזה על הדשא נושא את הצעד הראשון."},"ICON-0168":{"nm":"מסרגה","de":"תפר אחד, ועוד אחד. מפילים תפר אחד, וצריך לפרום הכל ולחזור להתחלה. הצעיף שהתארך לאט על הברכיים לאורך עונת חורף, המקום שבו סבלנות קצות האצבעות נארגה לחום."},"ICON-0169":{"nm":"קו מנגינה","de":"קו מנגינה אחד שדלף מהשפתיים בזמזום עוד לפני שהמילים הונחו מעליו. בתוך הלחן המעורפל ההוא, עוד ללא מילים, שוכנות פניה הכנות והראשונות ביותר של השיר."},"ICON-0170":{"nm":"מכ\"ם","de":"הוא יורה אות אל תוך החושך שאינו רואה, וממתין בשקט לנקודה אחת שתחזור. הסבלנות של האור הירוק העגול, המאמין שמשהו נמצא שם גם כשכלום לא נראה."},"ICON-0171":{"nm":"לוח קצב","de":"נקישה קלה אחת, ואור וקול קופצים בבת אחת. מקום שגורם לידיים לזכור את הקצב לפני שהראש זוכר. הבמה הקטנה והחמה ביותר, הנפרשת על כף היד."},"ICON-0172":{"nm":"צבע","de":"ציירים עתיקים טחנו אבן ואדמה כדי להשיג צבע. כחול אינדיגו מהעשב, אדום מהאדמה. גם בטיפה האחת הזאת שנסחטת עכשיו על קצות האצבעות, זורמת הקפידה העתיקה של העברת הטבע בעדינות אל תוך כלי."},"ICON-0173":{"nm":"קו","de":"הדבר שנולד רק ברגע שמחליטים לחבר נקודה לנקודה. קצר או ארוך, מעוקל או ישר, זהו העקבה הפשוטה ביותר שמותיר הרצון ללכת לאיזשהו מקום. תחילתו של כל ציור."},"ICON-0174":{"nm":"תריס מצלמה","de":"קליק — חשכה קצרה אחת אוחזת סצנה לנצח. אפילו הבעה שכמעט חמקה בין ריצוד ריסים, היא חותכת מעט אור ומקשה אותו לזיכרון. להב קטן."},"ICON-0175":{"nm":"חבל ביטחון","de":"החבל שנקשר איתן צעד אחד לפני מי שמטפס גבוה. הוא אוחז במקומך את הלב הדואג לנפילה, שומר על צדך בלי להיראות, חוט של הבטחה. הוא תמיד מאחורי גבך."},"ICON-0176":{"nm":"מנעול","de":"המנעול הכבד והברזלי שנתלה על האסם. הוא לא נועד לכלוא דבר, אלא היה משאלה להשאיר את היקר בשקט ובביטחון. גם היד שנעלה אותו נשאה בה קפידה, יציבותו החמימה של בית ישן."},"ICON-0177":{"nm":"מאזניים","de":"כשצד אחד מכביד, הצד השני נעשה קל מאליו. באותו רגע של היסוס לגבי מה ובאיזו כמות להניח, האדם לומד הוגנות. שתי זרועות שמלמדות איזון בהתנדנדות."},"ICON-0178":{"nm":"מפצל","de":"גם מה שמחובר היטב, אם הולכים לפי הסיב, בסוף נבקע. כלי קטן לחלק כל דבר לשניים ולהציץ פנימה. קצות אצבעות סקרניות, הרוצות לפרק שוב את מה שחובר יחד ולהביט בו מחדש."},"ICON-0179":{"nm":"מונה","de":"אחת, שתיים, שלוש. חבר קטן שסופר מספרים בשקט במקום האצבעות. הוא הופך את הלב הדואג שמא יפספס ספירה, נקישה אחר נקישה, לרוגע. בן לוויה חמים של החישוב."},"ICON-0180":{"nm":"סמן","de":"חץ קטן שמהבהב אי שם על המסך, ומחכה לפקודה הבאה. גם בזמן ההיסוס, הוא לא עוזב את מקומו, קצה האור שמורה בשקט: בואו נתחיל עכשיו."},"ICON-0181":{"nm":"תפס טיפוס","de":"הנקודה האחת שנתפסת אחרונה, רגע לפני שהכוח נגמר מקצות האצבעות. יש רגעים שמחזיקים מעמד רק בכוח הרצון לא להרפות, כך מספר בשקט הבליטה הקטנה שעל הקיר."},"ICON-0182":{"nm":"חלוק נחל","de":"אבן שהתגלגלה זמן רב בנחל, וויתרה על כל פינותיה. להיעשות עגול הוא שם נוסף לזמן שנשחק. אוחזים אותה בעדינות בכף היד, וניתן לחוש בסבלנותו של הנהר הזורם."},"ICON-0183":{"nm":"סמל משפחה","de":"משפחות עתיקות חרתו חיות וכוכבים על דגל אחד כדי להכריז על עצמן. תמונה שהעבירה את הלב לפני שהמילים הספיקו. סימן עתיק, הדוחס בקפידה את גאוותו של אדם אחד לתוך משבצת קטנה אחת."},"ICON-0184":{"nm":"מגן","de":"לעמוד בדרך תמיד היה למען מי שעומד מאחורי הגב. לקלוט חצים מתעופפים במקומו, כדי לשמור על יומו הרגיל של מישהו — קיר כבד ועם זאת עדין."},"ICON-0185":{"nm":"תחייה","de":"יש לב שכבה ונדלק מחדש. רק לאחר נפילה אחת אפשר סוף סוף ללמוד איך לקום מחדש. נשימה שנייה שעולה בשקט בדיוק במקום שנחשב לסוף."},"ICON-0186":{"nm":"קשת","de":"היד שמתכוונת לשלוח רחוק מושכת תחילה את המיתר עד הסוף. כדי לשחרר, צריך קודם לחבק קרוב באותה מידה — כך אומר בשקט ובלי מילה מוט הקשת המתוח והכפוף."},"ICON-0187":{"nm":"לב","de":"המילים \"אני מחבב אותך\" הולכות ומתכווצות לצורה קטנה. הצורה הזאת המצוירת בערמומיות בקצה מקל האור, או בין שתי אצבעות נוגעות. הקיצור הנפוץ וההגון ביותר של הלב."},"ICON-0188":{"nm":"ענן","de":"נסחף לאט לכיוון הרוח, והופך לפרצוף שונה בכל פעם. ארנב, ואז צמר גפן, בלי להחזיק דבר לאורך זמן ובלי להפסיק לשחרר — הלב הקל ביותר של השמיים."},"ICON-0189":{"nm":"מבוך","de":"מקום שבו לומדים איך לחזור מקיר ללא מוצא. גם בזמן התעייה, הצעדים גדלים לאט לעבר היציאה. צריך לאבד את הדרך פעם אחת כדי לפתח חוש כיוון."},"ICON-0190":{"nm":"שן","de":"הייתה מנהג של זריקת שן שנשרה אל הגג. משאלה קטנה שהשן החדשה תצמח ישרה. הבטחה עדינה מימי הילדות, שצריך לאבד משהו פעם אחת בגדילה כדי להשיג משהו חזק יותר."},"ICON-0191":{"nm":"כוכב לכת","de":"גוף עגול שמקיף כוכב מבלי לסטות מעולם מנתיבו. נראה בודד, אך הכבידה שלו תמיד גורמת למשהו לסובב לצדו. להחזיק במקום בשקט הופך בעצמו לעולם שלם."},"ICON-0192":{"nm":"כוכב","de":"בלילות שאיבדו בהם את הדרך, אנשים הביטו כלפי מעלה אל הנקודה הבוהקת ביותר. אור רחוק מהישג יד, אך מורה בבירור על הכיוון. הבטחה שנעשית איתנה יותר בשל היותה רחוקה."},"ICON-0193":{"nm":"צללית","de":"עומדים עם הגב לאור, ומאדם נותר רק המתאר. צורה שחורה אחת, ששמה והבעתה נמחקו. חלל ריק שדווקא בשל ריקנותו גורם לנו לדמיין עוד יותר."},"ICON-0194":{"nm":"אוזן","de":"כדי לשיר היטב, צריך תחילה להקשיב היטב. גם הקצב וגם הלב מתחילים בסופו של דבר בהקשבה. דלת קטנה שנפתחת עגולה, שכל צלילי העולם מגיעים אליה ראשונים ושוהים בה."},"ICON-0195":{"nm":"עלה נושר","de":"יש עלים שזוהרים הכי יפה ברגע נפילתם. הקלילות של לשרוף את כל הירוק של העונה לאדום ולהניח אותו בעדינות. הסתיו מראה לנו שגם סיום יכול להיות יפה כל כך."},"ICON-0196":{"nm":"ירח","de":"היו לילות שבהם אספו כפות ידיים וביקשו משאלה תחת האור העגול של החג. פנים שלא היו זהות אף פעם, בהתמלאות ובהתרוקנות חוזרות ונשנות. פנס שמשתנה ובכל זאת תמיד מאיר את אותו מקום."},"ICON-0197":{"nm":"לב פועם","de":"גם על הבמה, הדבר הכן ביותר הוא בסוף הפעימה הזאת. הוא לא נעצר גם כשרועד, ופועם חזק יותר כשמתמלא. תוף קטן ואדום, הפועם במקומך את העידוד שהמילים לא הספיקו לבטא."},"ICON-0198":{"nm":"צל","de":"בן לוויה שלעולם לא נופל כל עוד יש אור. מחשיך ככל שבהיר יותר, ומתבהר ככל שעכור יותר — אני נוסף שליווה אותי הכי הרבה זמן. אדם אחד שעומד לצדי גם בימים בודדים."},"ICON-0199":{"nm":"זנב","de":"מתנועע מאליו כשמאושר, ומתכווץ בחשאי כשמפחד. הקצה הכן שלא מצליח להסתיר את הלב עד הסוף, גם כשהפה סגור חזק. הרגש הפנימי שהגוף מדליף ראשון."},"ICON-0200":{"nm":"סרט קשירה","de":"חוט קטן שקושרים בקצה לסיום, כמו סרט. הלב שקשר את המקשה עוד פעם אחת, חזק, כדי שלא תיפרם. סיום עדין שאוסף ומרגיע יחד את הדברים הנוטים להתפזר."},"ICON-0201":{"nm":"אישון","de":"אפשר לבחור מילים, אבל את המבט בעיניים אי אפשר להסתיר. המקום שבו לב שנחשף דולף ראשון, בתוך אותו עיגול שחור. גם כשבולעים את המילים \"אני מחבב אותך\", האישונים כבר רוטטים לקראתך."},"ICON-0202":{"nm":"פרסה","de":"פיסת ברזל שהתחזקה ככל שקצה הפרסה נשחק מריצה בדרכים ארוכות. תלו אותה הפוכה מעל הדלת, כי כך, אמרו, המזל הבא וההולך יצטבר בתוכה. בשקט היא תומכת בשובו הבטוח של מישהו הביתה."},"ICON-0203":{"nm":"אבן סמל","de":"גם כשרוח וגשם משחקים את האותיות עד טשטוש, מגע קצות האצבעות מחזיר לחיים את החריטה בבירור. משקלו של לב שלא רצה להישכח. כך אבן נושאת שם אחד זמן רב."},"ICON-0204":{"nm":"קרום שחייה","de":"בעזרת קרום דק אחד המחבר בין האצבעות, לומדים לדחוף את המים. משוט קטן שהטבע החליק לתוך כף היד של שחיין מגושם. עיצוב עדין שגם כשהוא איטי, מביא בסוף אל עבר הנהר השני."},"ICON-0205":{"nm":"נצנצים","de":"כולם מתלוננים שהם נדבקים לימים כשהם נוגעים בידיים, ובכל זאת ביום חגיגה כולם מושיטים יד ראשונים אל גרגירי האור האלה. פזרו קומץ אבק כוכבים, ואפילו נייר רגיל נוצץ, והיום הופך למיוחד."},"ICON-0206":{"nm":"טופר","de":"חיות היער שורטות באדמה בטפריהן ומשאירות את שבילן. לא איום אלא עקבה - חתימה שקטה שאומרת \"כאן עברתי\". קצה חד יכול, למישהו, להפוך לתמרור עדין."},"ICON-0207":{"nm":"ברק","de":"ברגע שהשמיים פורשים לרגע את קווי כף היד, האור מגיע לפני הרעם. כאילו מבקש ממך לשאוף נשימה אחת לפני שהקול הגדול יגיע. פחד והשתאות נולדים תמיד יחד מאותו הבזק."},"ICON-0208":{"nm":"קמע","de":"שורת משאלה אחת שנלחצה בדיו על נייר אדום. האמינו שכאשר הוא מונח מתחת לכרית, חלומות רעים סוטים הצידה. לב שמתפלל לשלומו של מישהו חם כל כך, גם בדף נייר דק אחד."},"ICON-0209":{"nm":"כנף מכחול","de":"יש רגעים שבהם קצה המכחול הופך לכנף. הקלילות ההיא של החלקה על פני הנייר בעת משיכת קו אחד. שכתיבה היא בעצם מעין תעופה - היד הזקנה שטחנה דיו ודאי ידעה זאת באופן מעורפל."},"ICON-0210":{"nm":"עצם","de":"הדבר שנשאר רק אחרי שכל הבשר התפורר. השלד הלבן ששרד עד הסוף כי היה החזק ביותר. עדות שקטה אחת שזוכרת, לפחות, את הצורה, גם כשהזמן לוקח את כל השאר."},"ICON-0211":{"nm":"אף","de":"ריח הוא הדרך הקצרה ביותר אל הזיכרון. ניחוח השמן במטבח החג, האוויר הקר של בוקר אחרי שלג ראשון - קצה האף קולט זאת ראשון, והלב מגיע פעימה אחת אחריו."},"ICON-0212":{"nm":"טוסט","de":"הארוחה המהירה ביותר לתפוס ביד בבוקר עמוס. נגסו בפני השחומים הקלויים, ומנת האומץ ליום שלם מתפוררת בפריכות. דברים שלא צריכים להיות מרשימים אבל משביעים, מקימים אדם מחדש."},"ICON-0213":{"nm":"עוגייה","de":"מי שחיכה הכי הרבה זמן ליד התנור זוכה בביס הראשון. חום הקצה שזה עתה נאפה, מתיקות רגעית. עוגיות שנאפו תוך מחשבה על מישהו הן, משום מה, מתוקות עוד יותר."},"ICON-0214":{"nm":"חטיף","de":"אחר צהריים שבו האימון מתארך, שקית קטנה שנשלפת מעומק התיק. חלקו לשניים, והתחושה המשביעה, באורח מוזר, מכפילה את עצמה. קומץ עדינות שממלא את הלב עוד לפני הרעב."},"ICON-0215":{"nm":"קפסולה","de":"אף אחד לא יכול לדעת עד שפותחים אותה בסיבוב. מה שבתוך הקליפה העגולה הוא תמיד אותו פרפור לב. הריגוש הכן ביותר בעולם - שבו קונים ומוכרים מקרה קטן."},"ICON-0216":{"nm":"ידית דלת","de":"המקום שבו כל יד הפותחת ונועלת דלת נוגעת ראשונה. ברכת הבית הראשונה - מתחילה קרה ומתחממת בכף היד. ככל שנצברות עוד ועוד נגיעות יד, החדר הופך לאט לאט לביתו של מישהו."},"ICON-0217":{"nm":"טיול","de":"גם בהליכה ללא יעד יש טעם. זמן שבו פורמים מחשבות סבוכות חוט אחר חוט אל תוך הצעדים. שבים מהקפה אחת, והתשובה נשארת אותה תשובה, אך הלב לבדו קליל בהרבה יותר."},"ICON-0218":{"nm":"קורקינט","de":"שני גלגלים שדוהרים וחוצים סמטה צרה. גם אם לא מהר, הרוח נלקחת בכל הגוף. יש ימים שבהם רק רוצים לרכוב היום ברעננות, טוב גם אם לא מגיעים רחוק."},"ICON-0219":{"nm":"מוט בטיחות","de":"לפני העלייה, מוט אחד היורד בחוזקה מול החזה. הבטחה מרגיעה שתלווה אותך עד סוף הקטע המפחיד. הוא אומר, בקור וללא מילה, שמותר להיאחז חזק."},"ICON-0220":{"nm":"מדרגות","de":"מטפסים מדרגה אחר מדרגה, ולפתע הנוף כבר השתנה. כפות הרגליים לומדות ראשונות שאין גובה שמגיעים אליו בקפיצה אחת. העלייה והירידה עצמן היו, למישהו, מנת הצעדים של יום שלם."},"ICON-0221":{"nm":"טרריום","de":"זה לא לכלוא יער בזכוכית, אלא לטפח עולם שלם בתשומת לב. יקום בגודל כף יד שבו טחב מתפשט וטיפות מים נקוות. ככל שמסתכלים פנימה יותר, הלב נצבע לאט לאט בירוק."},"ICON-0222":{"nm":"דוכן","de":"מטפסים למקום גבוה במעט, והנוף הנראה משתנה. מקום שבו פחד וגאווה נפגשים באותו הגובה. תלוי מי עומד שם, אותה מדרגה אחת הופכת בכל פעם לבמה אחרת."},"ICON-0223":{"nm":"מטוס","de":"ברגע שהעננים נפרשים מתחת לרגליים, המקום שעזבת סוף סוף מתגעגע. זו לא התרחקות, אלא העולם שמתרחב. גם חלום שגדל על אי קטן חוצה כך את השמיים."},"ICON-0224":{"nm":"סקייטבורד","de":"דבר שרק אחרי שלומדים ליפול אפשר באמת לרכוב עליו. בכל פעם שהברך נשרטת, שיווי המשקל נחרט מעט יותר בגוף. ארבעה גלגלים כנים שמתגלגלים רחוק יותר בזכות כל נפילה טובה."},"ICON-0225":{"nm":"דרכון","de":"פותחים את הכריכה, ודפים ריקים מלאים אותו. כל חותמת שתתמלא הופכת לעדות של חיים שחיו. ספר קטן שנושא בתוכו לא כמה כבר ראית, אלא את האפשרות ללכת לכל מקום."},"ICON-0226":{"nm":"מפה מצוירת ביד","de":"אין בה מרחק מדויק או קנה מידה, אבל בהיותה שביל שצויר ביד, אין חשש ללכת לאיבוד. נייר שבו סמטאות ושמות חנויות משתרגים בחום. הדרכה שיש בה לב תמיד חמה יותר מהדרך עצמה."},"ICON-0227":{"nm":"תרשים תנועה","de":"נייר שבו כל צעד על הבמה מצויר כקו. איפה לעצור, איפה לפנות - החצים מבטיחים מראש. גם ריקוד שנראה חופשי מתחיל, למעשה, מדף אחד זה."},"ICON-0228":{"nm":"כרטיס הכוונת מושבים","de":"במרחב זר, הדבר הראשון שמגששים למצוא הוא המקום שלך. עוקבים אחר שורה ומספר עד שמגיעים סוף סוף לאותו תא אחד. דף נייר בודד מיישב אלפי פרפורי לב, כל אחד במקומו המסודר."},"ICON-0229":{"nm":"כרטיס הדרכה לסמטאות","de":"הדרכה שמישהו כתב בכתב ידו למען מי שעלול ללכת לאיבוד בסמטאות דמויות מבוך. כתב היד החם המורה באיזו פינה לפנות. חמימות השכונה נכתבה, אות אחר אות, בכרטיס קטן אחד."},"ICON-0230":{"nm":"כרטיס אבטחה","de":"רק כשתולים כרטיס זה על הצוואר נפתחת סוף סוף הדלת אל העולם הפנימי. הרשאה קטנה המתירה כניסה, ואות שקט לכך שאתה שייך לכאן. רק מי שיודע כמה זמן לקח להשיג אותו, מכיר את משקלו."},"ICON-0231":{"nm":"צמיד כניסה יומי","de":"רתמו אותו פעם אחת לפרק היד, ואתה חבר של אותו היום עד שמסירים אותו. סרט נייר אחד מפריד בין פנים לחוץ, והופך לסימן שביליתם את אותו היום יחד. גם אחרי שקרעו אותו, העקבה נשארת עוד זמן רב."},"ICON-0232":{"nm":"תג אורח","de":"תג שם קטן אחד שנצמד לחזה, ומקום זר הופך למקומך. כשהמילה \"ברוך הבא\" מועברת על גבי דף נייר אחד, גם מי שהגיע לראשונה הופך סוף סוף לאורח."},"ICON-0233":{"nm":"צינור פוסטרים","de":"גליל מוצק ששומר על פוסטר מגולגל בלי קמט אחד. כי ככל שהתמונה יקרה יותר, כך צריך לשלוח אותה פרושה וישרה. את הפנים אי אפשר לראות, אך הוא יוצא לדרך נושא בתוכו מסירות של מישהו."},"ICON-0234":{"nm":"כריכת קלסר","de":"הדף הראשון העוטף חבילה עבה של מסמכים. הפנים שהיד נוגעת בהן לפני התוכן. כאשר הכריכה מסודרת, גם הגישה שבפנים נראית מסודרת - התחלה עדינה של פורמליות קטנה."},"ICON-0235":{"nm":"גלויית מזכרת","de":"כותבים ברכה על פיסת נוף רחוק ושולחים אותה לדרך. עד שהיא מגיעה, גם הלב ששלח הזדקן קצת ונעשה יקר יותר. חום איטי של מכתב כתוב ביד שהודעה על מסך אף פעם לא באמת משיגה."},"ICON-0236":{"nm":"תווית מתנה","de":"פתק נייר קטן שנקשר על מתנה. במילה אחת בלבד, \"בשבילך\", העטיפה כבר שלמה. המכתב הקצר ביותר בעולם - כותב לא מה נותנים, אלא במי חשבו."},"ICON-0237":{"nm":"גליל מדבקות עטיפה","de":"בכל פעם שקורעים חתיכה אחת לשימוש, הגימור יוצא הרבה יותר מסודר. קשר קטן שאוחז בקפידה בקצה שרוצה להתרפות. המהלך האחרון של עטיפה שנעטפה בקפידה תמיד מגיע מהסרט המגולגל הזה."},"ICON-0238":{"nm":"שרוול שקוף למכתבים","de":"שכבה שקופה העוטפת מכתב כתוב ביד כדי שלא יִדהה עם השנים. האותיות נשארות גלויות, אך מגע הידיים לא מגיע אליהן. קרום בלתי נראה שומר בשקט על לבו המחבב של מישהו."},"ICON-0239":{"nm":"חותם שעווה צבעוני","de":"הנקודה האחרונה הסוגרת מעטפה - ככל שהצבע בהיר יותר, כך פחות מהלב דולף החוצה. הבטחה שאף יד לא נגעה בה עד שהיא נקרעת. גם לסוד דרוש קשר יפה כזה."},"ICON-0240":{"nm":"פנקס פתקי מסר","de":"ספר קטן הכורך יחד פתקים קצרים. כל דף הוא מילה אחת שמיועדת למישהו. אספו, אחד אחד, את המילים שלא הצלחתם לומר, ויום אחד יגדל האומץ למסור אותן בוודאות."},"ICON-0241":{"nm":"שלט מתקפל","de":"פתוח, והוא אומר \"מכאן\"; מקופל, והוא אומר \"זהו זה להיום\". רגליו פשוקות בפתח הסמטה, הוא עומד יום שלם למען מישהו שעלול ללכת לאיבוד. הערב שבו הוא מתקפל הוא, עבורי, המנוחה העדינה ביותר."},"ICON-0242":{"nm":"סרט מיון דואר","de":"כשעוטפים ערמת גלויות סביב המותן, ברכות שהיו עומדות להתפזר הופכות סוף סוף לחבילת לב אחת. סרט קל אחד קושר בסדר את המילים ההולכות למקומות רחוקים, ומלווה בשקט את הגב היוצא לדרך."},"ICON-0243":{"nm":"צרור פתקי תודה","de":"מכיוון שמילת התודה תמיד מחליקה מהלשון, כותבים אותה על נייר בגודל כף יד וקושרים בשקט. ככל שהצרור מתעבה, כך גדל בד בבד עובי הלב החייב למישהו."},"ICON-0244":{"nm":"דף דוגמת קריאות עידוד","de":"דף דוגמה שכתוב עליו \"צעקו ככה\". קריאת עידוד שעדיין לא הולבשה בקול נושאת רק פרפור שקט, כמו תווים ריקים שמחכים לפעימה הראשונה."},"ICON-0245":{"nm":"פתק בקשה לצילום מוקדם","de":"פתק המבקש לשריין הקלטה מוקדמת נשאר תמיד בתא של חמש בבוקר. הנייר הקטן רושם בשתיקה, כאילו הוא מבין הכול, את הלב שמקצר את השינה כדי לשמור מקום."},"ICON-0246":{"nm":"כרטיס תור למפגש מעריצים","de":"דף אחד שקובע באיזה תור תמסור את הברכה שלך. עמידה בתור אינה המתנה לתורך - היא השאלת סדר לרגע, כי אי אפשר לתת מספר לכמה שאתה מחבב."},"ICON-0247":{"nm":"צמיד מספר המתנה","de":"מספר אחד קובע את סדר התור להיום. בראש התור או בסופו, מי שעונדים את הסרט הקטן והקל הזה על פרק היד הם, בסופו של דבר, חברים בלב אחד שהתאספו לראות את אותה במה."},"ICON-0248":{"nm":"לוח מיון כרטיסי צילום","de":"אותם פנים, ובכל זאת שונים כל כך - רושמים בתא נפרד כל אחד. ככל שהלוח מתמלא, הלב מתסדר יותר, והתא היחיד שנשאר ריק מרעיד את הלב בציפייה למלא אותו היום."},"ICON-0249":{"nm":"דף בדיקת אלבומים","de":"גרסה, כרטיס צילום, ואפילו אם האריזה חתומה - רשימת חיבה שנכתבת במספרים. מדמיינים מראש את הגאווה של היום שבו הכול יתמלא, וגם היום מציירים בקפידה עיגול קטן על שורה אחת."},"ICON-0250":{"nm":"פתק שיטת עידוד","de":"תנוחת ידיים, קצב הצעקה, ואפילו נקודות לנשום. כדי שגם מי שמגיע לראשונה יתמזג במהרה לקול אחד, הפתק הקטן הופך למדריך אדיב שעובר מיד ליד."},"ICON-0251":{"nm":"פנקס פתקים פרטי","de":"בוחרים כאן רק את המשפטים שלא יוצגו לאיש. שהעמוד שמעולם לא נפתח הוא הכן ביותר - פנקס זה שומר בשתיקה, וכריכתו סגורה."},"ICON-0252":{"nm":"דף חותמות לימי זיכרון","de":"לוחצים, ויום נוסף הופך למיוחד. בחותמת קטנה אחת שמוטבעת על תאריך רגיל, \"היום\" נרשם בערמומיות ברשימת הימים הראויים להיזכר."},"ICON-0253":{"nm":"כיסוי ללוח כתיבה","de":"גם כשהרוח נושבת, גם כשהגשם חודר, הוא שומר עד הסוף על הנייר הצמוד. אני, שנטלתי על עצמי להיות שריון הלוח, שומר הראש הנאמן של האותיות הכתובות."},"ICON-0254":{"nm":"אינדקס לקלסר","de":"כדי שלא תלכו לאיבוד בתוך מסמכים עבים, הוא מוציא לשון קטנה ומכריז \"כאן\". תווית צבעונית אחת שולטת במאה עמודים במבט אחד."},"ICON-0255":{"nm":"תווית לשונית מיון","de":"זה בתא הזה, זה בתא ההוא. עבודתי היא לסדר את בלגן העולם, שורה אחר שורה. ברגע שהתווית נדבקת, הדברים המבולגנים מוצאים סוף סוף את מקומם."},"ICON-0256":{"nm":"לוח אישור מיני","de":"ברגע שהחותמת נוחתת בטפיחה, מרגישים משום מה ממש כמו מבוגר אמיתי. קטן בגודלו אך בעל סמכות ערנית - חותמת אישור אחת, והעבודה שהצטברה נגמרת במהירות."},"ICON-0257":{"nm":"תיק מסמכים שקוף","de":"הכול נראה מבפנים, אין מה להסתיר. הוא אוחז נייר חשוב, ופן ירטב בגשם או יתקמט, עוטף אותו בגופו השקוף ומוביל אותו עד מקום הפגישה."},"ICON-0258":{"nm":"סרט בדיקת נוכחות","de":"הגעת, ותא נוסף מתמלא. כשעקבות היום מצטברים בשורה לאורך הסרט, שקדנות בלתי נראית הופכת סוף סוף לדפוס הנראה במבט אחד."},"ICON-0259":{"nm":"מחברת טעויות","de":"לרשום מה טעית בו אינו אגירת בושה. כדי לא למעוד פעמיים באותו מקום, זוהי כתיבה מחדש של טעות אתמול כמדריך להיום."},"ICON-0260":{"nm":"לוח חותמות לוח זמנים","de":"מטביעים חותמת אחת על יומן ריק, ו\"תוכנית\" נולדת. הקסם של יום שנקבע בתנועת פרק כף יד אחת - קסם זה הוא, למעשה, שם נוסף לשקדנות של הכנה מוקדמת."},"ICON-0261":{"nm":"תווית לשדרת ספר","de":"תג השם של ספרים העומדים כשגבם פונה למדף. האותיות הקצרות הכתובות על השדרה הצרה קוראות בקריצה אחת, ותוך רגע מזמנות את אותו ספר בודד שחיפשת בין מאות."},"ICON-0262":{"nm":"מגן תמונה","de":"אסור לגעת בידיים חשופות. הוא אומר לא להשאיר אפילו טביעת אצבע אחת, ומכסה בעדינות בגופו את התמונה היקרה. כך לב אוהב מחזיק מעמד זמן רב, זמן רב, הודות למגע זהיר שכזה."},"ICON-0263":{"nm":"דף אינדקס לפילם","de":"מספרים כל שורת פילם, אחת אחר השנייה, והרגעים המפוזרים מוצאים מחדש את תורם בסיפור. מדריך קטן שמטפל בזיכרונות הכתובים באור, כדי שלא יתבלבלו."},"ICON-0264":{"nm":"כיס שקוף לתמונות","de":"בית שקוף שבו פיסות אושר מרובעות נשמרות אחת אחת. בלי חשש לפינות מעוכות, הפנים היקרים ביותר זוהרים כאן בטוהר לאורך כל ארבע העונות."},"ICON-0265":{"nm":"מעטפה מיני להדפסות","de":"לפני שחום התמונה שזה עתה נדפסה מספיק להתקרר, מעטפה קטנה פותחת שתי זרועות ומקבלת אותה בחיבוק. הצילום שנכנס דרך הפתח בגודל כף יד הופך, בלי שמרגישים, לאוצר בתיק של מישהו."},"ICON-0266":{"nm":"כיסוי הולוגרפי","de":"תפקידי הוא לשמור בלי שריטה אחת על תמונה גחמנית שהבעתה משתנה כשמטים אותה. להגן על כל פנים שונים בכל זווית וזווית - גם אני חייב להיות חרוץ מעל ומעבר."},"ICON-0267":{"nm":"תווית מיון תמונות","de":"מבין ארבע התמונות, איזו הכי טובה - התווית מצביעה במקומכם. משימה קטנה זו של הפרדת הצילום המוצלח מהמצחיק, זו בזו, היא הסוד ליהנות מהזיכרון פעמיים."},"ICON-0268":{"nm":"סרט לשמירת רצועת תמונות","de":"הוא עוטף בסדר רצועת זיכרון צרה וארוכה של ארבע תמונות. אוחז בחוזקה בצחוק אותו יום שעמד להתפזר, לתוך חבילה אחת, ומוביל אותו בשלום עד עומק התיק."},"ICON-0269":{"nm":"מדבקת פינת תמונה","de":"כשמדביקים תמונה באלבום, יד קטנה שאוחזת בעדינות בארבע פינותיה. כדי שלא תיפול בלי למרוח דבק בעובי - העדינות מתחילה כך, מהפינות."},"ICON-0270":{"nm":"לוח כיוונון הדפסה","de":"קצת יותר חם, מעט פחות בהיר. דף אחד שבו מתעסקים במספרים עד שמגיע הצבע הרצוי, הופך בשקט תמונה רגילה ליצירת אמנות."},"ICON-0271":{"nm":"תפס לקבלות","de":"הוא נושך בסדר את הקבלות המקומטות ולא מרפה. בפה הקטן שלו הוא שומר בקפידה על הוצאות היום, כך שהחישוב בסוף החודש הופך קליל בהרבה יותר."},"ICON-0272":{"nm":"פתק אישור הזמנה","de":"בשורה אחת, \"ההזמנה אושרה\", הלב נרגע לאיטו. דף נייר אחד הופך לעדות להבטחה, שומר את הריגוש מתאסף לאט לאט עד היום המצופה."},"ICON-0273":{"nm":"אישור החזרה","de":"עדות קטנה אך גאה לכך שהחזרת את מה ששאלת למקומו. ברגע שהנייר הזה נמצא בידך, חוב אחד שהכביד על פינה בלב נמחק בקלות."},"ICON-0274":{"nm":"מחזיק כרטיס איסוף","de":"כדי שלא תאבד את הכרטיס לאיסוף מה שהפקדת, אני אחזיק בו חזק במקומך. כי לפעמים מקום הימצאותו של פתק קטן אחד יכול להכריע את סוף היום של מישהו."},"ICON-0275":{"nm":"זנב תג השאלה","de":"תג קטן שמתנופף על כל חפץ מושאל. עקבו אחר הזנב הזה, ומיד יתגלה מי לקח מה, כך שגם תעלומת האבידה נפתרת במהרה."},"ICON-0276":{"nm":"דף בדיקת פיקוח","de":"בוחנים אחד אחד בעיניים כדי לוודא שדבר לא חסר. כשסימוני הוי מתמלאים בשורה, קפדנות בלתי נראית זוכה סוף סוף בשם אמון."},"ICON-0277":{"nm":"מעטפת פתק חשבון","de":"כשרושמים על המעטפה את הכסף שנכנס ויצא, המספרים המבולגנים נכנסים בשקט לשורה. סוף החישוב תמיד מגיע בזכות הפתק הקטן הזה, שמעמיד בנחת נקודה סופית."},"ICON-0278":{"nm":"תווית משלוח","de":"היא יוצאת לדרך כשגופה נושא רשום עליו לאן היא הולכת ולמי תגיע. ברגע שהתווית הזאת נדבקת, הקופסה הופכת לנוסעת בעלת יעד ויוצאת לדרך ברגש התרגשות."},"ICON-0279":{"nm":"סרט אישור קבלה","de":"הוא כורך את המילים \"התקבל בשלום\" בסרט אחד ושולח אותן בחזרה. הקלתו של מי שקיבל ורוגעו של מי ששלח לוחצים ידיים בשקט על החוט הקטן הזה."},"ICON-0280":{"nm":"טבעת כרטיסיות מילים","de":"מילים שהיו הולכות לאיבוד אילו התפזרו כדפים בודדים - טבעת קטנה אחת משחילה ומחזיקה אותן יחד. דפדפו שוב ושוב, והמילים הזרות פעם הופכות, בלי שמרגישים, לחברות ותיקות בלשון."},"ICON-0281":{"nm":"סרט פתקי הגייה","de":"תולים תג קטן במקום שבו קצה הלשון תמיד מחליק. גם צליל זר שאיבד את דרכו בפה מוצא, בלי שמרגישים, את הגייתו הנכונה כשעוקבים אחר הפתק הזה. העמוד הראשון של אילוף צליל מגושם, לאט לאט."},"ICON-0282":{"nm":"תיבת פתקי תרגום","de":"גשרים קטנים החוצים בין מילה למילה מקופלים בעדינות, כל אחד בתאו. כותבים מילה אחת שנבחרה בקושי ומעבירים אותה בחשאי, וגם לב שלא הצליח להתחבר מתקרב בזכות פתק בודד ביניהם."},"ICON-0283":{"nm":"דף גזירת ציטוטים","de":"משפט שנוגע ישר בלב נשאר רק אם מעתיקים אותו ביד. הדביקו שורה שנגזרה מפינת ספר מול השולחן, והאותיות ההן תומכות בשקט ביום שהיה שוקע."},"ICON-0284":{"nm":"אינדקס רישום","de":"דגלים קטנים צבעוניים שתוחבים כדי לא ללכת לאיבוד בתוך ספר עבה. רק כשיודעים לאיזה מקום לחזור אפשר לשוטט רחוק יותר - הלשוניות הבולטות אומרות זאת בשקט מבין הדפים."},"ICON-0285":{"nm":"שבב בדיקת שינון","de":"סימן אחד שמוטבע לצד מה שזכרו בעל פה. עוגן קטן שאוחז בדברים העוברים לרגע בראש ומנסים להיעלם - בכל תא שמוצבע בשחור טמון בשקט המאמץ שהושקע אמש בלילה."},"ICON-0286":{"nm":"חבילת מעטפות חידון","de":"עד שקורעים את המעטפה, אף אחד לא יודע מה יצא ממנה. אותן שניות ספורות של משחק אצבעות במקום החתום - צרור ריגוש שבו שאלה אחת מקופלת בעדינות, וההתרגשות חתומה יחד איתה."},"ICON-0287":{"nm":"מחברת לשוניות דקדוק","de":"כללים לא זוכרים בראש, לומדים אותם ביד. מהלשונית הצבעונית של העמוד הכי פתוח ועד המחברת הרכה שנשחקת, אותה פינה שחוקה הופכת לטבעת הגדילה של הזמן שהחזקת מעמד."},"ICON-0288":{"nm":"לוח תרגול דיבור","de":"דף אחד למען מי שפתיחת הפה היא הדבר הקשה ביותר בעולם. עוקבים באצבע כלפי מטה תא אחר תא, וגם המילה הראשונה שרעדה בגרון מוצאת, בלי שמרגישים, את קולה שלה. גם לאומץ יש תור."},"ICON-0289":{"nm":"דף טיוטת צבעים","de":"צבעים שטרם הושלמו שוכבים גולמיים, מתאווררים. לא תשובה נכונה אלא עדיין אפשרות - בדף גולמי זה, פחות מלוטש, נעה יותר ממה שנדמה כמות של מחר."},"ICON-0290":{"nm":"פיסת לוח השראה","de":"אספו והדביקו במקום אחד רשמים שהתפזרו לפרודות, ואווירה שקשה היה לתפוס חושפת לאיטה מתאר מעורפל. תחושה שעדיין אין לה שם - הפיסות נשענות זו על זו ומצביעות עליה בשקט."},"ICON-0291":{"nm":"ספר דוגמאות תבנית","de":"הרשת של מטפחת עטיפה ומארג סורגי החלון מסודרים בקפידה, עמוד אחר עמוד, בכרך אחד. במקום שבו אותה תבנית חוזרת עד הסוף שוכן לא עצלות אלא הבטחה - הלב היציב ששומר על קו אחד."},"ICON-0292":{"nm":"דף דוגמת בד תלבושת","de":"גם כשהאור אותו האור, המרקם והצל נספגים אחרת בכל פיסת בד. לפני בחירת תלבושת הבמה, אותו לילה של היסוס שבו ליטפת שוב ושוב בקצות האצבעות משומר שלם בדוגמית קטנה אחת."},"ICON-0293":{"nm":"דף הנחיות איסור לוגו","de":"נייר שרושם קודם, בבירור, את הדברים שאסור לעשות. בתוך המתאר המשורטט בקו X אדום, החירות דווקא מתבהרת יותר, כך שדרך חדשה נפתחת דווקא במקום שנדמה היה כמבוי סתום."},"ICON-0294":{"nm":"שבב התייחסות צבע","de":"צבע שאי אפשר בשום אופן להסביר במילים - לכן נוצרה דוגמית נפרדת. היא לוכדת על כף יד קטנה רגע מסוים שבו השקיעה הייתה האדומה ביותר, כדי שאפשר יהיה למסור לבא בתור, בדיוק, \"זה בדיוק הצבע הזה\"."},"ICON-0295":{"nm":"כרטיס טיוטת פריסה","de":"סקיצה ראשונה שסומנה בקלילות - מה למקם היכן. להחליט על המיקום זה בעצם להחליט על הלב, כך שבין הקווים המפוזרים בגמלוניות, איזון השלם פוקח את עיניו לאיטו."},"ICON-0296":{"nm":"לוח פתקי חומרים","de":"עץ, אדמה, אבן - שמות הדברים הנגישים למגע רשומים בצפיפות. סוד הידוע רק למי שמתחיל בקריאת המרקם ביד תחילה - ממה בונים כבר קובע, בחצי הדרך, מה זה יהפוך להיות."},"ICON-0297":{"nm":"נייר שקוף להעתקת שרטוט","de":"מניחים נייר דק מעל השרטוט ועוקבים בשקט אחר הקווים. בזמן ששואלים לרגע דרך של מישהו אחר, היד לומדת את הדרך ההיא, ובין הקווים המועתקים צומח, בלי שמרגישים, קו משלך."},"ICON-0298":{"nm":"סרט שביל כניסה","de":"אנשים נכנסים בשורה, בעקבות הסרט הארוך המודבק על הרצפה. קו אחד שמנחה בשקט כדי שהצעדים הנרגשים לא יתבלבלו - יד עדינה בלתי נראית שתומכת ברגש כדי שלא יתמוטט."},"ICON-0299":{"nm":"שלט הכוונה לאירוע","de":"שלט שעומד במקום המילים \"מכאן, בבקשה\". חסד קטן שהוצב בכל צומת כדי שאף אחד לא ילך לאיבוד, לוקח כמו ביד את יומו הזר של מי שמגיע לראשונה ומלווה אותו בשקט בהליכה."},"ICON-0300":{"nm":"תווית מספר דוכן","de":"מספר אחד שמוקצה לכל דוכן קובע בבירור את בעל אותו תא. מספר קטן, אך בהיותו ההבטחה ש\"זה המקום שלך\", הוא מעניק מקום לחזור אליו באירוע זר."},"ICON-0301":{"nm":"טופס הסכמת צוות","de":"חתימה אחת שנותרה במקום שבו לבבות הסכימו לעבוד יחד. זהו רק דף נייר דק אחד, אך בתוכו טמון המשקל של הבחירה לבטוח זה בזה, ומכאן, בדיוק כאן, מתחילה כל יד עוזרת באירוע."},"ICON-0302":{"nm":"חבילת כרטיסי התנסות","de":"ערמת כרטיסי התנסות שמנמנה, קשורה בעדינות כך שתשב בנוחות בכף יד אחת. ככל שמחלקים ממנה יותר, היא לא מצטמצמת אלא מעניקה עוד ועוד \"פעמים ראשונות\" לאחרים, צרור של נדיבות שמתחמם ככל שנוגעים בו יותר."},"ICON-0303":{"nm":"שלט סימון תור","de":"\"מכאן תמתינו,\" לוחש הרצפה בשקט. כשלבבות ששומרים על תורם מתאספים יחד, גם שורה ארוכה הופכת לתמונה משלה, וסימון קטן אחד הופך חוסר סבלנות לרוגע."},"ICON-0304":{"nm":"תווית איסוף עצמי","de":"תווית קטנה שנתלית בעדינות במקום שבו אוספים את מה שהוזמן מראש. ברגע שהיא בכף היד, ההקלה העדינה ההיא מחליקה מהכתפיים, קשר שבו לב שחיכה זמן רב סוף סוף מקבל צורה."},"ICON-0305":{"nm":"כרטיס קופסת הפתעה","de":"העונג שבבחירת אחת בלי לדעת מה בפנים. מנערים אותה והלב דוהר תחילה לקול הנקישות מבפנים, והרגע הקצר ההוא ממש לפני הפתיחה הופך לרגע התפוח ביותר בתקווה מכל היום."},"ICON-0306":{"nm":"מדבקת החלפה הושלמה","de":"חותמת עגולה קטנה שמכריזה שההחלפה עברה בשלום. זוהי הנקודה החלקה שנותרת בין הידיים שנתנו וקיבלו, וברגע שהיא נדבקת בטפיחה קלה, העסקה סוף סוף מתעגלת בחמימות."},"ICON-0307":{"nm":"סרט חתימת תיעוד","de":"תיבה יקרה עטופה פעם אחת בסרט ונחתמת בשקט. בקשה לא לפתוח בפזיזות, ואת הנימוס השקט ביותר של יקרת מה שבפנים, סרט אחד מכיל בתוכו."},"ICON-0308":{"nm":"קפסולת פתק סודי","de":"מילה שרצית לומר, סגורה בעדינות בתוך גליל קטן. אוטמים אותה חזק כמו קוברים רגש שלא הצלחת לשלוח, וכספת זעירה בכף היד שומרת על הזמן עד היום שבו תפתחו אותה שוב."},"ICON-0309":{"nm":"כרטיס גזירים קטן","de":"פיסה גזורה ומודבקת נושאת בעדינות את מצב הרוח של אותו יום. קלה יותר מיומן ואישית יותר מתצלום, דף בגודל כף יד אוחז חזק ביום שאחרת היה חומק בין האצבעות."},"ICON-0310":{"nm":"דף תיעוד ביקור ראשון","de":"הרטט של היום שבו דרכה כף רגלך לראשונה על האי הזה נשאר בשורה קצרה. ממש לפני שהזרות הפכה לחיבה, הנייר מחזיק במקומך את הרגש הראשוני והצלול ביותר, ושומר עליו זמן רב."},"ICON-0311":{"nm":"טבלת מיון זיכרונות","de":"טבלה שבה זיכרונות מסודרים לפי גוון וענף, נכתבים אחד אחד. לערום כל זיכרון במגירה אחת פירושו שגם היום היקר ביותר ייקבר, ולכן ככל שדבר יקר יותר, כך הוא מקבל בעדינות רבה יותר מקום משלו."},"ICON-0312":{"nm":"שבב פתק בועת דיבור","de":"המילים שרצית לומר תופחות עגולות כמו בלון וצפות על הנייר. אפילו משפט שלא הצלחת לבטא בקול מוצא בשקט אומץ בתוך המסגרת העגולה הזו, מעבר קטן וחם שדרכו הלב מצליח לחמוק החוצה."},"ICON-0313":{"nm":"מעמד לתאריך","de":"מעמד קטן שמציב את תאריך היום זקוף מולך. בוחרים יום אחד מבין כל הימים הזורמים ומושיבים אותו במרכז, וגם תאריך רגיל לגמרי זוכה בחמימות ראויה לחגיגה."},"ICON-0314":{"nm":"תווית מספר אוסף","de":"מספר ייחודי שהוקצה לכל דבר שיקר לך. לאסוף פירושו להישבע לקרוא לאותו דבר היחיד מסוגו בעולם, ולכן המספר על התווית הקטנה נושא במפורש את משקל הלב."},"ICON-0315":{"nm":"דף ארכיון","de":"שרוול פנימי דק שמחליקים לתוכו כל דבר שרוצים לשמור לאורך זמן, אחד בכל פעם. להרחיק משהו שכבה אחת בלבד מהאור ומהזמן, לאהוב משהו זה, בסופו של דבר, לדעת לשמור עליו היטב."},"ICON-0316":{"nm":"רצועת תולדר לצילום","de":"רצועה דקה שמאפשרת לתלות תולדר על הצוואר. זוהי דרך של פנדום, לצעוד את היום עם האידול האהוב קרוב ללב, ועל החוט הדק הזה קשורה לוויה עדינה של יום שלם."},"ICON-0317":{"nm":"סיכת מעמד לצילום","de":"בעזרת סיכה קטנה אחת, כרטיס הצילום עומד זקוף על השולחן. שכוב הוא רק דף נייר, אך עומד הוא הופך לפנים שפוגשות עין בעין, ויוצר בשקט מקום שהמבט יכול להישאר בו זמן רב."},"ICON-0318":{"nm":"קרום הולוגרפי לכרטיס צילום","de":"שכבת סרט דקה אחת שממנה זורמת קשת בענן עם כל שינוי זווית. שכבה שכולאת מעט אור מלבישה כרטיס רגיל באור כוכבים, קסם קטן שבו הבעה אחרת ניעורה ומנצנצת בכל תנועת שורש כף היד."},"ICON-0319":{"nm":"מגן קשיח לכרטיס צילום","de":"לחיצה אחת בלבד על הפינה, וזה מרגיש כאילו הלב היקר מתקפל גם הוא. שריון שקוף שמחבק חזק דף יקר אחד, וזהירות כזו תמיד מלווה יקרת אמת."},"ICON-0320":{"nm":"מגש סידור כרטיסי צילום","de":"מגש שטוח שמשכיב עשרות כרטיסי צילום מסודרים לפי כיוון, זה לצד זה. מפוזרים, הם רק ערמה, אך מסודרים בשורות הם הופכים לאוסף, וסדר החיבה נחרת בכל תנועת יד מסדרת."},"ICON-0321":{"nm":"מעטפת החלפת כרטיסי צילום","de":"כשמחליקים כרטיס צילום לתוך מעטפה כדי למסור אותו, קצות האצבעות מהססים לרגע. זו לא פרידה, אלא בקשה שהוא יהפוך לאהוב הלב של מישהו אחר. ברגע שמקפלים את שולי המעטפה, קשר קטן מחליף בשקט ידיים."},"ICON-0322":{"nm":"עט קישוט לכרטיס צילום","de":"את השטח הריק ממלא לא כתב אלא לב. בכל מקום שבו עובר החוד, נובטים לבבות וכוכבים זעירים, ודף נייר רגיל מתעורר כעידוד יחיד מסוגו בעולם. קישוט הוא רק שם אחר להתוודות."},"ICON-0323":{"nm":"טבעת קליפס לכרטיסי צילום","de":"נקישה, קול הקליפס שנסגר. במנעול קטן אחד, כרטיסים שכמעט התפזרו מתאספים לשורה אחת. גם אחרי טלטול יום שלם בתוך תיק, אף פינה לא נפגעת. יציבות היא כה שקטה."},"ICON-0324":{"nm":"נרתיק נשיאה לכרטיסי צילום","de":"הרגל התיישב מבלי משים ביד שפותחת וסוגרת את הרוכסן. גם בגשם פתאומי, גם בתוך המולת קהל, רק הפנים נשארים יבשים. לשמור את היקר ביותר במקום העמוק ביותר, זו העבודה העדינה שנקראת נשיאה."},"ICON-0325":{"nm":"רצועת צמיד למפגש מעריצים","de":"מעריצה אחת זכרה זמן רב כמה חמות היו ידי הצוות שקשרו את הרצועה על שורש כף ידה. קשר אחד מסמן שייכות למקום הזה, כאן, היום. הרצועה שנכרכה פעמיים כדי שלא תשתחרר, אוחזת את מלוא ההתרגשות של היום."},"ICON-0326":{"nm":"צמיד כניסה","de":"ברגע עצמו של המעבר בכניסה, הפנים והחוץ סוף סוף נפרדים בבירור. לובשים אותו יום שלם והוא מתרגל אל העור, ועד שמסירים אותו נותר סימן דק, כמו עדות למקום שבו שהית."},"ICON-0327":{"nm":"שבב פינת שיחה","de":"כשפינת השיחה נפתחת, שבב מתגלגל בעדינות. מי ידבר ראשון, איזו שאלה תיבחר, המקריות הקטנה הזו משנה את כל האווירה. גחמת שבב אחד חביבה יותר מכל תסריט כתוב."},"ICON-0328":{"nm":"כרטיס תור לאירוע חתימות","de":"תופסים מקום בתור כשבידכם פתק ממוספר. מספר 142. בזמן שסופרים את 141 שלפניכם, הלב סופר את תורו קודם. ההמתנה ארוכה, אך בזכות הפתק הזה גם הזמן הזה הופך לחלק מההתרגשות."},"ICON-0329":{"nm":"כפפת מגע חם","de":"ברגע שכפות היד נוגעות, הכפפה קולטת במקומך את החום החולף הזה. יד שהתחממה יום שלם למען מגע של חצי שנייה. גם מבעד לבד, אי אפשר לחסום את הרטט ההוא, וכל אחד מבין זאת רק אז."},"ICON-0330":{"nm":"סיכת תצלום זיכרון","de":"קליק, קול אחד, וההיום נשמר בדיוק כפי שהוא. בתוך המסגרת שמוחזקת יציבה בסיכה, גם חיוך מביך הופך יום אחד לתמונה הכי נכספת. תיעוד הוא התאוותנות העדינה ביותר לאחיזה ברגע."},"ICON-0331":{"nm":"תווית סרט למושב","de":"סרט קטן שתלוי על גב המושב מתנדנד גם בלי רוח. סימן שמישהו קשר, עקבה שאדם היה כאן. גם במושב הריק אחרי ההופעה, רק הסרט עדיין נראה זוכר את הקצב."},"ICON-0332":{"nm":"תווית בדיקת מתנות","de":"תווית מודבקת על כל מתנה ומתנה. האם נשלחה, האם נבדקה, האם משהו חסר. גם קבלת לבו של מישהו דורשת ניהול משק בית, ולכן המדבקה הקטנה הזו מחברת בין דאגה לדאגה בלי לפספס דבר."},"ICON-0333":{"nm":"דף זיכרון","de":"דף נייר שנכתב כדי לשמור ולחזור אליו לאורך זמן. מזג האוויר של אותו יום, מספר המושב, אפילו שם השיר האחרון. הזיכרון דוהה, אבל רק הדף הזה לא. גם לאחסון זיכרון דרוש טופס קטן."},"ICON-0334":{"nm":"תלולית למגבת עידוד","de":"משחילים לולאה בקצה המגבת והיא לא מחליקה מהכתף. בין ניגוב הזיעה, סיבוב מעל הראש, וחזרה לתלייה על הצוואר, חיבור קטן אחד שומר על תנועות העידוד רציפות ללא הפרעה."},"ICON-0335":{"nm":"קליפס לשלט עידוד","de":"קליפסים אוחזים חזק בשני קצות השלט. כך שגם כששתי הזרועות מורמות גבוה, האותיות לא מתקפלות או מתעופפות. כאן נמצא השחקן המשני הנאמן ביותר, שמיישר את המסר הרחק מהעין."},"ICON-0336":{"nm":"נרתיק אילום רעש","de":"הרוכסן מחליק לאט, בלי קול. שתיקה שתוכננה כך שלא יחמוק רעש אחד יחיד במקום שבו הובטח שקט. התחשבות היא לפעמים לגרום לעצמך לא להישמע, כך אומר בשקט הנרתיק הזה."},"ICON-0337":{"nm":"שבב קצב מחיאות כפיים","de":"בכל פעם שכפות היד נפגשות, השבב סופר את הקצב. טפח, טפח, טפח, מחיאות כפיים מפוזרות מתאספות ברגע מסוים לקצב אחד. הקסם שבו אלפי מחיאות כפיים הופכות לנשימה אחת, שבב קטן מסייע לו בשקט."},"ICON-0338":{"nm":"תיקיית שיטת עידוד","de":"פותחים אותה ושיטת העידוד כתובה שלב אחר שלב. איזה צבע להרים באיזו שורה, מתי להוסיף קריאה. גם מי שבא בפעם הראשונה הופך למשפחה תוך רגע בזכות התיקייה הזו. מדריך קטן לחלוקת הבטחה."},"ICON-0339":{"nm":"רצועת מניפה למושב","de":"קושרים רצועה לידית המניפה והיא לא נופלת גם אם מחליקה מהאחיזה. ביום חם, כשהמניפה מנפנפת ואחר כך שתי הידיים משתחררות לעידוד, היא מתנדנדת מהשורש. רצועה אחת מקררת את החום ואת ההתרגשות בבת אחת."},"ICON-0340":{"nm":"פיסת סרט נוצץ","de":"כשהאור פוגע בה, כל פיסה שוברת אותו בזווית אחרת. מניחים אותה על כף היד וקשת בענן זעירה מרצדת, והצבעים מתעוררים לחיים בכל נענוע. אולי נצנוץ הוא רק חלוקת אור לפיסות קטנות."},"ICON-0341":{"nm":"מוט שלט קטן","de":"פותחים את המוט הקטן והבד נמתח ברוח. מרימים אותו גבוה בשתי ידיים והאותיות מגיעות עד מעבר לקהל, מקפלים אותו והוא נכנס לפינת התיק. גודל הלב לא נמדד באורך המוט."},"ICON-0342":{"nm":"חבילת מדבקות עידוד","de":"על כל מדבקה ומדבקה חקוקה מילת עידוד. על יומן, על טלפון, על פינת המחשב הנייד, בכל מקום שמדביקים, היומיום נצבע בעידוד. כך לב חובב משאיר עקבות בכל מקום."},"ICON-0343":{"nm":"כריכת מגן לאלבום","de":"היד שעוטפת את האלבום בכריכה זהירה. כדי שהפינות לא ישחקו, כדי שלא ידהה בשמש. מוזיקה נשמעת באוזניים, אך את הדף הזה זוכרות הידיים. שריון של הלב ששומר קרוב לזמן רב על מה שיקר."},"ICON-0344":{"nm":"טבעת שרוולי דיסקים","de":"מכניסים דיסקים לשרוולים וכורכים בטבעת, והם הופכים לאלבום כרוך. קול ההפשלה בכל דף שמדפדפים בו נעים. לאסוף מוזיקה מפוזרת מסודרת ליד אחת, זו האושר השקט של אספן."},"ICON-0345":{"nm":"מחיצת אחסון למרצ'נדייז","de":"מחיצה אחת בלבד, וחפצים שכמעט התערבבו מוצאים את מקומם. כאן כרטיסי צילום, שם מחזיקי מפתחות, לידם מקלות אור. לארגן פירושו לבנות בית לכל חפץ. ברגע שהתא מתחלק, הבלגן הופך לסדר."},"ICON-0346":{"nm":"חוט אטימה לחבילת הפתעה","de":"קושרים בחוט את פתח חבילת ההפתעה, וגורלו של איש עדיין לא נחרץ. עד שמתירים אותו, כולם הם גיבורי התקווה שלהם עצמם. רטט קצות האצבעות בהתרת החותם הוא בדיוק העונג שהחוט הזה שמר עליו."},"ICON-0347":{"nm":"קופסת מיון מתנות מיוחדות","de":"המתנות המיוחדות עומדות בשורה לפי סוג בתוך הקופסה. גלויות עם גלויות, סימניות עם סימניות. מביטים בתאים שמתמלאים צפוף יותר ככל שהם גדלים, וכל הזמן שנאסף נגלה במבט אחד. למיין הוא בעצם לרשום רשימת זיכרונות."},"ICON-0348":{"nm":"תווית הפרדת גרסאות","de":"יש דברים שנראים זהים אך אינם. תווית אחת מפרידה בין גרסה A לגרסה B, בין הדפסה ראשונה לחוזרת. הודות לסימון קטן, הבלבול נעלם, ותג שם ברור אחד נצמד לעולם האספנות."},"ICON-0349":{"nm":"פתק בדיקת שבוע השקה","de":"שבוע ההשקה, ומספר אחד גורם ללב להתנדנד. סימוני וי כתובים בקפידה על פתק. אספו כמה ימים של רישום והם הופכים לתעודת הישגים קטנה של תמיכה. הרגל קפדני של תרגום לב חובב למספרים."},"ICON-0350":{"nm":"פקק קיבוע לפוסטר","de":"משחילים פקק בקצה פוסטר מגולגל, והוא נותר פרוש ורגוע. כדי שלא יתקמט בזמן שמתלבטים אם לתלות אותו על הקיר או להכניס למסגרת. פקק קטן ששומר את הסצנה האהובה ביותר ישרה בשלמותה."},"ICON-0351":{"nm":"מעמד לתצלום עומד","de":"התמונה עומדת נטויה על המעמד. בפינת השולחן, בזווית מדויקת לגובה העיניים. המצאה שגורמת לעיניים להיפגש בכל פעם שחולפים על פניה. הדרך הפשוטה ביותר להכניס פנים אהובות לנוף היומיומי."},"ICON-0352":{"nm":"גליל סרט לחזרות","de":"מדביקים סרט על הרצפה כדי לסמן איפה צריך לעמוד. תא אחד, שני תאים, בדיוק כאן. דורכים על אותם סימנים עשרות פעמים עד שהתנועה נחרטת בגוף. מתחת לבמה המרהיבה מונחים סימני הסרט הכנים הללו."},"ICON-0353":{"nm":"סיכת תנועת במה","de":"סיכה אחת נעוצה ברצפת הבמה מבשרת את הצעד הבא. גם בחושך, קצות האצבעות מוצאים את המקום ראשונים. דרך מדויקת שלא נראית, מפה בלתי נראית שציירו אינספור חזרות."},"ICON-0354":{"nm":"אטם אוזן לצוות","de":"מכניסים את אטם האוזן וקול הקהל השואג נחלש שכבה אחת, בעוד רק הקול שמעביר את הרמז נשאר צלול. אוזני הצוות מאחורי הקלעים תמיד שומעות שני עולמות בו זמנית. כלי קטן לבירור האות מתוך המהומה."},"ICON-0355":{"nm":"תווית קולב לחדר המתנה","de":"על כל קולב תלויה תווית שם. תלבושת 1, תלבושת 2, תלבושת הדרן. מביטים בטבלה שמפרטת את סדר ההחלפה, והבמה של היום מצוירת מראש לפי סדר הבגדים. סדר שקט ששולט במהומה."},"ICON-0356":{"nm":"תג בדיקת אביזרים","de":"לפני העלייה לבמה, תג מוצמד לכל אביזר ואביזר. האם משהו חסר, האם הכול תקין. הקהל לא יודע, אבל הבדיקה הקטנה הזו מונעת תקלות. מאחורי במה שנראית מושלמת תמיד יש יד קפדנית."},"ICON-0357":{"nm":"שבב אות רמז","de":"שבב האות עובר מיד ליד. עכשיו, תיכנס. רגע שבו התזמון מועבר בלי מילה אחת. בחשכה שליד הבמה, האות הקטן הזה שומר על כולם מלפספס את הקצב."},"ICON-0358":{"nm":"תלאי מאחורי הקלעים","de":"יש דלת שרק מי שעונד את התלאי הזה יכול לעבור דרכה. מאחורי הבמה, שם התשואות נשמעות מעבר לקיר. פיסת בד קטנה אחת מפרידה בין החזית המרהיבה לעורף העמוס. סימן של האנשים שמחזיקים את הבמה על כתפיהם."},"ICON-0359":{"nm":"לוח הצללה לפרומפטר","de":"לוח ההצללה מונע מאור הפרומפטר לדלוף אל הקהל. רק מי שעל הבמה רואה אותו, והצופים לא יודעים דבר. שומר אדיב של סוד הבמה, שמסתיר בשקט עזרה שאסור שתתגלה."},"ICON-0360":{"nm":"כיסוי מראה לחדר המתנה","de":"בחדר ההמתנה אחרי ההופעה, המראה מכוסה בבד. הזכוכית שהשתקפו בה אינספור הבעות במשך היום עוצמת עיניים לזמן מה. הפנים העירומות שנוקו מאיפור פוגשות לבסוף לא את המראה, אלא חושך שקט."},"ICON-0361":{"nm":"צמיד כניסה להקלטה מוקדמת","de":"רצועה קטנה שברגע שנקשרת לא משתחררת עד שגוזרים אותה. עבור הזכות היחידה להיכנס למושבי ההקלטה המוקדמת, מישהו עלה על הרכבת הראשונה בשחר האפל. משקל שורש כף היד הופך להתרגשות של יום שלם."},"ICON-0362":{"nm":"תווית המתנה להקלטה","de":"ממש לפני שהאור האדום נדלק, לכרוך את נשימת כולם לשורה אחת, זהו תפקידי. בדממה שממתינה לאות הרמז, אני מחזיק מעמד בשקט עד הרגע האחרון. ברגע שמקלפים אותי, מסך השידור החי סוף סוף עולה."},"ICON-0363":{"nm":"שבב מיקום מצלמה","de":"סימון קטן אחד שהוטבע ברצפה קובע בקפידה את מסלולי שש המצלמות. איפה הכי בהיר להצטלם, הבמאי יודע עוד לפני החזרה. יד שמציירת מראש את מה שבתוך המסך, מבחוץ למסך."},"ICON-0364":{"nm":"תווית בדיקת סאונד","de":"מקישים קלות על המיקרופון לעבר המושבים הריקים. אם ההד ארוך, עוד שכבת חומר סופג רעש בתקרה. הקפדנות שמלטשת את מרקם הצליל בלי שהקהל יידע, מתחילה בשקט מהתווית הקטנה הזו."},"ICON-0365":{"nm":"פנקס חותמות אתר","de":"בכל מעבר באתר אוספים עוד חותמת אחת בתא. בכל כתם דיו נמרח נחתמו יחד מזג האוויר ופעימת הלב של אותו יום. עמוד שמתמלא כולו הופך למפת עקבות שאיש אינו יכול לחקות, שלי בלבד."},"ICON-0366":{"nm":"רצועת תג מבקר בתחנת שידור","de":"בלי הרצועה הזו, שער הלובי לא נפתח. תלויה על הצוואר, בזמן שהולכים צעד אחר צעד במסדרון, העולם שראית עד אתמול רק מבעד למסך מתקרב לאט עד כדי מגע."},"ICON-0367":{"nm":"חבילת כיסויי נעליים לסטודיו","de":"רצפת הסטודיו תמיד קרה וחלקה. חולצים נעליים, לובשים כיסוי דק, וקול הצעדים נעלם בשקט. המצלמה תופסת את הריקוד, לא את הצעדים, ולכן מחיקת הקול היא גם היא נימוס כלפי הבמה."},"ICON-0368":{"nm":"תווית חטיף לחדר המתנה","de":"בין החזרה לשידור החי, הרעב מגיע בכנות רבה ביותר. תווית שם קטנה על כל חטיף בחדר ההמתנה, מציינת של מי הוא. אותה עדינות של הקצאה מראש היא זו שמעבירה אותך דרך היום הארוך והמתיש עד הסוף."},"ICON-0369":{"nm":"סרט פתקי צפייה חוזרת","de":"צופים בהקלטה החוזרת וכותבים. כאן את המבט, שם חצי פעימה. הכתב הצפוף הוא מכתב סודי אל העצמי של מחר. הסרט המודבק בקצה הוא הבטחה שקטה להיות טוב ביד אחת יותר מאתמול."},"ICON-0370":{"nm":"פתק הזמנה לשואקייס","de":"דף נייר אחד יכול להיות בשביל מישהו המתנה של שנה שלמה. משפט קצר אחד המזמין לשואקייס, נולד להזמנה הקטנה ביותר בעולם, ואוחז אפילו את רטט קצות האצבעות שפותחות את המעטפה."},"ICON-0371":{"nm":"רצועת תג לעיתונאים","de":"תלוי על צוואר איש התקשורת, חוצה את לב קול התריסים. צעדים ממהרים למצוא את הזווית הטובה ביותר, ומהירות זו עצמה הופכת למעבר שמעביר את חום הבמה אל העולם הרחב יותר."},"ICON-0372":{"nm":"לוח סדר קידת סיום","de":"כדי שאיש לא יתבלבל גם ברגע שהמחיאות ניגרות בזרם, מי ראשון ומי הבא נכתב בשורה אחת. סידור הקידה האחרונה נארג בקפידה בדיוק כמו הכניסה הראשונה."},"ICON-0373":{"nm":"סימון רצפה לקיר צילום","de":"מול קיר הצילום, מקום להניח בו את קצות הרגליים מסומן מראש ברצפה. צעד אחד בלבד הצידה והלוגו שברקע נחתך. סוד המיקום שבו הצילום יוצא הכי בהיר, מסומן בשקט מתחת לרגליים."},"ICON-0374":{"nm":"צמיד לבכורה","de":"רצועה קטנה שנקשרת לשורש כף היד ממש לפני שאורות האולם כבים. כשהמסך עולה, כולם פוגשים באותה חשכה, בפעם הראשונה בחייהם, את אותה סצנה בדיוק. סימן קטן של השתייכות לרגע הראשון ההוא, יחד."},"ICON-0375":{"nm":"פיסת וילון זיכרון","de":"ביום ההצגה האחרונה, אחרי הקידה האחרונה, הווילון ירד לאט. פיסה אחת שנגזרה משטח הבד ההוא והוכנסה למסגרת. בבד עדיין ספוגים חום התאורה ורטט המחיאות, פושרים, טרם התקררו."},"ICON-0376":{"nm":"חותמת חשיפה ראשונה","de":"חותמת שנחקקה למען הפעם האחת שבה מציגים את עצמך לעולם לראשונה. אין חשיפה ראשונה שנייה, ולכן גם הרגע הקצר שבו הדיו מתייבש הוא זמן שלא ישוב עוד לעולם."},"ICON-0377":{"nm":"כרטיס רגע במה","de":"הקאט הזוהר ביותר מבמה אחת, נגזר והוכנס לכרטיס. המוזיקה והתאורה נעצרו, אבל ברגע שהוא בכף היד, תשואות אותו היום תופחות שוב באוזניים. קסם קטן שבו סצנה קפואה חוזרת לחיים."},"ICON-0378":{"nm":"פתק תנוחת סיום","de":"פתק שמשרטט את זווית קצות האצבעות והמבט שצריכים לקפוא ברגע שהצליל האחרון מסתיים. רק מי שיודע שקאט סיום אחד יכול להכריע ימים שלמים, מקפל בזהירות את הציור הקטן הזה."},"ICON-0379":{"nm":"סיכת עיר סיבוב הופעות","de":"על המפה, סיכה אחת ננעצת בכל עיר שביקרת בה. גם רוח הים של בוסאן וגם צהריי גוואנג'ו נעוצים בקצה המסמר הקטן הזה. חברו בשקט את הנקודות, ותראו את הקו הארוך של מסע שחצה עונה שלמה."},"ICON-0380":{"nm":"קליפס אזור מושבים","de":"מחלק עשרות אלפי מושבים לאזורים ומדריך את הדרך. כדי שלא תלכו לאיבוד, כדי שלא תתנגשו באיש. עקבו אחריי וכל אחד יגיע למקומו. סדר הוא, בסופו של דבר, נדיבות קטנה למען כולם."},"ICON-0381":{"nm":"תג שער כניסה","de":"מול השער, כל אדם עובר בתורו בדיקה. השער האחרון שמכניס פנימה יד אוחזת כרטיס ולב פועם. ברגע שאתה עובר אותי, ההמתנה הארוכה מסתיימת ובמת היום מתחילה."},"ICON-0382":{"nm":"קפסולת שימור צמיד","de":"גם כשהצבע דוהה, שאגת אותו יום נשארת חתומה בדיוק כפי שהייתה. לא מסוגלים לזרוק את הרצועה משורש כף היד, מגלגלים אותה בעדינות לתוך קפסולה קטנה. כי גם לזיכרון יקר מגיע תא קטן משלו לשכב בו."},"ICON-0383":{"nm":"מוט חילופין באתר","de":"בין המעריצה לבמה, משהו עובר מיד ליד. יכול להיות מכתב, יכול להיות מתנה קטנה. אני סולל דרך כדי שהלב הזה יגיע בשלום, הגשר העמוס ביותר באתר."},"ICON-0384":{"nm":"חותם תאריך הופעה","de":"תאריך אותו יום מוטבע בתוך חותם עגול ונעצר לנצח. הלוח שנה מתקדם, אבל רק העיגול הקטן הזה נשאר באותו יום בדיוק. כשמדובר ביום שלא רוצים לשכוח, אנשים תמיד חותמים משהו."},"ICON-0385":{"nm":"תלאי תיק סיבוב הופעות","de":"תיק שסייר יחד מקבל עוד תלאי אחד לכל עיר. שמות המקומות הרקומים על הבד הופכים בלי משים לקורות חיים. גם הפינות השחוקות והבלויות נשארות כעדות לכך שהלכתם יחד לכל מקום."},"ICON-0386":{"nm":"חוט לוח כרטיסים","de":"לוח מתנדנד בקצה תור הכניסה, קצהו קשור חזק בחוט אחד. בתוך התמונה של ידיים שמרימות כרטיסים גבוה ומשתרכות לאורך, אני מסמן בשקט את ראש התהלוכה שבה ההתרגשות עומדת בתור."},"ICON-0387":{"nm":"פיסת סרט הדרן","de":"בלילה שבו הקולות שקראו להדרן היו הכי חזקים, נפלה פיסה אחת מהסרט שקישט את הבמה. כמו שיר שהושר ארוך יותר כי חבל שייגמר, גם בפיסה הזו קשור בקשר החוסר רצון להיפרד."},"ICON-0388":{"nm":"בקבוק קפסולת מסר","de":"מילה אחת מקופלת בעדינות בתוך בקבוק זכוכית. כמו סירה קטנה שהושטה בתקווה שתגיע יום אחד למישהו, אני נושא לב ונסחף לאט מעל הזמן. עד היום שבו יפתחו אותי, ההבטחה ישנה בשקט בפנים."},"ICON-0389":{"nm":"תווית התוודות קטנה","de":"מילים שלא הצלחת לומר בקול, כתובות על תווית קטנה ומוחלקות פנימה בשקט. הכתב רעד, אבל רק הכנות הייתה ברורה. יש רגעים שבהם הנייר הקטן ביותר נושא את האומץ הגדול ביותר."},"ICON-0390":{"nm":"תיבת פתקי עידוד אנונימיים","de":"גם בלי לכתוב שם, הלב מגיע ליעדו. עם כל פתק שנכנס לתיבה, עידוד של מישהו נערם, דף אחר דף, בעילום שם. אוסף של עדינות ללא פנים, שבו רק החום ברור אף שלא יודעים מי כתב."},"ICON-0391":{"nm":"נייר קיפול משאלה","de":"נייר מרובע הופך לעגור, הופך לכוכב, בעקבות קצות האצבעות. עם כל קיפול, גם המשאלה מתקפלת שכבה נוספת. בצורה שקופלה בקפידה שוכנת כנות שנשארת זמן רב יותר מהמילים."},"ICON-0392":{"nm":"שעוות חותם לסרט","de":"מטפטפים שעווה ולוחצים את החותם, וסוף סוף המכתב נאטם. בדיוק בדרך הישנה של הקשחת הלב. על השעווה האדומה שמתקררת, סוד אחד ננעל בשקט."},"ICON-0393":{"nm":"נייר ריפוד למתנה","de":"מחשש שהמתנה תיפגע, הוא עוטף אותה סביב סביב ברוך. בכל קפל מקומט חדורה בקשה לא להישבר. שכבה זהירה של לב במקום נסתר שהמקבל, מן הסתם, יעבור על פניה בלי לשים לב."},"ICON-0394":{"nm":"חוט מכתב צבעוני","de":"גם לחוט שקושר מכתב יש צבע. צהוב לעידוד, כחול לגעגוע. רגשות שהמילים לא הצליחו להביע נבחרים לפי גוון ונקשרים. עוד לפני שמתירים אותו, טמפרטורת הלב כבר מגיעה קודם לקצות האצבעות."},"ICON-0395":{"nm":"סרט הסתרת כתב יד","de":"סרט אחד שמסתיר את הכתב עד ממש רגע המסירה. הוא שומר על התוודות שחוששת שתתגלה עד השנייה האחרונה. הכנות שנחשפת כשמרימים אותו קלות, את משקל הרטט הזה אני מכיר מקרוב מכולם."},"ICON-0396":{"nm":"שבב משפט עידוד","de":"בלילה שבו מקלות האור גולשים כגלים, משפט אחד שיישקק בקול אחד חקוק בתוך השבב. מילות הבטחה שמאספות לבבות מפוזרים לשורה אחת. כשכולם שרים יחד, המשפט הזה זוהר בהכי חזק."},"ICON-0397":{"nm":"מחזיק מפתחות בלוי לחדר חזרות","de":"מחזיק מפתחות שפתח וסגר את דלת חדר החזרות מאות פעמים. הצבע התקלף והטבעת התרופפה, אך בו נותרה בזיעת מגע היד הזיעה של הימים המסורבלים ביותר. בלוי פירושו שהיית שם זמן רב כל כך."},"ICON-0398":{"nm":"פיסת עיפרון איפור לבמה","de":"איפור הבמה נשלם רק תחת האור. פיסה אחת מהצבע העמוק ההוא. בעקבה שהוטבעה חזק כדי שלא תימרח מהזיעה, ספוגה בשלמותה הקפדנות של מי שרצה להעביר הבעה עד המושבים הרחוקים ביותר."},"ICON-0399":{"nm":"קופסת אטמי אוזן","de":"אטמי אוזן קטנים שאפשרו לשמוע את הקול שלך על הבמה. כשההופעה מסתיימת, משכיבים אותם בעדינות בתוך הקופסה. ככל שדבר מה נשא את המוזיקה קרוב אליך יותר, כך רוצים לשמור עליו בקפידה רבה יותר."},"ICON-0400":{"nm":"תווית לוקר אישי","de":"בקצה מסדרון המעונות, על כל לוקר תווית שם. כתב קטן שמציין של מי המקום הופך חלל זר לבית. לקבל תא משלך הוא היתר עדין להישאר כאן."},"ICON-0401":{"nm":"בקבוק טיפוח גרון נייד","de":"בין החזרות, לוגמים לאט לגימה של מים פושרים. הגרון הוא כלי נגינה שהזמר רק שואל לזמן מה, ולכן הבקבוקון הקטן הזה, שמתמלא לפני שיתקרר, שומר מראש על הצליל הראשון של מחר. לב אוהב תמיד שקט כזה."},"ICON-0402":{"nm":"סיכת תזכורת לוח זמנים","de":"מעל יום עמוס עד הדקה האחרונה, סיכה אחת מצביעה על התא הבא. מבין השורות הצפופות, הדבר המשמח ביותר הוא תא אחד ריק. שם, קטנטן, מסתתר הזמן שמותר בו להביט לרגע מבעד לחלון."},"ICON-0403":{"nm":"קליפס שמיכה לחדר ההמתנה","de":"אחר צהריים שבו נשענת על הכיסא ונרדמת לרגע, כשהאיפור כבר גמור, מישהו עטף בעדינות שמיכה על כתפייך. הקליפס הזה, שנושך אותה כדי שלא תחליק, אוחז בשקט בחום המגע הזה עד שיגיע הרגע לעלות לבמה."},"ICON-0404":{"nm":"דוגמית בושם קטנה","de":"נגיעה קלה בפנים שורש כף היד, והריח פורח רק בטווח של זרת. זה בסדר שהוא לא נודף למרחוק. זהו עקבות שרק מי שמתקרב באמת מבחין בו, ולכן הוא אינטימי יותר, ולכן הוא יותר אני."},"ICON-0405":{"nm":"תווית כביסה לבגד אימונים","de":"כמה פעמים שלא תכבסי אותו, ריח הזיעה שחדר עמוק אל תוך הבד לעולם לא נעלם לגמרי. כשמקפלים מחדש את בגד האימונים שיובש ברוח השמש ונעשה רך, חושבים - הכתם שלא נמחק הוא בעצם העקבה הכי כנה שיש."},"ICON-0406":{"nm":"פילטר ג'ל לתאורה","de":"כשמכניסים יריעת צבע דקה אחת, האור הלבן נמס לגוון שקיעה, ועוד יריעה אחת נוספת מביאה איתה שחר. איזו עונה תצבע את הבמה - יד שמלבישה גם את האור בבגדים עוצרת נשימה מאחורי הקלעים."},"ICON-0407":{"nm":"מכסה עדשה לזרקור","de":"גם כשהמצלמה כבויה, מישהו פותח את המכסה הקטן הזה ומנקה את העדשה, למען הסצנה הבאה שעוד לא צולמה. בזמן שלא נקלט על המסך, היד הכי עסוקה כבר מכוונת מראש את המיקוד."},"ICON-0408":{"nm":"לוח רפלקטור לבמה","de":"יש לוח שגם בלי לזרוח בעצמו, מחזיר את האור שקיבל אל פנים מוצלות. מרכז הבמה כה מואר כי בקצה, בשקט, יש זרוע של מישהו שמכוונת את הזווית ומחזירה את האור."},"ICON-0409":{"nm":"שרוול פילטר צבע","de":"כשמכניסים אור כחול אל השרוול השקוף, כל אולם הצופים הופך לים, ובהחלפה לאדום שוקעת שם שקיעה. הקסם שבו אותה במה הופכת לעונה אחרת בזכות צבע אחד, מתחיל בשכבה הדקה הזאת."},"ICON-0410":{"nm":"סיכת מספור לתאורה","de":"לכל אחד מן הזרקורים הרבים יש מספר קטן משלו. איזה יידלק ואיזה יירדם - זרימת המופע הערב כבר נארגה מראש בסדר המספרים האלה. מאחורי מסך מסנוור תמיד פרושה רשימה קפדנית."},"ICON-0411":{"nm":"סרט סימון זוהר","de":"על רצפת הבמה החשוכה, סרט זוהר מאיר בשקט את המקום שבו העקב אמור לעצור. הצופים לא רואים אותו, אך קצות אצבעות הרגל של המבצע ממששות את האור הקלוש הזה כדי למצוא את מקומן. גם בחושך יש מדריך רך."},"ICON-0412":{"nm":"לוח חסימת אור לצל","de":"לוח שחוסם אור דולף כדי להטיל צל חד וברור. גם התמודדות עם החושך היא בסופו של דבר עבודה עם האור, ולכן מה שמראים נקבע קודם כול על ידי מה שמסתירים בשקט."},"ICON-0413":{"nm":"שבב בדיקת תאורה","de":"שבב קטן שמודד את בהירות החלל קורא מספרים על כף היד. כי גם אור חזק מדי וגם חושך רב מדי מטרידים את העיניים. הגבול הבלתי נראה, המדויק, שבו האדם נינוח ביותר - השבב הזה שומר עליו בשקט."},"ICON-0414":{"nm":"מגן לזרקור נקודתי","de":"מגן שמותקן כדי שאור הזרקור הנקודתי לא ידלוף למקום הלא נכון. לרכז אור על אדם אחד בלבד זהו ריכוז מלא חיבה. ברגע שהרגל דורכת אל תוך אותו עיגול אור, העולם כולו מביט לרגע באדם אחד בלבד."},"ICON-0415":{"nm":"סט אטמי אוזניים","de":"זוג אטמי אוזניים שמתאימים בדיוק לאוזן. אפילו סטייה קלה בגודל גורמת לקול לדלוף, וברגע שהוא דולף מפספסים את הקצב. שיר שמתנגן על הבמה בלי כל רעד - לפעמים מתחיל בדיוק מזוג הגומי הקטן הזה."},"ICON-0416":{"nm":"רצועת סקוץ' לכבלים","de":"רצועת סקוץ' שקושרת חוטים סבוכים לצרור אחד מסודר. דווקא מאחורי הבמה, שם איש אינו רואה, הסדר זוהר יותר. הסדר של צרור כבלים אחד תומך בשקט בקול שזורם בלי רעד לפני הקהל."},"ICON-0417":{"nm":"תווית בדיקת קווים","de":"תוויות שנכתבו ביד ונדבקו על עשרות חוטים, כל אחת מציינת לאיזה כלי היא שייכת. רק כשכל אות עקומה ומעוקלת שומרת על מקומה, הצלילים שניגנו כל אחד לחוד סוף סוף זורמים יחד לשיר אחד."},"ICON-0418":{"nm":"משטח השתקה","de":"משטח השתקה אחד שבולע בשקט גם צעדים וגם רעד. הוא מונח בדיוק במקום שבו הדממה הכרחית. הצליל הצלול ביותר לפעמים נולד רק על הרצפה השקטה הזאת, שממנה לא דולפת שום רעש."},"ICON-0419":{"nm":"אסימון בדיקת סאונד","de":"אסימון שמתחמם בכף היד בזמן כיוון הסאונד לפני המופע. בכל פעם שבודקים מיקרופון אחד, רמקול אחד, הוא עובר לאחיזה חדשה. השלמות של הבמה האמיתית מתעצבת צעד אחר צעד בתוך החזרה השקטה הזו."},"ICON-0420":{"nm":"כיסוי ראש מיקרופון","de":"מכיוון שזה המקום שבו נגעו כל כך הרבה קולות, מנקים את הכיסוי העוטף את קצה המיקרופון בתשומת לב יתרה. זהו כלי שמכיל שיר, ולכן הוא כמו יד נוספת עבור הזמר. בזמן הניקוי מציירים מראש את הבית הראשון של מחר."},"ICON-0421":{"nm":"קליפס לפילטר רוח","de":"רשת דקה אחת פרושה בין השפתיים למיקרופון. הודות לקליפס הקטן שמחזיק את המסך הזה, נשימה שדלפה מחוספסת מתעדנת בלי משים לקול עגול ורך שזורם החוצה."},"ICON-0422":{"nm":"תווית מדף ציוד סאונד","de":"תווית קטנה שתלויה כדי לא ללכת לאיבוד בין מדפי הציוד הערוכים זה על גבי זה, מאחורי הבמה החשוכה. מקור הצליל המרהיב שממלא את אולם הצופים תמיד מסודר בקפידה, שכבה אחר שכבה, במקום עמום כזה."},"ICON-0423":{"nm":"סיכת רשת לרמקול","de":"סיכה שמקבעת היטב את רשת הרמקול. החלון שממנו יוצא הצליל הוא הראשון שפוגש אבק, ולכן שכבת רשת דקה שומרת על הטון. על כל דבר שנוגע באוזן עוטה שכבת הגנה בלתי נראית משלה."},"ICON-0424":{"nm":"מדבקת סימון צעדים","de":"מדבקות מסלול שהודבקו נקודה נקודה על הרצפה. הסוד שבו ריקוד קבוצתי מתלכד כמו להב חבוי למעשה מתחת לכפות הרגליים. על עקבות מוסכמים אינספור, שבהם עשרות רגליים דורכות באותה נקודה, מתפזרות ומתאספות שוב."},"ICON-0425":{"nm":"דיסקית תרגול סיבובים","de":"דיסקית תרגול שמסתובבת שוב ושוב במקומה. כדי להתגבר על הסחרחורת, קודם לומדים לנעוץ את המבט בנקודה אחת. איזון שנחרט לאט בגוף, כדי שלא לאבד את הנקודה הזאת גם כשמסתובבים במהירות רבה."},"ICON-0426":{"nm":"גליל טייפ לברך","de":"גליל טייפ אחד שעוטף את הברך היטב. המפרק שקפץ ונחת אלפי פעמים נשאר שותק עד הסוף, אך שכבה אחת זו תומכת בשקט בשתיקה ההיא. מאחורי גוף שמחזיק מעמד עד הקצה, תמיד יש דאגה של מישהו."},"ICON-0427":{"nm":"לוח יישור בהונות","de":"לוח שמיישר בדייקנות את זווית קצות הרגליים. אומרים שריקוד מושלם דווקא בקצות הרגליים, יותר מבקצות האצבעות. עשרות בהונות שמושטות באותו כיוון מתאספות ויוצרות את הקסם שבו רבים נראים כאדם אחד."},"ICON-0428":{"nm":"משטח נגד החלקה לחדר אימונים","de":"משטח נגד החלקה שמונח על רצפת חדר האימונים. כדי לקפוץ בחופשיות, קודם צריך להיות בטוחים. רק על רצפה שאפשר להתגלגל עליה בלי חשש ליפול, פורחות סוף סוף התנועות הנועזות והנטולות פחד ביותר."},"ICON-0429":{"nm":"כרטיס פירוק תנועה","de":"כרטיס שמפרק את הכוריאוגרפיה לפעימות קטנות ומצייר אותן. גם התנועה הקשה ביותר, כשמחלקים אותה לתא-תא, בלי משים מוצאים את עצמכם עוקבים אחריה. הזרימה החלקה כמו מים על הבמה נוצרת מציורים כאלה, שנלמדו בפירוק, כשהם מתאחדים."},"ICON-0430":{"nm":"סיכת וילון לכיסוי מראה","de":"סיכה שמחזיקה את הווילון שמכסה לרגע את מראת חדר האימונים. יש צורך גם בזמן לרקוד בלי השתקפות, רק לפי תחושת הגוף בלבד. יודעים שברגע שהמראה מתכסה, המוזיקה סוף סוף חודרת עד לעור."},"ICON-0431":{"nm":"חרוז ספירת קצב","de":"טיק, בכל פעימה דוחפים חרוז אחד באצבע וסופרים את הקצב. מוחשי, כמו שיטת ספירה עתיקה. הקצב, שדרו של המוזיקה, נטמע ביציבות בגוף רק כשלומדים אותו דרך משהו שאפשר לגעת בו כך."},"ICON-0432":{"nm":"רצועת בדיקת חימום","de":"רצועת בדיקה שמסמנת אם הגוף התחמם כראוי. לפני אימון של ממש, תמיד קודמת הכנה רגועה. במקום להצטער אחרי פציעה, לקשור רצועה אחת ולהעיר את הגוף לאט - זה מה שבסופו של דבר מאפשר לרקוד לזמן ארוך יותר."},"ICON-0433":{"nm":"קליפס מספור תלבושות","de":"קליפס שנושך מספר על כל תלבושת כדי שהתלבושות הרבות לא יתערבבו. בהחלפת בגדים מנשימה, בלבול בתלבושת אחת בלבד עלול להיות אסון, ולכן לכל בגד רשום בבירור תורו. אפילו מהומה זקוקה לסדר כדי להיות אלגנטית."},"ICON-0434":{"nm":"כרית סיכות לחדר תפירה","de":"כרית סיכות שמונחת בפינת חדר התפירה. כאן שוהה היד ששתקה ותפרה תפרים שנקרעו, כפתורים שנפלו. מאחורי מראה מסודר וחלק לגמרי על הבמה, מסתתרת מסירותם של תפרים שמעולם לא ראו את הבמה בעצמם."},"ICON-0435":{"nm":"טבעת פיסות בד","de":"טבעת שמשחילה יחד פיסות בד עודפות. אותו בד עצמו נשמר מראש למקרה שהתלבושת המקורית תינזק. ההכנה הקטנה הזאת, שנשמרה בתקווה שלא יקרה כלום, היא זו שבסופו של דבר מצילה את תלבושת הבמה ברגע שהאסון מגיע."},"ICON-0436":{"nm":"מארז כפתורים מהיר","de":"מארז כפתורים שאפשר לתפור עליהם מיד ברגע חירום. אם כפתור אחד נופל ממש לפני המופע, כל חדר האיפור נסער לרגע. זהו ערכת עזרה ראשונה קטנה אך אמינה להפליא, שמרגיעה בבת אחת את החירום הקצר והמסחרר הזה."},"ICON-0437":{"nm":"מחזיק חגורה לתלבושת במה","de":"מחזיק שאוחז היטב בחגורת תלבושת הבמה, כדי שהבגד לא יתפרק גם בקפיצות וסיבובים עזים. החופש שנהנים ממנו במלואו על הבמה מגיע בדיוק מהמקום הבלתי נראה שנקשר בחוזקה."},"ICON-0438":{"nm":"מטאטא נוצות לאבק","de":"מכיוון שתחת האורות אפילו כדור סיב קטן בולט, מבריש בעדינות את התלבושת במטאטא הנוצות. רגע לפני שהרגל דורכת על הבמה, המגע האחרון והרך על הבגד תמיד שייך לנוצה הרכה הזאת."},"ICON-0439":{"nm":"תווית כפכף לחדר ההמתנה","de":"תווית שם על כל כפכף בחדר ההמתנה. בפתק הקטן שרושם למי הוא שייך, טמונה בשקט ההקלה שאנחנו אותה קבוצה. החדר שבו חולצים נעליים ומותחים רגליים הופך לבית הנוח ביותר מאחורי הבמה."},"ICON-0440":{"nm":"לוח קליפסים לעיצוב שיער","de":"לוח קליפסים שמחזיק חלוקות שיער בזמן העיצוב. בין ליטוף לליטוף של כל קווצה, האצבעות מפקידות לרגע את השיער הרוצה להתפזר בידי הקליפס הזה. סדר, בסופו של דבר, נוצר מהצטברות של הפסקות קטנות כאלה."},"ICON-0441":{"nm":"קפסולת סידור סיכות ביטחון","de":"בשעת שחר שבה נקרע תפר, פותחים את מכסה הקפסולה ומגלים כסף קטן וקריר שוכב מסודר. יד שאוחזת בתלבושת הכי חזק מבפנים, במקום שלא נראה - סיכת הביטחון תמיד עובדת בשקט מאחורי הבמה."},"ICON-0442":{"nm":"מטלית ניקוי לעדשה","de":"הו, נשיפה אחת ואז ניגוב בתנועה עגולה, והעולם המעורפל מתבהר. אוהבים את הרגע הקצר הזה, ולכן ממשיכים לנקות את העדשה שוב ושוב. פיסת אור אביב קטנה שמבהירה במקום מישהו את שדה הראייה שלו."},"ICON-0443":{"nm":"רגליות גומי לחצובה","de":"כשמתקינים גומי על שלוש קצות הרגליים, רצפת הפרקט מפסיקה לצרוח. בזמן שהנקודה הקטנה בולעת את הרעד, הנוף על המסך נרגע כמו בקסם. יציבות תמיד מתחילה בשקט מתחת לרגליים."},"ICON-0444":{"nm":"כיסוי גשם למצלמה","de":"גם כשטיפות גשם זולגות למטה, העדשה נשארת יבשה וממשיכה ללכוד את העולם. באחר צהריים מעונן של צילומי חוץ, מעיל גשם שקוף מתלבש בעדינות על המצלמה. כי דבר יקר עוטפים לפני שהוא נרטב."},"ICON-0445":{"nm":"סרט סימון צילום","de":"עמדי כאן, פני לשם - סימונים קצרים וצבעוניים מורים בבירור על הדרך, בלי מילה אחת. גם כשמסירים אותם בלי היסוס אחרי סיום הצילום, קצות הרגליים שהתרגלו זוכרות את המקום עוד זמן רב."},"ICON-0446":{"nm":"קליפס להפרדת עמודים","de":"קליפס קטן שנושך בביס אחד דפים שרוצים להתפזר. קליק, בקול עליז אחד אתמול והיום נקשרים יחד בסדר. סידור הוא הרגל יד עדין שאוחז בשקט במה שכמעט אבד."},"ICON-0447":{"nm":"לוח איזון לבן","de":"כשמראים ללוח הלבן את המסך, הצבעים מוצאים בשקט את מקומם הנכון. גם שקיעה צהובה, גם שחר כחול - בלי שקר. לוח אחד שמכיר לבן אמיתי גורם לשאר הצבעים לדבר בכנות."},"ICON-0448":{"nm":"פחית אחסון זיכרונות","de":"בתוך פחית פח קטנה ישנים בשלווה שבבי זיכרון. פותחים את המכסה, קליק, וסצנות מהעונה שחלפה נשפכות אל כף היד. הזיכרון שוהה כך, שמור באהבה, בתוך פחית איתנה אחת."},"ICON-0449":{"nm":"כובע צל למסך","de":"כשעוטפים את המסך בהוד שחור, ההשתקפות נעצרת מיד. גם ליד חלון מוצף שמש, המסך לא מאבד את צבעו. כדי לראות טוב, קודם צריך לחסום את האור הזר - כך אומר בשקט ההוד."},"ICON-0450":{"nm":"סיכת בידוד קול לסט","de":"סיכה קטנה אחת שתקועה בסדק הדלת חותכת בשקט את הרעש שבחוץ. גם צעדים במסדרון, גם צחוק מהחדר הסמוך, לא מגיעים לכאן. כי כדי ללכוד קול צלול, צריך קודם לבנות דממה."},"ICON-0451":{"nm":"מארז ספוגי איפור","de":"צרור ספוגים רכים שערוכים זה על גבי זה. טפיחות קלות של אבקה באצבעות, והפנים מבהירות גוון אחד. מאחורי כל חיוך זוהר על הבמה, תמיד מסתתרים המגעים העדינים האלה."},"ICON-0452":{"nm":"קופסת סיכות שיער","de":"בית מסודר לסיכות הקטנות שכה קל לאבד. פותחים את המכסה וכסף מבריק מקבל את הפנים בשורה מסודרת. מפוזרות הן בלתי נראות, אך מאוגדות הן מרגיעות - גם דברים קטנים זקוקים לבית משלהם."},"ICON-0453":{"nm":"קופסת חיטוי למברשות","de":"מברשות שספגו צבע כל היום מתקלחות באור UV בתוך הקופסה. בזמן שאור בלתי נראה שוטף את הישן, קצה המברשת של מחר מתרכך שוב כמו חדש. גם ניקיון הוא שכבה אחת של מסירות."},"ICON-0454":{"nm":"רשת לפאפי פודרה","de":"פאפים עגלגלים נחים בשקט ותופסים אוויר בתוך רשת. כשרוח נכנסת ויוצאת דרך הרשת, הרכות שורדת זמן רב יותר. בפאף אחד שהתייבש כראוי כבר טמון מראש זוהר הבוקר של מחר."},"ICON-0455":{"nm":"מכסה תרסיס קיבוע שיער","de":"פסססס - התזה אחת, וגם הרוח לא תזיז שערה. פקק קטן שיחזיק את התסרוקת המושקעת לאורך כל הלילה. על השיער המקובע היטב, אור בהיר נשפך ומתפזר כמו רסיסים."},"ICON-0456":{"nm":"כיסוי למברשת שפתיים","de":"מכסה קטן שעוטף בעדינות את קצה השיער הדק. גם כשמתנדנד בתוך התיק לכל עבר, המברשת נשמרת ישרה ונקייה. הלב שמוקיר מברשת קטנה אחת משלים משיחת צבע אחת על השפתיים."},"ICON-0457":{"nm":"מראה מספר תור","de":"לצד המספר שמכריז על תורי, דבוקה בעדינות מראה קטנה. רגע לפני העלייה לבמה, זהו המקום להחליק בפעם האחרונה שיער פזור. גם המתח נעשה קצת קל יותר כשמסתכלים בו רגע."},"ICON-0458":{"nm":"רצועת מגבת לשורש כף היד","de":"רצועה רכה שמנגבת את זיעת המצח בתנועה אחת של פרק כף היד. ככל שהכוריאוגרפיה מתעצמת, היד פונה אליה לעיתים קרובות יותר. שורת נחמה קטנה על שורש כף היד, שנשארת קרובה בכל רגע של קוצר נשימה."},"ICON-0459":{"nm":"תווית לתיק אביזרים","de":"גם אם עשרה תיקים זהים עומדים בשורה בחדר האיפור, אין סכנת בלבול. כי על כל תיק דבוקה תווית שם שמכריזה בבירור מי הבעלים. לכתוב \"שלי\" זה סימון קטן אך מלא חיבה."},"ICON-0460":{"nm":"סיכת הזמנת חדר אימונים","de":"מי ישתמש היום בחדר האימונים הזה? סיכה קטנה, נעוצה על הלוח ליד הדלת, מחלקת בשקט את הזמן בלי מילה. לבבות שמחכים לתורם עומדים בשקט בתור, סביב סיכה אחת זו."},"ICON-0461":{"nm":"טבעת כיסוי לשעון קיר","de":"מכסה שקוף נוחת בעדינות מעל שעון הקיר וחוסם את האבק. המחוגים המקתקתים לא מיטשטשים, והזמן זורם צלול. על כל דבר יקר, תמיד יש צורך בשכבת הגנה בלתי נראית."},"ICON-0462":{"nm":"משטח הגנה לרצפה","de":"משטח דק שדבוק מתחת לרגלי הכיסא מונע מראש פציעות ברצפת הפרקט. גם כשגוררים אותו הוא לא שורט, גם כשמזיזים אותו לא נשאר סימן. לב שמוקיר את הרצפה בלי שרואים - זהו הסוד להשתמש בה זמן רב."},"ICON-0463":{"nm":"שבב סימון איסור שתייה","de":"בואו נניח את המשקה בצד לרגע כאן, מבקש בעדינות השבב הקטן. כי גם תווי נגינה וגם ציוד נקלעים לצרה אם הם נרטבים. אפילו מילה כמו \"אסור\" הופכת בלי משים לדאגה חמה, כשמעבירים אותה כך."},"ICON-0464":{"nm":"תווית כפתור אוורור","de":"כשרוצים להחליף אוויר מחניק, לחצו כאן - כך מכוונת התווית הקטנה ליד הכפתור. הרווחה של נשימה חופשית, באופן מפתיע, מתחילה בשקט מסימון קטן שכזה."},"ICON-0465":{"nm":"רגלית גומי לרמקול","de":"כרית גומי שמונחת מתחת לרמקול בולעת בשקט את הרעד העמום. כשהבס לא מתפשט דרך הרצפה, הצליל צלול הרבה יותר. הד טוב מתבהר רק מעל בסיס יציב."},"ICON-0466":{"nm":"מגנט מספור לוקר","de":"מגנט מספרים קטן שנדבק מיד לדלת הלוקר. באיזה תא ישנו החפצים שלי הלילה? גם אם המקום מתחלף כל יום, מגנט אחד מספיק כדי שתא יהיה שלי ברגע. שייכות מגיעה מסימון קל כל כך."},"ICON-0467":{"nm":"מגב לניקוי מראה","de":"מעבר אחד מהיר על המראה, והאדים מתפזרים לגמרי. הרגע שבו פניי המטושטשות עולות בבירור. כדי לראות את עצמי באמת, קודם צריך לנגב בשקט את מה שמעורפל."},"ICON-0468":{"nm":"כרית ריפוד לדלת","de":"ריפוד רך שתקוע בסדק הדלת שנטרקת בחוזקה. הוא קולט ברכות גם את קול הטריקה וגם יד שנתפסת. בטיחות קטנה שמכניסה בחשאי שכבת חמלה אחת לתוך התנגשות מחוספסת."},"ICON-0469":{"nm":"בלוק כיסוי לכבלים","de":"מכסה יציב בונה גשר איתן מעל כבלים שחוצים את הרצפה. אין סכנת מעידה, אין חוט שנרמס. שתיקתו של בלוק אחד ששומר על הדרך בלי לחסום אותה."},"ICON-0470":{"nm":"קונוס אזהרת רצפה חלקה","de":"קונוס צהוב עומד לבדו על הרצפה הרטובה ומזהיר בשקט. דרכו בזהירות, לאט. מאחורי הבמה המוארת עומד שומר קטן כזה, ששותק ומגן על כל צעד."},"ICON-0471":{"nm":"מקל אור חירום","de":"קרן אור אחת שנדלקת פתאום במסדרון שבו הופסק החשמל. כדי שלא תלכו לאיבוד גם בחושך, אור החירום מונח בידכם. בעולם בהחלט קיימים דברים שזוהרים הכי חזק ברגע הכי חשוך."},"ICON-0472":{"nm":"כיסוי מגן למעקה","de":"כיסוי עגול שמולבש על קצה מעקה המדרגות עוטף ברכות את הפינה החדה. גם אם היד נוגעת בהיסח הדעת, אין סכנת פציעה. לכסות בשקט את מה שחד - גם זו דאגה כלפי מישהו."},"ICON-0473":{"nm":"כרית מגן לקצה הבמה","de":"כרית רכה עוטפת את קצה הבמה. כדי שגם כשקצה כף הרגל נוגע בה בכוריאוגרפיה עזה, לא יישאר חבלה. מאחורי כל תנועה זוהרת, הגנה בלתי נראית רוקדת יחד איתה."},"ICON-0474":{"nm":"דיסקית סימון רצפה","de":"דיסקית עגולה שמונחת על הרצפה אומרת בשקט \"עמדו כאן\". גם מי שעומד בתור, גם מי שמחפש את מקומו, עוצר בשקט מול הנקודה הזאת. סדר צומח מסימון קטן."},"ICON-0475":{"nm":"רצועה לפנס","de":"כשכורכים פעם אחת סביב פרק כף היד את החוט התלוי בקצה הפנס, לא מאבדים את האור גם בחושך. כריכה אחת, קטנה אך מרגיעה, ששני הידיים משתחררות בעזרתה בלי חשש להפיל."},"ICON-0476":{"nm":"חבל הפרדה","de":"בבקשה אל תיכנסו מעבר לכאן - חבל אחד מותח בעדינות קו. גבול חם שמפריד בשקט בין מקום מסוכן למקום בטוח. גם לחסום מישהו זו דרך להגן עליו."},"ICON-0477":{"nm":"סיכת אישור בטיחות","de":"בכל מקום שהבדיקה הושלמה בו, סיכה קטנה משאירה \"אושר\". נקודה אחת, כמו חותמת של לב שסקר הכול בלי לפספס דבר. בטיחות איננה משהו גדול - היא סכום העקבות של כל בדיקה ובדיקה שנעשתה בקפידה."},"ICON-0478":{"nm":"לוח צלפה מיני","de":"טרק - בקול העליז שקוטע את הפעימה הראשונה, נשימתם של כולם באתר הצילום מתואמת בבת אחת. קטן ככל שיהיה, קו הפתיחה של כל סצנה הוא תמיד הפעימה הזאת. ההתחלה המרגשת של הצילום נפתחת בדיוק כאן."},"ICON-0479":{"nm":"כיסוי מיקרופון שולחני","de":"כיסוי רך מולבש בעדינות על מיקרופון השולחן. גם כשנשימה פורצת בחוזקה, היא עוברת חלקה בלי שום רעש. מה שעוטף את הקול הכי בחום הוא בדיוק השכבה הקטנה והרכה הזאת."},"ICON-0480":{"nm":"פיסת פאנל בליעת קול","de":"פיסת פאנל בליעת קול אחת, קבועה בקיר, אוספת בשקט את ההד. מכיוון שהצליל לא מתנגש ומתפזר, השיר מצטבר צלול הרבה יותר. הד טוב נובע מעיצוב הדממה בקפידה."},"ICON-0481":{"nm":"מכסה וו לאוזניות","de":"לתלות כאן את האוזניות זו הבטחה קטנה. לשחרר את הכבל ולסדר אותו כדי שהאדם הבא יוכל להרים ולהשתמש מיד. וו אחד מכניס סדר שקט לתא עבודה עמוס."},"ICON-0482":{"nm":"נורית הקלטה","de":"ברגע שהנורה האדומה נדלקת, כל נשימה בתוך התא נעצרת. אות שעוצר אפילו את הצעדים מעבר לדלת. לכידת קול מתחילה בשמירה על הדממה העמוקה הזאת."},"ICON-0483":{"nm":"קופסת מפרטים לפיקים","de":"פיקים מונחים בתאים מסודרים לפי צבע. העובי והמשקל מעצבים את הרגלי האצבעות. ממש לפני הבמה, הדיוק שבו תופסים בבת אחת בלי להסתכל צומח בדיוק כאן."},"ICON-0484":{"nm":"מדביק תוויות לכבלים","de":"כדי לא ללכת לאיבוד בין עשרות חוטים סבוכים על הרצפה, צריך לכתוב שם על שני הקצוות. רק מי שרשם מאיפה בא ולאן הולך, יד לא תתעה גם בחושך."},"ICON-0485":{"nm":"כפתור למיקסר קטן","de":"סיבוב אחד קטן, ברוחב פרק אצבע, ומרקם הקול משתנה. להעלות - וזה נעשה מחוספס, להוריד - וזה נבלע, מישוש אחר הנקודה האחת שביניהם. המגע העדין ביותר יוצר את השינוי הגדול ביותר."},"ICON-0486":{"nm":"דסקית נעילה למעמד","de":"מה שתומך בבמה איננו האור המרהיב אלא הטבעת הקטנה הזאת. היא אוחזת בחוזקה ברעד, ומחזיקה מעמד בשקט במקומה, בלי שאיש שם לב אליה."},"ICON-0487":{"nm":"תווית פירוק תפאורה","de":"גם בהשכבה זהירה מחדש של כל מה שהוקם יש סדר ברור. דף אחד שרושם איפה לשחרר ולאן להעביר. היד שמפרקת בטוחה בדיוק כמו היד שבנתה."},"ICON-0488":{"nm":"שבב מעטפה לאבידות","de":"לכל חפץ שמישהו הפיל ועזב יש סיפור משלו. להניח אותו במעטפה קטנה ולחכות לשם הבעלים זוהי חמלה ששומרת לרגע גם על ליבו של מי שאיבד."},"ICON-0489":{"nm":"סימון מסלול ניקיון","de":"כשעוקבים אחר החצים המצוירים על הרצפה, מנקים בלי להשאיר פינה. גם למטאטא צריך דרך כדי שלא יסתובב לשווא. המקום הנוצץ ביותר נמצא בסוף העקבות המצוירות היטב ביותר."},"ICON-0490":{"nm":"מוט הכוונה ליציאה","de":"כשהמחיאות כפיים האחרונות דועכות, המוט הזה פותח את הדרך. יד שמלווה לאט, בלי לפגוע בלבבות עדיין נרגשים. גם בהכוונת הסיום טמונה דאגה חמה."},"ICON-0491":{"nm":"כדור טייפ שיורי","de":"כשגלגלים לכדור עגול את השיירים שנותרו, נולד להם שימוש נוסף. כמו שקצוות שכמעט הושלכו מתאספים לכדי כדור מוצק, לב חסכני צומח מקצות אצבעות קטנות."},"ICON-0492":{"nm":"כיפת מספור לכיסא","de":"רק אם על כל כיסא באולם חקוק מספר, איש לא הולך לאיבוד. כובע קטן אחד שקובע מקום, הופך את הפעימות של מי שמגיע בפעם הראשונה להקלה נינוחה."},"ICON-0493":{"nm":"סיכת מיון פסולת","de":"סיכה קטנה שמפרידה נייר מפלסטיק. מעורבבים - הם רק זבל, אך מופרדים - הם הופכים למשאב לשימוש חוזר. מיון הוא מעשה עדין שמחזיר לחפצים חיים שניים."},"ICON-0494":{"nm":"תווית החזרת ציוד","de":"מה שהושאל חייב תמיד לחזור למקומו. עם כל אצבע שמצמידה תווית ומחזירה, אמון נערם שכבה אחר שכבה. מי שמחזיר היטב שואל שוב בלב שקט בפעם הבאה."},"ICON-0495":{"nm":"מפתח יציאה לחדר ההמתנה","de":"מסירים את כל האיפור והתלבושת של היום, ולבסוף מחזירים את המפתח הזה. להחזיר ביציאה את מה שקיבלת בכניסה. תחילת היום וסופו נאחזים באותה כף יד."},"ICON-0496":{"nm":"קופסת פאף כרית","de":"פאף רך מאבד את המרקם שלו כשלוחצים עליו. משם הסיבה שהוא מונח לנוח בעדינות בתוך בית עגול אחד. כדי לשמור על רכות לאורך זמן, קודם צריך לטפל בעדינות."},"ICON-0497":{"nm":"שבב צלליות","de":"נקודת צבע אחת שמונחת על העפעף משנה את כל ההבעה. הצבע שישן בשבב הקטן מתעורר רק תחת האורות, ומוסיף עומק למבט הפונה אל הבמה."},"ICON-0498":{"nm":"כיסוי למברשת סומק","de":"כשקצה השיער נהרס, גם עוצמת הצבע קורסת איתו. להלביש כובע קטן ולשמור על המרקם הזה, זהו הרגל שקט של מי שרוצה לשמור כלים טובים לצידה זמן רב."},"ICON-0499":{"nm":"פלטת שפתיים דקה","de":"פלטה עבה תופסת את כל המקום בתוך התיק. יד שיודעת שרצועה דקה אחת שנחתכה מספיקה. הרגע שבו לוותר על דברים הופך בעצמו למעשה של הכנה טובה."},"ICON-0500":{"nm":"מגן מסקרה","de":"כדי שהריסים שהורמו אחד אחד לא יימרחו, מגן קטן שומר בעדינות על העקומה הזאת. מה שהורם במסירות, צריך לשמור עליו במסירות - כך מלמד הזמן מול המראה."},"ICON-0501":{"nm":"קופסת מקלות צמר גפן","de":"בית קטן ששומר על מקלות צמר גפן לבנים מלהתפזר לכל עבר. מגע ששומרים תמיד קרוב, לתיקון אחרון. הכנות קטנות משלימות את הרווחים של במה גדולה."},"ICON-0502":{"nm":"מארז גומיות למסלסל ריסים","de":"כשהגומי מתקשה, סלסול הריסים דוקר וכואב. לשמור רזרבה מוכנה מראש נובע מעדינות שמביאה בחשבון אפילו כאב קטן."},"ICON-0503":{"nm":"מברשת קונסילר","de":"קצה מברשת דק מוחק בעדינות את הצללים. להביא אור למקום שהאור לא הגיע אליו. יד שמוסיפה אור במקום להסתיר פגמים מסיימת בעדינות רבה יותר."},"ICON-0504":{"nm":"מסננת פודרה","de":"מסננים את האבקה העדינה פעם אחת והיא נשכבת חלקה, בלי גושים. הטרחה שבניפוי נוסף דרך המסננת. מסירות, בסופו של דבר, ניכרת באצבע שעושה צעד נוסף."},"ICON-0505":{"nm":"מהדק גלילה לפוני","de":"מהדק שמגלגל את הפוני ומחזיק אותו לרגע. בזמן ההמתנה הצורה מתיישבת בשקט. סדר נולד במקום שיודעים להמתין בלי למהר."},"ICON-0506":{"nm":"כפית שעווה לשיער","de":"את השעווה לוקחים בכפית הקטנה הזו לפני שהיא נוגעת ביד. הריסון שבלקיחת בדיוק מה שצריך. יד שיודעת להשתמש בלי עודף יוצרת את המרקם הטבעי ביותר."},"ICON-0507":{"nm":"מזרן הנחה למסלסל שיער","de":"אי אפשר סתם להניח מסלסל שיער לוהט בכל מקום. מזרן הנחה אחד מגן גם על השולחן וגם על הידיים. מקום שמתמודד עם חום תמיד זקוק למפלט בטוח."},"ICON-0508":{"nm":"דוגמית שמן לשיער","de":"טיפה אחת מספיקה לברק, אז שמים אותה בבקבוקון דוגמית קטן ותוחבים לפינה בתיק. בקבוקון קטן, יותר מבקבוק גדול, מגיע ליד הרבה יותר לעיתים קרובות."},"ICON-0509":{"nm":"מגרפת ניקוי למברשת","de":"את השיער שהסתבך בזיפים מסרקים לאט עם המגרפה. הטיפול בכלים הוא טקס שקט אחרי סיום העבודה. מברשת מטופחת מעצבת יפה את המרקם של מחר."},"ICON-0510":{"nm":"סליל לגומיות שיער","de":"רק לכרוך סביב סליל, וכולן נראות במבט אחד. החבילה הקטנה הזו, מסודרת בעיגול, היא רגיעה עדינה שמוגשת לבקרים עמוסים שבהם גומיות השיער התגלגלו לכל עבר."},"ICON-0511":{"nm":"מארז כפפות לצביעה","de":"כפפות דקות שלובשים כדי שהיד שצובעת לא תוכתם. רצון לפגוש את הדבר הבא בידיים נקיות גם אחרי שהעבודה נגמרה. הגנה היא רק שם אחר להיערכות כזו."},"ICON-0512":{"nm":"נרתיק לרשת שיער","de":"כיס קטן לקפל ולשמור בעדינות את הרשת ששומרת על תסרוקת. ככל שדבר קל יותר, כך קל יותר לאבד אותו, לכן מגע קשוב שנותן לו בית הוא דבר מבורך."},"ICON-0513":{"nm":"עט מיישר שערות סוררות","de":"עט שמקיש בעדינות על שערות סוררות ומחזיר אותן למקום. המגע האחרון ממש אחרי שכל הסידור הגדול הושלם. סיום הוא תמיד העבודה של ליטוף המקום הקטן ביותר."},"ICON-0514":{"nm":"מכסה בדיקת בושם","de":"כשבוחרים ריח, לא מקרבים אותו ישר לאף. מטפטפים על מכסה קטן ונותנים לו להתפזר באוויר כדי לחשוף את המרקם האמיתי שלו. גם ריח כן רק כשמריחים אותו מרחוק."},"ICON-0515":{"nm":"בקבוקון בושם רול-און","de":"כדור עגול מתגלגל ומצייר ריח על פרק כף היד. בשונה מבקבוקי הבושם הישנים שהיו מנוגבים בנגיעה, קו אחד גולש ומתפשט. הריח משאיר סיפור שונה בכל דרך שבה הוא נוגע."},"ICON-0516":{"nm":"מכסה למיסט לגוף","de":"מכסה קטן שכולא ריח שמתפשט כמו ערפל. לסגור ולשמור את מה שמתפזר רק כשפותחים. לב קטן שחוסך קצת גורם לניחוח להישאר לצדך זמן רב יותר."},"ICON-0517":{"nm":"מחזיק מפתחות עם קרם ידיים","de":"מצמידים טבעת לקרם הקטן שמורחים על הידיים, והוא הולך איתך לכל מקום. בן לוויה שמתנדנד מחוץ לתיק הופך לברכת שלום עדינה לקצות אצבעות יבשות."},"ICON-0518":{"nm":"וו לספוגית מקלחת","de":"אחרי שיוצרים קצף בועבע, צריך לייבש היטב. כדור הרשת שתלוי על וו בפינת חדר האמבטיה מנער את הטיפות, ומחכה בציפייה לבוקר רענן."},"ICON-0519":{"nm":"נרתיק לכדור עיסוי","de":"כיס קטן לשמור בו את הכדור המוצק שמשחרר כתפיים תפוסות. מנוחה קצרה מאחורי הבמה, זמן ללטף בשקט גוף נוקשה. טיפול תמיד מתחיל מהעצמי."},"ICON-0520":{"nm":"פחית פלסטרים מקררים","de":"פחית שאוספת פלסטרים שמצננים בנעימות כשמדביקים אותם. בלילה שבו במה לוהטת מסתיימת, נחמה קטנה ישנה בפנים, ומרגיעה לאט גוף ולב שהתחממו."},"ICON-0521":{"nm":"עט שמן ציפורניים","de":"לוחצים, משפשפים, נוצץ. טיפה אחת מספיקה לקצות אצבעות יבשות. אין צורך בטיפול מפואר; ברק עדין שמתפשט מקצה העט הקטן מתפתל בחן על הציפורניים. טיפול מתחיל בטיפה קטנה כזו."},"ICON-0522":{"nm":"קליפס לשקית ריח","de":"קשר קטן שכולא ריח בתוך נייר. בכל פעם שפותחים מגירה, קורטוב עדין מברך לשלום עוד לפני היד. עדינות ששוהה קרוב גם בלי להיראות; קליפס אחד מחזיק בשקט נחמה של יום שלם."},"ICON-0523":{"nm":"מגש טיפים לציפורניים","de":"במה קטנה שפורשת מראש את הצבעים של עשר האצבעות. איזה גוון יתאים להיום? אודישן שקט נפתח על המגש. אותו רגע קצר של בחירה מרגש איכשהו, ויום קצות האצבעות מתחיל כאן."},"ICON-0524":{"nm":"מכסה דוחף קוטיקולה","de":"יש עדינות גם בדחיפה לאחור. שערת יתר אחת, בעדינות עם הקצה העגול, בלי חיפזון. יד ממהרת תמיד מפספסת משהו, ולכן סידור קרוב יותר לתודעה שמסתכלת לאט."},"ICON-0525":{"nm":"משייפת מיני","de":"צד גס וצד עדין, שני פנים באחיזת יד אחת. לשייף בעדינות פינות מחוספסות עד שהן חלקות זה דבר קטן, אבל השלמות תמיד מגיעה ממגעים קטנים כאלה. המילה האחרונה, בסוף, שייכת לרכות."},"ICON-0526":{"nm":"דף מדבקות לציפורניים","de":"כוכב, פרח, לב, פשוט בוחרים דף אחד שמתאים למצב הרוח של היום ומדביקים. על דף שמסודר בשורות של ציורים קטנים בגודל ציפורן, מדבקה אחת נוצצת כמו חתימה עדינה שנשארת על קצה האצבע."},"ICON-0527":{"nm":"מגן אור למנורת ג'ל","de":"מסך דק שכולא את האור לזמן מה. בזמן ההתקשות העיניים נחות, ורק קצות האצבעות מתקשים בשקט. גם להמתנה דרוש פס צל; בזמן שאינו נחפז, קצות האצבעות של היום מושלמים."},"ICON-0528":{"nm":"פחית חלקי אמנות ציפורניים","de":"פיסות נוצצות ישנות בתא אחר תא. אבנים, פנינים, אבק כוכבים, מרימים את המכסה בהתרגשות של פתיחת תיבת תכשיטים ללא תווית. איזה אור להניח על הציפורן? רגע הבחירה הזה נוצץ הכי הרבה."},"ICON-0529":{"nm":"מארז כפפות טיפוח ידיים","de":"חופשה קצרה שהידיים לוקחות בזמן שישנים. בתוך הכפפות העור היבש הולך ומתרכך לאט כל הלילה. טיפול, בסופו של דבר, הוא משהו שקורה במקום שאינו נראה, ובבוקר קצות האצבעות הם הראשונים לדעת את העדינות הזו."},"ICON-0530":{"nm":"בקבוק משאבה למסיר לק","de":"לחיצה אחת, בדיוק כמה שצריך. ריח קריר חודר לצמר הגפן ומוחק את אתמול מהציפורניים. יש קצב גם בריקון; משאבה אחת מפנה בשקט מקום לצייר מחדש."},"ICON-0531":{"nm":"פינצטת אבני חן","de":"כדי להרים אבן דקה יותר מקצה אצבע, דרושה יד עוד יותר דקה. קצה הפינצטה מזיז נקודה אחת בלי רעד; עדינות היא לא רק עניין של לב אלא גם של הכלי. אור קטן אחד מוצא את מקומו."},"ICON-0532":{"nm":"לוח אחסון לעגילים","de":"כדי שעגיל בודד לא יתעה שוב במגירה. תוקעים כל זוג במקומו, ובוקר עמוס בבחירה הופך קל יותר. סידור הוא חסד קטן שנותנים לעצמנו העתידי."},"ICON-0533":{"nm":"טבעות מדידה לטבעת","de":"צרור קטן של טבעות שהופך היקף אצבע למספר. לנסות כל מידה אחת אחרי השנייה דומה להכיר לאט משהו שמתאים לך בדיוק. כמו אותה הקלה כשזה מתאים בול."},"ICON-0534":{"nm":"פין לרצועת שעון","de":"כשרצועת השעון מתרופפת, סיכה קטנה אחת קושרת שוב את הזמן אל פרק כף היד. שהחלק הכי חבוי הוא זה ששורד הכי הרבה זמן, דבר ששעון שנלבש שנים מכיר בשתיקה."},"ICON-0535":{"nm":"לוח מונע הסתבכות לשרשראות","de":"תאים מחולקים כדי ששרשראות דקות לא יסתבכו זו בזו. בוקר בלי הסתבכות מתחיל במחיצות הקטנות שהופרדו אמש. רווחה, בסוף, היא תודעה מסודרת עוד לפני שהיד נוגעת."},"ICON-0536":{"nm":"סוגר אחורי לסיכת תכשיט","de":"ככל שהחזית מרהיבה יותר, כך העורף שקט יותר. סוגר קטן שתומך בחוזקה בסיכה שננעצה בשולי בגד; מאחורי כל זוהר גלוי תמיד יש יד אלמונית שמחזיקה מעמד. מקום איתן יותר דווקא כי אינו נראה."},"ICON-0537":{"nm":"נרתיק למשקפי שמש","de":"בד רך עוטף בעדינות את העדשות שחסמו את אור הקיץ. כיס קטן ששומר זוג ראייה אחד מהחיכוכים בתוך התיק. הלב שמוקיר משהו תמיד מגיע כשכבה רכה כזו."},"ICON-0538":{"nm":"מנקב חורים לחגורה","de":"למותן שהצטמצם חור אחד, ולעונה שהתרחבה חור אחד. פשוט לנקב עוד חור אחד וחגורה חוזרת להתאים לגוף. תמיד אני זה שמשתנה, וההתאמה השקטה היא עבודתו של הכלי הקטן הזה."},"ICON-0539":{"nm":"קליפס טבעת לצעיף","de":"קליפס שאוסף צעיף מחליק לנקודה אחת ומחזיק אותו. סגנון שהמשיך להשתחרר ברוח סוף סוף מתיישב במקומו. גם אלגנטיות לפעמים נשענת על הקליפס הקטן הזה, ומסדרת יום שכמעט התפרק."},"ICON-0540":{"nm":"סט חישוקי קישוט","de":"סט של חישוקים קטנים לתלות בצד התיק. הלב של לשמור קרוב את מה שאוהבים; לתלות את מצב הרוח של היום על תליון אחד הוא טקס קטן שרק את מכירה, ומשום מה זו הנאה."},"ICON-0541":{"nm":"מכשיר להסרת פלומה","de":"כשסוודר נראה כאילו הזדקן בין לילה עם פלומה, מגלגלים בעדינות את המכשיר הזה עליו והוא לובש שוב פנים של חדש. הזמזום הקל שמסיר את הבלאי מרגיע איכשהו. בגד אהוב חוזר לחיים בפעם נוספת."},"ICON-0542":{"nm":"כרטיס ריח לבדים","de":"תוחבים עמוק בארון והוא ממלא בשקט את הימים בניחוח. מכתב שנכתב בריח במקום במילים, עמוד שנקרא בלי לפתוח. בכל בוקר שמוציאים בגד, העדינות שנכתבה אתמול מתפשטת ראשונה."},"ICON-0543":{"nm":"פין נגד חשמל סטטי","de":"בבוקר חורפי כשחצאית נדבקת לרגליים, סיכה אחת משחררת בעדינות את ההידבקות ההיא. שלום קטן שמרגיע גם חיכוך בלתי נראה; כשעצבנות קטנה אחת נעלמת, היום זורם הרבה יותר חלק."},"ICON-0544":{"nm":"מברשת בגדים ניידת","de":"רגע לפני היציאה מהדלת, פס אבק ניחת בעדינות על הכתף. פותחים את המברשת המקופלת, ניפוח אחד, והרושם הראשוני מסודר שוב. הגימור תמיד קורה ליד הדלת, והסדר מושלם במגע אחד כזה."},"ICON-0545":{"nm":"תווית לרשת כביסה","de":"כולאים ברשת את הדברים שאסור שיתערבבו, ותווית כותבת בשקט את שמם. גם לכביסה יש מקום, ולמקום יש סימון קטן. הסדר של יום שנוטה להתבלבל צומח מתווית קטנה כזו."},"ICON-0546":{"nm":"עט להסרת כתמים","de":"אפילו הסימן שטיפת קפה השאירה על חולצה נסוג בשקט כשמקישים עליו. עט שלא מכסה טעות אלא מוחק אותה בעדינות. כל אחד זקוק להזדמנות אחת להתחיל את היום נקי מחדש."},"ICON-0547":{"nm":"מטלית להברקת נעליים","de":"ניגוב אחד עם המטלית והעור מחזיר את הברק שלו. ככל שהנעליים ננעלות זמן רב יותר, כך הברק חודר עמוק יותר. הזוהר הוא תגמול על הזמן שהלכתם יחד; הנעל חורטת בשקט את השנים ההן על גב כף הרגל."},"ICON-0548":{"nm":"כובעון לקצה שרוך","de":"כובעון קטן שהוצמד לקצה השרוך המשוחרר. כדי שלא תסיטי מבט לפני קו הסיום, הקצה נאטם היטב. שרוך אחד קשור היטב שולח צעד נוסף רחוק יותר; זהירות קטנה הופכת לאומץ לרוץ עד הסוף."},"ICON-0549":{"nm":"שבב שם לקולב","de":"בין קולבים דומים זה לזה, שבב קטן אחד זה מודיע בשקט 'המקום שלי'. מדריך שקט שמקל על הבלבול של הבוקר העמוס; כשהחיפוש פוחת, גם תחילת היום קלה יותר."},"ICON-0550":{"nm":"פחית פינצטה לעדשות","de":"יש רגעים שבהם נדרש קצה מדויק יותר מקצה אצבע. פינצטה שמרימה עדשה קטנה בלי רעד ממתינה לתורה בתוך הפחית. דיוק תמיד שוכב מוכן בשקט, ישן עד שקוראים לו, ומתעורר מיד."},"ICON-0551":{"nm":"מארז מיני של פדים לאיפור","de":"חבילה קטנה שמכילה בדיוק כמה שצריך לשימוש אחד. היא מצמצמת את הנפח בתיק בעוד הרכות נשארת אותה רכות. לארוז מעט הוא גם סוג של עדינות; יום קל נכנס למקום שפינו."},"ICON-0552":{"nm":"נרתיק לניירות סופג שומן","de":"מנגבים בעדינות את הברק שהתפשט על האף בצהריים בגיליון דק אחד. הניירות ישנים מסודרים בשורות בתוך הנרתיק; לרגע שבו שולפים אחד, כל אחת עוצרת רגע ומביטה בעדינות בעצמה במראה."},"ICON-0553":{"nm":"מסרק-מראה מתקפל","de":"מקופל הוא כף יד; פתוח הוא מראה ומסרק. חפץ רב-תכליתי קטן שמטפל בתיקון מהיר מפינת התיק. סדר אינו דבר גדול; הוא קרוב יותר ללב שיכול להיפתח בכל מקום למגע מהיר אחד."},"ICON-0554":{"nm":"מכסה סכין גילוח נסיעות","de":"הוא מרדים בבטחה את הלהב החד בתוך תיק הנסיעות. בזכות המכסה הזה, קהה אך יציב, גם אצבעות שממששות בבוקר עמוס לא נפצעות. דאגה היא תמיד לכסות סכנה צעד אחד מראש."},"ICON-0555":{"nm":"חישוק שפתון לחות","de":"מגן קטן שמתנדנד מרצועת התיק. בלי חשש שיתגלגל בכיס וישבר, שפתיים יבשות נשארות תמיד בהישג יד. לשמור משהו קרוב הוא, בסוף, לב ששם את הדרוש במרחק הקרוב ביותר."},"ICON-0556":{"nm":"מחזיק ג'ל חיטוי ידיים","de":"לוחצים ביד אחת וקורטוב של ניקיון נוטף. תולים אותו ליד הדלת, על השולחן, בכל מקום, וההרגל של ידיים נקיות מתקרב באותה מידה. הרגל טוב אינו דבר גדול; הוא מתחיל בהישג יד."},"ICON-0557":{"nm":"נרתיק דק לטישו","de":"גוף חטוב שמכיל קורטוב טישו. בלי שהכיס יתנפח, הוא תמיד מוכן בשקט לנזלת פתאומית או לדמעות. פיסה אחת להושיט למישהו; ככל שההיערכות דקה יותר, כך היא נאה יותר."},"ICON-0558":{"nm":"בקבוקון מי פה","de":"ביום שצריך לפגוש מישהו אחרי אכילת ראמן חריף, הבקבוקון הקטן הזה דואג בשקט לרענון מהיר. לגימה אחת של רעננות הופכת לפעמים לביטחון עצמי גדול, והופכת ברכת שלום מהוססת לקלה הרבה יותר."},"ICON-0559":{"nm":"שבב פודרה נוצצת","de":"נוגעים בקצה האצבע ומניחים על הלחי, וזה מתפשט כמו אבק כוכבים מתפזר תחת האורות. לחי רגילה נוצצת ברגע אחד בקסם של שבב קטן אחד זה. אור תמיד מגיע כך, כאבקה שדבקה בקצה האצבע."},"ICON-0560":{"nm":"מדבקת ריסון נצנצים","de":"במקום שנוצץ יותר מדי ומטריד, המדבקה הזו מעמעמת בעדינות את האור. להוריד שכבת זוהר אחת היא גם חלק מהעיטור; הרוך שנשאר במקום שפינו הופך לפעמים לתחושה משלו."},"ICON-0561":{"nm":"עט לאיסוף אבנים","de":"אבן קטנה שנתקלה ברגל בזמן הליכה בדרך. עט שמתכופף בכוונה כדי להרימה. הלב שאוסף בעדינות בקצה האצבע את מה שאפשר היה פשוט לחלוף על פניו; עדינות תמיד מתחילה בעצירה."},"ICON-0562":{"nm":"לוח אחסון לריסים תותבים","de":"לוח קטן להשכיב עליו ריסים תותבים אחד אחד בסדר. גם אחרי שמסירים אותם, העקומה החיננית שלהם לא מתערערת. הנחמה השקטה והמסודרת של אחסון שאומר שגם מה שהונח בצד לרגע זוכר את מקומו."},"ICON-0563":{"nm":"מכסה גזם לסרט עפעף כפול","de":"שתי להבים נפגשות וחותכות קשר בתנועה אחת. ככל שהחיתוך נקי יותר, כך הקשר הבא מסודר יותר. מקצה אצבע שיודע לקשור ולחתוך היטב, גם התחלה חדשה נפרמת קלה הרבה יותר."},"ICON-0564":{"nm":"סרט קו פנים","de":"קו אחד לאורך קו הלסת, מודבק בזהירות, בעצירת נשימה. עיצוב קווי המתאר אינו ציור קו שלא היה שם אלא הצבעה על מקום שכבר יפה. מגע שעוקב בעדינות אחר המרקם שתמיד היה שם."},"ICON-0565":{"nm":"פודרת החזרת אור","de":"פודרה שסופגת אור עד תום ומחזירה אותו בחן. גם בלי לזרוח בעצמה, היא מאירה בפיזור האור שקיבלה לפירורים דקים. כמו העברת עדינות מושאלת הלאה למישהו אחר, הנצנוץ גדל ככל שמשתפים אותו."},"ICON-0566":{"nm":"מאוורר קיבוע איפור","de":"רוח מאוורר שמחזיקה איפור מושקע עד סוף היום. כדי שלא יתפורר, כדי שלא יזוב, הוא מקרר ומקבע בשקט. כדי שפנים שטופחו בקפידה יישארו ברורות עד שמסך הבמה יורד."},"ICON-0567":{"nm":"שבב פלטת תיקון גוונים","de":"פיסות קטנות שמרגיעות ומיישרות גוון שסטה, תא אחר תא. גם צבע שריחף לבדו מתבהר סוף סוף כשיש לצדו גוון משלים. רק כשצבע לוחץ יד לצבע נוצר לוח אחד צלול."},"ICON-0568":{"nm":"מארז צעיף צוואר","de":"עוטפים סביב הצוואר והאוויר הקר של חדר האימונים לפנות בוקר מתרכך מאוד. חמים כמו המגע של סבתא שעטפה את צוואר נכדה. הקור תמיד מגיע קודם למקום הדק ביותר, ולכן הוא חובק ראשית את העורף."},"ICON-0569":{"nm":"מעטפה לכריות עיניים מחוממות","de":"מעטפה קטנה לשמור בה כרית עיניים מחוממת. ברגע שפותחים את הכיסוי, חום עייף מתפשט לאט על העפעפיים. טקס עדין לפני השינה, שאוטם לרגע יום מתיש ואז משחרר אותו."},"ICON-0570":{"nm":"מסנן מכשיר אדים נייד","de":"קרום סינון קטן שמחזיר לחות לחדר יבש לגמרי. מבפנים, במקום שאינו נראה, הוא מסנן בשקט את מה שמעונן. הלחות שממלאת את החדר היא בהירות ששמר עליה מאמץ בלתי נראה של מישהו."},"ICON-0571":{"nm":"קופסת סידור ויטמינים","de":"קופסה שמחלקת את כדורי היום תא אחר תא. לקחת אותם באמונה זה נדר לעמוד על הבמה גם מחר. בכל תא קטן, לב שמוקיר את עצמו מסודר בקפידה."},"ICON-0572":{"nm":"נרתיק אטמי אוזניים לשינה","de":"בית לאטמי האוזניים שסוגרים לרגע את רעש העולם. גם לשקט דרוש טיפוח, לכן הם שוכבים בעדינות בתוך הנרתיק. לילה שישנים בו עמוק הוא מה שמאפשר לקול להתעורר צלול למחרת, כפי שהמנוחה יודעת היטב."},"ICON-0573":{"nm":"קליפס למגבת מקררת","de":"קליפס שנועץ בחוזקה בכתף כדי שמגבת מקוררת לא תחליק. ביום לוהט, פס אחד של קרירות על העורף מחזיק מעמד אחר צהריים ארוך. גם קרירות קטנה, כשמחזיקים אותה במקום, שוהה זמן רב."},"ICON-0574":{"nm":"שקית לכדור מתיחות","de":"שקית שמחזירה אליה את הכדור ששחרר את הגוף. למתוח עד הסוף ואז לאסוף חזרה לקטן דומה לשאיפה ונשיפה. בין הפריסה לאיסוף, הגוף והנפש מתחזקים לאט."},"ICON-0575":{"nm":"גליל תחבושת לחץ","de":"רצועה שעוטפת קרסול שנקע סיבוב אחר סיבוב. זה לא לחיצה אלא תמיכה שקטה. ככל שהמקום פגוע יותר, כך הוא זקוק ליד שמחזיקה מעמד בשקט לצדו, לוחש הגליל בזמן שהוא מתגלגל."},"ICON-0576":{"nm":"תג בדיקת מצב","de":"תג שכותבים עליו בשורה אחת את המצב של היום ותולים. לסמן בכנות טוב ורע הוא אומץ קטן. במקום להעמיד פנים שהכול בסדר, כותבים את העצמי של היום, ומישהו יקרא את השורה ההיא וידאג בשקט."},"ICON-0577":{"nm":"קפסולת מבשם לנעליים","de":"קפסולת ריח שמכניסים בפנים לנעל. נחמה קטנה ועדינה שמוגשת לרגליים שסבבו את הבמה כל היום. הריח הטוב ביותר למקום שעבד הכי קשה; עדינות מגיעה עד לקצות האצבעות, בלי לפספס דבר."},"ICON-0578":{"nm":"טבלת מידות מדרס","de":"טבלה שחורטת בבירור את מידת הרגל אפילו על מדרס אחד. זוג שמתאים בול מקל את הצעדים על הבמה. להביא בחשבון פסיעה שונה אצל כל אחד; התאמה טובה היא, בסוף, לב שמביט לעומק בזולת."},"ICON-0579":{"nm":"מחזיק מפתחות עם כף נעליים","de":"מחזיק מפתחות עם כף נעליים שהוקטנה לגודל כף יד. התחשבות קטנה שמחליקה את הרגע הקצר של נעילת נעל. רגליים שיוצאות לדרך תמיד נושאות איתן, תלויה בעדינות לצידן, יד עוזרת עדינה של מישהו."},"ICON-0580":{"nm":"כיסוי אבק לתיק","de":"בד שמכסה בעדינות תיק אהוב מפני אבק. גם כשאינו בשימוש, הוא מרדים אותו בעדינות ושומר על המרקם שלו. דברים שהלב שוהה בהם, גם אם היד לא נוגעת בהם לעיתים קרובות, נושאים בהם טיפול שקט כזה."},"ICON-0581":{"nm":"סיכת כיוונון רצועה","de":"סיכה שמהדקת רצועה משוחררת בדיוק לגוף. כשרפוי מדי הכתף מחליקה, וכשהדוק מדי הנשימה נעתקת. בכיוון הקטן שמוצא את הבדיוק, גם תלבושת הבמה וגם הלב מוצאים סוף סוף נחת."},"ICON-0582":{"nm":"עט סיכה לרוכסן","de":"מעבירים פעם אחת על רוכסן תקוע והוא מחליק שוב בעדינות. כמה מרענן הצליל של משהו תקוע שמשתחרר לפתע. מה שמזרים מחדש מקום שנתקע הוא פס אחד של חלקות."},"ICON-0583":{"nm":"קצה ניקוי לנעלי ספורט","de":"קצה זיפים שמנקה נעלי ספורט מכוסות אבק ועפר, נקודה אחר נקודה. מחוץ לבמה, הוא מוחק בקפידה את עקבות האימון הבלתי נראים. כשרואים את חוד הנעל לבן שוב, מרגישים שמחר אפשר לרוץ בלב מחודש."},"ICON-0584":{"nm":"מכסה תרסיס אטימה למים","de":"מכסה של איטום מים שמגלגל טיפות גשם לכדורים ומפיל אותן. לצפות מראש בשכבה אחת כדי שכלום לא ירטב היא עדינות שמביטה רחוק קדימה. מכיוון שיודעים שימי גשם יבואו, עוטפים שכבת קרום אחת סביב היום הבהיר של עכשיו."},"ICON-0585":{"nm":"בד הגנה לעור","de":"בד שמונח בעדינות על עור כדי למנוע קמטים. הוא שומר על המרקם כמו יד ישנה שעטפה מסך מתקפל בנייר האנג'י. ככל שדבר יישאר קרוב זמן רב יותר, כך לוקחים אותו לאט; להתרגל הוא רק שם אחר לזמן שמושקע בטיפול."},"ICON-0586":{"nm":"רצועת שם למזוודה","de":"רצועת שם שמאפשרת לזהות במבט אחד את התיק שלך בין אינספור תיקים אחרים. בין המטענים שסובבים על המסוע, היא מרימה יד עם אות אחת. לא משנה כמה רחוק נוסעים, שם אחד הוא הביטחון של להיפגש שוב."},"ICON-0587":{"nm":"קליפס לשקית דחיסה","de":"קליפס שלוחץ מטען שהתנפח לשטוח וסוגר אותו. זה פחות ריקון ויותר קיפול מסודר. מקצה אצבע שמצמצם בקפידה את משק הבית, גם התאווה מתכווצת, כפי שהמטען הלחוץ בחוזקה מספר בשקט."},"ICON-0588":{"nm":"גיליון אבקת כביסה לנסיעות","de":"גיליון אבקת כביסה שהופך כיור לכביסה בפיסה אחת. הוא דומה לחוכמת הנווד של כיבוס בגדים ביד רחוק מהבית. לצאת לדרך בקלילות אך עדיין לארוז סדר, גישה ישנה של מטייל בדרכים."},"ICON-0589":{"nm":"כיסוי לכרית צוואר","de":"כיסוי נקי שמחליפים על הכרית שתמכה בצוואר. מקום להישען עליו צריך תמיד להיות נקי כדי שהלב ירגע. להשאיר מקום רך ופנוי כדי שמישהו יוכל להישען בנוחות; אירוח מתחיל שם."},"ICON-0590":{"nm":"רצועת שקילה למזוודה","de":"רצועה שמרימה תיק כדי לאמוד את משקלו. לפני היציאה, אוחזים ביד מראש את משקל המטען. בין מה שלוקחים למה שמשאירים, רגע של שקילה שקטה גם למשקל הלב."},"ICON-0591":{"nm":"זוג נרתיקים לנעליים","de":"זוג נרתיקים שמכיל זו לצד זו שתי נעליים, שמאל וימין. קל לאבד אותן כשהן לבד, אך מרגיע כשהן מזווגות. לדברים שתמיד הולכים ביחד יש כוח לשמור זה על זה בשקט."},"ICON-0592":{"nm":"חישוק תיק נוסף","de":"ביום שיד אחת לא מספיקה, חישוק קטן לתלות עליו תיק לרגע. תא רזרבי לימים עם יותר מטען משאפשר לשאת. רק העובדה שיש איפה לתלות לרגע הופכת את הכתפיים לקלות הרבה יותר."},"ICON-0593":{"nm":"שבב לוח זמנים לנסיעה","de":"חורטים בבירור על שבב אחד את מסלול היום. איפה להיפגש ולאן לזרום הלאה, קו הנחיה שנמתח מראש לצעדים שמתקשים למצוא דרך. דרך שהולכים בה יחד, כשרושמים אותה תא אחר תא, כמעט לא נודדת לאיבוד."},"ICON-0594":{"nm":"מכסה מתאם רב-תכליתי","de":"מכסה שמתאים היטב אפילו לשקעים של ארץ זרה. שונה בצורתו, אך בסוף מחובר כאחד. לחבר דברים שהגיעו ממקומות שונים; הרמוניה מתחילה בשקט בהמרה קטנה אחת."},"ICON-0595":{"nm":"נרתיק שקוף לכרטיס נסיעה","de":"גיליון שקוף אחד שמגן על הכרטיס בכל פעם שהוא נוגע בקורא. הנסיעה היומית, כל סימן שנמחק משימוש, עטופים בחן. גם דרך רגילה הופכת לזיכרון כשמוקירים אותה, כפי שהשכבה הדקה הזו מוכיחה."},"ICON-0596":{"nm":"קליפס לכרטיס נסיעה","de":"קליפס שאוחז בקפידה בכרטיס שמתקמט כה מהר. לאבד כרטיס בדרך מרעיד גם את הלב. ככל שהנייר קטן יותר, כך מחזיקים אותו בחוזקה; הביטחון של המסע מגיע בדיוק מהתא הקטן ההוא."},"ICON-0597":{"nm":"שבב פתק החלפה","de":"שבב קטן עם רשומה בשורה אחת איפה להחליף. בכל צומת דרכים מבלבל, מילה אחת שנכתבה מראש פותחת את הדרך בבהירות. פתק הוא רמז עדין שמוגש בחשאי לעצמי העתידי שעלול ללכת לאיבוד."},"ICON-0598":{"nm":"תג מעבר בשער","de":"תג מעבר שמזוהה בשקט כשעוברים דרך השער. גם דרך שנראתה חסומה נפתחת בעדינות ברגע שנושאים את ההסמכה שלך. לעבור בגלוי הוא לצעוד קלות אל התא הבא בלי היסוס."},"ICON-0599":{"nm":"מחזיק קבלות מונית","de":"על כל פיסת נייר קטנה טבוע בבירור עקבות הדרך שעברו באותו יום. אוספים את הקבלות שהתגלגלו לכל עבר ותוחבים אותן יחד בסדר, ואפילו יום לא יוצא דופן נערם, פיסה אחר פיסה, למסע של ממש."},"ICON-0600":{"nm":"רצועת זוהרן לאופניים","de":"רצועה שקולטת אור עובר בדרך אפלולית ונוצצת בשקט. גם בלי להאיר בעצמה, היא מתבהרת באורו של מישהו אחר. להיראות הוא בקשה עדינה של דרך הלילה, שבבקשה תחזרי הביתה בשלום."},"ICON-0601":{"nm":"כיסוי לגלגלי מזוודה","de":"הסיבה שפינות המזוודה שלך נשארות שלמות אחרי אלפי סיבובים על מסועי שדה התעופה היא הכיסוי הקטן הזה שעוטף את הגלגלים. החלק שפוגש ראשון את הדרך הכי מחוספסת - להגן על מישהו בשקט תמיד מתחבא במקום שאיש לא שם לב אליו."},"ICON-0602":{"nm":"כיסוי למשענת ראש","de":"בנסיעת אוטובוס ארוכה, מכסים את משענת הראש בבד ונשענים אל החלון. ריח הנוסע הקודם, העייפות של אתמול - שום דבר מזה לא מגיע לכאן. מקום נקי להניח עליו את הראש הוא נחמה גדולה במפתיע בדרך זרה."},"ICON-0603":{"nm":"סיכת מיקום חניה","de":"\"באיזו קומה, באיזה תא זה היה?\" מי שהתעה פעם בחניון ריק יודע כמה הסיכה הזאת מרגיעה. סימון אחד קטן שנתקע במקום זיכרון דוהה, קובע מראש את הדרך חזרה."},"ICON-0604":{"nm":"רצועת מפתח לחדר","de":"איך זה שמפתח חדר נעלם כל כך בקלות? משחילים אותו על רצועה ותולים על פרק כף היד, וכבר אי אפשר לשכוח את החדר שמחכה הלילה. גם בעיר זרה, ההקלה הקטנה של מקום משלך תלויה על שורש כף היד."},"ICON-0605":{"nm":"שלט תלייה לדלת","de":"כשהחזרה מתחילה, תולים שלט קטן על הדלת. אל תפריעו - זהו זמן לריכוז טהור. השקט העמוק מאחורי הקלעים נשמר בלי מילים על ידי סימנים קטנים כאלה."},"ICON-0606":{"nm":"נרתיק כלי רחצה","de":"מברשת שיניים, סבון פנים, מגבת בגודל כף יד. לא משנה לאן נוסעים, אורזים רק את הנרתיק הזה וסוף היום ותחילתו תמיד מסודרים באותן ידיים מוכרות. חופן קטן של סדר בית שהופך מיטה זרה למוכרת כמעט מיד."},"ICON-0607":{"nm":"קליפס למגבת רזרבית","de":"ליד הכיור, המגבת הרזרבית תמיד ישבה רטובה בלי מקום משלה. תופסים אותה בקליפס ותולים, וסוף סוף היא מוצאת את מקומה. לתת למשהו מקום להתייבש - חסד בדרך כלל נראה בערך בגודל הזה."},"ICON-0608":{"nm":"נרתיק למפצל חשמל","de":"בכל פעם שפתחת את התיק, המטענים היו סבוכים בגוש אחד. גוללים את כל המפצל ותוחבים פנימה, והכול מסתדר. חוט שמתפתל ונרפה - זו גם פינה קטנה בלב שמתרפה לפני הנסיעה."},"ICON-0609":{"nm":"תווית מספר למיטה","de":"תג מספר על כל מיטת קומתיים במעונות. עם תווית אחת שמספרת לך איזה מקום שלך, גם חדר זר וחדש הופך לבית עם רדת הלילה. ההתחלה תמיד כל כך קטנה."},"ICON-0610":{"nm":"חבל כביסה מיני","de":"תולים את שני הקצוות בין מסגרות החלון וזה הופך לחבל כביסה. ביום שמשי, כמה גרביים שכובסו ביד מתנדנדות רכות ויבשות ברוח. גם רחוק מהבית, החיים היומיומיים מתייבשים על חבל כזה."},"ICON-0611":{"nm":"תג זיהוי לכפכפים","de":"כשכפכפים מצטברים ליד הדלת, אי אפשר לדעת של מי הם. תולים תג קטן וגם הנעליים מזהות את הבעלים שלהן. חיים צפופים ביחד עם אחרים דורשים בדיוק סימנים ידידותיים כאלה."},"ICON-0612":{"nm":"מחזיק שובר ארוחת בוקר","de":"מחזיק לתקוע בו את שובר ארוחת הבוקר. בבוקר מוקדם ורעב, פתק אחד מבטיח קערת מרק מהבילה. יום בדרכים תמיד נפתח לאט עם ארוחה חמה אחת."},"ICON-0613":{"nm":"רצועת זוהרן לקרסול","de":"כורכים אותה סביב הקרסול והיא מחזירה אור בחושך. בהליכת לילה, היא מנופפת בשקט למכונית מתקרבת מרחוק - \"יש כאן מישהו\". הביטחון נוצץ בענווה כזאת."},"ICON-0614":{"nm":"מכסה למגבונים ניידים","de":"מכסה שמתאים בדיוק לפתח חבילת מגבונים. כל דף נשלף ברכות, והשאר לא מתייבשים. נראה שולי, אבל לדברים שנוגעים בהם כל יום תמיד יש סיבה טובה שמסתתרת בהם."},"ICON-0615":{"nm":"רצועה למחצלת פיקניק","de":"גוללים את המחצלת לעיגול וקושרים ברצועה. גדת הנהר, צל פריחת הדובדבן - ברגע שפורשים אותה, המקום הזה הופך לשלנו. רצועה שנושאת איתה שטח מדשאה בגודל כף יד לכל מקום."},"ICON-0616":{"nm":"קופסה למדבקות יתושים","de":"פריט חיוני לליל קיץ, קופסה שמחזיקה מדבקות נגד יתושים. תשומת הלב של להיערך מראש, לפני שהגירוד מתחיל, נכנסת לתא הקטן הזה. השורות האחוריות של במה בחוץ תמיד מתחזקות בזכות הכנות קטנות כאלה."},"ICON-0617":{"nm":"וו לבקבוק מים לטיול","de":"וו לתלות בקבוק מים על התיק כשיוצאים לטיול. לדעת שיש מים בהישג יד כשהצמא מגיע פירושו שאפשר ללכת עוד קצת יותר רחוק. חיבור קטן שלא נותן להולך לעצור."},"ICON-0618":{"nm":"סל קניות מתקפל","de":"פותחים וזה סל קניות; מקפלים וזה נכנס לכף היד. בדיוק מתאים לצרור ירקות שהתאהבת בו תוך שיטוט בסמטאות השוק. חוכמת משק הבית תמיד גדלה לכיוון של פחות נפח, לכיוון של קלילות בנשיאה."},"ICON-0619":{"nm":"קליפס לעצירת רוח","de":"ביום סוער, הוא תופס את קצה האוהל המתנפנף ומחזיק אותו חזק. קליפס אחד לוחץ למקום את מה שהמשיך להתנועע. בחוץ, הדבר הכי אמין הוא, באופן מפתיע, משהו בגודל אצבע."},"ICON-0620":{"nm":"סיכת הצללה מהשמש","de":"סיכה שתוקעים בחלון כדי להטות ולחסום את קרני השמש. כשאור הצהריים חזק מדי, היא מטילה בעדינות חופן צל. להקל על הסנוור יכול להיות, עבור מישהו, המגע הכי אדיב שיש."},"ICON-0621":{"nm":"מכסה למשרוקית חירום","de":"מכסה שמכסה את פתח משרוקית החירום. שומר על אבק בחוץ, כדי שברגע האמת היא תישמע בנשימה אחת. יש דברים שמביאים שלווה רק בזכות נוכחותם, גם כשמקווים שלעולם לא נצטרך להשתמש בהם."},"ICON-0622":{"nm":"מכסה לקצה מטרייה","de":"מכסה קטן שמלביש על קצה המטרייה. כשהקצה החד מתעמעם, לא נפגע האדם שלידך ולא התיק שלך. נימוסי יום גשום מתחילים בשקט מלעטוף קצה חד וחדש ולעשות אותו רך ועגול."},"ICON-0623":{"nm":"נרתיק למעיל גשם","de":"נרתיק לגלגל מעיל גשם מקופל ולתחוב פנימה. הוא ממתין בשקט בפינת התיק עד לגשם הבא. הכנה היא, בסופו של דבר, פיסת לב שאורזת מראש את מה שאולי לעולם לא ישמש."},"ICON-0624":{"nm":"כיסויי נעליים אטומים למים","de":"מכסים בהם את הנעליים והגשם כבר לא חודר. גם בהליכה לבית הספר בגשם השוטף, הגרביים נשארות יבשות. יום שבו לא נרטבת עד קצות האצבעות משנה את מצב הרוח הרבה יותר ממה שנדמה."},"ICON-0625":{"nm":"פד נגד החלקה בשלג","de":"מדביקים לסוליות הנעליים ודרכים מקורחות מפחידות הרבה פחות. באותו חורף שרצת בצעדים קטנים דרך סמטאות מכוסות שלג, הפד הזה החזיק אותך יציב בשקט. העוצמה המרגיעה שמסתתרת מתחת לצעדים זהירים."},"ICON-0626":{"nm":"טבעת צוואר מקררת","de":"עוטפים סביב הצוואר וזרם קריר מתיישב בשקט. חוכמת הקיץ של לענוד רצועת קרירות על העורף גם בשיא החום המהביל. גם דרך ההתמודדות עם החום נהיית קצת יותר חכמה מדי שנה."},"ICON-0627":{"nm":"מעמד למאוורר יד","de":"מעמד להעמיד עליו מאוורר יד. כששתי הידיים משתחררות, אפשר גם לדפדף וגם לכתוב במקום לנפנף. משב רוח קטן הופך קיץ ארוך ליד השולחן לנסבל בקושי."},"ICON-0628":{"nm":"נרתיק לחימום כפות ידיים","de":"נרתיק לשאת בו חימום כפות ידיים. כשתוחבים אצבעות קפואות לכיס כדי לחמם אותן, חום קטן כבר שם, מחכה. יציאות בחורף שורדות בזכות החופן הזה של חום."},"ICON-0629":{"nm":"נרתיק לאוזניות חורף","de":"נרתיק לשמור בו אוזניות חורף. מקום להניח אותן שם בעדינות עד שהקור הבא יגיע. דברים שקשה לזרוק כשהעונות מתחלפות נושאים אמונה שקטה בחורף שנפגוש שוב."},"ICON-0630":{"nm":"שבב מדידת קרינת UV","de":"מקרבים בעדינות לאור והשבב מספר בצבע את עוצמת קרינת ה-UV של היום. הוא הופך סוף סוף את עוצמת השמש הבלתי נראית לגלויה. כמו לחבר עין קטנה שקוראת את השמיים ולענוד אותה בשקט על פרק כף היד."},"ICON-0631":{"nm":"לוח חותמות שכונתי","de":"לוח שממלאים בחותמות מכל חנות לאורך הסמטה. עם כל משבצת שמתמלאת, מפת השכונה מצטיירת בבירור בלב. זיכרונות שנאספו ברגל נשארים ככתמי דיו כאלה."},"ICON-0632":{"nm":"לוח סיכות למקומות שביקרת בהם","de":"לוח קטן שתוקעים בו סיכה על כל מקום שביקרת בו. ככל שהנקודות מצטברות, גם היקף העולם שלך מתרחב יחד איתן. כל סיכה היא עקבה שאומרת בשקט, \"הייתי כאן\"."},"ICON-0633":{"nm":"חוט למצפן קטן","de":"כמה שלא תיעה, הצפון לבדו תמיד נשאר במקומו. המצפן הקטן שתלוי על החזה, כשאין לך מושג לאן ללכת, מרגיע קודם כול, בשקט, את הלב הרועד."},"ICON-0634":{"nm":"טבעת פתקי הכוונה","de":"פתקים שכתבת בזמן חיפוש הדרך, מושחלים על טבעת. \"פנה שמאלה בתיבת הדואר האדומה.\" כתב יד מגושם של מישהו מנחה בשקט סמטה זרה. דרך שנשארת על נייר כמעט אף פעם לא מתעמעמת."},"ICON-0635":{"nm":"ספר מדבקות אתרים","de":"ספר שממלאים במדבקה אחת שנקנתה בכל יעד. מגדלים, גשרים, חומות מבצר עתיקות נערמים דף אחר דף. לאסוף את המקומות שביקרת בהם דומה לגעת מחדש בקצות האצבעות בזמן שחלף."},"ICON-0636":{"nm":"שבב החלפת רכבת תחתית","de":"שבב שאוחזים חזק בתחנת מעבר שבה הקווים מתפצלים. הרגע הקצר של הבחירה לאן להחליף יכול לפעמים לשנות לגמרי את כיוון היום כולו. בבחירה קטנה אחת, העיר מראה פנים אחרות."},"ICON-0637":{"nm":"קלף גילוי שכונתי","de":"\"היום, עד המאפייה בשכונה הזאת.\" שולפים קלף אחד ויעד היום נקבע. גם סמטה מוכרת שעוברים בה תמיד הופכת לדרך חדשה כשמופיעה משימה. קלף שמזכיר שההרפתקה לא רחוקה."},"ICON-0638":{"nm":"מחזיק כרטיסי ביקור מחנויות","de":"מחזיק לתקוע בו כרטיסי ביקור שקיבלת מהחנויות האהובות עליך. המקום הטעים, הבעלים האדיב - הם מצטברים תא אחר תא. להתאהב בעיר מתחיל מפיסות נייר קטנות כאלה."},"ICON-0639":{"nm":"לוח תגי סיום מסלול","de":"לוח שבו סיום מסלול הליכה עד הסוף מזכה בתג. הגמול של ללכת עד הסוף נשאר בידך כפיסת מתכת עגולה. הגאווה שרק מי שהלך עד הסוף מכיר נחקקת כאן בבירור."},"ICON-0640":{"nm":"מחזיק מפתחות עם מנעול לתיק","de":"מנעול קטן עם מחזיק מפתחות שמצמידים לרוכסן התיק. הוא שומר על הדברים היקרים בקפדנות בזמן שהוא מקשקש בקצה התיק. בן לוויה חכם למדי של המטייל, שבו ביטחון וקישוט הופכים לאחד."},"ICON-0641":{"nm":"תג נגד אבדן","de":"הוא כורע בחשכה העמוקה ביותר של התיק, וברגע שכולם כבר מוותרים, הוא מהבהב בעדינות. \"כאן.\" הצליל של משהו שחשבת שאבד חוזר לקצות האצבעות שלך. קטן ככל שיהיה, הוא נשאר לצד בעליו עד הסוף."},"ICON-0642":{"nm":"טבעת נעילה לרוכסן","de":"קליק - ברגע שהוא ננעל, אף יד רגילה לא יכולה לפתוח אותו. עקשנות שחוסמת בשווה יד נחפזת וגם אצבע ערמומית שמתקרבת בשקט. הביטחון מזכיר לך, במשקלו המוצק, שזה בסדר להיות קצת קשוח לפעמים."},"ICON-0643":{"nm":"רצועת פעמון נגד גניבה","de":"שוער בלתי נראה ששומר שהמוצרים על המדף לא יצאו לטיול לפני התשלום. כשיד ישרה נוגעת בו במעבר, הוא נשאר שותק עד הסוף. פעמון שלא מצלצל הוא הפעמון השליו ביותר מכולם."},"ICON-0644":{"nm":"תווית הסתרת פרטי קשר","de":"היא מניחה בשקט שכבה מעל השם והמספר על קופסת חבילה. מי גר כאן, לאן זה הולך - רק המקבל צריך לדעת. להסתיר היטב זה גם סוג של אדיבות, היא אומרת, שומרת בשקט על מקומה."},"ICON-0645":{"nm":"רצועת כריכה לדרכון","de":"שדה תעופה זר, עשרות כריכות זהות מסתובבות על המסוע בשעת שחר. בתוך כל אלה היא מנפנפת \"לכאן\" בצבע שרק אתה מכיר. מעיל קטן שמלבישים על התעודה היוצאת לדרך ארוכה. גם כשהכריכה נשחקת, המסע נשאר בהיר."},"ICON-0646":{"nm":"נרתיק להפרדת מזומן","de":"שטרות משמאל, מטבעות מימין, כסף לשעת חירום בתא שאף אחד לא יודע עליו. זה המקום הראשון שיד טרייה מהשוק פונה אליו. גם יום מבולגן מוצא בפנים סדר, בקול מקשקש, במקומו."},"ICON-0647":{"nm":"מדבקת חותם אבטחה","de":"קולפים פעם אחת וסימן נשאר. מצפון קטן וישר שלעולם לא יכול להסתיר לגמרי \"מישהו פתח אותי\". מתחת לכל קופסה שהגיעה חתומה ובטוחה מסתתרת השתיקה הבלתי מתפשרת של החבר הזה."},"ICON-0648":{"nm":"שבב איש קשר לחירום","de":"כיס של ילד שהלך לאיבוד, פנים של תיק מחשב נייד, קצה רצועת כלב. גם כשהרגע לא יכול לדבר, השבב קורא בבירור את המספר במקומו. בשבב קטן אחד מסתתר \"בבקשה קחו אותי הביתה\" שלם."},"ICON-0649":{"nm":"מכסה שלט למקל סלפי","de":"תמונות קבוצתיות שבהן תמיד מישהו נחתך בגלל חוסר באורך זרוע. עכשיו נגיעה קלה בכפתור בקצה מכניסה את כל המשפחה לפריים אחד. באותו רגע שכולם מחייכים, אני לוחץ בשקט על התריס וקופץ פנימה."},"ICON-0650":{"nm":"חוט לנרתיק עדשות","de":"חוט שמחבק עדשות רזרביות כדי שלא יתנגשו בתוך התיק. מכיוון שפיסת זכוכית אחת שווה נוף שלם, לא מנערים את המשקל הזה בקלות ראש. הזהירות של הצלם קשורה בכל קשר."},"ICON-0651":{"nm":"טבעת נרתיק פילטרים","de":"דף דק אחד הופך אותם שמיים לאור אחר. מקום לשמור את הקסמים הקטנים האלה מסודרים בקן עגול. בכל פתיחה של הנרתיק, קצות האצבעות מתרגשים לרגע - איזה שקיעה אתפוס היום?"},"ICON-0652":{"nm":"נרתיק לחצובה","de":"מקופל - זרת אחת, פרוש - שלוש רגליים יציבות בלי רעד. גוללים בעדינות את החבר שיחזיק את הנוף במקום הידיים הרועדות. ככל שהציוד כבד יותר, כך מגיע לו לשכב על בד רך יותר."},"ICON-0653":{"nm":"כרית לרצועת מצלמה","de":"מהלכים כל היום ומגיע רגע שבו המצלמה לוחצת על הכתף. אז כרית קטנה אחת נוטלת בשקט חלק מהמשקל הזה. נחמה קטנה ורכה שמונחת על כתף שהולכת דרך ארוכה בשביל צילום אחד טוב."},"ICON-0654":{"nm":"כרטיס מיון זיכרון","de":"לילות שבהם קשה לזכור באיזה כרטיס נחות מאות זיכרונות, וסימנים צבעוניים מסמנים את הדרך. טיול אביב בכחול, במה ראשונה בצהוב. ספרנית קטנה ואדיבה שנותנת גם לזיכרונות מדף משלהם."},"ICON-0655":{"nm":"גליל כבל טעינה","de":"לפני שהכבלים עורכים מופע קשרים בתוך התיק, מגלגלים אותם עגול ומרדימים אותם מסודרים. מסדרים חוט אחד ואיכשהו גם פס אחד בלב מתרפה יחד איתו. המראה המגולגל שקט להסתכל עליו."},"ICON-0656":{"nm":"תווית גיבוי תמונות","de":"\"התמונות האלה, גיביתי אותן?\" פתק קטן שעונה מראש לחרדה הזאת שעולה בשעת לילה מאוחרת. ככל שהרגע יקר יותר, כך הוא חייב לחיות ביותר ממקום אחד - כך התווית כותבת בבירור."},"ICON-0657":{"nm":"לוח מסגרת קומפוזיציה","de":"מסתכלים על העולם דרך החלון המרובע ורואים מיד מה לכלול ומה להשאיר בחוץ. תמונה טובה היא לא להוסיף עוד, אלא לגרוע היטב - זה מה שהמסגרת הריקה מלמדת ראשונה."},"ICON-0658":{"nm":"תליון ארנק מטבעות","de":"הוא מתנדנד בקצה התיק, מכיל כמה מטבעות. אוצר קטן שנפתח ראשון מול מכונת ממכר, מול דוכן דגי אורז מהביל. הצליל המקשקש הזה הוא אפקט הקול של אושר קטן."},"ICON-0659":{"nm":"מוט לאיסוף קבלות","de":"פיסות נייר שכמעט זרקת משוחלות אחת אחרי השנייה. מה אכלת וקנית היום - הקבלה היא יומן כן יותר מכל פנקס הוצאות. אוספים חודש שלם והוא הופך לתיעוד עבה למדי של החיים."},"ICON-0660":{"nm":"תווית סל שוק","de":"היא נתלית על פרק כף היד שיוצא לקניות ומשוטטת יחד בסמטאות השוק. חתיכת טופו, צרור בצל ירוק, ואפילו החום שמוסיפים במתנה. היא נושאת את כל המשקל הזה בלי תלונה. חברה שנרגשת יותר למלא מאשר לרוקן."},"ICON-0661":{"nm":"לוח מגנטי מזכרות","de":"בוחרים אחד בכל יעד ומדביקים על המקרר, והמטבח הופך למפת עולם קטנה. הערים שביקרת בהן תלויות זו לצד זו, לוחשות \"בואו נלך שוב\". גם פח פשוט מחזיק בכוח כזה לתפוס זיכרונות."},"ICON-0662":{"nm":"ספר חותמות אזוריות","de":"חותמת אחת בכל עמוד, הסמטאות שהלכת בהן קמות לתחייה שוב בדיו. הסימנים האדומים שנאספו בסיור ברחבי הארץ הם מפה של עקבות הצעדים שלך. ככל שהמשבצות הריקות פוחתות, המסע הבא קורא בשקט יותר ויותר."},"ICON-0663":{"nm":"סליל חוט אריזה","de":"סבלנות ארוכה, ארוכה שנמתחת בלי סוף כדי לקשור קופסת מתנה אחת. הוא מעניק קשר מסודר רק לידיים שיודעות מתי לחתוך. מגולגל, הוא ממתין בשקט לתורו הבא."},"ICON-0664":{"nm":"אריזת ריפוד למתנה","de":"הוא מרפד לב שביר בחיבוק רך. גם בתוך תא משלוחים מתנדנד, הוא מחזיק מעמד רך ויציב - \"זה בסדר, אני תומך בך\". הוא שומר מראש אפילו על החיוך הבהיר של מי שיפתח את הקופסה."},"ICON-0665":{"nm":"מדבקת כיסוי תג מחיר","de":"שקר לבן וחביב שמכסה בשקט את מחיר המתנה. \"אין צורך לדעת כמה זה עולה, רק קבל את הלב,\" היא אומרת, מתיישבת בעדינות מעל התג. לא מסתירה, אלא מבליטה את הלב הזה עוד יותר."},"ICON-0666":{"nm":"שבב עגלת קניות קטנה","de":"אי אפשר לדחוף עגלה אמיתית, אבל בחבר הקטן הזה שמתנדנד מקצה האצבע יש את כל ההתרגשות של יציאה לחנות. קטן ככל שיהיה, הפרפור של \"מה אקנה היום?\" שוקל לא פחות מהדבר האמיתי."},"ICON-0667":{"nm":"קליפס זוהר לנעליים","de":"נצנוץ בקצה נעל ספורט שיצאה לטיול לילי, שולח למכונית חולפת את האות \"יש כאן מישהו\". האור הקטן הראשון שיוצא לקבל את פניך בסמטה חשוכה. הביטחון תמיד מתחיל בשקט מקצות האצבעות של כף הרגל."},"ICON-0668":{"nm":"מכסה לפנס כיס קטן","de":"מלבישים על ראש הפנס והאור מתפזר רחוק יותר, רך יותר. קוסם קטן שמצייר צביר כוכבים על תקרת אוהל חשוכה. בלילות שבהם החושך קצת מפחיד, אין חבר טוב יותר מזה."},"ICON-0669":{"nm":"כפתור הודעת הגעה הביתה","de":"לוחצים והשורה \"הגעתי הביתה בשלום\" עפה למשפחה הרחוקה. במקום קול דלת הכניסה בשעת לילה מאוחרת, כפתור קטן אחד מוסר את הבשורה. מישהו נרדם ומחכה לאות הזה."},"ICON-0670":{"nm":"גליל מדבקות זוהרות","de":"חותכים משבצת ומדביקים על תיק, על אופניים, על מטרייה, ודרך הלילה נעשית הרבה פחות מסוכנת. ישנוני שמתעורר בהיר ברגע שהוא פוגש פנס ראשי. מגולגל, הוא ממתין לחושך הבא שיגיע."},"ICON-0671":{"nm":"כרטיס מונית חירום","de":"תוחבים בתא בארנק וגם תחנה ריקה בשעת לילה מאוחרת מרגישה פחות מדכאת. מספר אחד, שורת כתובת אחת כתובים כמו הבטחה - \"אקח אותך הביתה\". מי היה מאמין שהמילה חירום יכולה להיות כל כך מרגיעה."},"ICON-0672":{"nm":"רצועת מפת דרכי לילה","de":"הולכים ברחובות דלי תאורה עם הרצועה הזאת כרוכה על פרק כף היד. איזו סמטה בהירה, איפה חשוך - היא חושפת בשקט את הקיצור שרק הלילה מכיר. רצועה שקושרת עצמה לצדך כדי שלא תאבד כיוון בחושך."},"ICON-0673":{"nm":"נרתיק אזעקת ביטחון","de":"מושכים אותה במצב חירום והיא צורחת חזק מספיק כדי להבהיל את כל הסמטה. בשאר הזמן היא מסתתרת בשקט בתוך הנרתיק, חוסכת את קולה לרגע האחד הזה. הצעקה הגדולה ביותר, שמורה בתיק הכי קטן."},"ICON-0674":{"nm":"מחזיק מפתחות עם אור לדלת","de":"להתראות ללילות של גישוש אחר חור המנעול בקצה מסדרון חשוך. תלוי ליד הדלת, הוא מקבל את פני היד החוזרת באור עגול. \"כל הכבוד, הגעת הביתה\" - המחזיק מפתחות מברך ראשון."},"ICON-0675":{"nm":"פתק חזרה לחדר","de":"\"קח מטרייה, כבה את האור לפני שאתה יוצא.\" תזכורת קצרה על המקרר שומרת על החדר הריק. פתק קטן למי שעתיד לחזור. האדיבות שבדף נייר אחד מלווה בשקט עד לדלת הכניסה."},"ICON-0676":{"nm":"מסרק לסידור כבלים","de":"הוא מסרק כבלים סבוכים בעדינות למשעי וישר, כמו סירוק שיער. יער הכבלים שנראה כמו ג'ונגל מאחורי השולחן נעשה מסודר בכמה תנועות מסרק. לא רק שיער מסתבך, המסרק מזכיר בשקט."},"ICON-0677":{"nm":"מחיצה למעמד עטים","de":"עפרונות כאן, טושים שם, מספריים בתא האחרון. הוא מחלק כפר קטן בתוך כוס אחת ונותן לכל עט את מקומו. עם תאים, היד כבר לא תועה. תחילתו של סדר קטן על השולחן."},"ICON-0678":{"nm":"קליפס פתקים למסך","de":"הוא נתלה בצד המסך ומציב את \"המשימות של היום\" בדיוק בגובה העיניים. לוח הודעות קטן שרואים ישירות, בלי סיכוי לשכוח. קליפס אחד תופס בשקט את הלב שממשיך לנסות לדחות."},"ICON-0679":{"nm":"מגש מיון למגירה","de":"אטבים וגומיות, נעצים ומחקים. הוא נותן לכל שבט קטן במגירה חדר משלו. כשהיד מגיעה לתאים מחולקים, זמן החיפוש מתקצר ופינה בלב נעשית קלה יותר."},"ICON-0680":{"nm":"מארז מברשת אבק","de":"גם גרגר אבק בודד שמונח על עדשה הופך בתמונה לכתם ענק. לכן המברשת ממתינה בתוך המארז שלה, תמיד מוכנה ונקייה. קצה אצבע חרוץ ששומר על ניקיון שאיש אף פעם לא שם לב אליו."},"ICON-0681":{"nm":"פינת משטח שולחן","de":"זרת אחת של רכות מונחת בפינת השולחן. עטים לא מתגלגלים ונופלים, ובמקום זכוכית קרה, מרקם חמים תומך בפרק כף היד. משטח אדיב שנותן את מקומו ראשון, כדי שהכתיבה בלילה ארוך תישאר יציבה."},"ICON-0682":{"nm":"מחזיק לחוט עכבר","de":"כשהחוט מסתבך, גם הלב מסתבך איפשהו. מגע שתופס גדיל תועה מראש ומניח אותו מסודר. כמעט לא נראה לעין, אבל מסדר בשקט את מרקם השולחן - סידור קטן וחרוץ."},"ICON-0683":{"nm":"מעמד לתחנת טעינה","de":"מקימים מכשיר ששכב שטוח לזקוף אלכסוני, והמסך סוף סוף פוגש את העיניים. אפילו ההמתנה בזמן הטעינה נעשית מסודרת. לתמוך פירושו לתת גם למשהו שנח רגע, יציבה נכונה."},"ICON-0684":{"nm":"תווית לפח אשפה קטן","de":"גם לפח הכי קטן יש שם משלו. השורה \"זרקו כאן\" קוראת בשקט לסדר על שולחן מבולגן. תווית היא, בסופו של דבר, ברכה קטנה שאומרת לחפץ: כאן השימוש שלך."},"ICON-0685":{"nm":"סיכה ללוח מחיצה","de":"היא לוחצת דף נייר בחוזקה על הלוח. להפקיד בקיר, לרגע, רגש שלא רוצים לשכוח. ההחלטה של היום התלויה על קצה הסיכה מתנדנדת קלות ברוח, ותופסת אותך בכל פעם שאתה עובר."},"ICON-0686":{"nm":"שבב מסגרת לתוויות","de":"מסגרת מרובעת אחת הופכת כתב רגיל למשפט אחד וברור. שבב שעוטף כבוד מסודר סביב פתקים שנוטים להתפזר בקלות. לא לכלוא, אלא לחבק מילים חשובות כדי שלא יאבדו."},"ICON-0687":{"nm":"ידית למגירה שקופה","de":"מציבים ידית על מגירה שקופה, ואפשר לראות מה יש בפנים בלי לפתוח אותה בקלות ראש. מרחק בגודל זרת - גלוי, אך לא מתקרבים. גם לשקיפות דרושים נימוסים, כך המגירה לוחשת."},"ICON-0688":{"nm":"קליפס נעילה למכסה","de":"משאירים פתוח והריח והצבע נעלמים בשקט. עם צבת קטנה אחת שנועלת את המכסה חזק, צבע האתמול נשאר שלם עד מחר. לנעול הוא, למעשה, מעשה של הגנה על מה שיקר לך."},"ICON-0689":{"nm":"מחזיק לחומר סופג לחות","de":"שומר קטן ששונא לחות ושומר בשקט על עמדתו. לשמור אוויר יבש קרוב הוא התנאי הראשון לאחסון ארוך טווח, המחזיק המסודר הזה מזכיר בשקט. כך היובש נשמר."},"ICON-0690":{"nm":"תווית סל אחסון","de":"תווית שם קטנה על כל סל. קובעים מראש איזה תא מכיל מה, והזמן שהיה מוקדש לחיפוש הופך ישר לזמן מנוחה. סידור הוא פתק אדיב שמעבירים מראש לעצמך העתידי."},"ICON-0691":{"nm":"לוח מחיצה מיני","de":"מחיצה קטנה שמקימה במהירות חדר נעים על השולחן. עם לוח אחד זה, מופיעה פינה שקטה שמפנה קצת עורף לעולם. מקום נעים משלך, מתאים לריכוז להתיישב בו."},"ICON-0692":{"nm":"מעמד לשקיות אחסון","de":"מעמד שתומך בעדינות בגב שקיות שהמשיכו ליפול. רק מזה שהן עומדות מסודרות בשורה, קל הרבה יותר לבחור. להעמיד דברים זקוף פירושו לדאוג מראש ליד הבאה."},"ICON-0693":{"nm":"שבב סימון תא ריק","de":"שבב שמסמן במכוון ריקנות. להשאיר מקום שצריך למלא הוא בהחלט תוכנית בפני עצמה. תא ריק הוא לא עצלות, אלא שוליים בגודל זרת שהושארו פנויים בנימוס למשהו שעומד להגיע בקרוב."},"ICON-0694":{"nm":"מכסה למברשת שיניים","de":"למברשת שנוגעת בפה שמים לב תובעני יותר. כובע קטן אחד שחוסם אפילו גרגר אבק בודד. לטפל בניקיון בלתי נראה הוא בדיוק המסירות הקטנה שפותחת כל בוקר רענן."},"ICON-0695":{"nm":"רשת מעמד לסבון","de":"רשת שמצפה בעדינות את הסבון כדי שלא ירכך בשוכבו במים. את העיקרון שלנקז את המים שומר אותו זמן רב יותר, היא מוכיחה בשקט כל יום מהמקום הנמוך והקטן ביותר באמבטיה."},"ICON-0696":{"nm":"קליפס למשאבת שמפו","de":"הוא תופס בעדינות את ראש המשאבה, כך שלחיצה אחת משחררת בדיוק את הכמות הנכונה. ההרגל של שימוש חסכוני הוא הבסיס של משק בית שמחזיק מעמד לאורך זמן. קליפס קטן אחד מרסן בעדינות בזבוז."},"ICON-0697":{"nm":"מכסה תלייה לסכין גילוח","de":"לדברים חדים מכינים בית קטן משלהם. תוחבים את הסכין למכסה ותולים, ולחות וסכנה מנוקזות יחד. לטפל בחדות בזהירות הוא, בסופו של דבר, גם דרך לטפח את עצמך."},"ICON-0698":{"nm":"טבעת מגבת מקלחת","de":"מגבת ארוכה ומתמתחת יוצרת לולאה ומגיעה לגב שהיד לא הגיעה אליו. לאורך אותו קו אחד שבו הקצף מחליק, חום אדיב שמצחצח את הגב לבד מתפשט חמים בכל האמבטיה."},"ICON-0699":{"nm":"רשת סינון לניקוז","de":"רשת קטנה אחת שנותנת למים לזרום ותופסת את השאריות. במקום שאיש לא רואה, היא מונעת בשקט סתימות. הדברים שעובדים במקום הכי נמוך שומרים על זרימת הבית, הניקוז מזכיר בלי מילה."},"ICON-0700":{"nm":"לוח וו יניקה","de":"הוא יוצר מקום חדש על הקיר בלי לתקוע ולו מסמר אחד. לוחצים ומדביקים, מקלפים, ואפילו סימן לא נשאר. אמנות השהייה לזמן קצר ועזיבה בלי להשאיר עקבות - כוס היניקה מכירה היטב את הנימוס הקל הזה."},"ICON-0701":{"nm":"תווית כפכפי אמבטיה","de":"זוג המונח מסודר לפני הסף. הדאגה של בית שבו חולצים נעליים ממשיכה בעדינות עד לדלת חדר האמבטיה. תווית קטנה מציינת בשקט את מקומה של הכנסת אורחים זעירה זו, המחממת בהונות קפואות."},"ICON-0702":{"nm":"כוסית שטיפת פה","de":"כוסית קטנה ועגולה המחזיקה לגימה לצחצוח שיניים. ברגע הקצר של השטיפה היא קולטת בשקט את תחילתו וסופו של היום. לא מפוארת, אך נוכחת לצדך בכל יום - הפשטות היא משק הבית הבר-קיימא ביותר."},"ICON-0703":{"nm":"שרוול למטאטא נוצות","de":"שרוול שמולבש על נוצות המברשת האוספת אבק כמו בליטוף. כמו ציפור המקפלת בעדינות את כנפיה כשאינה עפה, כלי שיודע היכן לנוח נשאר לצדך זמן רב."},"ICON-0704":{"nm":"מילוי לגלגלת ניקוי בדים","de":"מקלפים שכבה אחת ומתחתיה צצה משטח רענן וחלק. הדפים הדביקים הפנימיים אוספים מוך ושיער. בתוך מילוי עגול שמתמלא מחדש כשהוא נגמר, כרוכה מידת השקדנות של החזרתיות."},"ICON-0705":{"nm":"מלחציים לסמרטוט","de":"מלחציים שנושכים את הסמרטוט בחוזקה במקום היד. הם שומרים על מרחק זעיר בין הרצפה הקרה לאצבעותיך. ידית אחת שנוטלת על עצמה את העבודה המלוכלכת הופכת את הניקיון הקשה לקל בהרבה."},"ICON-0706":{"nm":"מכסה למברשת סדקים","de":"כובע קטן המגן על קצה רך של מברשת דקה העשויה לחדור לחריצים צרים. לב שמטפל אפילו בפינות שידיים לא מגיעות אליהן. מי שמנקה את המקומות הבלתי נראים מגדיל את חיבוקו של הבית בעוד קצת."},"ICON-0707":{"nm":"טבעת תווית לבקבוק תרסיס","de":"תווית קטנה שיושבת בעדינות על כתפו של בקבוק תרסיס. אם בפנים מים צלולים או חומר ניקוי, היא אומרת בבירור בשורה אחת. תווית שמוחקת מראש בלבול היא הרגל ותיק של עקרת בית זריזת יד."},"ICON-0708":{"nm":"רצועת מילוי לנייר טואלט","de":"רצועה שמכניסה גליל חדש למקום הריק וקושרת אותו היטב. המגע הפשוט ביותר שמחבר מחדש את מה שנקטע. לבו של מישהו, שממלא מחדש לפני שנגמר, כרוך בעיגול סביב הלולאה הקטנה הזו."},"ICON-0709":{"nm":"וו לכפפות ניקוי","de":"וו שתולה כפפות רטובות לייבוש מיד לאחר סיום עבודת הרחיצה. הוא מציע לידיים העמלות מקום לנוח לרגע. בזמן שהלחות מתייבשת לאט, זו הפסקה קצרה שתופסת נשימה למשימה הבאה."},"ICON-0710":{"nm":"סיכת תלייה למטאטא","de":"כשתולים מטאטא הפוך, הזיפים נשארים ישרים במקום להתעקם. תנוחה שממתינה זקופה לחצר הבאה. מקום קטן אך יציב שעוזר לו לשמור על צורתו גם אחרי שעבודתו הסתיימה."},"ICON-0711":{"nm":"קליפס לשקית זבל","de":"הוא נושך את פתח השקית בחוזקה, אוטם אותה היטב כך שדבר לא דולף. מגע אחד שסוגר את הקצה בבטחה הופך את הסידור לנקי בהרבה. הסיום, בסופו של דבר, מתחיל בסגירה טובה."},"ICON-0712":{"nm":"קופסת אטבי כביסה","de":"קופסה שבה אטבי הכביסה, שקל לאבד כשהם מפוזרים, חיים יחד. היא נותנת לקטנים בית משותף לשהות בו. אוספים את חיילי הקרקע הזעירים של קצות אצבעותיך למקום אחד, ותוכל למצוא אותם במבט אחד כשצריך."},"ICON-0713":{"nm":"טבעת זיווג לגרביים","de":"גרב בודדת תמיד נעלמת לאנשהו בחשאי. קשרו כל זוג עם טבעת לפני הכביסה, וגם אחרי שהם מתייבשים רכים ותפוחים, השניים לא יתפרדו. מיון הוא הבטחה קטנה שניתנת מראש נגד היעלמות."},"ICON-0714":{"nm":"כיס לכדור כביסה","de":"הוא מתגלגל שוב ושוב בתוך המכונה, מקיש ומעיר את הלכלוך שספג הבגד. קצב שמלטף את הכביסה בגופו העגול. בתוך המים הסוערים, הוא נושא את האינסטינקט הקדום של הכביסה - הקשה - כרוך בתוך כיס."},"ICON-0715":{"nm":"מכסה מדידה לסבון צמר","de":"לבגד עדין - כמות עדינה בהתאמה. מכסה מדידה שמודד בדיוק מכסה אחד של סבון צמר. בסימון קטן אחד טמון המגע הזהיר של הטיפול בצמר. גם צמצום העודף הוא סוג של מסירות."},"ICON-0716":{"nm":"טלאי תיקון לבד","de":"טלאי קטן המונח בעדינות מעל מקום בלוי. לב קצות האצבעות שמטפל במקום שחוק במקום לזרוק אותו בלי מחשבה. בכל סימן תפור נשמר, בפירוט עדין, דוגמת השנים שעברו יחד עם הבגד."},"ICON-0717":{"nm":"סיכת עיגון למתקן ייבוש","de":"סיכה שתופסת בשקט את מתקן הייבוש כדי שהכביסה לא תעוף ברוח. גם בימים שבהם הכביסה מתנופפת בשמש, היא עוזרת לה לשמור על מקומה בתוך התנודה. תפקידו של משקולת נגד קטנה אך אמינה."},"ICON-0718":{"nm":"תווית לרשת כביסה לתחתונים","de":"תחתונים עדינים נשטפים בנפרד בתוך רשת. רשת שעוטפת את הדברים הרכים בעדינות מפני המים הסוערים. שקית קטנה עם תווית מזכירה שלהגן בזהירות על השביר הוא גם סוג של ניהול משק בית."},"ICON-0719":{"nm":"וו לכפית אבקת כביסה","de":"תולים את כפית אבקת הכביסה מסודרת על הקיר. בלי הטרחה של להפיל אותה לתוך הקופסה ולהרטיב את היד. ההרגל המסודר של להשאיר תמיד את אותו הכלי באותו המקום, מוחזק היטב בתוך הווו הקטן הזה."},"ICON-0720":{"nm":"עוצר לחבל כביסה","de":"הוא נושך את קצה חבל הכביסה בחוזקה, כך שגם עמוסה בכביסה כבדה היא לא תתרופף. הקשר האחרון שמחזיק מעמד עד הסוף, שומר על חוט מתוח מלהישמט. סיום מוצק תלוי בזה."},"ICON-0721":{"nm":"תווית ציפית כרית","de":"המקום שהלחי נוגעת בו ראשונה בכל לילה, עם תווית בגודל ציפורן תפורה בפנים. מי קורא את האותיות הזעירות שמפרטות את טמפרטורת הכביסה? ובכל זאת, זהו המדריך הקרוב ביותר, ששומר לצד פנים ישנות."},"ICON-0722":{"nm":"קליפס לשמיכה","de":"בלילה שהחלון פתוח, השמיכה לא תברח גם כשהרוח נכנסת. כי קליפס עם פה סגור היטב אוחז בפינה. יד שקטה שמחזיקה את הקצה במקום הישן."},"ICON-0723":{"nm":"לוח האפלה למנורת לילה","de":"\"כשהאור נוגע בעיניים, השינה בורחת.\" עם לוח האפלה אחד שמישהו הציב בשקט, האור נסוג לאחור ורק מרטיב קלות את כף הרגל של המיטה. מחיצה קטנה שמשאילה חופן חשיכה."},"ICON-0724":{"nm":"כיס לפער שליד המיטה","de":"דמיינו את הפער בין המזרן לקיר, זה שהיד אף פעם לא הגיעה אליו. השלט רחוק שהתגלגל, המשקפיים גם, עכשיו מתכנסים לכאן. כיס שהמיטה פורשת בשקט כדי לתפוס את הדברים שכמעט אבדו."},"ICON-0725":{"nm":"מגש לאחסון משקפיים","de":"מסירים את העדשות והעולם מיטשטש ברכות, וצלחת רדודה קולטת את חוסר ההגנה הרגעי הזה. עם בוקר, גם בלי שהאצבעות מגששות, המשקפיים תמיד מחכות באותו המקום."},"ICON-0726":{"nm":"בסיס לשעון מעורר","de":"שש בבוקר, על גבי הבסיס היציב שממנו נשמע הצליל השנוא ביותר. יציב וללא רעד, הוא תומך בשעון, ובסופו של דבר פותח את יומו של מישהו. הוא נושא בשקט את ההבטחה הגסה של ההתעוררות."},"ICON-0727":{"nm":"מחזיק כבל למראשות המיטה","de":"כבל הטעינה שנהג לגלוש ליד ראש המיטה כבר לא נופל לרצפה. כי מחזיק קטן אוחז בעדינות בקצה הכבל. במרחק יד - מגע שסידר את מסלול הלילה."},"ICON-0728":{"nm":"רצועת אחסון לפיג'מה","de":"רצועה שעוטפת פעם אחת פיג'מה מקופלת יפה וקושרת אותה. גם רכות שנוטה להתפרע זקוקה לסידור. למען ה'אני' של מחר בלילה, ה'אני' של היום מגלגל אותה בקפידה - הכנה קטנה."},"ICON-0729":{"nm":"מעמד לכרטיס ריח","de":"מציבים כרטיס מבושם באלכסון, וכמו בהפיכת דף, מעבירים את העונה דרך האף. מלבנדר לפרי הדר - זה הופך ליומן של אותו היום, שנכתב בריח."},"ICON-0730":{"nm":"רפידה לצלחת מפתחות","de":"פינה ליד הכניסה, המקום שבו המפתחות נהגו ליפול בקול צלצול. צלחת מרופדת ברפידה רכה בולעת את הצליל החד ההוא. משטח קטן שקולט בשקט את התנועה הראשונה של מי שחזר הביתה."},"ICON-0731":{"nm":"מכסה ניקוז למטרייה","de":"מי גשם מטפטפים מקצה המטרייה שהבאת פנימה. מכסה אחד קולט את הטיפה הזו בקפידה, כך שמישהו צפה מראש ומנע את השלולית הקטנה שהייתה מתפשטת על הרצפה."},"ICON-0732":{"nm":"שבב וו למסכה","de":"שבב בגודל ציפורן דבוק לקיר ליד הדלת. כמו הטקס האחרון של היציאה, המסכה תלויה כאן. מכשיר זיכרון קטן ששומר על גובה העין ליד הדלת, כדי שלא תשכח מה לקחת."},"ICON-0733":{"nm":"כיסוי נדן לסכין חבילות","de":"כיסוי מגן שמתלבש על הלהב שחותך קופסאות חבילה. הוא מכסה בשקט את סכנת החתך החבויה מאחורי ריגוש הפתיחה. תשומת לב בלתי מורגשת שפותחת בבטחה את סוף הציפייה."},"ICON-0734":{"nm":"מעמד למברשת נעליים","de":"המקום שבו מברשת הנעליים נחה, עדיין רטובה לאחר הצחצוח. גם כשהיא סופגת לחות, הרצפה נשארת יבשה. גם כלי שיוצר ניקיון זקוק למקום לנוח, מזכיר לנו המעמד הקטן."},"ICON-0735":{"nm":"לוח פתקים לאורחים","de":"\"עברתי לרגע ויצאתי.\" שורה קצרה שנותרה על לוח הפתקים ליד הכניסה. כיכר קטנה שבה אנשים שהחמיצו זה את זה חולקים חוצה זמן. על משבצת נייר אחת, ברכה, בקשה ולב אחד נערמים זה על זה."},"ICON-0736":{"nm":"גליל אטימה לתחתית הדלת","de":"הפרזול שחדר דרך הפער הצר כרוחב אצבע מתחת לדלת. גליל מגולגל חוסם בשקט את המעבר הזה. הוא שומר עוד שכבת חום אחת בחדר, שדלף בלי שיבחינו בו."},"ICON-0737":{"nm":"קמיע עוצר דלת","de":"קמיע קטן שתומך בבסיס דלת פתוחה לרווחה כדי שלא תיסגר שוב. הוא שומר על משקלו היציב לרוח ולצעדים החולפים. עקשנות אדיבה ששומרת על הדלת פתוחה."},"ICON-0738":{"nm":"כיסוי מתג תאורה לכניסה","de":"מתג הכניסה שגששת אחריו בלילה מאוחר. כיסוי זוהר בחושך מסמן בעדינות את מקומו באפלה. כדי שהיד לא תתעה - מדריך קטן שזוהר לפני שהאור נדלק."},"ICON-0739":{"nm":"רפידה למחזיק כוס","de":"הרגע שבו כוס שהונחה על השולחן מתחילה להחליק, רפידה אחת תופסת בעדינות את בסיסה. תחתית שמחזיקה מקום בשלווה, לא משאירה סימן אפילו כשטיפות מים נקוות עליה."},"ICON-0740":{"nm":"קליפס ריח לרכב","de":"קליפס ריח קטן תלוי בתוך המכונית. רוכב על משב פתחי האוורור, ניחוח עדין ממלא לאט את החלל הצר. נחמה אדיבה במושב הנהג, שמחממת בריח אפילו את השעמום של ההמתנה ברמזור."},"ICON-0741":{"nm":"כיסוי לחגורת בטיחות","de":"כיסוי רך שמתלבש על החגורה החוצה את הכתף. הגירוד שנגע בעורף נעלם בהדרגה. גם רצועה שנועדה לבטיחות יכולה לקבל תוספת אדיבות, אומר חופן הבד הזה."},"ICON-0742":{"nm":"לוח הסתרה למספר חנייה","de":"לוח שמכסה בשקט את השלט שסימן את המשבצת שלך בחניון תת-קרקעי, לפני שמצלמים תמונה. לכל אחד יש מידע שהוא מעדיף לא להשאיר מאחור. שכבה אחת שנמחקת בזהירות מתמונה של חיי היום-יום."},"ICON-0743":{"nm":"כיסוי לפעמון אופניים","de":"טרינג. הברכה הצלולה שהאופניים מציעים בפינת הסמטה. כיסוי מעל הפעמון שומר על הצליל הזה גם בגשם. בצליל פעמון קטן אחד, אנשים מחייכים וצועדים הצידה."},"ICON-0744":{"nm":"טבעת אחיזה לכידון","de":"טבעת שעוטפת ברכות את המגע של הכידון בכף היד. גם אחרי אחיזה ורכיבה ממושכת, הידיים לא מתקהות. ככל שהדרך רחוקה יותר, כך נוחות מקום האחיזה מקצרת את המרחק ההוא."},"ICON-0745":{"nm":"מדבקת שם לקסדה","de":"מדבקת שם בפנים הקסדה. בין קסדות בטיחות זהות, היא קוראת בשקט 'זו שלי'. הסימן האישי ביותר, חרוט על גבי הקשיחות ששומרת על הראש."},"ICON-0746":{"nm":"מכסה זוהר לגלגל","de":"מכסה שמתחיל את עבודתו רק כשהשמש שוקעת. הוא קולט אור חולף ומחזיר בבירור את זוהר הגלגל. בחושך, הוא שולח באור את האות הקטן: \"יש כאן מישהו\"."},"ICON-0747":{"nm":"נרתיק מגן למפתח רכב","de":"מפתח רכב שנהג להישרט מהתנגשות עם מפתחות אחרים בכיס. נרתיק רך עוטף את המשטח שלו בחביבות. הרצון שחפץ שאוחזים בו כל יום יישאר ללא שריטות ויחזיק זמן רב, טמון בו."},"ICON-0748":{"nm":"סיכת מדף יניקה","de":"סיכת מדף יניקה שנצמדת לקיר בלי לתקוע מסמר אחד. גם קיר שלא רוצים לסמן בו זוכה למשבצת אחסון אחת. האומנות של לתלות משק בית בחדר ששוהים בו רק לזמן קצר, בלי להשאיר עקבות."},"ICON-0749":{"nm":"לוח וו ללא קידוח","de":"לתלות משהו בלי לקדוח את הקיר - זה אפשרי. לוח וו ללא קידוח נוטל בשקט על עצמו משא קל. הרצון לא לפגוע במרחב שאול טמון בחן בווו קטן אחד."},"ICON-0750":{"nm":"מוט ארגון מגנטי","de":"הצליל של מתכת שנצמדת בקליק למקומה. אוספים בעזרת מגנט כלים קטנים המפוזרים בכל מקום, ושולחן עבודה כאוטי מסתדר בשורה מסודרת - סיפוק קטן שבא בעקבות זאת."},"ICON-0751":{"nm":"מוט אחסון לפער צר","de":"דמיינו את החריץ הצר והנשכח בין המקרר לקיר. מוט דק ממלא את הפער הזה בתועלת. רעיון חסכני שמפיק אחסון ממרחב שנחשב חסר ערך."},"ICON-0752":{"nm":"גיליון רפידה דביקה","de":"גיליון רפידה דביקה שברגע שהוא נדבק, מחזיק בקלות אפילו דברים כבדים. מקלפים אותו ולפלא, לא נשאר אף סימן. כוח שקט ועיקש שנושא משקל ממקום בלתי נראה."},"ICON-0753":{"nm":"וו תלייה לדלת","de":"וו שפשוט נתלה קלות מעל הדלת. תיקים ומגבות תלויים בדיוק בטווח היד. תולה שנולד בלי מסמר אחד, מוסיף עוד קצת מרחב נשימה לחדר צפוף."},"ICON-0754":{"nm":"קליפס קיר לכבלים","de":"קליפס שאוסף כבלים שהיו תלויים לאורך הקיר לשורה אחת מסודרת. הפקעת הסבוכה מאחורי השולחן מתפרשת לקו נקי. סידור בלתי נראה שהופך אפילו את אוויר החדר לקל יותר."},"ICON-0755":{"nm":"רפידה לבסיס מנורה","de":"רפידה שמניחים בעדינות מתחת לרגלי מנורת עמידה. היא לא משאירה שריטות על השולחן ומרגיעה אפילו את הרעד הקל ביותר. גם כדי להעמיד אור, קודם צריך רצפה שלא רועדת."},"ICON-0756":{"nm":"לוח דבק נגד החלקה","de":"השטיח שהיה מחליק בחשאי מתחת לרגליים סוף סוף עוצר במקומו, כי לוח הדבק נאחז ברצפה בחוזקה. רשת ביטחון בלתי מורגשת שמסלקת מראש רגע של כמעט נפילה."},"ICON-0757":{"nm":"מכסה למברג עדין","de":"\"הבורג הקטנטן הזה פשוט לא משתחרר.\" מכסה שמתלבש על קצה מברג עדין שומר על הלהב. הכלי העדין ביותר של קצות האצבעות, שפותח עולם בגודל כף יד בתוך מכונה."},"ICON-0758":{"nm":"טבעת למפתחות אלן","de":"טבעת שמשחילה כמה מפתחות אלן על לולאה אחת. המתכת, מסודרת לפי גודל, נפרשת כמו מניפה. הקצב המסודר של יד שבוחרת בתנועה אחת בדיוק את מה שהיא צריכה."},"ICON-0759":{"nm":"קמיע סרט מדידה מיני","de":"קמיע המחובר לסרט מדידה זעיר שנכנס בדיוק לכף היד. הוא נתלה על מחזיק מפתחות ומלווה לכל מקום. חבר קטן שמודד ועונה על כל אורך שמסקרן פתאום, במקום."},"ICON-0760":{"nm":"קופסת מיון ברגים","de":"קופסת מיון שבה בורגים שונים זה מזה מוצאים כל אחד את המשבצת שלו. גם החלקים הקטנים שהתגלגלו בערבוביה זוכים לסדר. היד שלומדת קודם לסדר, לפני שהיא מתקנת משהו."},"ICON-0761":{"nm":"מכסה זרבובית לדבק","de":"סגור - לא אתקשה; פתוח - אתייבש. אני חי בין השניים. עם כל טיפה שנופלת, אי-שם משהו שבור מתחבר מחדש. מכסה קטן אחד שומר בשקט על הגבול בין קיפאון לזרימה."},"ICON-0762":{"nm":"מחזיק מפתחות פלס","de":"יושר בגודל כף יד, מתנדנד בקצה צרור מפתחות. תמיד זו הבועה הקטנה הזו הראשונה להבחין במדף עקום. אני נושא בכיס חבר ששקט מודיע לי שהעולם התעקם קצת."},"ICON-0763":{"nm":"מכסה מגן לפינצטה","de":"ככל שדבר חד יותר, כך הוא זקוק יותר לבגד שירגיע אותו. עוטפים את הקצוות בעדינות, ולא הידיים ולא החלקים נפגעים. הנימוס הראשון בטיפול בחדות הוא לכסות בשקט את הקצה - מכסה קטן נוטל על עצמו את החביבות הזו."},"ICON-0764":{"nm":"מזרן חיתוך קטן","de":"לוח שצלקותיו מחלימות מעצמן גם אחרי אלפי מעברי להב. המשימה הבאה מונחת שוב על מקום החתך, ושוב היא מחלימה. רצפה שקטה שנותנת מגופה כדי שדברים אחרים ייחתכו בנקיות."},"ICON-0765":{"nm":"שקית חלקי תיקון","de":"שקית שקומטת את פיה כדי שבורג בודד, קפיץ בודד, לא ייעלמו לנצח. הדברים הקטנים שנשארו אחרי תיקון ממתינים כאן בשקט לתורם הבא. תמיד משבצות צנועות כאלה הן שמונעות אובדן."},"ICON-0766":{"nm":"קליפס לשקית חטיפים","de":"לשמור על הפריכות של שקית פתוחה מסתכם, בסופו של דבר, בלחיצה נחרצת אחת. הבטחה קטנה לא לתת סיכוי להתרככות. הרגל של סגירת הקצה בחוזקה מציל את החטיף של מחר."},"ICON-0767":{"nm":"כוסית מנה לג'לי","de":"כדי לחלוק שקית אחת בין רבים, קודם צריך לחלק בהגינות. הלב שיוצק מנה שווה לכל כוסית קטנה. אני מאמינה ששיתוף מתחיל בדיוק באותה כמות, כדי שאף אחד לא ירגיש מקופח."},"ICON-0768":{"nm":"פיסת נייר כסף שוקולד","de":"הכסף שעטף את המתיקות מתקמט בקלות בקצות האצבעות. פורשים אותו והוא נוצץ לרגע; מקפלים אותו והוא הופך לזיכרון. פיסת אור שנעשית יפה ביותר רק אחרי שהכול נאכל - מביטים בה עוד פעם אחת לפני שזורקים."},"ICON-0769":{"nm":"רצועת תווית לחטיף","de":"מה יש בפנים, עד מתי טוב - במקום השקית השותקת, אני זו שמדברת. ברגע שרצועה אחת נדבקת, גם לחטיף יש שם והבטחה. מיון הוא, למעשה, שיטת הזיכרון הכי אדיבה."},"ICON-0770":{"nm":"קופסת מיון סוכריות","de":"לא שמים את החמוצות ואת המתוקות באותה משבצת. עבודת ההפרדה המוקדמת כדי שהיד לא תהסס. כשהקופסאות הקטנות מסתדרות בשורה, ההנאה של הבחירה מכפילה את עצמה בחשאי."},"ICON-0771":{"nm":"נייר ריפוד לעוגיות","de":"נייר דק שמוכנס בין עוגיות כדי שלא ייחבלו בדרך. ככל שדבר שביר יותר, כך הוא זקוק ללוויה עדינה יותר. לפעמים רכות מגנה טוב יותר מקשיחות."},"ICON-0772":{"nm":"חוט לקופסת דונאטס","de":"קשר צולב אחד אחראי על שלום העוגה בתוך הקופסה. הוא הופך לידית, לחותם, לסימן של ציפייה נרגשת. הרגע שהחוט הזה מתרופף הוא יום ההולדת של מישהו."},"ICON-0773":{"nm":"קליפס לשקית לחם","de":"מסובבים פעם אחת, מקפלים, ומתלבשים עליי, והרכות של הלחם נחתמת עד הבוקר. עקשנות קטנה ונחרצת שחוסמת אוויר. לשמור על משהו רך לאורך זמן, זו תמיד עבודתו של משהו יציב."},"ICON-0774":{"nm":"תווית החלפת חטיפים","de":"החלק שלך אליי, החלק שלי אליך. זוכרים את הריגוש של כתיבת שמות על תוויות קטנות והחלפת חטיפים באותו יום? על הנייר שמתלווה ללב שמשתף, תמיד כתוב בבירור שמו של חבר."},"ICON-0775":{"nm":"מכסה סתימה לקשית","de":"כשעוצרים לרגע בין לגימה ללגימה, סוגרים אותי. כדי שלא יישפך, כדי שלא יתקרר, כדי שימתין שם בשקט. זו עבודתו של מכסה קטן ששומר על הפתח לרגע שהשפתיים חוזרות."},"ICON-0776":{"nm":"טבעת שם לתרמוס","de":"טבעת קטנה שאומרת 'זה שלי' בין שורה של תרמוסים עומדים זה לצד זה. צבע אחד, והבלבול נמס בעדינות. סימן בעלות אחד מספיק כדי להבהיר לגמרי מה שייך לך."},"ICON-0777":{"nm":"שרוול למחזיק כוס","de":"שכבת קרטון גלי אחת מתגנבת בין כוס חמה לכף היד. מחוות דאגה שמוכנסת כדי שלא תיכווה ולא תחליק. שמירה על המרחב שביניהם היא בדיוק מה שמשלים כוס בטוחה ושלמה."},"ICON-0778":{"nm":"תווית לתבנית קרח","de":"יש אנשים שכותבים את תאריך ההכנה על כל אצווה של קרח. מתוך אמונה שגם לקור יש סדר. תווית קטנה אחת מאפשרת לזמן במקפיא לזרום ביושר, תור אחר תור."},"ICON-0779":{"nm":"מלקחיים לשקית תה","de":"עוקבים אחר זמן החליטה, ומרימים בדיוק ברגע הנכון. המגע העדין של לדעת מתי לעצור לפני שהוא מתחזק מדי. עומקו של תה נקבע פחות על ידי משך הטבילה, ויותר על ידי תזמון ההוצאה."},"ICON-0780":{"nm":"מעמד לפילטר טפטוף","de":"הוא מחזיק את הפילטר ועומד בשקט כדי שהמים החמים יטפטפו לאט. הוא יודע היטב שמיהור הופך את הארומה לדלה. גם עבודת התמיכה בסבלנות דורשת יציבה איתנה."},"ICON-0781":{"nm":"רצועה לבקבוק מים","de":"רצועה שתולה את בקבוק המים על פרק כף היד או על הכתף כדי ללכת יחד. דרך של ליווי ששומרת אותו קרוב תמיד, בלי שתצטרך לארוז אותו בכוונה. לפעמים קשר קטן הוא הדרך האדיבה ביותר לא לשכוח."},"ICON-0782":{"nm":"כיסוי למכסה פחית","de":"הוא מכסה את פתח הפחית שנשארה פתוחה חלקית, כדי למנוע אבק ואיבוד גזים. כובע קטן שאחראי על הרעננות עד הלגימה הבאה. גם המעשה של לכסות בעדינות משהו שנפתח לרגע, נושא בתוכו מסירות."},"ICON-0783":{"nm":"מחזיק כרטיסיית קופונים למשקה","de":"הכוס העשירית בחינם - הוא מחבק את כרטיסיית החותמות כדי שההבטחה הזו לא תאבד. כדי שהימים שמולאו משבצת אחר משבצת לא יתקמטו. בתוך מחזיק זה נערמים צעדיו החרוצים של לקוח קבוע."},"ICON-0784":{"nm":"רצועה לקופסת אוכל","de":"רצועה שמחבקת את קופסת האוכל היקף אחד שלם כדי שהמכסה לא ייפתח. הרגעה קטנה שהמרק לא ידלוף בתוך התיק. השלום בטוח עד ארוחת הצהריים נמצא בשמירתה של הלולאה ההדוקה הזו."},"ICON-0785":{"nm":"סט כוסיות לתוספות","de":"תנו לכל תוספת מקום משלה והטעמים לא יתערבבו. קימצ'י כקימצ'י, ירק כירק, כל אחד ברור. המשבצות שכוסיות קטנות אלה יוצרות הן סדרה של קופסת האוכל, ורוך שמעל למגע הבישול."},"ICON-0786":{"nm":"נרתיק לצ'ופסטיקס","de":"בית קטן ששומר נקיים ונושא את הצ'ופסטיקס ששיתפו את שלוש הארוחות ביום. מלווה שקט ששומר על הסדר גם בתוך תיק בית הספר. הדאגה של לשאת אותם היא, בסופו של דבר, מה שיוצר ארוחה מסודרת."},"ICON-0787":{"nm":"תווית לבקבוק רוטב","de":"רוטב סויה או חומץ? היא מעניקה בהירות לבקבוק שנהגת לבלבל. ברגע שנדבקת שורה אחת, ההיסוס בקצות האצבעות נעלם. הקצב של מטבח עמוס נוצר בשקט על ידי סימנים קטנים כאלה."},"ICON-0788":{"nm":"גיליון גלגול לגימבאפ","de":"גיליון אצות דק שגולל את האורז והמילוי לגוף אחד. עוטפים בחוזקה כדי שלא יתפרק בחיתוך. הריגוש של בוקר טיול יוצא עגול ומגולגל מתוך השכבה הבודדת הזו."},"ICON-0789":{"nm":"כוס למחטי שיפוד","de":"מעמידים שיפודים וקיסמים במקום אחד, והיד לא תגשש כשמגיע הרגע. נותנים אפילו לחפצים החדים בית משלהם. סידור הוא, בסופו של דבר, חסד קטן ליד הבאה שתושיט יד."},"ICON-0790":{"nm":"כיסוי לשקית קרח","de":"עוטפים את שקית הקרח בעוד שכבה כדי להחזיק את הקור עוד קצת. גם מונעים מהתיק להירטב מעיבוי. לשמור על הצינון עד הסוף, זו תמיד עבודתה של השכבה העבה הזו."},"ICON-0791":{"nm":"מחיצה לקופסת אוכל","de":"חומה קטנה שהוקמה כדי שהאורז והתוספות לא יפלשו זה למקומו של זה. השלווה של משבצת אחת שהמרק לא חוצה. קופסת אוכל שמחולקת למשבצות נושאת, שלמה, את הלב הקפדני של מי שהכין אותה."},"ICON-0792":{"nm":"כרטיס סדר ארוחה","de":"מרק קודם או אורז קודם? כרטיס שמציע בעדינות את מהלך הארוחה של היום. הדרכה אדיבה שאומרת שזה טעים יותר כשאוכלים לפי הסדר. הוא אומר בשקט שגם לארוחה יש זרימה, כמו לסיפור."},"ICON-0793":{"nm":"מדבקה לכוס מדידה","de":"מדבקה קטנה ליד הסימון מצביעה בדיוק 'עד כאן'. סימן שמכוון בדיוק, בבת אחת, את הכמות שתמיד בלבלה. דיוק נובע מקו הנחיה קטן אחד כזה."},"ICON-0794":{"nm":"ידית סיליקון למכסה","de":"ידית קטנה שמאפשרת להרים מכסה חם בלי לצרוב את האצבעות. היא משאילה בשקט את האומץ לפתוח סיר מהביל. בטיחות תמיד מגיעה מהכנת מקום אחיזה מראש."},"ICON-0795":{"nm":"תלייה בקליפס מיני","de":"קליפס קטן שנותן מקום למטלית או לשקית שלא היה להן איפה להיתלות. הוא הופך פינת קיר עמוסה לנוף מסודר. הרגל אחד של תלייה הופך את המטבח לקל בהרבה."},"ICON-0796":{"nm":"מכסה למברשת שמן","de":"מכסים את קצה מברשת השמן ואבק והתקשות חולפים מעליה. כובע ששומר על הרכות הזו עד המנה הבאה. דאגה קטנה לכלים, בסופו של דבר, שומרת על הטעם לאורך זמן."},"ICON-0797":{"nm":"כד עם כפית מלח","de":"כפית קטנה שחיה תקועה בתוך קופסת המלח. היא אוספת בקפידה, בכל פעם, את הדיוק של קורט אחד. המגע הנכון של תיבול הוא בדיוק כמות הלב שהכפית הקטנה הזו זוכרת."},"ICON-0798":{"nm":"לוח מגנטי לטיימר","de":"דבוק לדלת המקרר, הוא סופר 3 דקות לאטריות ומודד 30 שניות לאימון. במגנט אחד, הזמן העומד לחלוף נשאר לנגד העיניים. עיגול חרוץ שמצמיד לרגע את הרגע החולף לקיר."},"ICON-0799":{"nm":"כיסוי לידית סיר","de":"שכבה שעוטפת כדי שלא תאחזו בידית מחוממת בידיים חשופות. מגן קטן שעומד בין החום לכף היד. הובלה בטוחה תמיד מתחילה בעטיפה הרכה הזו."},"ICON-0800":{"nm":"גומי אחיזה לקרש חיתוך","de":"כשאני מונח על הרצפה, קרש החיתוך כבר לא מחליק. פיסת גומי שתומכת מלמטה בכל פעם שהחיתוך מתנדנד. יציבות היא עבודתה של נשיכה חזקה במקום בלתי נראה."},"ICON-0801":{"nm":"קליפס לכפפת מטבח","de":"מקום שבו היד שלא חדלה לנוע מול הלהבה עוצרת לרגע. תולים את הכפפה המתנפנפת על הקיר, ומתחילה נשימה קצרה עד הארוחה הבאה. סידור הוא, בסופו של דבר, שם אחר לעדינות."},"ICON-0802":{"nm":"מעמד למקלות ערבוב קפה","de":"לצד הדלפק, פינה שבה מקלות דקים נשענים כתף אל כתף, ערוכים בשורה מסודרת. מוכנים לצייר סלסול בספל הבוקר של מישהו, הם עומדים בשורה כמו מקהלה רגע לפני שהיא פוצחת בשיר."},"ICON-0803":{"nm":"רצועת סט תחתיות לכוסות","de":"רצועה שקולטת ברכות את הנקישה הקטנה של כוס הנוגעת בשולחן. כשקושרים יחד את התחתיות העגולות, ההכנה לקבלת האורחים הושלמה. הכנסת אורחים תמיד מתחילה, כך, במקומות הקטנים ביותר."},"ICON-0804":{"nm":"תווית לבקבוק סירופ","de":"שם אחד, כתוב על הבקבוק. מתוק, סמיך - מילה קצרה אחת שמרגיעה בוקר עמוס ומסדרת אותו קמעה. תווית היא נייר שעליו רושמים מראש הבטחה קטנה."},"ICON-0805":{"nm":"קופסת קיסמי קינוח","de":"קופסה שבה חיים יחד מקלות מחודדים המיועדים לנעוץ פרוסת פרי אחת. לפני שהם ננעצים כמו דגלים על צלחת הקינוח, הם ממתינים כאן בשקט לתורם. גם למתיקות יש סדר משלה."},"ICON-0806":{"nm":"שרוול נייר למקלות ערבוב","de":"מעטה נייר החובק בעדינות חופן מקלות ערבוב. הוא סופג את הלחות הנוטפת ממשקה קר, ושומר על קצות האצבעות האוחזות בכוס יבשות. דאגה בלתי נראית מגיעה תמיד מהשוליים."},"ICON-0807":{"nm":"תג למגש כוסות לקחת-איתך","de":"ברגע ששתי ידיים אינן מספיקות, ידית קטנה נושאת את הכוסות במקומן. היא אוחזת בחום העטוף כך שלא תישפך אף טיפה, ומלווה את החום ההוא עד פינת הרחוב של מישהו."},"ICON-0808":{"nm":"כיסוי לזמזם בית קפה","de":"מעטפת שעוטפת בשקט את ההמתנה עד לרגע שהזמזום יישמע. היא שומרת על כרטיס התור הנוצץ בפינת בית הקפה, ואוצרת בתוכה גם את ההתרגשות שבעוד רגע ייקרא מספרי."},"ICON-0809":{"nm":"טבעת לכרטיסיות חותמות","de":"נייר שבו מילוי עשרת המשבצות מזכה בכוס אחת במתנה. עם כל חותמת נוספת, גם השם 'לקוח קבוע' גדל קצת. שמחה צנועה להפליא, מושחלת על טבעת קטנה."},"ICON-0810":{"nm":"שקית דוגמית פולי קפה","de":"שקית המכילה חופן פולים ומציעה קודם כול את הניחוח. החמיצות והמתיקות החולפות על פני האף, הרושם הראשון הזה קובע את גורלו של הספל. ריח מגיע מהר יותר מכל הסבר."},"ICON-0811":{"nm":"מגנט תווית למקרר","de":"תג מגנטי קטן שנצמד בקלות לדלת המקרר. רושמים מה נכנס ומתי, וגם תוספת שכמעט נשכחה מוצאת מחדש את תורה. משק בית הוא מעשה של ריתוק הזיכרון הזורם."},"ICON-0812":{"nm":"פתקית תאריך אחסון","de":"פיסה שחורטת בבירור את היום שבו משהו נארז. עד קטן שאומר בשקט, גם ימים אחר כך, שזה עדיין בסדר. הטריות נשמרת בקצות האצבעות שזוכרות את התאריך."},"ICON-0813":{"nm":"רצועה לקופסת אחסון מנות","de":"רצועה החובקת את מותני הקופסה המחולקת למנות. היא מהדקת את המכסה הרועד, ושומרת על סדר קטן בתוך המקרר. לקשור משהו דומה למעשה של סידור הלב."},"ICON-0814":{"nm":"פס תפסי איטום צבעוניים","de":"תפסים צבעוניים שנושכים בחוזקה את פתח השקית. אדום לחריף, צהוב למתוק - היד יודעת כבר מהצבע לבדו. רמזורי המטבח מכוונים את הדרך כך, בלי מילה אחת."},"ICON-0815":{"nm":"תג שם לחבילת הקפאה","de":"תג שם המונח בעדינות מעל למשהו קפוא. הוא מרגיע את השקית המכוסה כפור, כדי שלא תשכח מה הייתה. ברכת שלום קטנה, נשלחת למרכיבים ששקעו בתרדמת החורף שלהם."},"ICON-0816":{"nm":"רשת אחסון לירקות","de":"רשת רופפת המחבקת בנדיבות ירקות מאובקי אדמה. מטבחה של הסבתא ידע כבר מזמן שמתן מרווח לנשימה הוא שמאריך את חייהם. אוורור הוא שוליים עדינים המוענקים לירקות."},"ICON-0817":{"nm":"מכסה מיון לפקקי בקבוקים","de":"מכסה מיון שמזווג פקק לפקק, לפי גודל. למצוא בן זוג אבוד הוא מעשה עדין יותר משנדמה. כשמתאימים זוג הולם, גם המטבח מסתדר לו בסדר טוב יותר."},"ICON-0818":{"nm":"תווית למגש ביצים","de":"סימון המוצמד בקפידה לכל אחד מעשרת הקנים הקטנים. חוכמת הבית שאומרת להשתמש קודם בביצים הישנות יותר. אפילו בביצת עין אחת של הבוקר טמון לב שמקפיד על הסדר."},"ICON-0819":{"nm":"מדבקת אוכל שיורי","de":"כותבים 'זה שלי!' ומדביקים, ואפילו למקרר יש רגע של שלווה. הכרזת מלחמה חמודה, שקובעת מראש למי שייכת ארוחת הלילה. משפחה ממשיכה להתגלגל, גם היום, על הסכמים קטנים כאלה."},"ICON-0820":{"nm":"משענת לכפית ולמקלות אכילה","de":"פיסה קטנה שתומכת בעדינות בכף ובמקלות האכילה, כדי שלא ייגעו ישירות בשולחן. סדר קטן זה מעלה בחשאי את הכבוד של הארוחה. נימוסי השולחן גדלים בשקט במקומות כאלה."},"ICON-0821":{"nm":"טבעת מהדקת למפיות","de":"טבעת שמחזיקה בשקט מפית שהייתה מתעופפת ברוח. היא אוספת בסדר את הנייר הלבן הממתין לתורו להיפתח, וחורטת סדר קטן על השולחן."},"ICON-0822":{"nm":"פינת מגן לשטיח שולחן","de":"פיסה שלוחצת בעדינות ומרגיעה פינה מורמת של המחצלת. השולחן מלמד בכל יום שרק כאשר קצה אחד מוחזק, כל השטח נעשה ישר. גם לפינה יש חלק אחריות משלה."},"ICON-0823":{"nm":"מגש תבלינים קטן","de":"מגש קטן המחזיק זו לצד זו קערית רוטב סויה וקורט מלח. חיבוקו הרחב של השולחן שמעניק מקום גם לתוספת הקטנה ביותר. המטבח הקוריאני מעמיק דווקא בלב שדואג לתוספות הצדדיות."},"ICON-0824":{"nm":"שבב מספר שולחן","de":"המספר שנקרא 'לקוח מספר כך וכך!' במסעדה סואנת. הוא מעניק סדר להמתנה ושומר על הוגנות לכולם. מה שטמון בשבב אחד הוא הבטחה קטנה, וקערה חמימה שעוד מעט תגיע."},"ICON-0825":{"nm":"רצועת סימון לכוס מים","de":"רצועה העוטפת כוס מים ומספרת בשקט למי היא שייכת. דגל קטן שמסמן את מקומי בין כוסות דומות זו לזו. סביב שולחן משותף, התחשבות כזו מונעת אי-הבנות מיותרות."},"ICON-0826":{"nm":"סיכת מיון לצלחות אישיות","de":"סיכה שממיינת בצבעים את הצלחות שאליהן מגישים מנות. היא מותחת קו עדין בין שלי לשלך, והופכת את שמחת השיתוף לנקייה יותר. חולקים חום, אך שומרים היגיינה בקפדנות."},"ICON-0827":{"nm":"לוח הסתרה לתפריט","de":"זמן ההתלבטות המוסתר מאחורי תפריט פתוח. אפילו ההיסוס הקצר על מה לאכול הוא, למעשה, חלק מהארוחה. מה נבחר היום - הלוח מסתיר בעדינות את ההתרגשות הזו."},"ICON-0828":{"nm":"מעמד לכרטיס מקום","de":"מעמד קטן שמחזיק תג שם זקוף. בין אם באירוע ובין אם בסעודה חגיגית, הוא מכריז בבירור: כאן מקומך. הכנסת אורחים מושלמת רק ברגע שקוראים בשם."},"ICON-0829":{"nm":"שרוול נייר למאפין","de":"מעטה נייר החובק בחוזקה את מותניו העבים של מאפין טרי מהתנור. הוא תומך בגוף החם כדי שלא יחמוק מהיד, ושומר על החום עד רגע הנגיסה הראשונה. גם לקינוח דרוש מעיל."},"ICON-0830":{"nm":"מכסה לשקית שרביט קרם","de":"פקק שסוגר היטב את קצה שקית סחיטת הקרם. הוא אוטם את הפה בחוזקה כך שאף טיפה לא תדלוף בזמן המנוחה. הפרח הקטן על העוגה פורח מתוך ריסון זה."},"ICON-0831":{"nm":"טבעת תבניות עוגיות","de":"סט תבניות עגול שחותך את הבצק לצורת כוכב או דוב. אותו קמח מתעורר, דרך קצות האצבעות, לעשרות הבעות שונות. לא משנה מה אופים - הדבר הראשון הנוגע בבצק הוא תמיד מסירות."},"ICON-0832":{"nm":"קמע למגרדת בצק","de":"יד שטוחה שאוספת בחסכנות את הבצק ומחלקת אותו בניקיון. אותה חריצות שדואגת אפילו לחופן הדבוק לקערה קובעת את נפחה של ככר הלחם. אפייה היא מלאכת היד החסכנית."},"ICON-0833":{"nm":"לוח לכפות מדידה","de":"כפית אחת, חצי כף - לוח שמניח את כפות המדידה בשורה יציבה, ללא רעד. כפית מדויקת אחת מיישרת את איזון הטעם. מאחורי הביטוי 'טעם ידיים' מסתתרת, למעשה, מדידה קפדנית."},"ICON-0834":{"nm":"וו לכפפת תנור","de":"וו לתלייה עבור הכפפה ששמרה משמר מול תנור לוהט. היד העבה שמנעה כוויות שוהה, גם בשעת מנוחה, בהישג יד. בטיחות מתחילה תמיד ממה ששוהה במקומו הקבוע."},"ICON-0835":{"nm":"תפס לרשת קירור","de":"תפסים שנושכים בקפידה את הרשת שעליה מתקררים מאפים טריים. הם מחזיקים אותם כדי שלא יזוזו בזמן שהאדים נמלטים, וממתינים יחד לשלמות הפריכות. גם לקירור דרוש חופן סבלנות."},"ICON-0836":{"nm":"מקל קישוט לעוגה","de":"מקל שמעמיד על העוגה את מילות 'מזל טוב ליום הולדת'. רגע לפני שהנרות כבים, הדגל הקטן הזה מאיר את היום של מישהו בזוהר הרב ביותר. חגיגה נראית הכי טוב כשמרימים אותה גבוה."},"ICON-0837":{"nm":"מפזרת אבקת סוכר","de":"כלי המכיל פיזור עדין אחרון. הוא שוקע כמו שלג לבן על קינוח טרי מהתנור, והופך פרוסה רגילה למתנה קטנה. הנגיעה האחרונה מגיעה תמיד מהיד הקלה ביותר."},"ICON-0838":{"nm":"תווית לגימבאפ משולש","de":"מקלפים את העטיפה לפי הסדר 1, 2, 3 והאצה חוזרת לפריכותה על המשולש הזה. שורה אחת שמאפשרת לזהות במבט אחד חבר נאמן מחנות הנוחות בשעת שחר. הלילות הרעבים אחרי שיעורים מאוחרים דבוקים כאן."},"ICON-0839":{"nm":"מחזיק מכסה לנודלס בכוס","de":"תמיכה שלוחצת בשקט כדי שהמכסה לא יורם במהלך שלוש דקות ההמתנה. היא תופסת את מקום המקלות שהונחו פעם למעלה כדי למנוע בריחת אדים. הזמן הקצר שבו הנודלס מתבשל הוא הרגע המרגש ביותר של ארוחת לילה."},"ICON-0840":{"nm":"מכסה לשיפוד נקניקייה","de":"מכסה קטן שאוחז בחוזקה בקצה השיפוד. הוא שומר שיהיה נוח לנגוס, ושלא תיפול טיפת רוטב על היד. ההנאה מנשנוש מול חנות החטיפים מושלמת תמיד בפרטים קטנים כאלה."},"ICON-0841":{"nm":"ידית לשקית ניילון","de":"תולים על האצבעות והניילון בוכה בשריקה קטנה. משקל הקניות נוטה לצד אחד, והדרך הביתה משאירה סימן אדום על כף היד. בתוך הצליל הקל הזה, נטל של יום שלם של משק בית מתנדנד, כבד."},"ICON-0842":{"nm":"תפס לקבלות מקופלות","de":"מקפלים לשניים קבלה ארוכה ותוקעים אותה - וההוצאות של היום הופכות לחבילה מסודרת אחת. בזמן שהנייר המריח דיו נערם שכבה על שכבה, גם זיכרונות משק הבית הקטנים מסתדרים בסדר."},"ICON-0843":{"nm":"תג למיקרוגל","de":"לפני שנשמע הצפצוף, התג מחשב בשקט את זמן החימום. שלט קטן שמציין דקות ושניות, ואת שם מה שיש לחמם. גם ללב הממתין לתורו להתחמם יש סימונים כאלה."},"ICON-0844":{"nm":"גליל מדבקות הנחה","de":"בכל פעם שמקלפים משבצת אחת, צליל דביק קטן מדגדג את קצות האצבעות. כשהמספרים האדומים נגללים בשורה, סל הקניות של מישהו נעשה קצת יותר קל. גליל אחד של חסד קטן, מגולגל וממתין."},"ICON-0845":{"nm":"טבעת לשקיק רוטב","de":"משהו חמצמץ מתפוצץ בזווית הפה, ויום רגיל נעשה קצת יותר מתוק. כשהשקיק התלוי בטבעת עגולה מתנדנד עם כל צעד, מתיקות קטנה אחת מלווה אותי כל היום בכיס."},"ICON-0846":{"nm":"שבב לסלסלת מינימרקט","de":"אוחזים ביד, והפלסטיק מתכופף בקלילות. חנות מוארת בשעת לילה מאוחרת, עומק שמספיק לזוג גימבאפ משולשים ומשקה אחד. כלי חביב בגודל של ארוחה אחת בדיוק, שגם לבד בו אינך בודד."},"ICON-0847":{"nm":"רצועת קופסת מקרונים","de":"רצועה אחת מחבקת בעדינות את הקופסה כדי שהמקרונים הצבעוניים לא יתפזרו. מי שקיבל אי פעם מתנה יודע בקצות אצבעותיו שההתרגשות רגע לפני התרת הסרט היא בעצם המתוקה מכול."},"ICON-0848":{"nm":"תפס לרשת פירות","de":"אוספים את פתח הרשת וצובטים אותו, וניחוח התפוחים חומק בעדינות מבעד לרשת. יד קטנה אחת שמחזיקה כדי שלא יתגלגלו החוצה. בקשה עדינה וחסרת מילים לאכול אותם בקרוב, לפני שירככו."},"ICON-0849":{"nm":"בד למכסה צנצנת ריבה","de":"זה מזכיר את מטבח הקיץ של סבתא, שכיסתה מכסי צנצנות בבד עגול וקשרה אותם בגומייה. פיסת בד משובצת אחת אוטמת בתוכה את הזמן המתוק והמסירות שבהם מבשילה הריבה. טעם היד נשמר כך, מכוסה."},"ICON-0850":{"nm":"סרט קשירה לעוגיות","de":"עוטפים עוגיות טריות בצלופן ומסובבים את הקשר, וניחוח החמאה חודר עד קצות הסרט. היד שמושיטה משהו תוצרת בית למישהו רוטטת תמיד קצת. קשר שקושר יחד גם את הלב."},"ICON-0851":{"nm":"לוח מחיצות לשוקולד","de":"משבצת אחר משבצת, הוא קובע מקום כדי שהשוקולדים לא ייגעו זה בזה. שלא יימסו, שלא יימעכו. מה שהמחיצה הקטנה שומרת עד הסוף הוא, בסופו של דבר, לב שלם אחד להעניק למישהו."},"ICON-0852":{"nm":"תווית מתנה לתה","de":"על התווית העוטפת את שקית התה, שם כתוב בקפידה בכתב יד. הנייר הקטן רומז מראש שההשריה תעלה ניחוח עשב עם האדים. כוס שמחממת את הידיים עוד לפני שלוגמים ממנה."},"ICON-0853":{"nm":"שרשרת בקבוקון סוכריות","de":"שרשרת שנוצרה מחוט שכרוך סביב צוואר בקבוק מלא סוכריות ססגוניות. עם כל צעד, צליל קטן כמו חרוזים מתגלגלים בפנים. אוצר גאה מימי הילדות, לענוד מתיקות סביב הצוואר."},"ICON-0854":{"nm":"קמע לכף מתנה","de":"קמע קטן אחד התלוי בקצה הידית הופך כף רגילה למתנה כמעט בלי משים. צלצול קל וצלול בכל כפית. קישוט זעיר שמוסיף נגיעת אלגנטיות ללב שמעניקים."},"ICON-0855":{"nm":"תג תודה לחטיף","de":"הרצון להחזיר, ולו מעט, כתמורה למה שקיבלת. תג תודה קטן, תלוי בעדינות על שקית חטיף. במקום ה'תודה' שלא הספקת לסיים לומר, ברכה קטנה עוברת בשקט מיד ליד."},"ICON-0856":{"nm":"טבעת דוגמיות סרט הדבקה","de":"דוגמאות שנחתכו והודבקו, זרת אחר זרת, מסתדרות בשורה כרצועה קטנה. בזמן שבוחרים לאט באצבעות איזה צבע אהוב, עצם המחשבה על קישוט צובעת את היום בססגוניות. שורת דוגמיות שבה אפילו ההתלבטות היא הנאה."},"ICON-0857":{"nm":"מכסה לפינצטת מדבקות","de":"מכסים את קצה הפינצטה המחודד, ואפילו מדבקה בגודל ציפורן לא נפגעת. יד מדויקת שמרימה בעדינות פינות שהאצבעות לא היו מגיעות אליהן. בטיפול במה שאוהבים תמיד נלווית זהירות."},"ICON-0858":{"nm":"מדבקת פינה ליומן","de":"מדביקים מדבקות בארבע פינות היומן, והדפים המתנפנפים נרגעים כאילו בקסם. מגע הנייר הנלחץ בעדינות, טקס קטן שאוטם באלגנטיות את היום הזה. תיעוד מתחזק דווקא מהפינות."},"ICON-0859":{"nm":"לוח מדריך לניקוב","de":"לוח שמראה מראש איפה לנקב חור. מיישרים בשקט לאורך הקו המנוקד, ואין סטייה. הלב שבוחן שוב, בלי למהר, זהו הביט הקטן שממנו מגיעה הדיוק תמיד בשקט."},"ICON-0860":{"nm":"מגש שאריות נייר","de":"פירורי נייר שנותרו מגזירה נאספים בעדינות אל תוך המגש. מחסה זמני לפיסות הקטנות, כדי שהשולחן לא יתלכלך. שאריות היצירה מסתדרות כך, בלי רעש."},"ICON-0861":{"nm":"כרית דיו צבעונית","de":"לוחצים על הכרית בעדינות ומרימים, וצבע נמרח לח על קצות האצבעות. אדום צהוב כחול, קשת קטנה שנדבקת בחותמת אחת. פינה רכה לנטיעת צבע, נגיעה אחר נגיעה, על נייר לבן."},"ICON-0862":{"nm":"גליל סרט קישוט","de":"הדוגמה שנגללת החוצה בלי הפסקה נמשכת ללא סוף. מדביקים זרת אחת ופרחים פורחים במקום שהיה חד-גוני. גליל קסם קטן, מגולגל וממתין, שנעשה יפה יותר ויותר ככל שהיד מתקדמת."},"ICON-0863":{"nm":"מכסה לחותמת נושא","de":"כובע קטן שעוטף בחוזקה את ראש החותמת כדי שהדיו לא תתייבש. הוא שומר בשקט שהדוגמה הבאה תישאר ברורה. צבע שנשמר היטב פורח באותה עוצמה גם על הדף הבא."},"ICON-0864":{"nm":"שאריות ניקוב קישוט","de":"הפיסות הקטנות שהמנקב מפיל בנקישה אחת. קונפטי של נייר צבעוני חתוך לכוכבים, לבבות ועלי כותרת נערם ברכות בכף היד. אבנים קטנות יפות מכדי להשליך, ולכן מדביקים אותן שוב איפשהו."},"ICON-0865":{"nm":"טבעת תוויות לסלילי חוט","de":"תווית קטנה עם שם הצבע של החוט, מודבקת על כל סליל. סימון עדין שמצביע על מקומו לפני שיתפתל. גם חוט מסובך, וגם לב מסובך, קל הרבה יותר להתיר בעזרת תג שם אחד."},"ICON-0866":{"nm":"כריכה לספרון מחטים","de":"כריכה רכה לספר עשוי לבד שבו נעוצות מחטים בצפיפות. פותחים, וכלי התפירה שוכבים מסודרים ומקבלים את פני. כרך קטן שמרדים בעדינות את הדברים המחודדים, כדי שקצות האצבעות לא ייפגעו."},"ICON-0867":{"nm":"טבעת דוגמיות בדים","de":"גס או רך, הזמן האיטי שבו ממששים את מרקם הבד, פיסה אחר פיסה, כדי לבחור. בין הגזרים הערוכים לפי צבע, לפני שהופך לבגד, הבד ממתין בשקט להיות מגושש קודם כול."},"ICON-0868":{"nm":"חישוק לרקמה","de":"משחילים בד לתוך החישוק העגול ומהדקים, והוא נמתח כמו עור תוף. אות קטן שאומר שההכנה לרקום תפר אחר תפר הסתיימה. מה שהחישוק אוחז בחוזקה אינו הבד, אלא הלב המרוכז."},"ICON-0869":{"nm":"קפסולת מיון לכפתורים","de":"כפתורים שהתגלגלו פעם מתיישבים בשקט, לפי צבע, בכל תא בקפסולה. חוכמת הבית שמחלקת לחלקים קטנים כדי שדבר לא ילך לאיבוד. גם באיסוף דברים מפוזרים טמונה מסירות שכזו."},"ICON-0870":{"nm":"מחזיק גיר לתפירה","de":"מחזיק שתופס בנוחות ביד גיר שמסמן קווים על בד. הוא תומך בחוזקה בדבר שביר שנשבר בקלות. המחשבה הראשונה, השלווה, לפני שמרימים את המספריים - שקו ראשון ישר הופך גם את הבגד לישר."},"ICON-0871":{"nm":"צנצנת סיכות תפירה","de":"בתוך הצנצנת השקופה, סיכות תפירה מתנגשות ומקשקשות זו בזו. מחזיקים לאור השמש וברק קטן מתיישב על קצה כל מחט. כלי מהודק אחד שאוסף למקום אחד, ומרדים בעדינות, דברים מסוכנים כשהם מפוזרים."},"ICON-0872":{"nm":"גליל סרט תיקון","de":"רצועת קסם שנדבקת בשקט כשמגהצים אותה על מקום קרוע. בלי תפר אחד, בגד בלוי מחלים בשקט. הלב שתיקן ולבש הלאה, במקום לזרוק, מגולגל, שכבה אחר שכבה, בתוך הגליל העגול."},"ICON-0873":{"nm":"דף תבנית לטלאי","de":"דף תבנית שעליו רשומה מראש צורת הטלאי. קו מנוקד מדריך בחביבות את הדרך שבה יעברו המספריים. לשרטט קודם את קווי המתאר של מה שרוצים ליצור - ההתרגשות מתחילה תמיד מהתרשים הדהוי הזה."},"ICON-0874":{"nm":"מכסה לצנצנת מים לצבעי מים","de":"מכסים את פתח הצנצנת ולא תישפך טיפה, לא משנה כמה יתנדנדו המים הצבועים. הוא מכסה גם את החשש ממים עכורים שישטפו את השולחן. פקק שקט אחד ששומר בדממה על מקום הציור."},"ICON-0875":{"nm":"רצועת מגן לפסטל","de":"כורכים רצועה סביב פסטל שמותיר אבקה לבנבנה, והאצבעות מתלכלכות פחות. נייר שעוטף בעדינות צבע רך כדי שלא יתפורר. ככל שהצבע רך יותר, כך יש לאחוז בו בעדינות רבה יותר, כדי שיצבע בעדינות גם על הנייר."},"ICON-0876":{"nm":"מכסה מאריך לעפרון צבעוני","de":"מרכיבים מכסה על קצה עפרון צבעוני שנשחק, וגדם קצר מתארך שוב. הלב שלא נפטר בקלות ממשהו רק כי התקצר. מקצות אצבעות שמנצלות עד הסוף, צבע הציור מתעצם עד למשבצת האחרונה ממש."},"ICON-0877":{"nm":"וו לכוס שטיפת מכחולים","de":"תולים את כוס השטיפה על הוו, וטיפות מים שנשרו מהמכחול זולגות בטפטוף. לפני צביעת הצבע הבא, הדממה הקצרה והצלולה של שטיפת המכחול. גם בצליל ההתנקות הזה זורם קצב שקט."},"ICON-0878":{"nm":"מכסה לסכין פלטה","de":"מכסה קטן שעוטף בחוזקה את להב הסכין המפזרת ומגרדת צבע. הוא שומר בשקט שהקצה החד לא יקהה. המרקם של צבע מרוח בעובי נולד מקצה זה, שנשמר היטב."},"ICON-0879":{"nm":"תפס לקנבס","de":"תפס איתן שמותח את בד הקנבס בחוזקה על המסגרת ומהדק אותו. נושכים חזק, ומשטח הציור נמתח כמו עור תוף. רק כשיש בסיס יציב שאינו מתנדנד, גם משיכות המכחול שרצות מעליו יכולות להשתחרר לגמרי."},"ICON-0880":{"nm":"רצועה ללוח ציור","de":"תולים את הרצועה בקלילות על הכתף, והלוח עוקב אחרי הגב. מתיישבים בכל מקום, והוא הופך מיד לסטודיו הפרטי שלי. סטודיו קטן נישא על הגב, יוצא בקלילות בחיפוש אחר נוף לצייר."},"ICON-0881":{"nm":"שפופרת צבעי אקריליק","de":"מוסיפים טיפת מים אחת ומתקבל שחר, פחות - וזה נעשה חצות. אותו כחול פותח שמיים שונים בכל פעם מתחת לאצבעות. ברגע שסוחטים שפופרת אחת, צבע הלב של היום מתפשט על הנייר."},"ICON-0882":{"nm":"דף דוגמית מעברי גוון","de":"הדף הזה ידע ראשון שהשקיעה לא מאדימה בבת אחת. מדרגות קטנות שעוברות מבהיר לכהה. העין הולכת ביניהן לאט, ועוקבת בשקט אחר הזמן שבו הצבע מבשיל."},"ICON-0883":{"nm":"מכסה למסרגת סריגה","de":"מגן קטן כמו אצבעון, שמרכיבים לפני שהחוט חודר לתוך האצבע. יד שסרגה זמן רב יודעת. רק כשלא נפגעים אפשר ללוות אותה בעדינות עד התפר האחרון."},"ICON-0884":{"nm":"טבעת סימון לסריגה","de":"סימון אחד, ולאן הגעת מתבהר שוב. תחושת הביטחון שלא צריך לספור פעמיים את אותו תפר. גם הלב, כך בדיוק, כשמסמנים בעדינות את המקום שממנו באת, לא מאבד את דרכו."},"ICON-0885":{"nm":"קמע ספירת שורות","de":"הוכחה שקטה על שורה שהושלמה נערמת, משבצת אחר משבצת. גם עבודה שנראתה אינסופית, כשסופרים אותה אחת אחת, חוצה בפתאומיות את החצי. חשבון קטן נושא את הלב של היום עד הסוף."},"ICON-0886":{"nm":"סיכת סידור לקצה חוט","de":"משאירים קצה חוט משוחרר כמות שהוא, ואין לדעת איפה הקשר הבא יסתבך. מגע שמסדר מראש מקום שלא ייראה. עדינות, לרוב, מזדרזת קודם כול במקומות שאינם גלויים לעין."},"ICON-0887":{"nm":"חוט תרגול קשרים","de":"קשר פשוט, קשר פרפר, קשר טבעת. קושרים ומתירים את אותו החוט שוב ושוב, עד שהיד זוכרת את הצורה. כשקצות אצבעות מגושמות נעשות פתאום חלקות בלילה כלשהו, החוט הזה הוא הראשון לדעת."},"ICON-0888":{"nm":"רצועת תווית לפקעת צמר","de":"רצועה קטנה שמציינת על כל פקעת את עוביה וצבעה. הרגל שנולד מלילות שבהם חיפשו לשווא את אותו החוט אחרי שאזל. תיעוד הוא פתק עדין המופנה אל העצמי העתידי."},"ICON-0889":{"nm":"פיסת סרגל דוגמית","de":"כמה תפרים נכנסים ב-10 סנטימטרים - המספר הקטן הזה קובע את מידתו של בגד שלם. שפיסה בגודל כף יד אוחזת במידה של הכול, זהו דבר לא קל משקל כלל, כשמרימים אותה."},"ICON-0890":{"nm":"סימון לחור כפתור","de":"לפני תפירת כפתור, מסמנים תחילה נקודה אחת - היכן לנקב. בזכות הסימון הזה, שעומד להיעלם בקרוב, מדף הבגד לא יוצא עקום. מסירות, לרוב, נותרת בשקט במקום שבסוף לא ייראה כלל."},"ICON-0891":{"nm":"לולאת פונפון קטנה","de":"כמו הפונפון בקצה נוריגה, טבעת קטנה יוצרת תנודה. עין תמיד נעצרת על מה שתלוי ומתנועע בשקט. מרקם שקם לחיים בעדינות בכל פעם שהרוח חולפת."},"ICON-0892":{"nm":"בקבוקון צבע קטן","de":"לא לחסוך, אלא להשתמש בדיוק - זו הדרך הנכונה לטפל בצבע. גוון שדי בטיפה אחת ממנו, נמדד ביד שנשארת לצד הבקבוקון הקטן. איפוק מגיע מהנחת התאווה בצד, פעם אחת."},"ICON-0893":{"nm":"מקל שיוף קטן","de":"מתחילים מהצד הגס ועוברים בהדרגה אל הצד העדין. אין שום משטח שנעשה חלק בבת אחת. מקצות אצבעות שמורידות את המרקם צעד אחר צעד, מקום שהיה גס נעשה לאט לאט רך."},"ICON-0894":{"nm":"מעמד מלחציים לדגמים","de":"אוחזים ביד חלק מודבק, ונשארת טביעת אצבע. תופסים אותו בעדינות במלחציים, והיד משתחררת, וההתייבשות מסתיימת בשקט לבדה. גם ההמתנה נעשית קלה יותר כשמישהו תומך בה."},"ICON-0895":{"nm":"לוח עבודה לדבק","de":"טיפת דבק אחת שנופלת על השולחן משאירה עקבות לזמן רב. ההרגל להניח קודם לוח אחד. אולי מחצית העבודה מתחילה בדיוק מהרצון הזה לא ללכלך את המקום."},"ICON-0896":{"nm":"תא מיון לחלקים","de":"כשעשרות חלקים בצורה זהה מתערבבים, ההרכבה הופכת עד מהרה למבוך. המגע שמחלק אותם לכל תא מקצר מראש את זמן ההתמסרות. סידור הוא חסד המוענק לעצמי העתידי."},"ICON-0897":{"nm":"שבב סדר הרכבה","de":"שבב קטן שמציין באיזה חלק ממוספר להתחיל. שומרים על הסדר, וזה לא מתפרק בקלות. גם דגם, וגם כל יום שנבנה צעד אחר צעד בזהירות, מתחזק על ההבטחה השקטה הזו."},"ICON-0898":{"nm":"וו קטן למכחולים","de":"מניחים מכחול משומש לשכיבה, והשיער נלחץ ומתעקם. מקום לתלייה הפוכה שמנקזת את הלחות. מי ששומר על כליו לצדו זמן רב, דווקא אחרי שהעבודה נגמרת, הוא עסוק ועדין יותר."},"ICON-0899":{"nm":"קופסת שאריות פלסטיק","de":"קופסה שבה נאספות בשקט השאריות שנחתכו מהמסגרת. נראות כמושלכות, אך יום אחד הן חוזרות כפרט קטן. לשאריות יש תור משלהן, והקופסה יודעת זאת, ממתינה בשתיקה."},"ICON-0900":{"nm":"מכסה תרסיס גימור","de":"השכבה האחרונה, אם מרססים אותה מקרוב מדי, פשוט זולגת למטה. ממרחק של זרת, בקלילות, בקלילות. הענקת הברק היא אולי גם תרגול בהנחת תאוות הלב, פעם אחת."},"ICON-0901":{"nm":"קופסת עופרות לעפרון מכני","de":"עופרות דקות לעפרון מכני נשברות בקלות בתוך הכיס. כשמניחים אותן מסודרות בשפופרת קטנה, אף עיפרון לא הולך לאיבוד לשווא. סידור הוא, בסופו של דבר, לב שקט שדואג מראש לעצמי של מחר."},"ICON-0902":{"nm":"מעטפת נייר למחק","de":"מעיל נייר קטן שלובשים על המחק. ככל שהוא מתכהה משימוש, כך הוא צובר יותר עקבות של תיקונים. למחוק זה גם רשות עדינה לחזור ולהתחיל מההתחלה."},"ICON-0903":{"nm":"שפופרת אחסון לניבים","de":"ניבי עט נסדקים כשהם מתייבשים ומתעקלים כשמכים בהם. שפופרת קטנה שמניחה אותם בנפרד לבד שומרת לאורך זמן על מרקם הכתיבה. כלי שמטפלים בו בעדינות מחליק בעדינות בחזרה כתודה."},"ICON-0904":{"nm":"דגימת דיו לעט נובע","de":"דיו שבודקים טיפה אחר טיפה. צבע שנדמה כתכלת הופך על הדף לים עמוק. את הצבע תמיד צריך לפגוש במו העין - הגוון שדמיינת בלב מפספס לעיתים קרובות."},"ICON-0905":{"nm":"פחית סימניות ספר","de":"דגלון קטן שתוחבים בעדינות במקום שבו הפסקת לקרוא. כשפותחים את הספר בפעם הבאה, האני של אתמול מנפנף וממתין. אפילו המקום שבו עצרת הופך להבטחה - זו המלאכה העדינה של הסימן הקטן ההוא."},"ICON-0906":{"nm":"חבילת דגלוני סימון","de":"קולפים דף אחד ומדביקים, והסיפור מתחיל מחדש בדיוק משם. כשהדגלונים הקטנים מתיישרים לאורך שולי הספר, מחשבות שהיו מפוזרות נאספות בסדר לתוך מפה אחת."},"ICON-0907":{"nm":"מגנט לאיסוף מהדקים","de":"מגנט קטן שאוסף בבת אחת מהדקים מפוזרים. ככל שהחפץ קטן יותר, כך קל יותר לאבד אותו, ולכן כוח איסוף אחד מציל בשקט שולחן מבולגן. גם במשיכה יש עדינות."},"ICON-0908":{"nm":"סט מכסים לקצה עיפרון","de":"כובעים קטנים שעוטפים את קצות העפרונות ושומרים על תוך התיק. כל דבר חד עלול לנקוב במשהו, ולכן הוא זקוק ליד שתכסה אותו בעדינות. חד יישאר, אך בלי לפצוע."},"ICON-0909":{"nm":"מדבקת שילוט לשולחן","de":"ברגע שכותבים שם ומדביקים אותו על השולחן, המקום הזה סוף־סוף הופך לשייך למישהו. כשגם שטח בגודל כף יד מקבל בעלים, גם האופן שבו יושבים בו בלב משתנה לגמרי."},"ICON-0910":{"nm":"מכסה ידית לחבל קפיצה","de":"מכסה שמלבישים לפני שקצה הידית משתפשף ונסדק. את הקצב של חבל שהסתובב אלף פעמים, כף היד זוכרת עוד לפני הראש. מקצב שנחרט בגוף לא נשכח בקלות."},"ICON-0911":{"nm":"רצועת טבעת ליוגה","de":"אוחזים בטבעת ופותחים לאט את הגוף. ככל שהרצועה נמתחת יותר, כך הכתפיים הנוקשות משתחררות שכבה אחר שכבה. למתוח זה לא לכפות משיכה, אלא קרוב יותר לחכות בשקט עד שהגוף נפתח מעצמו."},"ICON-0912":{"nm":"קופסת כדורי פינג פונג","de":"כדור לבן קל כל כך שהוא מתגלגל למרחקים, ומתקמט לגמרי אם דורכים עליו. קופסה קטנה אחת שומרת על הכדור השברירי הזה עד המשחק הבא. חוזק מגיע לא פעם מעטיפה רכה."},"ICON-0913":{"nm":"סרט אחיזה למחבט בדמינטון","de":"כורכים שכבה נקייה אחת סביב ידית שמחליקה מהזיעה. על אחיזה כרוכה היטב, המחבט הופך לחלק מהיד. הסוד לשחק בתחושה ולא בכוח מסתתר בשכבה הדקה הזו."},"ICON-0914":{"nm":"אסימון ניקוד קטן","de":"נקודה, ואז עוד נקודה. מזיזים אסימונים קטנים וצוברים את הניקוד אחד אחד. כשהספירה גלויה לעין, המשחק מתבהר, ואומץ להדביק פער של נקודה אחת מבצבץ בשקט."},"ICON-0915":{"nm":"מהדק כיוון לנעלי ספורט","de":"קצות נעליים מונחות בסדר תמיד פונים לאותו כיוון. סיבוב קל של היד כשחולצים אותן. סידור קטן אחד הופך את הצעדים של מחר בבוקר לקלים יותר."},"ICON-0916":{"nm":"רצועת צוואר למשרוקית","de":"תולים משרוקית על הצוואר ומקבלים את הזכות להגיד עצור. המראה של מגרש שלם שנעצר בבת אחת מצליל קצר אחד. הלבבות שנותנים אמון בקול הקטן הזה מתאספים והופכים להבטחה."},"ICON-0917":{"nm":"שפופרת מחטי משאבה לכדורים","de":"גם כדור מרוקן מאוויר נמתח שוב עם מחט דקה אחת. אותה מחט שמורה בעדינות בתוך שפופרת קטנה - ברגע שהיא אובדת, המשאבה כולה הופכת לחסרת תועלת. כשהדבר הקטן ביותר הוא החשוב ביותר."},"ICON-0918":{"nm":"קונוס סימון מיני","de":"מכאן ועד שם, קונוס קטן מצייר גבול שלא נראה לעין. גם בלי קו, אנשים נעמדים בטבעיות בתור לפי הסימון. סדר צומח בשקט מאותות קטנים כאלה."},"ICON-0919":{"nm":"כיס לאסימונים","de":"כיס שאוסף אסימונים מקשקשים למקום אחד. כשמהדקים את הפתח, שום דבר לא מתפזר. אפילו דברים קטנים ופעוטים זקוקים למקום להיאסף בו כדי למלא את תפקידם - הכיס מראה זאת בלי מילים."},"ICON-0920":{"nm":"מזרן ערבוב קלפים","de":"על שולחן חלקלק, קלפים לא נאחזים היטב ביד. מפית אחת הופכת גם את הערבוב וגם את ההרמה לחלקים בהרבה. גם במשחק טוב יש הכנה עדינה שמתחילה בבחירת המשטח."},"ICON-0921":{"nm":"מגן פינות ללוח משחק","de":"כשליל משחק לוח מסתיים, מישהו תמיד דואג בשקט קודם כל לארבע פינות הלוח. כי הוא יודע שקפל עמוק יעוות את הסיבוב הבא. בקצות האצבעות שמיישרות את הפינות טמונה המשאלה לשחק יחד שוב מחר."},"ICON-0922":{"nm":"מכסה לכוס קוביות","de":"הרגע הקצר שבו כולם מנערים, מגלגלים ועוצרים נשימה יחד. זו תקרה קטנה ששומרת על הקוביות מלקפוץ החוצה. מתחת למכסה, המזל של היום עוצר לרגע לנשום, ואז מתגלגל החוצה בקול נקישה."},"ICON-0923":{"nm":"לוח יישור אריחים","de":"ככל שמישהו נלהב יותר מהמשחק, כך השורה שלו מתעקמת יותר. לדחוף בעדינות אריחים נוטים כדי ליישר אותם בשקט. יישור הוא יד שמקבלת בחביבות את הקוצר רוח הנרגש של מישהו."},"ICON-0924":{"nm":"פחית אסימוני ניקוד","de":"ככל שהפחית מתמלאת יותר באסימונים, כך המשחק מתלהט יחד איתה. כשהעיגולים העגולים של הניקוד מתנגשים בקול נקישה בכף היד, הצליל הזה משמח עוד לפני שהניצחון וההפסד בכלל משנים."},"ICON-0925":{"nm":"טבעת סימון תור","de":"טבעת קטנה שמודיעה שעכשיו תורך. באותו רגע שבו מזיזים אותה חריץ אחד, כל העיניים מתכנסות בשקט עליי. חישוק שמסתובב לאט בין ציפייה להתרגשות."},"ICON-0926":{"nm":"בסיס לכלי משחק","de":"ככל שכלי נופל בקלות רבה יותר, כך צריך שהבסיס שלו יהיה יציב יותר. בסיס אחד שומר על מקומו גם על לוח שמתנדנד קלות. הדבר הקטן צריך להחזיק מעמד כדי שהדבר הגדול שמעליו יעמוד זקוף."},"ICON-0927":{"nm":"קליפס לחוברת הוראות","de":"חוברת ההוראות תמיד מחליקה בעמודיה כשמשאירים אותה פתוחה. לפני שהרוח נותנת לדפים לברוח, המהדק הזה נועץ את שיניו בעדינות בעמוד אחד. את הכללים צריך להחזיק במקום כדי שהמשחק ימשיך עד הסוף."},"ICON-0928":{"nm":"רצועה לנרתיק פיקים","de":"פיק לגיטרה תמיד מחליק מהאצבעות דווקא ברגע הכי מרגש. רצועה אחת התלויה מהנרתיק עוצרת את הבריחה הקטנה הזו. רק מי שחווה לילה שבו המוזיקה נעצרה יודע להעריך את הרצועה הזו."},"ICON-0929":{"nm":"שפופרת אחסון לקנה חליל","de":"קנה מאבד את קולו ברגע שהוא מתייבש. בתוך שפופרת לחה, פיסת קנה דקה ממתינה להופעה הבאה. מקום שבו מרדימים את הנשימה, עוד לפני שנושפים אותה חזרה פנימה."},"ICON-0930":{"nm":"מפתח החלפת מיתרים","de":"כשמיתר משתחרר, גם הצליל שוקע בשקט. לסובב לאט את הידית ולהשיב את המתיחות - התשומת לב תמיד מגיעה מקצה שורש כף היד. צליל מסודר מתחיל מסדר קטן שכזה."},"ICON-0931":{"nm":"מטלית ניקוי לכלי נגינה","de":"כשהופעה מסתיימת, גם על כלי הנגינה נותרת זיעה קלה. מעבר אחד עם מטלית רכה מחזיר את הברק ומניח לצלילי היום לשקוע בשלווה. לב אוהב תמיד מתגלה בסיום."},"ICON-0932":{"nm":"כיסוי ליתדות כוונון","de":"יתדות כוונון חשופות מחלידות מבלי משים. כיסוי קטן אחד מאט בפעימה אחת את עונות הברזל. מי שדואג קודם לפינות הבלתי נראות הוא זה שמנגן הכי הרבה זמן."},"ICON-0933":{"nm":"מנורת קליפס לעמוד תווים","de":"מאחורי הבמה החשוכה, יש רגעים שבהם רק התווים צריכים להאיר. פנס קטן שמתהדק לעמוד ומשלשל את האור בעדינות מטה. קורטוב תאורה שמאיר את הדרך כדי שהתווים לא יאבדו את הדרך."},"ICON-0934":{"nm":"מכסה השתקה לתרגול","de":"תרגול השכם בבוקר תמיד מתעמת בשקט עם שנת השכנים. כשעוטים מכסה אחד, קול רועם מצטמצם ללחישה. יש גם מוזיקה שגדלה תוך שמירה על שנתו המתוקה של מישהו."},"ICON-0935":{"nm":"מדבקות ללוח תופים","de":"סימונים קטנים שמודבקים על לוח התופים. איפה להכות ואיזה צליל ייצא - העיניים לומדות את הדרך לפני שהידיים זוכרות אותה בעל פה. כך הקצב נחרט לאט בגוף."},"ICON-0936":{"nm":"אסימון תזכורת מנגינה","de":"מנגינה שמזמזמים נעלמת מהר אם לא תופסים אותה. כמה שורות שנרשמו בחיפזון על אסימון גדלות לפעמים בעתיד לשיר שלם. השראה תמיד חוזרת ליד ששוקדת לרשום."},"ICON-0937":{"nm":"רצועה לכריכת ספר","de":"מטריד כשספר שלא סיימו לקרוא נפתח מעצמו בתוך התיק. רצועה אחת כורכת בעדינות את דפי הספר וגורמת להם להיות צייתנים. הבטחה לקפל דברים בסדר לקראת העמוד הבא."},"ICON-0938":{"nm":"טבעת מחזיקת עמודים","de":"יום שבו רוצים להחזיק ספר פתוח ביד אחת וללגום קפה חם. טבעת שמשחילים על האצבע מחזיקה את הדפים במקומך. רווחה קטנה מתחילה מהמצאות פעוטות כאלה."},"ICON-0939":{"nm":"אסימון טיימר לקריאה","de":"אומרים לעצמם רק פרק אחד ויושבים, וכבר הלילה מעמיק. לוחצים על האסימון וקובעים זמן, וגם לקריאה יש עצירה. ככל שהדבר האהוב יקר יותר, כך נדרש אומץ עדין יותר לדעת מתי לעצור."},"ICON-0940":{"nm":"מגן פינות לספר","de":"ככל שהספר יקר יותר, כך הפינות שלו משתפשפות ראשונות בשקט. מכסה אחד שומר על פינות הכריכה עגולות ובטוחות. שריון קטן שעוטים כדי לשמור לאורך זמן ארוך את מה שרוצים לשמור קרוב."},"ICON-0941":{"nm":"סרט הערות קריאה","de":"יש רגעים שבהם שורה אחת גורמת ללב לשקוע פנימה. התרשמות שהועתקה על הסרט נשארת בעמוד ההוא כמו סימנייה. החום החמים של קו תחתי, שרק מי שקרא מכיר."},"ICON-0942":{"nm":"תגית החזרה לספרייה","de":"תאריך ההחזרה תמיד מגיע יום אחד מוקדם מדי. כשהתאריך הכתוב על התגית דוחף בשקט בגב, גם לספר שהושאל יש נימוס של סיום. למען הידיים הבאות, כך הספרייה ממתינה."},"ICON-0943":{"nm":"מנורת קליפס לספר","de":"לילה שבו נשארים ערים לקרוא לבד לצד המשפחה הישנה. אור קטן אחד שנצמד עם קליפס לקצה הספר די והותר. לא צריך לדחוף את כל החושך הצידה - עמוד אחד מספיק לזמן שקט זה."},"ICON-0944":{"nm":"כרטיס ריח ספרים","de":"מספרים ישנים עולה ריח של אור שמש ונייר שהתערבבו יחד. הכרטיס הזה, שאומרים שהוא שומר את הריח הזה בדף אחד, כשפותחים אותו מחייה לרגע סמטת ספרים משומשים בקצה האף. גם הזיכרון תוחב סימניות בעזרת ריחות."},"ICON-0945":{"nm":"סיכת סימון מיקום קריאה","de":"עד איפה קראתי - סיכה קטנה שמוחקת את השאלה חסרת הישע הזו. תוחבים אותה במשפט האחרון, והאני של מחר לא ילך יותר לאיבוד. סימון עדין שזוכר במקומך את המקום שבו עצרת."},"ICON-0946":{"nm":"תליון לרצועת טלפון","de":"תליון אחד שתלוי על רצועת הטלפון גורם לאדם להיראות קצת אחרת. צבע אהוב, צורה אהובה. טעם קטן שמחזיקים ביד מנדנד בעדינות את מצב הרוח של היום."},"ICON-0947":{"nm":"מכסה מגן לעדשת מצלמה","de":"גורלן של תמונות הטיול תלוי בעדשה אחת. הרגע שבו מסירים את מכסה המגן הוא בעצם המוכנות של הלב ללחוץ על התריס. טקס קטן, הראשון לפקוח עיניים לפני שמנציחים נוף."},"ICON-0948":{"nm":"פקק ליציאת טעינה","de":"האבק בתוך התיק תמיד מכוון קודם כל לחור הטעינה. חוסמים את הפתח הקטן עם פקק אחד והמחבר נשאר נקי לאורך זמן. יש כאן חריצות שמטפלת גם בפינות הבלתי נראות."},"ICON-0949":{"nm":"טבעת פופ לאחיזת טלפון","de":"להעמיד את הטלפון באלכסון רק כדי לצפות בנוחות בסרטון אחד. פותחים את הטבעת שמודבקת מאחור, ויד ומסך נושמים בקלות רבה יותר. בסיס קטן שבולט מציע שעת ערב נינוחה יותר."},"ICON-0950":{"nm":"מדבקת ניקוי למסך","de":"מסך מלא טביעות אצבע איכשהו מטשטש גם את הלב. מגע אחד עם המדבקה והעולם חוזר להתמקד. ניקיון הוא לפעמים משימה קצרה של אצבע אחת."},"ICON-0951":{"nm":"נרתיק סיכת סים","de":"סיכת הסים היא פיה שנעלמת רק ברגע שבאמת זקוקים לה. מניחים אותה בתא אחד בנרתיק ולא צריך יותר לחפש סיכת שיער בכל הבית. סדר קטן מציל בשקט רגע דחוף."},"ICON-0952":{"nm":"מדבקה למשטח טעינה אלחוטית","de":"לילה שבו הכל מתמלא מעצמו כשמניחים בעדינות על המשטח. מדבקה מודבקת מסמנת קלות את המקום שבו הטלפון צריך לשכב. זרם בלתי נראה ממלא בשקט מנת אנרגיה ליום."},"ICON-0953":{"nm":"מדבקת הסתרת התראות","de":"התראות שלא רוצים לראות עדיף להשאיר מכוסות - כך יותר קל ללב. מדבקה אחת משתיקה את האור הקטן של השחר. לפעמים גם לא להסתכל הוא דרך עדינה להגן על עצמך."},"ICON-0954":{"nm":"טבעת מגן לעדשה","de":"הרגע שבו עדשת המצלמה נוגעת ברצפה, הלב צונח בבהלה. טבעת אחת שעוטפת אותה סביב מונעת בשקט את הנפילה הקטנה. מסגרת שמגנה קודם כל על העין ששומרת את הזיכרונות."},"ICON-0955":{"nm":"תגית שם לכבל","de":"לזהות סוף כל סוף את שלי מתוך ערמת כבלים מסובכת וקשורה. תגית אחת סוף סוף נותנת לכבל טעינה שם משלו. דגלון קטן שמורה על הדרך בין החוטים המבולגנים."},"ICON-0956":{"nm":"נרתיק מטענים","de":"מטענים בתוך תיק נסיעות תמיד מסתבכים וריבים זה בזה. אוספים אותם בסדר לתוך תא אחד בנרתיק והם סוף סוף משלימים. אמנות האריזה טמונה בקריאה עדינה לדברים המפוזרים להתאסף למקום אחד."},"ICON-0957":{"nm":"מדבקת סימון למאריך","de":"החורים במאריך כולם נראים אותו דבר, ומבלבלים בכל פעם מחדש. מדביקים תווית שקובעת למי שייך כל מקום, ובוקר עמוס נעשה חלק בהרבה. תג שם קטן מצמצם את הריבים הקטנים של היומיום."},"ICON-0958":{"nm":"גלגלת לכריכת כבלים","de":"מתירים לשימוש וכורכים בחזרה - יום מסודר לחוט. כורכים אותו שכבה אחר שכבה על גלגלת אחת והסבך נעלם לגמרי. היד שמחזירה דברים למקומם אחרי השימוש הופכת את מחר לקל יותר."},"ICON-0959":{"nm":"מכסה למחבר מגנטי","de":"מחבר מגנטי אוסף מבלי משים אבקת מתכת דקה. מכסים אותו במכסה ואבק דביק לא נדבק. מכשיר שנוגעת בו יד דואגת נוספת חי לצדך זמן רב יותר."},"ICON-0960":{"nm":"רצועה לסוללת גיבוי","de":"משאירים סוללת גיבוי וכבל בנפרד ותמיד אחד מהם נעלם. קושרים אותם ברצועה והשניים סוף סוף הופכים לזוג. קשר קטן שקושרים בעדינות ממש לפני היציאה, כדי לומר להם לנסוע יחד."},"ICON-0961":{"nm":"מכסה אבק לשקע","de":"שקע ריק בקיר מספיק לו כמה ימים כדי שהאבק יתחיל בשקט לעשות בו בית. כשמכסה קטן זה שומר על המקום במקומו, המטען שיתחבר בפעם הבאה יכול לשאוף נשימה ראשונה ונקייה. שוער ששומר בעדינות על הזמן הריק."},"ICON-0962":{"nm":"טבעת צבע לכבלים","de":"לילה שבו מגששים אחר הכבל שלי בין חוטים מסובכים - מי אמר שנצבע אותם? כחול זה אתה, צהוב זו אני. עם חישוק קטן אחד, כבר אין בלבול בינינו. עקבות של הבטחה חמה שנותרו בפינת חדר החזרות."},"ICON-0963":{"nm":"אסימון סיווג מתאמים","de":"רגליים עגולות ורגליים שטוחות, 110 ו-220. אסימון ששינן בשקט את פרצופי השקעים השונים בכל מדינה. בפינת המזוודה של אותה נסיעה ראשונה מעבר לים אל הבמה, אסימון סיווג קטן זה תמיד היה תחוב שם."},"ICON-0964":{"nm":"מגש מיון כריות אוזניות","de":"אומרים שתעלות האוזניים שונות בעומק וברוחב מאדם לאדם. להניח בשורה גדול, בינוני וקטן, ולבחור את הזוג המדויק שמתאים לאוזן שלך. הליך עדין שמתאים קודם כל את הגוף, לפני שמאזינים לצליל."},"ICON-0965":{"nm":"טבעת סיליקון לנרתיק","de":"לתלבושת הבמה מקדישים תשומת לב עד לתפר האחרון, אך פינות הנרתיק תמיד נחבטות חשופות. כשמסגרת הסיליקון הדקה הזו עוטפת בעדינות את ההיקף, גם בשחר שבו הוא מחליק מהיד, המסך מקבל את הבוקר שלם."},"ICON-0966":{"nm":"מדבקת ביטול רעשים","de":"יש ימים שרוצים לכבות לרגע את קולות העולם. המדבקה הקטנה הזו שמודבקת על אוזן האוזניות היא סימן שמדליק את הדממה. קמע שלוקח את תשואות הקהל ורעש הרכבת התחתית למרחק, רק עד שהשיר האחד מסתיים."},"ICON-0967":{"nm":"סט וו לאוזניות","de":"כשרוקדים, אוזנייה אחת תמיד בורחת ראשונה. תולים את הווים האלה שמחבקים בעדינות את הסחוס - וגם בתוך כוריאוגרפיה עזה, המוזיקה לבדה נשארת באוזניים עד הסוף. תגלית קטנה שאנשי חדר החזרות העבירו זה לזה."},"ICON-0968":{"nm":"מכסה למברשת ניקוי","de":"כובע קטן שעוטים כדי שהאבק שדבק בקצות הזיפים לא יתעופף שוב. שגם לכלי הניקוי עצמו נדרש ניקוי - זאת ידעה מזמן היד שהעמידה את המטאטא הפוך אחרי הטיאטוא."},"ICON-0969":{"nm":"משטח בסיס למעמד טעינה","de":"מעמד הטעינה החליק שוב ושוב על השולחן כי לא היו לו רגליים. כשמשטח דק זה על הרצפה תפס את מקום הרגליים, המכשיר נשאר במקומו והתמלא בשקט באנרגיה כל הלילה."},"ICON-0970":{"nm":"סימון שמאל-ימין","de":"שמאל L, ימין R. מסמנים נקודה נוספת כדי שאפשר יהיה לזהות גם בגישוש בחושך. המשאלה לא לטעות אף פעם בין רגל שמאל לרגל ימין על הבמה חקוקה בשלמותה בסימון הקטן הזה."},"ICON-0971":{"nm":"מכסה ליציאת מפצל אודיו","de":"אותו ג'ק שדרכו חלקו רבים קול אחד, בזמן המנוחה צריך לסתום את קצהו. כדי שהאבק לא יחלחל למעגל החשמלי. יד קטנה וזהירה שרוצה לשלוח את השיר ששרו יחד לזרום צלול גם בפעם הבאה."},"ICON-0972":{"nm":"גלגלת כריכה לכבל אוזניות","de":"כמו התנועה הישנה של כריכת פקעת חוט, גם כבל האוזניות נעשה מסודר כשכורכים אותו כאן במעגל. הרגע שבו מוזיקה שהתגלגלה מסובכת בתוך התיק מסתדרת בסדר. ההתרה של מחר תהיה קלה בהרבה יותר."},"ICON-0973":{"nm":"רצועת אחיזה למכסה עדשה","de":"בכל פעם שפותחים את העדשה, המכסה תמיד איבד את דרכו. קושרים אותו לרצועה שמחוברת לצד המצלמה, ואין יותר צורך לגשש לשווא בכיס. שלא לאבד דבר - צריך פשוט לקשור אותו קרוב; היד למדה זאת ראשונה."},"ICON-0974":{"nm":"תליון מכסה נעל חמה","de":"לתוך נעל החמה הריקה שמעל המצלמה, מחליקים בעדינות קישוט קטן. התליון הזה, חסר כל פונקציה, גורם באורח פלא לציוד הכבד והמחוספס להיראות יקר ואהוב כמו רכוש ממש. מלאכת ההתאהבות בכלי."},"ICON-0975":{"nm":"אבזם כוונון רצועה","de":"בכל פעם שרצועת התיק חופרת בכתף, מרפים ומהדקים מעט את האבזם הזה. תנועת אצבעות אחת לבחור אורך שמתאים לגוף. גם לשאת משא הוא, בסופו של דבר, לדאוג לעצמך - כך האבזם לוחש בשקט."},"ICON-0976":{"nm":"נרתיק ערמת פילטרים","de":"בית קטן שבו מניחים שכבה על שכבה פיסות זכוכית שמפצלות אור. עננות ובהירות, שקיעה ולילה. כמו מגירה שבה בוחרים ואוגרים מראש את מזג האוויר, הצלם תמיד פותח קודם כל את הנרתיק הזה לפני שיוצא לדרך."},"ICON-0977":{"nm":"מכסה אבק למנפחית","de":"כדור גומי שנופח אוויר כדי לגרש אבק חלש גם הוא, בפתחו שלו, מפני האבק. בזמן המנוחה מכסים אותו במכסה הזה. יש משהו מרגש בכלי שמנקה אחרים אך מכסה בשקט קודם כל את פיו שלו."},"ICON-0978":{"nm":"כיסוי כפתור תריס","de":"התריס שנלחץ מעצמו בתוך התיק ומצלם מאה תמונות של שמיים ריקים - כל אחד חווה את זה פעם אחת. הכיסוי הקטן הזה מעל הכפתור מונע את המאמץ המבוזבז ההוא. נעילה פעוטה, כדי לשמר רק את הרגעים שבאמת רוצים לשמר."},"ICON-0979":{"nm":"מדבקת סיווג סוללות","de":"תמיד יש בלבול כשהריקות והמלאות מתערבבות בכיס אחד. מדבקת צבע על כל סוללה מסדרת בשקט את המהומה הזו. אדום זה ריק, ירוק זה בטוח. רמזור שקט שדולק בסט הצילומים."},"ICON-0980":{"nm":"מחיצה לתיק מצלמה","de":"מחלקים את התיק לתאים כדי שהעדשה, הגוף וסוללת הרזרבה לא יתנגשו זה בזה. מעשה של הכנסת כמה חדרים קטנים לתוך משא אחד. לכל מקום יש בעלים משלו, כך שכלום לא מאבד את מקומו גם כשמנערים."},"ICON-0981":{"nm":"כפפת ריפוד לצילום","de":"צילומים בחוץ בחורף, שבהם רק קצה האצבע שלוחצת על התריס אסור לו לקפוא. כרית עבה בכף היד, כפפות ששומרות על תחושה בקצות האצבעות. פשרה עדינה של השטח, שאוחזת חום ודיוק יחד ביד אחת."},"ICON-0982":{"nm":"שפופרת ניבים לטאבלט","de":"שגם ניב עט נשחק כמו עופרת עיפרון, זה יודע מי שאחז זמן רב בטאבלט. השפופרת הקטנה הזו שבה מתגלגלים ניבים חלופיים דומה לקרן חירום של קצות האצבעות, שממלאת מראש קווים שאסור להם להיקטע."},"ICON-0983":{"nm":"מגש לכיסויי מקשים","de":"ביום שבו שלפו מקש אחר מקש, שטפו והרכיבו בחזרה, המגש הזה הפך לשטח בוץ קטן. המראה של עיצורים ותנועות שוכבים תא אחר תא ומתייבשים. יש תשומת לב שרואים רק אחרי שמפרקים משהו."},"ICON-0984":{"nm":"חבילת רגליות לעכבר","de":"הסוד שהעכבר גולש על השולחן כמו מחליק, טמון ברגליים הקטנות האלה שמודבקות לתחתיתו. חבילה שמחליפים כשהן משתפשפות. עמלם של דברים שנושאים בשקט את החלקלקות ממקום בלתי נראה."},"ICON-0985":{"nm":"כרית גומי למעמד מחשב נייד","de":"הוא דומה למחברת, אבל בעצם זהו כרית גומי שמרימה מחשב נייד. להרים את המסך מעט לגובה העיניים כדי ליישר צוואר כפוף. תשומת לב שמיישרת את היציבה, למען מי שכותב ומביט זמן רב."},"ICON-0986":{"nm":"מחליק כיסוי למצלמת רשת","de":"מזיזים אצבע כדי לכסות את העדשה, ומזיזים שוב כדי לפתוח. המשאלה להיראות רק כשרוצים להיראות. במחליק הקטן הזה שוכנת ההקלה הגדולה שנקראת פרטיות. קול הסגירה מרגיע איכשהו."},"ICON-0987":{"nm":"מדבקת סיווג ל-USB","de":"חמישה מקלות שחורים דומים, ואין שום דרך לדעת מה שמור באיזה. מדביקים תווית קטנה ונותנים שם, ורק אז הוא הופך לאחד מבני המשפחה. לדבר צריך שם כדי שיהיה קל למצוא אותו."},"ICON-0988":{"nm":"פינות למשטח שולחן","de":"כשפינות משטח השולחן ממשיכות להסתלסל, אפילו כתב היד נעשה עקום. החלקים הקטנים האלה שלוחצים בעדינות על ארבע הפינות שומרים על השלווה השטוחה שעל השולחן. המשטח חייב להיות שקט כדי שגם קצות האצבעות יהיו רגועים."},"ICON-0989":{"nm":"קליפס למעמד רכזת","de":"מהדק שמעמיד באלכסון בקצה השולחן רכזת שאליה מתאספים חוטים רבים. המראה של חוטים מבולגנים שמתכנסים ומסתדרים לנקודה אחת. הכישרון לאגד את המפוזר לגדיל אחד חי גם כאן."},"ICON-0990":{"nm":"מכסה לתרסיס ניקוי מסכים","de":"פקק קטן לפתח של תרסיס שמוחק טביעות אצבע ממסך. תמיד סוגרים אותו היטב כדי שהנוזל לא ידלוף או יתייבש. כדי לראות בבהירות, צריך קודם לחסוך באמצעי הניקוי עצמו - הסדר הצנוע של ניהול הבית."},"ICON-0991":{"nm":"ארנק לכרטיסי זיכרון","de":"כמה ימים של סרטוני במה ישנים בשקט בתוך כרטיס לא גדול מציפורן. אם מאבדים אותו, יום שלם נעלם כליל, ולכן אוספים אותו בחיבה לארנק קטן. בית ששומר את הזיכרון הקטן והגדול ביותר גם יחד."},"ICON-0992":{"nm":"תגית סימון לכונן חיצוני","de":"חמישה כוננים חיצוניים שחורים ישנים במגירה בפרצוף זהה. הפעולה של הדבקת תווית וקריאה להם 'אותו קיץ', 'קליפים לא יצאו'. מלאכה של חיבור אינדקס ברור לזיכרון מטושטש."},"ICON-0993":{"nm":"אסימון בדיקת גיבוי","de":"האם הגיבוי הושלם או לא - ההבדל הדק ההוא מכווץ את הלב. האסימון הקטן הזה שתוחבים במקום שהסתיים אומר 'עד כאן זה בטוח'. הביטחון מגיע מהשארת סימן מאחור."},"ICON-0994":{"nm":"אסימון תזכורת לענן","de":"אסימון ששולח שורת תזכורת אחת לצוף אל מחסן אי שם בשמיים. קסם קטן שבו, בכל מקום שמדליקים, אותה כתיבה יוצאת לקדם את פניך. שמי הלילה שבהם עפו עפיפון וכתבו משאלה, כמו יורדים עכשיו בעדינות אל כף היד."},"ICON-0995":{"nm":"סט מכסי מגן ל-USB","de":"כשהמחבר חשוף ומתגלגל בתוך התיק, המגעים עלולים להיפגע. עוטים כובע קטן על כל קצה ושומרים אותם כסט אחד. מעשה של הרדמת זמן הכי שקטה עבור החיבור הבא."},"ICON-0996":{"nm":"רצועה לנרתיק נתונים","de":"רצועה שעוטפת ומהדקת סביב מכשיר שמכיל נתונים יקרים. כורכים סיבוב אחד וקושרים חזק כדי שכלום לא יתנגש בתוך תיק מתנדנד. היד שקשרה פעם חבילה בתשומת לב חיה בדיוק כך גם בעולם הדיגיטלי."},"ICON-0997":{"nm":"תגית סידור קבצים","de":"כשמאות קבצים נערמים בלי שם, החיפוש עצמו הופך לתעייה. ברגע שמצמידים תגיות צבעוניות ופותחים ענפים, נסללת דרך בתוך הערימה המבולגנת. סידור הוא, בסופו של דבר, מלאכת סלילת דרך."},"ICON-0998":{"nm":"כרטיס רמז לסיסמה","de":"לכתוב סיסמה בשלמותה מסוכן, ולא לכתוב אותה כלל גורם לשכוח אותה. לכן משאירים רק רמז שרק אני מבין. כמו 'אותה עיר של ההופעה הראשונה'. דרך זכירה חכמה ועדינה שכותבת את הדרך, לא את התשובה."},"ICON-0999":{"nm":"מדבקת תאריך אחסון","de":"אם לא רושמים את היום שבו הכניסו, האחסון הופך במהרה לשִׁכחה. מדבקת תאריך על כל קופסה חורטת בבירור 'מאיזה מועד'. לב מחסן הישן שרשם את היום שבו נעשה משחת הסויה ממשיך לחיות על הנייר הקטן הזה."},"ICON-1000":{"nm":"מכסה למיני-פנס טבעתי","de":"מכסה שמכסה את חור האור של מנורה קטנה שמפיצה זוהר עגול. מרדימים את האור לרגע כדי שהעדשה לא תישרט בתוך התיק. גם לשמור בעדינות על החושך שלפני ההדלקה הוא דרך אחת לחסוך באור."},"ICON-1001":{"nm":"בורג הידוק למעמד","de":"עוד סיבוב אחד, רק עוד אחד. הרווח הרופף נעלם, וביטחון כבד שוקע מתחת לכף היד. מאחורי במה שאינה מתנדנדת תמיד מסתתר סיבוב זריז אחד של פרק כף יד של מישהו. מה שבורג קטן נושא הוא יציבות בלתי נראית."},"ICON-1002":{"nm":"שבב סימון בשידור","de":"ברגע שהאור האדום נדלק, צעדי המסדרון מתרוממים בשקט על קצות האצבעות. לפני המילים בשידור, כולם עוצרים את נשימתם. שאפילו הדממה שמעבר לדלת היא לב הפונה אל מישהו — זה מה שהשבב הקטן הזה מכריז בשקט."},"ICON-1003":{"nm":"פנקס פתקים לצ'אט","de":"לתפוס בקצות האצבעות את העידוד שהיה חולף על פני המסך. זמן שבו כל מילה שהייתה נעלמת נשארת, ברורה ומסודרת, על הנייר. לתעד הוא מקום שבו שוכנת העדינות של הרצון להגיע, ולו באיחור."},"ICON-1004":{"nm":"כיסוי מקלדת אילם","de":"שתיים לפנות בוקר, וקול הקשת המקשים נעלם כאילו בקסם. קרום דק אחד, כדי לא להעיר את נשימתה השלווה של השותפה לחדר הישנה. תשומת הלב השקטה ביותר תמיד מתחילה במקום חסר קול."},"ICON-1005":{"nm":"תפס לזרוע מיקרופון","de":"בין השפתיים למיקרופון, בדיוק המרחק שבו השיר אינו מתנדנד. הקליפס הקטן הזה מחזיק בהבטחה הזו חזק. מאחורי הקלעים תמיד מחכה כבר יד כזו, שהגיעה מראש כדי להחזיק הכול יציב."},"ICON-1006":{"nm":"מהדק בד רקע","de":"גם כשהרוח נושבת, בד הרקע אינו זע. כי לסת קטנה אחת, הנושכת בחוזקה בפינה, מחזיקה את כל הסצנה במקומה. מאחורי נוף שאינו מתנודד יש תמיד מישהו במקום נסתר, ששיניו חשוקות."},"ICON-1007":{"nm":"מדבקת תיוג לסטרים דק","de":"מעל עשרות כפתורים, תוויות שם קטנות שומרות על היד מלאבד את דרכה. שורת תווית אחת מוחקת מראש טעות אחת בשידור חי. קור רוח מגיע מהאותיות שנכתבו לפני שהרעד התחיל."},"ICON-1008":{"nm":"כפתור חותמת זמן","de":"לוחצים חזק, ודגל קטן ננעץ בזמן הזורם. פעולת ההטבעה של חותם על ה'עכשיו' שלעולם לא ישוב. כשמביטים אחורה זמן רב לאחר מכן, הסימן הזה הפך לדלת הנפתחת אל הזיכרון."},"ICON-1009":{"nm":"מחזיק מפתחות עם קורא תגים","de":"מקרבים אותו, ביפ, והמידע מתעורר. בן לוויה קטן התלוי על מחזיק המפתחות, מקשקש בכיס. יום רגיל ממשיך בשלום בזכות צלילי אות קטנים כאלה."},"ICON-1010":{"nm":"מדבקת שקע חכם","de":"כשמדביקים שם לכל שקע, כבר לא תועים לדעת איזה כבל שייך לאיזה. הלב שמעניק שם אפילו לחשמל הבלתי נראה. סדר הוא פנים אחרות שהעדינות שואלת ולובשת לרגע."},"ICON-1011":{"nm":"מעמד לחיישן טמפרטורה ולחות","de":"שומר בגודל כף יד, הצופה בשתיקה בטמפרטורה ובלחות של החדר. הנוחות אינה פותחת פה, אך המעמד הזה דואג בשקט למצבך בכל רגע. כך, בשקט, נשמר הרווחה."},"ICON-1012":{"nm":"כיסוי חיישן פתיחת דלת","de":"עין קטנה שאינה מפספסת את הרגע שבו הדלת נפתחת בעדינות. היא מעבירה בשקט את הסימן שמישהו חזר הביתה. מה ששומר על בית ריק הוא תמיד, כך, הדברים חסרי המילים."},"ICON-1013":{"nm":"מחזיק שלטים","de":"השלטים שהתגלגלו הנה והנה מוצאים סוף סוף מקום משלהם. פינה קטנה המחזיקה בעדינות את מה שכמעט אבד, יד החורטת מראש את ההבטחה להיפגש שוב."},"ICON-1014":{"nm":"אסימון אפליקציית שינה","de":"בכל לילה של שינה טובה, פרס עגול אחד מצטרף לערמה. גם השינה נאספת בהדרגה כמו תרגול, אומרת האפליקציה בעדינות. הפרס הקטן בעולם, מוגש לך על שנחת היטב."},"ICON-1015":{"nm":"בסיס לקוביית טיימר","de":"בעוד שלוש דקות זורמות בקצב יציב, הקובייה סופרת את זמנה ללא רעד. פינה אחת בגודל כף יד, התומכת בה בעדינות מלמטה. גם לציפייה יש צורך ברצפה שאפשר לדרוך עליה בראש שקט."},"ICON-1016":{"nm":"כיסוי נורת התראה","de":"כדי שלא יהיה בהיר מדי, הוא עוטף את האור בעדינות בשכבה אחת. שההתראה תהיה דחופה, אך שהעיניים לפחות ינוחו. תשומת לב היא לב המודד בשקט אפילו את עוצמת האור."},"ICON-1017":{"nm":"כרטיס החלפת סוללה","de":"כשהכרטיס הזה מופיע, זה אומר שהגיע הזמן להחליף את הלב הקטן שבתוך המכשיר. רמז עדין להקדים ולדאוג, לפני שהוא נעצר. הסוד לשותפות ארוכה טמון תמיד בערנות המקדימה בפעימה אחת."},"ICON-1018":{"nm":"סט כיפות לג'ויסטיק","de":"כובעים זעירים המולבשים בעדינות כדי שהאגודל לא יחליק. התחושה בקצות האצבעות מתבהרת עוד יותר. כובע קטן אחד זה יכול אפילו להכריע ניצחון או הפסד של סיבוב ששוחק בכפיים מיוזעות."},"ICON-1019":{"nm":"כיסוי לעריסת קונסולה","de":"הוא מכסה בעדינות את מקום המנוחה של הקונסולה מפני אבק. כי גם מכשיר הנח לישון לרגע זקוק לשמיכה אחת. לב אוהב מתגלה ביתר בהירות, למעשה, כשאין משתמשים בו."},"ICON-1020":{"nm":"נרתיק לקונסולה ניידת","de":"בכל תזוזה, בהחלט בפנים כאן. נרתיק העוטף בעדינות את הקונסולה הניידת בחיבוק רך. כדי שתישאר איתנה גם כשהיא נחבטת הנה והנה בתוך התיק, כדאי לעטוף את היקר עוד פעם אחת."},"ICON-1021":{"nm":"טבעת מדבקות לכפתורים","de":"מניחים רק ציור קטן אחד מעל כפתור פשוט, וברגע ההוא הוא הופך להיות כולו שלך. הפעולה של השארת סימן אישי מעל מכשיר זהה לכולם. האישיות תמיד פורחת בשקט ממקומות של מה בכך שכאלה."},"ICON-1022":{"nm":"קופסת מחסנית משחק","de":"משחק שאיבדת בו את עצמך כל הלילה נרדם בשלווה בתוך הקופסה הקטנה הזאת. פותחים את המכסה שוב, והלילה ההוא מתעורר שלם. זיכרונות, למרבה הפלא, לעיתים קרובות נשמרים בקופסה לא גדולה מכף יד."},"ICON-1023":{"nm":"מעמד למאוורר קירור","de":"בעוד הרוח מקררת את החום, פינה אחת המשעינה את המכשיר בזווית קלה. היא פותחת מקום לגוף שהתחמם לתפוס נשימה. כדי לרוץ רחוק, צריך גם לדעת לעצור לרגע ולהתקרר."},"ICON-1024":{"nm":"סיכת רצועת שורש כף יד","de":"עוטפים סביב שורש כף היד ומהדקים את הסיכה, ולא משנה כמה עז התנועה, השלט לא יעזוב את צדך. הרצועה הזו שנראית כמו מטרד היא למעשה הביטחון שמאפשר לך להשתולל בלב שקט."},"ICON-1025":{"nm":"כיסוי אחיזה אנלוגית","de":"מלבישים בגד חדש מעל אחיזה שהחליקה מרוב שימוש. משאירים את התחושה המוכרת ליד כפי שהיא, ורק את פני השטח כמו חדש. רגע שבו ההיכרות וריגוש קל שוכנים זה לצד זה בכף יד אחת."},"ICON-1026":{"nm":"מדבקת חריץ שמירה","de":"בכל חריץ שמירה כותבים בבירור של מי ההרפתקה. שורת תווית אחת שומרת בשתיקה על מסע הימים האחרונים. זיכרונות יקרים מוטב שיקבלו שם חקוק, כדי שלא יידרסו."},"ICON-1027":{"nm":"נרתיק למכשיר הקלטה","de":"מכונה השומרת קול הופכת ליקרה עוד יותר בזכות מה שיש בתוכה. נושאים אותה עטופה בעדינות בנרתיק רך המגן מפני חבטות. אולי קול של מישהו ישן שם בפנים, ולכן ביתר זהירות."},"ICON-1028":{"nm":"כיסוי רוח למיקרופון","de":"מסלק את קול הרוח ומשאיר רק את הקול. כיפה רכה המולבשת בעדינות על מיקרופון בהקלטות חוץ. מסננת קטנה הבוררת רק את הכנות מתוך הרעש הפרוע."},"ICON-1029":{"nm":"מדבקת תזכורת קולית","de":"זה מילות שיר שעלו בראש, זה מנגינה שזומזמה. מדביקים תווית צבעונית על כל תזכורת קולית. שברי ההשראה שהיו מפוזרים מכל עבר סוף סוף מוצאים את מקומם ונעמדים בשורה."},"ICON-1030":{"nm":"שבב כפתור דגימה","de":"לוחצים חזק, ופיסת קול ששמורה מראש קופצת החוצה. טיפת גשם, מחיאות כפיים, צחוק של מישהו — שברי עולם מתעוררים בקצה האצבע. מוזיקה היא המקהלה העדינה של שבבים קטנים כאלה."},"ICON-1031":{"nm":"מעטפת איסוף קולות","de":"אוספים בעדינות למעטפה הזו קולות שנתפסים בטעות תוך כדי הליכה. מרקם הרוח, ואפילו הדממה של סמטה בשחר. חומרים שיהפכו יום אחד לשיר תמיד נאספים בצניעות שכזו."},"ICON-1032":{"nm":"רגליים לחצובה מיני","de":"שלוש רגליים פורשות במה קטנה מעל השולחן. במקום יד רועדת, הן עומדות איתן ומחזיקות את הסצנה במקומה. צילום חד ובהיר נולד, לבסוף, משלוש רגליים העומדות דומם בשתיקה."},"ICON-1033":{"nm":"תגית קובץ הקלטה","de":"על מאות קבצי הקלטה מצמידים תווית קצרה אחת בכל פעם. כדי לדעת במבט אחד איזו השורה הראשונה שזרמה החוצה ובאיזה יום. ציון דרך קטן העוזר למצוא שוב קולות שהתפזרו."},"ICON-1034":{"nm":"סרט מדבקות גל קול","de":"סרט בדוגמת גלים, יצוק בדיוק לפי צורת הקול עצמה. עוטפים אותו סביב מחברת או נרתיק, וזה כמו שהמוזיקה נראית ממש לנגד עיניך. אשליה עדינה ההופכת את הנשמע לנראה."},"ICON-1035":{"nm":"וו לתלייה של אוזניות","de":"כשהתרגול מסתיים, הוא מכין בעדינות פינת מנוחה לאוזניות העייפות. וו קטן אחד, נעוץ בקצה השולחן. שולחן מסודר הוא מקום לתלות בו מראש את המרץ של מחר."},"ICON-1036":{"nm":"סרט למארז מתנה קטן","de":"הסיבוב האחרון סביב מותניה של קופסת מתנה. עם סרט אחד זה הלב סוף סוף שלם. הכנות מועברת לעיתים קרובות קודם כול מהיד המחליקה על החוץ, יותר מאשר ממה שיש בפנים."},"ICON-1037":{"nm":"כיסוי לקצה סרט","de":"עוטפים ומסיימים בעדינות את קצה הסרט כדי שלא יתפרם. פרט אחד שכמעט לא בולט לעין משנה בשקט את הרושם הראשון של מתנה. כשהסיום עדין, גם הלב מגיע בעדינות."},"ICON-1038":{"nm":"שעוות חותם לאריזה","de":"מטיפים טיפה חמה אחת כדי לחתום את המעטפה. כמו מכתב ישן, הבטחה כבדה אחת לא לפתוח בפזיזות. פורמליות לעיתים נושאת בתוכה משקל חם שכזה."},"ICON-1039":{"nm":"מעמד לכרטיס תודה","de":"הוא מעמיד ישר כרטיס הנושא מילות תודה, כדי שלא יתקמט. כדי שהלב יעמוד זקוף כשהוא מועבר. תודה נשארת בלב זמן רב יותר כשגם צורתה מסודרת."},"ICON-1040":{"nm":"נייר מילוי בצורת כוכבים","de":"פיסות נייר גזורות בצורת כוכבים ממלאות בעדינות רכה את הרווחים בקופסה. הצמר גפן של לב המאחל שדבר לא ייפגע גם כשמנערים. גם באפלת האריזה כוכב קטן אחד מרחף."},"ICON-1041":{"nm":"תווית רשימת מתנות","de":"לפני שדה שם המקבל, העט עוצר לזמן ארוך. הפנים שעולות בעודך כותב שם, העונות שעברו ביחד. ברגע שהיא נקשרת, הנייר הקטן הזה הופך לסוד שאיש לא יוכל לקרוא עד שייפתח."},"ICON-1042":{"nm":"טבעת חותמת ברכה","de":"לוחצים חזק, וברכה עגולה נדפסת בבירור. בעוד אתה מחכה את הרגע הקצר שהדיו מתייבשת, הלב המדמיין למי להעניק אותה הוא הכי חם. אם יש בכך פגם, זה שמתחשק לך להטביע עוד פעם אחת."},"ICON-1043":{"nm":"סליל חוט למארז מתנות","de":"כרוך בקפידה, ואז נפתח בעליזות בקצות אצבעותיו הנרגשות של מישהו. באותו רגע קצר של כריכה ופתיחה, לב אחד שהיה קשור לחוט הופך, סוף סוף, למתנה."},"ICON-1044":{"nm":"תליון קשר (לא פרח)","de":"לא חיקוי של פרח, אלא צורה שבה חוט בודד מחבק את עצמו שוב ושוב ופורח מעצמו. הסבלנות של קצות אצבעות שבררו קשרים כל הלילה נותרה כניצן קטן אחד כזה."},"ICON-1045":{"nm":"כיס מטבעות מזל","de":"הלב שהחליק כמה מטבעות לכיסו של מי שיוצא לדרך ארוכה. הפעולה של מילוי לא במשקל אלא בעדינות. הצליל המקשקש בכל צעד מחליף ברכה של דרך צלחה."},"ICON-1046":{"nm":"תליון קפסולת משאלה","de":"בתוך קליפה עגולה, משאלה מקופלת אחת ישנה בשלווה. שפתיחתה מגשימה אותה — זה שקר, אך שהחזקתה סגורה שומרת על המשאלה הזו חיה לנצח — זו האמת."},"ICON-1047":{"nm":"חוט קשר מגן","de":"חוט הסרוג בחוזקה מחמישה צבעים, המפנה אנרגיה רעה חזרה מאחוריך. כמו יד הסבתא שקשרה קשר סביב שורש כף היד בילדות, בכל מקום קשור מונחת בעדינות תפילתו של מישהו."},"ICON-1048":{"nm":"קופסה לעגור נייר קטן","de":"בית קטן השומר על עגור נייר אחד בלבד בבטחה, מתוך האלף שיש לקפל כדי שיהפוך למשאלה. כי אם אפילו כנף אחת מתקמטת, אותה מסירות שהושקעה באותו לילה מתפרקת בשקט."},"ICON-1049":{"nm":"נרתיק אבני נצנץ","de":"פירורי אור קטנים שנפלו מתלבושת במה, פינה לאסוף אליה את מה שאין לב לזרוק. אפילו הנצנוץ שפעם דבק ועקב אחריך שבוע שלם ישן כאן בצייתנות כמו על כף היד."},"ICON-1050":{"nm":"שבב חותמת סימן טוב","de":"אסימון קטן שמוסיפים בשקט בבחירת יום טוב. לא על סף בית קוסמת, אלא על שולחני שלי, פיסת אמונה תפלה עדינה שמטביעים בעדינות, ומאחלים רק דברים טובים ליום הזה בלבד."},"ICON-1051":{"nm":"כרטיס צמיד משאלה","de":"דף נייר בודד המודפס בצורת צמיד, נושא בתוכו משאלה שקטה של מישהו. גם אם אי אפשר להדק אותו סביב שורש כף היד, שים אותו עמוק בארנק, והלב הזה נשאר קשור לצדך, הולך איתך תמיד."},"ICON-1052":{"nm":"צנצנת מלח לפתח הבית","de":"מלח גס יוצק לצנצנת קטנה, מונח בעדינות ליד הדלת. חשבון עתיק המפנה אנרגיה רעה ומקבל רק אורחים אהובים. כל גרגר מלוח הוא שוער קטן השומר על ביתנו."},"ICON-1053":{"nm":"תווית כיסוי למספר מזל","de":"רגע לפני הגרידה, כולם זוכים לרגע. התווית הזו, המכסה בעדינות את המספר המנצח, שומרת על השנייה האחרונה שבה התקווה תופחת ביותר. גם אם אצבעות הגרידה רועדות, היא מעמידה פנים שלא שמה לב ועוצמת עיניים."},"ICON-1054":{"nm":"כיסוי שמירת נר יום הולדת","de":"לב מסודר קטן ששומר גם על נר שהודלק פעם אחת בטוח עד יום ההולדת הבא. אם המשאלה של שנה שעברה עדיין לא התגשמה, השנה אפשר פשוט להמשיך מאותה נקודה ולאחל שוב — חשבון עדין שכזה."},"ICON-1055":{"nm":"טבעת ספירה לאחור לאירוע","de":"דבר חצוף המחליק את יום ה-D אל האצבע. בכל פעם שמספר הימים שנותרו יורד בסימן אחד, גם הלב נמשך קדימה באותה מידה. היא מתעקשת, לגמרי לבד, שתאיר כשתגיע ל-0."},"ICON-1056":{"nm":"רצועה לכובע מסיבה","de":"רצועה דקה המחזיקה את כובע המסיבה חזק על הראש. חוגג יום ההולדת עצמו מתלונן עד מהרה שזה מציק ומוריד אותו, אך בתמונה הצילום ההוא משאיר אותו על הראש לנצח. זו משימה מספיקה."},"ICON-1057":{"nm":"פיק קטן לעוגה","de":"סימן קטן נעוץ בעוגה בגודל שני פרקי אצבע. גם מעל מתיקות שנעלמת בביס אחד, החגיגה עומדת זקופה. גם אם קטנה, יום הולדת הוא יום הולדת, וכוכבת היום היא את."},"ICON-1058":{"nm":"מדבקת קונפטי חגיגי","de":"קונפטי נייר שאינו משמיע פצפוץ אך נראה הכי מרהיב מכולם. ברגע שהוא נדבק, דואר רגיל הופך למכתב שהגיע ממסיבה. הרבה אנשים משאירים אותו, לא מוכנים לקלף אותו."},"ICON-1059":{"nm":"תפס לתליית תמונות","de":"פוחד לאבד את הזיכרונות התלויים על החוט, אני תמיד שומר על פי סגור היטב. כל עוד תמונה אחת אחוזה בלסתי, אפילו הרוח הנכנסת דרך סדק החלון לא תוכל להפיל את הימים ההם."},"ICON-1060":{"nm":"טלאי בלון עם תאריך","de":"טלאי בצורת בלון עם מספר עליו. מדביקים אותו על הבגד, וכל השכונה יודעת איזה יום מיוחד הוא היום. מקלפים אותו ונשאר סימן, ואפילו הסימן העמום הזה הופך למזכרת נוספת."},"ICON-1061":{"nm":"סימון החלפת מתנות","de":"סימן שובבי המבלבל בעדינות בין היד שקיבלה ליד שנתנה. חוק קטן ועדין של שולחן חילופי המתנות, המבקש לזכור לא כל כך מי נתן, אלא מה עבר ביניכם."},"ICON-1062":{"nm":"מספר שולחן לאירוע","de":"מספר קטן שמעמידים על כל שולחן חגיגה. קביעה מראש של מי יושב איפה כדי שאיש לא ירגיש לא בנוח, נושאת בתוכה את החוכמה החמה של אנשים שערכו לא מעט חגיגות."},"ICON-1063":{"nm":"שקית מתנה לידית הדלת","de":"דרך להעביר לב בלי לצלצל בפעמון. תולים אותה בערמומיות בידית הדלת ונעלמים כמו בורח, והפנים המופתעות של מי שמוצא אותה הופכות למתנה הגדולה ביותר שחוזרת אל הנותן."},"ICON-1064":{"nm":"מדבקת משלוח סודי","de":"שום דבר לא כתוב על פניה. להסתיר מי שלח עד הסוף היא הגאווה הקטנה של התווית הזו. ככל שהמקבל מטה את ראשו ומחייך זמן רב יותר, כך המשימה הסודית שלה מושלמת יותר."},"ICON-1065":{"nm":"שבב פתק לפעמון","de":"פתק קטן שמדביקים במקום כשאין אומץ לדפוק בדלת. שורה קצרה כמו “עברתי לרגע” נשארת זמן רב יותר מצלצול פעמון. כי לכתב יד עקום יש הבעה משלו."},"ICON-1066":{"nm":"כיסוי בטיחות לסכין קרטונים","de":"כשלהב סכין הקרטונים מכוון בהיסח דעת לעבר האצבע, גיבור קטן חוסם בשקט את הדרך. הוא שומר בבטחה על קצות האצבעות, שממהרות מרוב התרגשות לדבר החדש, עד לחיתוך האחרון."},"ICON-1067":{"nm":"פיסת ניילון בועות","de":"נולדתי כדי שילחצו עליי. עם פצפוץ קטן ההוא, המתח של היום מתפוגג איכשהו. יש גם ימים שבהם אוהבים אותי זמן רב יותר מאשר את הדבר עצמו שהייתי עוטף."},"ICON-1068":{"nm":"סיכת שעת הגעה","de":"סיכה המציינת בדיוק באיזו שעה זה יגיע. גם המתנה המעורפלת נעשית נסבלת יותר ברגע שיש לה קואורדינטה אחת. כמה פעמים תציץ החוצה מדלת הכניסה עד אז, זה כולו עניינך."},"ICON-1069":{"nm":"מחזיק מפתחות לתא חבילות","de":"בן לוויה קטן למי ששוכח כל הזמן את קוד תא החבילות. הוא נדלה על מחזיק המפתחות, ומתמחה בשקט בהוצאת “אה, נכון” ברגע המכריע."},"ICON-1070":{"nm":"תווית סל כניסה","de":"תווית שם על הסל בפינת הכניסה. עליה כתובה ההבטחה חסרת המילים, “השאירו כאן”. גם כשהוא ריק, מקום המחכה ללב של מישהו לעולם אינו בודד."},"ICON-1071":{"nm":"מדבקת הסתרת כתובת","de":"על קופסה שזורקים, משאירים את השם אך מוחקים את הכתובת. השם בסדר שכולם ידעו, המקום שבו גרים נשאר סוד שלי בלבד. ברגע שמקלפים ומדביקים שכבה אחת זו, נולד שקט נפשי קטן."},"ICON-1072":{"nm":"מדבקת קופסת חטיפים","de":"תווית המספרת במבט אחד מה יש בתוך הקופסה. אבל הקאץ' הוא שכתיבת 'חטיפים' משום מה מרגיעה אפילו בלי לפתוח את המכסה. התווית לא אחראית על התיאבון, עם זאת."},"ICON-1073":{"nm":"תליון שרשרת קטן","de":"גרעין קטן החולק בשקט חום גוף מתחת לבגדים. תמיד נוגע במקום שאיש לא רואה, ודווקא בגלל זה יקר יותר. החבר הקרוב ביותר, ההולך יחד לצד החזה."},"ICON-1074":{"nm":"מזרן חותמת טביעות רגליים","de":"לוחצים על כף הרגל, ושורת טביעות רגליים קטנות נשארת מאחור. יומן טיולים יומי, הרושם בבירור על נייר מי הלך לאן. הצעד הראשון המוכתם בדיו תמיד הכי ברור."},"ICON-1075":{"nm":"כיסוי מברשת פרווה","de":"כיסוי קטן המטפל בקפידה בפרווה שהסתבכה במברשת. בעונת נשירת השיער, כשמברשת אחת אוספת מלוא חופן, בלי הכיסוי הזה כל הבית היה הופך לשדה שלג פרוותי. מנקה חרוצה שלא מרעישה."},"ICON-1076":{"nm":"נרתיק שקיות לטיול","de":"בית קטן הנושא בסדר את השקיות הדרושות לטיול. הנרתיק הזה מוכיח בשקט כל יום שרק מי שהתכונן מראש הולך בנחת. אותו פריט אחד שבלעדיו תסתבך."},"ICON-1077":{"nm":"תווית הסתרת שם","de":"תווית המסתירה בערמומיות את השם האמיתי ומשאירה רק את הכינוי. בעולם הזה יש גם סוג של עדינות שלא בא לך להראות לכל אחד. אותה קריאה מיוחדת, שרק מי שיודע — יודע, מתחבאת כאן בעדינות."},"ICON-1078":{"nm":"משטח לקערת מים","de":"מונח מתחת לקערת המים, אני תמיד לח. תופס במקומם את טיפות המים המתיזות לכל הכיוונים, ושומר על רצפת העץ יבשה. איש לא משבח אותי, אבל גם אני לא מתלונן."},"ICON-1079":{"nm":"חוט תיקון לצעצועים","de":"בובה עם תפר שנפתח לא נזרקת, אלא נתפרת מחדש. בכל מקום שממלאים תפר אחר תפר, הזמן שהושקע עם הילד ההוא מתחזק שוב. תיקון הוא, בסופו של דבר, דחיית פרידה בעדינות."},"ICON-1080":{"nm":"שרשרת תמונת מזכרת","de":"הלב שנושא על הצוואר את הצילום המחייך ביותר. במקום להיות מוקפא בתמונה, אותו יום מתנדנד יחד עם כל צעד ומגיע עד היום הזה. הרגע הטוב ההוא אינו נעצר."},"ICON-1081":{"nm":"שבב צבע מצב רוח","de":"אם גם ללב היו גוונים, איזה צבע היה שלך היום? ברגע שבוחרים שבב אחד ומניחים אותו על השולחן, הרגשות שהמילים לא הצליחו לבטא במלואן מתפשטים בשקט. גם אור שקיעה וגם אור שחר טובים — זו מראה קטנה המשקפת בעדינות את מי שאת היום הזה."},"ICON-1082":{"nm":"כדור זיכרון יומי","de":"כשהיום שוקע, היום מתעגל בתוך הכדור. גם הדברים שהצליחו וגם הדברים שנעשו במגושם נאספים ומתגלגלים יחד. מניחים אותו על כף היד, ואתמול שלך מרגיש קצת חם, מטפח את גבך, אומר לך שהיית טוב גם היום."},"ICON-1083":{"nm":"צנצנת פתקי מחמאות","de":"מילים טובות מתפזרות בקלות רבה מדי, ולכן מקפלים אותן אחת אחת לתוך הצנצנת הזו. כשהמחמאות מצטברות כמו קטורת, פותחים את המכסה בלילות שבהם הלב חלול. מוציאים שוב פיסת חום שמישהו העניק וקוראים אותה, וחום אותו יום שב לחיים."},"ICON-1084":{"nm":"חוט סרט פיוס","de":"לב מסובך דומה לקשר; גם לפתוח אותו דורש קפידה. כששני אנשים אוחזים בשני קצות החוט ומושכים לאט, לפתע נוצר סרט יפה. פיוס אינו לחתוך אלא לקשור מחדש, החוט הזה אומר בשקט."},"ICON-1085":{"nm":"אסימון תודה","de":"בימים שבהם 'תודה' לא רוצה לצאת מהפה, מעניקים במקום זאת אסימון אחד בעדינות. היד המקבלת קוראת את כל הלב מהמשקל הקטן הזה. כנות המגיעה לפני המילים — חיבה נישאת בחרוז עגול אחד."},"ICON-1086":{"nm":"תווית זמן הפסקה","de":"גם לחדר חזרות שרץ כל היום זקוק לפעימה אחת לתפוס נשימה. תולים את הסימון הזה על הדלת, והזמן מאט לרגע. שצריך הפסקה כדי שהשיר יוכל לנשום, כל מי שחי יום בלי נשימה יודע."},"ICON-1087":{"nm":"מגירת רגשות סודית","de":"יש ימים שבהם אי אפשר להוציא הכול מהלב. בימים כאלה, שמים בעדינות עצב וריגוש כאחד במגירה קטנה בתוך התודעה וסוגרים אותה. מותר להשאיר אותם כרגע, כי יבוא יום לפתוח לאט ולסדר הכול."},"ICON-1088":{"nm":"גליל מדבקות חיוך","de":"מקלפים משבצת אחת, וסימן חיוך נדבק לקצה האצבע. עליזות קטנה שמדביקים בעדינות בפינת מחברת או בארונית של חבר. כששמש קטנה זורחת על הנייר, היום של מי שמוצא אותה מתבהר קצת."},"ICON-1089":{"nm":"תליון פעמון דרישת שלום","de":"הרצון להגיע אליך מרחוק התגבש לפעמון אחד. מנערים אותו וצליל צלול נושא במקומך את דרישת השלום. בימים שלא הצלחת לשאול 'מה שלומך' — הצלצול הקטן הזה רוכב על הרוח ומגיע אליך ראשון."},"ICON-1090":{"nm":"סיכת כיסוי לגשם אביבי","de":"בימי גשם אביביים, הדברים היקרים ביותר הם אלה שמתרטבים בקלות הרבה ביותר. סוגרים את הכריכה עם הסיכה הזו וטיפות הגשם נשפכות הצידה. הלב של חיבוק ספר יקר אחד קרוב אל הגוף — סיכה קטנה אחת ממלאת מקום העדינות הזו."},"ICON-1091":{"nm":"מדבקת קירור קיץ","de":"לחיצה מהירה אחת על גב יד עייפה מחום הקיץ הלוהט. תחושת קרירות מתפשטת כמו מנטה והזיעה נרגעת מעט. הקרירות של השכיבה על מרפסת העץ תוך כדי הנפת מניפה, מחוקה במסירות על ידי דף נייר בגודל כף יד."},"ICON-1092":{"nm":"פיסת בד משובץ סתווי","de":"פיסת בד משובץ הדומה לשדה סתווי. זהו סימן של מישהו שטיפל בקפידה במקום בלוי. הלב שמתקן במקום לזרוק — בדים קטנים מתאספים ומחיים מחדש בחום את מה שהתבלה."},"ICON-1093":{"nm":"תפס כפפות חורף","de":"כפפות חורף איכשהו כל הזמן בורחות, אחת בכל פעם. מחברים את הזוג עם התפס הזה וידיים קפואות לא תאבדנה את דרכן. הרצון לא לאבד אותן שוכן בפיסת מתכת קטנה, שומרת על שתי הכפפות זו לצד זו."},"ICON-1094":{"nm":"תווית עמידה במים לעונת הגשמים","de":"בעונת הגשמים אפילו תווית שם מיטשטשת בגשם. התווית העמידה במים הזו שומרת על הכתב שלה גם תחת גשם שוטף. שורה אחת שנשארת ברורה גם אחרי שהגשם נפסק — כדי שמי הבעלים לא יישכח עד הסוף."},"ICON-1095":{"nm":"צנצנת שימור שלג ראשון","de":"השלג הראשון נעלם ברגע שנוגע בו, ולכן שמרת לפחות את הריגוש בצנצנת. מה שכלוא בזכוכית אינו שלג אלא הלב שפעם בהתרגשות באותו יום. מנערים, וחורף שלם מתעופף שוב, לוקח אותך חזרה לאותו בוקר."},"ICON-1096":{"nm":"סרט למעטפת חג","de":"סרט אדום אחד העוטף מעטפת חג. כולם יודעים שהחיבה שביד הנותנת גדולה יותר ממה שבפנים. הלב העוטף ברכות יחד עם איחולי בריאות טובה קשור בעדינות בתוך הסרט הדק הזה."},"ICON-1097":{"nm":"רצועה לכלי פיקניק","de":"פורשים את השטיח ופותחים את ארוחת הצהריים, והרוח ממשיכה להרים את המכסים. מהדקים את הכלים היטב עם הרצועה הזו והפיקניק לא מתפרק. הלב ששומר על ארוחה שנארזה עד הסוף מוחזק ברצועה קטנה אחת."},"ICON-1098":{"nm":"כרטיס דוגמת ריח עונתי","de":"כדי שתדע את העונה בלי אפילו לפתוח, ריח אותה תקופת שנה מוחזק בכרטיס בודד. פרחים באביב, ריח עלים יבשים בסתיו. ברגע שהוא נוגע באף, כל העונה שבה — “זה אוויר אפריל”."},"ICON-1099":{"nm":"לוח קליפ לתגי מחיר","de":"את כאב הראש של הדוכן, שתגי המחיר ממשיכים לעוף, לוח קליפ אחד זה השקיט אחת ולתמיד. הוא נושך היטב את המספרים ומציג אותם ישר מול הלקוח. ברכת הפתיחה של המסחר מתחילה בשורה כנה אחת שלא סוטה מדרכה."},"ICON-1100":{"nm":"לוח היפוך פתוח","de":"הופכים את הלוח הזה ותולים אותו על הדלת, והחנות מתעוררת סוף סוף. מ“בהכנות” ל“ברוכים הבאים”. אות קטן המבשר את תחילת היום — המקום שיד הבעלים נוגעת בו ראשון בכל בוקר."},"ICON-1101":{"nm":"כרטיסיית חותמות נאמנות","de":"כשממלאים את כל עשרת המשבצות, קורה משהו טוב, איכשהו. כל חותמת היא צעד של לקוח קבוע, חיבה שהצטברה עם הזמן. בכל סימן שנלחץ עד שהדיו התייבש, חיה ונושמת הבטחה קטנה לשוב."},"ICON-1102":{"nm":"מגן לידית שקית נייר","de":"ידית של שקית נייר תמיד חלשה מול המשקל. כשמחליקים עליה את המגן הזה, החוט שכמעט נקרע הופך יציב. הרצון לשאת את מה שבפנים הביתה בשלום, אביזר קטן שתומך במסע הזה עד סופו."},"ICON-1103":{"nm":"מגש מטבעות לקופה","de":"המגש הזה מקל בשקט על ההיסוס שבהעברת עודף מיד ליד. קול המטבעות המקשקש בדרכם למקומם. ההענקה והקבלה נעשות חמות יותר בזכות אדיבות עגולה קטנה כזו."},"ICON-1104":{"nm":"אסימון צבירת נקודות","de":"הצעדים של היום נערמים בסדר בתוך אסימון אחד. חשבון מוזר שבו ככל שאוספים יותר, הלב מרגיש קל יותר. השמחה שבמילוי הדרגתי דומה לעונג שבצפייה בכד ריק מתמלא לפתע."},"ICON-1105":{"nm":"סיכת מספר למדף","de":"על כל מדף נעוצה בחיבה מספרה קטנה. מדריך שקט שמספר לך היכן נמצא הכול. הלב שמסמן את המקום מראש כדי שלא תתעה, אפילו לסדר יכולה להיות חמימות כזו."},"ICON-1106":{"nm":"כוסית שיפוד לטעימה","de":"כוסית קטנה שמושיטה ביס לטעימה. גם לקוח מהסס פותח בעדינות את לבו לנגיסה הזאת. הנדיבות שבהזמנה \"טעמו קצת\" תלויה בקצה השיפוד, ועוצרת את צעדיו של מי שבא לראשונה."},"ICON-1107":{"nm":"מעמד לרשימת הזמנות","de":"שמות האורחים של היום עומדים מסודרים במעמד הזה. הבטחה עדינה שגם להמתנה יש תור. להעמיד דף נייר אחד זקוף הופך להכנה הראשונה, המכוונת בקפידה, לקבל את פניו של יום מישהו."},"ICON-1108":{"nm":"אטבים לחוט תמונות קיר","de":"מותחים חוט על הקיר ותולים עליו תמונות אחת אחת באטבים. רגעים של חיוך תלויים זה לצד זה ומתייבשים כמו כביסה. תולים את הזיכרונות במקום שהשמש מגיעה אליו, ובכל פעם שעוברים שם, הצחוק של אותו יום מתנפנף שוב."},"ICON-1109":{"nm":"פינת שטיחון קטן","de":"שטיחון קטן פרוש בקצה החדר. פינה שפורשת חום ראשונה על הרצפה הקרה. הטפח הראשון שנוגעות בו כפות רגליים יחפות, שבו קצות האצבעות של מי ששב הביתה נרגעים סוף סוף ומתעייפים לתוך שלווה."},"ICON-1110":{"nm":"בד הסתרה לשלט השם","de":"יריעת בד המכסה בעדינות את שלט השם. להסתיר את השם לזמן מה הוא סוג משלו של אלגנטיות ביתית. וילון נאה על גבול שבין פנים לחוץ, תלוי ברכות עם הרצון לנוח בשקט היום."},"ICON-1111":{"nm":"קליפס לחוט תאורה","de":"הקליפס הזה אוחז בסדר בחוט תאורה משתלשל. יד שמיישרת את הדרך כדי שהאור לא יתפזר. ליישר חוט מבולגן אחד עם רדת הערב, והאור בחדר, וגם הלב, נרגעים יותר."},"ICON-1112":{"nm":"מגנט לתליית פוסטרים","de":"מגנט קטן להדבקת פוסטר על הקיר. הנייר שומר על מקומו בלי לנקב ולו חור נעץ אחד. היד שנוגעת במה שהיא מוקירה תמיד עדינה, ובזה טמון הרצון לשמור עליו שלם."},"ICON-1113":{"nm":"חבל גדילים לווילון","de":"חבל גדילים שקושר את שולי הווילון הצידה. הוא פותח דרך נאה לאור השמש של הבוקר להיכנס. משיכה אחת בחוט המגודל, ויום בהיר גועש אל תוך החדר ונשאר בו."},"ICON-1114":{"nm":"מדבקה למעמד נר ריח","de":"מדבקה קטנה המודבקת על מעמד לנר ריח. היא רושמת בקפידה איזה ריח נשרף ומתי הודלק לראשונה. להעניק שם לניחוח אהוב, הסדר הזה הופך את האוויר בחדר לעדין עוד יותר."},"ICON-1115":{"nm":"רגליות גומי למדף תצוגה","de":"ארבע רגליות גומי התומכות במדף כדי שלא יתנדנד. ממקום בלתי נראה הן נושאות את המשקל בשתיקה. קטנות ונמוכות וקל להתעלם מהן, אך מה שמחזיק מעמד הכי נמוך הוא בסופו של דבר מה שמחזיק הכי הרבה זמן."},"ICON-1116":{"nm":"תליון חץ שילוט כיוונים","de":"למען מי שמהסס לאיזה כיוון ללכת, חץ אחד מצביע בשקט על הדרך. תנועת יד עדינה שאומרת, אל תאבד את דרכך. הודות ללב שמישהו הציב מראש בכל פיצול דרך, גם היום ממשיכים הלאה בלי לתעות."},"ICON-1117":{"nm":"חבל מפתח הזמנה לאי","de":"חבל מפתח שמונח בידו של מי שמזמין אותך לאי. קח אותו, ומעכשיו גם אתה בן משפחה כאן. ההכנסת אורח הזר לתוך החום הפנימי מוחזקת בחוזקה בהבטחה הקטנה התלויה בקצה החבל."},"ICON-1118":{"nm":"אסימון מדיד קרבה","de":"אסימון אחד מגלה לך בערמומיות את הטמפרטורה בין שני אנשים. אם היא עדיין כחול מביך או כבר הפכה לארגמן חם. את המהירות שבה הקרבה מעמיקה קשה למדוד, אך כף היד חשה את החום הזה ראשונה."},"ICON-1119":{"nm":"קופסת דגימות טעם אישי","de":"כשעדיין לא יודעים מה מישהו אוהב, אוספים דגימות קטנות לתוך קופסה אחת ומעניקים אותה. בתוך שמחת הבחירה, טעם אישי צומח לאט. איזו מהן תהיה שלך, הקופסה מלאה באפשרות מרגשת."},"ICON-1120":{"nm":"סיכת תור לטיפול","de":"ההבטחה לדאוג למישהו נעוצה בבירור בסיכה קטנה זו. רושמים את השם והשעה, והלב לא מאבד את דרכו. אותה עזרה הדדית ומתחלפת בשמירה על ילדיהם זה של זה, חיה ונושמת ממש כאן."},"ICON-1121":{"nm":"קפסולת תיעוד גדילה","de":"כמו שסימוני גובה נערמים קו אחר קו על מזוזת הדלת, הקפסולה הזו אוטמת בשקט את מי שהיית אתמול. פתחו את המכסה בעתיד הרחוק ותדעו, כמה רחוק צעדו אותם צעדים קטנים."},"ICON-1122":{"nm":"סרט זיכרון למפגש ראשון","de":"הרעד של אחיזת ידיים ראשונה קשור בעדינות בסרט אחד. הקשר לא נועד להתרה, אלא נשאר שם כדי לשמר את חום אותו היום חי על פרק היד."},"ICON-1123":{"nm":"מדבקת חפצי החדר שלי","de":"\"כאן המקום שלי.\" ברגע שמדבקה קטנה נדבקת בפינת השולחן, החדר הזר סוף סוף נושם ונעשה לחדר שלי. תווית שם היא המקום הראשון שבו הלב שוקע למנוחה."},"ICON-1124":{"nm":"צנצנת חרוזי קרבה","de":"מנערים אותה, וקול הצטרפותם של שניים לצעד קרוב יותר מתגלגל בפנים. עד שהצנצנת תתמלא עד השוליים, סתם קריאה בשם יגרום לצחוק לצאת ולקדם את פנייך."},"ICON-1125":{"nm":"מדבקת חותם הכנה להופעת בכורה","de":"הדף האחרון שסוגר את המעטפה. עד כאן ההכנה, בעמוד הבא כבר הבמה. בלוחצו עליו בקצה האצבע, המתלמד מיישר את נשימתו. סוף סוף, זו ההתחלה."},"ICON-1126":{"nm":"מים","de":"הנפוצים ביותר, ולכן היקרים ביותר. באולם חזרות בשעת שחר, כשהאורות כבויים, לגימה אחת בלבד מקימה מחדש מי שקרס. עדינות חסרת צורה משלה, החודרת אל כל כלי."},"ICON-1127":{"nm":"מים צלולים","de":"שקיפות שמאירה בבהירות אפילו את החלוקים שבתחתית. מעיין הררי לעולם אינו מתפאר בצלילותו שלו. לב שאין לו מה להסתיר תמיד נראה כך, עד לתחתית ממש."},"ICON-1128":{"nm":"מי ים","de":"ברגע שהוא נוגע בקצה הלשון, גלים רחוקים מגיעים בהמולה. בלגימה מלוחה אחת נמסים שלמים האופק והשחפים והנמל שהושאר מאחור. הים תמיד נשאר בזיכרון בטעם מלוח."},"ICON-1129":{"nm":"קרח","de":"הוא מתכווץ על כף היד, נעלם ככל שאוחזים בו. קשיח כמראהו, הוא יודע שבסוף ישוב להיות מים. קרח הוא נהר שעצר לרגע את נשימתו."},"ICON-1130":{"nm":"כדור שלג","de":"גוש אחד שנלחץ היטב טס לבן וחוצה את הסמטה. צחוק מתגלגל ולחיים אדומות מקור. הצעצוע הכי לבן שהחורף מבריח בחשאי לידיהם של הילדים."},"ICON-1131":{"nm":"אדמה","de":"היא חובקת זרעים, שותה גשם, וקולטת בשתיקה צעדים חולפים. עור שחור המחבק הכול. במקום הראשון של כל מה שצומח, נמצא חופן זה."},"ICON-1132":{"nm":"אדמה פורייה","de":"תוחבים אצבעות פנימה, ושומן שחור עוטף אותן ברכות. הסוד מאחורי הגינה הירוקה של הסבתא מדי שנה היה כאן, ממש כאן. אדמה מיושנת היטב לוחשת על יבול עשיר בריח הזבל שלה."},"ICON-1133":{"nm":"חמר","de":"ברגע שהוא סופג לחות, הוא מקבל בציות כל צורה שהיא. בשר עדין ההופך לציפור, ההופך לקערה, בעקבות הנגיעה. בעוד האובניים סובבים, חופן אדמה חולם סוף סוף חלום."},"ICON-1134":{"nm":"חול","de":"גרגרים דקים המחלחלים בין האצבעות. ככל שאוחזים בהם חזק יותר, כך הם נשפכים מהר יותר, ותמיד דומים לזמן. בחופן אחד של חוף רדומים אינספור אתמולים."},"ICON-1135":{"nm":"חלוקי נחל","de":"אבנים שנשחקו לעגול ליד הפלג. הן העקבה של מים שליטפו זמן רב עד שהפינות החדות נעלמו. ככל שהתגלגלה רחוק יותר, כך היא מתכרבלת עדין יותר בכף היד."},"ICON-1136":{"nm":"אבן","de":"גוש המונח באדישות בצד הדרך. מישהו בועט בו במעבר, מישהו אחר מרים אותו בשקט לבנות מגדל. אותה אבן ממש הופכת למשא או למשאלה, בהתאם ללב."},"ICON-1137":{"nm":"אבן ריצוף","de":"אבן שטוחה ורחבה החוצה חצר ארמון עתיק. מאות שנות נעליים שדרכו עליה שחקו שקע במרכזה. כל אדם שדורך עליה, צעד אחר צעד, מוסיף לה עוד שכבת זמן."},"ICON-1138":{"nm":"אבן גיר","de":"הצדפות מימי היותה ים התקשו שכבה על שכבה לאבן לבנה. הכניסו אותה לכבשן והיא נמסה לסיד, צובעת חומות בלובן צח. שלווה למראה, אך זו אבן שחובקת בתוכה עידן שלם."},"ICON-1139":{"nm":"פחם","de":"יער עתיק ששקע לתרדמה שחורה. שרכים מלפני מאות מיליוני שנים, שנקרשו איתן עמוק באדמה. הציתו אותו, ואור השמש שנטמן זמן כה רב מתעורר שוב בלהבות."},"ICON-1140":{"nm":"פחם עץ","de":"הוא סופג את האש אך בולע את העשן בשקט. עץ שנדחס לשחור בתוך הכבשן פורח באודם ללא מילה מעל האח. ככל שהדבר שקט יותר, כך הוא נשאר חם זמן ארוך יותר."},"ICON-1141":{"nm":"ענף","de":"ענף שהתכופף בשתיקה במקום להישבר יודע את דרכה של הכניעה. בכל מקום ששרד רוח קשה נוצר קשר עץ, וקשיחות אמיתית היא, בסופו של דבר, סימנה של כפיפות מוצלחת."},"ICON-1142":{"nm":"בול עץ","de":"בתוך טבעותיו הכרותות, מאה אביבים וחורפים ערוכים עגולים זה על גבי זה. השנים שחי עץ בודד שוכבות כאן שלמות, וממתינות בשקט לתורן להפוך לעמוד של בית."},"ICON-1143":{"nm":"קרשי עץ","de":"בכל מעבר של המקצועה נחשף סיב ריחני, שכבה אחר שכבה. בעוד העץ המחוספס הופך חלק, נסורת נערמת על הרצפה כמו שלג צהוב. היד המלטשת מעוררת את התועלת שבו."},"ICON-1144":{"nm":"לוח עץ","de":"הוא מרצף אולם, בונה ספסל, מקיף גדר. כשהקרשים המנוסרים ישר נאספים, אחד אחד, מקום למגורי אדם קם סוף סוף. דברים פשוטים נערמים והופכים לבית."},"ICON-1145":{"nm":"במבוק","de":"חלול מבפנים, ובכל זאת זקוף מול הרוח. חכמי הקדם ייחלו להידמות לנחישותו, הנקטע בכל פרק ונובט מחדש. כאן ניצב דבר זקוף עוד יותר בשל היותו ריק."},"ICON-1146":{"nm":"פקק שעם","de":"לוחצים ומשחררים, והוא תופח חזרה לעוביו המקורי. במרקם הזה, קל ועם זאת עקשן, לומדים שרכות אינה בהכרח חולשה. מפקקי בקבוקים ועד לוחות מודעות, הוא תומך בשקט."},"ICON-1147":{"nm":"עשב","de":"נרמס, והוא קם שוב עם הגשם הבא. עקשנות ירוקה המכסה שדה שלם בלי שם אחד משלה. אל תזלזלו בקוטנו, מי שמבשר את האביב ראשון תמיד הוא המקום הנמוך הזה."},"ICON-1148":{"nm":"קש","de":"מה שנשאר צהוב בשדה אחרי קציר הסתיו. קלוע, הוא הופך לגג; פרוש, הוא הופך למשכב חם. הלב שגם אחרי שנתן כל גרגר, ממשיך לכסות אנשים עד הסוף."},"ICON-1149":{"nm":"קנה סוף","de":"כשהרוח נוגעת בו, רשרוש רשרוש, כל גדת הנהר שרה כאחת. גבעול שחלול מבפנים בוכה עוד רחוק יותר. שקנה הסוף לא מתבייש כלל שעצם התנודדות שלו היא שירתו."},"ICON-1150":{"nm":"כותנה","de":"כשהתרמיל הבשל נפתח בפצפוץ, פורח פרח ענן קטן. הפלומה הקלה והרכה הזו הופכת לחוט ולבד, ומחממת בעדינות את כתפיו של מישהו בליל חורף קר."},"ICON-1151":{"nm":"צמר כבשים","de":"מרחו אותו על היד, ושמנוניות נותרת ונשארת בשקט חמימות. המעיל שהכבשה עטפה על גופה כדי לשרוד את ההרים הקרים. אותה חמימות שנגזזה עוברת עכשיו אל חורפו של אדם."},"ICON-1152":{"nm":"חוט","de":"דק כמעט עד להיעלמות, זהו תמיד מה שמחבר מחדש שני קצוות שנפרדו. חלש כגדיל בודד, אך שזור הוא הופך לבד שלם. בעבודת החיבור, העובי אינו חשוב."},"ICON-1153":{"nm":"בד","de":"ערב ושתי חוצים זה את זה אינספור פעמים כדי ליצור יריעה אחת. זו התוצאה של חוטים שהיו נפרמים לבדם, האוחזים חזק זה בזה. שככל שהאריגה צפופה יותר כך היא חמה יותר, נכון גם בין אנשים."},"ICON-1154":{"nm":"עור","de":"ככל שמשתמשים בו יותר, כתמי המגע חודרים בו, וקמעה קמעה הוא הולך ומידמה לבעליו. בעוד הנוקשות הראשונית מתרככת, הצבע מעמיק והמרקם נעשה רך יותר. הברק שהזמן חרת בו אי אפשר לחקות בשום דבר."},"ICON-1155":{"nm":"נוצה","de":"קלה עד כדי כך שלא חשים משקל אפילו כשמניחים אותה על כף היד. גדיל בודד ששומר בתוכו את זיכרון הטיסה בשמיים כמו שהיה. אל נא תשכחו, שהדבר הקל ביותר עלה הכי גבוה."},"ICON-1156":{"nm":"קונכייה","de":"דברי הסבתא, להצמיד אותה לאוזן, עולים לפתע בזיכרון. על ברק הקשת שבפנים חרוט שלם הים שהושאר מאחור, כך שגם קונכייה ריקה נושאת בתוכה את גליו של זמן חלף."},"ICON-1157":{"nm":"אלמוג","de":"קשיח כאבן, ובכל זאת פעם היה בוודאי מושבה נושמת. בים האיטי הוא מבלה מאות שנים בפרישת ענפיו. הענף החזק ביותר צומח רק לאחר ההמתנה הארוכה ביותר."},"ICON-1158":{"nm":"פנינה","de":"לא יכולה עוד לסבול את גירוי גרגר החול הבודד, הצדפה עטפה אותו בשקט באור. חבקו את הכאב עגלגל, והוא נעשה מבריק כך, נחמה קטנה שהים מציע."},"ICON-1159":{"nm":"אצות ים","de":"סרט ירוק ומחליק פרוש על סלעי החוף בשעת שפל. אחזו בו, וריח ים דגי מציף אתכם. חסר שורשים, מפקיד את גופו בזרם, הים מטפח בשקט את גינתו שלו."},"ICON-1160":{"nm":"נורי (אצת ים מיובשת)","de":"קרבו יריעה שחורה אחת לאש לרגע קט, והיא מוריקה ומפיצה ניחוח קלוי. הבוקר ההוא של גלגול אורז טרי בפנים. דקה ככל שתהיה, היא חובקת בקלות את אושרה של ארוחה אחת."},"ICON-1161":{"nm":"מלח","de":"אני הגביש הלבן שהים השאיר בשמש. קורט אחד מעמיק מרק תפל, אבל החלקת יד קוברת כל טעם. רק אצבעות שיודעות את המידה הנכונה יכולות להפעיל אותי כראוי."},"ICON-1162":{"nm":"שבר זכוכית","de":"רק במקום שנשבר בו הוא לבסוף שובר את האור לקשת בענן. כישרון שלא ידע על עצמו כשהיה שלם. שגם דבר שבור שומר בתוכו חלק לתת מאור השמש, לוחש בשקט השבר השוכב על אדן החלון."},"ICON-1163":{"nm":"זכוכית","de":"שקיפות אינה אומרת רק שאין מה להסתיר. היא מחקה את צורתה שלה כדי לתת לאור לעבור דרכה שלם. גם בשהייה שם בלתי נראית, יש קפדנות צוננת כשיד נוגעת בה."},"ICON-1164":{"nm":"בקבוק זכוכית","de":"הוא חייב להיות ריק בפנים כדי להכיל משהו. ריבה, חופן פרחי בר, או מכתב מקופל, שמו משתנה לפי מה שנכנס. כלי שאינו חושש מריקנות הוא הנדיב מכולם."},"ICON-1165":{"nm":"בקבוק ריק","de":"אני אוהב את הדממה שבאה אחרי הטיפה האחרונה שנשתתה. מישהו זורק אותי, מישהו אחר שוטף אותי ומניח אותי על אדן החלון כדי למלא אותי באור שמש. למצוא שימוש מחדש במקום שהדברים הסתיימו בו, זה החיים השניים של המתרוקנים."},"ICON-1166":{"nm":"נייר","de":"אני שוכב פרוש לבן, מוכן לרשום כל דבר. תמיד אני זה שמביט הכי ארוך אל לבו של מי שמהסס לפני השורה הראשונה. סבלנותו של דף חלק עמוקה בטפח שלם יותר מהדיו."},"ICON-1167":{"nm":"נייר ישן","de":"מצהיב אינו זקנה אלא סבולת. בכל קפל ספוגה חמימות הידיים שפתחו וקראו בו. נייר ישן, כדי שלא יישכח, רושם בצבעו שלו את הזמן שחלף."},"ICON-1168":{"nm":"דיו","de":"הוא מתחיל בטיפה בודדת, הופך למשפט, ומשיבש נשאר כמו הבטחה. נמרח, הוא עקבתו של אותו היום ממש כמו שנמרח. מכיוון שתפקידי הוא להפוך דברים לבלתי הפיכים, אנשים לוחצים אותי פעם נוספת, בזהירות."},"ICON-1169":{"nm":"עפרת ברזל","de":"אבן שישנה שינה אדומה מתחת לאדמה. רק אחרי מעבר דרך האש היא סוף סוף מוסרת את הברזל שבתוכה. קשיחות אינה קשה מלכתחילה, היא שם שמקבלים אחרי מעבר בחום."},"ICON-1170":{"nm":"מטיל ברזל","de":"רק אחרי שהעפרה שרדה את האש היא התקררה לגוש אחד. הצורה הקרה והכבדה הזו הופכת לגשר, לסכין, למעדר. מכיוון שהשימוש בי עדיין לא נקבע, אני יכול להפוך לכל דבר."},"ICON-1171":{"nm":"עפרת נחושת","de":"יצאתי מהאדמה עוטה חלודה בצבע תפוח ירוק. המיסו אותי, ופעמונים מצלצלים, פסלים ניצבים, חוטי חשמל זורמים. גם בעודי ישן באדמה חשוכה, תמיד חיכיתי לתורי להיקרא למשהו."},"ICON-1172":{"nm":"מטיל נחושת","de":"השאירו אותי לצדכם זמן רב, ואני תופר בעצמי גלימה כחולה. יש הקוראים לגוון הזה פגם, ויש המלטפים אותו כדפוס של שנים. המתכת שאינה מתביישת בצבעה המשתנה, זו האהובה ביותר לאורך זמן."},"ICON-1173":{"nm":"עפרת זהב","de":"פיסה אחת שנפגשה בניפוי חול הנהר שוב ושוב. יקרה לא בשל נדירותה, אלא בשל אי-השתנותה. אנשי קדם לחצו אותה לתוך כפות ידיים כאסימון, ואמרו: הידמו ללב שאינו מחליד."},"ICON-1174":{"nm":"מטיל זהב","de":"הוא שוכב כגוש אחד, לא דוהה ולא מחליד. הוא שמע יותר מכול על תאוות בצע של בני אדם, ובכל זאת אני עצמי אינני חומד דבר. רק דממה כבדה, נאמנה אך ורק למלאכת הזוהר."},"ICON-1175":{"nm":"גרוטאות מתכת","de":"הוא לא מיצה את שימושו; הוא ממתין לשימושו הבא. מסמרים שבורים ופחיות מעוכות מתכנסים יחד לפגוש שוב את האש הלוהטת. עבורי, המילה \"נזרק\" פירושה מנוחה לזמן מה."},"ICON-1176":{"nm":"בורג","de":"לבד אני לא מסוגל לכלום. רק כשמברגים אותי פנימה לצמיד שני לוחות זה לזה בחוזקה, אני ממלא סוף סוף את תפקידי. הכישרון של גוף קטן האוחז בדבר גדול, גם בכוח ההידוק הזה יש מסירות."},"ICON-1177":{"nm":"מסמר","de":"משננעצתי, אני כמעט לא נסוג. עם כל מכת פטיש מה שמעמיק אינו פצע אלא הבטחה. אם מדובר בחיבור איתן של משהו, אני מציע ברצון את ראשי."},"ICON-1178":{"nm":"גלגל שיניים","de":"אני דוחף את שיני שכני וסובב יחד איתו. אינני מנסה לרוץ קדימה לבד, אלא יודע להתאים את הקצב לצד. כמו שעון שזמנו זורם רק כששיניים נשזרות זו בזו, אני מאמין שהרמוניה היא עצמה תנועה."},"ICON-1179":{"nm":"קפיץ","de":"ככל שנלחצים עליו יותר, כך הוא צובר בפנימיותו כוח לחזור. להתכופף אין פירושו להיכנע, אלא להתכונן להיפרש שוב. סליל קטן שקופץ בחזרה בדיוק כמידת הזעזוע שספג, שבו הגמישות היא עצמה עוצמה."},"ICON-1180":{"nm":"חוט חשמל","de":"מבחוץ מעטפת צנועה, מבפנים דרך הזורמת בלי הפסקה. ממקומות בלתי נראים היא נושאת אור וקול. כמו יד שמחברת דברים בשקט מאחורי הקלעים, זהו מעבר אמין עוד יותר בזכות היותו נסתר."},"ICON-1181":{"nm":"סוללה","de":"היא אוגרת בתוך גופה הקטן, קמעה קמעה, אור בהיר של חצי יום. אם נגמרה, פשוט מלאו אותה מחדש, היא אומרת, ולעולם אינה רואה בריקנות סוף. היא חובקת ערב קטן שיאיר את הלילה הארוך של מישהו."},"ICON-1182":{"nm":"נורה","de":"חוט להט דק בודד מלהט באודם ודוחק הצידה את החושך. הוא שורף את גופו שלו לא כדי לחמם את החדר אלא כדי להאיר אותו. הכי חם ברגע ההדלקה, ולכן הכי בהיר, שמש קטנה של רגע אחד."},"ICON-1183":{"nm":"עדשה","de":"היא אוספת אור מתפזר ומעמידה אותו חד בנקודה אחת. היא קוראת בשקט הן לכוכבים הרחוקים והן לאותיות הקטנטנות על כף היד. עוזרת למעשה הראייה תוך שהיא מסתירה את צורתה שלה, שדכנית צלולה ועגולה."},"ICON-1184":{"nm":"גומי","de":"לוחצים או מותחים, והוא חוזר בסוף למקומו. גם מי שלעג לו כרך יבחר בי לנעול ביום גשום. עבודת קליטת זעזוע קשה ברכות, גם בתוך הרכות הזו חיה עקשנות."},"ICON-1185":{"nm":"שבב פלסטיק","de":"פיסה קטנה שנשברה מהגוף הראשי. כמעט נזרקה, אך אם רבים מתאספים יחד היא הופכת שוב לחדשה. לא קלה כי היא קטנה, אלא מסוגלת להגיע רחוק כי היא קלה, חלק ממשהו."},"ICON-1186":{"nm":"חבל","de":"רק בשזירת כמה גדילים יחד הוא הופך לחוט אחד. לבדו הוא נפרם בקלות, אך שזור הוא גורר סירה וקושר משא. קשר עתיק של שיתוף פעולה, מחוספס לכף היד, שמתחזק ככל שהצטמד יחד."},"ICON-1187":{"nm":"בד מפרש","de":"הוא לא שונא את הרוח, אלא מחבק אותה בכל חזהו. רק כשהוא מתוח ותפוח הוא שולח את הסירה למרחקים, כך שגם רוח נגדית הופכת עבורי לכוח. את הדרך להתקדם באמצעות חיבוק המתעצם ולא התנגדות לו, למד בים."},"ICON-1188":{"nm":"שבר עוגן","de":"הוא רק פינה אחת של עוגן, אך הוא זוכר את המשקל ההוא במלואו. את הימים שבהם אחז בקרקעית העמוקה ועצר ספינה. גם עכשיו, כשהוא שבור, הוא פיסה כבדה שיודעת את משקל ההישארות."},"ICON-1189":{"nm":"מסמר ספינה","de":"מסמר שהחזיק סיפון מתנדנד בגלים, נקודה אחר נקודה. גם כשהחליד באדום מהמלח, מעולם לא ויתר על מקומו עד הסוף. גם לאחוז חזק בדבר צף נדרש עקשנות."},"ICON-1190":{"nm":"בד עמיד למים","de":"הוא לא מתלונן על עבודת חסימת הגשם. הוא קולט בשקט את מה שנשפך מלמעלה, ושומר על מה שמתחת יבש. גם בלי זוהר, שכבה אמינה אחת שמכסה את משאו של מישהו כדי שלא ירטב."},"ICON-1191":{"nm":"צבע צביעה","de":"כשהוא חודר בשקט לתוך בד לבן, הוא הופך סוף סוף לצבע. אינדיגו או פואה, האמהות של פעם צבעו את קצות אצבעותיהן בעודן מלבישות את הבד בצבע. גם בעבודת השקיעה והספיגה, יש עומק שכמעט אינו דוהה."},"ICON-1192":{"nm":"שמן ריח","de":"טיפה אחת בלבד, ושדה רחב נפרש לפתע וממלא את החדר. אורח שמגיע ראשון אף שאינו נראה לעין. נוף שנוגע באף ראשון, מושך בעורמה בשולי גלימתו של זיכרון ישן."},"ICON-1193":{"nm":"שעווה","de":"היא זורמת כשהיא סופגת חום ומתקשה כשהיא מתקררת, ושומרת על צורתה. נעה בין רכות לקשיחות, היא מעצבת בשקט כל דבר. חומר עדין הסוגר, אוטם ומצחצח, ומשנה את הבעתו לפי הטמפרטורה."},"ICON-1194":{"nm":"נר שעווה","de":"הוא ממיס לאט את גופו שלו כדי להאיר משבצת חושך אחת. כשהוא נשרף כליל נותר רק גובהו המקוצר, אך הזמן שבו חימם את ליל מישהו לא נעלם. פתיל זקוף שיודע את דרך הזוהר בעודו הולך וקטן."},"ICON-1195":{"nm":"קומפוסט","de":"דברים נרקבים מתכנסים יחד והופכים לאדמה השמנה ביותר. קליפות שנזרקו ועלים יבשים שנפלו הופכים למזון של נבטי האביב. במקום שחשבתם שהסתיים, החיים הבאים מיישרים בשקט את נשימתם הראשונה."},"ICON-1196":{"nm":"אורז","de":"נדרשות שמונים ושמונה נגיעות יד עד שגרגר בודד מונח בכף ידך. משתילה ועד דישה, שנה שלמה של איכר טמונה כולה בגרגר הקטן הזה. קערת אורז מהבילה היא, כשלעצמה, ארבע העונות של מישהו."},"ICON-1197":{"nm":"אורז מלא","de":"רק קליפתו החיצונית קולפה קלות, והוא שמר על צבעו המקורי כמות שהוא. שהוא נעשה עשיר יותר ככל שלועסים אותו זהו טעמה של יושרה שלא מיהרה. עקשנותו האיתנה של הגרגר, המסרב להיטחן חלק ושומר על מרקמו המחוספס."},"ICON-1198":{"nm":"חיטה","de":"הוא זוכר את השדה הזהוב שהרכין את ראשו כאחד ברוח. הופך ללחם, לאיטריות, לבצק פסטים, הוא מחמם שולחנות בכל רחבי העולם. תבואה שדווקא בשל היותה נפוצה כל כך, חדרה עמוק עוד יותר לחיי בני האדם."},"ICON-1199":{"nm":"קמח","de":"רק אחרי שהוא הופך לאבקה לבנה ועדינה הוא מוכן סוף סוף להפוך לכל דבר. פוגש מים והוא תופח, פוגש אש והוא מתבשל. בלי צורה קבועה, הוא בסיס עדין שמקבל כל צורה שהידיים לשות אותו לתוכה."},"ICON-1200":{"nm":"בצק","de":"קמח ומים מתמזגים לגוש אחד מתחת לכף היד. ככל שלשים אותו יותר, כך הוא נעשה דביק יותר; ככל שממתינים יותר, כך הוא תופח עגלגל יותר. אם ממהרים הוא מתקשה, כך שדווקא את זמן התפיחה אי אפשר לזרז, אומרת המאפייה הישנה."},"ICON-1201":{"nm":"פירורי לחם","de":"כשמנערים את האבקה הלבנה שנדבקת לקצות האצבעות, לפתע גם השרוולים כבר לבנים. כציפוי הם נעשים פריכים; כשהם נערמים רכות, הם נראים כמו שלג ראשון. זהו העקבות הקל ביותר שכיכר לחם משאירה מהאפייה, ואף על פי כן גם דברים קטנים צומחים לכדי תועלת."},"ICON-1202":{"nm":"אטריות פסטה","de":"ברגע שפורשים חופן אל תוך המים הרותחים כמו מניפה, אור שמש רחוק חוצה אל תוך המטבח. אטריות ארוכות הן מלאכת פרקי הידיים, וה'אל דנטה' הוא הסבלנות לדעת להמתין כשהן עדיין לא לגמרי מוכנות. הביטו בברק הזה כשהוא מתפתל שוב ושוב סביב המזלג."},"ICON-1203":{"nm":"ראמן","de":"שקית שמבריחים אל הכיריים עם שחר, אחרי שכל איפור הבמה נמחק. שלוש הדקות שלוקח לאטריות להתרכך הן הזמן הפרטי ביותר ביום כולו. המתח מתקרר יחד עם הנשיפה כשנושפים עליו, ומאחורי משקפיים מעורפלים היום מסתיים בשקט."},"ICON-1204":{"nm":"עוגת אורז (טוק)","de":"רק לאחר שהאורז עומד בפני מכות המכתש, הוא הופך סוף סוף לטוק. פשוט, כאינג'ולמי, כסונגפיון - אותו הדגן זוכה למאה שמות מהידיים שמעצבות אותו. כשהוא מונח על שולחן חגיגי, הוא קורא לחיבה עוד לפני הפה; טעמו הטוב ביותר כשחולקים אותו."},"ICON-1205":{"nm":"עוגות אורז למרק","de":"פורסים גליל טוק באלכסון והעיגולים יוצאים כמו מטבעות קטנים. האם זו עוגת אורז הצפה במרק הלבן, או משאלה עגולה קטנה? כשמסיימים קערה בבוקר ראש השנה, מוסיפים שנה לגיל - דרך עדינה, כך סופרת המדינה הזאת."},"ICON-1206":{"nm":"תפוח אדמה","de":"מנערים את האדמה והפנים העגולות נחשפות. פקעת שהתעבתה בשקט ברוחות מדרונות קנגוון, תפוחה כשמאדים, ריחנית כשמטגנים. גם בימים של כיס דל, הוא מילא ביושר את בטני המשפחה."},"ICON-1207":{"nm":"בטטה","de":"כשחבית תפוחי האדמה הצלויים הופיעה בפינת הסמטה, זו הייתה תחילת החורף. מקלפים את נייר הכסף והאדים הצהובים מחממים תחילה את האצבעות; המתיקות ההיא היא הפרס של השורש על עמידותו בקור. בדיוק מתאימה לנשיפה, לחלוקה לשניים ולשיתוף בחום."},"ICON-1208":{"nm":"גזר","de":"חנית כתומה אחת שיורדת ישר דרך האדמה. חשבו שרק ארנבים אוהבים אותו, אבל כשמטגנים אותו קלות מתעוררת מתיקות נסתרת, וכשמכניסים אותו למרק הוא מוסיף גם צבע. הזקנים שאמרו שהוא טוב לעיניים צדקו, ברובם."},"ICON-1209":{"nm":"צנון קוריאני","de":"שורש לבן וכבד אחד, והשולחן החורפי מוכן. צונן ומרענן כדונגצ'ימי, קריר כמרק צנון, פריך ככאקדוגי. שום דבר לא הולך לאיבוד - אפילו העלים הירוקים מיובשים תחת המרזב ונשמרים כסירֶגי - ירק חסכני."},"ICON-1210":{"nm":"בצל","de":"מקלפים את הקליפה ודמעה בודדת מתגלגלת. הבשר החריף והצורב הופך מתוק כמו שקר ברגע שהוא פוגש שמן חם. שמו כתוב בשורה הראשונה כמעט בכל מנה קוריאנית - הכוכב השקט שמניח בשקט את יסוד הטעם."},"ICON-1211":{"nm":"בצל ירוק","de":"מפזרים את הבסיס הלבן הפרוס דק ואת העלים הירוקים מעל המרק, ורק אז קערה מרגישה שלמה באמת. מציבים את השורש הנותר בכוס מים והוא צומח שוב מהר - גינת אדן קטנה לבעלי הבית."},"ICON-1212":{"nm":"שום","de":"שישה בתי שן מתכנסים במעגל ליצור ראש אחד. השורש החריף שאמרו שהפך דובה לאישה. כותשים אותו בגב הסכין והריח מתלקח מיד; בלי חופן ממנו, לא קימצ'י ולא תבשיל הגיוני בכלל."},"ICON-1213":{"nm":"ג'ינג'ר","de":"שורש קטן ומחוספס כמו סבך של קשרים. פרוסה אחת בלבד משתיקה ריח דגי ומחממת גוף קפוא מבפנים. בלילות שגנחת מהצטננות, אותה כוס חמה שהוצפה עם דבש התחילה מהעקצוץ הקטן הזה."},"ICON-1214":{"nm":"כרוב סיני","de":"ממליחים את העלים הצפופים, ורק אז נפתח הפרק הראשון של הקימצ'י. בסתיו המאוחר הוא נערם כהרים בכל חצר. כל המשפחה שמתכנסת להכין אצווה הייתה הבטחה לעבור יחד את החורף הארוך."},"ICON-1215":{"nm":"כרוב לבן","de":"מקלפים את העלים העגולים והשכובים זה על זה, עלה אחרי עלה, ואין לזה סוף, עד שהלב נרגע בהדרגה. מאודה הוא רך; מוקפץ, הוא מתוק. מתחת למראה החיצוני הפשוט, הירק הזה מסתיר עדינות בלתי צפויה."},"ICON-1216":{"nm":"חסה","de":"מניחים פרוסת בשר בעלה הקעור, מוסיפים כפית רוטב סאמג'אנג, ודוחסים ביס מלא. במעגל אנשים שעוטפים ואוכלים, כל אחד מניח בשקט לפורמליות - זו לא פחות מהכנסת אורחים בירוק."},"ICON-1217":{"nm":"חסת עלים","de":"העלה הראשון שצומח בפינת הגינה. קוטפים אותו והוא צומח שוב, ממלא את השולחן לאורך כל הקיץ. הריח הירוק והרענן הזה - שנשטף במים קרים ונעטף ביד - הוא, עבור מישהו, כל טעמו של הבית."},"ICON-1218":{"nm":"תרד","de":"הירוק ההוא מהקומיקס שהעניק פרץ כוח כשהפחית התרוקנה. כשמאדים אותו הוא מתכווץ לחופן, אבל ריחו ועוצמתו נשארים שלמים. טוב מתובל ביד או מעורבב במרק סויה - ירק שלעולם אין לזלזל בו רק כי הוא נפוץ."},"ICON-1219":{"nm":"קוסארי (גבעולי שרך)","de":"קוטפים את הניצנים הרכים שהר האביב מציע, ואז מבשלים ומייבשים. רק אחרי כל העמל הארוך הזה הם מגיעים לשולחן האבות או לקערת הביבימבאפ. שכבה על גבי שכבה של טיפול בשל כל הטרחה שהם דורשים - עשב יקר שההר גידל במשך עונה אחת."},"ICON-1220":{"nm":"ירקות בר הרים","de":"כביכול חסרי שם, ואף על פי כן כל אחד נושא ריח משלו - מתנת האביב. ידי הסבתא מזהות במבט אחד איזה עלה בשביל ההר טוב לאכילה. בסל אחד של ירקות, עונה שלמה מגיעה איתו, על כל ריחה."},"ICON-1221":{"nm":"לענת נגד","de":"העשב המר-ריחני שפורץ ראשון דרך האדמה הקפואה. כשמעצבים אותו לעוגת אורז, אור האביב נכנס ישר לפה. באחד לחודש הראשון האמינו שהרתחתו למרק מגנה מפני מזל רע של השנה, כך שהאביב תמיד הגיע דרך הריח הזה."},"ICON-1222":{"nm":"עלה פרילה","de":"עלה בודד מספיק כדי להכתים את כל הפה בריחו. מלווים אותו עם חזה חזיר צלוי וזהוב, או כובשים אותו בשכבות ברוטב סויה, וקערת אורז נעלמת תוך רגע. הארומה המיוחדת הזו הולמת רק את שולחנה של הארץ הזאת."},"ICON-1223":{"nm":"פלפל ירוק","de":"פרי ירוק חלול שנשבר בפריכות. המרירות הקלה מעוררת תיאבון קהה, ומוקפץ בשמן צבעו מבהיק עוד יותר. חתוך דק ומפוזר, הוא מרענן כל מנה תוך רגע."},"ICON-1224":{"nm":"פלפל גמבה","de":"אדום, צהוב, כתום - צבעים כמו רמזור שממלאים סל שלם. נושכים אחד טרי והמיץ המתוק זולג; הצבע לבדו מאיר את השולחן. האמרה שירקות יפי מראה מגבירים תיאבון מתאימה בדיוק לכאן."},"ICON-1225":{"nm":"עגבנייה","de":"העגול האדום שתמיד התווכחו עליו - פרי או ירק? מבושל ארוכות, טעמו מעמיק; נאכל טרי, הוא רענן להפליא. זהו הפרי שאוסף את שמש אמצע הקיץ בכנות רבה ביותר, כך שביס אחד פוצח שלמות של אחר צהריים בהיר."},"ICON-1226":{"nm":"מלפפון","de":"הירוק שמקרר את חום הקיץ בצורה המרעננת ביותר. מציפים אותו במרק קר והפה נעשה פריך וצונן; כובשים אותו כסובאגי והפריכות מתעוררת. בימים לוהטים אפשר אפילו לפרוס אותו דק ולהניח על העיניים - קריר מבפנים ומבחוץ."},"ICON-1227":{"nm":"דלעת","de":"הוא תלוי עגול בקצה הגפן, ממלא את עצמו במתיקות באיטיות עד סתיו מאוחר. מבושל רך הוא הופך לדייסה צהובה שמרגיעה את הבטן; מטוגן הוא הופך לג'ון זהוב. תלוי תחת המרזב, הוא משמש כמחסן אמין לכל החורף."},"ICON-1228":{"nm":"דלעת צעירה","de":"הירוק-הבהיר שמתעבה יום אחר יום בגינת הקיץ. חתוך לקוביות בתבשיל סויה, מטוגן זהוב כג'ון - כה רך שהוא עדין אפילו לפה של ילד קטן. נפוץ, ומשום כך אהוב עוד יותר - אורח קבוע בשולחן אמצע הקיץ."},"ICON-1229":{"nm":"חציל","de":"פרי מוארך זוהר בברק סגול. סופג שמן והוא הופך רך ללא גבול; מאודה היטב המרקם דק כמשי. פשוט כפי שהוא נראה, הוא משתלב היטב עם הכול - השחקן המשני העדין של השולחן."},"ICON-1230":{"nm":"תירס","de":"גרגירים צהובים ערוכים בשורה מסודרת, אחד ליד השני. חטיף קיץ שמאדים בסיר, נושפים עליו ונושכים בו; גם הסימן המבשר שהשדות הבשילו. בתוך אותה חבילה שעירה של שיער תירס, המתיקות ארוזה עד אפס מקום."},"ICON-1231":{"nm":"פולי סויה","de":"גרעינים קטנים וקשים שותים מים בלילה ומתנפחים. טחונים דק הם הופכים לחלב סויה, מותססים רכות הם הופכים לג'אנג - רוב חלבון השולחן בארץ הזאת התחיל בדיוק כאן. קוברים גרגר אחד באדמה והוא חוזר כצמח שלם."},"ICON-1232":{"nm":"טופו","de":"כשפולי הסויה שותים מים, נטחנים ומתמצקים, הם הופכים לגוש לבן עם פינות ישרות ואחידות. רך וצנוע, הוא לעולם לא מתעקש על צבעו שלו בשום מרק. הוא קורס בעדינות גם למגע הכף - מאכל שמעלתו היא הפשטות עצמה."},"ICON-1233":{"nm":"פולי אזוקי","de":"מבשלים היטב את הגרגירים האדומים הקטנים, ומתיקות אדומה-כהה עמוקה נשרית ממנה. בלילה הארוך ביותר, קערת דייסת פולי אזוקי חמה נהגה פעם לגרש יחד את הקור ואת הרוחות הרעות - הלב ההוא עדיין שוכן בה. שכבה על גבי שכבה בעוגת האורז המאודה, האדום ההוא לא היה אלא מסירות."},"ICON-1234":{"nm":"ממרח פולי אזוקי מתוק","de":"פולי אזוקי מבושלים נמעכים דק, ואז מצומצמים ומצומצמים שוב עד למילוי רך. כף אחת בין פרוסות לחם, בתוך עוגת אורז, על גבי קרח מגורד - חוט אחד של מתיקות מחמם אפילו זיכרונות ישנים. כל אותו הזמן הארוך של סינון וצמצום הופך בעצמו למתיקות."},"ICON-1235":{"nm":"פטרייה","de":"אחרי שהגשם חולף, היא מרימה ראש בלי קול בצל האפל של היער. מלאכת האדמה, שמגדלת ריח משלה גם בלי שמץ שמש. מוסיפים רק חופן למרק ועושר טעם עמוק נשרה ממנו בלי בשר בכלל - סוד שהיער מסתיר."},"ICON-1236":{"nm":"פטריית שיטאקי","de":"מטרייה חומה שפרשה את כובעה לרווחה. מיובשת יבש-יבש בשמש, ריחה מעמיק פי כמה, כך שכובע יבש אחד יכול לשאת סיר מרק שלם בקלות. עמוד תווך יציב בשולחן הצמחוני, ולקוח קבוע ותיק של מי שמכיר טעם עמוק."},"ICON-1237":{"nm":"פטריית מטסוטקה","de":"עמוק ביער האורנים הסתווי, היא מרימה ראש בעדינות רק לצד האורנים. אי אפשר לגדל אותה, ויש למצוא אותה רק בהליכה ברגל, מה שהופך את ריחה ליקר עוד יותר. צלויה קלות עם קורט מלח בלבד, פס של יער נכנס לפה."},"ICON-1238":{"nm":"פטריית קינג אויסטר","de":"קורעים את הגבעול העבה לאורך הסיבים והדביקות מגיעה ישר ליד. היא גדלה איתן בכל עונה, כך שהיא לעולם לא רחוקה מהשולחן. צלויה או מוקפצת - בתוך בשרה הנדיב, שובע קליל וללא דאגה מלא עד אפס מקום."},"ICON-1239":{"nm":"תות שדה","de":"בקצה החממה שעמדה בפני החורף, היא מבשילה אדומה ראשונה מכולן. ביס אחד הוא חמצמץ-מתוק, בדיוק כמו הברכה הראשונה של תחילת האביב. מניחים גרגר עגול אחד על עוגה, ואפילו יום רגיל לגמרי הופך בקרוב לחגיגה."},"ICON-1240":{"nm":"אוכמנית","de":"כשהיא נפצחת בקול קטן, חמיצות בהירה מתפשטת בכל הפה. אוספים את החרוזים הסגולים הקטנים אחד אחד, ותוך זמן קצר הקופסה כבר ריקה; מפוזרים על חלב לבן, שמיים לילה קטנים נפרשים בדיוק שם."},"ICON-1241":{"nm":"תפוח עץ","de":"נושכים אחד וקרס, הסתיו מתנפץ. האדום ההוא שהסבתא מהמטע ניגבה בסינרה והושיטה הוא צבע שמגיע רק מהחזקה ארוכה של אור שמש. ככל שהוא קשה יותר, כך הוא יודע טוב יותר להישאר מתוק עד הסוף."},"ICON-1242":{"nm":"אגס קוריאני","de":"מקלפים את הקליפה והאצבעות מתקררות ראשונות. השורה הקדמית של שולחן צ'וסוק - ברגע שהמיץ הקר והמתוק ממלא את הפה, מידה קטנה של רוח ליל הסתיו באה בשקט ומתיישבת לצדך."},"ICON-1243":{"nm":"אפרסק","de":"היכן שכל פרח אפרסק נשר, קיץ שעיר מקבל צורה. לוחצים עליו קלות והריח מתפשט תחילה; ברגע שנושכים בו, כל העונה נכנסת אחריו לפה."},"ICON-1244":{"nm":"ענבים","de":"חרוזים סגולים תלויים כאשכול אחד, נשענים כתף אל כתף. פוצחים אחד והחמיצות מגיעה תחילה, המתיקות חצי פעימה מאחור - כמו מקהלה מסודרת שקוראים לה ימי הקיץ האחרונים."},"ICON-1245":{"nm":"ענבים ירוקים","de":"הירוק-הבהיר מעביר את אור השמש היישר דרכו, מדליק פנס בכל חרוז. נטול גרעינים ונקי כה צלול, מתיקותו נטולת כל עודף, כמו משפט ראשון שזה עתה נשלף בטהרתו."},"ICON-1246":{"nm":"לימון","de":"מגרדים את הקליפה הצהובה בציפורן והריח מתפרץ, מעיר את קצה האף. טיפה אחת וקצוות השפתיים מתכווצים מעצמם, ואף על פי כן בקצה החמיצות ההיא יש פינה מוזרה שבה כל היום מתבהר."},"ICON-1247":{"nm":"ליים","de":"קטן וירוק-עמוק יותר מלימון, הפרי הקטן הזה מברך אותך תחילה בריחו החד והמעורר. פרוסה אחת מעירה אפילו מים פושרים תוך רגע - חופן קטן של רעננות, זעיר אך עקשן."},"ICON-1248":{"nm":"תפוז","de":"ברגע שמקלפים אותו, ריח אור שמש נדבק לאצבעות. מכניסים כל פלח לפה ופופ, פופ - בלוני מיץ מתוק קטנים מתפוצצים, והעגול מגלגל אפילו את מצב הרוח לעגול."},"ICON-1249":{"nm":"קלמנטינה","de":"זוכרים את הטעם ההוא - קילוף עם הרגליים תחובות תחת השמיכה החמה של הרצפה המחוממת בחורף? הריח שהתפשט מבין הציפורניים צבע את כל החדר בצהוב. שקית אחת היא תירוץ למשפחה כולה להתכנס."},"ICON-1250":{"nm":"בננה","de":"היו ימים שהסתפקתי בארוחה של דבר צהוב אחד שהתגלגל מהתיק בפינת חדר החזרות בשחר רעב. רך, מתוק ומשביע - התחליף הזמני העדין ביותר."},"ICON-1251":{"nm":"אננס","de":"צריך לעבור שכבה של קליפה קוצנית לפני שהבשר הצהוב נחשף. מחזיקים פרוסה בפה והחמצמץ-מתוק עוקץ את הלשון, בעוד ריח של ים דרומי מרחף על השפתיים."},"ICON-1252":{"nm":"מנגו","de":"פורצים את הבשר הבשל ביד וריח מתוק ודביק מרטיב את האצבעות. כשהצהוב העמוק נמס ונעלם בפה, חולף חלום מתוק כמו תנומת צהריים קצרה של קיץ."},"ICON-1253":{"nm":"קוקוס","de":"מנערים את הקליפה הקשה ושומעים מים מקשקשים בפנים. שוברים אותה פתוח - בשר לבן ומיץ קריר - כד קטן שמחזיק ים רחוק שלם, מתנדנד בתוכו."},"ICON-1254":{"nm":"פרי דרקון","de":"מראהו הוורוד המקושקש גורם להיסוס לרגע, אבל כשפוצחים אותו הפנים הלבנים מנוקדים בזרעים שחורים זעירים. פשוט בטעמו אך ראוותני בלבושו - נוכל ערמומי, ההפך הגמור מבפנים ומבחוץ."},"ICON-1255":{"nm":"קיווי","de":"חותכים את הבז'-שעיר החום לשניים ואבן חן ירוקה נחשפת. כפית של החתך שבו זרעים שחורים משובצים כמו כוכבים, וביס חמצמץ אחד מנער אותך מתוך שינה."},"ICON-1256":{"nm":"בשר עוף","de":"מניחים אותו במחבת משומנת והציוץ הזהוב מתבשל תחילה. עדין ורך, הוא מצטרף בקלות לכל שולחן - אורח קבוע לארוחה נוחה."},"ICON-1257":{"nm":"בשר חזיר","de":"על הגריל הוא מצליף, השומן קופץ בזמן שהוא מזהיב. באותם לילות ארוחות עבודה של דחיסת ביס מלא עטוף בעלה חסה עם קורט רוטב סאמג'אנג, עושרו הריחני מחמם את כל השולחן."},"ICON-1258":{"nm":"בשר בקר","de":"לאורך כל סיב אדום, שומן משוקע בעדינות ומבריק. מניחים אותו על אבן לוהטת והריח ממלא את החדר תחילה; ברגע שפרוסה נכנסת לפה, עייפות היום מתרופפת בשקט."},"ICON-1259":{"nm":"בייקון","de":"על מחבת הבוקר הוא נעשה פריך, השומן רוקד. הריח המלוח הזה לבדו מושך אפילו את המשפחה המאחרת לישון, משפשפת עיניים, אל המטבח - ארוחה שהריח קורא לה תחילה."},"ICON-1260":{"nm":"נקניקייה","de":"החתכים נפתחים לרווחה, מתפוצצים במיץ. צורת התמנון האדומה שהחזיקה פינה אחת בקופסת האוכל הייתה מותרות קטנות שהפסקות הצהריים של הילדות נהנו מהן."},"ICON-1261":{"nm":"פפרוני","de":"פרוסה עגולה וחריפה מסתלסלת מהקצוות מעל הגבינה החמה. כשקצת שמן מצטבר, זו נקודת השיא של הפיצה כולה - קטנה, אך עגולה ועשירת נוכחות."},"ICON-1262":{"nm":"קציצת בשר","de":"מעצבים אותה עבה, מניחים על הגריל, והיא מזהיבה מהקצוות פנימה. תוחבים ירקות בין הפרוסה הלחוצה והצלויה, ושובע שנכנס בדיוק ליד אחת מושלם."},"ICON-1263":{"nm":"ביצה","de":"פוצחים אותה והחלמון מחליק החוצה כמו שמש עגולה קטנה. נהדרת מעורבבת באורז טרי, נהדרת כפס הצהוב בתוך קימבאפ - החלבון הנפוץ ביותר ולכן החביב ביותר."},"ICON-1264":{"nm":"חלב","de":"בקבוק קר שהונח ליד הדלת עם שחר - היום נפתח לרוב בקרירות ההיא כנגד כף היד. מהביל כשמחממים, עשיר-טעם כשמקררים - לבן שנשאר לצדך בכל עת."},"ICON-1265":{"nm":"גבינה","de":"פרוסה צהובה מתמוססת לאט מעל לחם חם. הלב שמחכה לרגע ההוא שבו היא נמתחת - ככל שהיא נמסה יותר, כך העושר שלה מעמיק ומתעצם."},"ICON-1266":{"nm":"גבינת צ'דר","de":"הכתום העמוק מבשר במבט אחד טעם מלוח. פורסים דק לתוך טוסט וטעם עשיר מתפשט בפה - צלול בצבע ממש כפי שהוא צלול בטעם."},"ICON-1267":{"nm":"חמאה","de":"מפילים חתיכה למחבת חמה והיא נמסה בעדינות, אדים ריחניים עולים. מרוחה על לחם, מעורבבת באורז - קסם צהוב שהופך כל מה שהוא נוגע בו לרך יותר במעט."},"ICON-1268":{"nm":"קצפת","de":"ככל שמקציפים יותר, כך הלבן הנוזלי מתנפח לענני יציבות. ברגע שמניחים כף על עוגה, אחר צהריים רגיל מתבהר כמו יום הולדת קטן."},"ICON-1269":{"nm":"יוגורט","de":"משקעים כף פנימה והלבן החמצמץ מתרומם בחלקות. מערבבים פיסת פרי והבוקר נעשה קליל יותר; כוס אחת והבטן מתיישבת בשקט - טעמה של התחלה עדינה."},"ICON-1270":{"nm":"מקרל","de":"מניחים אותו על הרשת והשמן קופץ, ממלא את המטבח בעשן שהוא גם דגי וגם ריחני. הידיים שהוציאו את העצמות והניחו אותו על האורז - המסירות העמוקה ביותר בארוחת יומיום."},"ICON-1271":{"nm":"סלמון","de":"סיבי ורוד שוכבים ערוכים שכבה על שכבה. מוגש קר הוא נפרם בעדינות בפה, צלוי השמן חודר וטעים - טעם איתן ששחה נגד הזרם מים רחוק הביתה."},"ICON-1272":{"nm":"טונה","de":"פותחים את מכסה הפחית וריח מלוח פורץ. היו זמנים בחדר שכור קטן בלילה שפחית אחת, מעורבבת באורז או עטופה באצה, הייתה לארוחה משביעה."},"ICON-1273":{"nm":"בקלה","de":"בשרו הצלול כה עדין, שכשמבשלים אותו, מרק מרענן נשרה כבר מההתחלה. דג לבן שעמד בפני רוח הסכין של נמל חורפי - קערת נזיד חמה אחת וגם ידיים קפואות נמסות לאט."},"ICON-1274":{"nm":"שרימפס","de":"מסלסל את גבו לעיגול, וכשהוא מתבשל האפור מסמיק. פרץ קפיצי ופתאומי וריח עשיר - קולפים ואוכלים אחד אחד, והצלחת כבר איכשהו ריקה."},"ICON-1275":{"nm":"סרטן ים","de":"הוצאת הבשר הלבן מתוך הקליפה הקשה היא זמן קטן של סבלנות. הפיסה שמכניסים לפה בסוף כל הטרחה מתוקה - ים סתווי שלם נכנס לפה."},"ICON-1276":{"nm":"דיונון","de":"על הגריל הוא מתכווץ לעיגולים, מעלה ריח עשיר. ביס אחד גמיש, טבול בקורט רוטב צ'ילי, ומכניסים לפה - הים המלוח בא בעקבותיו."},"ICON-1277":{"nm":"צדפות","de":"במרק צלול הן פותחות את פיהן ובשקט מוסרות את ריחן. כשהן רותחות ומבעבעות, ריח הים מתפשט, וגמיעה אחת מחממת ומרפה בטן קפואה."},"ICON-1278":{"nm":"עוגת דגים","de":"טובלים אותה על השיפוד במרק חם והאדים עולים בתלתלים. ביום קר לפני דוכן רחוב, ידיים אוחזות מרק בכוס נייר ונושפות עליו - נחמה קטנה שהסמטה מציעה."},"ICON-1279":{"nm":"קימצ'י","de":"בתוך הכד היא מבשילה לאט, מגדלת ריח חמוץ ועמוק. קורעים ביד ומניחים על אורז טרי וזה מספיק; הטעם השונה מבית לבית הוא בעצם ההיסטוריה של אותו הבית."},"ICON-1280":{"nm":"צנון כבוש צהוב","de":"פיסה צהובה נשברת בפריכות, קלילה בפה. השותפה הקבועה לצד גליל קימבאפ או צלחת חטיפי רחוב - החמיצות-מתיקות שלה שוטפת רעננות לפה שמן."},"ICON-1281":{"nm":"מלפפונים כבושים","de":"המלפפונים עוצרים את נשימתם לרגע במלח, ואז פוקחים עיניים בחומץ. כדי לא לפספס את הרגע שבו הפריכות חוזרת, צנצנת הזכוכית לא עוזבת את אדן החלון המוצף שמש. הזמן שבו הם נכבשים לאט הוא שמביא את הטעם."},"ICON-1282":{"nm":"גוצ'וג'אנג","de":"אדום שעמד בפני שנה שלמה בתוך הכד. מאחורי החריפות מתחבאת בעדינות מתיקות הפולים, כך שכף אחת הופכת תבשיל לפנים של הבית שלנו סוף סוף. עומק שכדי הג'אנג בחצר גידלו בעזרת אור שמש."},"ICON-1283":{"nm":"דנג'אנג","de":"גוש המג'ו חיבק את העובש שלו וחי דרך חורף שלם. עושרו הריחני הוא הליכה על חבל דק בין הבשלה למוגזמת - הסבתא זיהתה את הקו הזה מריח בודד בקצות אצבעותיה. טעם שמעמיק ככל שממתינים."},"ICON-1284":{"nm":"רוטב סויה","de":"ככל שפולי הסויה מכהים, כך פנימם מעמיק. טיפה אחת מחייה ירק ומעניקה ברק לתבשיל - כך שכל צבע במטבח מתחיל, בסופו של דבר, מהחום החם הזה. עושר טעם שמעבר למליחות."},"ICON-1285":{"nm":"רוטב שעועית שחורה","de":"גם שחור זהה יש לו סיבים שונים. הטעם המתוק-מלוח הסופי של מטוגן פעם נוספת עם קרמל - מערבבים אותו באטריות והברק השחור ההוא מנער את התיאבון. הכפתור הראשון שממנו מתחיל טעם הווק הסיני."},"ICON-1286":{"nm":"אבקת קארי","de":"אבקה צהובה שבה תבלינים רבים מתמזגים בשלום בכף אחת. ממיסים אותה במים והיא מבעבעת ועולה, מחממת את כל הבית - היא הופכת לתצוגה מקדימה לקערה המשביעה ביותר בערב גשום."},"ICON-1287":{"nm":"פלפל שחור","de":"טחון שלם, הריח חי; טחון מראש, הריח בורח בשקט. הסיבוב האחרון תמיד ממש לפני כיבוי האש - נקודה קטנה שהיד המבשלת מניחה בחיסכון."},"ICON-1288":{"nm":"אבקת צ'ילי","de":"פלפלים מיובשים בשמש תחת אור הסתיו משלימים סוף סוף את אדומם. אם טוחנים דק או גס קובע את אופייה של הקימצ'י, כך שנגיעת האומן מגיעה, בסופו של דבר, מבחירת גרגר האבקה הזאת."},"ICON-1289":{"nm":"מלח","de":"לתבל נכון פירושו להתקרב צעד צעד לצד החסר-מלח. מלח שנוסף פעם אחת אי אפשר לבטל, כך שיד מנוסה תמיד מוסיפה מעט פחות בסוף וטועמת. מה שנשמר בצד הוא מרחב הנשימה שלך."},"ICON-1290":{"nm":"סוכר","de":"הוא מרגיע מרירות ומעגל את קצוות החמיצות. אבל המתיקות לא צריכה להיתפס בנוכחותה, כך שככל שהתיבול טוב יותר, כך הסוכר נעלם בשקט יותר מהמבט בסוף. מתיקות שיודעת להסתתר."},"ICON-1291":{"nm":"דבש","de":"צנצנת שהדבורים אספו כשעברו אלפי פעמים בין שדות הפרחים. כשהוא מתקשה, מחייה אותו באמבט מים חם; מערבבים אותו בתה והוא עוטף את הגרון בעדינות. כף זהובה של עונה שלמה אחת שצומצמה כולה."},"ICON-1292":{"nm":"שמן בישול","de":"מסובבים אותו פעם אחת סביב מחבת חמה והמרכיבים שוכחים להידבק. יוצקים מוקדם מדי והוא נשרף, מאוחר מדי והוא נדבק, כך שהפעימה היחידה שבה העשן רק מתחיל לעלות היא כלל הטיגון. מודדים את הרגע לפי הצליל."},"ICON-1293":{"nm":"שמן זית","de":"בירוק של הסחיטה הראשונה חיים יחד ריח עשב ועקצוץ קל. מטפטפים אותו בסוף במקום להניחו על האש, כך שהריח שורד עד הסוף - להשאיר אותו לא מבושל הוא השימוש הכן ביותר בו."},"ICON-1294":{"nm":"שמן שומשום","de":"מטפטפים טיפה אחת בסוף והירקות המתובלים מכריזים סוף סוף על השלמתם. עושרו הריחני נוטה לברוח בקלות מעל האש, כך שהוא תמיד הנקודה שמתווספת בעדינות אחרי שכל הבישול הסתיים."},"ICON-1295":{"nm":"תרמיל וניל","de":"מפצלים תרמיל אחד וגורדים את הזרעים השחורים, והקינוח מחליף בגד לריח. לא לזרוק גם את הקליפה המשומשת אלא לטמון אותה בסוכר - חסכנות ישנה שהקונדיטור ירש."},"ICON-1296":{"nm":"קקאו","de":"בשר לבן וזרעים מרים בתוך הפרי. רק אחרי תסיסה וייבוש בשמש הם מתורגמים סוף סוף למתיקות שאנחנו מכירים. לפני שהופך לשוקולד, הוא נושא את הפנים הראשונים, הקרובים ביותר לפראי."},"ICON-1297":{"nm":"שוקולד","de":"טבע קפדני שנמס מעצם החום של כף היד. יש להקשיח אותו סביב 28 מעלות כדי שהברק והפצפוץ יחיו, כך שמאחורי המתיקות מסתתר, באופן מפתיע, חוק טמפרטורה קפדני."},"ICON-1298":{"nm":"פולי קפה","de":"לפני הטחינה, גרגר אחד קרוב לשתיקה קשה. אבל כשהוא פוגש מים חמים הוא מתנפח ופולט את ריחו - האות הראשון שמעיר את הבוקר תמיד מתחיל מהגרגר הקטן הזה."},"ICON-1299":{"nm":"עלי תה","de":"נשארים זמן רב מדי במים חמים והם נעשים עפיצים; קצר מדי והם שטוחים. לחשב בשקט את הזמן שבו העלים נפתחים לאט - להכין תה זה למדוד המתנה בקצות האצבעות."},"ICON-1300":{"nm":"נענע","de":"מועכים אותה ומרירות נשרית, כך שזהו עלה עדין שיש לטפל בו תמיד בעדינות. מקישים עליו קלות כדי להעיר את הריח הרדום, ומצפים אותו בכוס זכוכית ביום לוהט - וקיץ שלם שוקע בטון קריר יותר."},"ICON-1301":{"nm":"עשבי תיבול","de":"כשמוסיפים אותם עם הגבעול, הריח עמוק; כשמשתמשים רק בעלים, הוא צלול. מיובשים הם מתעצמים, טריים הם רעננים - וככל שהצרור טומן בתוכו טווח ריחות רחב יותר, כך גם הבעתו של המטבח מתרחבת יחד איתו."},"ICON-1302":{"nm":"ערמון","de":"מתחת לקליפה קוצנית מסתתר בשר מבריק. חורצים ופותחים על האש, והוא נפתח בפצפוץ ונודף ריח מתוק - חום שקית הערמונים הצלויים בסמטה בליל רוח קרה, נדמה כמעט אפשר לגעת בו."},"ICON-1303":{"nm":"בוטן","de":"הטעם העשיר נשלם על אש הקלייה. גרעין קטן שמקלפים אחד אחד, עד ששוכחים את הזמן החולף - וכשחולקים אותו יושבים במעגל על הרצפה, גם הסיפורים מתקלפים יחד איתו, לאט לאט."},"ICON-1304":{"nm":"שקד","de":"כשמרתיחים קלות ומקלפים, הפנים הופכים לבנים ורכים יותר. כתוש וטחון הוא כמו חלב, קלוי בשלמותו הוא פריך - וטווח ההשתנות הטמון בגרעין אחד מרחיב עד מאוד את דמיונו של הקונדיטור."},"ICON-1305":{"nm":"שומשום","de":"מנענעים אותו בעדינות על אש נמוכה, ובאיזה רגע הוא מתחיל לקפוץ בפצפוצים. הרגע שלפני שהצליל נפסק הוא הרגע העשיר ביותר בטעם - קלייה של שומשום, מתברר, היא מלאכה שעושים באוזניים."},"ICON-1306":{"nm":"קנה סוכר","de":"לועסים פרק אחד והמיץ המתוק נוזל החוצה יחד עם ריח דשא. גבעול שצריך לצמצם ולצמצם שוב כדי שיהפוך למתיקות שאנו מכירים - התחלתו של הסוכר, למרבה ההפתעה, כה ירוקה וכה גבוהה."},"ICON-1307":{"nm":"סוכר גולמי","de":"מתיקות גסה השומרת על צבעה שלה, לאחר שעברה עידון מועט. עומק אדמתי דק נותר בעדינות, ולכן ידיים האוהבות את הכנות של הדבר לפני שהוא מלוטש עד חלקלקות, מחפשות אותו בכוונה."},"ICON-1308":{"nm":"פולי קקאו","de":"הזרעים שהוצאו זה עתה מהתרמיל מרים וחריפים. עליהם לשאת בשקט ימים של תסיסה עד שהריח יפרח, ולכן המתיקות היא פרס קטן שהפול הזה מקבל אחרי סבלנות ארוכה."},"ICON-1309":{"nm":"קרעי קקאו","de":"בפירורי הפול הקלוי הכתוש אין אף גרגר סוכר אחד. שמים בפה, והמרירות מגיעה קודם, ועושר הטעם מגיע בעקבותיה באיחור - כך פוגשים את הקקאו לפני המתיקות, בצורה הכי כנה שיש."},"ICON-1310":{"nm":"פולי קפה ירוקים","de":"גרגרים ירוקים שעדיין נושאים ריח גולמי. כך כמות שהם, הארומה ישנה בשלווה, ולכן עד שיקבלו את טבילת האש, הם נותרים בשקט בגדר אפשרות שעוד אינה יודעת למה תהפוך."},"ICON-1311":{"nm":"פולי קפה קלויים","de":"על פני השטח החומים שמהם נדלף מעט שמן, התכנס ריח מלא. יש לטחון אותם לפני שיתקררו כדי שהריח יישאר שלם, ולכן גורלה של כוס קפה נחרץ בשקט תוך ימים ספורים מהקלייה."},"ICON-1312":{"nm":"תרמיל וניל","de":"קו ריח אחד צובע סיר חלב שלם מקצה לקצה. אפילו את התרמיל הריק אם תוחבים לצנצנת סוכר, כעבור ימים כל הסוכר יתמלא בניחוח - מותרות שאין בהן שום חלק להשליך."},"ICON-1313":{"nm":"פלפל שחור","de":"ריחו של גרגר פלפל שלם דועך מרגע הטחינה. לכן משאירים אותו שלם על השולחן וכותשים אותו בכל פעם מחדש - הרעננות פורחת מלב שאינו דוחה דברים למחר."},"ICON-1314":{"nm":"פלפל לבן","de":"הגרגר, חלק יותר לאחר שהוסרה קליפתו, עדין יותר מאשר חריף. נולד מתוך דאגה שלא להשאיר אף כתם שחור ברוטב לבן - עדינות של מקום בלתי נראה."},"ICON-1315":{"nm":"קינמון","de":"כשמכינים חליטה מנתח אחד, חריפות חמימה מתפשטת לאט בתה. כשמוסיפים אותו שלם ולא כאבקה, הריח נשמר זמן רב יותר - עומקו של משקה חורפי נובע מהתמדתה של קליפת עץ מיובשת זו."},"ICON-1316":{"nm":"ציפורן","de":"בניצן פרח קטן שצורתו כמו מסמר זעיר, מתעבה ריח בעוצמה רבה. מוסיפים יותר מדי, והוא בולע את המנה כולה - ולכן הריסון של גרגר בודד שומר בשקט על מאזן הטעם."},"ICON-1317":{"nm":"אגוז מוסקט","de":"שומרים את הזרע שלם ומגרדים ממנו מעט בכל פעם מחדש. יש לו טבע שריחו מתפזר במהירות ברגע שנטחן מראש, ולכן המגע האחרון של גירוד מהיר אחד מעמיק עוד יותר את ניחוחו של החלב."},"ICON-1318":{"nm":"הל","de":"פוצחים את התרמיל הירוק וריח קריר וחריף נשפך מבפנים. די בכתישת תרמיל אחד או שניים לתוך התה כדי שכוס רגילה תקבל, לפתע, את בשמיה של ארץ רחוקה."},"ICON-1319":{"nm":"זעפרן","de":"חוטים אדומים, בקושי שלושה נאספים מפרח בודד. מומסים במים חמים, והאור הצהוב מתפשט לאט - היוקרה היא גם משקלו של הזמן שהושקע בליקוט ביד, אחד אחד."},"ICON-1320":{"nm":"כורכום","de":"טוחנים את השורש מהאדמה, והוא צובע בצהוב אפילו את קצות האצבעות. יש לו טבע שהריח מתעורר רק כשמטגנים קלות בשמן, ולכן זהובו של הקארי הוא צבע ששורש קטן זה העלה מעל האש."},"ICON-1321":{"nm":"עלה דפנה","de":"העלה שלפי האגדה הונח על מצחו של המנצח. מציפים עלה אחד במים רותחים, ומבעד לאדים עולות לרגע תשואותיה של זירה עתיקה. גם בימים שלא ניצחת, שאיפת ריחו הופכת לנחמה ירוקה המחבקת בשקט את מי שאתה היום."},"ICON-1322":{"nm":"חלב קוקוס","de":"המיץ הלבן הזורם רק כששוברים את הקליפה הקשה. בפינת שוק במדינה חמה, תוחבים קשית ולוגמים לגימה אחת, וצמאונו של אמצע היום נמס כליל. המתיקות הקרירה המתפשטת בפה מביאה איתה את צלו של הטרופי."},"ICON-1323":{"nm":"שמן קוקוס","de":"כשהוא מתקשה הוא לבן כמו שלג ראשון, וכשמחממים אותו בכף היד הריח מתפשט בעדינות. חוכמת הבית החמה של סבתא מהאי, שמסרה אותו באומרה כי צנצנת אחת מספיקה מהראש ועד כפות הרגליים, שמורה כולה בתוך הקופסה העגולה."},"ICON-1324":{"nm":"בננה מיובשת","de":"כשמניחים אותה בשמש כמה ימים, הבשר הצהוב הופך דביק ולעיס. נושכים חתיכה אחת בכל פעם בחסכנות, וריחה הדביק והמתוק של עונת קציר גשומה מתעורר בעדינות מחדש בפה. מתיקות שהבשילה לאט צוברת בתוכה עונה שלמה."},"ICON-1325":{"nm":"מנגו מיובש","de":"הבשר הרך, שהתעבה מתחת לשמש, נולד מחדש כג'לי בגון ענבר. שלושה טעמים - חמוץ, מתוק ולעיס - כלולים בפיסה אחת, ואם מגלגלים אותה לאט בפה, שקית אחת מאריכה את אחר הצהריים."},"ICON-1326":{"nm":"אננס מיובש","de":"בניגוד למראהו הקוצני מבחוץ, הבשר בפנים צהוב ובהיר עד מאוד. כשהוא מתייבש בשמש, החמיצות מתעבה, ולכן די בביס אחד כדי שקצוות הפה יתרוממו מעצמם. שארית הטעם הרעננה בסוף פיסה אחת נשארת לאורך זמן."},"ICON-1327":{"nm":"סלסלת פירות טרופיים","de":"צבעים שנקטפו זה עתה מתמזגים יחד בסלסלה אחת. הכתום של המנגו, הצהוב של הבננה, הזהב של האננס - עוד לפני שמושיטים יד לבחור, הקיץ נכנס דרך קצה האף. חופן שכבר עצם המבט בו מאיר את הלב."},"ICON-1328":{"nm":"צרור אצות ים","de":"שערו של הים, שנאסף מהסלעים שנחשפו בשפל. קול הגלים שזור בריח המליחות הימי שלו, ולכן כשמשרים אותו בעדינות במים קרים, ריח ים דגיגי נודף לאט עד המטבח. חופן אחד פורש על השולחן לשון חוף בוצית קטנה."},"ICON-1329":{"nm":"פירות ים מיובשים","de":"חופן של ים שיובש עד קשיחות. קורעים ביד לפי הסיבים, ויחד עם המליחות משתחררת רוחו המלוחה של נמל עתיק. חבר ותיק לצד שולחן אוכל חם-לב, שמעורר חשק בלתי נמנע לכוס מקולי."},"ICON-1330":{"nm":"דיונון מיובש","de":"עשרת זרועותיו נפרשו בסדר ויובשו בשמש. צולים קלות עד שעולה ריח עשיר, ואז קורעים לפי הסיבים. בטעמו הלעיס עולה כבודה של צלחת נשנוש לילית בדרגה אחת."},"ICON-1331":{"nm":"דג מלוח","de":"כשקוברים אותו במלח גס, הדג לומד כיצד לשרוד את הזמן. ביס אחד מבשרו המלוח לעומק מרוקן קערת אורז כהרף עין - סוד מסור וחם שסבתא מהחוף העבירה בקצות אצבעותיה."},"ICON-1332":{"nm":"שרימפס מלוח","de":"שרימפסים קטנים מבשילים לאט במלח ונולדים מחדש כעושר טעם. ברגע שכף אחת נוספת לתוך כרוב הנאפה בעונת הקימצ'י, ריח מליח מתפשט בכל החצר. אותה כף אחת קובעת את טעמו של הקימצ'י לשנה שלמה."},"ICON-1333":{"nm":"אנשובי","de":"גוף בגודל אצבע נושא באחריות על עומקו של סיר מרק שלם. במטבח הילדות, שם עקרו את הראש והמעיים תוך שיחה נעימה - דג קטן אך אסיר תודה, שעמד איתן בלב-לבו של משק הבית."},"ICON-1334":{"nm":"קלפ","de":"רצועה שחורה וארוכה שגדלה בקרקעית הים. מכניסים למים קרים ומוציאים בעדינות רגע לפני הרתיחה - הבטחה ששומרות ידי מבשלי המרק מדור לדור. עושר הטעם העמוק אף פעם לא ממהר."},"ICON-1335":{"nm":"היג'יקי","de":"המרקם המחוספס פוקע בפה בקול פצפוץ. האצה שצבעה בירוק את סלעי החוף באביב - כשמתבלים אותה ביד, היא פורשת פינת ים קטנה ורעננה על השולחן. טעמה של לעיסת האביב."},"ICON-1336":{"nm":"צדפת פנינים","de":"אור עגול שנוצר בהחזקה ממושכת בין שני קשוות קשות. עד שהפכה את אי-הנוחות של גרגר חול אחד לאבן חן, הים מעולם לא מיהר. מניחים אותה על כף היד, ומשקלה של אותה סבלנות ארוכה נח שם יחד עמה."},"ICON-1337":{"nm":"קישוט אלמוגים","de":"ענף עצו של הים, שהגלים עיצבו במשך מאות שנים. כשהאור נוגע בו, הוא מתפשט לוורוד וכתום, ולכן די בכך שינוח על המדף כדי שחדר שלם יצבע לאי חמים. אפילו הטקסטורה המחוספסת הנוגעת בקצות האצבעות מעוררת חיבה."},"ICON-1338":{"nm":"כפתור צדף","de":"במקום שבו עזב בשר הצדף, נחתך בעיגול פנים נוצץ בגוני קשת. תופרים על דש הבגד, ובכל רכיסה מנצנצת קשת קטנה בקצות האצבעות. מתנת הפרידה האחרונה שהשאיר הים, לאחר שנתן את הכול."},"ICON-1339":{"nm":"גולת זכוכית","de":"מגלגלים על כף היד והאור הכלוא בפנים מתגלגל יחד. באותם ימים של ישיבה בשפיפה בסמטה, משחקים בגולות בלי לשים לב שהשמש שוקעת, כיסו של ילד שזכה בגולה נוספת היה כבד ומלא גאווה במיוחד."},"ICON-1340":{"nm":"גילוף עץ ארז","de":"מכל סיב מגולף נודף ריח דק. אנשי קדם שרפו עץ זה כדי לארגן מחדש לב שהתפזר. אוחזים בפיסה אחת בשקט, ורוגע מתמלא לאט מקצות האצבעות."},"ICON-1341":{"nm":"קטורת","de":"גבעול דק בוער לאט וסולל דרך כלפי מעלה. עוקבים בעיניים אחר העקומה שמצייר העשן, ולב שמיהר כל היום מאט את צעדיו בלי משים ונח שם בשקט."},"ICON-1342":{"nm":"פרח צבע","de":"כשמשחררים לתוך סיר רותח את הגוון החבוי בעלי הכותרת, בד צלול נצבע לאט בגוון הזה. שאילת האור שהטבע כבר צייר מראש לזמן קצר - הצביעה הייתה, מיסודה, ברכת שלום עדינה שהוגשה לפרחים."},"ICON-1343":{"nm":"צבע אינדיגו","de":"כחול עמוק ורך שהופק מתסיסה ותסיסה חוזרת של צמח האינדיגו. בכל טבילה והוצאה מחדש, הבד מעביר את צבעו לאט מגון שמים לגון ים. צבעה של ההמתנה, הפורח רק כשמניחים בצד את חוסר הסבלנות."},"ICON-1344":{"nm":"צבע ארגמן","de":"כשמחלצים את שורש הפוארה, שקיעה שישנה באדמה מתעוררת בתוך הסיר. זה היה הצבע החגיגי והבהיר ביותר בכפר, זה שצבע בעדינות את שולי חצאיתה של כלה חדשה ביום החתונה."},"ICON-1345":{"nm":"חוט זהב","de":"מושכים זהב דק משיער ומטווים אותו בקפידה, חוט אחר חוט. בכל מקום שנרקם, הוא סופג אור, ולכן אפילו בחדר חשוך ללא נר, אותה תבנית לבדה עולה ומאירה בעדינות מעצמה."},"ICON-1346":{"nm":"משי","de":"את החוט שפולט התולעת יש לארוג ולארוג שוב עד שנוצר בקושי פס אחד. מגע המחליק כמו מי אביב על גב היד - בד עדין-מרקם שאנשי קדם החזיקו עונה שלמה וגידלו לאט."},"ICON-1347":{"nm":"כפתור פנינה","de":"רק האור הפנימי של הפנינה נבחר ועוצב בעיגול. בכל רכיסה על דש הג'ורוגי, קצות האצבעות הופכות לרגע לאלגנטיות. גרגר קטן אך מסודר, המרים בשקט את מעמדו של הלבוש."},"ICON-1348":{"nm":"קרע ממפת שיט","de":"מעבר לקצה הקרוע, קו חוף לא נודע נקטע בפתאומיות. אומרים שרק מי שאוסף את שאר החלקים מגיע אל האוצר - אך אולי המסע עצמו, של נדוד אחריו ברוח, כבר היה האוצר."},"ICON-1349":{"nm":"מפת ים ישנה","de":"נתיבי שיט שהתמסמסו במי ים וציור מצפן דהוי. עוקבים בקצה האצבע אחר קווים שספן כלשהו שרטט לאור הכוכבים בלבד בלילה אפל, ואי שנעלם מזמן עולה שוב לאט על הנייר הישן."},"ICON-1350":{"nm":"מכתב בבקבוק","de":"דף נייר מגולגל אחד, בתוך בקבוק זכוכית שהגלים הביאו לחוף. ברכה - אין לדעת מי שלח אותה ומתי - הגיעה סוף סוף לידיו של מישהו. אם יש לב מספיק, גם הים הופך לדוור איטי כזה."},"ICON-1351":{"nm":"תיבה סחופה","de":"ההרפתקה נמשכת עד לרגע פתיחת המכסה, שתפח והתקשה מהמלח. בין אם מה שממתין בפנים הוא אוצר או חול ריק, תיבה שנסחפה למרחקים תמיד נושאת איתה גם את סיפורו של מישהו אלמוני."},"ICON-1352":{"nm":"מפתח קטן","de":"פיסת מתכת שחוקה שמתיישבת בול בכף היד. גם אם נשכח לחלוטין איזו דלת היא פותחת, משקל עדין ונעים נותר כבד בקצות האצבעות - מהסוג שגורם לך לחשוב על פתיחה לפני נעילה."},"ICON-1353":{"nm":"מטבע כסף","de":"כסף עגול שתבניתו דהתה ממגע ידיים רבות. מטבע בודד ששימש פעם דמי מעבר של מישהו או לינת לילה מייגעת - מלטפים את פניו הקרים, וחומה של עסקה עתיקה מתעורר בעמימות בקצות האצבעות."},"ICON-1354":{"nm":"מטבע זהב","de":"מניחים על כף היד, ומשקלו הכבד מרעיד את הלב תחילה. מטבע בודד הנוצץ בצהוב באור השמש, כאילו מבטיח עושר אם רק תחזיק בו - אך מה שבאמת זוהר הכי בהיר הוא הרטט שרגע לפני שהוא נוחת בכף היד."},"ICON-1355":{"nm":"חותם הרב-חובל","de":"הבטחתו של הרב-חובל, שהוטבעה בחוזקה בשעווה אדומה. תבנית אחת יכלה להקים פקודה ולקבוע מסלול משוגע. סמכות, בסופו של דבר, הייתה חותם קטן ומוצק אחד שכל מי שהיה על אותה ספינה הסכים יחד להאמין בו."},"ICON-1356":{"nm":"מיקרופון יד","de":"ברגע שאוחזים בו, משקל מרגיע באורח מוזר ממלא את כף היד. גם כשמושיטים שלום ראשון רועד, וגם ברגע שסוף-סוף פורצת הצליל הגבוה - מוט קטן אחד זה מעניק בעדינות כנפיים לקולך."},"ICON-1357":{"nm":"מיקרופון אלחוטי","de":"כשנעלם הכבל, הבמה כולה התרחבה. גם אם רצים עד קצה האולם, הקול אף פעם לא נקטע - כאילו מישהו דוחף בעדינות את גבך ואומר לך לרוץ ולשיר עד כלות."},"ICON-1358":{"nm":"מיקרופון עומד","de":"עומד יציב לרגליך וממתין בשתיקה לזמר. כשהידיים משתחררות, השיר מתפשט בכל הגוף במקום בקצות האצבעות. יש קסם ברור גם בלהחזיק מקום אחד עד הסוף - כך אומר בשקט מוט זה."},"ICON-1359":{"nm":"מסנן רוח","de":"שכבת בד עגולה אחת חוסמת את פני המיקרופון. היא מסננת בעדינות נשימות עזות ומאפשרת רק לקול הצלול לעבור. לגרום למישהו להישמע היטב פירושו להגן בשקט ממקום שנשאר בלתי נראה עד הסוף."},"ICON-1360":{"nm":"אוזניית ניטור","de":"נכנסת בול לתוך האוזן, ושירך שלך חוזר לחיים בבירור מעבר לשאגתם של רבבות. המלווה הקטן והחשאי ביותר, ששומר עליך שלא תפספס את הקצב על במה מוצפת אור וקול."},"ICON-1361":{"nm":"אוזניות","de":"ברגע שהן מכסות את האוזניים, העולם מצטמצם מעט והשיר לבדו נותר גדול. חדר עגול קטן שאיש לא יכול לפרוץ אליו. באוזניות שנלבשות לבד, באורח מוזר, אינך לבד."},"ICON-1362":{"nm":"תווים","de":"כשהנקודות השחורות מתיישבות בשקט על הקווים, נייר ששתק מתחיל לשאת בתוכו צליל. כתב שקוראים באוזניים ולא בעיניים. ברגע שפותחים אותו, שיר שעמד דומם נושם מחדש."},"ICON-1363":{"nm":"תווי שירה","de":"בכל מקום לנשום מצויר עיגול קטן. שאף כאן, ושחרר בעדינות שם. מפה עדינה הסוללת דרך כדי שהקול לא ייפגע."},"ICON-1364":{"nm":"תווי פסנתר","de":"עמוד שבו עשר אצבעות שואלות את הדרך בו-זמנית. היד השמאלית אוחזת בשורשים, היד הימנית מציירת את השיר. שתי ידיים שסיפרו סיפורים שונים מתקפלות סוף סוף לאחת בטקט האחרון."},"ICON-1365":{"nm":"טבלת אקורדים","de":"השפה הזרה הראשונה שהאצבעות לומדות, המילה הראשונה שלה כתובה כאן. כששש נקודות מתכנסות לעיגולים, רק אז בוכה צליל אחד. בכל לילה של לחיצה ולחיצה שוב, יבלות צומחות בקצות האצבעות."},"ICON-1366":{"nm":"מטרונום","de":"טיק, טיק - צעד יציב אחד פועם לצדך. כשהלב ממהר קדימה, הוא עוצר אותך מאחור, לאט, לאט. כי הקצב הוא, בסופו של דבר, הבטחה ללכת יחד."},"ICON-1367":{"nm":"מכוון","de":"כשהמחט מחליקה אל המרכז הממש, הצליל מוצא סוף-סוף את מקומו. אותה נקודה יחידה, לא גבוהה ולא נמוכה. כיוון נכון, מתברר, הוא בדיוק זה: להפסיק לרעוד ולנוח בשקט."},"ICON-1368":{"nm":"כרטיס קלידי פסנתר","de":"מדפדפים דף אחר דף, והקלידים צועדים ישר לתוך כף היד. יקום קטן של שבעה תאים, מדו עד סי. גם בלילות בלי פסנתר אמיתי, השיר צומח כאן בשקט."},"ICON-1369":{"nm":"פיק גיטרה","de":"פיסה קטנה ואיתנה, לחוצה בין האגודל לאצבע המורה. מפילים אותה, והיא נעלמת לתמיד מתחת לכיסא - אך ברגע שאוחזים בה, כל שש המיתרים מהדהדות בבת אחת."},"ICON-1370":{"nm":"מקלות תופים","de":"כששני המקלות נפגשים באוויר, נופל שם אות. אחת, שתיים, שלוש, ארבע. כל הלבבות המפוזרים מתחילים לפעום באותו קצב, מתואמים לאותם ארבעה מונים."},"ICON-1371":{"nm":"תוף מרים","de":"מכה אחת, וצליל צלול מתפזר לכל עבר כמו אור שמש שמתנפץ לרסיסים דקים. גם אם נראה קליל, זו הפעימה הראשונה שהיד מגיעה אליה כשההתלהבות מתחילה לדעוך. קטן, אך איש אינו יכול להתעלם ממנו."},"ICON-1372":{"nm":"נעלי ריקוד","de":"לרגליים המסתובבות כמחליקות על הרצפה, החיכוך הופך לנשק. בכל סוליה שנשחקה, נחרתים סיבובים על גבי סיבובים. התנועה המרשימה ביותר תמיד מתחילה מזוג אחד יציב."},"ICON-1373":{"nm":"מגני ברכיים","de":"רק מי שכרע על ברכיו אינספור פעמים וקם שוב, יודע להעריך שכבת בד דקה זו. משהו ששומר על הרצפה מלהיות מפחידה עוד - אומץ לפעמים עטוף כך סביב הברכיים."},"ICON-1374":{"nm":"מגן שורש כף היד","de":"עוטפים מראש את הנקודה המתכופפת, ואפילו תנועה מאומצת נעשית מעט יותר סלחנית. שורש כף היד שותק ונושא לבדו עד שהוא כואב. את השתיקה הארוכה הזו, שכבה אחת נושאת במקומו."},"ICON-1375":{"nm":"מגן קרסול","de":"בסוף קפיצה גבוהה מגיעה הנחיתה, ובסוף אותה נחיתה נמצא הקרסול. המקום הנמוך ביותר, שקולט את משקל הגוף כולו. רצועה קטנה זו שומרת בשקט על אימון המחר."},"ICON-1376":{"nm":"רצועת מתיחה","de":"מותחים אותה, והיא מתנגדת, נאבקת לחזור למקומה. בזמן שסופגים את ההתנגדות הזו, הגוף מתארך מעט בלי לשים לב. מתיחה היא, בסופו של דבר, הסימן שמותיר הזמן שהוקדש להתמדה."},"ICON-1377":{"nm":"מזרן יוגה","de":"ברגע שפורשים אותו, נוצרת על הרצפה חלקת אדמה בגודל אדם אחד. שטח קטן לשכב, לכרוע ולווסת נשימה. תחילתו וסופו של היום נאספים בשקט על גיליון אחד זה."},"ICON-1378":{"nm":"גליל קצף","de":"לוחצים בעדינות על מקום מהודק, וזה כואב תחילה, ואז מקל במהרה. תמיד יש קצת כאב בשחרור של מה שהתקשה. כי הגוף והנפש שניהם צריכים לחוות לחץ פעם אחת לפני שיוכלו להשתחרר."},"ICON-1379":{"nm":"משקולת יד","de":"מרימים את אותו משקל, ושוב מרימים. פעם אחת יותר מאתמול, בדיוק - וזה הכול. בתוך חזרתיות שאין בה שום נוצץ, הזרוע מתעבה בלי מילה. גוש ברזל שהוא רק כן, אמיתי."},"ICON-1380":{"nm":"קטלבל","de":"ידית אחת מטלטלת את הגוף כולו. כשהמשקל העגול חג במעגל, מאזנו של האוחז בו עולה למבחן. כדי לא להתערער, צריך קודם לדעת את מרכז הכובד של עצמך."},"ICON-1381":{"nm":"חבל קפיצה","de":"קופצים מעל חבל אחד שחולף במהירות מתחת לרגליים, ושוב. כמו אותו משחק ספירה עם החברים בחצר, ככל שהמספרים גדלים, הנשימה קצרה יותר והצחוק גובר."},"ICON-1382":{"nm":"נעלי ריצה","de":"זוג שערכו האמיתי נודע רק לאחר שיוצאים איתו לדרך. חותכים את אוויר השחר ורצים שוב באותו נתיב, והפינה שהייתה רחוקה אתמול נמצאת היום ממש מולך. הרגליים זוכרות את המרחק."},"ICON-1383":{"nm":"מגבת אימונים","de":"מנגבים את הזיעה מהמצח, ושם ספוגה שורה אחת של מאמץ היום. שוטפים והעקבות נעלמים, אך כמות מה שהוזלף מצטברת אי-שם בקפידה. העידוד הכן ביותר תמיד מתייבש לצדך."},"ICON-1384":{"nm":"בקבוק מים","de":"ריק - ממלאים, יבש - לוגמים לגימה. אותו מעגל פשוט תומך בשתיקה ביום כולו. כמו דלי שעולה ויורד ליד הבאר, מהמעשה של המילוי מתחיל היום מחדש."},"ICON-1385":{"nm":"שייק חלבון","de":"מנערים היטב ולוגמים לגימה, והשריר שנשבר היום מתמלא שוב מחר. הטעם לא נוצץ, אך הגוף יודע שזו שפת ההתאוששות. הצמיחה תמיד נשתית בשקט."},"ICON-1386":{"nm":"חטיף אנרגיה","de":"פס אחד שהתשטח בכיס. מזון חירום הממלא את הזמן הריק בין ארוחה לארוחה. שום דבר מרהיב, אך הביס הקטן הזה מאפשר להחזיק מעמד לתנועה אחת נוספת אחר הצהריים."},"ICON-1387":{"nm":"סוכריית גרון","de":"מגלגלים בפה, ונענע חריפה מלטפת בעדינות גרון שהתקשה. ביום שבו דיברת הרבה, בלילה שבו שרת הרבה - סוכרייה קטנה אחת מלטפת דרך משופשפת. גם למתיקות יש שימוש ברור."},"ICON-1388":{"nm":"תה לקול","de":"אדים חמים מחממים את הגרון, ובלגימה אחת המתח בכתפיים משתחרר. תרופה עתיקה כמו תה הג'ינג'ר שסבתא הייתה מכינה. ברכת שלום עדינה שמושיטים לקול לפני השירה."},"ICON-1389":{"nm":"מי דבש","de":"מערבבים לאט כף דבש אחת במים פושרים. אותה כוס שהמבוגרים תמיד היו מכינים כשהגרון היה גס. לא תרופה ולא משקה, סתם מתיקות המלטפת בשקט את הגוף מבפנים."},"ICON-1390":{"nm":"מיכל מכשיר אדים","de":"כלי המשחרר ערפל קטן לתוך החדר. בליל חורף שבו האוויר היבש שורט את הגרון, הוא חולק לחות בלי שרואים. לטפל במישהו, לרוב, זורם בשקט כך."},"ICON-1391":{"nm":"קופון מנוחה","de":"פתק נייר אחד עליו כתוב שמותר לנוח. ברגע שלוקחים אותו ליד, נטל הלב נעשה קל בדרגה אחת. שגם לעצור זו תרגול - כרטיס קטן זה מעניק לך רשות במקומך."},"ICON-1392":{"nm":"לוח זמנים לתרגול","de":"על גבי הזמן הכתוב בכל תא, היום שוקע בקפידה. בבוקר - הפקת קול, אחר הצהריים - כוריאוגרפיה, בערב - מנוחה. גם מחר מבלבל, ברגע שמחלקים אותו בקווים, הופך למשהו שאפשר לצעוד בו."},"ICON-1393":{"nm":"חותמת נוכחות","de":"מטביעים בחוזקה סימן אחד המעיד שגם היום הגעת. ככל שהעיגולים המרוחים מעט בדיו מצטברים תא אחר תא, התמדה שנראתה לא-כלום הופכת לבסוף לדרך. עדות קטנה של כל יום."},"ICON-1394":{"nm":"מדבקת שבח","de":"במקום לומר \"כל הכבוד\", מדביקים בשקט כוכב אחד. ניצוץ בגודל ציפורן, אך ברגע שהוא מתיישב בפינת המחברת, היום כולו מתבהר. השבח קטן, אך באורח מוזר זוהר זמן רב."},"ICON-1395":{"nm":"יומן נפשי","de":"עמוד שבו הלב שרעד מאחורי הקלעים משתחרר למילים. גם ימים שלא הלכו טוב, כשכותבים עליהם בכנות, נעשים איכשהו קלים יותר. הלב מתחזק ככל שמסתכלים בו."},"ICON-1396":{"nm":"כרטיס דמיון-אימון","de":"עוצמים עיניים ואוחזים בו, ובמה נפתחת בשקט בראש. הליכה סיבוב מקדים במקום שעדיין לא עמדת בו. מסלול שצויר בדמיון מגיע צעד אחד לפני קצות האצבעות עצמן."},"ICON-1397":{"nm":"מראת תרגול הבעות","de":"מול המראה מחייכים, ואז קופאים - אותם פנים נעשים מאה פעמים ויותר. כאן לומדים ששמחה וגם עצב זקוקים לתרגול. כי הבעה היא מלאכת העתקת הלב אל החוץ."},"ICON-1398":{"nm":"יומן כוריאוגרפיה","de":"עמוד שבו הדרך שיעברו הרגליים והידיים הועתקה כציור. בכל שמונה-מנה, חצים מורים בשקט לאן על הגוף לזוז. גם תנועה שבקושי נזכרת, מתרגלת לאט על גבי דף זה."},"ICON-1399":{"nm":"שבב וידאו כוריאוגרפיה","de":"שבב קטן אחד שומר בתוכו מאות תנועות בשלמותן. מפעילים אותו שוב לפני השינה, וקצות האצבעות זזות לבדן לאורך אותו נתיב. חזרתיות היא רישום נוסף, המועתק דרך הגוף."},"ICON-1400":{"nm":"תרשים תנועה על הבמה","de":"מפה אחת של הבמה, שנצפתה מלמעלה. מי נפגש איפה ומתפזר לאן, הכול מובטח מראש בקווים ונקודות. כדי לצייר תמונה אחת יחד, צריך קודם לחלוק את הדרכים."},"ICON-1401":{"nm":"כרטיס חזרות","de":"האולם ריק והתאורה עוד ישנה. כרטיס אחד כזה נותן לך להיכנס אל תוך הדממה הזאת. הבמה כשאף אחד לא צופה - ומכאן בדיוק מתחיל הרגע לפגוש את הגרסה הכי כנה שלך."},"ICON-1402":{"nm":"מחברת סטייל","de":"באיזו הרגשה להתלבש היום? גם לחולצה אחת יש תחושה שמתאימה לה, הספר הזה לוחש בשקט. ככל שהופכים עוד עמוד, כך מצטבר עוד קצת טעם עדין בקצות האצבעות שהססו פעם מול המראה."},"ICON-1403":{"nm":"ספריי לשיער","de":"פססס, התזה אחת והרוח כבר לא יכולה לפרוע בקלות. שאיפה קטנה לקבע את אותן דקות בודדות על הבמה במקומן, בלי רבב. הרגע המושלם תמיד נשלם על גבי עקשנות פעוטה שכזאת."},"ICON-1404":{"nm":"פלטת איפור","de":"שנים עשר משבצות של צבע הן שתים עשרה מצבי רוח שונים. באיזו הבעה לשיר היום - קצות האצבעות בוחרות קודם והלב הולך בעקבותיהן. בכל משבצת שמתרוקנת נחבאים בשקט הימים שהושארו על הבמה."},"ICON-1405":{"nm":"סיכת תלבושת","de":"ברגע הזוהר ביותר, דווקא במקום שלא רואים, יש סיכה קטנה שאוחזת בבד. שלא יחליק, שלא יתפרק. הברק שעל הבמה תמיד ניצב על יציבותו השקטה של מישהו."},"ICON-1406":{"nm":"לוח שם","de":"ברגע שהלוח הריק מתמלא בשם, הבטחה מעורפלת אחת מתבהרת. מי יעמוד במקום הזה - שורת כתב אחת מכריעה. שם הוא ההחלטה הקצרה והמוצקה ביותר שיש."},"ICON-1407":{"nm":"כרטיס מעריצים","de":"מקבל אחד בלבד, ולאותו אחד זה כל העולם. המעשה של דחיסת תודה של כמה לילות לתוך ברכה קצרה אחת. הלב גולש כך גם על פיסת נייר בגודל כף יד."},"ICON-1408":{"nm":"דף תרגול חתימה","de":"בהתחלה אפילו השם שלך עצמו נראה מצויר בזרות. דרך שחרים של משיכות מאה פעם וליטוש אלף פעם, עד שהיד זוכרת את הזרימה עוד לפני הלב. כך שם אחד הופך סוף סוף לחתימה."},"ICON-1409":{"nm":"דף שאלות ראיון","de":"\"מה אני עונה לשאלה הזאת?\" קצות האצבעות האוחזות בנייר רועדות קלות. לא לשנן תשובות אלא לסדר כנות בתור - כי ראיון, כמו וידוי, הוא בסופו של דבר שאלה על סדר הלב."},"ICON-1410":{"nm":"מחברת אוצר מילים","de":"הפינה הבלויה ביותר מצביעה על המילה שהוסתכלו בה הכי הרבה זמן. כמו הזמן שלוקח לצליל זר אחד להשתקע על הלשון, כך המרחק אל עולם שמעולם לא ביקרת בו מתקרב עוד זרת אחת."},"ICON-1411":{"nm":"כרטיס תיקון הגייה","de":"ה-R' המתגלגל, ה-'S' החומק. יש שחרים שמושקעים בהפיכת קלף אחר קלף, במיסוד הלשון. ככל שהדיבור מתבהר, כך מתבהרות גם פני מישהו שרוצים להגיע אליו במילים האלה."},"ICON-1412":{"nm":"רשימת בדיקה לשידור חי","de":"מיקרופון דלוק, אוזניות נבדקו, מסלול תנועה נבדק. עם כל ריבוע שמתמלא, החרדה בחזה מתרוקנת עוד תא אחד. לפני העלייה לבמה, קפדנות היא סוג האומץ השקט ביותר."},"ICON-1413":{"nm":"פלסטר התאוששות","de":"יש מקום שמתחמם ומתפשט ברגע ההדבקה. כתף מותשת, שוק נוקשה - נחמה בגודל כף יד שעונה בשקט לאותות הקטנים שהגוף שולח. גם מנוחה טובה היא חלק מהאימון."},"ICON-1414":{"nm":"שקית קרח","de":"מניחים אותה בעדינות על קרסול נפוח. רק בזמן שהקור חודר לאט מבינים סוף סוף כמה רצת היום. ההחלמה מאחורי הקלעים תמיד מגיעה כך, ללא קול."},"ICON-1415":{"nm":"נרתיק עזרה ראשונה","de":"פלסטרים, כדורי כאב, מראה קטנה. מגיע רגע שבו הכיס הקטן הזה, מלא בדברים לא-מיוחדים, הופך למרגיע ביותר מכולם. אדיבות שהוכנה מראש זוהרת הכי בהיר מול משבר בלתי צפוי."},"ICON-1416":{"nm":"כרטיס תזכורת","de":"מישהו מרים אותו בחשאי מעבר למצלמה. המשפט שכמעט נשכח כתוב שם באותיות מסודרות. מאחורי תוכנית שזורמת ללא מכשול תמיד יש יד כזאת, שלעולם לא נתפסת במסך."},"ICON-1417":{"nm":"מעטפת משימה","de":"הרגע המרגש ביותר הוא ממש לפני קריעת המעטפה. לא משנה מה בפנים, אותו רגע קצר של אי-ידיעה מרגשת. הקסם של תוכניות בידור חי כולו בתוך הרגע האטום ההוא."},"ICON-1418":{"nm":"תג שם","de":"שם קטן שמוצמד לחזה מחליף את השלום הראשון. בין אנשים שעדיין לא מכירים זה את זה, תג שם אחד שובר את קרח המבוכה. מהרגע שקוראים בשם, מערכת יחסים מתחילה."},"ICON-1419":{"nm":"מדבקת עונש","de":"פתק אחד שנדבק על מצח המפסיד מפוצץ את כולם בצחוק. עדין מדי בשביל להיקרא עונש, כך שגם ההפסד הופך לזיכרון לשנים. סימן קטן וחביב שנוצר כדי שכולם יצחקו יחד."},"ICON-1420":{"nm":"כרטיס עונש אקראי","de":"אף אחד לא יודע עד שמושכים. עשר סיבובים של חדק פיל, או סבב חן אחד. ברגע שמפקידים את כל הגורל בפיסת נייר אחת, דווקא הצחוק הוא זה שמשתחרר ראשון."},"ICON-1421":{"nm":"כרטיס רמז","de":"כמו יד שמושטת בשקט למקום תקוע. הוא לא נותן את כל התשובה, אבל מצביע על הדרך. רמז טוב הוא לא הפתרון עצמו, אלא המעשה של העברה עדינה של האומץ לחשוב עוד פעם אחת."},"ICON-1422":{"nm":"כרטיס הזדמנות","de":"הזדמנות יחידה להפוך לוח נטוי בתנופה אחת. מתי שולפים את הקלף הזה מכריע את התוצאה. מזל ששמרו עליו בקפידה מוכיח את ערכו רק ברגע המכריע ביותר."},"ICON-1423":{"nm":"כרטיס פסק זמן","de":"מותר לעצור לרגע, הקלף הזה אומר את זה בשבילך. להרים יד בביטחון כשצריך רגע לנשום - עצירה היא אסטרטגיה לגיטימית בפני עצמה, ומנוחה טובה היא גם מקום של מיומנות."},"ICON-1424":{"nm":"כפתור צחוק","de":"טאק, וברגע הלחיצה מתפרץ החוצה גל בהיר של צחקוקים. לסצנה שבאמת מצחיקה מגיע גם אפקט קול כזה שמסתנן לעזור. החמימות של המקום מתחממת בדיוק ממתיחה קטנה כזאת."},"ICON-1425":{"nm":"שלט לאפקטי קול","de":"כפתור אחד למחיאות כפיים, כפתור נוסף לקריאות בוז. קוסם שמעצב את האווירה בעזרת קצות האצבעות בלבד יושב בשקט בחדר הבקרה. בימוי שלעולם לא נתפס במסך הוא זה שמעניק לסצנה נשימת חיים."},"ICON-1426":{"nm":"לוח צילום","de":"טאק, וקול חד כזה פותח צילום אחד. בין עשרות טעויות לבין OK יחיד, הלוח השחור הזה סופר כל רגע בבירור. זהו הפעימה הראשונה שהתיעוד צועד לתוכה."},"ICON-1427":{"nm":"סרט סימון","de":"ברגע שהבהונות נוגעות בקו ההוא בשקט, האורות יורדים בעדינות כאילו חיכו. המשבצת האחת שנלמדה בעל-פה עד בלאי - הבמה נשלמת סוף סוף בזכות רצועת צבע קטנה אחת המסומנת על הרצפה."},"ICON-1428":{"nm":"פילטר תאורה","de":"אותם פנים משתנים כליל בזכות צבע האור. בפילטר כחול שוכן שחר, בפילטר אדום שוכנת שקיעה. האווירה לעולם אינה רחוקה - היא מקופלת בשקט בתוך גיליון נייר צבעוני דק אחד."},"ICON-1429":{"nm":"סוללת מצלמה","de":"כשהאור האדום מתחיל להבהב, הלב נעשה חסר סבלנות ראשון. כי דווקא הסצנה הכי טובה תמיד מגיעה כשנשאר רק אחוז אחד. סוללה רזרבית אחת בכיס הופכת להקלה של נשימה עמוקה."},"ICON-1430":{"nm":"כרטיס זיכרון","de":"צחוק וזיעה של יום שלם נדחסים בצפיפות לתוך שבב בגודל ציפורן. קטן כל כך שקל לאבד אותו, ודווקא בגלל זה יקר עוד יותר. משקל הזיכרונות שהוא נושא לעולם לא ניתן למדידה לפי גודל."},"ICON-1431":{"nm":"פילם פולרואיד","de":"קליק, ואז המתנה שקטה. השניות הבודדות שבהן פנים עולות באיטיות מעל השטח הלבן מרגשות באופן מוזר. גם בתמונה מיידית שאוחזים ביד חייבת להיות כפית סבלנות אחת בדיוק."},"ICON-1432":{"nm":"פילם לפוטוקארד","de":"איזו הבעה תודפס על הפוטוקארד הזה נשארת סוד עד רגע ההדפסה ממש. הפנים שיהפכו לאהוב הגדול של מישהו נולדות בדיוק כאן. פיסת נייר קטנה אחת מכילה לב כה גדול."},"ICON-1433":{"nm":"שרוול לפוטוקארד","de":"פוטוקארד לא נוגעים בו בידיים חשופות לעולם. לחיצה אחת על הפינה וגם החיוך של אותו יום כואב. לעטוף את האהוב בזהירות בגיליון שקוף אחד - גם הטיפוח דורש מסירות כזאת."},"ICON-1434":{"nm":"מגן קשיח","de":"מחליקים אותו בין שני גיליונות קשיחים, ואפילו הזמן לא יכול לקמט אותו בקלות ראש. שלא יתעקל, שלא יתקפל. לשמור על משהו יקר תמיד שואל שכבת קשיחות נוספת."},"ICON-1435":{"nm":"חבילת מדבקות","de":"מקלפים אחת אחת ומדביקים בפינת יומן, על גב מחשב נייד. עם ציור קטן אחד יום חסר צבע נצבע בכל גוון. לרצון לקשט את הסביבה אין גיל."},"ICON-1436":{"nm":"טוש חתימה","de":"לצליל דיו ששורט בעדינות על הנייר, השורה מתארכת יותר ויותר. מעל אלבום שמושט ביד רועדת, מפגש של שניות בודדות נשאר לזמן רב. הלב חוצה גבולות דרך קצה העט."},"ICON-1437":{"nm":"אלבום חתום","de":"פותחים את הכריכה וחתימה מוכרת בעקומותיה מברכת ראשונה. קשר שנוצר דרך מוזיקה מתקרב עוד זרת אחת על הנייר. לשמור זה לעצור את הרגע בשקט במקומו."},"ICON-1438":{"nm":"סוללה ללייטסטיק","de":"\"תדלוק, בבקשה.\" ידיים עסוקות בהחלפת סוללות רגע לפני הכניסה. כדי שמתוך רבבות אורות האור שלי לא יכבה - סוללה קטנה אחת מאירה את הלילה הגדול ההוא בזוהר."},"ICON-1439":{"nm":"נרתיק ללייטסטיק","de":"מונח בעדינות ללא שריטה אחת, שמור בקפידה גם ללילה הבא של תרועות. גם כשהמקום הלוהט מתקרר לגמרי, לוקחים אותו הביתה עטוף בזהירות. גם לכלי ההצדעה יש מקום משלו, ולב שדואג למקום ההוא."},"ICON-1440":{"nm":"באנר תמיכה","de":"משפט כתוב על בד ארוך נפרש לרוחב היציעים. ברגע שקריאת עידוד שקשה מדי להגיד בקול נפתחת לרווחה, כנות של אדם אחד הופכת לצעקה של כולם. הבד ההוא הופך ממש לקול."},"ICON-1441":{"nm":"מיני באנר","de":"עידוד קטן שנכנס בדיוק לתוך כף היד. השלט התלוי הרחק שייך לכולם, אבל זה מתנפנף רק בקצה השולחן שלך. בהתנדנדות שקטה הוא מוכיח שגודל קטן לא הופך את הלב לקטן יותר."},"ICON-1442":{"nm":"מכתב מעריצים","de":"כתבתי מחדש את שם הנמען שלוש פעמים ומחקתי את המשפט הראשון שבע. קצות האצבעות רועדות ממש לפני סגירת המעטפה כי הלב כן מדי. כנות כבדה יותר מבול אחד מקופלת בפנים."},"ICON-1443":{"nm":"נייר עטיפה","de":"השנייה האחת לפני הפתיחה היא המרגשת ביותר, ונייר העטיפה יודע זאת טוב מכל אחד. גם כשהוא יודע שגורלו להיקרע בקרוב, הוא עוטף את עצמו במרקם העדין ביותר, בדומה ללב הנותן."},"ICON-1444":{"nm":"סרט","de":"קושרים חזק מדי וזה מחניק, רופף מדי וזה מתפרק, כך שלמצוא בדיוק את הנקודה שביניהם היא המסירות. צורת הלב נשמרת בקשר אחד שנבחר בקצות האצבעות. את השורה האחרונה של מתנה תמיד כותב הסרט במקומך."},"ICON-1445":{"nm":"כרטיס תודה","de":"תודה שנאמרת בקול מתפזרת ברוח, אבל כשכותבים אותה בכתב יד היא נשארת זמן רב. המעשה של להחזיר את הטוב שקיבלת, עם קצת נוסף עליו. תוך כדי לחיצת כל אות, הלב מתעמק פי שניים."},"ICON-1446":{"nm":"קופון ארוחת צהריים","de":"בפיסת נייר אחת זו דאגת הצהריים משתחררת. אורז טרי עם אדים עולים, ארוחה עם תוספות שממלאות כל תא מובטחת. קמע קטן שמגן ביציבות על אחר צהריים רעב."},"ICON-1447":{"nm":"קופון חטיף","de":"נוצר כדי שיוציאו אותו בשלוש אחר הצהריים, כשרעב קל שולח אות עדין. קופון שיודע שממתק קטן אחד מרים את מצב הרוח בחצי זרת. לא פרס גדול, אבל מגיע בעדינות בדיוק ברגע הנחוץ."},"ICON-1448":{"nm":"קופון בית קפה","de":"כוס חמה אחת ומקום ליד החלון, זה כל מה שהקופון הזה מבטיח. נראה כמו כלום, אבל למישהו זה הופך לפרס קטן על ששרד את היום. הזמנה עדינה שהניחוח שלה מגיע צעד אחד לפני."},"ICON-1449":{"nm":"שובר ניקיון למגורים","de":"פותחים חלונות לרווחה, מנערים שמיכות, יום שאפילו גרגר אבק אחד לא נשאר. מי היה מאמין שלא לעשות זאת בעצמך זה מותרות כאלה. כשהחדר נוצץ, גם הלב מתסדר בשקט."},"ICON-1450":{"nm":"ערכת תיקונים","de":"מברג, נייר דבק, כמה חלקים לא מזוהים. כשהכל מתכנס נראה שאין דבר שלא ניתן לתקן, אבל כשפותחים תמיד חסר חלק אחד. ובכל זאת, קופסה של ביטחון שאיכשהו מרגיעה רק בזה שאוחזים בה."},"ICON-1451":{"nm":"כרטיס מזל","de":"כרטיס ריק ללא מושב וללא מספר. הנקודה היא שהדבר הטוב שיקרה היום לא כתוב עליו. למלא את החלל הזה זה תפקידו של מי שנושא אותו בכיס."},"ICON-1452":{"nm":"קוביה","de":"חבר שמכיר הכי טוב את המילה הוגנות. הוא לא בוחר צד ואוהב את כל שש הפאות באותה מידה. באותו רגע שהוא עוזב את כף היד ומתגלגל, גם כישרון וגם קשרים מוותרים לרגע על מקומם למען המזל."},"ICON-1453":{"nm":"כרטיס נסיעה","de":"הבטחה שמכאן לשם, צעד אחד מספיק. פיסת נייר קסומה שמקפלת דרך ארוכה לגודל קטן ותוחבת אותה בכיס. ביום שמהססים לצאת, אין חוסם תירוצים טוב מזה."},"ICON-1454":{"nm":"כרטיס לניסיון נוסף","de":"במקום להושיט יד למי שנפל, כרטיס שדוחף בעדינות בגב ואומר לנסות שוב. הוא מספר בשקט הגדול ביותר שכישלון הוא לא הסוף אלא פסיק קצר. האומץ לעוד פעם אחת מצטבר כאן."},"ICON-1455":{"nm":"כרטיס סיום מהיר","de":"תחבולה עדינה שמדלגת קצת על ההמתנה. מי יכול להאשים לב שלא סובל אפילו שלוש דקות? כאן טמונה הנאה קצת אסורה, כמו להזיז את החול של שעון החול בקצה האצבע."},"ICON-1456":{"nm":"מאיץ ייצור","de":"אותן ידיים, אותו זמן, ובכל זאת התוצר כפול. כאילו אומר אל תשאלו על הסוד, הוא מסתובב בעליזות על שולחן העבודה. מכשיר קטן שמעניק כנפיים בשקט לשתי ידיים חרוצות."},"ICON-1457":{"nm":"סוכריית קרבה","de":"גם מבוכה שקשה לפרק במילים נמסה בקלות מול משהו מתוק. קשר שמתקרב זרת אחת יותר מאתמול מעל סוכריה אחת שנפתחה יחד. תגלית חמודה - שמתיקות היא בעצם קצב ההתקרבות."},"ICON-1458":{"nm":"ג'לי משקם מצב רוח","de":"ביום מעציב, משהו קר ורך פועל כמו קסם. נגיסה אחת וההבעה המעוננת משתחררת בשקט. לתקן את הלב הוא דבר יקר מטבעו, ודירוג R לא הודבק בו סתם."},"ICON-1459":{"nm":"אבקת נצנצים","de":"מפזרים קלות מעל משהו רגיל והוא הופך פתאום למיוחד. הזהות שלה היא סתם אבקה נוצצת, אבל ברגע שהיא נוגעת, העולם נראה קצת יותר נרגש - איזה פלא. כמו תבלין של אושר שמוזרק ליום היומיומי."},"ICON-1460":{"nm":"סרט במה","de":"כשעומדים על הבמה, אינספור אורות מוצאים אותך בבת אחת. X קטן על הרצפה מסמן את המקום ההוא בשתיקה. הדבר המדויק ביותר במקום שלא נראה הוא זה שבסוף תומך בבמה הגדולה ביותר."},"ICON-1461":{"nm":"קשר כבלים","de":"גיבור קטן שמסדר חוטים מסובכים בתנופה אחת. שברגע שהודק אי אפשר לשחרר, זה גם החיסרון וגם הקסם שלו. כלי חיוני ששומרים עליו בשקט מי שרציניים לגבי סדר."},"ICON-1462":{"nm":"כבל רזרבי","de":"חפץ שאין לו נוכחות כשיש אותו, ורק כשאין אותו נכסף בכל הלב. ישן עמוק בתיק מאחורי הקלעים ומתעורר בזינוק ברגע המכריע. הוא מוכיח את המילה מוכנות בגופו ממש."},"ICON-1463":{"nm":"טבלת בדיקת חזרות","de":"נייר צפוף תא אחר תא במסלולי תנועה, רמזים, ואפילו החלפות תלבושת. אם אפילו סימון אחד כאן חסר, ליבו של מישהו צונח. במה מושלמת מרימה את המסך רק אחרי שהטבלה הזאת מתמלאת כולה."},"ICON-1464":{"nm":"שלט תפאורה","de":"כאן בית קפה, שם סמטה, עוקבים אחר החצים אל עולם אחר לגמרי. שקר מצויר על לוח דיקט, אבל מול המצלמה הוא הופך לאמיתי. מדריך כן שהקדיש חיים שלמים להצבעה על הכיוון."},"ICON-1465":{"nm":"מיני גביע","de":"פיסת זהב אחת שברגע קבלתה מרגישה כאילו הגובה שלך גדל בזרת. הוא נוצץ על השולחן ואומר שזה באמת בסדר לא להיות ראשון, שהוא יודע כמה השתדלת היום. הנחמה הגדולה שפרס קטן מעניק."},"ICON-1466":{"nm":"תרמיל","de":"ברגע שחוגרים אותו על הגב, נדמה שאפשר לצאת לכל מקום. גם אם יש בפנים מעט, האפשרות ממלאת אותו עד גדותיו. ההרפתקה תמיד מתחילה במעשה של הידוק רצועות הכתף האלה."},"ICON-1467":{"nm":"מצפן","de":"לא להיבהל גם כשהולכים לאיבוד זה כי קצה המחט תמיד מצביע צפונה. האופן שבו הוא רועד זמן רב ובסוף מוצא את מקומו הוא ממש כמו לב אדם. מותר לתעות, הוא אומר בקצה הרועד שלו."},"ICON-1468":{"nm":"מחברת","de":"העמוד הראשון תמיד ריק. רק מי שאוחז בעט יודע מה לכתוב. אני פשוט מחכה שמחשבות היום יהפכו לכתב וישקעו בשקט מעליי. דירוג R הוא משקל הפוטנציאל שעוד יתמלא."},"ICON-1469":{"nm":"עיפרון","de":"שמותר לטעות זהו הצד העדין ביותר של הכלי הזה. כל עוד חברתו המחק לצדו, אפשר להתחיל מחדש כמה פעמים שרוצים. הוא מתקצר ככל שמחדדים אותו, אבל הקיצור הוא ההוכחה שאהבו אותו זמן רב."},"ICON-1470":{"nm":"פילם","de":"ברגע שהאור חודר, צבע היום ההוא נחקק במלואו. שברגע שצילום אחד חולף אי אפשר לחזור בו לעולם, זה גם המתח וגם הקסם. הבחירה של מי שרוצים לזכור בכוונה בקצב איטי יותר בעידן המהיר הזה."},"ICON-1471":{"nm":"מצלמה מיידית","de":"קליק, ואז המתנה קצרה. אוחזים בה ומנופפים אותה בעדינות, ורגע מטושטש מתבהר בהדרגה. מכונה קצת קסומה שתופסת את המקום הזה, כמות שהוא, בתוך גיליון נייר אחד."},"ICON-1472":{"nm":"תמונה ישנה","de":"ככל שהצבע דהה כך עבר זמן רב יותר. בכל פינה שחוקה נגעה יד של מישהו. שהתמונה הישנה ביותר נושאת את הזיכרון הברור ביותר, זה כנראה בגלל אותן נגיעות."},"ICON-1473":{"nm":"אלבום גזרים","de":"פיסות יקרות מדי לזרוק מתאספות ומתאספות לכרך אחד. כרטיס קולנוע דהוי, עלה כותרת יבש, פתק קצר אחד. גרוטאות בעיני אחרים, אבל למי שפותח אותו מתעורר לתחייה עידן שלם."},"ICON-1474":{"nm":"יומן שיט","de":"רוח וגלים של היום, ושורה אחת של הלב. לכתוב באמונה גם בימים שקטים הוא חוק השיט. ההוכחה שהגעת בשלום תמיד כתובה איפשהו בתוך התיעוד העבה הזה."},"ICON-1475":{"nm":"פיסת מפה","de":"זו רק פינה אחת מהשלם, ובכל זאת בלעדיה לעולם לא תמצא את הדרך. הריגוש של קצה קרוע שמתחבר בול לפיסה אחרת. לדירוג R יש נוכחות של החלק האחרון בפאזל."},"ICON-1476":{"nm":"מכתב בבקבוק","de":"מבלי לדעת מי יקרא, הוא מפקיד את עצמו בשקט לגלים. הוא לא מצפה לתשובה, רק מקווה שהלב הזה יגיע לאיפשהו. הדרך האיטית ביותר אך הרומנטית ביותר לשלוח דואר."},"ICON-1477":{"nm":"קוביה","de":"שש פאות מחייכות עגלגל כאילו אומרות, שוב אתה? אותה צורה בדיוק, ובכל זאת לתת תשובה שונה בכל גלגול הוא ההפכפכות הבלתי משתנה של החבר הזה. ברגע שהיא עוזבת את היד, מפקידים לרגע את הבחירה בידי הגורל."},"ICON-1478":{"nm":"טחנת רוח נייר","de":"היא קמה לתחייה רק כשהרוח נושבת. מונחת בשקט היא רק כנפי נייר, אבל תני למישהו לנשוף עליה והיא מתחילה להסתובב בעליזות. לא להתבייש בקבלת עזרה זו החוכמה של הפרח הקטן הזה."},"ICON-1479":{"nm":"סל פיקניק","de":"פותחים את המכסה וריח הגימבאפ מברך ראשון. דשא ירוק, מחצלת פרושה, וידיים שחולקות אוכל עם ידיים. הימים שהסל הזה התמלא היו, למרבה הפלא, תמיד תחת שמיים בהירים."},"ICON-1480":{"nm":"אגרטל","de":"אפילו גבעול אחד מוצב בה, ואוויר החדר משתנה. כשהוא ריק, לחכות בשתיקה זה תפקידו הראוי. אביזר הבמה הצנוע ביותר בחדר, שמנמיך את נוכחותו כדי שהפרח יזהיר עוד יותר."},"ICON-1481":{"nm":"עלה כותרת","de":"כשהרוח לוקחת עלה אחד, האביב נעשה קל יותר באותה מידה. העץ הזקן בחצר מציע כל שנה את אותה ברכה - שגם הנשירה היא חלק ממעשה הפריחה. ההתעופפות אינה הסוף, אלא מכתב שנשלח מראש לאביב הבא."},"ICON-1482":{"nm":"ורד","de":"להקים קוצים ראשונים היא הבטחה שלא לגעת בקלות ראש. בפנים מסתתר הלב האדום ביותר. מישהו הניח גבעול אחד בשקט למרגלות והלך, כותב את ליבו בצבע בלבד במקום בשם."},"ICON-1483":{"nm":"שושן","de":"לצד חרסינה לבנה טהורה תמיד הונח הפרח הלבן הזה. שהניחוח יגיע רחוק אך ההופעה לא תתערער. במקום שבו הוא בחר בטוהר במקום בפאר, השושן שומר בשתיקה על מידה אחת של כבוד."},"ICON-1484":{"nm":"צבעוני","de":"עומדים בשורה עם ראש מושפל מעט, נראים איכשהו כל כך מסודרים. הפרח שלוקח על עצמו את השורה הראשונה של ערוגת האביב. הכנות שלו לפרוח כולם יחד וליפול כולם יחד צובעת את העונה הקצרה בעומק הרב ביותר."},"ICON-1485":{"nm":"יקינתון","de":"על גבעול אחד הוא תולה פעמונים קטנים בצפיפות. מנערים ואין קול, אבל הניחוח מהדהד במקום זאת בחדר. בפתח האביב, מותרות עדין שמחליף כליל את אוויר החדר באגרטל אחד."},"ICON-1486":{"nm":"דגימת צפרדע","de":"גוף קטן שהזמן נעצר בו בתוך קופסת זכוכית. על התווית כתוב - 'שדות אורז ובריכות, הכי חיוני ביום שאחרי הגשם.' רק אחרי העצירה, אפילו טמפרטורת גדת המים שבה חי היצור נשארת בתיעוד."},"ICON-1487":{"nm":"דגימת לטאה","de":"אפילו כדגימה, הפקחות של לנתק זנב ולברוח לא נמחקת. אורח קטן שאהב חומות אבן חמות מהשמש. בפתק הסמוך כתוב בבירור הכיוון של המקום המוצף שאהב לטפס עליו."},"ICON-1488":{"nm":"רישום חפרפרת","de":"היומן של מי שנע מתחת לאדמה כתוב בגרגר העפר. איפה חפר ואיפה עצר, מפה של שבילים שלא נראים. גם הזמן שחי בגב לאור הופך למישהו לתיעוד החרוץ ביותר."},"ICON-1489":{"nm":"דגימת צדפה","de":"תבנית מוצקה שהגלים ליטשו ושלחו אלפי פעמים. אנשי שטח הבוץ ידעו מאיזה ים היא באה רק לפי גרגר הקליפה. צורתו של ים שפעם חי ונשם נשמרת בשלמותה בדגימה בגודל כף יד."},"ICON-1490":{"nm":"דגימת אלמוג","de":"במעמקי הים הוא גדל בקושי זרת אחת במשך מאות שנים. נראה כמו ענפים, אבל למעשה זה בית שנבנה יחד על ידי אינספור חיים קטנים. ככל שדבר איטי יותר כך הוא נשאר זמן רב יותר - האלמוג מוכיח זאת בשתיקה."},"ICON-1491":{"nm":"רמז איידונג","de":"קטע מסיפור שמפוזר איפשהו באי. פיסת נייר קטנה אחת מצביעה בשקט על הצעד הבא. כל הרפתקה, בסופו של דבר, מתחילה באיסוף עקבות פעוטים כאלה, כך אומר המדריך הוותיק."},"ICON-1492":{"nm":"פיסת חתימה","de":"כשהדוגמה המפוזרת מוצאת את מקומה, סימן אחד מושלם סוף סוף. פיסה שחקוקה בה מרקם ייחודי של מישהו. היא מסתירה את משמעותה עד שמתאימים אותה, וברגע שמתאימים אותה, היא הופכת סוף סוף לשם."},"ICON-1493":{"nm":"רסיס זיכרון במה","de":"גם אחרי ששיר מסתיים, חום שיורי נשאר בין המושבים. מקלפים את החמימות ההיא ומקשים אותה והיא הופכת לרסיס קטן כזה. שברים מפוזרים של מחיאות כפיים ותרועות, כשאוספים אותם בשקט, הלילה ההוא קם לתחייה בשלמותו."},"ICON-1494":{"nm":"חותמת דביוט","de":"ביום שקראו בשמך לראשונה, סימן הדיו שהוטבע על גב היד. גם הזהירות בייבוש כדי שלא יימרח הייתה חלק מקו הזינוק. חותמת קטנה אחת שומרת על יום מסוים מלהימחק לעולם."},"ICON-1495":{"nm":"מדליית האידול המוביל","de":"כובד שמותר רק למי שמגיע למקום הגבוה ביותר. אבל המדליה הזו כבדה לא בגלל המתכת. זה כי משקלן של אינספור ידיים שמילאו את הבמה יחד מתכנס בשלמותו לנקודה אחת."},"ICON-1496":{"nm":"מפתח קטן","de":"המפתח הראשון של המגורים תמיד היה לחדר הפנימי ביותר. מקום שבו למדו קודם איך לפתוח לפני איך לנעול. ביום העזיבה, על המתכת הקרה נשארת זמן רב החמימות שהשאירה כף יד."},"ICON-1497":{"nm":"תיבת אוצר","de":"עד שפותחים, אף אחד לא יודע מה בפנים. אי-הידיעה הזו היא האוצר האמיתי של תיבת האוצר. ברגע הקצר של הרמת המכסה, כל אחד חוזר לרגע לפעימת הלב של ימי הילדות."},"ICON-1498":{"nm":"שרטוט","de":"מעל קו אחר קו המשורטטים משבצת אחר משבצת, חי בניין שעוד לא נבנה. לפרוש את השרטוט הוא ללכת פעם אחת מראש דרך המחר. קו אחד שמשורטט היטב תומך במחר שלא יתמוטט."},"ICON-1499":{"nm":"כרטיס מתכון","de":"על כרטיס שחוק אחד כתוב טעם ידיה של סבתא בכמויות. מילים מעורפלות כמו 'קורט מלח אחד' הן הסוד המדויק ביותר. ככל שהכתב מתעמעם, כך המטבח שבו בישלו את המנה ההיא עולה בבירור רב יותר לזיכרון."},"ICON-1500":{"nm":"היתר מתקן","de":"גיליון נייר אחד הופך חלקת אדמה ריקה ל'מקום שאפשר להשתמש בו'. בניין חדש תמיד היה זקוק קודם לחותמת הכפר. היתר, בסופו של דבר, הוא חותם חם שאומר שמותר להתחיל כאן משהו."},"ICON-1501":{"nm":"היתר נמל","de":"לפני שספינה יכולה להטיל עוגן, עליה תחילה להחזיק בדף אחד זה. החותמת הדהויה של הנמל היא ברכת השלום הראשונה למי שבא מרחוק. בין היציאה להגעה, הנמל תמיד פותח את ליבו בדף נייר אחד."},"ICON-1502":{"nm":"תעודת אזרחות האי","de":"תעודה קטנה המעידה שהפכת לבן משפחה של האי הזה. בכפר הישן, כשהיה מגיע שכן חדש, היו מוסיפים את שמו לרשימה ומחלקים עוגות אורז חמימות. זהו רק דף נייר אחד, אך עליו כתובה קבלת הפנים הבהירה: \"עכשיו גם את/ה אחד/ת משלנו.\""},"ICON-1503":{"nm":"שלט שם למגורים","de":"בזכות שם אחד התלוי ליד הדלת, חדר ריק הופך סוף־סוף לביתו של מישהו. גם באולם האורחים העתיק היה תלוי תחילה שלט חרוט בכינויו של הבעלים. השלט קטן, אך בתוכו טמונה כל החמימות של \"כאן גר מישהו\"."},"ICON-1504":{"nm":"בול פנדום","de":"אפילו ההקפדה שבליקוק ובלחיצה חזקה הייתה חלק ממכתב שלם אחד. המעשה של הדבקת לב אוהב על פיסת נייר קטנה ושליחתו למרחקים. גם בעידן הדיגיטלי, יש מי שממשיך לשלוח את ליבו ביד, במתכוון."},"ICON-1505":{"nm":"תג האי הנוצץ","de":"כשמצמידים אותו לצווארון, אור קטן מלווה בכל דרך שהולכים בה. פוגשים ברחוב מישהו שעונד תג זהה - ומבינים זה את זה גם בלי מילים. הנצנוץ אינו התרברבות, אלא איתות שקט: \"שנינו אוהבים את אותו האי.\""},"ICON-1506":{"nm":"שולחן עבודה","de":"משטח מלא שריטות מעיד על היד שיצרה הכי הרבה דברים. המקום שבו תיקנו, חיברו וליטשו דברים. יותר משולחן נקי, דווקא שולחן עבודה מבולגן טומן בחובו הרבה יותר סיפורים."},"ICON-1507":{"nm":"תיבת אחסון","de":"ככל שדבר יקר יותר, כך ממהרים לקבוע לו מקום משלו. גם בני אדם בעבר שמרו מסמכים יקרי ערך בנפרד, בתיבות עץ פאולוניה. לאחסן היטב פירושו, בסופו של דבר, לקפל את היום הזה בקפידה למען מישהו בעתיד."},"ICON-1508":{"nm":"ארגז אספקה","de":"כשיש בשפע - אוגרים, כשחסר - שולפים ומשתמשים. כאן טמונה חוכמתה של תקופה שבה מחסן מלא פירושו לב שקט. לאגור פירושו להעניק מראש ארוחה חמה לעצמי העתידי."},"ICON-1509":{"nm":"תיבת קירור","de":"תיבה מלאה קרח שמרה על צינה גם בעיצומו של הקיץ. כאילו חוכמתם העתיקה של בתי הקרח הועברה לגודל כף יד. לשמור על הקור פירושו להאריך את שהותו של הרגע הכי טרי."},"ICON-1510":{"nm":"משאבת מים","de":"מזיזים את הידית מעלה ומטה, והמים העמוקים שבאדמה עולים ונובעים. מכונה כנה שנשפכה בשצף רק לאחר שדלי אחד של \"מי הזמנה\" נשפך תחילה לתוכה. את האמת הזאת - שצריך לתת קודם כדי לקבל - למד עוד הבאר."},"ICON-1511":{"nm":"מטהר מים","de":"נס קטן שבו מים עכורים יוצאים צלולים יותר, שכבה אחר שכבה. בני אדם בעבר סיננו מים בכדים שבהם הניחו שכבות חול ופחם זו על גבי זו. הצלילות אינה ניתנת בחינם - היא מסירות הלב שבסינון האיטי."},"ICON-1512":{"nm":"מעמד למזלף","de":"ברגע שלמזלף יש מקום מנוחה משלו, יומה של ערוגת הפרחים מתארגן. לקבוע מקום לתלות בו כלים היא הרגלו של מי שאוהב את עבודתו. כשמקום אחד נקבע, החצר כולה נעשית מסודרת יותר."},"ICON-1513":{"nm":"מעמד לחכה","de":"עד שמגיעה נגיסה, האדם עשוי להתרחק, אך החכה שומרת על מקומה. תנוחת ההמתנה של מי שדג את השנים לצד הנהר, טבועה כאן ללא שינוי. מעמד, בסופו של דבר, הוא משענת להניח בה את חוסר הסבלנות לרגע."},"ICON-1514":{"nm":"סל ליקוט","de":"משא ידה של האם, שהביאה בו חופן ירקות בר ופרח שדה בודד. מבין חריצי הבמבוק הקלוע נודף בעדינות ריח האדמה. תלוי מה ממלאים בו - סל ריק יכול להיות גם אביב וגם סתיו."},"ICON-1515":{"nm":"מכתש ועלי","de":"בום, בום - כשטוחנים דגן בקצב קבוע, יומו של הכפר מתעורר. כלי שקולות הלימה שלו מילאו את הסמטאות בימי חג. כדי להפוך דבר קשה לרך, נדרש קצב יציב של יד עובדת."},"ICON-1516":{"nm":"קרש חיתוך","de":"בכל סימן שהותירה הסכין חרוטה היסטוריה של ארוחה. קרש עץ מלא שריטות הוא אות הכבוד של המטבח בעל היד החרוצה ביותר. פעולת החיתוך מתחילה תמיד ברצון להגיש משהו בלב שלם."},"ICON-1517":{"nm":"סיר","de":"קול הרתיחה המבעבעת עדין מכל מוזיקה. בשעת שחר רעבה, שלוש הדקות של המתנה לבישול האטריות הן הנחמה האישית ביותר. על כל תחתיתו העגולה, מתחממת החמימות של הרצון להאכיל מישהו."},"ICON-1518":{"nm":"מחבת","de":"המיומנות לבשל דבר-מה ברגע אחד מעל האש תלויה במחבת הבודדת הזאת. ככל שהמשטח מתורגל יותר, כך הוא נוצץ בלי להידבק. מחבת ברזל יצוק ותיקה היא כשלעצמה עדות לשנים שעבר עליהן המטבח."},"ICON-1519":{"nm":"תנור אפייה","de":"בזמן שהדלת סגורה וממתינים, בפנים מתרחש בשקט קסם. זהו הזמן שבו הבצק תופח והצבע מבשיל. גם כשלא רואים, אם ממתינים באמונה, תוצאה חמימה פותחת את הדלת ויוצאת."},"ICON-1520":{"nm":"בלנדר","de":"אפילו דבר קשה, אם מכניסים אותו לכאן, הופך ברגע לכוס רכה. מערבולת קטנה שבה מתערבבים מרכיבים שונים ונולד טעם חדש. הרמוניה, בסופו של דבר, היא כשכל אחד מוותר קמעה על הפינות החדות שלו."},"ICON-1521":{"nm":"מקציף","de":"בתנועת שורש כף יד אחת נלכד האוויר, ובקצב הערבוב הנוזלי מתייצב ומתקשה. בזמן שהקצף מתנשא כפסגות, לא רק הבצק הוא שתופח. גם הרצון להאכיל מישהו היום תופח יחד איתו."},"ICON-1522":{"nm":"מטחנת פולים","de":"מסובבים את הידית על חופן פולי קפה, והארומה היא הראשונה שנשברת בין השיניים. עד שהזרוע מתעייפת, האבקה סוף־סוף עדינה, וכמידת המאמץ כן מעמיק הלגימה הראשונה. ההשקעה תמיד מתחילה בשורש כף היד."},"ICON-1523":{"nm":"טחנת קמח","de":"הגרגר נכנס בין האבנים ויוצא כאבקה לבנה. זה בסדר אם זה לא עדין בפעם הראשונה - אפשר פשוט לטחון עוד פעמיים. גם כדי להפוך גס לעדין יש סדר, כך מלמדת אותנו טחנת הקמח בשתיקה."},"ICON-1524":{"nm":"שולחן ניסור","de":"כשעולה גזע עץ, המסור קורא תחילה את סיביו. יש להתחמק מהקשרים ולנסר רק בדרך ישרה, כדי שהקרש לא יתעקם. לחתוך עץ פירושו, בסופו של דבר, לפרוש בסדר נאה את הזמן שעץ אחד חי אותו."},"ICON-1525":{"nm":"מכונת תפירה","de":"טרררר - קול המחט הנועצת בבד ורצה ממלא את הלילה המאוחר. תפר אחד מאחד שני יריעות לגוף אחד, ובכל תך נסתר בפנים תלבושת הבמה, תפורות בחוזקה שעות שינה אבודות של מישהו."},"ICON-1526":{"nm":"שולחן צביעה","de":"טובלים בד לבן ומוציאים אותו: תחילה הוא ירוק-בהיר, ורק כשהוא פוגש את האוויר הוא הופך לכחול. הצבע הזה, שאומרים שיוצא רק לאחר שלוש טבילות באינדיגו. שההמתנה עצמה הופכת לצבע - את זה למדתי לראשונה מול שולחן הצביעה הזה."},"ICON-1527":{"nm":"חצובת צילום","de":"ברגע ששלוש הרגליים נפרשות ונוגעות באדמה, העולם הרועד נעצר. תמונה שהייתה רועדת אילו הוחזקה ביד, מתבהרת על הבטחתן של שלוש הנקודות הללו. כדי להביט בדבר-מה זמן רב, צריך קודם לדעת לעמוד בלי לזוז."},"ICON-1528":{"nm":"מעמד תאורה","de":"מניחים אור על עמוד אחד, וכל פינה בחדר הופכת לבמה קטנה. מטים מעט את הזווית - הצללים מתארכים וההבעה קמה לתחייה. זהו לא כלי שמוחק את החושך, אלא כזה שמניח גם לחושך במקום, בעדינות."},"ICON-1529":{"nm":"מעמד מיקרופון","de":"ברגע שמתאימים את הגובה, נקבע המרחק בין הפה לשיר. גם כשמרפים את הידיים, הקול נשאר במקומו. רק על במה שבה שתי הידיים חופשיות, מתחיל באמת השיר המושר בכל הגוף."},"ICON-1530":{"nm":"מעמד תווים","de":"כשדף פתוח נשען באלכסון, התווים מסתדרים בשורה בגובה עיניו של הנגן. גם כשהתיבה הבאה מגיעה בתנועת יד אחת, המשענת אינה מתנדנדת. מאחורי נגינתו של מישהו תמיד יש מקום שקט ללא מילים."},"ICON-1531":{"nm":"חלקת גינה","de":"חורשים את האדמה ויוצרים תלמים, ועל פני הקרקע נוצרות שורות קטנות של הבטחה. הימים שלאחר טמינת הזרעים נראים כאילו לא קורה דבר, אך בוקר אחד עלי הפסיגה הרכים דוחפים את האדמה ועולים. זהו נוף שרק מי שהמתין יכול לראותו."},"ICON-1532":{"nm":"חלקת גינה פורייה","de":"אותו הזרע עצמו, אך באדמה הזאת העלים גדולים פי שניים. תוחבים אצבע פנימה, והאדמה השחורה והרכה נדבקת עד מתחת לציפורניים. הצמיחה הטובה הייתה, בסופו של דבר, מלאכה שביצעה בשקט הקרקע הנסתרת מתחת לרגליים."},"ICON-1533":{"nm":"חממה","de":"מתחת לתקרת הזכוכית, העונות זורמות פעימה אחת לאט יותר. גם כשבחוץ יורדת כפור, בפנים לח מלחות אמצע הקיץ. למען הדברים הרגישים לקור, מישהו לכד בשקט את אור השמש בתוך הגג."},"ICON-1534":{"nm":"ערוגת עשבי תיבול","de":"מחליקים בקצות האצבעות על העלים, והריח הוא הראשון לברך לשלום. בזיליקום, רוזמרין, נענע - בכל שם שקוראים, ריח אחר נדבק לאצבעות. ערוגה קטנה אחת משנה בעדינות את המטבח כולו."},"ICON-1535":{"nm":"מטע פרי","de":"באביב בצל הפריחה, בסתיו במשקל הפרי - הענפים מתכופפים. עולים בסולם, קוטפים פרי אחד ונושכים בו, וכל המתיקות שאספה השמש במשך שנה שלמה מתפוצצת בפה. זה כמו מכתב תשובה שהעץ שולח לאדם."},"ICON-1536":{"nm":"בול פטריות","de":"קודחים חורים בגזע כרות ונוטעים בהם נבגים, והעץ המת מגדל שוב משהו. כמה ימים אחר כך, בבוקר שבו נבטים באשכולות, מתחיל בשקט קיום חדש במקום שנחשב לסופו."},"ICON-1537":{"nm":"כוורת","de":"מקרבים אוזן ושומעים מבפנים רטט נמוך וחרוץ. אלפי משיקות כנפיים מצטברות בקושי לכף אחת של מתיקות. עמלו של יום שלם, שהלך ושב בין ערוגות הפרחים, מצטבר כאן, דביק וזהוב."},"ICON-1538":{"nm":"לול תרנגולות","de":"לפני עלות השחר, אלה היושבות על המוט הראשונות לרשרש. תוחבים יד לתוך הקש החם ואוחזים ביצה שעדיין נשארה בה חמימות. המקום שמכריז ראשון על הבוקר, הוא הראשון לערוך את שולחן הבוקר."},"ICON-1539":{"nm":"מרעה","de":"שדה רחב ידיים שבו מתערבבים ריח העשב וריח השמש. מעל הגבים המעלים גירה באיטיות בתוך הגדר, חולפים צלליהם של עננים. במקום הזה שאין בו למה למהר, אפילו הזמן זורם לאט, כמו לועס עשב."},"ICON-1540":{"nm":"בית מלאכה לגבינות","de":"חלב שנחלב זה עתה מתקשה לאט דרך התגבנות והבשלה. ממתינים חודשים אחדים על מדף קריר כמו מערה, וטעם עמוק חודר אל תוך הגוש הלבן. גבינה הוא שם שניתן רק לחלב שלא מיהר."},"ICON-1541":{"nm":"בית מלאכה לטופו","de":"משרים את הפולים, טוחנים ומרתיחים, וחלב הפולים המימי הופך ריחני ואגוזי. טיפת מלח ים אחת מאספת את המפוזר לטופו רך, ולחיצה שקטה נותנת לו קצוות מרובעים. כאן נמצאת היד שמנחמת לב מפוזר ומעצבת אותו."},"ICON-1542":{"nm":"מרפסת כדי החמצה","de":"בפינה שטופת שמש בחצר, כדי חרס נמוכים מתקבצים ומתחממים באור. פותחים מכסה, וריח של זמן ישן פורץ החוצה. טעם הרוטב שהאמא הגדולה החמיצה הוא, למעשה, אכילת השנים כף אחר כף."},"ICON-1543":{"nm":"טחנה","de":"כשהאבן מסתובבת בקרקוש, הדגן משתחרר לאבקה. אבק לבן צף בתוך אור השמש, ואנשים הממתינים ליצור קערת עוגות אורז ממתינים בתור. יום החג של הכפר תמיד כאילו התחיל על סף הבית הזה."},"ICON-1544":{"nm":"מאפייה","de":"מסדק דלת התנור נודף ריח חמאה וסוכר. עד שהבצק התפוח משחים, צעדיו של עובר אורח ליד החנות מאטים בלי משים. בכיכר לחם אפויה טרייה יש חמימות שאין לה תחרות."},"ICON-1545":{"nm":"דוכן טוקבוקי רחוב","de":"יריעת הניילון מתנפנפת ברוח, ורוטב הטוקבוקי מבעבע ומצטמצם. ערב שבו לוגמים מרק מכוס נייר לצד שיפוד עוגת דגים אחד, מקום שמפשיר קור ורעב בבת אחת. נחמה קטנה המונחת בקצה הסמטה."},"ICON-1546":{"nm":"מטבח מערבי","de":"המחבת מתחממת ושמן הזית מצליף. תזוזה אחת של האש יכולה לגרום לרוטב להסמיך או להישרף. במקום הזה, שבו שוקלים אפילו את איזון הצבעים על הצלחת, ארוחה הופכת ליצירה במאית שנוצרה בקפידה."},"ICON-1547":{"nm":"מטבח סיני","de":"מעל אש עזה, הווק מסתובב הנה והנה כמו רוקד. ברגע הקצר שבו הלהבות מזנקות, נלכד ריח המרכיבים בשלמותו. מהר וחם - הסוד של הבישול הסיני חבוי בנשימה האחת ההיא שמפסידים אם מהססים."},"ICON-1548":{"nm":"בית קפה","de":"דוחפים את הדלת, וריח פולי הקפה ומוזיקה שקטה מקדמים פנים ראשונים. מושב ליד החלון, כוס לאטה שמתקררת ומחברת פתוחה. כדי לתת לך לתפוס נשימה באמצע יום עמוס, העיר הסתירה חדרים קטנים כאלה בכל מקום."},"ICON-1549":{"nm":"חנות קינוחים","de":"בתוך תיבת הזכוכית, עוגות צבעוניות עומדות בשורה וממתינות ללקוחות. ברגע שקצה המזלג בוקע את הקצפת, קצות השפתיים הם הראשונים לעלות. מרשם קטן ומתוק שהופך אפילו יום עצוב לנסבל בעזרת פרוסה אחת."},"ICON-1550":{"nm":"אטליז","de":"מתחת לתאורה אדומה, הבשר מסודר לפי סיביו. במילה אחת - \"היום זה טוב\" - הסכין מחליקה בעובי מדויק. השובע של שולחן הערב מתחיל בשקט ביד הזאת, ששומרת מדי יום על אותו המקום."},"ICON-1551":{"nm":"עמדת הכנת דגים","de":"שולחן עבודה שבו מתערבבים ריח הדגים של השחר וקור הקרח. גם כשקשקשים מתעופפים והידיים קופאות, העין הבוררת את הטרי ביותר לא נעצרת. הדברים שזה עתה עלו מהים מוצאים כאן את דרכם אל השולחן."},"ICON-1552":{"nm":"מלחת מלח","de":"כולאים את מי הים, והשמש והרוח עושות את השאר. ממתינים ימים אחדים עד שהמים מתייבשים, וגבישים לבנים נובטים על הקרקע כמו כוכבים. חופן מלוחות הוא, למעשה, מתנה שהים והשמיים יצרו יחד לאט לאט."},"ICON-1553":{"nm":"מתלה ייבוש אצות","de":"על חבל ארוך תלויים זה לצד זה מיוק וקומבו, מתנדנדים ברוח. הדברים הרוויים במי ים כהים לירוק עז בזמן שהם מתייבשים. כאן תלוי הטעם הצנוע ביותר של הים, שנוצר יחד על ידי אור השמש ורוח החוף."},"ICON-1554":{"nm":"מזח קטן","de":"קרשי עץ שקועים למחצה במים מתנודדים בעדינות מתחת לרגליים. המקום המושלם בדיוק לקשור בו סירה קטנה אחת. גם היציאה הרחוקה וגם השיבה הבטוחה - שתיהן מתחילות ומסתיימות בפינה האחת הזאת."},"ICON-1555":{"nm":"מחסן נמל","de":"פותחים דלת עץ ספוגת רוח ים, ורשתות, חביות וחבלים ערוכים עד לתקרה. מטען שעומד לצאת למסע רחוק ומטען שזה עתה הגיע שוהים לרגע תחת אותה הגג. מקום כמו תחנת מעבר, שבה החזרה והיציאה חולפות זו לצד זו לרגע קט."},"ICON-1556":{"nm":"מגדלור","de":"רק כשים הלילה הופך לחשוך ביותר, הוא מתחיל סוף־סוף במלאכתו. האור המסתובב בוקע את הערפל ואומר: \"כאן יש דרך.\" שומר גבוה שלמען שובו הבטוח של מישהו, מסרב עד הסוף להירדם."},"ICON-1557":{"nm":"מספנה","de":"מקימים את השדרית ומחברים את הצלעות, ושלד הספינה מקבל צורה. בחצר שבה קול הפטיש מהדהד כל היום, ספינה שעדיין אינה מכירה את טעם המים חולמת על מסעה הראשון. מקום שמתחזק תחילה, כדי שיוכל לצאת לדרך."},"ICON-1558":{"nm":"תא הקלטה","de":"כשהדלת נסגרת, כל הקולות מבחוץ נעלמים ברגע אחד. מעבר לאוזניות נשמעים רק קול הנשימה שלך והקצב. בתוך דממתו של החדר הקטן הזה, נולד סוף־סוף קול שמותר לו לרעוד בלי מעצורים."},"ICON-1559":{"nm":"חדר מוזיקה","de":"הרמוניה הבוקעת מסדק הדלת ממלאת את המסדרון. מישהו מצביע על הסולם, מישהו סופר את הקצב. מקום שבו מותר לצלילים מגושמים ולצלילים בשלים להתערבב, כיתה חמה שבה כל שיר עושה את צעדיו הראשונים."},"ICON-1560":{"nm":"חדר פסנתר","de":"פותחים את מכסה המקלדת, ואבק דק שוכב על המקשים הלבנים. ברגע שהאצבעות נוגעות בהם, תהודה צלולה מתפשטת בכל החדר. אם יש ערבים שאינם בודדים גם כשלבד, זה כנראה בזכות הפסנתר האחד הזה."},"ICON-1561":{"nm":"חדר ריקוד","de":"לוחצים בקצות האצבעות, והרצפה דוחפת בחזרה כלפי מעלה. בזמן שארבעת קירות המראה מעתיקים את אותה התנועה ארבע פעמים, הגוף זוכר את הכוריאוגרפיה חצי פעימה לפני הקצב עצמו. החדר שבו הזיעה והנשימה שוהות הכי הרבה זמן; התנועות שגדלו כאן צועדות אל הבמה."},"ICON-1562":{"nm":"חדר כושר","de":"המשקל אינו משקר. אנשים מחפשים אותי בכל שחר בגלל שהם אוהבים את הכנות הזאת - בדיוק כמה שהרמת, כך נצבר בכתפיים. מה שנחרט לאט לאט במראה אינו שריר, אלא השעות שבהן החזקת מעמד בלי לוותר."},"ICON-1563":{"nm":"חדר יוגה","de":"שואפים אוויר עמוק, ומרגישים כאילו רצפת העץ תופחת יחד איתך. חדר שבו מקפלים בעדינות יום שדהר במהירות; על מזרון אחד, כל אחד חוזר לקצב נשימתו שלו. גם הלב הממהר מניח כאן את עצמו לרגע."},"ICON-1564":{"nm":"חדר איפור","de":"רגע לפני היציאה אל הבמה, אנשים הופכים כאן לרגע למישהו אחר. כשהנורות סביב המראה מחממות את הפנים באחידות, הרעד נדבק לקצה כרית הפודרה ומתחבא בשקט מאחורי הצווארון. המקום שבו התחפושת מתחילה ומסתיימת."},"ICON-1565":{"nm":"חדר תלבושות","de":"עד שתלבושת אחת לבמה מושלמת, הבגדים התלויים כאן נלבשים ומוסרים עשרות פעמים. בובת תפירה מסתובבת עם סיכות תפירה נעוצות בה, קווי תפר מסומנים בגיר. מאחורי הנצנוץ תמיד נותר סימן תפירה של מישהו."},"ICON-1566":{"nm":"תפאורת שידור","de":"למדתי מוקדם שדי לקשט כאמיתי רק את הצד שהמצלמה מצלמת. מאחורי הדיקט אין אלא שלד ריק. את פאר החזית תומכים תמיד בשקט קרשים בלתי נראים."},"ICON-1567":{"nm":"סטודיו לצילום","de":"הסוד הראשון הוא להטיל אור משלושה כיוונים ולמחוק את הצללים. אור המפתח מבליט את הפנים, אור המילוי את הצל, ואור מהגב את קצות השיער. ברגע נפילת התריס, יריעת רקע לבנה אחת לוכדת את החיוך הכי טוב של היום."},"ICON-1568":{"nm":"אולם קונצרטים","de":"בתוך החושך גבוה התקרה, אני נושא תמיד את אותה ההבטחה: שכשהמסך יעלה, אפילו המושבים הריקים יעצרו את נשימתם כאיש אחד. למען הרגע האחד שבו נופלת הפעימה הראשונה, אני עומד ריק בשקט כל השנה כולה."},"ICON-1569":{"nm":"תא מפגש מעריצים","de":"המרחק בין יד ליד הוא בדיוק רוחב שולחן אחד. ברכה קצרה, חתימה רועדת, מילה אחת שלא נאמרה עד הסוף - כולן חולפות בשורה. בתוך התא הקטן הזה, לב אוהב שגדל שנים ארוכות פוגש לראשונה פנים אל פנים."},"ICON-1570":{"nm":"מיטה","de":"אני תמיד הייתי הראשונה לקבל את קצה היום. לאחר שהרגליים הכבדות מהאימון והרעד שנותר מאחורי הבמה שוקעים כולם, הבוקר מתחיל שוב על קצות אצבעות קלות. לילה טוב, אני אומרת, ומחבקת בלי מילים."},"ICON-1571":{"nm":"מיטת קומתיים","de":"בין הקומה העליונה לתחתונה, חמישה שלבי סולם מחברים בין שני אנשים. קולות קטנים הנחלקים אחרי כיבוי האור, כוכבים זוהרים בחושך מודבקים לתקרה. המגורים הצפופים נעשים הרחבים ביותר בזכות הסיפורים העולים ויורדים בסולם בכל לילה."},"ICON-1572":{"nm":"מדף","de":"מה שמניחים עליי מגלה מי האדם. מכתב שהתקבל, גביע ראשון, כרטיס כניסה דהוי עומדים בשורה זה לצד זה. אינני רהיט להתרברבות, אלא מקום שמציג בשקט זיכרונות שלא הצליחו לזרוק."},"ICON-1573":{"nm":"שולחן כתיבה","de":"מחברת המילים פתוחה, ומעל סימני המחיקה נמתחים קווים חדשים שוב. כוסות נייר שהצטברו כל הלילה ומנגינה אחת בקושי שניצלה. המלאכה האיטית של העברת הלב למילים מתרחשת תמיד בשקט על המשטח השטוח הזה."},"ICON-1574":{"nm":"כיסא","de":"המילים \"שב לרגע\" הן, למרבה ההפתעה, אמירה עדינה. גם כשהישיבה מתארכת והאימון נמשך, משענת הגב סופגת בשקט את משקל הגוף. אני יודע שמי שעמד הכי הרבה זמן, מקבל את פניי בשמחה הגדולה ביותר."},"ICON-1575":{"nm":"ספה","de":"כדי להפוך את מגורי הלילה המאוחר לסלון, די בי לבד. נדחקים יחד לצפות בתוכנית בידור, ולפני שמרגישים - מישהו כבר נרדם נשען על משענת היד. המושב האמצעי השקוע מוכיח את חמימותו של הבית הזה."},"ICON-1576":{"nm":"שולחן","de":"כשמתיישבים סביבי, אף אחד אינו יושב בראש השולחן. תבשיל שזה עתה הורתח וקול נקישת כפות, אירועי היום מתאספים אל המרכז. כשמשטח עגול אחד נפרש, גם היום המפוזר מתיישב שוב יחד במקום אחד."},"ICON-1577":{"nm":"ארון בגדים","de":"בכל פעם שהעונה מתחלפת, סיפורים ישנים נשפכים מבפנים. תלבושות במה ובגדי יומיום כתף אל כתף, מאחורי הדלת הסגורה הבגדים ממתינים לתורם הבא. רק כשפותחים את הדלת, נקבע סוף־סוף היום שילבשו היום."},"ICON-1578":{"nm":"מראה","de":"גם מחמאה וגם פגם, אני מחזירה באותה כנות בדיוק. המקום לבדיקה האחרונה לפני היציאה לבמה; מולי, אנשים בוחרים את הבעתם ומיישרים את יציבתם. החברה הכנה ביותר אף פעם לא אומרת מילה אחת."},"ICON-1579":{"nm":"שולחן איפור","de":"בכל מגירה קטנה ישנה פנים אחרות. קופסה אחת לבמה, קופסה אחת ליומיום, קופסה מהדורה מוגבלת שנשמרת בקפידה. יושבים מול המראה, ומתחילים לאט להחליט מי בדיוק תהיה כשתצא בפתח היום."},"ICON-1580":{"nm":"שטיח","de":"המגע הראשון של כף רגל יחפה קובע את הטמפרטורה של החדר. הסימנים של הישיבה סביב, נשנוש ואכילה חטופה, נשארים כפלומה. רהיט שעובד מהמקום הנמוך ביותר, ומחמם את הרצפה הקרה עוד קמעה."},"ICON-1581":{"nm":"וילון","de":"כמה מהבוקר להכניס - אני זו שמחליטה. פותחים אותי מעט, ואור השמש נכנס ארוך; סוגרים היטב, ואפילו איחור בקימה נהיה נסלח. לעמוד בין החלון לחדר ולכוון בשקט את כמות האור, זהו תמיד התפקיד שהופקד בידיי."},"ICON-1582":{"nm":"מנורה","de":"אותו החדר עצמו הופך לזמן שונה לחלוטין בהתאם לצבע האור. אור צהוב מותח את הערב לאורך, אור לבן מעיר את השחר בבהירות. קוסם בגודל כף יד, שבמתג אחד משנה בעורמה את מצב הרוח של היום."},"ICON-1583":{"nm":"שעון קיר","de":"קול מחוג השניות נשמע רק בחדר שקט. ככל שהאימון מעמיק, שוכחים אותי, ואז לפתע מרימים מבט ומגלים שבחוץ כבר שחר. בלי להאשים אף פעם את הזמן שחלף, אני פשוט מצביע בשתיקה על הקו הבא."},"ICON-1584":{"nm":"אגרטל","de":"גם כשהפרחים קמלים, אינני משאירה את מקומי ריק. כלי שמכיל לרגע לב שהתקבל; כל עוד יש יד שמחליפה את המים, השולחן נשאר מואר. גם כשאני ריקה, אני עומדת בצורה של המתנה למישהו."},"ICON-1585":{"nm":"מסגרת פוסטר","de":"גם לתלות פנים אהובות על הקיר דורש הקפדה. מקום שאור השמש לא נוגע בו ישירות, מסמר אחד שמאוזן בדיוק. דף נייר אחד שוכב בעדינות מאחורי הזכוכית, והוא הראשון לברך אותי לשלום בכל בוקר כשאני נכנס לחדר."},"ICON-1586":{"nm":"לוח פוטוקארד","de":"לסדר לפי אלף-בית או לפי סדר יציאה - הדילמה המאושרת הזו היא כבר תחילתו של הפנדום. תא ריק אחד הוא מקומו של אהוב הלב שטרם נפגש. ככל שהלוח מתמלא כרטיס אחר כרטיס, הוא הופך לכרוניקה קטנה משלי."},"ICON-1587":{"nm":"מעמד לייטסטיק","de":"מוציאים את הסוללה, הידית כלפי מעלה. יש טכניקה גם בזווית שבה מטים ומעמידים אותו באלכסון. בהמתנה לתשואות הבאות, המקל מכבה את אורו בדיוק כאן ושוכב מסודר. מנוחה טובה - וההדלקה הבאה תהיה בהירה יותר."},"ICON-1588":{"nm":"מדף גביעים","de":"בשורה הקדמית ביותר מונח הישן ביותר. מפסלון של תחרות קטנה ועד גביע של במה גדולה, הם עומדים בשורה לא לפי גובה אלא לפי סדר הלב. בכל פעם שמלטפים ומצחצחים אותם, הרעד של אותו יום על הבמה נדבק שוב לקצות האצבעות."},"ICON-1589":{"nm":"סל פיקניק","de":"פותחים את המכסה, וריח שמש אביבית נודף החוצה ראשון. גימבאפ, תרמוס ומחצלת אחת מסודרים בקפידה, מוכנים לצאת אל השדות. צעדיו של מי שנושא אותי תמיד קלים, משום מה, כף יד שלמה יותר מהרגיל."},"ICON-1590":{"nm":"עציץ קטן","de":"כף יד אחת של אדן חלון מספיקה לי. ירק קטן שסולח בנדיבות גם כשמשכיחים ממנו את ההשקיה. בפינת שולחנו של אדם עסוק, אני פורש עלה נוסף בכל יום, ומעביר בשקט את דרישת השלום של היום."},"ICON-1591":{"nm":"עציץ גדול","de":"בזמן שגובהי גדל, האדם גדל יחד איתי. כשהעלים הרחבים שתופסים פינה בסלון קולטים את השמש ומטילים צל, גם החדר נכנס בשקט לתוך העונה. סיפוק שרק מי שלא שוכח להשקות מכיר."},"ICON-1592":{"nm":"סט נר ריחני","de":"ברגע שמדליקים את הפתיל, אוויר החדר שוקע מדרגה אחת. הריח מתפשט לאט, מחמם ומשלח את העייפות שנותרה מאתמול. עם להבה קטנה אחת, לסיים את קצה יום עמוס כמו טקס שקט."},"ICON-1593":{"nm":"מקרר מיני","de":"פותחים דלת בלילה מאוחר, ופחית משקה קרה מקבלת את פניי. זמזום רטט קטן הופך את המגורים הריקים לפחות בודדים. אני לא יכול לנהל משק בית גדול, אבל בטיפול בשחר רעב אין כמוני."},"ICON-1594":{"nm":"כובע רשת לציד חרקים","de":"ברגע שמניחים אותו על הראש, שדה קיץ עוקב אחריך על הכתפיים. הרשת העגולה מסננת בעדינות את אור השמש, ובכל צעד נע בעדינות ריח העשב. כובע שעוטף עונה שלמה, טוב גם אם לא תפסת אפילו שפירית אחת."},"ICON-1595":{"nm":"שקית רשת ללקיטה","de":"תלויה על המותניים, היא הופכת לבת לוויה בליקוט. לכווץ מעט את הפתח כדי שהניצוד לא יברח בחזרה - זהו התכסיס הראשון שנלמד בשדות. שקית בד קלה אחת חובקת בחוזק את יבול היום."},"ICON-1596":{"nm":"צנצנת תצפית לחרקים","de":"אני יודעת שלאורח ששוהה רק לרגע, חורי אוויר הם החשובים ביותר. נתיב נשימה קטן קדוח במכסה, עלה עשב אחד פרוש בתחתית. גם החזרה אל תוך העשבים בתום התצפית היא חלק בלתי נפרד מהזוג הזה."},"ICON-1597":{"nm":"קופסת סיכות דגימה","de":"גם בזווית האחת שבה נועצים סיכה באלכסון חיה מיומנות. עמוק מדי - זה נשבר, רדוד מדי - זה מתנדנד, לכן יש לחלק בדיוק את כוח קצות האצבעות. קופסה שמכילה בשקט את הקפדתו של מי שרוצה להתבונן זמן רב בחיים קטנים."},"ICON-1598":{"nm":"מכסה טרריום","de":"תפקידי הוא לשמור על הגבול בין הפנים לחוץ. סוגרים חזק מדי - זה נחנק, משאירים רופף מדי - זה הולך לאיבוד, לכן אני תמיד משאיר פער דמוי שריטה. להגן פירושו, בבירור, משהו שונה לגמרי מלכלוא."},"ICON-1599":{"nm":"צלחת האכלה לפרפרים","de":"מניחים במרכז צמר גפן ספוג במי סוכר, והכנפיים מתקבצות. רדוד ורחב, בעומק שבו רגליים קטנות לא ישקעו - זהו הסוד. צלחת אחת קוראת בשקט לאורחים שעוצרים לרגע בגן שטוף שמש."},"ICON-1600":{"nm":"מנורת פיתוי לחרקים","de":"מדליקים אותה בעמעום בתוך החושך, וכנפיים קטנות מתקבצות בעקבות האור. הבהירות עדינה, המקום רחוק מבני אדם. מפתה עדין ביותר, שמשקיט את ליל הקיץ המזמזם לשקט רב יותר."},"ICON-1601":{"nm":"מדבקת חרק","de":"שש רגליים וזוג משוששים - בתוך פיסת נייר בגודל ציפורן, ישנים לו חיים קטנים. הדביקו אותה בעדינות בפינת המחברת, ורצועת אחו שקטה נפרשת בין דפי הספר."},"ICON-1602":{"nm":"תג היתר איסוף","de":"לפני שמרימים את רשת החרקים, המבוגר שואל קודם: כמה, ועד לאן. תג קטן אחד זה מותח קו רך בין הסקרנות הנרגשת לבין ההבטחה שיש לשמור."},"ICON-1603":{"nm":"קופסת פיתיון","de":"פותחים את המכסה ועולה ריח שחר קריר ודגי. אולי לא הפיתיון הוא שקורא לדגים, אלא הלב שיודע לחכות בשקט עד שהמצוף ירעד."},"ICON-1604":{"nm":"ארגז מצופים","de":"ארון קטן שבו מצופים צבעוניים שוכבים לישון, תא אחר תא. אחד הוא בוקר של אגם שליו, אחר - צהריים של זרם סוער. לכל ארשת של המים מקופל בעדינות בן הזוג המתאים."},"ICON-1605":{"nm":"סליל חוט דיג","de":"אין ללפף חוט משוחרר סביב האצבעות. כרכו אותו מחדש בקפידה על הכלי העגול הזה, והסבך מתיר את עצמו בשקט. זה מזכיר את המגע שמסדר מחדש יום שהתרופף."},"ICON-1606":{"nm":"מסיר קרסים","de":"רק מי שנדקר כשניסה לשלוף קרס תקוע בידיים חשופות, מזהה את הכלי הזה. דרך שכואבת פחות, גם ליצור הקטן וגם לקצות אצבעותיי. התחשבות תמיד מתחילה בקצוות הקטנים כאלה."},"ICON-1607":{"nm":"כיסוי את חפירה לצדפות","de":"שכבה אחת שעוטפת את להב האת שזה עתה נחפר משטח הבוץ. כדי שהבוץ והמים המלוחים לא ינגסו בלהב, היא תוחבת בעדינות מנוחה דקה ורכה בין הים לכלי."},"ICON-1608":{"nm":"כרטיס לוח שפל וגאות","de":"מתי המים עולים ומתי הם נסוגים - כרטיס בגודל כף יד מספר בשקט. לוח שנה קטן שבו אדם העתיק את ההבטחה הישנה שהירח והים כרתו יחד."},"ICON-1609":{"nm":"מברשת ניקוי לאקווריום","de":"מטאטאים בעדינות את האצה הירוקה שנדבקה לדופן הזכוכית, והאור חוזר לחלחל אל העולם הקטן שמתחת למים. להאיר את יומו של מישהו - זה בדרך כלל זורם בשקט כזה."},"ICON-1610":{"nm":"שבב טמפרטורה לאקווריום","de":"מספר אחד מהבהב, וכשהוא נעצר במעלה הנכונה, הדגים סוף סוף נרגעים. תא אחד של חום, לא קר מדי ולא חם מדי. הטיפול מגיע גם למקומות הבלתי נראים."},"ICON-1611":{"nm":"מבחנת תצפית לחיי ים","de":"אורח קטן שוהה לרגע בתוך השפופרת השקופה. סופרים בשקט את סנפיר הגב, ואז משיבים אותו לים. תצפית אינה החזקה, אלא השאלה לזמן קצר."},"ICON-1612":{"nm":"מברשת מאובנים","de":"מה שמעיר את מרקם האבן שישנה עשרות מיליוני שנים, אינו פטיש אלא קצה מברשת רך. לפני זמן שיתפורר אם ימהרו, הזהירות הופכת לנימוס העמוק ביותר."},"ICON-1613":{"nm":"מכסה למברשת חפירה","de":"כשקצה המברשת מתייבש לגמרי, גם העפר לא נופל בעדינות. מכסה קטן שומר את נשימת המברשת לחה. יד שמוקירה את כליה, צועדת בכך את הצעד הראשון של החפירה."},"ICON-1614":{"nm":"לוחית דגימת שכבות אדמה","de":"בתוך רצועת אדמה בגודל כף יד, מאות שנים מונחות שכבה על שכבה. הרימו אותה בעדינות אל הלוחית הזאת, ודוגמת הזמן שהייתה בלתי נראית, מציירת את קוויה ועולה לאיטה."},"ICON-1615":{"nm":"מגש שברי עצמות","de":"הניחו את השברים המפוזרים תא אחר תא, וחיים שהתפזרו ברוח מגששים לאיטם בחזרה אל מקומם. שחזור הוא מעשה של שאילת סדר אבוד בעדינות."},"ICON-1616":{"nm":"סרט שיקום","de":"רצועה דקה אחת שמאחדת את מקום השבר. היא לא טורחת להסתיר את הצלקת, אלא מחבקת ומחזיקה אותה ברוך. היא מוכיחה בשקט שגם מה שנשבר יכול לשוב ולהיות שלם."},"ICON-1617":{"nm":"כיסוי שלט תצוגה","de":"דף אחד שמכסה בעדינות את תווית השם מעבר לזכוכית, כדי שלא תדהה. הוא נושא בתוכו את המשאלה שהמשפט הקצר על מי חי, והיכן, יישאר קריא בבירור גם בעתיד הרחוק."},"ICON-1618":{"nm":"תג מחסן אוצרות","de":"חדר עמוק שבו אוצרות שמעולם לא יצאו אל האור ישנים. על כל דבר בתוכו תלוי תג שם קטן - כדי שגם בלי לעמוד במקום מואר, לעולם לא יישכחו."},"ICON-1619":{"nm":"מעטפת תרומה למוזיאון","de":"מישהו מוסר בלי מילים את מה שאסף במשך חיים שלמים. מה שטמון במעטפה הזו אינו חפץ, אלא לב שטופח זמן רב. שיתוף הופך לתערוכה שנשארת הכי הרבה זמן, ומאירה על מישהו."},"ICON-1620":{"nm":"שבב מספור דגימות","de":"בדיוק במקום שבו אספו אותו, מקצים בשקט מספר קטן. מתי, והיכן, פגשו אותו לראשונה. תגלית שלא נרשמה מתפזרת עד מהרה כמו ערפל הבוקר."},"ICON-1621":{"nm":"בקבוק שביב מטאור","de":"שביב שנפל בחתך על פני שמי הלילה נלכד בתוך בקבוק זכוכית. קרן אור אחת שדעכה עוד לפני שהספיקו לבקש משאלה, נוצצת שוב עתה, בעדינות רבה, בתוך כף היד."},"ICON-1622":{"nm":"חוט פעמון רוח מצדפות","de":"משחילים על חוט צדפות שנאספו אחת אחת על החוף, ותולים מהמרזב. בכל פעם שהרוח חולפת, בקול נקישות עדין, הים של אותו קיץ נכנס בשקט אל תוך הבית."},"ICON-1623":{"nm":"טיפת טל קשת בענן","de":"טיפה אחת שהצטברה על קצה עלה אחרי שהגשם חלף. בתוך העיגול הזה שוכנים כל השמיים ושבעת הצבעים במעגל אחד. יש רגעים שבהם הדבר הקטן ביותר מכיל את הנוף הרחב ביותר."},"ICON-1624":{"nm":"בקבוק איסוף ערפל","de":"הבאתי הביתה בקבוק מלא בערפל השחר ממורדות ההר. אוחזים בו והוא קריר ומעונן בלובן חלבי. תאווה קטנה ורכה - לשמור לרגע לצידך את מה שאי אפשר להחזיק."},"ICON-1625":{"nm":"כוסית לכידת טל","de":"כוסית קטנה שקולטת את הטל שעלי הדשא אספו טיפה אחר טיפה במשך הלילה. אפילו לא לגימה שלמה, אך החלק הצלול והנקי ביותר של הבוקר נח שם בשלווה."},"ICON-1626":{"nm":"סיכת סרט משב רוח","de":"סרט שנקשר בדיוק בדמות המרקם שהרוח הותירה בחלופה. הצמידו אותו לשיער, ובכל צעד רוח עדינה מלווה בנועם. קלילותו של יום אביב, קשורה בשקט בסיכה אחת."},"ICON-1627":{"nm":"קפסולת קול גלים","de":"קרבו אותה בעדינות אל האוזן, וגלי הים הרחוק גואים. כאילו מישהו אטם בזהירות בתוך גרגר קטן את הצליל ההוא ששמרתם פעם בקונכייה בילדות."},"ICON-1628":{"nm":"פירור כוכב בחול","de":"אחזו בחופן חול על חוף לילי, ופירורי כוכבים מעורבים בו, נוצצים. אם נפלו מן השמיים או שהגלים טחנו אותם דק, איש אינו טורח לשאול."},"ICON-1629":{"nm":"שבב יומן מזג אוויר לאי","de":"שמי האי משנים את דעתם כמה פעמים ביום. רשמו בקפידה בהיר, ערפל וממטר על שבב קטן, ותוכלו לפרוש שוב את שמי אתמול היום."},"ICON-1630":{"nm":"ערכת מדרגות למצוק","de":"מדרגה אחת, ועוד אחת, לעלות ולרדת במורד התלול. הרכיבו את החלקים המפוזרים, וגם צוק הופך לטיול נינוח. לסלול דרך - זה להניח מראש את הצעד הבא של מישהו."},"ICON-1631":{"nm":"גליל דוגמת שביל עפר","de":"גליל שהעתיק את המרקם עצמו של שביל עפר רך. פרשו אותו במהירות, ושביל כפרי שמעורר חשק ללכת בו יחפים נפרש בשקט מתחת לרגליים."},"ICON-1632":{"nm":"שבב דוגמת שביל אבן","de":"דוגמת אבני הריצוף שריצפו פעם את הסמטאות הישנות נשמרת בשלמותה בתוך שבב קטן. בכל צעד, נקישה אחר נקישה, צעדי הכפר העתיק שבים לחיים בקצות האצבעות."},"ICON-1633":{"nm":"חתיכת גדר חוף","de":"קטע אחד מהגדר הנמוכה שהוצבה בחול כדי שהגלים לא יעברו. שומר גבול קטן ושתקן, שעומד וממתח קו רך בין הים לחול."},"ICON-1634":{"nm":"טלאי שיקום דשא","de":"פיסת ירוק שמניחים בעדינות על מקום שנרמס עד לחשוף. תוך ימים ספורים העשבים אוחזים ידיים ומכסים את החלל הריק. הטבע תמיד יודע איך לרפא את עצמו."},"ICON-1635":{"nm":"יתד סימון תעלת מים","de":"יתד שמראה מראש את הדרך שבה יזרמו המים. כדי שמי הגשם לא יתעו בלי לדעת לאן, שלט קטן נעוץ באדמה עומד בשקט גם בימי גשם."},"ICON-1636":{"nm":"חלק לגשר קטן","de":"חלק אחד מגשר זעיר שמחבר בין שתי גדות הנחל. בין הצד הזה לצד ההוא, ההבטחה שאפשר לחצות בכל עת מתחילה בשקט בחלק הקטן הזה."},"ICON-1637":{"nm":"כיסוי מעקה לתצפית","de":"במקום הגבוה ביותר באי, גימור אחד שעוטף את קצה המעקה. הוא תומך ושומר בשקט על המקום שידיהם של הבאים להביט למרחקים נוגעות בו הכי הרבה."},"ICON-1638":{"nm":"בסיס למדורה","de":"לפני שמניחים את הזרדים, מקום שמחזיק כדי שהגחלים לא יתפזרו. מעליו, לילות של שיחה חמימה תוך הבטה בכוכבים בוערים חם לאורך זמן רב."},"ICON-1639":{"nm":"גליל דוגמאות טפט","de":"אווירת החדר מתחילה בקיר אחד. לפרוש גליל קטן ולבחור צבע - זה לשרטט מראש, בשקט, איזה מין ימים רוצים לחיות מכאן ואילך."},"ICON-1640":{"nm":"שבב דוגמת ריצוף","de":"בודקים תחילה עם קצות האצבעות את מרקם הרצפה שהרגליים היחפות ייגעו בה. חם או קריר - בשבב קטן אחד זה תלויה הנוחות של הימים שיחיו מכאן ואילך."},"ICON-1641":{"nm":"ערכת ווים לתקרה","de":"ברגע שתולים וו אחד על הקורה, התקרה הריקה הופכת למקום שמחכה למישהו. פעמון רוח, או עציץ? הוו הקטן הזה נושא את המשקל, אבל מה לתלות - זה נקבע בלב הדיירים."},"ICON-1642":{"nm":"קרום הצללה לחלון","de":"אור הצהריים כן מדי, ולכן מלבישים את החלון בשכבה דקה אחת. אור השמש נכנס כרגיל, אך הפינות מתרככות, וכל מה שבחדר נעשה בגוון משמש רך. זו לא חסימה, אלא פיזור עדין ואוהב של האור."},"ICON-1643":{"nm":"כיסוי לפעמון דלת","de":"באומרו שגם לפעמון שאורח לוחץ עליו דרושים בגדים, מישהו הלביש אותו בכיסוי עגול. הוא חוסם גשם, חוסם אבק, ומעל הכל - הפה העגול הקטן הראשון שמעביר את הברכה \"מישהו גר כאן\"."},"ICON-1644":{"nm":"מעמד לספר אורחים","de":"מעמד שהוצב כדי שכל בא ילך אחרי שכתב את שמו. לפני שהדיו מתייבש, שורת שלום זורמת מקצה העט. כשצעדי המבקרים מצטברים שורה אחר שורה, המחברת הריקה הופכת עד מהרה לאלבום העבה ביותר של הבית הזה."},"ICON-1645":{"nm":"סיכת סידור רהיטים","de":"את מקום השולחן שהיססתם אם להזיז - סיכה אחת נועצת אל הרצפה ומכריעה. מסמר קטן שאוחז בעדינות ברגלי הרהיט. מקום, ברגע שנקבע, הופך לאהוב - כך מהנהנת בשקט רצפת העץ."},"ICON-1646":{"nm":"מסגרת תווית אחסון","de":"מה שמור היכן - המגירה לעולם לא מסוגלת לומר. לכן שיבצו תווית שם במסגרת מרובעת שתדבר במקומה. ברגע שתווית אחת מתיישבת, התאים המבולגנים משיבים לעצמם את שמם ונרגעים."},"ICON-1647":{"nm":"מקל מפיץ ריח לחדר","de":"הריח שהרטיב את קצה המקל מתפשט לאיטו כלפי מעלה. פעם לבנדר, פעם אחו רחוץ בגשם. כשחוט ריח בלתי נראה מחליף את אוויר החדר, עייפות של יום שלם משתחררת בעדינות מכתפיו של מי ששב הביתה."},"ICON-1648":{"nm":"קליפס לשקית זרעים","de":"זרעים שנקנו באביב ולא הספיקו להיזרע, מהודקים היטב אל השקית באמצעות קליפס. אם ולו גרגר אחד יבריח החוצה, העונה הבאה תקטן בשורה. בתוך הסגירה הקטנה ישנה לה גינה שלמה של השנה הבאה."},"ICON-1649":{"nm":"מגש שתילים","de":"ממלאים כל תא באדמה כדי ליצור את החדר הראשון לנבט צעיר. חיים אחד לחור, תלמידי כיתה א' שגדלים מיושרים בשורה. הציצו פנימה, ובוקר של ירוק שקורא בשמות תא אחר תא מתחיל מחדש מדי יום על המגש."},"ICON-1650":{"nm":"סיכת סימון השקיה","de":"\"אני צמא.\" העציץ לא יכול לדבר, אז שלט קטן נעוץ באדמה שולח את האות במקומו. כשהצבע משתנה, זה הזמן להשקות. התרגום הקטן ביותר בין הצמח לאדם, מצטמצם כולו למקל בגודל כף יד זה."},"ICON-1651":{"nm":"חוט תמיכה לצמחים","de":"גבעול שגדל לגובה עלול להתנדנד תחת משקלו, לכן קושרים אותו בעדינות אל יתד תמיכה בחוט רך. הדוק מדי - ונחנק, רופף מדי - ונופל, כך שביד הקושרת נדרש חום בדיוק במידה הנכונה. גם בגדילה יש צורך במישהו לצד."},"ICON-1652":{"nm":"רשת הדברת מזיקים","de":"רשת ארוגה בדקדוק חוסמת בשקט את הפיות הקטנים שמכוונים אל העלים הרכים. היא מעבירה רוח ואור ומסיטה רק את מה שיזיק - שוער בלתי נראה. הגינה שלווה בזכות הדאגה הארוגה ברשת הצפופה הזו."},"ICON-1653":{"nm":"כרטיס מדידת אור שמש","de":"כמה שמש מגיעה לכאן? מציבים כרטיס אחד בערוגה ושואלים בשקט. ככל שצבעו מעמיק, כך יותר אור נקלט היום. פיסת נייר קטנה זו מפרידה בין מקומו של הילד שאוהב שמש למקומו של זה שנוח לו בצל."},"ICON-1654":{"nm":"רצועת בדיקת חומציות אדמה","de":"הצמידו רצועת בדיקה לאדמה, ומוורוד ועד כחול, האדמה חושפת בצבע את מצב רוחה. במקום שאינו חמוץ מדי ואינו מריר מדי, השורשים נושמים הכי בנוח. רגשותיה הנסתרים של האדמה נקראים תא אחר תא."},"ICON-1655":{"nm":"תווית לסל קטיף","de":"האם מה שנקטף היום הוא חסה או עגבניות שרי? מצמידים תווית שם לכל סל. בבוקר קטיף רווי בריח אדמה וירק, ברגע שהתווית מודבקת, הסל הופך לציון הדרך הראשון בדרך אל השולחן."},"ICON-1656":{"nm":"צנצנת אחסון זרעים","de":"אוספים את הזרעים שנקצרו השנה לתוך צנצנת זכוכית ושולחים אותם לאביב הבא. סוגרים את המכסה, והזמן נעצר לרגע, בעוד הגרגרים הקטנים ממתינים לתורם בחשיכה. צנצנת שדומה למכתב שנשלח מעבר לעונה שלמה."},"ICON-1657":{"nm":"סרט הרכבה","de":"מצמידים ענף חתוך לענף חדש, כורכים אותם בסרט, ולאיטו השניים נעשים לגוף אחד. מיץ הצמח שב וזורם דרך מקום השבר, הפצע נרפא לאיטו. חיבור, בסופו של דבר, הוא מעשה של קבלת המרקם של הזולת."},"ICON-1658":{"nm":"כיסוי למספריים לגיזום","de":"מלבישים כובע קטן על קצה המספריים החדות. בעוד היד שדיללה את הענפים נחה, הלהב נשאר חד והיד נשארת בטוחה. בטענה שגם לכלי שסיים את עבודתו דרושה פיג'מה, הגינה משכיבה את כליה בקפידה."},"ICON-1659":{"nm":"קופסת מיון זרעי פרחים","de":"בלזמין, ורדונית, פרח-הלילה - זרעים שונים בשם ובצבע, כל אחד מקבל חדר משלו בתא נפרד. אם יתערבבו, באביב לא יידעו מי הוא מי. המחיצות הקטנות בתוך הקופסה משרטטות מראש את תוכנית הגן שעוד לא פרח."},"ICON-1660":{"nm":"מגש גלגלים לעציץ","de":"הרכיבו ארבעה גלגלים, וגם עציץ כבד יוצא לטייל בעקבות אור השמש. חלון מזרחי בבוקר, צל בצהריים. ירק שהיה מרותק במקומו בגלל משקלו, מתגלגל בעקבות האור כל היום בחיפוש אחר המקום הטוב ביותר."},"ICON-1661":{"nm":"חוט הכוונה לצמח מטפס","de":"קנוקנת מגששת באוויר הריק, לא יודעת לאן, וחוט מוליך אותה בעדינות אל המסלול הנכון. למעלה, ועוד למעלה. תנו לה מקום לאחוז בו, ולפלא, הצמח תופס את היד ההיא. גם בגדילה דרוש מדריך אחד."},"ICON-1662":{"nm":"מעמד לכרטיס שפת פרחים","de":"הכרטיס הנעוץ ליד הפרח נושא את המילים שהפרח מציע. ההידראנגאה אומרת כנות, החרצית אומרת תמימות. כדי שהליכה בערוגה תהפוך לטיול של קריאת מכתבים, מעמד קטן משאיל בעדינות קול לפרח האילם."},"ICON-1663":{"nm":"כיסוי לשלט גינה","de":"פן הרוח והגשם ימחקו את הכתובת, מלבישים כובע שקוף על שלט הגינה. \"כאן עגבניות\", \"כאן בזיליקום\". שמות שכמעט התעמעמו נשארים ברורים, כך שגם אחרי שנה שלמה הגינה לא שוכחת אף אחד מבני משפחתה."},"ICON-1664":{"nm":"כפית דישון","de":"כשמוסיפים תזונה לאדמה, תאוות בצע רק שורפת את השורשים. לכן כפית אחת, בדיוק כך. הכפית הקטנה מרימה את הכמות הנכונה ומזכירה - לב שיודע לגדל היטב תמיד מגיע מקצות אצבעות שיודעות מידתיות."},"ICON-1665":{"nm":"מזלף ערפל","de":"מסובבים את המזלף והזרם מתפזר כלפי מטה כמו ערפל. עלה רך שהוכה בעבר בסילון עז, מרים את ראשו בעדינות תחת טיפות דמויות טל. אותם מים בדיוק הופכים לברכה שונה לגמרי, תלוי איך נותנים אותם."},"ICON-1666":{"nm":"כוסית מדידה למזון","de":"כוס אחת, שתי כוסות. מודדים את ארוחתו של חבר לא באומדן אלא במסירות. יותר מדי - ויישאר, פחות מדי - ועצוב, ולכן שוקלים בדיוק את הכמות הנכונה. אהבה מגיעה לפעמים בדמות של מדידה מדוקדקת."},"ICON-1667":{"nm":"כיסוי מברשת להחלפת פרווה","de":"בעונת החלפת הפרווה, כיסוי עוטף בקפידה את הפלומה הרכה שנלכדה במברשת. חבשו כובע למברשת אחרי הסירוק, והיום הבא מתחיל שוב רך ופלומתי. הברק של בן הבית הגדל בשקט מתוך סידורים קטנים כאלה."},"ICON-1668":{"nm":"כיסוי גוזם ציפורניים","de":"מלבישים מכסה קטן על קצהו החד של הגוזם, כדי שהכלי, אחרי שסיים, לא ישרוט חפצים אחרים במגירה. אחרי שזמן הטיפול תם, גם השכבת הכלי לישון היא חלק מסבב הטיפול השלם."},"ICON-1669":{"nm":"תליון קישוט לרצועה","de":"תלו תליון נוצץ אחד על הרצועה, ואותו שביל טיול ישן נעשה קצת יותר מיוחד. קישוט קטן שנוצץ באור השמש. הוא לא צעקני, אך די בו כסימן שהילד הזה הוא בן משפחה אהוב מאוד למישהו."},"ICON-1670":{"nm":"כרטיס בריאות לחיית מחמד","de":"האם אכל היטב היום, יש משהו שכואב? רושמים שורה אחת ליום על יומו של החבר שחי איתנו על הכרטיס. כשמצבו של בן המשפחה שלא יכול לדבר נכתב במילים, גם לב הטיפול נעשה קפדני ואיתן יותר."},"ICON-1671":{"nm":"כיסוי כרית שינה","de":"מלבישים את כרית השינה בגד חדש ורך. מסירים את הבד השחוק מהתגלגלות והתחככות, וריח פלומה מיובשת בשמש נודף. לשמור הכי נקי את המקום שבו שוכבים הכי הרבה, זו מסירות יומיומית לבן הבית שחי איתנו."},"ICON-1672":{"nm":"סיכות גדר קטנות","de":"נועצים סיכות קטנות לאורך קצה הערוגה ומקימים גדר נמוכה. לא איום נוקשה שלא לחצות, אלא גבול רך שאומר - עד כאן מקומם של הפרחים. רק כשיש קו לשמור, אפשר לגדול בתוכו בשלווה."},"ICON-1673":{"nm":"קופסת חטיפי היכרות","de":"גם ילד ביישן זוקף אוזניים לצליל שקשוק הקופסה הזאת. בפנים חופן חטיפים שפותח את הלב. מכיוון שהבטחות קטנות מהירות יותר ממילים בקירוב לבבות, הצליל המקושקש הוא זה שמתקדם קודם."},"ICON-1674":{"nm":"תג יומן טיולים","de":"איזה שביל היום, וכמה הלכנו? קושרים את הרישום לתג כמו תפר. צעדים שנאספים הופכים למפה, ומפות שנאספות הופכות לזיכרונות. כל יום שהלכנו יחד מצטבר בקפידה על התג הקטן הזה."},"ICON-1675":{"nm":"קערית מזון לציפורים","de":"מניחים את הקערית על אדן החלון, מפזרים כמה גרגרי דוחן, ואורחים אלמונים מגיעים בזה אחר זה. קול הניקור הקליל, רפרוף הכנפיים. שולחן קטן זעיר שבו חופן אחד שהוענק מביא קונצרט קטן בכל בוקר."},"ICON-1676":{"nm":"כלי תצפית לסנאים","de":"בתוך המיכל השקוף פוגשים את עיניו העגולות של הסנאי. לחיים גדושות בלוטים, מטה ראש בסקרנות - איזה מראה. על ההבטחה להציץ לרגע ומיד לשחרר, מחליפים ברכה קצרה עם פיסת טבע פראי זעירה."},"ICON-1677":{"nm":"תבנית גבס לטביעת רגל","de":"יוצקים גבס רך כדי להטביע כף רגל קטנה. בזמן ההמתנה להתייצבות, גם זמן החצר נעצר לרגע. את חותם כף הרגל בגודל טפח שעתיד להיעלם עם הגדילה, התבנית הלבנה מרימה כמו נצח ומניחה בעדינות בין שתי כפות הידיים."},"ICON-1678":{"nm":"כיסוי עדשה למשקפת לילה","de":"סוגרים מכסה קטן על קצה העדשה שמביטה אל תוך הלילה. כדי שהזכוכית שצפתה בכוכבים ובקנים תמתין ללילה הבא בלי אבק כלשהו. גם לעיניים שרואות את החושך בבירור, נדרשת נקודת מנוחה אחת במהלך היום."},"ICON-1679":{"nm":"שלט הגנה על קן","de":"מוצאים קן בין הענפים, ובמקום להתקרב, מציבים שלט. \"כאן גרה משפחת ציפורים, בבקשה בשקט.\" לצפות בלי לפלוש - הצעד הרך ההוא לאחור הוא שמגן על הקן הכי טוב מכולם."},"ICON-1680":{"nm":"שבב הקלטת קולות טבע","de":"שירת עומק העשב, ציוץ מתחת למרזב, קול חרקי הלילה - לא כולאים אותם בשבב, אלא שואלים אותם לזמן קצר. קופסת קול קטנה שכשמשמיעים אותה שוב, מחייה אפילו את האוויר של אותו רגע. כדי שכל מה שנשמע פעם, לא ייעלם באמת."},"ICON-1681":{"nm":"כיסוי למשקפת תצפית","de":"רגע לפני שציפור אחת מרקיעה לעוף, היער עוצר את נשימתו לרגע. באותו רגע דומם, בד אחד שפרוש על העדשה שומר על הבהירות הרחוקה, בלי שתיגע בה אפילו טביעת אצבע."},"ICON-1682":{"nm":"רצועת מצלמה לשביל יער","de":"בכל פעם שעולים בשביל היער התלול, המצלמה נוקשת קלות על החזה. פעימות הלב הרוטטות וקול התריס נעים באותו קצב, ורצועה אחת זו מחזיקה בביטחון את הרגעים ההם מול החזה."},"ICON-1683":{"nm":"כרטיס פירוש טבע","de":"גם לגבעול עשב בודד יש שם, מספר הכרטיס בשקט. ברגע שמה שחלף בלי משים מקבל תואר, שביל ההר לפתע נעשה עמוס בפנים מוכרות ואוהבות."},"ICON-1684":{"nm":"טלאי תיקון למפרש","de":"גם בבד שסופג את הרוח בכל גופו נשארות צלקות. עם טלאי קטן אחד שמונח בעדינות על הקרע, המפרש שב וזוכה בזכות לחבק שוב את הים הפתוח."},"ICON-1685":{"nm":"לוח תרגול קשרים","de":"למעלה, למטה, עוד סיבוב אחד - הסדר שהידיים שיננו הופך לקשר. בלילה שבו הסערה דופקת על הסיפון, נוהל אחד זה קושר יחד את האדם והספינה כאחד."},"ICON-1686":{"nm":"כיסוי הגנה לשרשרת עוגן","de":"אל תזלזלו בכובע הקטן הזה שמולבש על קצה השרשרת. החלודה גדלה בסתר מבפנים, ולכן כיסוי אחד שעומד נגד רוח הים מאריך בשקט את חיי העוגן."},"ICON-1687":{"nm":"דגל סימון מסלול שיט","de":"ביום שהערפל כה סמיך עד שהדרך שלפנים נמחקת, דגל אחד מדבר את הנתיב במקומה. נקודת צבע אחת שמתנופפת ברוח, משחררת סוף סוף את כתפיו הנוקשות של ההגאי שאבד לו הדרך."},"ICON-1688":{"nm":"מחזיק מפתחות לתא ספינה","de":"מעל ים מתנדנד, טבעת קטנה תלויה על דלת התא הצרה. כל עוד המפתח שומר על מקומו, חדר אחד לשוב אליו אף פעם לא ננעל מפניך."},"ICON-1689":{"nm":"נרתיק עמיד למים למפה","de":"בגשם, מפת נייר מוחקת את הדרך ראשונה. בעוד דף אחד מחזיק מעמד יבש בתוך הנרתיק השקוף, גם מסע רטוב לא מאבד את כיוונו לבסוף."},"ICON-1690":{"nm":"פתיל למנורת ספינה","de":"השמן שהפתיל שאב אליו לאיטו פורח סוף סוף ללהבה. נקודת אור אחת על הסיפון, ובריצוד הקטן ההוא המרחק האינסופי של ים הלילה מתקרב במעט."},"ICON-1691":{"nm":"בד אות מצוקה","de":"במרחק שהקול לא מגיע אליו, היד שמנופפת בבד אדום גבוה נוסעת רחוק יותר ממילים. יריעה אחת זו חותכת את הרוח, וזועקת במקומך שמישהו כאן חי."},"ICON-1692":{"nm":"סיכת כיוון רוח ימית","de":"מי שיודע מהיכן נושבת הרוח, קובע את המסלול. על הכיוון היחיד שסיכה קטנה מצביעה עליו בשקט, נשען גורלה של השייט של היום כולו."},"ICON-1693":{"nm":"כיסוי לאת מתקפלת","de":"מקפלים את הלהב ומכסים אותו, וגם האת החרוצה מאזנת נשימה לרגע. הדבר האחרון שהיד שחפרה את כל האדמה עושה, הוא לטפח את הלהב של מחר שלא יקהה."},"ICON-1694":{"nm":"נרתיק מצפן כיס","de":"המחט תמיד מצביעה צפונה בלי רעד, אך מה ששומר על המחט הזו הוא הנרתיק המוצק. ככל שאדם איבד את דרכו יותר פעמים, כך הוא מוקיר יותר תחושת כיוון."},"ICON-1695":{"nm":"רשת כלים למחנאות","de":"תולים את הכלים שנשטפו ברשת לייבוש בשמש הבוקר. יום במחנה מתחיל בקול ייבוש הטיפות, ואותו דבר של מה בכך ממלא את האוהל בביטחון."},"ICON-1696":{"nm":"כרטיס היתר מחנאות","de":"אישור ללון לילה אחד על ההר הזה. ברגע שדף נייר אחד נמצא ביד, גם היער הזר הופך לרגע לבן ברית ומקבל בעדינות את האוהל הקטן."},"ICON-1697":{"nm":"חוט דגלון לשביל חקירה","de":"קושרים דגלון בכל פיצול דרך, והדרך חזרה לא מתפזרת בחושך. סימן קטן אחד שהותיר מי שהלך לפני, דוחף בשקט את גבו של הצעד שבא אחריו."},"ICON-1698":{"nm":"קופסת גפרורים עמידה למים","de":"גפרור טובע בטיפה אחת ומשתתק לנצח. בתוך קופסה אטומה שאף טיפת מים לא חודרת אליה, הניצוץ מחכה יבש ושקט, רק בשביל הלילה הקר ביותר."},"ICON-1699":{"nm":"מסנן מים נייד","de":"גם מים עכורים שמעוררים היסוס מזדככים אחרי שעוברים דרך המסנן הזה. מכשיר קטן שמניח את הספק בצד עוד לפני הצמא - האמונה שאפשר לשתות היא כשלעצמה לגימת מנוחה."},"ICON-1700":{"nm":"חבילת שמיכת חירום","de":"מקופלת, היא בגודל כף יד; פרושה, היא הופכת לחום של אדם אחד. כדי שהמילה \"חירום\" תשקול קצת פחות, השמיכה ממתינה בפינת התיק, תמיד מוכנה להתחמם."},"ICON-1701":{"nm":"צמיד סימון לילי","de":"בשביל ההר שצנח לתוך החושך, פרק יד אחד פולט אור שקט. אותה רצועה קטנה המכריזה על מקומו של כל אחד, קושרת בעדינות את ההולכים יחד בחוט בלתי נראה."},"ICON-1702":{"nm":"מדבקת קסדת כורה","de":"המדבקה שעל הקסדה היא תג השם השני של הכורה. במנהרה העמוקה שבה אפילו האור יקר, מזהים בחיבה חבר לפי אותה תמונה קטנה הנתפסת באור הפנס."},"ICON-1703":{"nm":"סיכת סימון עורק מחצב","de":"במקום שבו נמצא עורק מחצב, נועצים בעדינות סיכה. נקודה אחת הזוהרת לבדה בחושך אומרת בטוב לב לכל מי שיבוא אחריך להתחיל לחפור מכאן."},"ICON-1704":{"nm":"סרגל מדידת סדקים","de":"מדידת הסדק המבקיע את הקיר היא סבלנות איטית ועיקשת. האם התרחב טפח מאתמול? המספר הקטן שהסרגל מדווח תופס התמוטטות לפני שהיא מגיעה."},"ICON-1705":{"nm":"נייר העתקת תבליט עתיק","de":"מניחים נייר על התבנית החרוטה באבן ומקישים בעדינות בדיו. ברגע שמגע בן אלף שנה עולה בגרגר שחור, ההעתקה מושיבה לרגע את הזמן החולף מולך."},"ICON-1706":{"nm":"תיבת מטבע עתיק","de":"פיסת המתכת הקטנה הזו, ישנה ושמורה מפני חלודה, נושאת בקִרבּה את הקול האחרון של אומה שנעלמה. עידן שלם שוכן במטבע אחד, מזדקן לאיטו בתוך התיבה השקופה."},"ICON-1707":{"nm":"מעמד לשברי בדולח","de":"גם לבדולח הכולא אור בתוכו דרוש משהו להישען עליו. ברגע שהוא שוכב בשלווה על מעמד קטן, הדבר השברירי סוף סוף פורש את זוהרו במלואו."},"ICON-1708":{"nm":"קרע ממפת המערה","de":"מפה קרועה חושפת בערמומיות רק חצי מסודה. עד היום שבו תמצא את החלק הנותר, דף אחד זה שומר את שאר הדרך למחצה מוסתרת אי־שם במערה."},"ICON-1709":{"nm":"קרבינר לירידה בחבל","de":"כדי למסור את גופך במורד הצוק, עליך תחילה לבטוח לגמרי בקרבינר הזה. לתלות את משקלך על פיסת פלדה קרה אחת - כזה, מטבעו, כבד גם האמון."},"ICON-1710":{"nm":"היתר חפירה","de":"דף אחד ועליו חותמת ברורה המתירה לחפור באדמה. כדי להעיר את הטמון, בקש רשות תחילה - החפירה מלמדת בשקט את דרך ההתחלה מתוך נימוס."},"ICON-1711":{"nm":"מארז מגן רוח","de":"פורשים אותו כשהגב מול הרוח, ומרובע של שקט נפתח באמצע המישור הסוער. מאחורי השכבה הדקה הזו ניצוץ קטן מוגן, והעייף זוכה לרגע מנוחה."},"ICON-1712":{"nm":"כיסוי משקפי סופת חול","de":"לא משנה כמה החול משתולל, לפחות מבטך חייב להישמר עד הסוף. כיסוי דק על המשקפיים הופך לאומץ לפקוח עיניים ולהמשיך ללכת, גם דרך הסערה."},"ICON-1713":{"nm":"מגש לאורחי הגשם","de":"מי גשם מטפטפים מקצות נעלי האורח שהגיע. מגש המונח בשקט ליד הכניסה מקבל בחום ובשתיקה כפות רגליים שהצטננו והרטיבו."},"ICON-1714":{"nm":"תג צינון לחום כבד","de":"תג קטן שמצנן בעדינות את חום הצהריים. תלוי על התיק, הוא שומר את קרירותו, ואז מעניק בחשאי חופן צל בדיוק כשהזיעה מתחילה להיפרש."},"ICON-1715":{"nm":"חגורת חימום ליד לגל קור","de":"חגורה חמימה הנכרכת פעם אחת סביב המותניים. כשחום מחמם הידיים מתפשט לאורך הגב התחתון, אפילו המישור המושלג והמריר הופך לנסבל מעט יותר."},"ICON-1716":{"nm":"שקית סופגת לחות","de":"הלחות מכרסמת בדברים בלי קול. בעוד שקית קטנה בתוך הקופסה סופגת בשתיקה את הרטיבות, הדברים היקרים לך שומרים על צורתם, יבשים ושלמים."},"ICON-1717":{"nm":"כיסוי נעליים לבוץ","de":"יש רגעים שבהם רק הנעליים חייבות להישאר נקיות גם כשחוצים בוץ. המגן הדק הזה החוסם את הבוץ הופך את הצעדים החוצים את סף הבית לקלים יותר."},"ICON-1718":{"nm":"כיסוי פנס לערפל ים","de":"כשערפל הים מנסה לבלוע את הפנס כולו, הכיסוי הזה אוסף בשקט את גרגרי האור המתפזרים. גם בשחר העמום, אור נמל אחד מסרב עד הסוף לכבות."},"ICON-1719":{"nm":"סיכת אזהרת ברקים","de":"כשעננים כהים שוקעים נמוך, סיכה אחת מציעה ראשונה אזהרה. המילה לשחוח לפני שהברק מכה - ענווה מול הטבע תמיד כדאי ללמוד מראש."},"ICON-1720":{"nm":"סימנייה לספר מתכונים","de":"סימנייה קטנה נתחבת בין דפי ספר בישול פתוח. כשאתה ממשש בחזרה אחר השורה שאיבדת לפני האש, גם טעם הבית של אמא מתעורר שוב באותו עמוד."},"ICON-1721":{"nm":"מקל למינון תבלינים","de":"אמא תמיד אמרה רק \"קורט אחד\". הערכה בעין לא יכלה להיות מדויקת, ובכל זאת ידה מעולם לא רעדה. כשאתה מודד מלח במקל הזה, אתה מבין שמה שהבשיל זמן רב יותר מכל מדידה לא היה אומדן אלא אהבה."},"ICON-1722":{"nm":"רצועת מכסה לתסיסה","de":"ידעת שגם הכד נושם? כשהרצועה הזו מחבקת את המכסה בחוזקה, הפנים והחוץ מתחילים לאט לשוחח. רק אחרי אותם ימים שלא ממהרים, הציפייה זוכה סוף סוף בשם הטעם."},"ICON-1723":{"nm":"שבב תווית להבשלה","de":"שבב קטן ועליו כתוב בקפידה תאריך ההכנה. הכתב דוהה בעוד מה שבפנים רק מעמיק. לרשום כאילו כדי לשכוח, ואז לשלוף פתאום יום אחד - כך נראית ההבטחה הנשמרת שנקראת הבשלה."},"ICON-1724":{"nm":"מסננת מרק","de":"מרק צלול מגיע רק אחרי סינון, ועוד סינון. צפה במסננת עוצרת את השאריות ומעבירה בשקט רק את המהות, ואמרת המטבח הישנה - שעומק נאסף במקום שממנו לוקחים משהו - מגיעה אליך דרך קצות אצבעותיך."},"ICON-1725":{"nm":"בד לתפיחת בצק","de":"מכסים את הבצק בעדינות בבד אחד. בעוד השמרים תופחים בשקדנות מתחת לאותו אפלולית, אתה לומד לראשונה את העדינות של דברים הגדלים בשקט במקומות בלתי נראים."},"ICON-1726":{"nm":"סיכת הכנת מצרכים","de":"סיכה קטנה המפצלת את סיבי הבצל הירוק ואוחזת בחוזקה בשום. ההכנה דומה לברכת שלום ראשונה למצרכים, וככל שתקצץ בקפידה רבה יותר, אור השולחן בערב יבהיק בגוון אחד יותר."},"ICON-1727":{"nm":"מלקחיים לעיצוב צלחת","de":"היכן להניח את הפיסה האחרונה בצלחת - בסופו של דבר, המלקחיים האלה מחליטים. באותו רגע קצר שבו יד מיומנת מהססת חצי פעימה באוויר, ארוחה הופכת בשקט לציור."},"ICON-1728":{"nm":"כיסוי תרמי לקופסת אוכל","de":"קופסת האוכל שקיבלת בשער בית הספר הייתה צריכה להישאר חמה עד צלצול ארוחת הצהריים. החום הכלוא בתוך הכיסוי הזה אינו מתקרר, עמוק כמו לב מי שעמד ליד האש מהשחר."},"ICON-1729":{"nm":"כרטיס הזמנה לארוחה","de":"\"בוא נאכל אצלנו פעם.\" האם יש דבר חם מזה שאפשר לומר? בלי הבטחה גדולה, רק לשבת לאותו שולחן - ההזמנה העתיקה ביותר שהקוריאנית יודעת להעניק נשמרת בכרטיס יחיד זה."},"ICON-1730":{"nm":"שבב הזמנת שולחן","de":"כותבים שם ושומרים מקום. בעוד שבב קטן קושר לרגע שולחן ריק למישהו, השעה המובטחת מתקרבת לאט, כמו צעדי רגליים."},"ICON-1731":{"nm":"כרטיס הערכת טעימה","de":"פנים נוגסות ביס אחד ומעניקות כוכבים ברצינות רבה. השורה הכנה הכתובה בקפידה על כרטיס זה היא הנזיפה החמה ביותר שיש, זו שהופכת את המנה הבאה לטעימה יותר."},"ICON-1732":{"nm":"רצועת תודה לקופסת אוכל","de":"כורכים רצועה סביב קופסת האוכל הריקה לחלוטין ושולחים אותה בחזרה. גם מי שמעולם לא הצליח לומר תודה, קושר בקשר הזה לפחות את הלב שלא הצליח לבטא."},"ICON-1733":{"nm":"תג סימון אלרגיה","de":"תג קטן אחד זה שומר בשקט על שולחנו של מישהו. לפרט בבירור מה מונח בפנים הוא שם נוסף להכנסת אורחים - אכפתיות המגיעה עד למקומות שאינם נראים."},"ICON-1734":{"nm":"כף זיכרון הטעם","de":"הטעם שנשאר זמן רב על הלשון היה, למעשה, נוף של יום ההוא. כשכף אחת לוקחת אותך ברגע חזרה למטבח הילדות, נדמה שהזיכרון הוא משהו שהלב, לא הקיבה, אוסף ושומר."},"ICON-1735":{"nm":"אסימון תפריט היום","de":"מה לאכול היום. מול השאלה הקשה בעולם, אנחנו מפסידים בכל פעם מחדש. הופכים את האסימון הזה ומפקידים את התפריט בידי הגורל, והלב, להפתעתך, נעשה קל ושמח."},"ICON-1736":{"nm":"פעמון שולחן משותף","de":"מצלצלים בפעמון פעם אחת והמשפחה המפוזרת בין החדרים מתכנסת למקום אחד. צלצול הפעמון הזה מעל השולחן העגול הוא התרגום החביב ביותר למילים \"מוכן, בואו מהר.\""},"ICON-1737":{"nm":"כרטיס סדר הקינוח","de":"הדבר המתוק תמיד אחרון. הבטחה שאיש אינו זוכר מי קבע - הכרטיס הזה שומר עליה במקומך. מנחה שולחן קטן וחם, השומר את שיא התיאבון לביס אחד של קינוח."},"ICON-1738":{"nm":"אסימון מיקוח","de":"בלב השוק, \"תוריד קצת\" ו\"אני כבר מפסיד\" מתנגשים בחיבה. האסימון הזה הוא הקבלה של לקוח ותיק, שבסופה המיקוח מסתיים, בכל זאת, בצחוק."},"ICON-1739":{"nm":"סיכת בדיקת מלאי","de":"סורקים בשקט את מדפי המחסן, מוצאים את המקומות הריקים ונועצים סיכה. לדעת מה נשאר ומה אזל - העבודה הגדולה של ניהול הבית תמיד מתחילה מהבדיקה הקטנה הזו."},"ICON-1740":{"nm":"מברשת ניקוי דוכן","de":"בערב שאחרי סגירת השוק, קול טאטוא נמוך של דוכן ריק שוקע בחנות. באצבעות המנקות מקום שיתמלא שוב מחר, טבועה חריצות הקושרת את היום בעדינות."},"ICON-1741":{"nm":"כרטיס המלצת היום","de":"\"היום זה טוב.\" כרטיס שהבעלים שולף בחשאי. בהמלצה הזו, הדוחפת בעדינות את כתפו של לקוח מהסס, טמונה בסדר גאווה של יום שלם."},"ICON-1742":{"nm":"מחזיק חותמות נאמנות","de":"מלאו עשר ואחת חינם. המחזיק הזה, שריבועי חותמותיו מתמלאים בהדרגה, הוא פנים נוספים למילה \"קבוע\" - כי לבוא לעיתים קרובות פירושו, בסופו של דבר, לאהוב."},"ICON-1743":{"nm":"אטב פנקס חליפין","de":"אטב האוסף ומחזיק את הרישומים של דברים שהוחלפו והוחזרו. ככל שעבר יותר הלוך ושוב, כן מתעבה הפנקס, ובעובי הזה מתעבה גם האמון שנבנה עם השכנים."},"ICON-1744":{"nm":"תג נמכר","de":"ברגע שהתג הזה מודבק על האחרון שנותר, הלב מתמלא באורח מוזר. זהו ליווי קצר, כמו \"להתראות\", לדבר היוצא לדרך אל שולחנו של מישהו, אל פינת חדר כלשהי."},"ICON-1745":{"nm":"סל מוצר שמור","de":"סל הנושא את תג שמך שומר על מדף אחד. אותו מקום שנשמר מראש אומר לך בשקט, כשאתה נכנס, \"חיכיתי לך כל הזמן הזה.\""},"ICON-1746":{"nm":"שטיח דוכן אריזה","de":"השטיח הפרוש על דוכן האריזה הוא במה לידיים עסוקות. בזמן הקצר שבו נייר מתקפל וחוט נקשר בקפידה, דבר רגיל מחליק והופך למתנה של מישהו."},"ICON-1747":{"nm":"פתק הבטחת ביקור","de":"\"אבוא מחר.\" פתק ובו שורה אחת, נתחב בעדינות בסדק הדלת. גם כשלא הצלחתם לפגוש פנים אל פנים, ההבטחה רוכבת על דף יחיד, מגיעה לפני האדם ומחכה בשקט."},"ICON-1748":{"nm":"סל מתנה לשכן","de":"הסל המועבר מעבר לגדר תמיד מגיע עם התירוץ \"הכנתי קצת יותר מדי\". החום הקוריאני חוצה כך לצד הזה, מעמיד פנים של אדישות תחת מסווה של שפע."},"ICON-1749":{"nm":"תיבת חדשות הכפר","de":"חדשות הכפר, הגדולות והקטנות, נערמות בקפידה בתוך התיבה הזו. מי עבר לגור, אצל מי חוגגים - כמה דפי נייר מתאספים כדי להעביר את הדופק השקט של השכונה."},"ICON-1750":{"nm":"חותמת תודה על ביקור","de":"לוחצים את התודה על כך שמישהו בא בחוזקה עם חותמת אחת. אותו כתם דיו יחיד שנספג בנייר נשאר במקומו זמן רב יותר מהמילים \"לא אשכח.\""},"ICON-1751":{"nm":"כרטיס שבח על נדיבות","de":"כרטיס שעליו רושמים בשקט את הנדיבות שמישהו העניק היום ומחזירים אותו הלאה. בכפר שטורח לכתוב עדינויות קטנות במילים, דברים טובים ממשיכים לחזור ולסובב."},"ICON-1752":{"nm":"חותם למכתב התנצלות","de":"כמו תפוח שהבשיל אדום, גם התנצלות אפשר להציע רק אחרי שהבשילה דיה. החותם הזה, הנלחץ בחוזקה על המעטפה, הוא סימן האומץ שהחזיק עד הסוף את הסליחה שקשה היה לומר."},"ICON-1753":{"nm":"לוח משימות משותף","de":"דף אחד המחולק לעמודות של מי אחראי למה. עבודה שהייתה כבדה מדי לבד נעשית קלה בהרבה כשמחלקים בה שמות - כל מי שעבד כתף אל כתף יודע זאת."},"ICON-1754":{"nm":"סרט טעם השכן","de":"מסמנים בשקט מה השכן אוהב בסרטים צבעוניים. לזכור את הטעם של מישהו הוא הווידוי השקט ביותר שאתה מוקיר אותו, בלי לומר זאת מעולם."},"ICON-1755":{"nm":"טבעת הזמנה לשלט הבית","de":"טבעת אחת התלויה על שלט הבית מכריזה \"מארחים היום\". זהו סימן בגודל כף יד, אך עליו תלוי לב הפתוח לרווחה, מוכן וגמור לקבל פני מישהו."},"ICON-1756":{"nm":"צמיד כניסה לפסטיבל","de":"רצועה דהויה שנישאה ימים ארוכים, יקרה מכדי להסירה. רק כשנקשרה סביב פרק היד, הפסטיבל באמת התחיל. בתוכה ישן שלם יום שלא נגמר באמת גם אחרי שנגמר."},"ICON-1757":{"nm":"מחזיק כרטיס לזיקוקים","de":"רגע לפני שהשמיים מתפוצצים, הכרטיס במחזיק הזה אוחז חזק בלב הפועם. זוהי הבטחה הנאחזת עד שהכף מזיעה, הכול למען אותו רגע אחד שבו הזיקוק הראשון פורח בקול פצפוץ."},"ICON-1758":{"nm":"צלחת לחזיית הירח","de":"היו לילות שבהם הרגשת כאילו העלית את הירח המלא כולו על צלחת. סדר פירות טריים וסונגפיון על הצלחת הזו והשתחווה לירח, ולב עגול אחד מגיע עד קצה השמיים."},"ICON-1759":{"nm":"סיכה לכפפות פסטיבל חורף","de":"גם כשהידיים קופאות בשלג, הכפפות ממשיכות להחליק מפרקי היד. רק אחרי שהסיכה הזו נלחצת בחוזקה לשרוול, אפשר סוף סוף לרוץ בפסטיבל החורף ככל העולה על רוחך."},"ICON-1760":{"nm":"כרטיס זרעים לקראת אביב","de":"כמה זרעים ישנים בתוך הכרטיס, כל אחד מחכה לאביב שלו. קוברים אותם באדמה והם נובטים בלי כשל, כמו הבטחה - נראה שכל התחלה נובעת מנקודה קטנה ומוצקה אחת."},"ICON-1761":{"nm":"חותמת חוף קיץ","de":"גל טובע חותמת בחול בחוזקה ונסוג לאט. בידיעה שהיא תימחק בקרוב, הוא עדיין משאיר סימן קטן שמישהו היה כאן. הקיץ תמיד מטביע כך פעם אחת, ברור, ואז נסחף עם ריח המלח."},"ICON-1762":{"nm":"סרט קציר הסתיו","de":"היד שקשרה את שיבולי התבואה קושרת לבסוף סרט יפה. קשר אחד האוסף בקפידה את זיעת השנה כולה. גם כשהשדות מתרוקנים, הסתיו מעניק ברכת שלום נוספת, כמו שקיעה, בגוון היפה ביותר שלו."},"ICON-1763":{"nm":"בלון דיבור לתמונת זיכרון","de":"\"תודה שבאת עד לכאן.\" ברכה שמעולם לא נאמרה בקול מתנפחת עגולה על הנייר. פיסת לב עגולה קטנה, המשאילה בעדינות קול לשתיקה הקפואה בתוך תמונה."},"ICON-1764":{"nm":"סיכת מפת פסטיבל","de":"סימן שמישהו נעץ כדי שלא תאבד בשטח הרחב. גם כשרגליך רצות קדימה אל צלילי המוזיקה העממית, סיכה אחת זו מובילה בעדינות אותך, התועה, אל המקום המובטח."},"ICON-1765":{"nm":"מפתח אב לאלבום","de":"מה שנעול אינו התקליט אלא הזמן החתום בתוכו. רעד ההקלטה הראשונה, שחר המיקס האחרון. סובבים את המפתח לאט, ודלת החדר ההוא, המוכר רק ליוצריו, נפתחת בחריקה."},"ICON-1766":{"nm":"כרטיס רשימת שירים","de":"סדר השירים הכתוב על דף אחד הוא, למעשה, סדר הלב. היכן זה ייתקע בגרון, היכן תעצור לנשום - הנייר כבר יודע הכול. התרגשות המציפה עוד לפני שמעת את הצליל הראשון."},"ICON-1767":{"nm":"תג בדיקת שמע","de":"רק מי שהחזיר קטע זהה כמאה פעמים מדביק תג זה. עוד פעם אחת, רק עוד האזנה אחת. לצד חותמת המעבר מסתתר ליל של מישהו שפקפק בשמיעתו עד השחר."},"ICON-1768":{"nm":"תווית הזמנה מוקדמת","de":"הבטחה לחכות למשהו שעדיין לא יצא לעולם. ברגע שהתווית מודבקת, מקום פנוי אחד נשמר בשקט על שם מישהו. גם לציפייה נרגשת יש מספר תור."},"ICON-1769":{"nm":"מדבקת חותם מהדורה ראשונה","de":"היא מזכירה את המגע הישן של כיסוי כד בנייר האנג'י וחתימתו בדבק. דף אחד הנודר לשמור את הראשוני כפי שהיה. בידיעה שהוא ייעלם ברגע שיקלפו אותו, אתה ממשיך להביט במראהו עוד ועוד."},"ICON-1770":{"nm":"שבב לוח שנה לקאמבק","de":"מוסיפים עיגול אחד ללוח השנה והלילות עד היום ההוא מתקצרים בריבוע אחד. תאריך החזרה ברור על השבב הקטן שבידך. למי שמחכה, הזמן נספר כך, ביד."},"ICON-1771":{"nm":"שרוול צילום קונספט","de":"לפני שהקונספט הבא ידחוק את צבעו של זה, דף שקוף מכניס בקפידה את סיביו לשמירה. כדי שלא יישכח כשהעונה תתחלף, הוא שומר בעדינות על גוון הימים שחלפו, עד לפינות עצמן."},"ICON-1772":{"nm":"אסימון חשיפת טיזר","de":"רגע לפני הסרת הצעיף, מטבע קטן נאחז בכף היד. ברגע שמושיטים אותו, הסצנה הראשונה הנעולה נפתחת טפח אחד לעבר העולם. חשיפה היא, בסופו של דבר, עניין של מי מושיט יד ראשון."},"ICON-1773":{"nm":"מעמד תצוגה לתקליט","de":"ברגע שמעמד נמוך אחד מרים מעט את התקליט, דיסק רגיל הופך לכוכב התצוגה. שחקן משנה עדין, התומך משום מאחור, בשתיקה, בזווית שבה האור נוגע בצורה היפה ביותר."},"ICON-1774":{"nm":"כרטיס מעבר להצגת בכורה","de":"כרטיס יחיד ועליו חתומות המילים \"מציגים לראשונה\". מהמסדרון הארוך מאחורי הקלעים ועד למחיאות הכפיים הראשונות מהקהל, הכרטיס הזה נושא אותך מעבר לסף הרועד של הופעת בכורה."},"ICON-1775":{"nm":"שבב סימון תנועה לבמה ראשונה","de":"אתה ממשש באצבעות רגליך את השבב המודבק לרצפה. משבצת אחת שהגוף מכיר תחילה, גם בלי להביט. ברגע שאתה נוחת בדיוק על המקום שזכרת, הרעד בקצות אצבעותיך הופך סוף סוף לתנועה ברורה."},"ICON-1776":{"nm":"כרטיס נאום פתיחה","de":"גם המשפט הרגיל \"הכול הודות לכם\" כבר אינו רגיל כשהוא כתוב בכתב יד רועד. כמה שורות שנרשמו מראש מפחד שההתרגשות תגרום לשכוח. הכנות מסתמכת לפעמים על כרטיס אחד."},"ICON-1777":{"nm":"לוח הזמנת צילומי פרופיל","de":"דף ועליו התאריך לעמוד מול העדשה כתוב בקפידה. לוח זמנים להכנה איטית של הפנים הטובות ביותר. ככל שכל משבצת מתמלאת, כך גם מתארכים הלילות מול המראה."},"ICON-1778":{"nm":"טופס הצטרפות למועדון מעריצים","de":"פתק כניסה שעליו רושמים בביישנות שם ולב בשורה אחת. לומר שאתה אוהב תמיד קשה, אבל פתק זה כותב עבורך את המילים האלה בקפידה במקומך. חתימה ראשונה על ההחלטה להיות יחד."},"ICON-1779":{"nm":"לוח בדיקת מתנת בכורה","de":"מגע הבודק כל פריט ופריט, מדמיין את מי שיקבל אותו. האם הפינות נפגעו, האם חסר לב כלשהו? מתנה כבר אהובה פעם אחת, עוד לפני שהיא נמסרת, ויוצאת לדרך."},"ICON-1780":{"nm":"סימן סיום במה","de":"רגע לפני שהמסך יורד, סימן המונח במקום שבו הפוזה האחרונה נחה. לא סימן לסיום אלא נקודה קטנה הקושרת את הסוף בקפידה. רק במה שנסגרה היטב פותחת את הבמה הבאה."},"ICON-1781":{"nm":"סיכת המתנה לראיון","de":"סיכה השומרת בשקט על הדממה שלפני תחילת השאלות. במהלך השתיקה הקצרה של בחירת תשובות בראש, סימן קטן זה אומר בטוב לב במקומך \"עוד לא, אבל בקרוב.\""},"ICON-1782":{"nm":"מעטפת מזכרת בכורה","de":"כמו הלב הישן שהכניס מכתב יקר, מעטפה ותוכן, לידו של יוצא לדרך, שכבה אחת שומרת בקפידה את תיעוד הבמה הראשונה. ביום שבו תפתח אותה בעתיד הרחוק, גם הרעד של אותו יום יישפך יחד."},"ICON-1783":{"nm":"קשית תרגול נשימה לשירה","de":"תרגול שליחת נשימה ארוכה, בזרם אחד, דרך קצה הצינור הדק. שירה, בסופו של דבר, היא נשימה מרוסנת היטב - קשית קטנה זו מספרת זאת בשקט כל בוקר. הרוח לפני הקול."},"ICON-1784":{"nm":"שבב קליק לתרגול קצב","de":"טיק, טיק, טיק - החבר הכן ביותר בעולם. הוא בולם אותך כשאתה ממהר ודוחף בעדינות את גבך כשאתה מפגר. לחרוט את הקצב בגוף דומה לשיחה ארוכה עם השבב האיתן הזה."},"ICON-1785":{"nm":"סרט בדיקת קו ריקוד","de":"היכן קצות האצבעות עוצרות, היכן הכתף נפתחת - עוקבים אחר קו התנועה בעזרת סרט אחד. קו ריקוד המשורטט היטב נשאר ישר ומסודר גם במקום שהקהל אינו רואה."},"ICON-1786":{"nm":"כרטיס משוב הבעות פנים","de":"האמירה שאפילו לחייך צריך ללמוד. דף הרושם בקפידה את זווית העיניים ואת גובה קצות השפתיים. את ההבעה שהמראה לא הצליחה ללמד, הכרטיס הזה אומר במקומה בעדינות."},"ICON-1787":{"nm":"פתק זרימת ראפ","de":"\"כאן תנוח רגע, שם תשפוך הכול\" - פתק המשרטט מראש את מסלול המים של המילים. ככל שהקטע מהיר יותר, כן חייב נתיב הנשימה להיות ברור יותר. בתוך החצים הרשומים בחיפזון, קצב של בית שלם חי ונושם."},"ICON-1788":{"nm":"מדבקת טמפרטורת קול","de":"גם לקול יש ימים חמים וימים קרים. סימן קטן שבוחרים בצבע ומדביקים עבור סיב היום. מחממים ומקררים לסירוגין, הקול מתעורר כל יום בטמפרטורה מעט שונה."},"ICON-1789":{"nm":"אסימון שגרת מנוחה","de":"מטבע המונח בידך עם המילים שגם לנוח היטב זו מיומנות. הושט אותו ותוכל לעצור לרגע בלי אשמה. למי שרץ ללא הפסקה, עצירה היא הבחירה האמיצה ביותר."},"ICON-1790":{"nm":"סיכת יעד צמיחה","de":"סיכה קטנה שננעצה עם המילים \"בוא ננסה להגיע לכאן\". גם אם זה נראה רחוק כמעט מהישג יד, אתה גדל צעד אחד לעברו בכל יום. יעד הוא כמו הבטחה עדינה המנופפת מרחוק."},"ICON-1791":{"nm":"מעטפת סיכום שבועי","de":"אוספים בקפידה זיעה ודמעות של שבוע שלם למעטפה אחת ומוסרים אותה. הדברים שהצליחו והדברים המחסירים שוכנים זה לצד זה בפנים. לפתוח אותה היא שיעורי בית קטנים המוענקים לעצמך של השבוע הבא."},"ICON-1792":{"nm":"קופסת חלקי עיטור לבמה","de":"מאחורי הבמה הנוצצת חיים חלקים ללא שם. בורג אחד, טבעת אחת מתאחדים כדי להצית את הכוכבים בתקרה. פותחים את הקופסה והיא מלאה במסירות קטנה ושקטה שתומכת בשתיקה בכל הפאר."},"ICON-1793":{"nm":"לוח קונספט תלבושת","de":"מצמידים פיסות בד וצבעים אחת אחת, ומודדים מראש בגד שעדיין אינו קיים בעולם. תלבושת במה המושלמת תחילה על הלוח. הדמיון תמיד צועד צעד אחד לפני המחט."},"ICON-1794":{"nm":"שבב התאמת צבע","de":"אותו בגד בדיוק לובש פנים שונות לגמרי בהתאם לאור. איזה צבע מחייך הכי בהיר עם אותו אדם - מגלים על ידי הצמדת שבבים אחד אחד. התאמה היא תגלית בסוף השוואה ארוכה."},"ICON-1795":{"nm":"לוח דוגמאות לשרוכי נעליים","de":"מה שאחראי לצעד יציב על הבמה הוא, להפתעתך, שרוך קטן. שלא ייפתח, אך גם לא ילחץ. השיקול העדין ביותר, הנעשה במקום הנמוך ביותר, בוחר מבין שרוכים המונחים לפי סיבם."},"ICON-1796":{"nm":"מעטפת בדיקת אביזרים","de":"ככל שדבר מה נוצץ יותר, כך פגם יחיד נראה בולט יותר. מגע המרים את התכשיט מהמעטפה מול האור, בודק אותו בקפידה. לב הבוחן דברים קטנים עד הסוף הוא זה השומר על הבמה."},"ICON-1797":{"nm":"דוגמית צבע לשיער","de":"דוגמית קטנה למדוד מראש עונה חדשה על השיער. הצבע הצובע בחשאי קווצה אחת, רומז בשקט לרושם הראשון של הקונספט הבא. שינוי תמיד מתחיל במקום בגודל כף יד."},"ICON-1798":{"nm":"כרטיס קונספט לציפורניים","de":"דף הקובע מראש את הציורים הקטנים שיצוירו על עשר קצות אצבעות. כדי שהקונספט יבצבץ בעדינות גם בתנועת יד אחת, אתה מלביש באהבה אפילו את הפרט הקטן ביותר בסיפור."},"ICON-1799":{"nm":"כרטיס שינוי סטייל","de":"\"אולי אהיה היום קצת שונה ממי שהייתי אתמול\" - כרטיס יחיד המאפשר את המשפט הזה. שיער, בגדים או אווירה, הכרטיס הזה פותח את הדלת המרגשת אל מראה חדש."},"ICON-1800":{"nm":"תג התאמת מידה","de":"תג הרושם בקפידה היכן להצר ולהרחיב עד שהמידה תתאים בדיוק. כמו המגע הישן שתיקן בגדי ילדים תפר אחר תפר, ההתאמה הקטנה הזו הופכת את הבמה לנוחה יותר בטפח."},"ICON-1801":{"nm":"כרטיס סקיצה לתמונה ממוזערת","de":"דף אחד שהצבע טרם נגע בו. מעל לקווי העיפרון הגסים הוא בוחן בשקט לאן תזרום הסצנה הבאה. יותר מהיצירה הגמורה מרגש תמיד קו ראשון בלתי גמור כזה, כך מלמד אותנו חדר העריכה השקט."},"ICON-1802":{"nm":"מדבקת הסכמה לצילום","de":"\"מותר לצלם אותי כאן?\" במקום מילים, מדביקים סימן עגול קטן על החזה. מדבקה קטנה אחת מציבה הבטחה עדינה בין המצלמה ובין הלב."},"ICON-1803":{"nm":"סיכת מיקום לקיר תמונות","de":"סיכה קטנה נעוצה בפינת הקיר. זהו מקום שנקבע מראש - מי יעמוד היכן. בכל מקום שבו נעוצה הסיכה, חיוך עוצר לרגע והופך לתצלום אחד."},"ICON-1804":{"nm":"אסימון בחירת תמונה","de":"אצבע המצביעה על תמונה אחת מתוך מאות. ברגע שהאסימון הזה מונח, כל ההבעות שנגנזו חיות מחדש למען אותה תמונה יחידה. הבחירה תמיד דומה לפרידה שקטה."},"ICON-1805":{"nm":"מעטפת מאחורי הקלעים","de":"כל מה שקורה מאחורי המצלמה נשמר כאן. כשמקפלים את הפתח, נרדמים יחד צחוק, טעויות צילום ופיהוק מנומנם. לעיתים קרובות, מה שמתחבבים עליו יותר מהתוצר עצמו הוא דווקא מה שבפנים."},"ICON-1806":{"nm":"פתק בקשות עריכה","de":"\"עוד שנייה אחת כאן, ואת המוזיקה קצת יותר נמוך.\" פתק מלא באדום עד אפס מקום. הקפדנות של מישהו מעצבת מחדש נשימה אחת בקצב הסרטון. השלמות צומחת דווקא מנגיעות קטנות כאלה."},"ICON-1807":{"nm":"תווית תזמון העלאה","de":"תג קטן המודבק לסרטון שייצא לעולם מעצמו, מחר בשבע בבוקר. גם כשכולם ישנים, ההבטחה נשארת ערה. זמן שנקבע מראש אינו יודע מהו איחור."},"ICON-1808":{"nm":"כיסוי מסגרת לתמונה ממוזערת","de":"כיסוי העוטף את הצילום המוצלח ביותר. הוא סוגר את הפינות בקפידה כדי שאבק ואצבעות לא יגעו בהן. עד לרגע החשיפה, הרושם הראשון נשמר כך, בעדינות רבה."},"ICON-1809":{"nm":"אסימון אורך צילום","de":"אסימון קטן המודד כמה דקות צולמו היום. ארוך אינו בהכרח טוב, וקצר אינו בהכרח קליל. הלב שיודע למצוא את האורך הנכון הוא הכפתור הראשון של העריכה."},"ICON-1810":{"nm":"גיליון הגהה לסיסמת עידוד","de":"דף שבודקים בו שוב לפני שצועקים בכל הכוח. כי אם אות אחת שגויה, אלפי קולות מתפזרים. מאחורי כל תרועה, יד הגהה בלתי נראית כבר עברה שם קודם."},"ICON-1811":{"nm":"שרוול אחסון לאמנות מעריצים","de":"ציור אחד שמישהו שרטט כל הלילה. ניתן לו בית שקוף כדי שלא יתקמט. כאילו מה שצויר בלב חייב להישמר בלב כדי להחזיק מעמד, השרוול מחבק אותו בלי מילה."},"ICON-1812":{"nm":"חוט מיון למכתבי מעריצים","de":"חוט הקושר בסדר ערמת מכתבים, כל אחד לפי שולחיו. בכל קשר מסתדר געגוע של יום שלם. יד שלא מוותרת אפילו על מכתב אחד, גם אם אינה יכולה להשיב לכולם, נמצאת כאן."},"ICON-1813":{"nm":"גיליון הרשמה להחלפת מוצרים","de":"\"יש מישהו שרוצה להחליף איתי?\" דף שכותבים עליו לב רועד ומגישים אותו. מהסיבה היחידה של אהבה משותפת לאותו דבר, שני זרים הופכים לרגע לחברים."},"ICON-1814":{"nm":"אסימון מושבי עידוד קבוצתי","de":"אסימון הקובע מקומות ישיבה זה לצד זה לאנשים הלובשים אותו צבע. כשלבבות מפוזרים מתכנסים לאזור אחד, קהל הצופים מתחיל לשיר כמו אדם ענק אחד."},"ICON-1815":{"nm":"קבלה למודעת יום הולדת","de":"קבלה אחת שמקבלים אחרי שמעלים אהבה על שלט חוצות. מה שלא כתוב לצד הסכום הוא המסירות שנאספה כל הלילה. הדף הזה נשאר כעדות לחגיגה שכוונה לאדם אחד בלבד."},"ICON-1816":{"nm":"כריכת ספר הודעות","de":"כריכה העוטפת ספר שנאסף מכתב ידם של אנשים רבים. כשפותחים אותו, כתבי יד שונים מתקפלים יחד ללב אחד. מבחוץ הוא מסודר, אך מבפנים הוא מלא ברעש חם."},"ICON-1817":{"nm":"סיכת חברות במועדון מעריצים","de":"סיכה קטנה הניתנת רק למי שקוראים את אותו השם. ברגע שהיא ננעצת בחזה, אהבה בודדה הופכת להבטחה משותפת של רבים. תחושת השייכות לובשת צורה עגולה כזאת."},"ICON-1818":{"nm":"אסימון עידוד מקוון","de":"נקודת אור אחת שידיים רחוקות מנפנפות מעבר למסך. המרחק עצום, אך הקצב זהה לחלוטין. זו הוכחה שהעידוד מגיע תמיד, גם ממושבים בלתי נראים."},"ICON-1819":{"nm":"שבר מפתח בלוי","de":"פיסת מתכת אחת עם שן חסרה. איש כבר לא זוכר איזו דלת היא פתחה פעם. מה ששורד יותר מהמקום הנעול הוא תמיד חצי כזה של מפתח שאיבד את תכליתו."},"ICON-1820":{"nm":"מפת מעבר סודי","de":"דף ישן המתאר שביל החבוי מאחורי הקיסוס. את קיצור הדרך מכירים רק היודעים. ברגע שפורשים אותו, האי הרגיל משנה בחשאי את פניו לבמת הרפתקה."},"ICON-1821":{"nm":"כרטיס פענוח צופן","de":"כרטיס המחזיר אותיות מפוזרות ומעורבבות למקומן המקורי. כשקו אחד מתיישר, הסוד הבא קורא לך. גם הקשר שנראה בלתי ניתן להתרה מתחיל, בסופו של דבר, באות הראשונה."},"ICON-1822":{"nm":"חוט לתיבה חתומה","de":"חוט הקשור חזק, כאילו אומר אל תפתחו. רק מי שקשר אותו יודע מה ישן בתוך הקשר. הרצון להתיר והרצון לשמור קשורים זה לצד זה בחוט הבודד הזה."},"ICON-1823":{"nm":"שבב פאזל מחורבות","de":"שבר קטן שנשר מקיר אבן עתיק. כשמתאימים אותו למקומו, אומנות של מישהו מלפני אלף שנה קמה לתחייה בקצות האצבעות. איסוף המפוזר הוא מעשה של חיבור הזמן מחדש."},"ICON-1824":{"nm":"גזיר אגדת האי","de":"דף שהועתקו עליו ביד סיפורים עתיקים הנודדים על פני האי. אם הם אמת או לא כמעט ואינו משנה. סיפור שעבר מפה לאוזן הופך, כשלעצמו, לטבעת שנה של האי."},"ICON-1825":{"nm":"אבן סימון נסתרת","de":"אבן אחת המונחת בשולי הדרך כמו במקרה. רק לעין יודעת היא מראה בשקט את הכיוון. ככל שהסוד עמוק יותר ורוצים להטמינו, כך הוא עומד שם בפנים רגילות יותר."},"ICON-1826":{"nm":"מעטפת חידה","de":"על החיצוני שלה לא כתובה שום מילה. הרגע שלפני קריעת החותם הוא המרגש ביותר. עד שהתשובה בידך, כל האפשרויות עדיין חיות בתוך המעטפה."},"ICON-1827":{"nm":"כיסוי לזכוכית מגדלת של בלש","de":"מכסה קטן שמניחים בעדינות על קצה הזכוכית המגדלת. כשלא מציצים דרכה, הוא מניח לעדשה לנוח בשקט. שכדי לראות היטב צריך קודם לשמור היטב - זה מה שהבלש לומד מוקדם."},"ICON-1828":{"nm":"כרטיס אוטובוס היקפי לאי","de":"כרטיס אחד לעלייה על אוטובוס המקיף את האי בסיבוב שלם. התחנה האחרונה היא שוב נקודת המוצא. על דרך שחוזרת שוב ושוב אל אותו מקום, הנוף נראה קצת חדש בכל פעם."},"ICON-1829":{"nm":"תג השכרת אופניים","de":"תג אחד תלוי בכידון של אופניים שאולים. חופש קצר מותר עד שיוחזרו. כשמסתיים הזמן של חציית הרוח, התג הזה אוסף בשקט את ההבטחה בחזרה."},"ICON-1830":{"nm":"כרטיס עלייה לסירה קטנה","de":"כרטיס עלייה לסירה קטנה אחת. על הסיפון המתנדנד, המרחק בין אי לאי מתקצר. חציית מסלול מים תמיד מביאה איתה קורטוב התרגשות וקורטוב בחילה גם יחד."},"ICON-1831":{"nm":"סיכת גלגל לעגלת משא","de":"סיכה האוחזת חזק בגלגל עגלת המשא. פיסת המתכת הקטנה הזאת היא שמאפשרת למשא הכבד להתגלגל. החלק הפחות בולט לעין הוא לרוב זה שנושא בדממה את מירב המשקל."},"ICON-1832":{"nm":"אסימון רכבל","de":"אסימון עגול שמכניסים לרכבל החוצה את האוויר. ברגע שהרגליים עוזבות את הקרקע, האי כולו מתקבץ למבט אחד. ככל שעולים גבוה יותר, הנוף נעשה נדיב יותר ויותר."},"ICON-1833":{"nm":"רצועת עלייה לכדור פורח","de":"רצועה שכורכים סביב פרק כף היד לפני העלייה לסל. כשהלהבה מתנפחת והאדמה מתרחקת, גם הלב נעשה קל יותר. לרחף פירושו להניח לרגע את המשקל בצד."},"ICON-1834":{"nm":"אסימון קריאה למונית מים","de":"אסימון קטן לקריאת מונית הדוהרת על פני המים. מרימים יד, והסירה מתקרבת בוקעת את הזרם. מה שסולל דרך גם היכן שאין דרך הוא, בסופו של דבר, האומץ של מי שקורא ראשון."},"ICON-1835":{"nm":"כרטיס כניסה לשביל הרים","de":"כרטיס שמקבלים בשער הראשון אל ההר. מכאן ואילך, קצות הרגליים הם שקובעים את הדרך. גם אם הפסגה רחוקה, רק מי שעבר את הכניסה מובטח לו הנוף הזה."},"ICON-1836":{"nm":"מפתח לוקר בנמל","de":"מפתח קטן הפותח לוקר ליד הרציף. לאחר שהפקדת את המטען, בידיים קלות אתה מביט אל הים. שיש היכן להניח דברים לרגע, זה מה שמלווה אומץ למי שיוצא למרחקים."},"ICON-1837":{"nm":"מכסה צנצנת כבישה","de":"מכסה צנצנת הכולא בתוכו דברים חמוצים. כשסוגרים אותו היטב, מלפפוני הקיץ שומרים על הפריכות שלהם עד החורף. סוד הניצחון על הזמן מתחיל, מתברר, בסגירה טובה."},"ICON-1838":{"nm":"תווית לרשת ייבוש","de":"תווית המודבקת לדברים הפרושים לייבוש על המצע. אם רושמים מה ומתי נפרש, ההמתנה אינה מתערבבת. גם בזמנו של השמש והרוח, יש צורך בסדר תורים."},"ICON-1839":{"nm":"שקית שבבי עישון","de":"שקית המכילה שבבי עץ ריחני. כשפותחים את הפתח, ריח כמו של מדורה מברך ראשון את האף. טעם שהעשן העמיק פותח את עצמו לאט, רק בפני מי שיודע להמתין."},"ICON-1840":{"nm":"מדבקת שימורים","de":"מדבקה שמדביקים על הכד כדי שיחזיק מעמד היטב לאורך שנה. היום שבו הוכן והמסירות שהושקעה כתובים עליה. אוכל שנשמר לאורך זמן תמיד מלווה בפתק קטן שמנסה לזכור את טעם הידיים של אותו יום."},"ICON-1841":{"nm":"תג שעון תסיסה","de":"התסיסה אינה מאמינה לשעון. היא מודדת זמן בריח ולא במחוג הדקות. ברגע שריח חמצמץ נוגע בקצה האף, התג מהנהן בשקט: \"עכשיו זה מוכן.\" גם להמתנה יש סרגל מדידה משלה."},"ICON-1842":{"nm":"סיכת מיון למקרר","de":"כאן עומד השוטר התנועה הקטן של המקרר. ירקות למעלה, תוספות למטה, שאריות אתמול בשורה הקדמית. נועצים סיכה אחת, והיד שתמיד תעתה בפתיחת הדלת מוצאת פתאום את דרכה."},"ICON-1843":{"nm":"רצועת חימום לקופסת אוכל","de":"אמא כרכה רצועה סביב קופסת האוכל, כדי שהחום לא יברח עד הצהריים. כשמתירים את הרצועה, מתחת למכסה המאודה מונחת עדיין המסירות של הבוקר, חמה, ומחכה לי."},"ICON-1844":{"nm":"בקבוק הבשלת רוטב","de":"תיבול טוב לעולם אינו ממהר. הוא נותן בשקט זמן לרוטב הסויה ולשום לחלחל זה אל זה. בחשכת הבקבוק הטעם מעמיק לאט, וחוכמתה האיטית של מרפסת הכדים עוברת להתגורר בבקבוק קטן."},"ICON-1845":{"nm":"תווית ריבת עונה","de":"באביב תות שדה, בקיץ משמש, בסתיו תאנה. תווית אחת רושמת בבירור את העונה על הצנצנת. פותחים את המכסה באמצע החורף, ואור השמש של אשתקד נמס לאט, כפית אחר כפית."},"ICON-1846":{"nm":"לוח סמלי איסוף","de":"אין צורך לספור כמה נאספו. לוח הסמלים מתגאה בשבילך. עם כל תא ריק שמתמלא, הכתפיים מתרוממות מעט - זה לא מספר, אלא שביל עקבות שהוטבע על קצות האצבעות."},"ICON-1847":{"nm":"כרטיס תא בלתי מגולה","de":"מקום אחד שעדיין לא נפגש. הצללית שבכרטיס מציעה הבטחה בקווי מתאר מטושטשים בלבד. ריק פירושו שעומד להתמלא, ולכן ההתרגשות תמיד מחכה לך בצורת סימן שאלה."},"ICON-1848":{"nm":"חותמת סיום קטלוג","de":"הצליל של החותמת שנוחתת \"טראח\" בתא האחרון. סוגרים את הקטלוג, פותחים את כף היד, ונקודת דיו אדומה נדבקת שם כמו אות הצטיינות על השלמה. ההקלה העמוקה הזאת מוכרת רק למי שאסף עד הסוף."},"ICON-1849":{"nm":"אסימון צבע נדירות","de":"גם אם הצורה זהה, כשהצבע שונה - הסיפור משתנה. אסימון אחד מותח בשקט קו בין השגרתי ליקר. עינו של האספן תמיד עוצרת זמן רב מול אותו הבדל גוון עדין."},"ICON-1850":{"nm":"שובר החלפה לפריטים כפולים","de":"עוד אחד, שוב. ביום שבו הרימו בפעם השלישית משהו שכבר יש לך, השובר הזה מושיט בחשאי יד. כמו נחמה עדינה שאומרת - גם כפילות, אם מחבקים אותה ולא זורקים, תחזור יום אחד כמשהו יקר."},"ICON-1851":{"nm":"לוחית מספר לתיבת אוסף","de":"כשמסמנים כל תיבה במספר, המחסן הופך לספרייה קטנה. בתיבה 17 מה שנאסף באביב, בתיבה 23 מה שנלקט על שפת הים. אני אינדקס שקט, המסדר זיכרונות מפוזרים שורה אחר שורה."},"ICON-1852":{"nm":"מדריך פריסת תצוגה","de":"מיקום בונה מחצית מהתצוגה. הגבוה אחורה, המבריק במרכז. עוקבים אחר המדריך ומזיזים ביד, והמדף המבולגן נרגע בלי משים כמו גלריה קטנה, ושואף אוויר."},"ICON-1853":{"nm":"מטלית אבק לאוסף","de":"ככל שהדבר יקר יותר, כך האבק שוקע עליו ביתר קלות. בקצה מברשת רכה, בעדינות, מטאטאים גם את תחושת האשמה על שלא הבטת בו זמן רב. בעת הניקוי, גם הזיכרונות הרדומים נוצצים לרגע מחדש."},"ICON-1854":{"nm":"שובר הרחבת אחסון","de":"כשאוספים מספיק זמן, אפילו מחסור במקום הופך לדאגה מאושרת. הלב הנח בשקט למראה מדף אחד נוסף - זו לא תאוות בצע, אלא הוכחה שיש כל כך הרבה שאוהבים."},"ICON-1855":{"nm":"כרטיס קוד הזמנת חברים","de":"מסירת הקוד הזה היא ההזמנה העדינה ביותר לומר \"בוא נשחק יחד\". הלב הטמון בכמה ספרות. רק כשהחבר שקיבל אותו דורך את צעדו הראשון על האי, מתחיל סיפור ששייך רק לשניכם."},"ICON-1856":{"nm":"מפתח מחסן משותף","de":"דלת המחסן לעולם אינה נפתחת לבד. מנעול שמסתובב רק כששתי ידיים, שלך ושלי, מתאחדות. במרחב משותף תמיד תלויה הבטחה נשמרת יחד, בצורת מפתח."},"ICON-1857":{"nm":"תג דיווח אבידה","de":"גם חפץ אבוד יקר למישהו. לתלות שורה שכתוב בה \"הנה זה כאן\". התג הוא חוט קטן המחבר בשקט מחדש בין לב שאבד לרגע לבין בעליו."},"ICON-1858":{"nm":"דגל קריאה לעזרה","de":"לבקש עזרה זה לא חולשה אלא אומץ. כשהדגל מונף, מישהו רץ ממקום כלשהו. מה שמתפשט הכי מהר באי הזה אינו שמועה, אלא ידיים המושטות זו אל זו."},"ICON-1859":{"nm":"צמיד קשר לחירום","de":"קורטוב שלווה קטן הכרוך סביב פרק כף היד. מה שלא יקרה, המספר הכתוב כאן ירוץ לעזרה מהר מכולם. מלווה שקט, נשכח בימי חול, שהופך לתומך ביותר ברגע הצורך."},"ICON-1860":{"nm":"אסימון חלוקת תפקידים","de":"מי עושה קניות ומי מבשל - מחלקים אסימונים ואין על מה לריב. הצעד הראשון ביצירת דבר משותף מתחיל בקביעה עדינה של חלקו של כל אחד."},"ICON-1861":{"nm":"לוח יצירה משותפת","de":"מה שלבד לא היה עולה אפילו על הדעת, כשרבים מתכנסים, נעשה אפשרי כמו קסם. ככל שנוספים שמות ללוח אחד אחר השני, התאים הריקים פוחתים והצחוק גדל. השיתוף גדל בשקט במרחב שבין תא לתא."},"ICON-1862":{"nm":"כרטיס נימוסי ביקור","de":"כשנכנסים לביתו של מישהו אחר, נעשים זהירים כבר מקצות האצבעות. מה שכתוב על הכרטיס אינו כללים גדולים, אלא רק הבטחות קטנות וחמות כמו \"לסדר את הנעליים, לברך תחילה\"."},"ICON-1863":{"nm":"פעמון סיום מסיבה","de":"גם לשמחה צריך סוף כדי שהבא יחכה לו. כשהפעמון מצלצל \"צלול\", כולם אוספים את חפציהם בפנים מהוססות ומלאות חרטה. מסיבה שיודעת להיפרד היטב היא זו שנשארת הכי הרבה זמן בלב."},"ICON-1864":{"nm":"רצועת פינות למזרן","de":"לא משנה כמה חלק פורשים את המצעים, הפינות תמיד מתרוממות. הודות לרצועה האוחזת חזק בארבע הפינות, המיטה מתעוררת כל בוקר מסודרת כמו בחדר מלון."},"ICON-1865":{"nm":"חוט כפתור לצוארון השמיכה","de":"אני חוט הכפתור האוחז בצווארון השמיכה. כמה שלא תתהפכו במהלך הלילה, אני אוחז חזק כדי שהצווארון לא יברח. שמיכה שאין בה קמט אחד עם ההתעוררות - זהו הגמול על משמרת הלילה שלי."},"ICON-1866":{"nm":"קליפס קיבוע לטופר","de":"הטופר מנסה להחליק בחשאי בכל הזדמנות. בכל פעם, הקליפס נושך חזק בפינה ושומר על מקומו. עקשן שקט אחד, האוחז במקום השינה מפינה בלתי נראית."},"ICON-1867":{"nm":"מחליק קמטי סדין","de":"קמטי הסדין הקטנים שנוצרים במהלך הלילה דומים איכשהו לקמטי הלב. כמו הבד המחליק בהעברה אחת של המחליק, הלוואי שגם היום המקומט יתגהץ כה יפה."},"ICON-1868":{"nm":"בסיס אוורור למזרן","de":"גם המזרן זקוק לרווח לנשום. כשהבסיס פותח מסלול אוויר מלמטה, הלחות בורחת והיובש חודר. שינה טובה מתחילה בשקט, מן האוויר עצמו התומך בגב."},"ICON-1869":{"nm":"כיסוי רוכסן לציפת שמיכה","de":"אותה מהומת חצות שבה הפלטה כל הזמן בוקעת בזמן החלפת ציפת השמיכה. כשמכסים את הרוכסן בדשן פעם אחת, אין עוד להתעורר מרגל שנתפסה בו. שלום גדול שמביא איתו כיסוי קטן אחד."},"ICON-1870":{"nm":"כרית מניעת גבשושיות","de":"מילוי הכרית נודד בלי משים לצד אחד ויוצר גבעה קטנה. כשהכרית עומדת בדממה בתווך, השטיחות נשארת עד הסוף. הודות לה, רכות כמו חדשה חוזרת בלי כשל בכל לילה."},"ICON-1871":{"nm":"וו אלסטי לסדין","de":"הסדין תמיד מנסה להתקלף לאט לצד אחד. כשתולים וו בפינות ומותחים אותו חזק, הוא לא זז גם אם מתהפכים כל הלילה. המתיחות הופכת כך בשקט לתשתית של שינה עמוקה."},"ICON-1872":{"nm":"תג החלפת ציפת כרית","de":"כשלפתע לא זוכרים אם כיבסו את ציפת הכרית היום, תג אחד עונה בבירור. לוח זמנים ששוכחים בגלל שינה על גבי שינה, הסימן הקטן הזה זוכר בקפדנות במקומך."},"ICON-1873":{"nm":"סימנייה ליומן חלומות","de":"את החלום המתפזר בין האצבעות ברגע ההתעוררות, הסימנייה עוצרת בעמוד שבו הונחה. פותחים אותו, והים והשמיים של אמש עדיין שם - גשר קטן המונח בעדינות בין השינה לכתיבה."},"ICON-1874":{"nm":"אבן חלוק לרעש לבן","de":"לילה שקט מדי דווקא נוטה להעיר. כשהחלוק משחרר רשרוש עדין הדומה לקול גשם, הלב שוקע לאט לאורך המרקם הזה. אבן קטנה המרגיעה בשקט את הדממה."},"ICON-1875":{"nm":"אסימון שינה חכם לחום גוף","de":"האם המצח חם או קצות הרגליים קרות במהלך השינה - האסימון עוקב בשקט מהצד. הודות לשומר הלילה שמוצא בעדינות את הטמפרטורה המדויקת לגוף, השינה זורמת עד השחר בלי להתעורר."},"ICON-1876":{"nm":"קליפס לווילון האפלה","de":"אור הבוקר כה חרוץ, שהוא כל הזמן מתגנב דרך הפער בווילון. כשקושרים את שני הקצוות חזק בקליפס, החדר מחשיך שוב כמו באמצע הלילה. שותף אמין לפשע של עוד קצת שינה."},"ICON-1877":{"nm":"מנורת הקרנת ירח","de":"כשמכבים את האור, ירח עולה על התקרה. האור העדין שהמנורה יורה כלפי מעלה הופך את החדר לרקיע לילה קטן. את התחושה של הירדמות בהבטה כלפי הירח, מניחים כך בדיוק ליד הראש."},"ICON-1878":{"nm":"תלייה לשקית ריח לשינה","de":"שקית ובה לבנדר וריח עשב מתנדנדת בעדינות ליד הראש. עם הריח החודר אל האף, הכתפיים מתרפות מעצמן, ושקית קטנה אחת מזמינה את השינה עוד לפני הכרית."},"ICON-1879":{"nm":"סיכת תיבת נגינה לשיר ערש","de":"כשמותחים בעדינות את הקפיץ, מנגינה קטנה משתחררת. שיר הערש המסתובב מקצה הסיכה דומה מאוד לקצב שבו סבתא ליטפה את הגב. כל צליל וצליל מכביד לאט על העפעפיים."},"ICON-1880":{"nm":"כוס צמח לחות","de":"אני כוס המגדלת צמח במים צלולים במקום באדמה. כשמתבוננים בשורשים הדקים הצפים במים, אפילו אוויר החדר נעשה לח יותר. באר ירוקה קטנה, אגורה על השולחן."},"ICON-1881":{"nm":"בקבוק איסוף שברי חלום","de":"לחלום שנשפך בתוך השינה אין צורה, וכשמתעוררים הוא נמלט בין האצבעות. לעצור בעדינות שבר אחד העומד להיעלם באמצעות מכסה הבקבוק, ולהחזיק בו עד הבוקר - כך, במקום קטן כזה, מתחיל הרצון לזכור."},"ICON-1882":{"nm":"מגש משקפיים ליד המיטה","de":"ברגע שמסירים את המשקפיים ומניחים אותם בצד, באורח מוזר, גם עייפות היום כולה יורדת איתם. הפינה הקטנה הזאת ליד הראש נמצאת שם כדי לקבל את התנועה היחידה הזאת. מגש שמטשטש בשקט את העולם לפני השינה."},"ICON-1883":{"nm":"טבעת תחתית לכוס על שידה","de":"כתם עגול אחד שכוס מים משאירה עשוי להיראות פעוט, אך לגזע העץ של השידה הוא פגם. טבעת קטנה שמניחים כדי למנוע זאת. לב אוהב תמיד עובד בשקט במקומות בלתי נראים כאלה."},"ICON-1884":{"nm":"מיישר פינות לקיפול שמיכה","de":"גם לקיפול השמיכה למרובע מסודר יש מרקם משלו. מיישרים פינות לפי הכלי הזה, וגם לב מבולגן מתיישר פעם אחת. מקום מסודר הוא הברכה המהוגנת ביותר לפתיחת היום."},"ICON-1885":{"nm":"וו כבל טעינה ליד המיטה","de":"וו שנתלה ליד הראש כי לא נסבל שכבל הטעינה מחליק אל הרצפה לאורך הלילה. הכבל שהתמלא בשקט באנרגיה במהלך השינה מחכה מלא לגמרי לקצות האצבעות עם הבוקר."},"ICON-1886":{"nm":"סלסלת חטיפים ליד המיטה","de":"סלסלה שאספה חטיפים אהובים במקום שהיד מגיעה אליו. הכנה עדינה שצפתה מראש רעב שיגיע בשעת לילה מאוחרת. קול הרשרוש של נגיסה בחפיסה אחת בחשכה מעורר חיבה סתם כך."},"ICON-1887":{"nm":"כנף אחזקת ספר לשעת שינה","de":"כנף התומכת בעדינות בדף הפתוח, כדי שגם כשעייפות גוברת לא תאבד את השורה שקראת. העמוד שסגרת רגע לפני שהעיניים נעצמו מחכה לך בדיוק באותו מקום, בלילה שלמחרת."},"ICON-1888":{"nm":"בסיס אבן לשעון מעורר ליד המיטה","de":"גם לשעון המעורר שמעיר את הבוקר דרוש מקום קבוע שלא יתנדנד. הבסיס העגול מקבל את משקלו ביציבות, ושומר על מקומו כמו הבטחה שלא תחליק גם כשעולה השחר."},"ICON-1889":{"nm":"מסמר תלייה למסכת שינה","de":"מסמר אחד שתולים עליו את מסכת השינה שחסמה את האור כל הלילה, כדי שתנשום במהלך היום. להעניק מקום יבש לבד שמילא את תפקידו - כך, ללא רבב, חודרת אכפתיות קטנה."},"ICON-1890":{"nm":"קליפס לפנס ליד המיטה","de":"קליפס האוחז את האור הקטן הדרוש בחצות, לכיוון הרצוי. כשנועצים את הפנס בקצה המיטה, היד שגששה בחשכה נעשית רגועה בהרבה. נגיעה הקובעת את כיוון האור."},"ICON-1891":{"nm":"חוט קשירה למחיצת וילון","de":"חוט האוחז בווילון המפריד מרחב משותף. זהו רק דף בד דק אחד, אך מעברו נמצא לילה פרטי של מישהו. גבול עדין השומר על שנתו של האחר בחדר משותף."},"ICON-1892":{"nm":"לוח עץ לחלוקת שקע משותף","de":"לוח עץ שנוצר כדי שרבים יוכלו לחלוק שקע יחיד. הוא מפזר את החשמל באופן שווה, כדי שלילה של אף אחד לא יישאר חשוך. חיים משותפים מתחילים, בסופו של דבר, בחלוקת דברים קטנים כאלה."},"ICON-1893":{"nm":"אבן ויתור לעמעום תאורה","de":"כשהאור בהיר מדי, מעבירים בחשאי אבן במקום מילים. \"אפשר להנמיך קצת?\" - את המשפט הזה מעביר במקומך החפץ הקטן הזה. הבקשה העדינה ביותר בחדר משותף."},"ICON-1894":{"nm":"אסימון ויתור על שעת השכמה","de":"פיסה קטנה שמעבירים לכף היד של מי שיקום ראשון. מי ישן עוד קצת בשחר ומי יתעורר ראשון - האסימון הזה קובע זאת בלי מריבה. הלב שקובע את סדר הוויתורים בקצות האצבעות."},"ICON-1895":{"nm":"טבעת מספור לקולב משותף","de":"טבעות מספר שסומנו על קולבים בשימוש משותף. כדי שלא יתבלבלו למי שייך כל מקום, מספר קטן אחד יוצר בשקט סדר. קו עדין המסומן בחיי יומיום שנוטים להתערבב."},"ICON-1896":{"nm":"כיסוי מדרגה למיטת קומותיים","de":"כיסוי המולבש על המדרגה העולה לקומה השנייה. כדי שכף רגל יחפה שנוגעת בו לא תהיה קרה או חלקה, הוא שומר על בטיחות המדרגה. תשומת הלב הקטנה הזאת בקצה הסולם תומכת בביטחון בחלומות של הקומה העליונה."},"ICON-1897":{"nm":"זרוע תלייה למגבוני נייר משותפים","de":"מתקן בצורת זרוע לתלייה של נייר טואלט בשירותים משותפים. הוא ממוקם כך שכל אחד יוכל למשוך פיסה אחת בקלות ביד אחת. גם אם נראה שולי, זו נגיעה המחברת בחלקות את בוקרם של רבים."},"ICON-1898":{"nm":"אסימון תור למבשם אוויר","de":"אסימון שרשום עליו התור - מי ימלא מחדש את המבשם. גם רצועת ריח עדינה אחת היא הבטחה לקחת אחריות לפי תור. ריח טוב אינו בא בחינם, הוא פורח בתורו של מישהו."},"ICON-1899":{"nm":"ידית מנורת לילה משותפת","de":"ידית של מנורת לילה שרבים מדליקים ומכבים יחד. היד שנשארה ערה עד הכי מאוחר היא זו שאוספת את האור אחרונה. הבטחה שקטה של אלה החולקים חדר אחד, לחלוק אור עדין."},"ICON-1900":{"nm":"שקע כוס בזרוע ספה","de":"שקע עגול חצוב בזרוע הספה. אפשר להניח מהיד את הכוס לרגע בלי לחשוש משפיכה. במקום למנוחה חייב להיות מקום להניח בו כוס, רק אז הלב יכול להשתרע בנחת סופית."},"ICON-1901":{"nm":"ידית רוכסן לציפית כרית","de":"לשונית קטנה המחוברת לרוכסן הפותח וסוגר את תוך הכרית. טבעת אחת חוסכת את הטרחה שבהחלפת הכיסוי. יד הדואגת גם לפינה הנסתרת מבפנים - החמימות שבניהול הבית תמיד מתחבאת שם."},"ICON-1902":{"nm":"כרית תמיכה למשענת ספה","de":"כרית הממלאת את הרווח במשענת ותומכת בגב התחתון. היא ממלאת את החלל הריק כדי שהגב לא יכאב גם אחרי ישיבה ארוכה. הנוחות שהגוף מזהה ראשון, נאנח “אה, זהו זה”, ברגע שנשענים אחורה."},"ICON-1903":{"nm":"רצועת הידוק לפינת כרית ישיבה","de":"רצועה האוחזת בכרית מהפינות, זו שנהגה לזחול בכל פעם שישבת עליה. היא מקבעת אותה במקום אחד כדי שלא תחליק. סדר מתחיל מהידוק קטן ועיקש כזה."},"ICON-1904":{"nm":"רצועת מיגון לתפר כרית","de":"המקום הראשון שבו כרית נשחקת הוא תמיד תפר הפינה. רצועת מיגון העוטפת את המקום הזה מראש, ושומרת עליו מפני קריעה. לב שרוצה לשמור אותה קרוב לאורך זמן, יציב כמו תפר."},"ICON-1905":{"nm":"כיס לשלט בין כריות הספה","de":"לשלט שנעלם שוב ושוב בין הכריות, סוף סוף יש בית משלו. כיס קטן שנתחב בסדק שבין כריות הספה. לדעת שמה שחשבת שאבד תמיד נמצא שם, זו הרגעה גדולה יותר משנדמה."},"ICON-1906":{"nm":"חבל לגלילת שמיכת ברכיים","de":"חבל לגלגל ולקשור בו שמיכת ברכיים. חום שמתפזר כשמשאירים אותה פרושה, נאסף בקפידה לקראת הלילה הבא. גם חמימות, כשאוספים אותה כך, אפשר להוציא ולפרוש שוב מחר."},"ICON-1907":{"nm":"כפתור לכיסוי הדום","de":"כפתור המהדק את כיסוי ההדום - החלק שנשחק הכי מהר ממגע כפות הרגליים - כדי שיהיה קל להחליפו. הנקישה הקטנה הזו מאריכה את חיי הבד. לב שרוצה להשתמש בדברים לאורך זמן, קפדני בפרטים הקטנים."},"ICON-1908":{"nm":"כיסוי החלקה לרגלי ספה","de":"גם ספה כבדה אסור שתשרוט את הרצפה. כיסוי רך המולבש על ארבע קצוות הרגליים מטפטף בזהירות ומגן על רצפת העץ. רהיט שזהיר עד קצות אצבעותיו זוכה איכשהו לחיבה נוספת."},"ICON-1909":{"nm":"מעמד לאיסוף שלטים","de":"מעמד שמסדר בשורה אחת, זה לצד זה, את השלטים שנהגו להתגלגל ולהתפזר לכל עבר. כשהמקלות הארוכים והקצרים עומדים מיושרים בשורה, זה לבדו משכיך את אווירת החדר בטון אחד."},"ICON-1910":{"nm":"וו טעינה לבקר משחק","de":"וו לתלות עליו ולטעון את בקר המשחק אחרי סבב משחק סוער. בזמן שהוא תלוי ומתמלא בשקט באנרגיה, גם הידיים נחות לרגע. ההפוגה הקצרה הזו מכינה בביטחון את הסיבוב הבא."},"ICON-1911":{"nm":"שקית לכלי משחק לוח","de":"שקית קטנה המכילה כלים בכל צבע. הכלים הממתינים בתוך שקית אחת לסיבוב הבא משמיעים קול נקישה בכל ניעור. בקול הזה מתעוררת ראשונה ההתרגשות של “עוד סיבוב אחד?”."},"ICON-1912":{"nm":"צלחת להטלת קוביות","de":"צלחת המיועדת אך ורק להטלת קוביות. את המזל שנהג לקפוץ מהשולחן ולהיעלם, השפה שלה כולאת בפנים. באותו רגע קצר שבו הקוביות מתגלגלות ונעצרות, הנשימה של כולם נעצרת יחד לרגע."},"ICON-1913":{"nm":"רצועה לחפיסת קלפים","de":"רצועה הכורכת חפיסת קלפים כדי שלא תתפזר. עד שהיא מעורבבת, הסדר הזה הוא הבטחה בפני עצמה. בתנועת ההסרה של הרצועה ופריסת הקלפים, מתחילה סוף סוף עלילת הסיבוב."},"ICON-1914":{"nm":"קליפס לסידור כבלים מאחורי הקונסולה","de":"קליפס האוחז ומסרק כלפי מטה את הכבלים המסובכים מאחורי הקונסולה. הוא מסדר בשקט את האי-סדר במקום שכמעט אי אפשר לראות. הסדר תמיד מושלם בשקט כזה, מאחורי הגב."},"ICON-1915":{"nm":"חוגת ניקוד","de":"חוגה קטנה שמסובבים כדי להראות את הניקוד. נקישה, ועם כל שלב שהמספר עולה, מצטרפות תשואות. גם בלי לספור בראש, קצות האצבעות זוכרים ראשונים את תוצאת אותו היום."},"ICON-1916":{"nm":"מעמד להצבת לוח משחק","de":"מעמד שמציב את לוח המשחק בשיפוע, וקובע את הזווית כך שכל היושבים סביב יראו את הלוח במבט אחד. כדי שאף אחד לא יצטרך למתוח את הצוואר, הוא פורש בשקט מבט הוגן לכולם."},"ICON-1917":{"nm":"כוס הגרלת תור","de":"כוס שתוחבים לתוכה יד כדי להגריל את סדר המשחק. המקל היחיד שממששים ותופסים קובע מי מתחיל ראשון. באותו רגע קצר של הישענות קלה על המזל, כולם רוטטים יחד בתוך הכוס העגולה."},"ICON-1918":{"nm":"צלחת מחולקת לחטיפים משותפים","de":"צלחת מחולקת להגשת חטיפים לפי סוג. כשהמקום מחולק, אפשר לבחור את מה שאוהבים בלי שהידיים יתנגשו. תשומת הלב שהביאה בחשבון את מי שישתפו איתם שוכנת בכל תא ותא."},"ICON-1919":{"nm":"כיסוי חימום לקומקום תה","de":"כיסוי העוטף את כתפי קומקום התה ושומר על חומו. הוא עוטף אותו כדי שהתה לא יתקרר בזמן שהוא מתבשל לאט. רצון קצות האצבעות להגיש כוס חמה, חמה עד הסוף."},"ICON-1920":{"nm":"תחתית למנוחת שקית תה","de":"תחתית שאליה מרימים שקית תה שהושרתה עד תום, ומניחים לה לנוח לרגע. היא קולטת אפילו את הטיפה האחרונה כדי שלא תישפך. מקום שמעניק אפילו לעלה שמילא את תפקידו, סיום מסודר."},"ICON-1921":{"nm":"טבעת סימון לספלים משותפים","de":"שישה ספלים זהים על מדף חדר ההפסקה. במקום לשאול של מי מה, הכנסנו טבעות בצבעים שונים. סימן קטן אחד קושר בשקט שישה אנשים, כל אחד עם טעמו שלו, לאותו מקום סביב אותו שולחן."},"ICON-1922":{"nm":"סלסלת פופקורן לשיתוף","de":"בזמן שהוא עובר מיד ליד, האד הריחני מברך ראשון לשלום. אם יש משהו שבמוזרות אינו פוחת ככל שקוצצים ממנו חופן אחר חופן, זהו כנראה ליבו של ערב שחולקים יחד סביב שולחן."},"ICON-1923":{"nm":"קופסת מלקחיים לקוביות סוכר","de":"קוביית סוכר מרובעת נוקשת במלקחיים ונופלת בעדינות לתוך כוס התה. לצפות בפינות הלבנות נמסות לאט ונעלמות - זהו טקס מתיקות שלא ממהר, שנלמד לראשונה על שולחן התה של סבתא."},"ICON-1924":{"nm":"מצע נגד החלקה למגש","de":"גם אם המגש נוטה הצידה, הכוסות שומרות על מקומן. כמו כל הדברים שתומכים בשקט מלמטה, המצע לבדו סופג את רגע ההחלקה שכמעט קרתה, ובסוף שותק."},"ICON-1925":{"nm":"כוס עמידה לקשית שתייה","de":"כשהקשית עומדת זקופה, גם המשקה וגם הלב אינם מתפזרים. אחר צהריים שבו השולחן מתארגן בזכות זקיפות קטנה אחת, הכוס מחבקת עמוד קטן ותומכת בשקט בשעות העצלות."},"ICON-1926":{"nm":"קולטן פירורי עוגיות","de":"פריך, וברגע שהעוגייה נשברת, הפירורים הנופלים נאספים לכאן. לקלוט אפילו את העקבות שהותירה הביס הטעים ביותר - זו נקודת הסיום השקטה של השולחן, עדינה גם עד לפירור האחרון."},"ICON-1927":{"nm":"חוט תלייה עם קליפסים לתמונות","de":"תולים תמונות פולארויד אחת אחת בעזרת קליפסים על חוט מתוח כמו חבל כביסה. בזמן שהחיוכים של היום מתנופפים ומתייבשים ברוח, פינה אחת בקיר הופכת לגלריית זיכרונות קטנה ומוארת."},"ICON-1928":{"nm":"סליל זיכרונות","de":"סליל שחוט מסובך נפרם ונכרך עליו מחדש בסדר. הדברים שנמשכו הלאה, קשורים בקשר בכל מקום שבו נקרעו. אם מכרכרים גם את הזיכרון כך לאט, סיבוב אחר סיבוב, דרך שנדמתה כמתקצרת מתארכת שוב."},"ICON-1929":{"nm":"כיסוי למסמר תלייה בקיר","de":"כיסוי עגול קטן שמסתיר סימן מסמר. לכסות בעדינות אפילו את הצלקת הקטנה שנותרה אחרי הורדת מה שהיה תלוי שם, והקיר חוזר לפנים חלקות כאילו לא קרה דבר."},"ICON-1930":{"nm":"מסגרת להכנסת תמונה קבוצתית","de":"תמונה קבוצתית של שישה שצולמו עם כתפיים צמודות. ברגע שמכניסים אותה למסגרת, הצחוק והחום של אותו יום נחתמים יחד בפנים. מסגרת היא היד שעוצרת בשקט הרב ביותר את היום החולף."},"ICON-1931":{"nm":"לוח שעם לפתקים","de":"לוח חום גדוש בסימני נעצים. הבטחה שאסור לשכוח, פתק עידוד שמישהו הדביק, המטלות של היום - כולם ננעצים שכבה על גבי שכבה. קיר נאמן ליד השולחן שזוכר במקום הראש."},"ICON-1932":{"nm":"קשר לתליית זר קישוט","de":"גם לזר אחד התלוי על הדלת נדרשת אומנות של קצות אצבעות. הקשר חייב להיות הדוק כדי שלא ייפול גם בעונה הסוערת. הלב שמקבל את פני מישהו תמיד מתחזק ראשון במקום הבלתי נראה."},"ICON-1933":{"nm":"כיסוי מטוטלת לשעון קיר","de":"כיסוי בד העוטף את המטוטלת המתקתקת ומגן עליה מאבק. אפילו מלאכת מדידת הזמן זוכה לטיפוח כזה. אם שומרים עליו בעדינות מפני בלאי, שעון הקיר נשאר לצדנו זמן מה נוסף."},"ICON-1934":{"nm":"לוח אוסף מדבקות","de":"מדבקות שנהגו להתפזר בכל מגירה מתאספות על לוח אחד ומתייצבות בשורה. דמות אהובה, כוכב נוצץ, פתק בכתב יד. כשהשמחה הקטנה של האיסוף מסתדרת בקפידה, גם הלב מתיישר."},"ICON-1935":{"nm":"חוט חיבור לדגלוני קישוט","de":"חוט המחבר דגלים צבעוניים לשורה אחת. יום הולדת או קבלת פנים - ברגע שהחוט חוצה את התקרה, חדר רגיל הופך לבית של חגיגה. חגיגה היא מלאכת חיבור ואיחוי של לב שנקרע."},"ICON-1936":{"nm":"תחתית שעם לקומקום חשמלי","de":"פיסת שעם אחת התומכת בתחתית הקומקום הרותח. כדי שהשולחן לא ייכווה, היא מחבקת את החום הזה לבדה. תשומת לב קטנה שתומכת בשקט כדי שחמימותו של איש לא תותיר סימן."},"ICON-1937":{"nm":"מגש פירורים למצנם","de":"הפירורים שהפילה הלחם הקלוי הזהוב מתגלגלים אל תוך המגש. פשוט מחליקים אותו החוצה ומנערים - וזהו. הוא קולט בלי מילים את הבוקר העמוס, ומתכונן שוב נקי לארוחה הבאה."},"ICON-1938":{"nm":"טבעת מסתובבת למיקרוגל","de":"על הטבעת המסתובבת, הצלחת מציירת לאט סיבוב שלם. הסיבוב הזה, שנועד לחמם באופן אחיד, מחיה מחדש את האורז המקורר של אתמול לארוחה מהבילה שוב."},"ICON-1939":{"nm":"כיסוי לכיריים אינדוקציה ניידות","de":"לא משנה לאן השמן מתיז, הכיריים נשארות נקיות. כיסוי אחד מפריד בין החום העז לבין הידיים. הדברים שחוסמים בלי שרואים אותם שומרים על המטבח כמקום שלא נכווה."},"ICON-1940":{"nm":"מכסה שחרור אדים לסיר אורז","de":"צליל שריקת האדים היוצא - פסססס. הודות למכסה קטן המשחרר בעדינות את הלחץ הכלוא, האורז שזה עתה התבשל פותח את מכסהו בפנים הרכות ביותר. בזמן ההשרייה אין למהר."},"ICON-1941":{"nm":"מעמד עמידה לכף בישול","de":"מציבים זקוף את הכף ששימשה לערבב את המרק. לב קטן שלא רוצה להשאיר אפילו כתם אחד על משטח העבודה. הסדר במטבח תמיד מתחיל ממקומות קטנים ובלתי בולטים כאלה."},"ICON-1942":{"nm":"כיסוי סיליקון לידית סיר","de":"מרכיבים סיליקון על ידית סיר לוהטת והיד לא נכווית. שכבה אחת שמתערבת בין החום לכף היד. הוא מגן על מי שמבשל ארוחות חמות, מהמקום הקרוב ביותר."},"ICON-1943":{"nm":"מסננת אבנית לקומקום חשמלי","de":"גם למים שמרתיחים כל יום מצטבר עם הזמן סימן דהוי. רשת צפופה מסננת בשקט את האבנית, ומוזגת רק כוס צלולה. יד חרוצה ששומרת מהמקום הבלתי נראה על הלגימה הראשונה של התה."},"ICON-1944":{"nm":"טיימר בישול עם רגלי קליפס","de":"“עוד שלוש דקות,” אומר הטיימר, נושך בחוזקה בקצה השולחן עם רגלי הקליפס שלו. בזמן שהאטריות מתבשלות, הוא עומד יציב על רגליו הקטנות, מתקתק וסופר יחד את הרגע המצופה ביותר של היום."},"ICON-1945":{"nm":"כוס ניקוז לסכו\"ם","de":"מים זולגים מהסכו\"ם שזה עתה נשטף. כשכוס הניקוז אוספת בשקט את הלחות הזו, השולחן מתייבש כלאחר יד. סדר הוא חריצות עדינה ששומרת אפילו על טיפת מים אחת."},"ICON-1946":{"nm":"מעמד תאים לצלחות בעמידה","de":"מציבים את הצלחות זקופות, מחולקות לתאים. כלים שנהגו לשרוט זה את זה כשנערמו, מקבלים כעת כל אחד את פינתו. סדר הוא, בסופו של דבר, הענקת תא משלו לכל אחד כדי שלא יתנגשו."},"ICON-1947":{"nm":"טבעת התאמת זוגות לצ'ופסטיקס","de":"משחילים על הטבעת את המקלות שנותרו בודדים בלי בן זוגם, ומחזירים את השניים יחד. מקל יחיד מאבד מהר את שימושו, ולכן הטבעת הקטנה הזו, הקושרת אותם זה לצד זה, שומרת על הסדר במגירה."},"ICON-1948":{"nm":"מעמד ענפים לתליית כוסות","de":"תולים את הכוסות אחת אחת על מעמד המתפצל כמו ענפים. בזמן שהלחות מתייבשת על כל כוס הפוכה, פינה אחת במטבח עומדת בשקט כמו עץ קטן ומסודר."},"ICON-1949":{"nm":"ידית למגש תאי סכו\"ם","de":"מגש שבו כף, מקלות אכילה ומזלג שוכבים זה לצד זה בתאים. אוחזים בידית ומרימים את כולו בבת אחת, וסידור השולחן נעשה קליל בהרבה. גם במגירה שוכן, בלי יוצא מן הכלל, האסתטיקה של הסדר."},"ICON-1950":{"nm":"לוח ייבוש לכוסות מים הפוכות","de":"מניחים את הכוסות השטופות הפוכות, וטיפות המים נופלות, טיפה אחר טיפה. בזמן שהן מתייבשות לאט ליד חלון מוצף שמש, הזכוכית משיבה לעצמה בשלווה את השקיפות הראשונית שלה, לקראת הלגימה הבאה."},"ICON-1951":{"nm":"מסרק ניקוי לשיני מזלג","de":"שיניו הדקות מסרקות בעדינות אוכל שנתקע בין שיני המזלג. הודות למגע שמטפל אפילו בסדק הצר ביותר, הארוחה הבאה תמיד נפתחת בביס ראשון ללא רבב, נקי לגמרי."},"ICON-1952":{"nm":"לבד נגד החלקה לערימת כלים","de":"כשעורמים קערות, החרסינה משמיעה קול חד וצורם זו כנגד זו. גיליון בד לבד אחד, שנתחב ביניהן, משתיק את החיכוך הזה. הסוד לחיים משותפים ארוכים טמון בהשארת זה לזה קצת רכות."},"ICON-1953":{"nm":"חוט תלייה לכפית תה","de":"תולים כפית תה חמודה על טבעת ומקבעים אותה לקיר. במקום להיטמן במגירה, היא נוצצת תמיד בהישג יד - כלי קטן שתובע בגאווה את מקומו הראוי. גם לניהול הבית יש מקום קבוע לכל דבר."},"ICON-1954":{"nm":"מגש תאים למקרר","de":"כשמחלקים את תא המקרר לתאים, כל מרכיב מקבל בית קטן משלו. הדברים שהיו מעורבבים ונשכחים מוצאים את מקומם, ובכל פתיחת דלת רואים במבט אחד ובבירור מה נמצא היכן."},"ICON-1955":{"nm":"קליפס עמידה לשקיות הקפאה","de":"אוחזים בשקית הקפאה שנותרה חצי ריקה עם קליפס ומציבים אותה זקופה. כדי שלא תיפול ותישפך, כדי שיהיה קל למצוא בפעם הבאה. גם בתוך המקפיא הקר שוכנת החוכמה הפיקחית של עקרת בית מסודרת."},"ICON-1956":{"nm":"מהדק פקק בקבוק","de":"בקבוק שלא נסגר היטב מאבד את הגז עד מהרה. סיבוב אחד חזק של פרק כף היד, שמהדק את הפקק היטב, כולא את הריח והבועות בפנים שלמים עד הבוקר שלמחרת. חריצות זוהרת בדברים הקטנים."},"ICON-1957":{"nm":"מצע נגד החלקה לתא ביצים","de":"מצע שתומך בביצים העגולות בתאים נפרדים, כדי שלא יתגלגלו וישברו. הרצון לטפל בדבר השביר ביותר בעדינות הרבה ביותר, יושב קטן וחם בפינה אחת של דלת המקרר."},"ICON-1958":{"nm":"רצועת הרחבה לכיס דלת המקרר","de":"מותחים מעט הצידה את כיס דלת המקרר וחוסכים תא נוסף. כי כשמשק הבית גדל, גם המקום שלו חייב לגדול. במיומנות להרחיב מקום צר משתקפת רוחה של עקרת בית פיקחית."},"ICON-1959":{"nm":"מכסה לחיצה לשאריות תוספות","de":"מכסה שנלחץ בעדינות מעל שאריות תוספות. הוא שומר עליהן בשקט כדי שלא יתייבשו ולא יספגו ריחות זרים. יד אכפתית מקפידה על סידור אפילו מה שנותר מארוחה אחת."},"ICON-1960":{"nm":"כנף כיוון לזרימת אוויר קר","de":"לאיזה כיוון יזרום האוויר הקר? כנף קטנה קובעת בשקט את הכיוון. מטים מעט את מסלול הרוח הבלתי נראה בקצה האצבע, והקור מגיע גם לפינה הפנימית העמוקה ביותר."},"ICON-1961":{"nm":"כרית ספיגת לחות לתא ירקות","de":"בפינה החשוכה ביותר של תא הירקות במקרר, אני סופגת בשקט את הלחות. הנס הקטן של עלה שקמל אתמול והתעורר קשיח שוב בבוקר. גם בלי שאיש יידע, הרעננות תמיד באחריותי."},"ICON-1962":{"nm":"מעצור לגלגול פחית משקה","de":"מודבק בשקט לשפת השולחן, הוא תופס את רגלה של פחית שעמדה להתגלגל. משקה שכמעט נשפך, שולחן שכמעט היה צריך לנגב. הביטחון בניהול הבית מתחיל במעצור קטן ובלתי נראה כזה."},"ICON-1963":{"nm":"חוגת תורנות מטלות","de":"היום, מי שוטף כלים, מי ממיין מיחזור. סיבוב אחד של החץ ומחלוקת נפתרת בעגילות. בבית שבו חמישה נדחקים יחד, תורנות היא סוג השלום הכי חמים."},"ICON-1964":{"nm":"רצועת סיליקון לזיהוי כוס אישית","de":"חמש כוסות דומות זו לזו, ובוקר של בלבול על של מי מה. עונדים רצועה צבעונית בגודל פרק היד, וההבטחה הקטנה “זו שלי” מתבהרת, ומעניקה לשולחן הבוקר סדר חמים ועדין."},"ICON-1965":{"nm":"טבעת מנות לקערת אוכל","de":"ביום עמוס, קווי הסימון בתוך הקערה הופכים לחבר נאמן. תא אחד לאורז, תא אחד לתוספות. לא מעט מדי ולא יותר מדי - קו עדין שמורה בשקט בדיוק כמה לאכול היום."},"ICON-1966":{"nm":"קופסת מלקחיים לחלוקת חטיפים","de":"כשדוחפים את השקית כולה, המקום שידיים נגעו בו נותר מביך. כשמחלקים במלקחיים אחד אחד, רק אז המנה של כולם יוצאת שווה. לשיתוף מתאימות ידיים מסודרות יותר מחפנים."},"ICON-1967":{"nm":"מחזיק תג תורנות לקומקום","de":"הרתחת המים תמיד נפלה לאותן ידיים. מאז שהתחלנו לתלות תגי שמות לסירוגין על המחזיק ליד הקומקום, כוס תה חמה הפכה לחיבה שמתבשלת בתורנות."},"ICON-1968":{"nm":"תג תזכורת “אל תשאיר” למרית","de":"“אל תשאיר שאריות” תלוי קטן בקצה המרית. זה אולי נשמע כמו נזיפה, אבל אין בו רוגז - כי כאן שוכנת רוחו של שולחן ישן, שבו כל ארוחה נחשבה יקרה."},"ICON-1969":{"nm":"וו תלייה לכיס סכו\"ם אישי","de":"הסכו\"ם כבר לא משתקשק חופשי במגירה. ברגע שכל ערכה נכנסת לכיס משלה ונתלית על הקיר, מקומם של חמשת בני המשפחה מתיישר זה לצד זה. סדר קטן תומך בשלוות היום-יום."},"ICON-1970":{"nm":"שבב שעם לזיהוי מקום ישיבה","de":"מניחים פיסות שעם על השולחן, ומתברר בבירור מי יושב איפה. המקום שתמיד תופסים, הפרופיל שתמיד רואים מולם. מקום קבוע הוא ההוכחה השקטה ביותר למילים “אנחנו חיים יחד”."},"ICON-1971":{"nm":"וו לגלילת סינר תורנות","de":"הסינר שסיים את שטיפת הכלים לא נזרק סתם לאנשהו. מגולגל ותלוי על הוו, הוא מוכן ורענן להישג היד למחר בבוקר. לב שחושב על הבא בתור שוכן בקשר הקטן הזה."},"ICON-1972":{"nm":"שקית מתקפלת לנעלי בית חד-פעמיות","de":"ביום שאורחים מגיעים, אני נפרשת שקית וכל. הנעליים החד-פעמיות המונחות בסדר בפנים מקבלות בעדינות רכה את הרגליים החדשות שהגיעו. הכנסת אורחים תמיד מתחילה בשקט מהכניסה."},"ICON-1973":{"nm":"כיס לזנבות נייר של מקלוני צמר גפן","de":"כשגומרים את מקלוני הצמר גפן ונשארים רק זנבות הנייר, אני אוספת את קצותיהם בקפידה. מקום אפילו למה שעומד להיזרק. אני יודעת שהסוד של שולחן מסודר הוא חסדים קטנים כאלה."},"ICON-1974":{"nm":"צרור סלילים לערכת תפירה","de":"כורכים יחד את החוטים הצבעוניים כדי שהסלילים לא ייפרמו ויסתבכו. כפתור שנפל, שרוול שהתרופף - צרור אחד כזה מתקן אותם במהרה. תפירת יד ששומרת בשקט על ערב חשוב."},"ICON-1975":{"nm":"חתיכת סבון עטופה בנפרד","de":"חתיכת סבון עטופה יפה בנפרד מונחת בכל חדר אורחים. גוף בגודל כף יד שוטף עם חופן קצף אחד את אבק היום. הניקיון תמיד מתחיל במקומות קטנים כאלה."},"ICON-1976":{"nm":"קפסולת קיפול לכובע מקלחת","de":"מקפלים את הקפלים והיא נכנסת בדיוק לכף היד; פותחים והיא עוטפת את השיער בחיבוק. כדי שתסרוקת מסודרת לא תתמוטט במקלחת אחת. השכבה הבודדת הזו שומרת על סדר הבוקר שלמחר."},"ICON-1977":{"nm":"נרתיק מגן למברשת שיניים","de":"זיפי המברשת עדינים יותר משנדמה. נרתיק אחד שמכסה את קצותיהם, ואפילו אבק התיק לא מגיע אליהם. לשמור על המקומות הבלתי נראים - זו העבודה האמיתית של ההיגיינה, שנלמדת בכל נסיעה."},"ICON-1978":{"nm":"מלקחיים למשיכת פדים בודדים","de":"פדי כותנה יוצאים נקיים רק כשמושכים אחד בכל פעם. אם שופכים את כולם בבת אחת, יותר מהם מתבזבזים. “אחד בכל פעם, בקפידה” - זהו הכלל השקט שעל שולחן האיפור."},"ICON-1979":{"nm":"כף נעליים מתקפלת מיני","de":"מקופלת - בתוך הכיס; פתוחה - בעקב. אני גאה במשימה גדולה יחסית שאני מבצעת עם גוף קטן. גם בבוקר שקמים בו מאוחר, אני תמיד זו שמאפשרת לנעול נעליים בלי לקלקל אותן."},"ICON-1980":{"nm":"סליל לחוט דנטלי בודד","de":"כורכים חוט דנטלי אחד בקפידה, וכשמגיע הצורך חותכים בדיוק כמה שצריך. סליל לא גדול מציפורן, אך אף פעם לא נעדר מהמלאכה של שמירה על חיוך בהיר. גם לחיוך יש הכנה בלתי נראית."},"ICON-1981":{"nm":"ידית מכסה לקומקום חשמלי","de":"כדי שאדי המים הרותחים לא יכוו את היד, אני מתחברת למכסה. רוחב כף יד בין החום לכף היד. המרחק הקטן הזה מחמם בבטחה את הבוקר העמוס של מישהו."},"ICON-1982":{"nm":"תחתית סיליקון למגהץ","de":"הרגע המסוכן ביותר הוא כשמניחים לרגע את המגהץ תוך כדי גיהוץ. מציבים אותו על משטח הסיליקון, ולא השולחן ולא הבגדים נכווים. החלקת קמטים מסתיימת רק על התחתית הזו."},"ICON-1983":{"nm":"וו מגן לקולב בגדים","de":"כדי שבגד תלוי לא ייפול בקלות, הוו סוגר את פיו בחוזקה. שומר קטן השומר על הפריט האהוב בארון. להגן - זהו דבר שקט כל כך."},"ICON-1984":{"nm":"מסננת אבנית לקומקום","de":"תפקידי הוא לסנן בשקט את האבנית הצפה במים הרותחים. רק אחרי סינון אפילו של המשקעים הבלתי נראים, כוס התה מתבהרת. מסירות תמיד נובעת מהמקומות שאיש לא רואה."},"ICON-1985":{"nm":"רצועת נגד החלקה לקולב","de":"קולב שעטוף ברצועת נגד החלקה לא מפיל אפילו משי קליל. מי שראה פעם בגד שנפל ארצה והתקמט, יודע להעריך את החוט הדק הזה."},"ICON-1986":{"nm":"קליפס לסידור כבל מגהץ","de":"כבל משוחרר נתפס ברגליים ומועד מישהו. מגע יד אחד שכורך אותו במסודר בעזרת קליפס. מניעת תאונות תמיד מתחילה מסידור קטן וטריוויאלי כזה."},"ICON-1987":{"nm":"חריץ בסיס לקומקום חשמלי","de":"אני מיישבת את הקומקום בדיוק בחריץ שלי כדי שלא יתנדנד. להיות במקום הנכון פירושו להיות רגוע. יש סיבה שמים חמים מתחממים כל בוקר באותו מקום בדיוק."},"ICON-1988":{"nm":"רגלי קליפס לקולב מכנסיים","de":"כשרגלי הקליפס אוחזות היטב בשולי המכנסיים, אף קמט לא נוצר. פריט מגוהץ היטב זוכה ליחס מכובד מהרגע שהוא נתלה. גזרה נקייה מושלמת בתוך הארון."},"ICON-1989":{"nm":"וו תלייה למייבש שיער","de":"משאירים את המייבש בכל מקום, והכבל מסתבך עד מהרה. תולים אותו על הוו, והכיור מתרחב, והבוקר של מחר נעשה קליל יותר. מקום מסודר משחרר מעט את היום העמוס."},"ICON-1990":{"nm":"תחתית לכוסות מיני-בר","de":"מניחים אותה בשקט מתחת לכוס, והטיפות לא מתפשטות על השולחן. תשומת הלב שבתחתית אחת לא משאירה עיגול. סדר הוא החמלה שלא משאירה עקבות."},"ICON-1991":{"nm":"שלט “נא לא להפריע” לדלת","de":"שלט תלוי על ידית הדלת לוחש בשקט “נחים כרגע”. שמירה על נשימה אחת של תנומה בסוף יום ארוך. גם להפסקה צריך מישהו שישמור עליה בקפידה."},"ICON-1992":{"nm":"כיסוי לכפתור קריאה לשירות חדרים","de":"הודות לכיסוי העוטף את הכפתור, גם שרוול חולף לא ילחץ עליו בטעות. כדי שיקראו בבירור רק כשבאמת צריך. כיסוי קטן אחד הופך חדר עמוס למסודר עוד יותר."},"ICON-1993":{"nm":"רגלי מלקחיים לקרח מיני-בר","de":"תופסים קרח בידיים חשופות, והוא קר ומחליק שוב ושוב. רגלי המלקחיים לוקחות על עצמן את המשימה הזו במיומנות. מאחורי תחילתה של כוס משקה קרירה מסתתרת יד עוזרת בלתי נראית."},"ICON-1994":{"nm":"חריץ להחדרת כרטיס מפתח לחדר","de":"מחדירים את הכרטיס לחריץ, ואור החדר נדלק בבת אחת. אני רק סדק קטן, אבל אני התנועה הראשונה שפותחת מרחב להניח בו את עייפות היום. האור נדלק שוב במקום שאליו חוזרים."},"ICON-1995":{"nm":"טבעת אטימה לצוואר בקבוק","de":"אם טבעת האטימה על צוואר הבקבוק שלמה, זה אומר שאיש עוד לא נגע בו. הבטחה קטנה שמוכיחה שהוא בדיוק כפי שהיה מלכתחילה. אמון מתחיל מחותם שלא נשבר."},"ICON-1996":{"nm":"מעמד לעמידת חוברת מידע","de":"מציבים את חוברת המידע בשיפוע, ומבט חולף נעצר בה מעצמו. עמידתו הצנועה של מידע שממתין להיפתח. רק בכך שמשאירים אותו גלוי, דרכו של מישהו נעשית קלה יותר."},"ICON-1997":{"nm":"פותחן בקבוקים שטוח למיני-בר","de":"בפינה של גוף שטוח מסתתר בצניעות חריץ לפתיחת פקקי בקבוקים. קטן ככל שיהיה, הוא מבצע את תפקידו בדייקנות. הלגימה הראשונה הקרירה של בקבוק תמיד נפתחת עם השבב הקטן הזה."},"ICON-1998":{"nm":"כיסוי ידית לעמעם תאורה","de":"מסובבים בעדינות את הידית העטופה בכיסוי, ובהירות החדר משתנה לאט. בוהק, ואז רך. בחירת האור לפני השינה היא טקס שמסיים את היום בעדינות."},"ICON-1999":{"nm":"טריז עצירה לגלגל מזוודה","de":"תוחבים אותו קלות מתחת לגלגל, והמזוודה לא מתגלגלת מעצמה. גם על רציף תחנה משופע, המטען שומר על מקומו. הביטחון שבדרך יוצאת מתחזק מהטריז הקטן הזה."},"ICON-2000":{"nm":"לוח קיפול לאריזת מזוודה","de":"פורשים חולצה או מכנסיים עליו, והם מתקפלים חדים ומסודרים. כדי שתוך התיק לא יתמוטט, כדי שאפשר יהיה לצאת בעיר היעד בלי קמטים. מטען ארוז היטב עוזר לטיול עוד לפני היציאה."},"ICON-2001":{"nm":"ידית מנעול כספת החדר","de":"כשמסובבים את הידית, בריח קטן מחליק פנימה. להפקיד חפצי ערך זה להבטיח שלילה אחד אפשר להניח את הלב במנוחה מלאה. המנעול נמצא שם לא כדאגה, אלא כשם אחר לשלוות נפש."},"ICON-2002":{"nm":"כיסוי לידית מזוודה","de":"בכל כתם שחוק מגע יד חרוטה יציאה של מישהו. אוחזים בכיסוי הזה, שחוק כמו הדרך שנגרר בה, ולאט לאט מבינים שעזיבה היא, בסופו של דבר, מילה שנושאת בתוכה חזרה."},"ICON-2003":{"nm":"קליפס תלייה לקלמית נסיעות","de":"תולים את הקלמית על קצה הכיור והחדר הצפוף מתרחב בטפח. שהסדר בתוך התיק מתחיל מקליפס קטן אחד - יד שנסעה רחוק כבר יודעת את זה."},"ICON-2004":{"nm":"קליפס מטען מרובה שקעים","de":"אוספים כמה כבלים לתוך שקע אחד. בלילה שמחכים שהטעינה תיגמר, יש כאן יד קטנה שמחזיקה באדיבות את החוטים המפוזרים במקום אחד."},"ICON-2005":{"nm":"רצועת תג שם למזוודה","de":"בין תיקים שחורים זהים, פס רצועה אחד מאפשר לזהות את שלך. לתלות שם הוא סימן עדין לכך שלמטען הזה יש דרך חזרה אל מישהו."},"ICON-2006":{"nm":"לוח תלייה לכבל טעינה על קיר החדר","de":"לוחית קטנה על הקיר ליד ראש המיטה תומכת בכבל הטעינה בסדר מופתי. בלילה הראשון בחדר זר, כשאור מוכר אחד נדלק, גם המקום הזה הופך לרגע לבית."},"ICON-2007":{"nm":"רגליים מתקפלות למעמד מזוודות","de":"פותחים את הרגליים המקופלות והתיק מתרומם טפח מעל אבק הרצפה. מזוודה שהונחה עדיין לא פתוחה, מחזיקה בשקט מסע שלא הסתיים, וממתינה לבוקר הבא."},"ICON-2008":{"nm":"חריץ הכנסת כרטיס מפתח","de":"צריך להכניס את הכרטיס כדי שהאור בחדר יידלק. אור שדולק רק בזמן השהייה - יומו של הנוסע מתחמם בדיוק בבהירות שהחריץ הקטן הזה מתיר."},"ICON-2009":{"nm":"לולאת רצועה לכרטיס מפתח","de":"תולים כרטיס אחד על הצוואר ושתי הידיים מתפנות. לקשור את דאגת האובדן לרצועה אחת היא פיקחות קטנה שעברה בירושה זמן רב אצל נוסעים עמוסי מטען."},"ICON-2010":{"nm":"כפתור פעמון קריאה לדלפק הקבלה","de":"לוחצים והיכן שהוא בדלפק הקבלה מצלצל צליל צלול. כדי שלבקש עזרה לא יהיה מביך, הפעמון תמיד מונח באדיבות במרחק תנועת יד אחת."},"ICON-2011":{"nm":"קליפס מספר תור לצ'ק-אין","de":"לוקחים את פתק המספר שניתן בקצה התור ומהדקים אותו. שגם להמתנה יש תור משלה - הסדר צומח מהבטחה קטנה לשמור בעדינות על זמנו של הזולת."},"ICON-2012":{"nm":"פונפון לתליית מפתח חדר","de":"פונפון התלוי מקצה המפתח מתנדנד בעדינות בכל צעד. הלב שמוסיף בחשאי נגיעת חן לתועלת, מגלים רק מי שמכיר את שמחת קצות האצבעות."},"ICON-2013":{"nm":"כיסוי לפעמון דלת הקבלה","de":"כשמניחים כיסוי מעל הפעמון, שקט הצהריים לא נשבר. מחשבה קטנה כדי לשמור על שנתו העמוקה של מישהו - גם שקט הוא משהו שמישהו יצר בקפידה."},"ICON-2014":{"nm":"פתק מספר חדר לתליה על הדלת","de":"פתק התלוי על ידית הדלת נושא בבירור את מספר החדר. כמה ספרות קובעות את המקום שאליו אשוב הלילה, ובמסדרון הזר הן הופכות למגדלור קטן."},"ICON-2015":{"nm":"פס מגנטי לכרטיס מפתח","de":"מצמידים את הפס השחור לחריץ הדלת והמנעול נפתח בשקט. תקופה שבה אות בלתי נראה פותח דלת - מה שפעם הרגיש כקסם השתקע כעת לשגרת יומיום בכף היד."},"ICON-2016":{"nm":"כרית חותמת לצ'ק-אין","de":"בכל הטבעת חותמת, הכרית סופגת את הדיו באחידות. כדי שקו האישור הבודד יישאר ברור, יש כאן יד שתומכת בדממה ממקום בלתי נראה."},"ICON-2017":{"nm":"מוט תלייה לעגלת מזוודות","de":"מוט אחד על עגלת המזוודות מחזיק את תיק הבגדים בלי קמט. גם למה שנושא במקומנו יום כבד, מתחשק לפעמים לומר מילת תודה."},"ICON-2018":{"nm":"תג לידית מזוודה גדולה","de":"תולים תג קטן על ידית המזוודה. כל עוד משבצת השם עדיין ריקה, נותר ריגוש - היעד הבא של התיק הזה עדיין לא נקבע."},"ICON-2019":{"nm":"טריז נעילה לגלגל עגלת מזוודות","de":"תוקעים טריז מתחת לגלגל כדי שהעגלה לא תתגלגל במורד. לשמור על עמידה במקום היא לפעמים הפנים הכי אמינות של הביטחון."},"ICON-2020":{"nm":"אבזם רצועת מטען","de":"מהדקים את הרצועה חזק כדי שהתיק התפוח מחפצי הנסיעה לא יתפקע. גם כשהדרך מסתיימת, נפח הזיכרונות לא מצטמצם, אז האבזם מחזיק במשקל הזה עד הסוף."},"ICON-2021":{"nm":"כיסוי לוו עגלת מזוודות","de":"הכיסוי שעל וו העגלה לא משאיר סימן אחד על הבגדים. לב שצופה מראש אפילו שריטות בלתי נראות - אירוח טוב שלם דווקא במקומות קטנים כאלה."},"ICON-2022":{"nm":"כיס לתג שם על מזוודה","de":"כיס קטן בצד התיק חובק תג שם. לרשום למי הוא שייך, זה כמו לחרוט מראש את הזכות להיפגש שוב גם אם הוא ילך לאיבוד."},"ICON-2023":{"nm":"קליפס לכפפות נשיאת מטען","de":"כשנושאים מטען כבד, הקליפס אוחז בחוזקה בכפפות כדי שלא יחליקו. לשמור על הידיים ולעשות את העבודה היטב נובעים, בסופו של דבר, מאותו לב עצמו."},"ICON-2024":{"nm":"רשת כיסוי למטען","de":"פורשים את הרשת והחפצים הקטנים לא מתפזרים לכל עבר. כל עין ברשת הצפופה אוחזת בדברים הקטנים ולא נותנת להם ללכת לאיבוד בתוך המהומה של הנסיעה."},"ICON-2025":{"nm":"מחזיק פתקים לעגלת מזוודות","de":"פתק תקוע בידית העגלה נושא את מספר החדר. ההרגל לרשום לאן ללכת - ככל שהידיים עסוקות יותר, כך הן נשענות בשקט על שורה אחת של כתב."},"ICON-2026":{"nm":"כיפת כיסוי למגש הגשה","de":"מרימים את הכיפה הכסופה והאדים עולים בבת אחת. הלב שמכסה את האוכל כדי שלא יתקרר הוא מסירות בעצמה, הרצון להעביר את החום בדיוק כמו שהוא."},"ICON-2027":{"nm":"שלט \"נא לא להפריע\" לידית דלת","de":"תולים שלט זה על ידית הדלת וגם צעדים במסדרון נעשים זהירים. המילים \"נא לא להעיר\" - גם מנוחה נעשית שלמה רק כשמישהו שומר עליה."},"ICON-2028":{"nm":"טבעת למפית נייר בשירות חדרים","de":"משחילים מפית נייר לתוך טבעת עגולה ומעצבים צורה מסודרת. ההדר של ארוחה מתחיל בחישוק הקטן הזה - הקפדה מתגלה הכי ברור בדברים הפעוטים."},"ICON-2029":{"nm":"מצע נגד החלקה למגש","de":"מניחים מצע על המגש והכלים לא מחליקים. לשמור על מקומם גם בתנודה - גם ביציבות השקטה טמון עיצוב קפדני של מישהו."},"ICON-2030":{"nm":"תג הזמנת ארוחת בוקר לדלת","de":"תולים את תג הזמנת ארוחת הבוקר על ידית הדלת ומחר בבוקר מובטח מראש. לרשום את הארוחה הראשונה כבר הלילה זו עוד פנים של ציפייה מלאת חיבה."},"ICON-2031":{"nm":"מעמד רגליים למגש","de":"פותחים את רגלי המגש והוא הופך לשולחן של ממש גם על המיטה. ארוחת בוקר המוגשת במקום שבו שוכבים - מעמד קטן הופך חדר רגיל לנוף מפואר."},"ICON-2032":{"nm":"כיסוי חימום לקומקום","de":"עוטפים את הקומקום בכיסוי חם והחום של המים נשאר זמן רב. כמו לילות עתיקים שהתכנסו סביב האח, הרצון לשמר חום אינו מכיר תקופה."},"ICON-2033":{"nm":"תג בקשת ניקיון לדלת","de":"תולים תג בקשת ניקיון על ידית הדלת ומשאירים אות שקט. בקשה שמועברת בלי לפתוח שפתיים - מאחורי חדר מסודר טמונה הבטחה של יד בלתי נראית."},"ICON-2034":{"nm":"מחזיק בקבוקוני תבלינים למגש","de":"המחזיק אוחז חזק כדי שבקבוקוני התבלינים לא ייפלו. לשמור על איזון הטעם גם על מגש מתנדנד הוא חלקו השקט של הידוק קטן אחד זה."},"ICON-2035":{"nm":"מעמד פתקי הזמנות","de":"מציבים את פתקי ההזמנה בעמידה והסדר נקרא במבט אחד. כדי שגם ידיים עסוקות לא יתבלבלו, זהו כלי סדר קטן שמחזיק דף אחד זקוף וברור."},"ICON-2036":{"nm":"לוח מפה עם סיכות לאתרי תיירות","de":"תוקעים סיכות במפה ומסמנים אחד אחד את המקומות שרוצים לבקר בהם. כל סיכה היא ריגוש של מקום שעוד לא ביקרו בו - הנסיעה מתחילה כבר ברגע שפורשים את המפה."},"ICON-2037":{"nm":"קליפס דגל לקריאת מונית","de":"כשקוראים למונית, קליפס מציב את הדגלון הקטן זקוף. אות שהדגל צועק במקום יד מורמת - גם ברחוב, קריאה חייבת להיות ברורה כדי שתגיע."},"ICON-2038":{"nm":"ידית פעמון לדלפק הקונסיירז'","de":"לוחצים על הידית וצליל צלול מגיע אל דלפק הקונסיירז'. אות של הכנסת אורחים שאומר שאפשר לשאול כל דבר - בעיר זרה, הקריאה האחת הזו הכי מרגיעה."},"ICON-2039":{"nm":"לוח קליפס למספר הזמנה","de":"מהדקים את פתק מספר ההזמנה ללוח כדי שייראה בבירור. כדי שהמקום המובטח לא יתבלבל, זו הקפדה קטנה שמחזיקה שורת ספרות אחת מסודרת."},"ICON-2040":{"nm":"מסגרת תצוגה לעלוני סיורים","de":"מציבים עלוני סיורים והיד של הנוסע נעצרת מעצמה. בכל דף שנפתח אחד אחד, מקופל בשקט הנוף של דרך שעוד לא נסעו בה."},"ICON-2041":{"nm":"כרית חותמת למפת דרכים","de":"לצעדים הראשונים אל הכניסה, היא מחזיקה יציב את קופסת החותמת שעל המפה. כשהדיו לא נמרח, גם הדרך לא מתבלבלת. מקום שתומך בדממה כדי שמדריך קטן יעמוד זקוף."},"ICON-2042":{"nm":"תג אחסון למטריות","de":"אחר צהריים שבו טיפות גשם נטפו מהמרזב, תולים מספר אחד על כל מטרייה. כשמי שחזר אחרי הגשם בא לקחת את שלו, התג קורא בבירור את הזיכרון הרטוב."},"ICON-2043":{"nm":"מחזיק פעמון קריאה לדלפק המידע","de":"דין-דין, מצלצל פעם אחת ומישהו רץ אליך בפנים קורנות מהצד השני. הפעמון הקטן התלוי בפינת הדלפק הוא המתורגמן הכי חם, מעביר גם מילים שלא הצלחת להוציא."},"ICON-2044":{"nm":"פומית מתקן שמפו","de":"פותחים כף יד ולוחצים בעדינות, וקצף פורח החוצה בפתאומיות. שחרור אחד שהריח מתפשט בו בכל חדר האמבטיה. הצליל שמעיר בוקר מנומנם הכי בעדינות מתחיל בדיוק כאן."},"ICON-2045":{"nm":"מגש ניקוז למעמד סבון","de":"מגש שמנקז בשקט את המים שנאספים מתחת לסבון. כדי שלא ירכך, כדי שלא יימעך. מחשבה קטנה ועדינה לשמור את מה שנשחק בכל יום קרוב עוד קצת יותר זמן."},"ICON-2046":{"nm":"כפית מלחי אמבט","de":"לוקחים כף אבקה וממיסים במים חמים, והצבע והריח מתפשטים לאט. בזמן שמערבבים בשורש כף היד, האמבטיה הופכת לאגם קטן, ועייפות היום שוקעת בשקט בתוכה."},"ICON-2047":{"nm":"שקית רשת להקצפה","de":"לוכדים חתיכת סבון ברשת ומשפשפים, וקצף רך ממלא את כפות הידיים. אלכימאי שקט בפינת חדר האמבטיה, שהופך את הגס לעדין."},"ICON-2048":{"nm":"כיפה חיטוי למברשת שיניים","de":"הרצון שמה שנוגע בפה יהיה תמיד נקי. כיפה קטנה אחת שעוטפת בעדינות את קצות הזיפים דואגת גם למקומות הבלתי נראים. ניקיון נבנה מצבירה של דברים קטנים כאלה."},"ICON-2049":{"nm":"מכסה לקופסת מקלוני אוזניים","de":"קופסה שבה מקלונים לבנים שוכבים מסודרים, ומכסה שעוגל מעליה. פותחים בטק, סוגרים בטוק. נקודה עדינה שמסיימת את הסדר של חדר האמבטיה בקול קטן."},"ICON-2050":{"nm":"בקבוקון טיפות שמן אמבט","de":"מטים אותו קלות וטיפה אחר טיפה, שמן ריחני נופל. ברק וניחוח עדין מתפשטים באמבטיה. צנוע מכדי להיות מותרות, עדין מכדי להיות יומיום - טיפה אחת בלבד."},"ICON-2051":{"nm":"מחיצה למגש מוצרי אירוח","de":"על מגש שמחולק לתאים, בקבוקונים קטנים מוצאים כל אחד את מקומו. דברים שנראים עמוסים כשמפוזרים, ומסודרים כשמאוחדים. מחיצה אחת שומרת על הסדר של בוקר עמוס."},"ICON-2052":{"nm":"מעמד לשעון חול בסאונה","de":"זו הבטחה עדינה לחמם את הגב לפחות בזמן שכל החול זורם למטה. כששעון החול הנשען באלכסון על המעמד סופר את הזמן טיפה טיפה, בתוך האדים הסמיכים אדם נח לרגע, בלי להיות דבר."},"ICON-2053":{"nm":"מגבת מגולגלת בצורת אוזני כבשה","de":"מגלגלים את קצוות המגבת ומזקיפים אותם כמו שתי אוזני כבשה, והפנים במראה נרפות בעדינות. בין האדים החמים, טקס קטן של הסאונה שבו כל אחד חוזר לרגע לילדות."},"ICON-2054":{"nm":"דלי מים לסאונה","de":"ממלאים את הדלי במים ושופכים על האבנים החמות - סיו! - והאדים מזנקים עד לתקרה. באותו רגע כל הגוף שוקע בערפל חם, והעייפות הישנה משתחררת לאט בטיפות זיעה."},"ICON-2055":{"nm":"מקל מדידת טמפרטורה לאמבט רגליים","de":"טובלים את המקל במים והסימונים מדברים בעדינות. לא חם מדי, לא התקרר - בדיוק הטמפרטורה הנכונה. לפני שטובלים את קצות האצבעות, זו האצבע ששואלת ראשונה לשלום המים."},"ICON-2056":{"nm":"מלקחיים לאבני חימום","de":"אי אפשר לתפוס אבן שזה עתה חוממה בידיים חשופות. כשהמלקחיים אוחזים בחוזקה ומרימים, החום עובר למרחק בטוח. שגם זהירות היא כישרון, אומר הסאונה בשקט."},"ICON-2057":{"nm":"מזרן ישיבה לסאונה","de":"פורשים אחד על הרצפה החמה והמקום שבו הגב נוגע נעשה רך יותר. מזרן שקולט בלי מילים יום שספוג בזיעה. מנוחה, בסופו של דבר, מגיעה מהמרחק הנכון מהרצפה."},"ICON-2058":{"nm":"שקית מלח לאמבט רגליים","de":"לוקחים חופן מלח גס וממיסים במים חמים, והתשישות נמסה בעדינות מקצות האצבעות. כשהאדים המלוחים עוטפים את השוקיים, יום שלם של הליכה עוצר לבסוף."},"ICON-2059":{"nm":"צלחת אבן לבישום סאונה","de":"מטפטפים כמה טיפות בושם על האבן החמה והריח המחומם מתפשט לאט בסאונה. עוצמים עיניים ותוהים אם זה יער או שדה פרחים. הטיול הקצר ביותר, שנעשה דרך האף."},"ICON-2060":{"nm":"כיסוי חימום לכרית חמה","de":"בד שעוטף את הכרית המחוממת בחוזקה ושומר על החום זמן רב. בדיוק כמו לב שמחבק חזק כדי שלא יתקרר, החום המונח על הבטן שומר עלייך כל הלילה."},"ICON-2061":{"nm":"מקלות מפזר ארומה","de":"מקלות דקים שואבים את הריח ומשחררים אותו לאט בחדר. ניחוח עדין שחודר עם כל נשימה. הדרך שבה מרחב מגורים הולך ומדמה בהדרגה לריחו של אותו אדם."},"ICON-2062":{"nm":"ידית כוונון זווית למיטת שיזוף","de":"מסובבים את הידית לאט והמשענת נוטה בחלקות. קצת לכיוון השמש, קצת לכיוון הצל. לגשש ולמצוא את הזווית הנוחה ביותר היא חשבון פרטי לגמרי משלך."},"ICON-2063":{"nm":"פס נגד החלקה לשפת הבריכה","de":"פס נגד החלקה שמקיף את שפת המים מסביב מסביב. כדי שרגליים קטנות שרצות בשמחה מתוך התזה יעצרו בבטחה, זהו קו סיום בטיחות שמונח בשקט במקום בלתי נראה."},"ICON-2064":{"nm":"לולאה לפקק אוויר של גלגל שחייה","de":"לולאה קטנה נקשרת בקפידה לפקק שכולא את האוויר. כדי שהפקק, שנשלף מהגלגל, לא יישטף במים. חוכמה שמונעת מראש אובדן פעוט של אמצע קיץ."},"ICON-2065":{"nm":"כיפה לקצה מדרגת כניסה לבריכה","de":"כיפה שעוטפת בעדינות את קצה המדרגה היורדת אל המים. כדי שכפות רגליים חשופות לא ייחרטו, היא קולטת ברכות את הצעד הראשון של הכניסה. כי כל התחלה צריכה תמיד להיות זהירה."},"ICON-2066":{"nm":"לולאת רצועה לכרית מיטת שיזוף","de":"לולאה שקושרים אליה רצועה כדי שהכרית לא תחליק. הבטחה קטנה לשמור על מקומה גם כשהרוח נושבת. קשר אחד מרתק את עצלות הצהריים למקומה."},"ICON-2067":{"nm":"לוח מחזיק כוסות לבריכת וילה","de":"לוח שתוקעים בו כוס משקה בקצה הבריכה. מקום אחד שלא מתערער גם מהתזה נלהבת. להניח קרירות בהישג יד מאריך אחר צהריים של קיץ."},"ICON-2068":{"nm":"קליפס לתליית בגד ים רטוב","de":"תולים בגד ים מטפטף ומפקידים אותו בשקט לרוח. בזמן שהוא מתייבש בשמש, הקליפס עומד ואוחז בדממה. המתנה שקטה ומלאת חיבה לשחייה הבאה."},"ICON-2069":{"nm":"משקולת בסיס למוט שמשייה","de":"משקולת כבדה שמונחת בבסיס המוט כדי שהשמשייה לא תתנדנד ברוח. הצל נשאר במקום אחד זמן רב הודות למשקל הזה בלבד. אמינות מסתתרת לעיתים קרובות במקום הכי נמוך."},"ICON-2070":{"nm":"שבב צף למדידת חום מי הבריכה","de":"שבב קטן שצף על המים ומודיע בשקט על הטמפרטורה. מסמיק אם קר מדי, נעשה רך אם בדיוק נכון. קוסמת חמודה שקוראת את מצב רוחם של המים בצבע אחד."},"ICON-2071":{"nm":"פונפון משיכה לרוכסן אוהל","de":"מושכים בקלות את הפונפון הקטן שתלוי בקצה הרוכסן ודלת האוהל נפתחת בחלקות. ידית שנתפסת מיד גם כשהאצבעות מגששות. היא מנחה באדיבות את הכניסות והיציאות של הלילה העמוק."},"ICON-2072":{"nm":"סיכת פרפר להידוק חבל אוהל","de":"סיכה שנוגסת בחבל בצורת פרפר ומחזיקה אותו חזק. הבד שהתנפנף ברוח נרגע לבסוף. לילה של קמפינג נשמר בשקט על ידי קשרים קטנים ומיומנים כאלה."},"ICON-2073":{"nm":"שסתום אוויר למזרן גלמפינג","de":"מקרבים את הפה ונושפים, נושפים, והמזרן מתנפח לאט לאט. ממלאים אותו וסוגרים את השסתום היטב, הרצפה נעשית תופחת, ומקום להשכיב עליו את הגוף תחת אור הכוכבים מושלם סוף סוף."},"ICON-2074":{"nm":"וו תלייה לתקרת אוהל","de":"וו שתלוי מתקרת האוהל לתליית פנס או מטפחת. חוכמת משק הבית שמנצלת בחסכנות אפילו את החלל הקטן שמעל הראש. זה כמו לתלות כוכב אחד על התקרה במקום על השמיים."},"ICON-2075":{"nm":"רצועת הידוק לגלגול שק שינה","de":"רצועה שכורכים ומהדקים כדי ששק השינה המגולגל לא ייפתח. מיטה שמצטמקת שוב עד הבוקר. להתכונן לצאת פירושו לקפל בקפידה את חום הלילה שעבר."},"ICON-2076":{"nm":"לוח מנעלים לכניסת אוהל","de":"לוח שמונח בכניסת האוהל להחזיק נעליים מסודרות. עפר בחוץ, פנים נקי. עם סף אחד, הוא מחלק בעדינות בין פנים לחוץ - נימוס קטן של קמפינג."},"ICON-2077":{"nm":"וו תלייה לפנס גלמפינג","de":"וו כפוף לתליית הפנס. תולים כאן ואור מתפשט בעיגול לתוך היריעה. המקום שבו תולים אור אחד בחושך הופך לסלון שלנו הלילה."},"ICON-2078":{"nm":"קליפס לגלגול חלון אוורור אוהל","de":"קליפס שמגלגל ומחזיק את חלון האוורור. פותחים סדק לרוח והאוויר בתוך האוהל נעשה הרבה יותר רענן. פער קטן אחד יוצר בשקט מרווח נשימה לכל הלילה."},"ICON-2079":{"nm":"מזרן קרקע לרצפת אוהל","de":"מזרן שפורשים על רצפת האוהל כדי לחסום עפר ולחות. שכבה אחת שפורשת משכב יבש גם מעל הדשא. כדי שתישאר בטבע בלי להירטב ממנו, היא עוזרת בשקט לצידך."},"ICON-2080":{"nm":"טבעת נעילה למוט משקולות","de":"טבעת שמהודקת בשני קצוות המוט כדי שהדיסקיות לא יחליקו. מנעול קטן שסומך לגמרי על משקלו של המרים. רק כשהבטיחות תומכת בחוזקה, הגבול מתחדש סוף סוף בעוד דרגה אחת."},"ICON-2081":{"nm":"כיפה לידית קטלבל","de":"בסט האחרון שבו הברזל כרסם בכף היד, כיפה קטנה אחת זו מעלימה את הכאב. שלהחזיק עד הסוף קשה יותר מלהרים את המשקל - היד יודעת זאת ראשונה ברגע הסיום."},"ICON-2082":{"nm":"טריז הכנסה לדיסקית משקולות","de":"אם הדיסקית מתנדנדת אפילו במעט, היציבה קורסת עוד לפני שמרימים. טריז שנתקע דק בפער מחזיק את המרכז בלי קול. יציבות תמיד מתחילה בשקט במקום הבלתי נראה."},"ICON-2083":{"nm":"קליפס נעילה למוט משקולות","de":"קצות האצבעות שמהדקות את הנעילה חייבות להיות בלי היסוס. קליק קטן אחד של נעילה נושא על גבו את כל התנועה הבאה. הגוף לומד ראשון איך להשליך אמון על קליפס אחד."},"ICON-2084":{"nm":"שבב צבע לזיהוי משקל דיסקית","de":"שבב שצבעו שונה בכל משקל - היד מזהה אותו ראשונה גם אם לא יודעים לקרוא את המספר. אדום זה כבד, כחול זה קל; לזכור משקל בעזרת צבע. הגוף, למרבה ההפתעה, מודד כוח דרך העיניים."},"ICON-2085":{"nm":"כרית רצפה לקטלבל","de":"הודות לכרית שמרחיבה את המשטח הנוגע ברצפה, קרשי הרצפה לא נחבטים. סימני האימון צריכים להישאר רק בזיעה ובשרירים. לב קטן שלא רוצה להשאיר פצע אפילו מתחת לרגליים מונח כאן."},"ICON-2086":{"nm":"סימון מרכז למוט משקולות","de":"הסימון החרוט באמצע המוט הוא נקודת הייחוס לאיזון בין ימין לשמאל. יד שאוחזת בדיוק במרכז מצמצמת את התנודה בחצי. ברגע שיודעים איפה המרכז, אפשר לבסוף להרים בבטחה."},"ICON-2087":{"nm":"מתלה אחסון לדיסקיות משקולות","de":"דיסקית שסיימו להשתמש בה חוזרת למקומה. הנוף של דיסקיות התלויות מסודרות לפי משקל על המתלה הוא התחשבות שקטה באדם הבא. מרחב מסודר הוא אמצעי הבטיחות הכי אמין, מאמין מישהו."},"ICON-2088":{"nm":"סף עצירה לדיסקית מתגלגלת","de":"התאונה שבה דיסקית שמונחת על הרצפה מתגלגלת ומכה בגב כף הרגל מגיעה תמיד ברגע אחד של חוסר תשומת לב. סף העצירה חוסם בשקט את השבריר הזה. צרה גדולה לא מגיעה ממקום גדול - היא מתגלגלת מסדק קטן."},"ICON-2089":{"nm":"כרית משענת לספסל","de":"אם הכרית שתומכת בגב קשה מדי, אפילו הנשימה נעשית שטחית. הגבול הזה, קשיח כראוי ורך כראוי, הוא נקודת איזון שרק מי שישב זמן רב מגלה בקצות האצבעות."},"ICON-2090":{"nm":"פין כוונון גובה למתקן","de":"עם סיכה אחת שקובעת את הגובה, המוט מתאים בדיוק לכתפיים של כל אחד. אנשים בגבהים שונים חולקים בידידות את אותו הציוד - חור כוונון קטן אחד יוצר את השוויון העדין הזה."},"ICON-2091":{"nm":"כיסוי לגלגלת מכשיר כושר","de":"בתוך הכיסוי שעוטף את הגלגלת, הכבל מסתובב שוב ושוב בלי קול. חלק שמסתיר את החיכוך בפנים ומעניק ליד רק חלקות. מכשיר טוב לעולם לא חושף בסוף את המאמץ ששילם."},"ICON-2092":{"nm":"כרעיים נגד החלקה לרגלי ספסל","de":"כרעיים נגד החלקה שמותקנות בקצות ארבע הרגליים מחזיקות את הספסל חזק לרצפה. רק כשהוא לא מתנדנד אפשר להשקיע בו את מלוא הכוח בלב שקט. יציבות, בסופו של דבר, מתחילה מחיכוך קטן בקצה הרגל."},"ICON-2093":{"nm":"וו הנחה למוט משקולות במתקן","de":"הוו שעליו מניחים את המוט חייב להיות תמיד בגובה בהישג יד. המקום שבו זרוע עייפה מניחה לבסוף בעדינות את המוט - המיקום הזה, ברוחב טפח, סוגר בבטחה את האימון של היום."},"ICON-2094":{"nm":"ידית פין משקל למכשיר כושר","de":"הידית שמכניסים בה סיכה כדי לבחור משקל חייבת להיות חלקה כדי שלא תפגע בציפורניים. גם בתנועה הקטנה והחטופה של החלפת משקל, מרגישים שיש כאן גימור שהתחשב בשקט בקצות אצבעותיו של אדם."},"ICON-2095":{"nm":"מנוף נעילת זווית לספסל","de":"אם המנוף שנועל את זווית המשענת רופף, היציבה קורסת בשקט. הביטחון של אותו רגע שבו הוא ננעל בקליק. המפעיל, כשהוא פותח את הדלתות כל בוקר, בודק בשקט ראשית את הצליל הזה."},"ICON-2096":{"nm":"משענת מוט בטיחות למתקן","de":"ברגע הגרוע ביותר שבו המוט עוזב את הידיים, משענת מוט הבטיחות קולטת את המשקל במקומן. כשיש משענת בלתי נראית שתמיד ממתינה למטה, אדם יכול סוף סוף לדחוף עד הגבול שלו."},"ICON-2097":{"nm":"כיפה לקצה כבל מכשיר כושר","de":"הכיפה הקטנה שאוספת את קצה הכבל היא הקשר האחרון נגד היתרה. לקשור בקפידה כדי שהחוטים לא יתפזרו - האצילות של סיום תמיד שוכנת בנקודת הקצה הבלתי מורגשת ההיא."},"ICON-2098":{"nm":"שקית גיר להרמת משקולות","de":"חופן אבקה לבנה שמורחים על הידיים כדי למחוק החלקה. בלתי נראה כמו איפור מאחורי הקלעים, ובכל זאת יציבות כל תנועה היום מתחילה מהחופן הזה. הכנה תמיד מתחילה מקצות האצבעות."},"ICON-2099":{"nm":"קליפס תרגול כוח אחיזה","de":"קליפס קטן שחוזר בדממה על לחיצה ושחרור מחזק את כוח כף היד. כוח האחיזה גדל לאט יותר מהשרירים הגדולים, אז זה גם תרגול בהנחת חוסר הסבלנות בצד בשקט."},"ICON-2100":{"nm":"רצועת פישוק אצבעות","de":"רצועה שמכניסים בין האצבעות ומרחיבים לאט כלפי חוץ. יד שהשתמשה רק בשריר האחיזה משיבה לעצמה את כוח הפתיחה. גם להרפות בעדינות, בדיוק כמו לאחוז חזק, דורש תרגול, אומרת היד."},"ICON-2101":{"nm":"מכסה לצינורית גיר","de":"אם מכסה צינורית האבקה רופף ולו במעט, כל התיק מתמלא בלובן. מכסה קטן אחד שנסגר בדיוק כמו שצריך מונע מראש את התקלה הקטנה הזו. הצלחת האיטום תלויה תמיד בפקק."},"ICON-2102":{"nm":"רצועת תמיכה לברך","de":"רצועה הנכרכת סביב הברך לתמיכה צריכה לעצור בדיוק בלחץ הנכון. אם היא הדוקה מדי היא חוסמת את הדם, ואם רפויה מדי היא חסרת תועלת, ולכן יד מנוסה שוקלת בשקט את האיזון העדין הזה מתוך זיכרון."},"ICON-2103":{"nm":"רצועת התנגדות אלסטית","de":"החבל האלסטי שמתארך וקופץ בחזרה מעיר שרירים ישנים בלי אף משקולת. התנגדות לא חייבת להיות כבדה. גם מול משיכה עדינה, הגוף תמיד עונה בכנות."},"ICON-2104":{"nm":"משקולת חול לקרסול","de":"שקית חול הנרכסת לקרסול מכבידה על כל צעד וצעד בכובד נעים. הוספת מעט משקל הופכת אפילו הליכה רגילה לאימון של ממש. זו חוכמה קטנה שמכניסה בחשאי מאמץ אל תוך היום-יום."},"ICON-2105":{"nm":"מוט גלגול לשורש כף היד","de":"מוט שגוללים אליו לאט משקולת התלויה על חבל. שורש כף היד הוא המפרק הקטן והנשכח ביותר, וכלי פשוט זה מחזיר בשקט את הכוח הנשכח הזה לחיים."},"ICON-2106":{"nm":"כדור גומי לחיזוק אחיזה","de":"כדור גומי שלוחצים ומשחררים בכף היד ממשיך את האימון בשקט גם ליד השולחן. כוח שנצבר ברגעים פנויים נשאר יותר זמן מכוח שמושקע בבת אחת. התמדה תמיד צומחת מדברים קטנים כאלה."},"ICON-2107":{"nm":"אבזם רצועת דופק","de":"אם האבזם ברצועת החזה מוסט ולו במעט, המספרים קופצים. גם המעשה של הקשבה לפעימות הלב שלך עצמך מתחיל בהידוק יציב. כל מדידה, בסופו של דבר, מתחילה מהתאמה צמודה וחסרת רווחים."},"ICON-2108":{"nm":"קליפס לדופק","de":"קליפס שנושך בעדינות את קצה האצבע וסופר בשקט את הדופק. מצמידים אותו, מיישרים את הנשימה, וקצב הלב עולה בבירור על מסך זעיר. הגוף תמיד מדווח את מצבו האמיתי, ללא כחל וסרק."},"ICON-2109":{"nm":"נרתיק לרצועת דופק","de":"הנרתיק ששומר את מד הדופק לשורש כף היד קטן, אך מכיר את בני משפחתו. ככל שמכשיר זעיר יותר קל לאבד, כך הוא זקוק יותר לבית שאליו יוכל לשוב. גם שמירה טובה על חפצים היא סוג של עדינות."},"ICON-2110":{"nm":"דגלון קצב ריצה","de":"דגלון קטן שמסמן את יעדו של הרץ. נקודה אחת שנקבעה מראש - \"עד כאן ותו לא\" - נושאת רגליים כבדות עד הסוף. קו הסיום שבלב תמיד נועץ במו ידיו."},"ICON-2111":{"nm":"מכסה נר-לב פועם","de":"אור זעיר המהבהב בשקט בקצב פעימות הלב. כשמתבוננים ברוגע בקצב ההידלקות והכיבוי, הלב מתרגש מחדש למחשבה שלהיות בחיים יכול להיות דבר כה סדיר."},"ICON-2112":{"nm":"מחרוזת חרוזים לספירת סבבים","de":"סופרים חזרות בעזרת חרוזים שמזיזים אחד-אחד בקליק קל. לא צריך לזכור את המספר בראש - האצבעות זוכרות במקומך. כשמפקידים את הספירה בידיים, הלב יכול להישאר כולו בתנועה."},"ICON-2113":{"nm":"קליפס לריווי חמצן","de":"כרית קליפס שמניחים על קצה האצבע קוראת בשקט את כמות החמצן בדם. כשעומק הנשימה הבלתי נראה עולה כמספר, מבינים מחדש שלטפל בגוף פירושו, בסופו של דבר, פשוט להתבונן היטב."},"ICON-2114":{"nm":"רצועת אזורי דופק צבעונית","de":"רצועה שמחלקת את עוצמת האימון לפי צבעים מספרת לך במבט אחד עד כמה אתה מתאמץ כרגע. כחול הוא נינוחות, אדום הוא הגבול. זו הבטחה שקטה שבה הצבע עצמו הופך לשפה חמה ופשוטה."},"ICON-2115":{"nm":"קפסולת ג'לי למדידה","de":"קפסולת ג'לי זעירה המודדת את מצב הגוף מכילה בגרגר אחד מידע של יום שלם. יהיה אשר יהיה מה שטמון בקליפתה השקופה, גם הרצון להכיר את עצמך קצת יותר טמון שם יחד איתו."},"ICON-2116":{"nm":"וו לתלייית מגבת זיעה","de":"ההרגל הקטן לתלות תמיד על הווו שלה ולא לזרוק סתם איפשהו שומר על סדר בחדר שלם. כמו הווו הזה, שמייעד מקום קבוע למגבת לשוב אליו, הסדר תמיד נוצץ בפרטים הקטנים."},"ICON-2117":{"nm":"רצועת אבטחה למכסה בקבוק מים","de":"החוט הקצר המחובר למכסה הבקבוק מונע את התקלה של המכסה שמתגלגל ונעלם. החוכמה שבקשירת דבר שקל לאבד אל הגוף - חוט קטן אחד מסלק בשקט טרחה של יום שלם."},"ICON-2118":{"nm":"להב מניפה","de":"להב מניפה שמעורר רוח כשפותחים אותו לרווחה. כמו המניפות הישנות שקיררו זיעה בימים חמים, הכלי הפשוט ביותר מעניק את הנחמה הקרירה ביותר. משב רוח אחד תמיד פורח מקצות האצבעות."},"ICON-2119":{"nm":"כיס למגבת קירור","de":"כיס קטן המכיל מגבת שמתקררת כשמרטיבים אותה. גיליון בד אחד שמקרר חום ישן שם בעדינות, עד שהוא נוחת ברכות על עורף עייף ולוקח בשקט את חום הצהריים."},"ICON-2120":{"nm":"צלוחית לטיפות","de":"צלוחית שהוכנה מראש כדי לתפוס את המקום שאליו ייפלו טיפות שהצטברו. להכין מקום שיקלוט את מה שזולג, במקום להאשים אותו על כך. החום של המטבח תמיד שוכן כך, בלי קול."},"ICON-2121":{"nm":"כנף כיוון למאוורר","de":"ברגע שהרוח שנשפכה ישר בפנים סוטה מעט לצד לאורך להב קטן, האוויר המחניק של חדר האימונים סוף סוף נושם לרווחה. שינוי הזרימה תמיד היה עניין של זווית קטנה כזו."},"ICON-2122":{"nm":"סרט מצח","de":"אם השוליים נרטבים בזמן רחיצת הפנים, היום כולו מתפרק. הסרט הזה, שמרים בעדינות את השיער מעל המצח, מעניק לאדם מול המראה חמש דקות יבשות. שמים לב אליו רק כשהוא נעדר."},"ICON-2123":{"nm":"מעמד קליפס לכוס שתייה","de":"כשכוס מתנדנדת בסכנה בקצה השולחן, הקליפס הזה אוחז בשקט בצד אחד שלה. יום שעבר בלי שנשפך דבר, לוגם המים מזכיר לך, הוא בזכות מישהו שאחז בקצה במקומך."},"ICON-2124":{"nm":"ידית וו לחלון אוורור","de":"חלון סגור לגמרי מחניק, וחלון פתוח לרווחה קר מדי. הידית הזו זוכרת את הרווח המדויק שביניהם. אוורור הוא, בסופו של דבר, עניין של הלב - להשאיר דברים פתוחים בדיוק כמה שצריך."},"ICON-2125":{"nm":"כיסוי פינה מקורק","de":"תמיד הפינה החדה היא זו שפוצעת בהתנגשות. לכן חותכים פיסת קורק וחובשים בה כל קצה. מקום שנעטף ברכות כבר לא יכאיב לאף ברך."},"ICON-2126":{"nm":"ידית רצועה לכרית גליל","de":"להעביר כרית ארוכה ממקום למקום מטריד יותר משנדמה. חוברים רצועה אחת והיא נכנסת בנוחות ליד אחת. הסוד להרים דבר כבד בקלות תלוי במקום שבו שמים את הידית."},"ICON-2127":{"nm":"אבזם חגורה","de":"יש ימים שמהדקים את המותניים חור אחד יותר, ויש ימים שמרפים חור אחד. זה שמכיר את מצב הרוח שלך בכנות הכי רבה הוא האבזם הקטן הזה. פיסת מתכת ששותקת ומתעדת את כנות הגוף."},"ICON-2128":{"nm":"משטח תמיכה ברבע-בלוק","de":"בלוק שנחתך לרבעים תומך היטב ברצפה. לא גבוה מדי ולא נמוך מדי - בדיוק במידת האיזון הנכונה. הוא מראה בשקט שלתמוך פירושו להשפיל את עצמך כדי להרים את מה שמעליך."},"ICON-2129":{"nm":"כיסוי לכרית-ביצה","de":"מלבישים את הכרית העגולה כביצה בבגד מותאם בדיוק. גם אם היא ספוגת זיעה, פשוט מפשיטים אותה ומכבסים. הבית יודע שככל שדבר נוגע יותר בעורך מדי יום, כך הוא זקוק יותר לחליפה נוספת להחליף אליה."},"ICON-2130":{"nm":"טריז יישור לבלוקים","de":"אם הרצפה נוטה ולו במעט, כל מה שנערם בטרחה מתנדנד. דוחפים טריז דק אחד אל הרווח, והעולם מוצא מחדש את איזונו. ליישר דברים לא דורש שום דבר גדול."},"ICON-2131":{"nm":"פקעת קשירה לקצה רצועה","de":"קושרים פקעת חזקה כדי שקצה הרצועה לא יתפרם ויתרפט. חוט שקצהו קשור בקפידה מחזיק זמן רב. קשר קטן אחד מלמד שסיום הוא קשה יותר מהתחלה."},"ICON-2132":{"nm":"כרית מתקפלת לברכיים","de":"הכאב החד ההוא בכל פעם שהברך נוגעת ברצפה קשה. כרית אחת שמתקפלת ונפתחת מתגנבת בעדינות בין הברך לרצפה. זו עדינות שתומכת בברך של מישהו במקומו."},"ICON-2133":{"nm":"בסיס נגד החלקה לבלוק","de":"אפילו הבלוק היציב ביותר חסר תועלת אם הוא מחליק. הקווים הדקים החרוטים בבסיסו נאחזים חזק ברצפה. הסוד ליציבות תמיד מסתתר בצד התחתון הבלתי נראה."},"ICON-2134":{"nm":"קליפס יישור למוטות","de":"מיישרים את המוטות בקו ישר ומהדקים בקליפס. מי שרגיל ליישר שורות מכיר את זה - את הסיפוק הקטן והמוזר שעולה מהצבת דברים עקומים זה לצד זה, ישרים."},"ICON-2135":{"nm":"לולאת רצועה לשריר הירך האחורי","de":"כשהחלק האחורי של הירך נמתח עד שצווחה נמלטת, הלולאה הזו מגיעה במקומך אל קצות האצבעות שהיד לא מגיעה אליהן. למקום שאליו לא הצלחת להגיע לבד, חוט אחד בונה גשר עבור הרגל."},"ICON-2136":{"nm":"כרית מרווחת אצבעות","de":"גם אצבעות רגליים שכלואות בנעליים כל היום זקוקות להפסקה. על כרית שמרווחת ביניהן, הרגל נמתחת סוף סוף כמו התעוררות. ערב שמרפה אותך החל מהמקום הרחוק ביותר."},"ICON-2137":{"nm":"מד זווית ליציבה","de":"בעין בלבד אין דרך לדעת כמה מעלות הסטתה היציבה שלך. כשהמד מגלה בשקט את הזווית, הגוף סוף סוף עומד ישר. סרגל שמראה את ההטיה שלא ראית."},"ICON-2138":{"nm":"טריז יישור לאגן","de":"אחר צהריים עייף שבו האגן קיפא נטוי לצד אחד. מציבים טריז אחד ומחזירים בהדרגה את שיווי המשקל. זה לא לכפות יישור בכוח, אלא לעזור לדברים למצוא מחדש את מקומם הנכון."},"ICON-2139":{"nm":"אבזם רצועה לפתיחת כתפיים","de":"רצועה שמיישרת בעדינות כתפיים כפופות. מהדקים את האבזם והגב הכפוף נפתח לאט. שואפים אוויר עמוק עם כתפיים פתוחות לרווחה, ורק אז מופיעה יציבת קידה על הבמה."},"ICON-2140":{"nm":"טריז תמיכה לעמוד השדרה","de":"שוכבים על הגב ועמוד השדרה מצייר את עקומתו הטבעית. טריז שתומך בשקט בעקומה הזו בלי להיאבק בה. לדעת לנוח כראוי מתחיל בהוקרת העקומה שאיתה נולד הגוף."},"ICON-2141":{"nm":"טריז מתיחה לגב כף הרגל","de":"מתיחת גב כף הרגל תמיד חסרה משהו. מציבים את הטריז הנכון ונמתחים בנעימות עד לעומק שלא הגיעו אליו קודם. שיפוע קטן שעוזר להגיע קצת יותר רחוק."},"ICON-2142":{"nm":"משענת יישור לשורש כף היד","de":"כששורש כף היד הכפוף מול המקלדת מתחיל לעקצץ, המשענת מחליקה בשקט מתחתיו. הראשונים לדאוג לידיים שעובדות שעות ארוכות הם חפצים צנועים ונמוכים כאלה."},"ICON-2143":{"nm":"תחבושת תמיכה לשורש כף היד","de":"לפני הרמת דבר כבד, כורכים תחבושת פעם אחת סביב שורש כף היד. ביטחון שגדל עם כל סיבוב. ההרגל לעטוף מראש לפני שנפצעים הוא הסוד השקט של מי שמתאמנים לטווח הארוך."},"ICON-2144":{"nm":"כיס טלפון לזרוע","de":"איפה להניח את הטלפון בזמן ריצה תמיד היה עניין מטריד. הכיס הזה שנרכס לאמת היד לוקח את הדאגה הזו. רצים עם שיר אהוב צמוד לזרוע, והדרך מרגישה קצרה בהרבה."},"ICON-2145":{"nm":"כיסוי קפיץ למכשיר אחיזה","de":"כיסוי שמונח על קצה קפיץ מכשיר האחיזה כדי שלא ידקור את כף היד. לאורך כל הלחיצה והשחרור, הפקק הקטן הזה שומר על השלום בין היד למתכת. תשומת לב במקום בלתי נראה."},"ICON-2146":{"nm":"אצבעון הגנה לכפפה","de":"לאצבעות הסבתא המיומנות בתפירה תמיד היה אצבעון. האצבעון הזה, המחובר לקצה הכפפה, מגן על קצה האצבע. הרצון להגן על ידיים שעבדו זמן רב דומה להפליא, גם בין דורות."},"ICON-2147":{"nm":"כרית יבלות לאחיזה","de":"היבלות שנצרבו בכף היד הן טביעות האצבע שהותיר המאמץ. כרית שמונחת מעליהן מאפשרת את החזרה הבאה. עוטפים מחדש את המקום שהתקשה, והאדם נאחז שוב."},"ICON-2148":{"nm":"סרט נגד החלקה לכף היד","de":"אם כף היד ממשיכה להחליק, מאבדים את מה שאחזו בו בעמל. כורכים סרט מחוספס והיד והכלי הופכים לגוף אחד. הכוח לא לאבד אחיזה מגיע, באופן מפתיע, מחיכוך."},"ICON-2149":{"nm":"רצועת ספיגת זיעה לאמת היד","de":"לפני שהזיעה שזלגה במהלך האימון מגיעה לשורש כף היד, הרצועה הזו על האמה סופגת אותה קודם. שהזיעה אינה דבר מביש - בד רטוב לגמרי מעיד על כך בשקט."},"ICON-2150":{"nm":"מתלה ייבוש לכפפות","de":"זורקים אותן סתם והבוקר שלמחרת הופך לעינוי, אך תולים אותן בקפידה והרוח מייבשת אותן ברכות במהלך הלילה מעצמה. ריח הנקיון של כפפות מיובשות היטב פותח את המחר בצלילות."},"ICON-2151":{"nm":"ידית רוכסן לבגדי ספורט","de":"בידיים רטובות לגמרי פשוט אי אפשר לאחוז ברוכסן זעיר. מחברים ידית אחת והכל נמשך בתנועה נקייה אחת. לולאה שולית כזו מצילה דקה שלמה של בהלה."},"ICON-2152":{"nm":"טלאי אוורור לזיעה","de":"מניחים טלאי אוורור על המקום החם ביותר בגוף. החום הכלוא בורח בשקט דרך הטלאי. המעשה של פתיחת נקב נשימה קטן אחד ממש במרכז המחניק."},"ICON-2153":{"nm":"פיסת כרית לתוך-נעל","de":"חותכים רק את החלק השחוק מתוך-נעל ישן ומכניסים פיסה חדשה. יד שלא זורקת את הכל, אלא מחליפה רק את מה שכואב. תיקון קטן מתחת לכף הרגל מקל על כל צעד ביום."},"ICON-2154":{"nm":"טלאי מספר להדבקה בגיהוץ","de":"מדביקים מספר גב לבד בעזרת מגהץ. בזמן שהחום מתקרר, המספר מתבסס יציב על הבד. חותמת הפתיחה שבזכותה אנשים החובשים אותו מספר הופכים לקבוצה אחת."},"ICON-2155":{"nm":"מגן חיזוק לקדמת נעל","de":"כיסוי חיזוק על קדמת הנעל בולם בשקט את גורלה של נעל שקצה אצבעה נחבט שוב ושוב. המקום הראשון שנשחק הופך לחזק ביותר. ככל שהנעל עמידה יותר לאורך זמן, כך היא איתנה יותר כבר מקצה האצבע."},"ICON-2156":{"nm":"קשר חוט הידוק לבגד ספורט","de":"ברגע שמושכים את חוט המותניים וקושרים אותו, הבגד הרפוי מתהדק בדיוק לגוף. הקשר האיתן הזה, שלא מתפרק, מחזיק הכל במקומו לאורך התנועות הכי אינטנסיביות."},"ICON-2157":{"nm":"רצועה נגד גלישה לגרב קרסול","de":"המטרד ההוא של גרב קרסול שממשיך להתגלגל פנימה לתוך הנעל. רצועה אחת עוצרת את ההחלקה הזו. גרב קטן כל כך שלא שמו לב אליו סוף סוף שומר על מקומו."},"ICON-2158":{"nm":"כרית זיעה לבית השחי בבגד ספורט","de":"כרית שמונחת מראש במקום שבו הזיעה נובעת הכי הרבה. גם אם היא ספוגה לגמרי, שום סימן לא ניכר על פני הבגד. הדברים שעובדים בשקט מחוץ לעין הם אלה ששומרים על הבמה נקייה."},"ICON-2159":{"nm":"לולאת משיכה לעקב הנעל","de":"אחרי נעילת הנעל, מושכים בקלות את לולאת העקב והרגל מחליקה פנימה. הנוחות הקצרה הזו שחוסכת התכופפות. בבוקר עמוס, לולאה קטנה כזו עושה עבודה נאמנה."},"ICON-2160":{"nm":"ראש חלופי לאקדח עיסוי","de":"מחליפים את הראש בהתאם למקום שמעסים. לכל שריר קשור יש צורה מתאימה משלו. ערב שבוחר בדיוק את עוצמת הנחמה הנכונה עבור כתפיים ששרדו את היום."},"ICON-2161":{"nm":"תחנת טעינה לאקדח עיסוי","de":"גם היד שתרפה את הגוף כל היום מתעוררת רק כשהיא נטענת. בזמן שהאור האדום הופך לירוק, מותר לנוח לרגע. כשההבהוב נעצר, מגיע בשקט התור לרפא שוב כתפיים נוקשות."},"ICON-2162":{"nm":"חוגת עוצמה לאקדח עיסוי","de":"חלש, קצת יותר, עד כאן. מסובבים את החוגה, וקצות האצבעות מתמקחים בשקט עם הגוף עצמו. ההבטחה של היום - להתחזק רק בדיוק כמה שכואב - כתובה בבירור בין החריצים הקטנים."},"ICON-2163":{"nm":"טבעת מעמד לכדור רטט","de":"גם לכדור שמתגלגל היטב יש צורך במקום עצירה קצר. המעמד העגול הזה מחבק בשקט את הלב שרוצה להתגלגל הרחק, שומר על מקומו עד שיגיע תורו הבא. גם מנוחה היא חלק מהאימון."},"ICON-2164":{"nm":"כיסוי ידית למקל דיקור-לחיצה","de":"עם כובעון קטן אחד על הקצה, הכאב בכף היד נמס בעדינות. בין קשיחות לעור תמיד דרושה שכבה רכה אחת. נגיעה עדינה שמעגלת ראשונה את המקום שבא במגע."},"ICON-2165":{"nm":"כיס לגליל בוטן","de":"שק קטן שמכיל גליל בצורת בוטן. כשהוא מתגלגל החוצה מפינת התיק, ההחלטה של אתמול לדאוג קצת לגוף היום מתגלגלת יחד איתו. כיס קטן זוכר את ההבטחה."},"ICON-2166":{"nm":"מעמד לגליל עיסוי לכף הרגל","de":"אם המקום שאליו מפקידים את הרגליים מתנדנד, גם ההרפיה מתנדנדת. המעמד הזה שתומך בגליל אוחז חזק ברצפה, ומכין מקום שבו שתי רגליים עייפות יכולות להישען ברוגע. אמינות מגיעה מיציבות בלתי מתנדנדת."},"ICON-2167":{"nm":"פקק ליבה לגליל","de":"פקק קטן שסותם ליבה חלולה. הפנים הבלתי נראים חייבים להיות מלאים כדי שהחוץ לא יתפרק. את המקום ההוא שאיש לא יראה בזמן שהוא מתגלגל, החלק השקט הזה תומך בו בדממה."},"ICON-2168":{"nm":"פקק קצה למקל עיסוי","de":"כיסוי עגול על קצה המקל. שלא ישחק, שלא יישרט - להגן על הקצה הוא, בסופו של דבר, הדרך לשמור אותו לצידך זמן רב. הרצון לעטוף במקום הרך ביותר את הנקודה הראשונה שסופגת מכה."},"ICON-2169":{"nm":"מכשיר חיתוך לגליל טייפ","de":"מושכים ביד אחת והטייפ נחתך בניקיון. גם בקשירה ובסיום יש טריק קטן, ולהב זה מכיר את התחושה של סיום מסודר. גמר נקי מקל על מה שיבוא אחריו."},"ICON-2170":{"nm":"כיסוי הדבקה לקצה טייפ","de":"כיסוי שלוחץ בשקט על הקצה כדי שלא יתפרק. כל אחד יכול להתחיל, אך להישאר דבוק עד הסוף תמיד קשה. היד הקטנה הזו שאוחזת בקטע האחרון לוקחת בשקט אחריות על סיום היום."},"ICON-2171":{"nm":"שרוול לחיצה לשורש כף היד","de":"כורכים שכבה אחת סביב שורש כף יד עמוס, והכאב מגיע בפיגור קל. כמו יד שאוחזת בשלך בשקט, לחיצה היא לעיתים ההגנה החמה ביותר. זו לא סחיטה, אלא תמיכה."},"ICON-2172":{"nm":"אבזם למגן קרסול","de":"קליק קצר של הידוק האבזם מרגיע את הלב. עוטפים את הקרסול בחוזק, ואומץ עולה בשקט שאולי מותר לצעוד עוד צעד קדימה. צליל קטן אחד הופך להתחלה איתנה."},"ICON-2173":{"nm":"מהדק לרצועת לחיצה לברך","de":"ככל שמושכים ומהדקים את הרצועה, כך הברך מרגישה בטוחה יותר. לא רופפת עד שתתפרק, אך גם לא כואבת - אי-שם ביניהם יש חריץ מדויק אחד. המהדק לעולם לא שוכח את המקום הזה."},"ICON-2174":{"nm":"מספריים לחיתוך טייפ אצבעות","de":"מספריים קטנים שחותכים בדיוק את הטייפ הכרוך סביב פרק. עגולים בקצה, כדי שלא יפצעו את העור. ככל שכלי מיועד לטפל, כך הלהב שלו מחודד ברוך רבה יותר - המספריים האלה מראים זאת בשקט."},"ICON-2175":{"nm":"גלגלת לרצועת לחיצה","de":"מסגרת שגוללת מחדש בסדר רצועת לחיצה שנפרשה. יד שמגלגלת בקפידה את מה שסיימה להשתמש בו לא תסתבך גם בפעם הבאה שתיפתח. בכל שכבה שנגללת בסדר, הצניעות של היום ספוגה."},"ICON-2176":{"nm":"רצועת קשירה למגן שוקיים","de":"רצועה שקושרת את הכרית שמגנה על חזית השוק. הלב שבודק מראש את המקום שעלול להיפגע הוא כשלעצמו הכנה. נכנסים למגרש עם רגליים קשורות חזק, והפחד בלב פוחת בחצי."},"ICON-2177":{"nm":"קליפס למגן מרפק","de":"קליפס קטן שנועל בחוזק כדי שהמגן לא יחליק למטה. שולי כמו לצבוט דף נייר, אבל אם זה מתרופף, הכל מתרופף. הידוק קטן אחד מחזיק חזק את הביטחון של יום שלם."},"ICON-2178":{"nm":"ידית לולאה למתיחות","de":"אוחזים בלולאה ומותחים את הגוף לאורכו, ורואים קצות אצבעות שהגיעו טפח רחוק יותר מאתמול. לא רק השריר מתארך ככל שמושכים. גם לב שהתקשה נפתח קצת בינתיים."},"ICON-2179":{"nm":"מפריד אצבעות לרגליים","de":"מרווחים בין אצבעות רגליים שהיו כלואות בנעליים כל היום, ורוח נכנסת אל המקום הצפוף. יש בעולם דברים שנעשים נוחים רק אחרי שנפרדו לרגע. גם לקצות הרגליים דרוש רווח לנשום."},"ICON-2180":{"nm":"לוח טריז להרפיית שוקיים","de":"כשמכניסים אותו כמו טריז מתחת לשוקיים, הרגליים נמסות ומשתחררות. זווית משופעת אחת מזרימה בשקט את משקל היום. לשכב נשען מעט - זו, לעיתים, היציבה הנוחה ביותר מכולן."},"ICON-2181":{"nm":"משענת הרפיית צוואר","de":"מניחים עליה את הצוואר וסוגרים עיניים לרגע. שמותר להניח לרגע את הראש הכבד, המשענת הקטנה הזו לוחשת תמיד מאותו מקום בעדינות אל הכתפיים. גם הישענות דורשת אומץ."},"ICON-2182":{"nm":"כיסוי קצה למוט מתיחות","de":"כיסוי אחד שמכסה את קצה המוט הארוך. עם קצה רך, אפשר להרגיש בטוח בכל מקום שהוא נוגע בו. לא משנה לאיזה כיוון פונים, לעגל תחילה את הפינות - כך תמיד מתחילה התחשבות, בשקט."},"ICON-2183":{"nm":"לוח בליטות לכרית דיקור","de":"משכיבים את הגוף על הבליטות המחוספסות, והיום נמלט מכל נקודת לחיצה. בגבול ההוא שבין כאב להקלה, כתפיים שנוקשו כל היום נמסות לאט כמו נכנעות."},"ICON-2184":{"nm":"שעון חול לנשימת הרפיה","de":"הבטחה שקטה למשוך נשימה ארוכה עד שגרגר החול האחרון ייפול. זרם החול הדק סופר בשקט את קצב השאיפה והנשיפה. גם לב עסוק שוקע לרגע בינתיים."},"ICON-2185":{"nm":"מעמד כדור דיקור לכף הרגל","de":"מניחים כדור במרכז כף הרגל ולוחצים בעדינות ובעקביות. לרגליים שתמכו בגוף כולו כל היום, המעמד הקטן מפנה בשקט את מקומו, כאילו אומר שהגיע תורן להיתמך. גם מה שתומך זקוק לפעמים למנוחה."},"ICON-2186":{"nm":"חוט לולאה להרפיית כתפיים","de":"חוט לולאה שתולים על הכתף ומושכים. מותחים את החוט לכיוון המקום הנוקשה, וכל פרק קשור משתחרר חופשי, חריץ אחר חריץ. הוא מלמד שגם להשתחרר דורש משהו שיאחוז ביד שלך."},"ICON-2187":{"nm":"דיסקית לחבל מסלול שחייה","de":"חרוז עגול אחד מתוך חבל המסלול המחלק את המים. גבול חם שנמתח מעל המים כדי שלא תתנגש בשחיין שלצידך. מחיצות קטנות ששומרות על מסלולו של כל אחד מקדמות את כולם, זה לצד זה, עד הסוף."},"ICON-2188":{"nm":"וו מתיחה לחבל מסלול","de":"וו שמותח את חבל המסלול ותופס אותו. אם רופף מדי הוא מתעקל בגלים, ואם מתוח מדי הוא נקרע. מציאת המתיחה הנכונה דומה לאיסוף הלב - תמיד מגששים אי-שם ביניהם."},"ICON-2189":{"nm":"כיסוי צבע למסלול שחייה","de":"כיסוי קטן שנצבע בצבע שונה לכל מסלול. סימן שנצבע כדי שתזהה את מסלולך שלך במבט אחד, גם מרחוק. לא לתת למישהו ללכת לאיבוד בעזרת צבע אחד - הכוונה, ביסודה, מתחילה מנדיבות קטנה כזו."},"ICON-2190":{"nm":"לוח תלייה לחבלי מסלול","de":"לוח לתלייה מסודרת של חבלי המסלול כשאינם בשימוש. ביד שמסדרת בקפידה את החבלים לקראת ההתחלה הבאה, טמונה בשקט החלטה רגועה לסיים את היום היטב."},"ICON-2191":{"nm":"ידית סליל לחבל מסלול","de":"מסובבים את הידית שוב ושוב כדי לגלגל פנימה חבל שנפרש לאורכו. לאסוף את מה שפוזר תמיד דורש סבלנות. סיבוב אחד, ואחריו עוד אחד - כך גמר מושלם בלי חיפזון, לאט לאט."},"ICON-2192":{"nm":"מהדק קשר לקצה מסלול","de":"מהדק שנועל בחוזק כדי שהקשר בקצה החבל לא יתפרק. הוא לא נותן לפרק שולי אחד להישמט. רק כשיש יד ששומרת עד הסוף, חבל ארוך שומר על צורתו המסודרת בלי להתפרק."},"ICON-2193":{"nm":"חרוז ציפה לחבל מסלול","de":"חרוז הציפה של חבל המסלול שצף על פני המים. כדי לא לשקוע, הוא אגר בתוכו כמות אוויר מלאה. אור מסוים מגיע מלב ריק שמולא בעמל - המים המתנודדים ממחישים זאת בכל פעם מחדש."},"ICON-2194":{"nm":"דגלון מספר מסלול","de":"דגלון קטן שמכריז על מספר המסלול. פיסת בד אחת שמתנופפת ברוח אומרת לך בבירור: \"זה המקום שלך\". תמרור קטן אך ברור שמכניס אותך ישר אל המסלול שלך בלי ללכת לאיבוד."},"ICON-2195":{"nm":"וו חיבור לחבלי מסלול","de":"וו שמחבר חבל מסלול לחבל הבא. עם וו אחד שמאחד מחדש מסלול שנקטע, נתיב המים סוף סוף שלם. לחבר, בסופו של דבר, הוא מלאכתה של פיסת מתכת קטנה שמושיטה בשקט יד בין דברים שנפרדו."},"ICON-2196":{"nm":"משטח דריכה לבלוק זינוק","de":"משטח הדריכה שמעל קו הזינוק סופג את כובד הקפיצה הראשונה במלואו. 0.1 השנייה של דחיפה חזקה - היציבות שבה נדרכות האצבעות דוחפת קדימה תחילתו של מרוץ שלם. כל המראה מתחילה ממקום לדרוך בו בחוזק."},"ICON-2197":{"nm":"מוט אחיזה לזינוק","de":"המוט שהיד אוחזת בו בחוזק רגע לפני איתות הזינוק. חייבים לעגן את הלב הרועד באיזשהו מקום, אחרת הזינוק יתנדנד. רק העובדה שיש היכן לאחוז הופכת את התנועה הבאה לצלולה ויציבה הרבה יותר."},"ICON-2198":{"nm":"חוט דגלוני גב-שחייה","de":"חוט דגלונים שמודיע לשוחה הפונה אל התקרה שהקיר מתקרב. עדינות שמזהירה מראש על מה שאי אפשר לראות. עם אות אחד ששומר בקפידה על הגב, החתירה האחרונה הופכת בטוחה."},"ICON-2199":{"nm":"כרית לקיר פנייה","de":"כרית רכה שמונחת על הקיר שבו משנים כיוון. כדי שלא יכאב גם בפגיעה חזקה, היא עוטפת ברכות את נקודת הפנייה. בדרך חזרה תמיד מונחת קודם התחשבות שקטה של מישהו."},"ICON-2200":{"nm":"לוח מגע לסיום","de":"ברגע שקצה האצבע נוגע, הכל נגמר. סופו של מסלול ארוך ומתנשף מצטמצם בסוף לנגיעה קלה אחת. הגעה אינה משהו מרשים - היא לגעת בדיוק במקום הנכון, עונה הלוח בשקט."},"ICON-2201":{"nm":"רצועת החלקה של פלטפורמת הזינוק","de":"מי שעומד בראש המדרון עוצר את נשימתו, ולו לרגע אחד. חולפים על הפחד הקצר הזה ומחליקים למטה - ופתאום, בהתזה של מים, פורץ הצחוק. כל התחלה נולדת תמיד צעד קטן אחד מעבר לפחד."},"ICON-2202":{"nm":"קונוס סימון מרחק פנייה","de":"כשמהססים בפרשת דרכים, הנקודה הקטנה הזאת פונה אליך ראשונה. \"כאן צריך לפנות\", היא אומרת, \"אל תלך לאיבוד\". מישהו מביט בצבע היחיד הזה ומוצא שוב את דרכו, וממשיך ללכת."},"ICON-2203":{"nm":"טריז זווית לבלוק זינוק","de":"באותו חצי-פעימה שבו הגוף כורע הכי נמוך, רגע לפני הקפיצה. דריכה קטנה נמצאת שם, תומכת בזווית כדי שקצות האצבעות לא יחליקו. כל רגע של המראה גבוהה נולד מתוך השיפוע הזה."},"ICON-2204":{"nm":"כיפת ריפוד לפינת קיר","de":"כדי שלא יכאב גם כשמתנגשים בו תוך כדי משחק, ויתרה הפינה על חדותה ונעשתה עגולה. הרצון שלא תיפגע נחצב שוב ושוב עד שנדבק אל הקיר. ההגנה הכי אוהבת היא לרוב כזאת, שקטה כל כך."},"ICON-2205":{"nm":"וו תלייה למציל","de":"ברוב הזמן זה רק מקום שמשהו תלוי בו. אבל ברגע שמישהו נופל למים, זהו המקום הראשון שיד מושטת אליו. יש בעולם מין אמינות כזאת - עדיף שלעולם לא תיעשה בה שימוש."},"ICON-2206":{"nm":"מוט וו הצלה","de":"זרוע ארוכה שמצמצמת במכה אחת מרחק שאי אפשר להגיע אליו. כשהיד קצרה מדי, הוו הזה הופך במקומה ליד. הצלה היא, בסופו של דבר, מעשה של הושטת קצות אצבעותיך למישהו רחוק."},"ICON-2207":{"nm":"ראש מקלחת לצד הבריכה","de":"\"תזכרו לשטוף לפני שנכנסים.\" כמו המשפט הקבוע של המציל, זרם מים ניתך מעל הראש. במכה קרה אחת, אבק היום כולו נשטף ונעלם."},"ICON-2208":{"nm":"אריח רצפה נגד החלקה","de":"מרקם עדין ומחוספס כדי שכפות רגליים יחפות לא יחליקו. ממקום בלתי נראה, הוא אוחז בשקט בכפות הרגליים. הביטחון החזק ביותר תמיד מסתתר במקומות הכי לא מרשימים."},"ICON-2209":{"nm":"שלט עומק מים","de":"לפני שהרגל נכנסת למים, המספר כבר מספר לך את העומק. מקום שהיה מפחיד אילו נכנסת אליו בלי לדעת, נרגע בלב ברגע שקוראים אותו. מה שהשלט הזה עושה הוא לעזור בהכנה קטנה."},"ICON-2210":{"nm":"חבל מצופים לתיחום בטיחות","de":"חבלים צבעוניים צפים על המים ומחלקים את האזורים. \"עד כאן בטוח\", מבטיחים המצופים, כשהם אוחזים ידיים. רק כשיש גבול אפשר סוף סוף לשחות בראש שקט ובלב חופשי."},"ICON-2211":{"nm":"אגן טבילת רגליים לחיטוי","de":"אגן קטן שבו כפות רגליים יחפות מתעכבות לרגע לפני הכניסה למים. טקס קצר של היטהרות מהרגליים ומעלה טמון בו. הניקיון תמיד מתחיל בצעד אחד קטן כזה, ובתשומת הלב שמאחוריו."},"ICON-2212":{"nm":"קונוס אזהרת רצפה רטובה","de":"קונוס צהוב אחד מאט בשקט את הצעדים. \"כאן רטוב, זהירות\" - התחשבות שנמסרת בצבע במקום במילים. אזהרה קטנה כזאת שומרת בשקט על היום של מישהו שכמעט החליק."},"ICON-2213":{"nm":"ארון עזרה ראשונה בקיר","de":"הארון הלבן על הקיר כמעט אף פעם לא נפתח. אבל ברגע שהוא כן נפתח, הוא הופך להיות ההקלה של מישהו. מקרה חירום תמיד ממתין בשקט במקום הכי קרוב שיש."},"ICON-2214":{"nm":"רשת איסוף לפני המים","de":"היא מרימה בשקט את העלים והאבק הנעים על פני המים. הבהירות לא מגיעה מעצמה, ומישהו צריך לדלות אותה ביד פעם ביום. מאחורי מים שקטים עומדת רשת חרוצה."},"ICON-2215":{"nm":"צינור רובוט ניקוי רצפה","de":"גם בלילה שבו כולם ישנים, הוא משוטט לאט, ממשש את הרצפה. העובד הכי מסור בשעות שבהן איש לא מביט. הבהירות של הבוקר היא השביל שהצינור הזה שרטט כל הלילה."},"ICON-2216":{"nm":"מכל מינון כלור","de":"גם בשמירה על צלילות המים יש כמות מדויקת נכונה. יותר מדי - והיא נעשית קשה, פחות מדי - והיא עכורה, והאיזון נמצא ביניהם. יד בלתי נראית מכווננת בשקט את הסימון הזה כל יום מחדש."},"ICON-2217":{"nm":"בקבוק בדיקת מים","de":"אוספים לגימת מים אחת לבקבוק קטן ושואלים לשלומו של היום. לעין זה נראה בדיוק אותו הדבר, אבל המספרים לא משקרים. שקט נפשי הוא דבר שבודקים אותו פעם ביום, כך."},"ICON-2218":{"nm":"מגרפה לאיסוף לוחות ציפה","de":"מגרפה ארוכה שאוספת יחד לוחות ופסולת צפה על המים. יד שאוספת את המפוזר דומה איכשהו ללב. גם אי-סדר, ברגע שמטאטאים אותו פעם אחת, נעשה מסודר."},"ICON-2219":{"nm":"רשת מכסה לניקוז","de":"רשת צפופה השומרת על המעבר שבו המים זורמים החוצה. היא בוררת בשקט מה לשחרר ומה לעצור. גם לשחרור צריך מסננת, אומרת הרשת הקטנה הזאת בלי מילים."},"ICON-2220":{"nm":"מצוף מדחום מים","de":"צופה קטן שצף על המים וקורא את הטמפרטורה. קר או בדיוק נכון - חסד שמודיע לך לפני שהגוף נוגע במים. השלווה הראשונה של הכניסה למים תמיד מתחילה במצוף הזה."},"ICON-2221":{"nm":"מוט גלגול לכיסוי בריכה","de":"ידית שגוללת כיסוי רחב ומאחסנת אותו הצידה. כלי שיודע מתי לפרוש ומתי לאסוף מרגיש איכשהו אמין. בזמן המנוחה, זה כמו לכסות גם את המים בשמיכה."},"ICON-2222":{"nm":"סל סקימר לבריכה","de":"הסל שבו הפסולת הצפה על פני המים אוספת את עצמה סופית. בגלל שיש כלי שקולט את השאריות במקום בלתי נראה, המים העליונים תמיד צלולים. מאחורי הניקיון מצטבר תמיד עמל."},"ICON-2223":{"nm":"מתלה ייבוש לכובע שחייה","de":"תולים כובע שחייה רווי מים הפוך על ראשו. בזמן שהוא מטפטף טיפה-טיפה, הכובע לומד לאט לנשום. הייבוש הוא, בסופו של דבר, רק שם אחר להמתנה."},"ICON-2224":{"nm":"לולאת רצועת כתף לבגד ים","de":"לולאה קטנה שמחזיקה את הרצועה כדי שלא תחליק מהכתף. ממקום בלתי נראה, היא שומרת בשקט על ההופעה מסודרת. אלגנטיות תמיד נשלמת מעל תמיכות קטנות שכאלה."},"ICON-2225":{"nm":"כיס אחסון לכובעי שחייה","de":"כיס שבו כובעי שחייה רטובים מוצאים את מקומם אחד-אחד. מעון קטן שאוסף לתוך חיבוק אחד דברים שנוטים להתפזר. סידור הוא הרגל עדין של מי שלא רוצה לאבד דברים."},"ICON-2226":{"nm":"כרית חזה לבגד ים","de":"כרית בודדת יושבת בשקט בתוך הבגד. גם אם היא לא נראית מבחוץ, היא מיישרת בעדינות את הכתפיים של מי שלובש אותה. ביטחון מסוים ממלא אותך בשקט מבפנים, לא מבחוץ."},"ICON-2227":{"nm":"קליפס תווית שם לכובע שחייה","de":"קליפס קטן שמצמיד תווית שם לקצה כובע השחייה. בין דברים שנראים זהים, הוא אומר בבירור: \"זה שלי\". סימון אחד וכל הבלבול נגמר בבת אחת."},"ICON-2228":{"nm":"לולאת רוכסן לבגד ים","de":"\"אפשר לסגור לי את הרוכסן בגב?\" את המקום ההוא שלא הגעת אליו לבד, הלולאה הקטנה הזאת מושכת במקום היד. מרחק עדין שעוזר בחריץ האחרון."},"ICON-2229":{"nm":"לוח מניעת התכרבלות לכובע שחייה","de":"מיישרים ותומכים כובע שחייה שהתרגל להתכרבל. תמיכה שמסייעת בשקט לדבר המעוקם לשוב לצורתו. צריך יד שתיישר כדי שמשהו יחזור להיות ישר והגון."},"ICON-2230":{"nm":"מהדק שרוך מותניים לבגד ים","de":"מהדק שעוטף את המותניים בדיוק נכון ומחזיק אותן שלא ייפלו. לא הדוק מדי ולא רופף מדי - בדיוק המידה הנכונה. הנוחות תמיד גרה איפשהו בין לבין."},"ICON-2231":{"nm":"מלחציים להפיכת כובע שחייה","de":"מלחציים שתופסים כובע שחייה הפוך ומיישרים אותו במכה אחת. תחושת היד שמחזירה את ההפוך למקומו נעימה למדי. ההנאה הקטנה שבסידור מגיעה מדברים פעוטים כאלה."},"ICON-2232":{"nm":"רצועת אחיזה ללוח בעיטה","de":"רצועה שנכרכת סביב היד כדי שלא תאבד את לוח הבעיטה. גם כשהזרם דוחף אותך, יש בזה נחמה גדולה שיש משהו להיאחז בו. הרעד של היום שבו למדת לבעוט בפעם הראשונה עדיין נשאר ברצועה הזאת."},"ICON-2233":{"nm":"רצועת הידוק למצוף שחייה","de":"רצועה שמחזיקה חזק את המצוף התחוב בין שתי הרגליים. רק כשהוא לא משתחרר אפשר להתרכז סוף סוף רק בטכניקה. מעל משהו שמוחזק היטב, האימון של אותו יום מעמיק זרת אחר זרת."},"ICON-2234":{"nm":"מתלה קיר לסנפירים","de":"כשהסנפירים תלויים זה לצד זה על הקיר, הם נראים ממש כמו להקת ברווזים שנחה על שפת המים. רגליים שסיימו לשחות מנערות טיפות ומחכות למחר. אפילו ההפסקה נראית שם עגולה וחמודה, איכשהו."},"ICON-2235":{"nm":"כיפה לפינת לוח בעיטה","de":"כיפה קטנה אחת שמולבשת על פינת לוח הבעיטה. כדי שלא יכאב במגע וכדי שלא יישחק בשימוש, היא עוטפת את הקצה. הסוד לשמור על משהו לאורך זמן טמון בטיפוח הפינות מלכתחילה."},"ICON-2236":{"nm":"רשת אחסון לסנפירים","de":"סנפירים שדומים לכפות רגליים שחייה משתזפים בתוך הרשת. כמו ברווזים שיצאו הרגע מהמים ומייבשים את נוצותיהם, הם מתייבשים לאט בתוך הרשת. תנומה נינוחה לקראת השחייה הבאה."},"ICON-2237":{"nm":"תג סימון למצוף שחייה","de":"מצמידים תווית שם לכל מצוף כדי לסמן בבירור למי הוא שייך. ככל שמקום משותף ליותר אנשים, כך נח יותר הלב כשברור \"של מי זה\". תג קטן אחד מטיל סדר."},"ICON-2238":{"nm":"מעמד ניקוז ללוח בעיטה","de":"מקום נשען באלכסון כדי שהמים שהצטברו בלוח הבעיטה יזלגו החוצה. צריך לרוקן את מה שנספג כדי להיעשות קל, מלמד המעמד בשקט. הצעד הראשון של הייבוש הוא להישען היטב."},"ICON-2239":{"nm":"מהדק רצועה לסנפיר","de":"חלק קטן שמהדק את רצועת הסנפיר כך שתתאים בדיוק לרגל. רופף מדי - והוא נשמט, הדוק מדי - וכואב, וזה החריץ העדין ביניהם. כדי לגלוש קלות כמו ברווז עם כפות רגליים, נחוץ המרווח הדק הזה."},"ICON-2240":{"nm":"שבב קצב לבעיטה","de":"שבב קטן שמסמן את הקצב בכל בעיטה. אחת, שתיים, שלוש - כשהקצב נכנס לגוף, גם המים הופכים בלי משים לשיר. השבב הזה מלמד בעדינות שגם לשחייה יש קצב."},"ICON-2241":{"nm":"כיס לבגד ים רטוב","de":"בתוך התיק שיוצא מהבריכה, אני תמיד הראשון לתפוס מקום. שאר החפצים ישלחו מבטים - מה לעשות, את הרטוב צריך להחזיק בנפרד כדי שכולם יישארו יבשים. חדר הבידוד של הלחות, זהו התפקיד העדין שקיבלתי."},"ICON-2242":{"nm":"לוח סחיטת מים","de":"ללחות יש נטייה לחמוק ברגע שלוחצים עליה. פעם אחת בחוזקה, ופעם שנייה - היא נכנעת רק כשמניחים משקל עליה על גבי הלוח. למי שלא היה שימוש לכוח פרק כף היד שלו, לא קל למצוא במה טובה יותר מזו."},"ICON-2243":{"nm":"לוח מחיצה לתיק שחייה","de":"כשהכול נארז בתא אחד, הרטוב והיבש מכתימים זה את זה. העבודה של להתגנב באמצע ולסמן בשקט קו. אם מחיצה אחת מביאה שלום, אולי פיוס הוא באמת עניין פשוט להפליא."},"ICON-2244":{"nm":"כיס אטום למים לנעליים","de":"הוא בולע בשלמות נעליים מלאות חול בלי לשנות את הבעת פניו כהוא זה. מה שקורה בפנים לא חשוב, כל עוד בחוץ הכול נשאר יבש - זו נימוסי האטימות למים. כיס דיסקרטי כזה מתקבל בברכה בכל מקום."},"ICON-2245":{"nm":"פקק ניקוז לתיק שחייה","de":"מסובבים את הפקק והיום שהצטבר בתחתית התיק זורם החוצה בבת אחת. סידור אחרי משחק שמח תלוי תמיד בחור קטן אחד כזה. גם בידיעה איך לשחרר דברים יש עיצוב מדויק."},"ICON-2246":{"nm":"שטיח סופג מים","de":"הוא שוכב בשקט לפני הכניסה וקולט את המים מכל רגל שנכנסת. גם אם איש לא מודה לו, הרצפה יודעת - שאיש לא החליק גם היום. במקום שקט שוכן גם גמול שקט."},"ICON-2247":{"nm":"צלוחית לכובע שחייה רטוב","de":"כשכובע שחייה שהוסר מאבד את מקומו, אני זה שמחזיק אותו. גם אם קוראים לי צלוחית ובמקום אוכל אני נושאת רק טיפות מים, אם זו עבודה של להכין מקום למישהו, גם מעמד יכול לשאת ראש בגאווה."},"ICON-2248":{"nm":"קליפס לייבוש מגבות","de":"העבודה של לנשוך חזק מגבת אחת על חבל הכביסה. הגאווה שלי היא עקשנות שלא מרפה, לא משנה כמה הרוח מתגרה בי. עד שהיא מתייבשת ומרככת בשמש, יד שאחזה פעם אחת לא מרפה ראשונה."},"ICON-2249":{"nm":"מתלה לכיס אטום למים","de":"ברגע שהוא נתלה על הוו, הכיס הנודד מקבל סוף-סוף כתובת. גם אם זה רק תלייה, שמשאילה פינת קיר אחת, האם יש משהו מרגיע יותר ממקום שלא צריך לפחד לאבד?"},"ICON-2250":{"nm":"צמיד כניסה למגלשה","de":"ההתרגשות שחיכתה בשקט לתורה קשורה כולה בצמיד הקטן הזה. רק לאחר שהוא נענד סביב פרק כף היד, התור למגלשה מתחיל לגלוש קדימה, אז אולי כניסה היא בעצם מעשה של קשירת הבטחה סביב פרק היד."},"ICON-2251":{"nm":"חתיכת מזרן למגלשת מים","de":"אנשים רצים עליו בשמחה, בלי לשים לב לפער מתחת לרגליים. הונח שם כדי שאיש לא יחליק, וקיומו מתגלה רק כשהחתיכה הבודדת ההיא נעלמת. יש בעולם הזה לא מעט דברים שנזכרים רק דרך המקום הריק שהם משאירים."},"ICON-2252":{"nm":"רצועה אטומה למים למפתח לוקר","de":"לשמור על מפתח לוקר מפני המים - זהו המקצוע שלי כל חיי. אני כרוכה סביב פרק כף היד ומתיזה יחד איתך, אבל דואגת שמפתח אחד יישאר יבש כעצם. תאבדי אותי ולא תמצאי אפילו את הבגדים שלך, אז לא מעט אחריות מוטלת עליי."},"ICON-2253":{"nm":"לוח רמזור זינוק למגלשה","de":"באותו רגע קצר שבו אדום הופך לירוק, כל לב על המגלשה קופץ יחד. הסמכות להתיר את הזינוק - ומי היה מאמין שלוח איתות כה זעיר יכול להכיל התרגשות כה גדולה."},"ICON-2254":{"nm":"אבזם אפוד הצלה לנהר עצל","de":"האבזם שמחזיק חזק גוף שצף בנהר העצל. רק אחרי קליק אחד אפשר סוף סוף להירגע ולמסור את עצמך לזרם. שלווה נפשית מתחילה לפעמים בנעילה קטנה כזאת."},"ICON-2255":{"nm":"דגל הכוונה לבריכת גלים","de":"הוא מודיע לכולם מראש מתי הגלים עומדים להגיע. דגל למעלה - תרועה, דגל למטה - רגע לתפוס נשימה. מוזר שמה ששומר על הקצב ליד הבריכה הגועשת הוא סתם פיסת בד אחת."},"ICON-2256":{"nm":"שרשרת מספר תור למגלשה","de":"עונדים על הצוואר את מספר התור ואין יותר בלבול. תג מספר אחד קובע מי בתורו - וכך, סדר, נראה שהוא מתחיל לרוב בשרשרת קטנה כזו."},"ICON-2257":{"nm":"אסימון טעינה לצמיד מים","de":"נוגעים בעדינות בצמיד וההטענה הושלמה. בעידן של שיטוט במים בלי מזומן ובלי כרטיס, האסימון הקטן הזה משמש ארנק שלם. ככל שפרק כף היד קל יותר, כך גם הלב."},"ICON-2258":{"nm":"כיפת אחיזה לתותח מים","de":"ידית תותח מים טעמה הטוב ביותר כשאוחזים בה חזק. תאבדי כיפה אחת ושכחי מכוונון - היא פשוט מסתובבת ביד, וגורלו של קרב מים באמצע הקיץ תלוי בחלק גימור קטן אחד כזה."},"ICON-2259":{"nm":"כוס תבנית למגדל טירת חול","de":"לוחצים חול רטוב פנימה, מהפכים - ומגדל קטן צץ. אף אחד לא מבין טוב יותר ממני את הלב שממשיך לבנות גם כשהוא יודע שהמגדל יתמוטט. עבור אדריכל החול, התבנית היא התוכנית עצמה."},"ICON-2260":{"nm":"שיני מגרפת חול","de":"גוררים אותה כמו מסרקים את החול ונשארות תלמים מסודרים. גם בידיעה שהגלים ימחקו בקרוב את התבנית, השיניים ממשיכות בשקדנות לחרוט את הקווים. יש חן מסוים בלטפח באהבה דבר שנועד להיעלם."},"ICON-2261":{"nm":"משקולת עוגן לעמוד שמשייה","de":"היא עומדת בשקט למרגלות העמוד כדי שהשמשייה לא תיסחף ברוח. שמירה על הצל היא לא תפקידו של הבד הצבעוני אלא של המשקולת הכבדה הנעוצה בקרקע. המשקל הבלתי נראה הוא תמיד הכי אמין."},"ICON-2262":{"nm":"ידית מסננת חול","de":"מנערים ומסננים את החול ורק צדפות ואוצרות קטנים נשארים ביד. אוחזים בידית ומנענעים - חצי מציד האוצרות בחוף נחרץ ברשת אחת כזאת."},"ICON-2263":{"nm":"תבנית חול בצורת צדפה","de":"ממלאים אותה בחול רטוב, נוקשים קלות, וצדפות בגודל כף יד פורחות בשורה על החוף. אולי אי אפשר לאכול צדפה אמיתית, אבל את הצורה הזו כל אחד יכול ליצור. קסם קייצי צנוע."},"ICON-2264":{"nm":"פין כוונון זווית לשמשייה","de":"בכל פעם שהשמש זזה, גם השמשייה צריכה להסב את ראשה בעקבותיה. שולפים פין אחד ותוקעים מחדש, והצל עובר בשקט מקום. לב האמנות של התחמקות מהאור טמון בזווית הקטנה הזאת."},"ICON-2265":{"nm":"כיפה לקצה להב את חול","de":"כשמכסים בה את קצה הלהב החד, התיק בטוח. משהים לרגע את האומץ של חפירה בחול, ועם כיפה אחת זה נהיה צעצוע רך. גם לדעת להסתיר את החדות היא סוג של התחשבות."},"ICON-2266":{"nm":"קליפס פינה למזרן חוף","de":"כשהרוח מנסה להרים את פינת המזרן, אני נושכת חזק. שמירה על מקום אחד בחול תלויה בסוף בעקשנות של ארבע הפינות. אחר צהריים ללא רפרוף הוא מעשה ידיהם של קליפסים קטנים."},"ICON-2267":{"nm":"וו תלייה לצל שמשייה","de":"תולים אותו סתם כך על עמוד השמשייה ובגדים רטובים מתייבשים בצל. הרחק מהשמש, בתוך הרוח - חבל כביסה מאולתר שיוצר וו אחד. גם בחוף שוכנת חכמת המשק הביתי."},"ICON-2268":{"nm":"תליון צוואר אטום לטלפון","de":"כשהטלפון עטוף ותלוי על הצוואר, נולד האומץ לצלם אפילו מתחת למים. שמירה על הרצון לתפוס עוד תמונה אחת, יבשה ובטוחה. כמעין שומר ראש לזכרונות, הוא די מיומן."},"ICON-2269":{"nm":"כיס אטום למים לבגדים רטובים","de":"הוא קולט בשלמות את הבגדים הרטובים שהוחלפו, בלי תלונה. הגאווה שלו היא שלא תיגע אפילו טיפה אחת בשאר הציוד, ולכן הוא שומר את פיו סגור היטב ומגן על פינה אחת בתיק. סוף נקי מתחיל ממני."},"ICON-2270":{"nm":"רצועת גב כף רגל לסנדל מים","de":"היא עוטפת בעדינות את גב כף הרגל כדי שהסנדל היחף לא ייפול. רצים בחול כאוות נפשך, ורצועה אחת מספיקה כדי להירגע. מלווה נאמן לצעדים, בלתי מורגש אך תמיד לצדך."},"ICON-2271":{"nm":"תיק צוואר אטום לכרטיסים","de":"מחזיק כרטיסי כניסה וכרטיסי תשלום, תלוי על הצוואר ומצטרף למשחקי המים. מתיזים בלב שלם, בלי דאגה לאבד דבר, כי הוא מגן על הכרטיסים בגופו שלו. עמדה של שומר ראש נאמן."},"ICON-2272":{"nm":"כיס בד נגד אידוי למשקפי שחייה","de":"מנגבים פעם אחת בבד את פנים המשקפיים המעורפלים, והעולם שמתחת למים חוזר להיות חד וברור. כיס בד קטן אחד הוא המפתח שפותח מבט מטושטש ומשיב לו את הצלילות."},"ICON-2273":{"nm":"מברשת ניעור חול רטוב","de":"היא מנערת בעדינות אפילו את החול שבין האצבעות. היד האחרונה שמסדרת את עקבות ההרפתקה השמחה בים, ממש על סף הבית. משיכת מברשת אחת - וגם החול של יום שלם נפרד לשלום."},"ICON-2274":{"nm":"כיס רוכסן אטום למטבעות","de":"היא נועלת בתוך הרוכסן כמה מטבעות בחוזקה. גם אם ספגה מים, הקישקוש נשמע בדיוק אותו הדבר, כך שכסף החירום לקיוסק נשמר עד הסוף. כיס קטן, אבל חסכן ומיומן."},"ICON-2275":{"nm":"רצועת גלגול למגבת","de":"מגלגלים מגבת, קושרים אותה ברצועה אחת, והיא נתלית ישר על רצועת התיק. ידיים חופשיות, מגבת על הכתף. סוד ההקלה במשחקי מים חבוי בצרור הקטן הזה."},"ICON-2276":{"nm":"כיפת סיום לרצועה אטומה למפתח","de":"כפתור הסיום של הרצועה ששומרת על מפתח מפני המים. רק כשהכיפה ננעלת בקליק אפשר סוף-סוף לצלול לבריכה בראש שקט. נקודה קטנה אך חסרת פרצות שאחראית לסיום הנעילה."},"ICON-2277":{"nm":"פקק פה לשנורקל","de":"נושכים אותו ודרך הנשימה נפתחת, ונוף הים מתקרב עד ממש מול העיניים. פקק קטן שמאפשר לנשום גם מתחת למים. מי היה מאמין שהשאלת נשימה יכולה להיות מרגשת כל כך."},"ICON-2278":{"nm":"כרית נגד אידוי למסכת צלילה","de":"כשפני המסכה מבפנים מתערפלים, גם הצפייה מתחת למים דועכת. כרית אחת חוסמת את הערפול הזה, כך שמבט צלול הוא תוצאה של השכבה הבודדת והבלתי נראית הזאת."},"ICON-2279":{"nm":"קליפס הידוק בוהן לסנפיר","de":"הוא מהדק את קצה הסנפיר בדיוק לרגל, כדי לבעוט במים בלי רפיון. כדי שהכוח שבבעיטה אחת לא יידלף, הקליפס קושר בשקט קשר הדוק בקצה כף הרגל."},"ICON-2280":{"nm":"כיסוי רצועה למסכת צלילה","de":"הוא עוטף ברכות את רצועת המסכה כדי שלא תמשוך בשיער. שכבה אחת של תשומת לב שמבטלת את אותו רגע כואב בכל הסרה. מה ששכבה קטנה כזאת שומרת עליו הוא, למרבה ההפתעה, עדינות."},"ICON-2281":{"nm":"כיפת שסתום ניקוז לשנורקל","de":"גם במעשה של החזקת נשימה יש פרצה שדרכה המים דולפים בשקט. שסתום קטן אחד מפנה בעדינות את הזרם ההוא בחזרה החוצה, ושומר עד הסוף על מקום השאיפה. הים זוכר את הדקדקנות הקטנה הזאת בהכרת תודה הכי גדולה."},"ICON-2282":{"nm":"וו אחסון לסנפירים","de":"כשסנפירים תלויים מסודרים על וו בודד הנעוץ בקיר, גם על חדר הציוד המבולגן יורדת שלווה מסודרת. להניח דבר במקומו הוא ההבטחה השקטה ביותר לקראת הצלילה הבאה."},"ICON-2283":{"nm":"כרית לחיץ אף למסכת צלילה","de":"כרית בודדת שלוחצת בעדינות על האף. הודות לעדינות הקטנה הזאת שחוסמת מים מלחדור, הפנים שומרות על הבעתן גם בים הקר."},"ICON-2284":{"nm":"מגן עליון לשנורקל","de":"המגן העוטף את קצה השנורקל דוחף בשקט את המים כשגלים שוטפים מעליו. ככל שחלק עובד בלי להיראות, כך הוא תומך עמוק יותר בביטחון של נשימה בודדת."},"ICON-2285":{"nm":"רצועת מדרך נגד החלקה לסנפיר","de":"רצועה דקה מודבקת לסוליית הסנפיר. זהו קו החיכוך היחיד שקצות האצבעות נאחזים בו כדי לא להחליק על סיפון רטוב. הביטחון תמיד מתחיל בשקט במרקמים קטנים כאלה."},"ICON-2286":{"nm":"מכסה שסתום למיכל חמצן","de":"כיפה שמכסה את שסתום המיכל המלא באוויר. כדי שאבק לא יישב, כדי שדרך הנשימה תישאר נקייה. לכסות הוא לדאוג מראש, עד לנשימה הראשונה של האדם הבא."},"ICON-2287":{"nm":"כיפה לפומית רגולטור","de":"המקום שנוגע בשפתיים חייב תמיד להיות הכי נקי. כיפה בודדת זו על הפומית שומרת בשקט על שער הנשימה מפני רוח מלוחה וחול."},"ICON-2288":{"nm":"לולאת משיכה לרוכסן חליפת צלילה","de":"לולאת משיכה קצרה מחוברת לרוכסן חליפת הצלילה. תוספת מלאת תשומת לב שנוספה כדי שגם ידיים קפואות ממים קרים יוכלו למשוך אותה במכה אחת. גם בסגירת בגד טמונה מחשבה של מישהו."},"ICON-2289":{"nm":"כיפת מגן למד אוויר","de":"כיפת המגן העוטפת את הזכוכית של המד שמראה כמה אוויר נותר. כי המספרים האלה אסור שיטשטשו לעולם. ככל שהחוגה קוראת את החיים עצמם, כך היא נוקה ומכוסה ביתר קפדנות."},"ICON-2290":{"nm":"אבזם חגורת משקולות","de":"אנשים כורכים משקל סביב מותניהם כדי לרדת אל העומק. באותו רגע שבו אבזם בודד נפתח או ננעל, הבחירה בין עלייה לשקיעה מתכנסת בשקט אל קצות האצבעות."},"ICON-2291":{"nm":"רצועת פרק יד לפנס צלילה","de":"במים האפלים לגמרי, רצועה אחת קשורה לפרק כף היד אוחזת חזק בפנס. שחררי את היד והאור עדיין עוקב אחריך. לא לאבד אור קטן בתוך החושך - וזו הסיבה שזה כה מרגיע."},"ICON-2292":{"nm":"קליפס סידור לצינור נשימה","de":"קליפס קטן שאוסף צינורות מפוזרים לאחד. מנעי הסתבכות מראש והידיים לא יתעו גם ברגע דחוף. סידור הוא חסד שקט לעצמך של העתיד."},"ICON-2293":{"nm":"חיזוק בהונות לכפפת צלילה","de":"בד חיזוק שמונח על כל קצה אצבע. המקומות שמושכים חבלים ואוחזים בסלעים נשחקים תמיד ראשונים, ולכן הונחה שכבה נוספת כדי לחבק את הבלאי הזה מראש."},"ICON-2294":{"nm":"טבעת בסיס למיכל חמצן","de":"טבעת בסיס אחת שמחזיקה את המיכל הכבד זקוף. היא מחבקת בעיגול משקל שעלול היה להתמוטט, ומעניקה לו איזון. לתמוך פירושו להשאיל את הצד שלך כדי שמשהו לא ייפול."},"ICON-2295":{"nm":"כיפה לסנפיר קרש גלישה","de":"כיפה שעוטפת את הקצה החד של הסנפיר שמתחת ללוח. כדי שלא תיפצע כשתלכי בחול, היא מרדימה לזמן מה את להב הקוצץ הגלים. בזמן המנוחה, מותר לכל אחד להתקהות."},"ICON-2296":{"nm":"כיפת מגן לקצה משוט","de":"כיפת מגן ששומרת על קצה להב המשוט. היא חוסמת שריטות מסלעים מלהפריע לזרימת המים. תטפחי את הקצה, וחתירה אחת תישא אותך רחוק יותר."},"ICON-2297":{"nm":"גריפ ידית למשוט קיאק","de":"גריפ כרוך במקום שבו כף היד פוגשת את המשוט. הוא מרפד ברכות את המקום שבו נוצרו יבלות, כך שהידיים לא ילמדו לשנוא את המשוט גם בזמן חתירה במעלה הנהר."},"ICON-2298":{"nm":"קופסת פח לשעוות גלישה","de":"קופסת פח קטנה שמחזיקה גוש שעווה. הקסם שמצמיד את הרגליים ללוח נשלף תמיד מהקופסה הזאת בגודל כף יד. ההכנה של היום מתחילה בקופסה מסודרת אחת."},"ICON-2299":{"nm":"לולאת הידוק קרסול לרצועת גלישה","de":"הלולאה שמהדקת את הרצועה המחברת בין הקרסול ללוח. קשר בודד שמבטיח שלא יעזוב אותך גם כשגל גדול יסחוף אותך. חיבור הוא הבטחה להחזיק כדי שלא תיסחפי רחוק מדי."},"ICON-2300":{"nm":"פקק אוויר ללוח סאפ","de":"לוח שמתקשה כשממלאים אותו באוויר, והפקק שכולא את הנשימה הזאת. פותחים אותו והוא מתקפל שטוח, סוגרים והוא עומד על המים. בפקק קטן אחד טמון יום שלם שמתנפח ושוקע."},"ICON-2301":{"nm":"רצועת כרית מושב קיאק","de":"רצועה הקושרת את הכרית אל המושב. עבור הגב והמותניים שחותרים ישובים זמן רב, היא שומרת על הרכות במקומה כדי שלא תחליק הצידה. גם לנוחות דרוש קשר איתן."},"ICON-2302":{"nm":"פגוש לחרטום גלשן גלים","de":"פגוש העוטף את חרטום הגלשן. זהו ריפוד שנוסף לאף, המקום שסופג את מרבית ההתנגשויות, כדי שהוא יתקהה ראשון. להניח רכות במקום שמוביל היא הבטחה להשתמש בו זמן רב."},"ICON-2303":{"nm":"אבזם סגירה לתיק אטום למים","de":"אבזם שמקפלים ומהדקים פעמיים, שלוש פעמים, כדי שלא תחדור אפילו טיפה אחת. לשמור על דברים יקרים יבשים דורש תמיד עוד נגיעת יד אחת. אותו הידוק אחד ואיתן הופך לשלוות נפש."},"ICON-2304":{"nm":"קטע רשת משער פוטסל","de":"קטע בודד מן הרשת שהרעידה פעם את השער. הוא זוכר, חוט אחר חוט, את התרועות מן הרגע שבו הכדור מילא אותה. שער התגורר בכל קשר, ובכל מקום בלוי עדיין חי המשחק של אותו יום."},"ICON-2305":{"nm":"פיית משאבה לכדורגל","de":"פיית משאבה הנופחת רוח לתוך כדור מרוקן. העור שהתגלגל שטוח ומדוכא שב וקופץ ומנתר. למלא אותו מחדש פירושו להקים משחק שנעצר בחזרה על רגליו."},"ICON-2306":{"nm":"בסיס דגל פינתי","de":"בסיס המציב דגל זקוף בפינת המגרש. זהו סימון קטן של הגבול, אך בזכות אותה נקודה אחת סוף־סוף מקבל משטח האדמה צורה של אצטדיון."},"ICON-2307":{"nm":"רצועת מגן שוקיים","de":"רצועה הקושרת את מגן השוקיים אל השוק. היא אוחזת בחוזקה במקום הסופג מכות תכופות, כך שכל צעד וצעד נשאר חסר פחד גם בתוך התכתשות מחוספסת."},"ICON-2308":{"nm":"פין להחלפת פיני נעלי כדורגל","de":"פין להחלפת פין בלוי בחדש. השיניים הקטנות בקצה הנעל האוחזות בדשא. כדי לא להחליק, לפעמים צריך לבנות מחדש החל מכפות הרגליים."},"ICON-2309":{"nm":"מכסה שסתום לכדורגל","de":"מכסה שסתום קטן האוטם את נקב הנשימה של הכדור. הוא שומר על הפתח כדי שהאוויר שמולא בפנים לא ידלוף החוצה. לשמור על המתיחות דומה לכך שלא לאבד את החדות עד למשחק הבא."},"ICON-2310":{"nm":"קונוס סימון קווים","de":"קונוס המצייר קווים על הקרקע ומחלק את הדרך. עד כאן שלנו, ומשם והלאה של היריב. קונוס קטן אחד הופך חלקת אדמה מבולגנת למגרש משחקים בעל חוקים."},"ICON-2311":{"nm":"מברשת אבק לנעלי פוטסל","de":"מברשת המסלקת עפר ואבק שנתקעו בחריצי נעלי הפוטסל. כשהמשחק מסתיים, גם על הנעליים נערם עפרו של יום שלם. יד המברישה היא תודה שקטה לרגליים שרצו כה יפה."},"ICON-2312":{"nm":"מתלה כפפות שוער","de":"מתלה המייבש ומחזיק את כפפות השוער. זהו מקום שבו הידיים הרטובות מזיעה נחות לרגע, כמספר הבעיטות שנבלמו. לקראת המשחק הבא, הרטוב מתייבש והלב הקפוא מתרכך לאיטו."},"ICON-2313":{"nm":"וווי רשת לסלסלת כדורסל","de":"הווים הקטנים התולים את הרשת מן הטבעת. בזכותם משמיע הכדור את אותו רשרוש רך בעברו דרכה. הצליל הצלול ההוא של קליעה מתחיל למעשה בדיוק בווים הקטנים הללו."},"ICON-2314":{"nm":"כלי לשחרור אוויר מכדורסל","de":"כלי המוציא מעט אוויר מכדור נוקשה מדי. מתיחות יתרה הופכת את הניתור לפראי. להפחית בדיוק כפי הנדרש. כדור בעל מגע טוב תמיד נולד מאותה מידה נכונה."},"ICON-2315":{"nm":"כרית חיישן ללוח הסל","de":"כרית חיישן המודבקת מאחורי לוח הסל. היא קוראת את רגע נגיעת הכדור בבירור, במספרים. אפילו הרגע שהעין החמיצה, החישה הקטנה הזו זוכרת, כך שההכרעה הופכת הוגנת יותר."},"ICON-2316":{"nm":"קונוסי מכשולים לכדרור","de":"קונוסי מכשולים המסודרים לאורך מסלול אימוני הכדרור. תוך התפתלות ביניהם הנה והנה, גדלה זריזות הרגליים. לעמוד בדרך היא גם טוב לב, המלמד כיצד לחמוק ביתר קלות."},"ICON-2317":{"nm":"מברשת שסתום לכדורסל","de":"מברשת קטנה המנקה את חור השסתום של הכדור. אם אבק סותם אותו, המחט לא תיכנס, לכן מנקים תחילה מן הפתח הבלתי נראה. לפני שממלאים, תמיד מרוקנים ומנגבים."},"ICON-2318":{"nm":"גליל טייפ לאצבעות","de":"גליל טייפ הנכרך סביב האצבעות. הוא אוחז פרק נקוע בחוזקה, ומעניק את האומץ לתפוס שוב את הכדור. לחבוש פצע הוא הכרזה קטנה שלא תפסיק."},"ICON-2319":{"nm":"קליפס למספר גב","de":"קליפס המהדק את מספר הגב אל החולצה. במקום שמך, מספר משוטט על המגרש. באותו הידוק אחד ואיתן שלא ייפול, נכתב בבירור מי משחק היום."},"ICON-2320":{"nm":"טבעת מטרה לאימוני זריקה","de":"טבעת מטרה המוכנסת לתוך הסלסלה כדי לצמצם את היעד. היא מקטינה את השטח שהכדור חייב לחדור אליו, ומאמנת אותך לשאת החמצות. זרוק אל השער הצר ההוא מספיק זמן, וקצות אצבעותיך ילמדו דיוק בשקט."},"ICON-2321":{"nm":"מנקה סוליות לנעלי כדורסל","de":"לפני שנכנסים למגרש, כורעים ומנגבים תחילה את הסוליות. כי אינך רוצה להשאיר אפילו החלקה אחת על רצפת העץ. הנח את הצעד הראשון עם קצות אצבעות נקיים, וה\"אתה\" של היום איתן מעט יותר מזה של אתמול."},"ICON-2322":{"nm":"וו מתיחת רשת כדורעף","de":"מתיחות אינה נראית לעין. רק ברגע שהוו מותח את החוט עד קצהו ועוצר, מחלקת הרשת את המגרש לשניים במרחק כף יד של מתח. שיווי משקל המוחזק ביד בלתי נראית הוא זה שמעיר את המשחק."},"ICON-2323":{"nm":"קליפס קיבוע אנטנה","de":"האנטנה שהתנדנדה שוב ושוב ברוח ניצבת ישרה בקליפס אחד. דבר קטן העוצר תנודה גדולה. גם היד המהדקת בשקט כבל בודד מאחורי הקלעים פועלת בדיוק במידה כזו של לב."},"ICON-2324":{"nm":"מתלה לאפודת ליברו","de":"אפודת הליברו, בצבע שונה, תלויה על הקיר וממתינה למשחק הבא. אינה זוהרת, אך שמה נושא את המגרש כולו: הליברו. במקום הנמוך ביותר נמצאות העיניים הרואות הכי רחוק."},"ICON-2325":{"nm":"כיס למגני ברכיים","de":"ככל שמתגלגלים יותר על הרצפה, כך הברכיים נחבטות לעתים תכופות יותר. הכיס הקטן הזה, המאחסן בקפידה את המגנים, יודע: רק מי שלמד תחילה כיצד ליפול היטב, בסופו של דבר מרחיף הכי רחוק."},"ICON-2326":{"nm":"מד לחץ לכדורעף","de":"אי אפשר לדעת בנקישת אצבע קלה. מחט המד רועדת בעדינות ומצביעה על סימון אחד. למדוד את נשימת הכדור היא הכפתור הראשון של המשחק. מלחץ כן נולד מסלול כן."},"ICON-2327":{"nm":"סרט קווי משחק כדור חבטות","de":"עיגול בודד שצויר בטייפ על אדמת המגרש. פנימו וחיצוניותו מחלקים יקום שלם של תפיסת ידיים לחצי יום. היד שציירה את הקו יודעת: החוקים הם עצמם ראשית המשחק."},"ICON-2328":{"nm":"תושבת שריקת שופט","de":"כשקול השריקה החדה משתתק, היא מונחת שוב בשקט למקומה על התושבת. המקום השומע את נשימת השופט מקרוב ביותר. הגינות מתחילה תמיד במלאכה הקטנה של שמירת מקום."},"ICON-2329":{"nm":"מטרת קיר לאימוני מסירה","de":"בשחר שאין בו איש לקבל, מרימים את קצות האצבעות אלפי פעמים אל עבר המטרה שעל הקיר. הקיר הוא החבר הסלחן ביותר. הכדור החוזר מרים בחזרה את מי שהתעייף."},"ICON-2330":{"nm":"מוט מדידת גובה רשת","de":"אם הרשת נמוכה אפילו ברוחב אצבע אחת, המשחק סוטה מדרכו. ברגע שמרימים את מוט המדידה, ההגינות הופכת לא למספר אלא להרגל יומיומי. דיוק בלתי נראה שומר על המגרש."},"ICON-2331":{"nm":"פין זווית לבלוקי זינוק","de":"מן העמידה הכפופה, הזווית שבה נוגעות האצבעות בבלוק, אותה מעלה אחת מכריעה את הזינוק. בפין בודד מקבעים את הבלוק ומיישבים את הנשימה. תנוחת ההתחלה מלווה בשקט עד קו הסיום."},"ICON-2332":{"nm":"דגלון מספר מסלול","de":"דגלון קטן הנעוץ בכל מסלול מניף את מספרו ברוח. כולם רצים באותו כיוון, אך לכל אחד נתיב נפרד משלו. המסלול מכיל בבת אחת שיתוף לצד שוני."},"ICON-2333":{"nm":"פקק קצה שרביט שליחים","de":"לקראת הרגע שיגע ביד הרץ האחרון, מעגל פקק הקצה את הפינות. במרוץ שליחים, היקר ביותר אינו המהירות אלא היד המושטת לבא בתור."},"ICON-2334":{"nm":"מתלה לסרט מדידת שיאים","de":"תולים על הקיר את סרט המדידה שרשם את התוצאות, כדי שלא יסתבך. זהו המקום שבו המרחק של אתמול ושל היום תלויים זה לצד זה. הצמיחה מגיעה תמיד תחילה כהפרש קטן במספרים."},"ICON-2335":{"nm":"קונוס סימון עקומת מסלול","de":"קונוס קטן המונח בפנים העקומה מגלה את כוונת הדרך. אל תחתוך פנימה יותר מדי, ואל תתפזר החוצה יותר מדי. מי שמסתובב היטב, בסוף מוביל ראשון."},"ICON-2336":{"nm":"קליפס לסרט קו סיום","de":"את הסרט שייגע ראשון בחזה, הקליפס אוחז מתוח וממתין. חוט קיים כדי להיקרע. הוא סובל את הרוח יום שלם למען שנייה אחת בודדת של מישהו."},"ICON-2337":{"nm":"כיסוי אקדח זינוק","de":"עד שנשמע קול הפיצוץ של האות, ישן קנה האקדח מתחת לכיסוי. כלי המחזיק בתוכו את קול ההתחלה. ככל שהדממה עמוקה יותר, כך הד היריה הראשונה נישא רחוק יותר."},"ICON-2338":{"nm":"פין כוונון גובה משוכה","de":"בכל פעם שמעלים את הגובה עוד שלב, גם מקום הפין זז בעקבותיו. גם הפחד גדל בדיוק באותה מידה. ובכל זאת הרגליים אומדות בכל פעם נקודה מעט גבוהה יותר וממשיכות לרוץ."},"ICON-2339":{"nm":"חוגה לספירת הקפות","de":"כשמאבדים ספירה כמה הקפות נותרו, מסובבים את החוגה שלב אחד. הקליק הקטן של מספר מתכווץ מזרים כוח חדש לרגליים. היד הסופרת את המרחק שנותר שומרת על הקצב."},"ICON-2340":{"nm":"מעמד אחסון למוט קפיצה","de":"מוט ארוך ומתנדנד זקוק למקום משלו להישען עליו. מכיוון שזהו כלי שחייב להתכופף כדי לזנק, מעמידים אותו בזהירות יתרה. גמישות שמורה היטב מכילה בתוכה את הקפיצה הגבוהה ביותר."},"ICON-2341":{"nm":"מגרפת יישור בור חול","de":"לאיטו מגרפים אפילו את עקבות הרגליים שהותיר הספורטאי הקודם. בור החול משתטח מחדש בכל סבב, כמו בפעם הראשונה. היד המוחקת עקבות למען קפיצתו של מישהו נמצאת שם, שקטה ונאמנה."},"ICON-2342":{"nm":"רצועת סימון מרחק ריצת התארגנות","de":"צעד אחד חסר לא יעשה זאת, ואף צעד אחד עודף לא יעשה זאת. רצועת סימון המרחק על הקרקע מגלה בכנות היכן לנעוץ את כף הרגל. ריצת התארגנות טובה אינה תאוות בצע פזיזה, אלא תוצאה של חישוב מיושב דעת."},"ICON-2343":{"nm":"אחיזה לדיסקוס","de":"אם האצבעות מחליקות, הזריקה כבר נזרקה עוד לפני שנזרקה. המרקם המחוספס של האחיזה העוטפת את הדיסקוס בולם את הסיבוב. תזמון השחרור מתחיל תמיד בתחושת האחיזה."},"ICON-2344":{"nm":"טבעת עריסה לכדור ברזל","de":"טבעת עריסה מחזיקה בשקט את כדור הברזל הכבד כדי שלא יתגלגל. קן קטן השומר על הדממה רגע לפני הזריקה. ככל שהכוח נפיץ יותר, כך מקום המנוחה שלו חייב להיות איתן יותר."},"ICON-2345":{"nm":"מכסה מגן לחוד כידון","de":"מכסה החופה על חוד הכידון החד עוטף אותו בדממה רכה. כשכלי שנועד לעוף רחוק שוכב שקט ודומם, האיום מתורבת באדיבות. גם באחסון שוכנת בטיחות."},"ICON-2346":{"nm":"תפס תמיכה למוט קפיצה לגובה","de":"כדי שהמוט הרוחבי לא ייפול גם במגע קל, אוחז בו התפס באיזון נפלא. המקום האחראי על אותו קו רועד שבין מעבר ללא מעבר. ההגינות שוכנת בפרטים הקטנים."},"ICON-2347":{"nm":"עוגן פינת מזרן נחיתה","de":"אם פינת מזרן הנחיתה מתרוממת, מישהו עלול להיפגע. העוגן לוחץ את ארבע הפינות בחוזקה. כדי שהגוף שעף הכי גבוה ינחת הכי בטוח, הוא תומך בו בלי שייראה."},"ICON-2348":{"nm":"סרט תיחום מעגל זריקה","de":"גבול מקום הזריקה מסומן בקו טייפ בודד. בין אם דורכים על הקו ובין אם לא, תוצאה חיה או מתה. הקו הדק היחיד שבו נפגשים חופש וחוקים - הבטחה."},"ICON-2349":{"nm":"רגל גומי לקורת שיווי משקל","de":"כדי שקורת שיווי המשקל הצרה לא תתנדנד, רגל הגומי נושכת את הרצפה בחוזקה. שיווי המשקל חסר הרעד שמתגלה מעליה נוצר, למעשה, על ידי איתנות בלתי נראית שמתחת."},"ICON-2350":{"nm":"כריכה לאחיזת מתח","de":"כדי שכף היד לא תחליק, כורכים כריכה על אחיזת המתח. סוד הסיבוב המסתחרר אינו טמון בברק אלא ביד האוחזת בחוזקה. הזיעה שנטפה על המזרן יודעת זאת."},"ICON-2351":{"nm":"תפס גובה לרצועות טבעות","de":"אם גובה שתי הרצועות שונה אף במרחק כף יד, התרגיל קורס. התפס אוחז בשקט את שיווי המשקל הזה. רק מעל גובה מותאם בדיוק מתחילה סוף־סוף התעופה החופשית."},"ICON-2352":{"nm":"כיסוי ידית לסוס קפיצה","de":"הכיסוי העוטף את הידית מונע יבלות בכף היד. מתחת לתרגיל המסתובב והמסתחרר מסתתרת יד ששפשפה והחלימה אינספור פעמים. הגנה היא הבטחה עדינה כלפי האימון הבא."},"ICON-2353":{"nm":"פין מרווח למקבילי בר שונה","de":"את המרווח בין שני המוטות מכוונים בדיוק בעזרת פין. החלל הריק שבו יעבור הגוף הופך לבמה. קצות האצבעות יודעות ראשונות: מעל מרחק מדויק נולדת הקפיצה הנועזת ביותר."},"ICON-2354":{"nm":"מכסה קפיץ לקרש קפיצה","de":"ברגע שדוחפים ברגל את הקרש, הקפיץ דוחף את הגוף השמימה. המכסה עוטף בחוזקה את כוח הניתור ההוא. ריצת ההתארגנות הקצרה ביותר יוצרת את שהות האוויר הארוכה ביותר."},"ICON-2355":{"nm":"שקית אבקת מגנזיום","de":"האבקה הלבנה הנמרחת על הידיים היא קמע קטן המוחק החלקה. הטקס הקצר של טבילת היד בשקית והוצאתה מרגיע את הפחד. גם המתח, בסופו של דבר, מתורבת בקצות האצבעות."},"ICON-2356":{"nm":"כריכת סרט אימון שורש כף היד","de":"כשכורכים סרט סביב שורש כף היד, מהדקים יחד גם את חוטי הלב. להחזיק מראש פרק שעמד לרעוד. שורש כף יד אחד קשור היטב מתיר בשקט סיבוב נועז יותר."},"ICON-2357":{"nm":"לולאת ביטחון לטרפז אווירי","de":"רגע לפני שהגוף מוטח אל תוך האוויר, לולאת הביטחון הופכת ליד בלתי נראית. רק כשחשש הנפילה נעלם אפשר לעוף הכי רחוק. אמון משלים את התעופה."},"ICON-2358":{"nm":"מכסה קופסת שימור כדורי טניס","de":"מתחת למכסה האוטם את פי הקופסה, כדורים חדשים ישנים כשהם אוחזים בלחץ. הפצפוץ הקטן של פתיחת פחית מעיר את התרגשות המשחק. איטום הוא הבטחה השומרת על טריות."},"ICON-2359":{"nm":"מהדק מתח למיתרי מחבט","de":"המהדק נושך את מתיחות המיתר בחוזקה ואינו מרפה עד הסוף. כי מתח מיתר בודד קובע את קפיצת הכדור. אותו מגע בלתי נראה מתחיל במהדק הקטן הזה."},"ICON-2360":{"nm":"מטאטא קווים למגרש טניס","de":"כשהמשחק מסתיים, מטאטאים לאיטם לאורך הקווים הלבנים של המגרש. מסלקים את אבק העפר והקווים מתבהרים שוב. לסלול את הדרך למשחק הבא - הטיפול האחרון ההוא מחייה את המגרש."},"ICON-2361":{"nm":"סרט מגן לראש מחבט","de":"כריכה אחת סביב מסגרת המחבט, וגם התנגשות מחוספסת נקלטת בעיגול רך. אני יודע שהקצה הוא המקום הראשון שנשחק. מכיוון שחלקי לקחת על עצמי את הבלייה במקומך, גם היום אני עומד בקצה הרחוק ביותר."},"ICON-2362":{"nm":"שבב טמפרטורה למיזוג אוויר","de":"את הרוח הקרה של השחר הפורצת פנימה עם פתיחת הדלת, שבב בגודל כף יד קורא לפני כל אדם. לחוש בה עוד לפני שהאף מצטנן - זו הברכה השקטה ביותר הפותחת יום באולם ספורט ריק."},"ICON-2363":{"nm":"לוח דריכה לקו בסיס","de":"לספורטאי המהסס היכן להניח את קצה הרגל, מספיק קו בודד המצויר על הקרקע. הקו שאסור לחצות אותו הופך בעצמו לקו הזינוק לקפיצה הרחוקה ביותר, כך אומר לוח הדריכה בלי מילים."},"ICON-2364":{"nm":"מתלה סל כדורי טניס","de":"הוא מכיל עשרות כדורים בלגימה אחת ואינו מפיל אף אחד מהם. לאסוף את המפוזר על המגרש ולמסור אותו לאימון הבא - יד עסוקה בשקט בפינה, תלויה כאן גם היום."},"ICON-2365":{"nm":"פקק קצה ידית מחבט","de":"ברגע שמתקינים אותו בנקישה על קצה הידית, המחבט מתמצא סוף־סוף בכף היד. פקק קטן אחד מפריד בין החלקה לביטחון. רק כשקצה הידית סגור היטב, הסווינג הראשון הופך איתן."},"ICON-2366":{"nm":"קליפס מגבת לצד המגרש","de":"גם כשהרוח נושבת בעוצמה, הוא נועל את פיו ומחזיק מעמד לצד המגרש, כדי שהמגבת שנסחטה בקפידה לא תעוף. גם בשמירה על הפסקת נשימה קצרה, נגעו בה קצות אצבעות קפדניות של מישהו."},"ICON-2367":{"nm":"מלקחיים ליישור נוצות מיטלון","de":"נוצה אחת מקומטת מספיקה כדי לערער את התעופה. יישרו בעדינות את הכנף המקומטת, והמיטלון מתכונן לעוף ישר שוב. להגיע רחוק תמיד מתחיל בטיפוח קטן כזה."},"ICON-2368":{"nm":"פקק שפופרת מיטלונים","de":"כדי שהמיטלונים המסודרים בפנים לא ירכו, אוטמים את קצה השפופרת בחוזקה. ידעתי מספיק זמן שנגיעת לחות אחת מכופפת נוצה. לאחסן היטב הוא כבר חלק מהמשחק עצמו."},"ICON-2369":{"nm":"משטח מנוחה לכדור פינג פונג","de":"הכדור הקטן שהתגלגל בעדינות עוצר לנשום רגע מעליי. להעמיד אותו בשקט כדי שלא יידרדר משם - זוהי אדיבות בצורה העגולה ביותר, מוגשת לצד שולחן הפינג פונג."},"ICON-2370":{"nm":"גלגלת גומי למחבט טניס שולחן","de":"כשמגלגלים בעדינות את הגלגלת על פני הגומי, אבק ישן מתרומם והדביקות שבה. הסיבוב חייב לחיות כדי שהכדור יתעקל. מצבו של המחבט היום מתעורר מטיפול אחד עדין וחד זה."},"ICON-2371":{"nm":"מוט מדידת גובה רשת","de":"אם הרשת גבוהה אפילו ברוחב כף יד אחת, מרקם המשחק משתנה. אנשים שסירבו עד הסוף לבטוח בעין מביאים אותי אליה. הגינות, כך מסתבר, מגיעה רק מגובה שנמדד בקפידה על פי הכלל."},"ICON-2372":{"nm":"שבב מדידת מהירות מיטלון","de":"את מהירותו של המיטלון החוצה את האוויר, אני מחשב בשקט. כשהמהירות שהייתה בלתי נראית מתיישבת למספר ברור, המילה הבאה של המאמן נעשית ברורה עוד יותר. זוהי מלאכת הפיכת תחושה לעובדה."},"ICON-2373":{"nm":"קפסולת אחסון לכדורי פינג פונג","de":"מניחים כדור עגול בעדינות בתוך הקפסולה, ושריטות ואבק נסוגים הרחק. באיחול שיהיה בשלום עד המשחק הבא, זהו הלב המעניק חדר קטן שלם."},"ICON-2374":{"nm":"מתלה מיתרים למחבט בדמינטון","de":"תולים את המיתרים שהתרופפו בסדר, והיד הבאה בתור לא תגשש באפלה. סידור הוא, בסופו של דבר, כמו פתק אדיב שכותבים מראש לעצמך של מחר. היום מקל על המחר."},"ICON-2375":{"nm":"סרט מגן לשפת מחבט טניס שולחן","de":"את הקצה שבו נוטה הגומי להתרומם, אני מחבק בשקט בקו אחד. אם השפה נפתחת, אפילו מרקם הכדור מתערער. לשמור על הקצה הופך בסופו של דבר לשמירה על נקודה אחת."},"ICON-2376":{"nm":"שקית חימום לכדור סקווש","de":"כדור קר כמעט אינו מנתר. לפני המשחק, שקית המחממת ומחבקת אותו בחום כמו כף יד. אותה חמימות קטנה המועברת אל היד קובעת מראש את הנשימה והקצב של סיבוב שלם."},"ICON-2377":{"nm":"קליפס רשת ללקרוס","de":"כשקשר ברשת עומד להתרופף בשקט, אני נושך אותה תפר בודד בלי מילה. הרשת חייבת להיות מתוחה כדי שהכדור יישאר. הנה היד המחזיקה את המשחק כולו יחד ממקום בלתי נראה."},"ICON-2378":{"nm":"סרט מגן לקצה מחבט סקווש","de":"ככל שמנפנפים בעוצמה רבה יותר לעבר הקיר, המחבט בוכה תחילה מקצהו. עטפו בעדינות את הקצה הבוכה ההוא, והוא ישחק לצדך עונה נוספת. מי שיודע לחסוך בקצה, בסופו של דבר אוחז במחבט זמן רב."},"ICON-2379":{"nm":"כיסוי להב מקל הוקי","de":"כשמלבישים כיסוי על הלהב החד, סוף־סוף גם התיק וגם קצות האצבעות נרגעים. להרדים בשקט דבר מסוכן - זוהי הנימוס העתיק שמקפידים עליו ראשון בעת אריזת מקל."},"ICON-2380":{"nm":"מטלית הברקה לכדור קריקט","de":"כשמשפשפים את הכדור האדום במטלית, צד אחד אוחז באור כמו מראה. הבולר יודע בתחושת קצות האצבעות שהכדור מתעקל כשהברק חי. גם בליטוש קפדני שוכנת אסטרטגיה שקטה."},"ICON-2381":{"nm":"מכסה שפופרת אחסון לכדורי לקרוס","de":"כדי שהכדורים הקשים לא יתגלגלו כרצונם, אוטמים את פי השפופרת בחוזקה. לאסוף בעדינות דברים הנוטים להתפזר למקום אחד - יסודות הניהול תמיד קטנים כאלה."},"ICON-2382":{"nm":"פיסת מטרה לקיר סקווש","de":"מטרה קטנה הנטועה בקיר מכנסת את עיניו המתנדנדות של הספורטאי לנקודה אחת. הנקודה היחידה המורה היכן לכוון - אפילו אותו קיר רחב מצטמצם לפני פיסה קטנה זו למטרה ברורה."},"ICON-2383":{"nm":"שרוול אחיזה למקל הוקי","de":"מעבירים את האחיזה המוכרת ליד אל מקל חדש וזר, וברגע ההוא הופך הכלי לשלך בבת אחת. שרוול קטן המאפשר להלביש מיד היכרות - זהו קיצור הדרך אל ההסתגלות."},"ICON-2384":{"nm":"מתלה רשת לשער מגרש","de":"רק כשתולים רשת על השער, הופך גול לגול באמת. תמיד הרשת היא זו שהחזיקה עד הסוף את הרגע הקצר שבו הכדור מילא אותה. במקום הקולט את צורת התרועות הפורצות, אני נמצא."},"ICON-2385":{"nm":"כיסוי להב מחליקיים","de":"עם הלהב חשוף, אי אפשר לבטוח באף צעד מחוץ לקרח. כשעוזבים את הקרח, אנא הלבישו אותי. להרדים בשקט את החדות היא גם נימוס ישן שסקטרים שומרים עליו זה זמן רב."},"ICON-2386":{"nm":"מתלה שרוכי מגפי החלקה","de":"את השרוכים הארוכים של המגפיים שהוסרו, תולים בסדר, שרוך אחר שרוך. שרוכים שהותרו כדי שלא יסתבכו פותחים בחלקה את הקרח בפעם הבאה. הסיום של היום הופך בכך להכנה למחר."},"ICON-2387":{"nm":"מגבת ללהב מחליקיים","de":"על להב שזה עתה עזב את הקרח, נאספות טיפות מים קטנות. נגבו את הלחות ההיא בעדינות והחלודה חולפת על פניה. לאסוף בשקט את העקבות שהותיר הקור, זה יומי."},"ICON-2388":{"nm":"כרית קרסול למגפי החלקה","de":"קרסול שמתנדנד פעם אחת מפיל את כל ההחלקה. כרית העוטפת אותו בחוזקה ומחזיקה את הדריכה. שיווי המשקל האלגנטי הזה על הקרח תמיד מתחיל ראשון במקום בלתי נראה."},"ICON-2389":{"nm":"שקית למגני להב מחליקיים","de":"שקית קטנה בפינת התיק לאחסן בה בקפידה את מגני הלהב. ההרגל לארוז את הנחוץ בלי לדלג על דבר שומר על הציוד חי לאורך זמן רב. תיק מסודר הוא הסצנה הראשונה של החלקה טובה."},"ICON-2390":{"nm":"קליפס לרפידת מגפי החלקה","de":"כדי שהרפידה בתוך המגף לא תחליק בשקט החוצה, היא אוחזת בחוזקה מתחת לרגל. אם המקום שדורכים עליו סוטה, גם הקפיצה סוטה בעקבותיו. היד האוחזת במקום הנמוך ביותר, בסוף מסייעת לקפיצה הגבוהה ביותר."},"ICON-2391":{"nm":"לולאת סגירה לכיסוי להב מחליקיים","de":"כדי שהכיסוי לא יחליק החוצה, נועלים אותו בחוזקה בלולאה. אני יודע שהגנה רופפת אינה, בסופו של דבר, הגנה כלל. לולאה אחת סגורה היטב שומרת על אותו להב עד הסוף."},"ICON-2392":{"nm":"מכסה הידוק שרוכים למגפי החלקה","de":"מותחים את השרוכים בחוזקה ונועלים אותם במכסה, ומעתה לא יתרופפו עוד לעולם. להדק בקפידה מקצה הבוהן ללא רווח - זהו הקשר האיתן ביותר שקושרים לפני הצעד הראשון על הקרח."},"ICON-2393":{"nm":"מטלית ייבוש ללהב מחליקיים","de":"מלהב שזה עתה סיים החלקה, אוספים בעדינות את הלחות שנקוותה. אני יודע שלהב שנותר רטוב בוכה. רק להב שיובש ברכות מצייר בבירור את העקומה הבאה על הקרח."},"ICON-2394":{"nm":"מכסה ידית מקל סקי","de":"כשעוטפים בעדינות את קצה ידית המקל, כף היד האוחזת נעשית נוחה יותר. הכוח החוצה את שדה השלג נובע, בסוף, מאותו מקום שאחוז בחוזקה. מכסה קטן אחד תומך בגלישה ארוכה עד הסוף."},"ICON-2395":{"nm":"פין קשירה לסנובורד","de":"ברגע שהפין הקטן המחבר בין הלוח לרגל נשמט, ההר שלפניך נעצר. חלק שקשה להבחין בו אך יש לבדוק ראשון - חיבור איתן זה הופך לחירות על פני השלג."},"ICON-2396":{"nm":"מלקחיים מגנים לקצה סקי","de":"כדי שהקצה החד לא ישרוט את פנים התיק, נושכים בעדינות את הקצה. להרגיע את החדות לתרדמה - זהו הסיום האדיב שמעניקים לאחר ירידה טובה מן ההר."},"ICON-2397":{"nm":"מגן חרטום לסנובורד","de":"כשעוטפים היטב את חרטום הלוח, גם התנגשות ישירה מתפזרת ברכות. לשמור בשקט על המקום הפוגע ראשון - האומץ להתמודד עם ירידה תלולה מתחיל בדיוק כאן."},"ICON-2398":{"nm":"כיסוי אבזם למגפי סקי","de":"כדי שהאבזם לא ייפגע בהתנגשות עם השלג הקר, מכסים אותו בעדינות. עוד נעילה אחת השומרת על מנגנון הנעילה - כיסוי קטן זה מאריך בשקט את עונת המגף מעט יותר."},"ICON-2399":{"nm":"לולאת רצועת אבטחה לסנובורד","de":"כדי שהלוח לא יברח רחוק גם אם ייחלץ מהיד, אני מחבר קרסול ולוח בחוט אחד. כדי שגם אם תאבד את האחיזה, לא תאבד אותו לצמיתות - לולאת הרגעה שקטה התלויה בקצה חוט ארוך."},"ICON-2400":{"nm":"קצה מגרד לסוליית סקי","de":"את השעווה הישנה שהתקשתה על הסוליה, גוררים החוצה בחלקות. רק בסילוק היסודי של הישן מתעוררת החלקה חדשה. סוליה שטופלה בקפידה פותחת את שדה השלג הבא מהר עוד יותר."},"ICON-2401":{"nm":"פגוש לוח סנובורד","de":"לפני שהלוח חותך את השלג, קצה האף הוא הראשון לגעת בעולם. כל פגיעה נקלטת קודם כול בגומי הקטן הזה. במקום הכי קדמי, הוא נשחק בלי להתפאר בכך - הגלישה של מישהו מחליקה מעל המסירות הקהה הזו."},"ICON-2402":{"nm":"טבעת סל מקל הסקי","de":"ברגע שהמקל עומד לשקוע עמוק בשלג, הטבעת העגולה הזאת ממששת את הקרקע במקומו. חישוק ששומר בשקט על צעד שכמעט מעד. גם בלי שרואים אותו, הוא נשאר קרוב כמו יד שמונעת ממך להחליק."},"ICON-2403":{"nm":"מכסה מברשת שעוות הלהב","de":"כשהטיפוח מסתיים, הוא מכסה בעדינות את הזיפים לפני שהאבקה מתייבשת. חותם את הרכות של היום כדי שלא סיב אחד יזוז ממקומו. כדי שכשתפתח שוב בפעם הבאה, המסירות של אתמול תחכה לך בדיוק כפי שהייתה."},"ICON-2404":{"nm":"וו תלייה לאטמי אוזניים","de":"זוכר? את אטמי האוזניים שנשכחו לרגע ליד התיק כשהגיע האביב. ובכל זאת, בלילה שבו מגיעה הבשורה על השלג הראשון, הם הראשונים שנקראים בשמם. יש מקום מיוחד לתלות בו את העונה, והוו הקטן הזה לא שוכח את ההבטחה הזו."},"ICON-2405":{"nm":"נרתיק אבן השחזה","de":"כדי להשחיז סכין, צריך קודם להרטיב את האבן - סדר שחלחל כמו מגע ידה של סבתא. גם כלי שמרסן קהות זקוק למקום מנוחה משלו, ולכן הבית הקטן הזה מחבק את האבן וממתין לטיפוח הבא."},"ICON-2406":{"nm":"כיס גוש שעווה","de":"החומר שיוצר גלישה מבריקה ישן דווקא בתוכו, מגובש היטב. כובד המכיל גוש קשה. הגלישה תמיד משתחררת מהמשקל השקט הזה ומתפשטת על פני שדה השלג."},"ICON-2407":{"nm":"טבעת כיס מחמם ידיים","de":"בטיול חורפי, המקום שהאצבעות מגששות אחריו ראשון בתוך הכיס. הוא מעניק בית קבוע לחמימות הקטנה שמפשירה ידיים קפואות. ככל שהיום קר יותר, כך הטבעת הקטנה הזאת נעשית עדינה יותר."},"ICON-2408":{"nm":"משטח השחזה לקצה הלהב","de":"אם הוא רועד, הלהב יוצא עקום, ולכן הוא מייצב את עצמו קודם בחוזקה. משטח שלא זז לרגע, כדי לשאת באחריות לדיוק של מישהו אחר. קצה סכין ישר של מישהו עומד על השקט הזה."},"ICON-2409":{"nm":"קליפס לצעיף צוואר חורפי","de":"בדרך לבית הספר ברוח קרה, ברגע שהצעיף עומד להחליק - קליק, אל הצווארון. גם חום צריך לשמור על מקומו כדי לחמם באמת. קול קטן אחד שומר על החום של הבוקר."},"ICON-2410":{"nm":"כיסוי למגהץ שעווה","de":"בזמן שהמשטח שעבד כה חם מתקרר, בד אחד שומר עליו בשקט מפני האבק. כלי אחד דואג לכלי שהכין את הגלישה. כך הדאגה ממשיכה בשקט."},"ICON-2411":{"nm":"מכסה עט שמן הלהב","de":"אם הוא נשאר פתוח וקצה העט מתייבש, אי אפשר למשוך את הקו הבא. לכן לסגור זה בעצם לפתוח את הבא - המכסה הקטן הזה חותם את הלחות בקצה, ומבטיח מראש את המשיכה של מחר."},"ICON-2412":{"nm":"ראש פומפון עידוד","de":"מאות פתילים יוצאים מנקודה אחת זו, ומתפזרים יחד לפי הקצב. הפאר של הנדנוד תמיד מתחיל ממקום שנקשר בחוזקה. מתחת לבמה, הקשר הראשון שגורם לקהל לגלוש כמו גל."},"ICON-2413":{"nm":"רצועת יד למקל האור","de":"אחרי שעתיים של תרועות, ברגע שהמקל כמעט נשמט, הרצועה הזאת מחזירה אותו אל היד. הרצון לא לאבד אותו גם כשהוא נופל. הדאגה העדינה הזו יצרה טבעת סביב פרק כף היד."},"ICON-2414":{"nm":"תפס קיפול לכרית קהל","de":"לקום בקפיצה ולשבת שוב, עשרות פעמים בזמן העידוד. בינתיים, התפס הקטן הזה מקפל בקפידה את הכרית ושומר על המקום. גם בקהל הנרגש טמון מגע שדואג למקום של מישהו."},"ICON-2415":{"nm":"טבעת בנדנת עידוד","de":"ביום שבו אותה דוגמה מתפרשת על פני כל הקהל, בד אחד קושר עשרות אלפי לבבות לצבע אחד. הנקודה הראשונה שממנה מתחיל הגל הזה היא הטבעת הקטנה הזאת - המקום שבו עידוד בודד הופך ל'אנחנו'."},"ICON-2416":{"nm":"חצי מחיאת כפיים לעידוד","de":"כשמוחאים לבד, זה קול קטן; כשמתאספים בקהל, זה הופך לגל. החצי היחיד שיודע בכנות הכי גדולה שהוא מצלצל רק כשהוא פוגש את חברו. ברגע שמחיאת הכף שלך פוגשת את שלי, העידוד גדל."},"ICON-2417":{"nm":"כיסוי פינה לשלט עידוד","de":"הוא עוטף את הפינה החדה בעיגול, כדי שהיושב לצידך לא ייפגע. גם בלב הבוער בנפנוף נלהב טמונה התחשבות זה בזה. עידוד נהיה חם יותר דווקא במקום המעוגל הזה."},"ICON-2418":{"nm":"מעמד למוט סרט עידוד","de":"גם ברגע שההתנופפות פוסקת, המוט עומד זקוף וממתין לתרועה הבאה. מקום שנח לרגע בשקט כדי שיוכל להתנופף שוב. בין תרועה לתרועה, שקט קצר שבו הסרט תופס אוויר."},"ICON-2419":{"nm":"מניפת קול לעידוד","de":"כדי שקריאה של אדם אחד תגיע עד קצה הבמה, צורת המניפה מצמצמת את מסלול הצליל. פה ששוקל תמיד את דרך ההעברה יותר משהוא שוקל את גודל הלב. צורה שנוצרה מהכמיהה להגיע רחוק יותר."},"ICON-2420":{"nm":"נרתיק סיכת גב לתג","de":"לפני שהוא מוצמד לחזה ואחרי שמסירים אותו, מנוחת התג מתחילה ומסתיימת כאן. בית קטן שמניח לישון בבטחה את הסיכה החדה שבגב. גם נקודה נוצצת זקוקה למקום לשכב ולנוח בו לרגע."},"ICON-2421":{"nm":"לוחית מספר ללוח התוצאות","de":"היא נושאת בתוכה את המסירות של תקופה שבה כל שער הוחלף ביד. לפני העידן הדיגיטלי, התוצאה נחרתה משבצת אחר משבצת בקצות אצבעות אדם. לוחית שבה גם מספר בודד החזיק בתוכו התרגשות של מישהו."},"ICON-2422":{"nm":"כלי מגנט ללוח הטקטי","de":"בעקבות קצות אצבעותיו של המאמן, ההגנה וההתקפה מחליפות מקום. כל תמונה שבראש לפני המשחק מצוירת קודם בתזוזת הנקודות הקטנות הללו. התוצאה מתרחשת פעם אחת מראש, על גבי הלוח."},"ICON-2423":{"nm":"מצחיית סינוור ללוח התוצאות","de":"כדי שהמספרים המסנוורים לא יטשטשו את מבטו של השחקן, המצחייה חותכת את האור. גם הבהירות צריכה לפעמים להיות מוצלת במידה הנכונה כדי למלא את תפקידה. במקום הכי בהיר, הצל שעובד הכי בשקט."},"ICON-2424":{"nm":"טבעת היפוך תוצאה","de":"בכל דף שמתהפך, המספר משתנה והתרועות עולות בעקבותיו. עקבות מהעידן האנלוגי, כשהתוצאות התחדשו במגע היד. תקופה שבה, לצליל הפיכת הניקוד, גם הלב התהפך יחד איתו."},"ICON-2425":{"nm":"נרתיק עט לקווי אסטרטגיה","de":"כל מסלול שמצויר על הלוח הלבן בחדר ההלבשה יוצא מהעט הזה. מארז קטן וחזק שמחבק את שרטוט המשחק. בשתיקה שלפני הקרב המכריע, המקום שמכיל הכי הרבה מילים."},"ICON-2426":{"nm":"מונה תוצאות בקליק","de":"בכל לחיצה, משבצת אחת עולה, בקליק ברור שמעלה את הספירה. כשמפקידים את המספרים באצבעות, הלב יכול לפנות כולו למשחק. קצב קטן שמקל על משא הספירה."},"ICON-2427":{"nm":"כיסוי כבלים ללוח התוצאות","de":"מאחורי האור המרהיב תמיד מסתתרים חוטים מסובכים שלא סודרו. העבודה של לכסות בעדינות את הבלגן הזה. רק כשהמקום הנסתר מסודר, המקום הנראה יכול סוף סוף להאיר."},"ICON-2428":{"nm":"מברשת מחיקה ללוח הטקטי","de":"כשסיבוב אחד מסתיים, היא מנקה את המשטח לקראת התמונה הבאה. אסטרטגיה חדשה יכולה תמיד להתחיל רק על שטח ריק. מברשת המחיקה היא, למעשה, המכחול הראשון של התוכנית הבאה."},"ICON-2429":{"nm":"קליפס לדגל הניקוד","de":"הוא נועל בשיניים דגל שעומד לעוף ברוח ולא מרפה. כדי שהבד המתנופף ישמור על מקומו. גם בעבודה של להודיע לעולם על התוצאה, נדרשת קודם יד שתחזיק חזק."},"ICON-2430":{"nm":"קליפס לחוט משרוקית השופט","de":"בשריקה אחת, המשחק נעצר וזורם שוב. קשר קטן שמהדק את הסמכות הזאת חזק אל הצוואר. עד שהמשרוקית משמיעה קול, לקשור את השקט בסדר הוא גם תפקידו של הקליפס הזה."},"ICON-2431":{"nm":"גלגלת סרט מדידה","de":"היא אוספת בחזרה לתוכה את האורך שנמדד ונפרש. מדידה היא, בסופו של דבר, חזרה על פתיחה וקיפול. ידית שמסייעת לנסיעת ההלוך-ושוב הפשוטה הזאת בלי תלונה, מסתובבת בכל פעם מאחורי הדיוק."},"ICON-2432":{"nm":"נרתיק קיפול לדגל השיפוט","de":"הדגל שהפריד בתוקף בין פנים לחוץ, כשהמשחק מסתיים, מתקפל בסדר ונח. גם האות הברור ההוא תופס אוויר לרגע לקראת הבא. גם בתקיפות יש מנוחה שקטה."},"ICON-2433":{"nm":"טבעת תלייה לשעון עצר","de":"היא תולה את הזמן הזורם במקום אחד, לא על פרק כף היד. עומדת מלכת לפני המדידה, ואז דוהרת מיד כשקוראים לה - תחנה לזמן. בית קטן לשניות, עוצר נשימה וממתין לאות ההתחלה."},"ICON-2434":{"nm":"גלגל סימון קווי מגרש","de":"בכל מקום שהוא מתגלגל, נותר שביל לבן וברור. גבולות הכללים נחרתים כך על הקרקע, סיבוב אחר סיבוב בדייקנות. לפני שהמשחק מתחיל, הגלגל שמשאיר את טביעת הרגל הראשונה על המגרש."},"ICON-2435":{"nm":"כיס כרטיסי השופט","de":"ברגע ההכרעה, הכרטיס שנשלף מהחזה ישן כאן. חדר ההמתנה של פסיקה ששותקת עד הסוף, עד שהיא מוצגת. כיס שתמיד מוכן וממתין, מקווה שלעולם לא יצטרכו לשלוף ממנו."},"ICON-2436":{"nm":"משטח למשקולת המאזניים","de":"עבודת השקילה כנה רק על רצפה שלא רועדת. משטח שנושא את המשקולת בעודו מציע את גופו שטוח ויציב. הצעד הראשון של מדידה מדויקת תמיד מתחיל ממקום שקט."},"ICON-2437":{"nm":"מקל האות לזינוק","de":"בקול אחד, כל הרגליים דוחפות את הקרקע בבת אחת. ההתחלה קצרה מאוד, אבל היד שיוצרת את הקוצר הזה רגועה יותר מכל אחד אחר. יד ששוחררת את הרעד של קו הזינוק בקליק אחד בלבד."},"ICON-2438":{"nm":"בסיס לחרוט המגרש","de":"השם אולי לא מוכר, אבל התפקיד ברור - הוא נושא בכובד את מרכז המגרש כמו במה. במרכז שבו כולם זוהרים, תמיד יש רגל אחת בלתי נראית שנושאת בשתיקה."},"ICON-2439":{"nm":"אבזם חגורת נשימה סרעפתית","de":"קול טוב לא בא מהגרון אלא מנשימה עמוקה, והמותניים יודעות זאת ראשונות. אבזם שמאפשר לכף היד לחוש את הבטן נפוחה ושוקעת. נקודת ההתחלה של שיר תמיד נמצאת מתחת לנשימה הזאת."},"ICON-2440":{"nm":"לוחית נוצה לתרגול נשימה","de":"כשהנוצה נעה בעדינות מהנשיפה, זה סימן שהנשימה יציבה. היא מעניקה צורה עדינה לנשימה הבלתי נראית, ומלמדת את יסוד השיר. תרגול שלומד בעיניים את הנשימה שלפני הצליל הראשון."},"ICON-2441":{"nm":"שעון חול לשאיפה","de":"בתוך הזכוכית, החול זורם למטה כמו נשימה. שאוף, עצור לרגע, נשוף לאט - הגרגרים סופרים במקומך את הקצב. הבט בשקט בחול הנופל בלי קול, ולפתע הנשימה המפוזרת שלך מתיישרת."},"ICON-2442":{"nm":"מעמד לתרגול לאור נר","de":"כשמדליקים את הפתילה, הקול רועד יחד עם הלהבה המרצדת. מישהו גילף בקפידה את המקום הזה כדי להחזיק לרגע את הרעד הקטן ההוא. בעובי שעוות הנר שהתקשתה והצטברה, שוקעים כאן לילות של שירה לבד."},"ICON-2443":{"nm":"רצועת כרית ללחיצת בטן","de":"במקום להניח יד על הבטן, רצועה אחת לוחצת בשקט על המקום הזה. היא נמתחת כשהנשימה גואה ומשתחררת בעדינות כשהיא מתרוקנת כולה. חבר קטן ושותק לצידך, שעוזר לגוף לזכור את הקצב קודם כול."},"ICON-2444":{"nm":"מכסה בלון להחזקת נשימה","de":"אל תנפח את הבלון בבת אחת. ארוך, לאט, דחוף עד הסוף. בזמן שאתה נושך את המכסה ומוציא את האוויר, הוא מגיע עד העומק ביותר של הריאות. שיר, בסופו של דבר, טס רחוק כמו אורך הנשימה שהחזקת."},"ICON-2445":{"nm":"ידית ליישוב הנשימה","de":"ככל שהלב רועד יותר, היד רוצה לאחוז במשהו חזק. תפוס בידית הזאת והכתפיים משתחררות למטה, השאיפה מתארכת עוד קצת. ללמוד לאחוז זה ללמוד ליישב את עצמך, כף היד יודעת זאת ראשונה."},"ICON-2446":{"nm":"טבעת רצועת רטט לבטן","de":"כשמחברים את הרצועה לטבעת, רטט עדין מתפשט אל מרכז הבטן. כוח נאסף בשקט באותו מקום בדיוק שרועד כשצוחקים בקול רם. מרכז יציב תמיד גדל כך לאט, במקום שאיש לא רואה."},"ICON-2447":{"nm":"חוגה לספירת שאיפות","de":"אחת, שתיים, שלוש - בכל פעם שהחוגה עוברת משבצת, עומק הנשימה שנשאפה נחרת בה. משבצת נוספת, ושורה נוספת בשיר. על החוגה הקטנה הזאת נרשם בשקט קיבול הריאות שנבנה היום."},"ICON-2448":{"nm":"לוחית כפית לתרגול לשון","de":"המקומות שקצה הלשון צריך לגעת בהם מסומנים בבירור על הלוחית. איך לגלגל, להקפיץ, ולעצור לרגע. מאחורי הגייה שזורמת בחלקות מסתתרים שחרים רבים שבהם הלשון שיננה את הדרך."},"ICON-2449":{"nm":"קליפס למראת צורת הפה","de":"הקליפס אוחז בעדינות בצורת הפה המשתקפת במראה. 'אה' עגולה, 'אי' נמתחת לצדדים. שיעור שקט של שניים בלבד, אני והמראה, שבו מעדנים את צורת הצליל בהתבוננות ישירה בפנים."},"ICON-2450":{"nm":"כלב ים מקורק לתרגול הגייה","de":"כלב ים קטן שגולף מקורק יושב בפינת השולחן ומקשיב להגייה. בלילות שבהם ה'ר' מחליקה שוב ושוב והרוח נופלת, עיניו העגולות של כלב הים אומרות בשקט: זה בסדר, ננסה עוד פעם אחת."},"ICON-2451":{"nm":"סיכת סימון נשימה למילות השיר","de":"איפה לנשום בתוך המילים - הסיכה הזאת אומרת לך קודם כול. תקע אותה בסוף שורה, והמקום הזה הופך לפסיק העדין של השיר. כדי לשיר בחופשיות, גם למשפט דרוש רווח קטן אחד לתפוס בו אוויר."},"ICON-2452":{"nm":"משענת סנטר לתרגול דיקציה","de":"גם תמיכה קלה בסנטר בלבד, וההגייה שעמדה להתפזר מוצאת את מקומה. דיבור ברור אינו עבודת הפה בלבד - הוא נבנה יחד על ידי הסנטר, הגרון והנשימה. משענת קטנה אחת זו מסייעת בשתיקה לאיזון העדין הזה."},"ICON-2453":{"nm":"מעמד תבנית פה לתנועות","de":"אָה, אֶה, אִי, אוֹ, אוּ - תבנית שמציבה כמות שהן את הדרכים שחמש התנועות יוצאות בהן מהפה. הנח אותה בשקט ליד המראה וכייל בה כל יום את שלד הצליל. שלד של כל שיר מתחיל, בסופו של דבר, מחמש התנועות האלה."},"ICON-2454":{"nm":"כרטיס שברי לשון","de":"כרטיס כה מסתבך, שבקריאתו הלשון נכשלת וסוף סוף פורץ צחוק. זה באמת בסדר לטעות - לטעות זה בעצם התרגול עצמו. בכל פעם שעוברים את המשפט השובב הזה, הגייה אחת נוספת מתעוררת צלולה וברורה."},"ICON-2455":{"nm":"פקק שחרור שפתיים","de":"חימום שמרעיד את השפתיים כדי להעיר פה נוקשה. נשוך את הפקק והוצא אוויר ארוך, והשפתיים הישנות משתחררות ומתרככות. חימום הכי קטן והכי עדין לפתיחת השורה הראשונה ברכות."},"ICON-2456":{"nm":"גומייה לסימון קטע במילים","de":"כורכים גומייה כדי לסמן את הקטע שתמיד נתקעים בו. בכל פעם שרואים את המקום הזה על פרק כף היד, עולה במחשבה ההר שיש לטפס עליו היום. ככל שהקטע קשה יותר, כך מסתכלים בו לעתים קרובות יותר, ושומרים אותו זמן רב יותר בלב."},"ICON-2457":{"nm":"טבעת לצעיף חימום הצוואר","de":"כדי שהגרון לא יצטרד באוויר השחר של מעבר העונות, תולים את הצעיף בחוזקה על הטבעת. רק מגרון עטוף בחום מתפרץ סוף סוף קול צלול. לשמור על הקול זה תמיד להתחיל מלהיזהר בצוואר קודם כול."},"ICON-2458":{"nm":"קצה גלגלת רטט למיתרי הקול","de":"כשקצה הגלגלת מתגלגל לאט לצד הצוואר, מיתרי הקול שישנו כל הלילה מתעוררים בעדינות. רטט קל משחרר מתח קשה, והצליל הראשון המהוסס נעשה רך יותר. מגע שמחמם את הגוף לפני השירה."},"ICON-2459":{"nm":"תחתית כוס לחימום זמזום","de":"שפתיים סגורות, מזמזמים בשקט, אוחזים בשתי כפות ידיים בכוס חמה ומהבילה והגרון מתחמם יחד איתה. זמזום נמוך מתפשט בעיגולים על התחתית. שיר מתחיל כך, מלגימה אחת של חום פושר."},"ICON-2460":{"nm":"קפסולה לאחסון סוכריות גרון","de":"לימים שבהם הגרון שוקע צרוד וגס, אוספים בשקט סוכריות בתוך הקפסולה. גלגל אחת בפה רגע לפני העלייה לבמה, והמנטה הקרירה פותחת בקרירות את הגרון החסום. נחמה קטנה למקרי חירום, שמורה בקופסה קטנה משלך בלבד."},"ICON-2461":{"nm":"כיס אדים לדחיסת גרון","de":"כורכים סביב הצוואר את הכיס שהאדים החמים חלחלו בו בעדינות, והמקומות שהתקשו מתרגול ארוך נמסים ברכות. עם החום הנעים של מגבת שחוממה זה עתה, הוא מעניק בשקט מנוחה של פעימה אחת למיתרי קול עייפים ושקועים."},"ICON-2462":{"nm":"שעון חול למנוחת מיתרי הקול","de":"את ההבטחה השקטה לא לדבר היום, גרגרים דקים סופרים בשקט. לסגור את הפה לרגע ולחסוך בקול. הזמן השקט הזה, שהוא גם הטיפול הטוב ביותר, זורם כאן לאט."},"ICON-2463":{"nm":"פקק חימום לרעד שפתיים","de":"רעד שפתיים קל שרוכב על הצלילים למעלה ולמטה. נשוך את הפקק בעדינות, והרעד הפרוע נעשה אחיד בהרבה. כלי קטן בגודל כף יד שמהדק בעדינות את הכפתור הראשון של הפקת הקול."},"ICON-2464":{"nm":"מכסה תרסיס לחות לגרון","de":"כדי שהגרון לא ייבש על במה יבשה, לוחצים על המכסה ומרססים ערפל דק. שואפים עמוק לגימה אחת של האוויר הלח, והקול היבש חוזר ומקבל ברק צלול."},"ICON-2465":{"nm":"כדור רטט לשחרור הפקת קול","de":"אוחזים בשקט בכדור הרוטט מעט על כף היד, והרטט עולה בעדינות דרך הזרוע עד הצוואר. חבר חימום עגול ואדיב שמנער ומעיר בעדינות איברי הפקה שהתקשו מתח."},"ICON-2466":{"nm":"סימון נקודה למבנה בימתי","de":"סימון קטן אחד נעוץ ברצפת הבמה. כאן המקום שלך, שם המקום שלי. כשרבים מתאספים לצייר תמונה אחת, הוא מחזיק בשקט את כולם במקומם - הבטחה בלתי נראית שאיש לא יתפזר."},"ICON-2467":{"nm":"שבב חץ למסלול תנועה","de":"שבב בצורת ראש חץ מצביע בבירור על כיוון הצעד הבא. איפה לפנות, איפה לעצור - הרצפה מודיעה קודם כדי שלא תלך לאיבוד. מסלול הוא מפה שהבהונות שיננו על ידי דריכה בלתי נספרת."},"ICON-2468":{"nm":"סיכת מרכז למבנה","de":"הנקודה היחידה שהופכת בשקט לקנה מידה כשרבים מתקבצים. סביב הסיכה הזאת נמתח עיגול, והמבנה נפתח לרווחה. גם תנועות מפוזרות מוצאות סדר משלהן ברגע שיש נקודת מרכז אחת בלבד."},"ICON-2469":{"nm":"יתד נקודת חצייה","de":"במקום שבו שני מסלולים נפגשים בנקודה אחת, נועצים יתד חזק. כדי שלא יתנגשו, כדי שלא ילכו לאיבוד זה בזה. גם ברגע החולף וקצר הנשימה של המעבר, איש לא הולך לאיבוד."},"ICON-2470":{"nm":"דגל כיוון יציאה","de":"כשההד של הצליל האחרון נמוג, יוצאים בשקט לכיוון שהדגל מצביע עליו. היציאה לא צריכה להיות מבולגנת יותר מהכניסה. גם לסיום הבמה יש כיוון שהובטח מראש."},"ICON-2471":{"nm":"קליפס סרט מדידה למרווחים","de":"מהדקים את קצה סרט המדידה חזק בקליפס, ואז זרת אחר זרת יוצאות מדויקות ללא כשל. אפילו המרווח בין אדם לאדם מיושר בקפידה, כאילו נמדד בסרגל. מראה נעים תמיד נולד מקצות אצבעות קפדניים כאלה."},"ICON-2472":{"nm":"טבעת חוט לקו יישור","de":"תולים חוט על הטבעת ומותחים אותו בקו אחד מתוח, והקו הדק הזה הופך לקנה מידה שלפיו כולם עומדים שווה בשווה. השורה נראית כה מסודרת בזכות הקו הישר והבלתי נראה הזה בלבד."},"ICON-2473":{"nm":"חתיכת קו מקווקו למסלול תנועה","de":"חתיכות שמציירות בשקט על הרצפה שביל בקו מקווקו. הולכים לאורך הסימנים החיוורים האלה ולא הולכים לאיבוד גם בחושך. תוך כדי חיבור נקודה לנקודה, צעדים מפוזרים מתמזגים לזרימה אחת."},"ICON-2474":{"nm":"נעץ רצפה לסימון עמדה","de":"נעץ שנדחף לרצפה כדי שלא תשכח את מקומך. גם בחושך מוחלט, קצות האצבעות ממששות את הבליטה הקטנה הזאת ומוצאות אותה בכל זאת. רק כשעוצרים בדיוק בנקודה ההיא, האור סוף סוף נשפך מלמעלה."},"ICON-2475":{"nm":"רצועת ריכוז לבידוד הצוואר","de":"אם הסנטר נע יחד, גם הקול רועד ומתפזר. כדי לשלוט בהזזת הצוואר בלבד בזמן שהראש נשאר יציב, כורכים את הרצועה. מאחורי תנועה שנראית חופשית לגמרי מסתתר תרגול שקט כזה של בידוד."},"ICON-2476":{"nm":"קליפס כרית לקיבוע כתפיים","de":"כדי שהכתפיים לא יתרוממו כרצונן, מקבעים בשקט את הכרית בקליפס. כדי שהגוף ידע להבחין בבירור בין מקום שצריך לנוע למקום שצריך להישאר דומם. קו מרוסן תמיד נולד ממעשים קטנים כאלה של איפוק."},"ICON-2477":{"nm":"אבזם חגורה לחישת הצלעות","de":"החגורה קוראת בשקט את המרקם הדק של הצלעות הנפתחות ונאספות מחדש. סוגרים את האבזם ותנועת הנשימה עוברת בבירור עד קצות האצבעות. הפקת קול עמוקה ויציבה נובעת מתנועת העצם הבלתי נראית הזאת."},"ICON-2478":{"nm":"מטוטלת נדנוד אגן","de":"המטוטלת מתנדנדת לאט מצד לצד, ומספרת בשקט את הקצב שהאגן מצייר. משקולת קטנה בגודל כף יד מלמדת בלי מילים איך מרכז הגוף מעביר את משקלו. שגם לנדנוד יש מרקם משלו."},"ICON-2479":{"nm":"טבעת סיבוב לפרק כף היד","de":"תולים את הטבעת על פרק כף היד ומסובבים לאט פנימה, ואז החוצה, והמפרק שהתקשה כל הלילה משתחרר ברכות. כדי שהתנועה תגיע חיה עד קצות האצבעות, פרק כף היד צריך קודם להיות גמיש. הסיבוב הקטן הזה פותח ביטוי גדול יותר."},"ICON-2480":{"nm":"חוט טבעת התנגדות לקרסול","de":"משחילים טבעת בקרסול ומותחים חוט, ובכל צעד שדורכים, התנגדות עדינה נתפסת בבהונות. ככל שדורכים בכבדות, כוח נבנה בשקט ברגליים. קפיצה קלה כנוצה תמיד עומדת על תרגול כבד כזה."},"ICON-2481":{"nm":"שק חול לריכוז הליבה","de":"רק אחרי שכורכים אותו סביב הבטן, סוף סוף יודעים איפה בדיוק נמצא מרכז הגוף. בזמן שהמשקל מושך את הכתפיים, המרכז המתנודד מוצא לאט את מקומו, ובמקום שממנו הוא הותר, נשארת יציבה זקופה אחת."},"ICON-2482":{"nm":"מכסה מוט ליישור עמוד השדרה","de":"כשמכסה קטן נוגע בגב שחי כל היום כפוף, זה מרגיש כאילו מישהו מיישר בשקט את הכתפיים. אפשר לשרוד גם כפוף, אבל לעמוד זקוף הוא אמנות עדינה שצריך ללמוד מחדש לאט."},"ICON-2483":{"nm":"כדור דיקור לשחרור שרירים","de":"לוחצים חזק על מקום קשור, ובהתחלה זה עוקצני ואז מיד נעים. כמו החום של גב יד סבתא שמשפשפת את הגב בילדות, לשחרר זה לתת לכאוב עוד קצת תוך שנשארים לצד."},"ICON-2484":{"nm":"בורג כיוונון זווית מראה","de":"אפילו סיבוב בגודל כף יד, והמראה משקפת פנים שונות לגמרי. בסיבוב בורג אחד העולם נוטה וחוזר לעמוד ישר, כך שנראה שגם להתבונן בעצמך דרוש כיוון שקט ומדויק."},"ICON-2485":{"nm":"פד ניגוב אדים למראה","de":"לפני מראה שמעורפלת מאדים חמים, אדם מאבד לרגע את פניו. משיכה אחת, והפנים חוזרות. הודות למגע הזה שמסלק את הערפול, פוגשים את עצמם מחדש כל בוקר."},"ICON-2486":{"nm":"גומי רגל לחצובת צילום","de":"בקצה רגל החצובה, נקודת גומי בגודל ציפורן מכריעה את גורל התמונה. האחיזה החזקה ברצפה משתיקה את הרעד, כך שתמונה יציבה תמיד מתחילה בשקט מחיכוך בלתי נראה."},"ICON-2487":{"nm":"סרט רשת ייחוס לזווית","de":"קווי הרשת הדקים על הסרט הם כמו גלגלי אימונים לעיניים. ככל שהקומפוזיציה מתבססת יותר בידיים, הקווים נעלמים בשקט ונשארת רק האינטואיציה. עקבות הלמידה נעשים בלתי נראים ככל שהם מבשילים."},"ICON-2488":{"nm":"דוושת רגל להתחלת הקלטה","de":"לאדם שידיו מלאות בחפצים, האצבע האחרונה הייתה תמיד קצה הרגל. נגיעה קלה, וההקלטה מתחילה - מאחורי הקלעים, משק הבית מתבצע בקפדנות עד קצה הבוהן."},"ICON-2489":{"nm":"קליפס כיוון תאורה","de":"לאן ייפול האור תלוי בקצות האצבעות של קליפס בגודל ציפורן זה. להזיז צל בזרת אחת ולהבליט קונטור - על ההבדל הקטן הזה מישהו מתלבט זמן רב ומעמיק."},"ICON-2490":{"nm":"מסך השוואת צילומים","de":"כשמניחים את אתמול והיום זה לצד זה, רק אז השינוי פותח את פיו. ברגע שהמסך מחליק למטה, מרחק הזמן שחצה את הפער נחשף ביושר על המסך."},"ICON-2491":{"nm":"רצועת יד לשלט","de":"כורכים חוט אחד סביב פרק כף היד, והלב שדאג שמא יפול משתחרר. אמצעי בטיחות קטן דווקא משחרר את היד, פרדוקס עדין שבו מה שקשור הוא זה שמרגיע את הלב."},"ICON-2492":{"nm":"כיסוי עדשה","de":"בזמן שהמצלמה נחה, גם העדשה עוצמת בשקט את עינה. בעולם שבו גרגר אבק אחד נשאר צלקת על המסך, לכסות בעדינות היא בעצם המשאלה לשמור לאורך זמן."},"ICON-2493":{"nm":"רצועת הרמת זוויות פה","de":"מרימים מעט את זוויות הפה, וההבעה הנוקשה משתחררת ברכות. גם חיוך הוא בסופו של דבר שריר - בהתחלה שואלים כוח מהכלי, ובבוקר אחד מחייכים בזוהר בכוחות עצמם."},"ICON-2494":{"nm":"גליל עיסוי לשריר הלחי","de":"מגלגלים לאט את פנים הלחי ומשחררים, והדיבור זורם חלק בהרבה. הכנה שקטה שמעירה בעדינות את הפנים לפני השירה. גם ההבעה נעשית חמה יותר כשמחממים אותה."},"ICON-2495":{"nm":"מד זווית לחיוך","de":"המצלמה יודעת שגם לחיוך יש זווית נכונה. מודדים הנה והנה עם המד, ולבסוף מבינים - החיוך היפה ביותר פורח מכנות שאי אפשר למדוד כלל."},"ICON-2496":{"nm":"קליפס תנועת גבה","de":"גם תזוזה של מילימטר אחד בגבה משנה את כל מרקם הלב. קליפס שאוחז בשקט בחלק הכי קטן של ההבעה - משחק הוא עבודת קצות אצבעות ששולטת בדקויות כאלה."},"ICON-2497":{"nm":"מדבקת הרמת עצם לחי","de":"מרימים מעט את עצם הלחי ומדביקים, ונוצרות פנים שבהן האור שוהה. הממד שיוצר פתק דביק אחד בגודל ציפורן - באיפור הבמה מסתתרים סודות בלתי נראים כאלה."},"ICON-2498":{"nm":"פד עין לתרגול קריצה","de":"מכסים עין אחת, והלב מתכנס כולו אל העין שנותרה. תרגול קריצה הוא, בסופו של דבר, ללמוד להסתיר בעדינות מחצית. יש בהחלט הבעות שנעשות ברורות יותר בזכות מה שהוסתר."},"ICON-2499":{"nm":"קליפס תבנית צורת פה","de":"גה, גיה, גו... מתאימים את צורת הפה לתבנית, וההגייה המטושטשת נעשית חדה. שכל תנועה היא בעצם תנוחה של הפנים - לומדים זאת לאט בגוף מול המראה."},"ICON-2500":{"nm":"כיס חימום להבעת פנים","de":"רגע לפני העלייה לבמה, כיס חם שמחמם בעדינות את הפנים. כמו שידיים קפואות מקשיחות נגינה, כך גם הבעת הפנים. אמת קטנה מאחורי הקלעים - שגם לחיוך דרוש חימום מקדים."},"ICON-2501":{"nm":"רצועת החלקת קמטי מצח","de":"כשקושרים את הרצועה סביב המצח, הקמטים העמוקים מתרככים בשקט. חפץ שמעניק מנוחה, ולו לרגע, לקמטים שחרצה הדאגה. מתחת למצח מוחלק, אדם נראה קצת יותר צעיר."},"ICON-2502":{"nm":"אצבעון להפיכת דפי תסריט","de":"אצבעון קטן שעוטים על קצה האצבע כדי להפוך דפים. הקצב של הפיכת תסריט עבה, דף אחר דף, הופך מבלי משים לקצב של הסיפור עצמו. גם בקריאה מסתתר הרגל יד עדין וחם."},"ICON-2503":{"nm":"דגל צביעת רגשות","de":"שמחה היא צהוב, עצב הוא כחול. כשצובעים את הלב ומניפים דגל, הרגש הבלתי נראה מקבל צורה ומתנופף ברוח. גם רגשות אפשר לצייר כך ביד."},"ICON-2504":{"nm":"אטב הדגשת דיאלוג","de":"\"שים את המשקל על המילה הזאת\" - כך לוחש האטב בשקט. אותה השורה משנה את משמעותה כליל בזכות הדגשה אחת, ולכן זהו סימון קטן שאוחז במרכז הכובד של הדיבור."},"ICON-2505":{"nm":"קובייה לפסיק בקריאה","de":"קובייה שהונחה כדי לומר \"נוח כאן פעימה אחת\". פסיק בתוך השורות אינו עצירה אלא נשימה שנשאבת לקראת המילים הבאות. מי שיודע לנוח היטב, בסופו של דבר, יודע לדבר היטב."},"ICON-2506":{"nm":"רצועת אטבים לסימון נשימה","de":"הרצועה עולה ויורדת לאורך האטב, מציירת לנגד העיניים את אורך הנשימה. לצפות וללכת בעקבות קצב השאיפה והנשיפה - פתיחתו של שיר תמיד מתחילה בשליטה בנשימה."},"ICON-2507":{"nm":"כיס קובייה לרגשות","de":"קובייה מתגלגלת החוצה מהכיס וקובעת את הרגש של היום. אם עולה שמחה, מנסים להיות שמחים; אם עולה כעס, מנסים לכעוס. תרגול המשחק הופך למשחק של הפקדת הלב בידי המקרה."},"ICON-2508":{"nm":"מעמד משופע לתסריט","de":"מניחים את התסריט על המעמד המשופע ואין צורך להרכין את הראש. השיפוע הקטן הזה, ששומר על גובה העיניים, מטפל בשקט בעורף שהתקשה מתרגול ארוך."},"ICON-2509":{"nm":"מסך ללחישה","de":"סימן שאומר: מכאן והלאה - בלחישה. מנמיכים את הקול מאחורי המסך, והקהל דווקא עוצר נשימה ומטה אוזן. הפרדוקס העדין של הבמה - ככל שמדברים בשקט רב יותר, כך זה מגיע רחוק יותר."},"ICON-2510":{"nm":"קופסת אסימוני החלפת תפקידים","de":"הופכים אסימון קלות והתפקיד משתנה. היום כוכב ראשי, מחר חבר שעומד לצד. באי שבו גדלים יחד, לכולם מגיע תורם לעמוד במרכז הבמה."},"ICON-2511":{"nm":"מדבקת נקודת מיקוד למבט","de":"מניחים את המבט בשקט על נקודה קטנה ליד המצלמה. ברגע שהמבט המתנדנד נוחת במקום אחד, העיניים במסך קמות לחיים בבהירות. מבט יציב מתחיל, בסופו של דבר, מהישארות במקום."},"ICON-2512":{"nm":"משולש למדידת זווית צילום","de":"כשפינה במסך נראית איכשהו נטויה, מצמידים את המשולש והתשובה מתגלה. המלאכה של להישיר את העקום. לפני שסומכים על העיניים, מנסים לסמוך לרגע על הסרגל."},"ICON-2513":{"nm":"משטח לגובה עיניים לעדשה","de":"כשמציבים את העדשה בגובה עיניו של האדם, המסך משקר פחות. לא מלמעלה ולא מלמטה - רק כשפוגשים בעיניים שוות נלכדת הבעה אמיתית ולא מקושטת."},"ICON-2514":{"nm":"נוצת חץ להכוונת מבט","de":"המבט גולש בעקבות הכיוון שאליו מצביעה הנוצה. חץ קטן שמוביל בעדינות את עיני הצופה. תמונה טובה מצביעה בנימוס לאן כדאי להסתכל."},"ICON-2515":{"nm":"שבב רצפה למסלול צילום","de":"דורכים בשקט על נקודה אחת ממסלול שנלמד עד שחיקה, והמקום הבא כבר בהישג יד. הצעדים המשוטטים על הבמה הם שביל בלתי נראה שנוצר מחיבור סימנים קטנים כאלה, נעוצים ברצפה."},"ICON-2516":{"nm":"סרט מדידה למרחק מצלמה","de":"מודדים ברצועה את המרחק בין הנושא למצלמה. בעולם שבו זרת אחת מפרידה בין רחוק לקרוב, סרט המדידה הופך לשומר שקט על הגבול בין טשטוש לבהירות."},"ICON-2517":{"nm":"מדריך להטיית ראש","de":"כמה להטות את הראש כדי להיראות הכי עדין? עוקבים אחר המדריך ולומדים בשקט - שזווית ההטייה דומה, בסופו של דבר, לזה שבו הלב נפתח."},"ICON-2518":{"nm":"אטב מראת יד ליצירת קשר עין","de":"מניחים מראת יד ליד המצלמה באמצעות האטב, ומביטים בעיניים של עצמך תוך כדי מפגש עיניים איתך. מכשיר קטן שמניח בעדינות גשר של מבט בין ה\"אני\" שבמראה ל\"אתה\" שבמסך."},"ICON-2519":{"nm":"נורית סימון צילום","de":"כשהאור נדלק, זה הסימן שהצילום מתבצע עכשיו. מנורה קטנה אחת אוספת לתוכה את המתח של הסט הנרגש. מרגע שהאור דולק, נשימתם של כולם מתיישרת לפעימה אחת."},"ICON-2520":{"nm":"כפתור פעמון לתגובה","de":"לוחצים על הכפתור ופעמון צלול מצלצל בבהירות. כמו מחיאות כפיים שפורצות אחרי סצנה טובה, מילה חמה של \"כל הכבוד\" טמונה בתוך הפעמון הקטן הזה."},"ICON-2521":{"nm":"שפופרת הגרלת תגובה מהירה","de":"מנערים וקיסמי העץ משמיעים קול נקישה, מעוררים ראשונים את האווירה. מי פותח את הבמה נקבע בתנועת שורש כף יד אחת - מי שנבחר מחייך במבוכה, והשאר נושמים לרווחה. גם בחלוקת המזל יש כללים חמים."},"ICON-2522":{"nm":"פעמון ניעור לאפקט קול","de":"מניעים קלות את פרק כף היד וצליל צלצול נכנס לתמונה. הפעמון הקטן הזה ממלא את הרווח לפני שהשקט יספיק להיות מביך. בספירת הקצב של הצחוק, זה תמיד צעד אחד לפני כולם."},"ICON-2523":{"nm":"מכסה קופסת ההפתעה","de":"עד שהיא נפתחת, איש אינו יכול לנחש מה בפנים. זה התפקיד היחיד שהמכסה הזה נטל על עצמו. כדי שצווחות וצחוק יפרצו יחד ברגע שהיא נפתחת בפתאומיות, הוא תולה את ההתרגשות כולה על ציר אחד."},"ICON-2524":{"nm":"מניפה מתקפלת לתגובה","de":"קול הפתיחה החד הופך בעצמו לתשובה. צלעות המניפה מניפות במקום את ההתפעלות שלא נאמרה במילים. בין תנועות הקיפול והפתיחה עובר ההתלהבות הלוך ושוב, ופיסת רגש נעה יחד ברוח."},"ICON-2525":{"nm":"גלגל רולטה לעונשים","de":"איש אינו יודע מראש על איזה תא המחט תעצור. ככל שהגלגל מאט, כך הלב דווקא מאיץ - קליק, והיא נעצרת, וגורלו המצחיק של היום נכתב במקום העצירה. כמה שניות שבהן אפילו הרעד הוא כיף."},"ICON-2526":{"nm":"לוח בלון דיבור לקריאת התפעלות","de":"מרימים מעל הראש והמילה \"וואו\" עולה כאותיות. דף נייר אחד מקדים את הלב, צועק את מה שהפה לא הספיק לעקוב אחריו. כי גם לתגובה נדרשת קצת בימוי במה."},"ICON-2527":{"nm":"דגל יד לעצירה רגעית","de":"ברגע שהדגל מתרומם, כולם קופאים בדיוק במקום שבו הם נמצאים. סימן שנועל אפילו את קול הנשימה לתוך פריים קפוא. כשהוא יורד שוב, כל הצחוק שהיה קפוא נשפך החוצה בבת אחת."},"ICON-2528":{"nm":"קופסת אטבים לתשובות מצחיקות","de":"ככל שהתשובה מוזרה יותר, כך היא נתלית באטב בנחישות רבה יותר. כשהתשובות השגויות התלויות על החבל מתנדנדות ברוח, הבמה הופכת למקום שבו הטעויות אהובות יותר מהתשובות הנכונות. זהו נוף של יום שבו זה בסדר לטעות."},"ICON-2529":{"nm":"טריז משענת לתיקון יציבה","de":"ברגע שנשענים לאחור, עמוד השדרה הכפוף מגשש בעדינות אחר דרכו שלו. טריז קטן אחד שתומך בלי מילה. יציבה נכונה, כך הוא אומר בשקט מהגב, נעשית נוחה רק כשמישהו תומך בה."},"ICON-2530":{"nm":"בלוק תמיכה ליישור אגן","de":"יציבות קטנה שמונחת מתחת לרגליים כשמרכז הכובד מתנדנד. שיווי המשקל של הגוף עולה, בסופו של דבר, לאט מהרצפה. שחקן משנה חסר שם שתומך ביציבה ממקום בלתי נראה."},"ICON-2531":{"nm":"כדור איזון להידוק בטן","de":"לוחצים בבטן ומהדקים בעדינות, והמרכז המפוזר מתכנס לנקודה אחת. ככל שהנשימה מתייצבת עמוק יותר, כך הכדור מתקשה, והגוף מוצא מחדש, נשימה אחר נשימה, את הציר ששכח."},"ICON-2532":{"nm":"סרגל בדיקת עקומת עמוד שדרה","de":"מצמידים את הסרגל לאורך הגב והעקמומיות הבלתי נראית מתגלה על הסקאלה. לעמוד ישר אין פירושו למחוק את העקומה - אלא לקרוא אפילו את הכיפוף הקטן הזה בעדינות."},"ICON-2533":{"nm":"לולאה אלסטית לפתיחת כתפיים","de":"תולים על הכתפיים ומושכים לאט, והחזה המכווץ נפתח לרווחה. הגומייה תמיד לוחשת \"חזור למקומך\", והגב שהתכופף לאורך היום מתיישר קמעה קמעה לקריאה העדינה הזאת."},"ICON-2534":{"nm":"שקית חול לגירוי שריר הליבה","de":"עוטפים את המותניים וגרגירי החול הכבדים מעוררים את שריר הליבה הרדום. אפילו תנועה קלה הופכת רצינית ברגע מול משקל זה. כמה שמחזיקים מעמד, כך מתחזקים - כל גרגיר וגרגיר מספר זאת בשקט."},"ICON-2535":{"nm":"תג כרית לתמיכת עצם הזנב","de":"כרית שתומכת בעדינות מתחת לעצם הזנב, ותג קטן תלוי בקצהּ. חפץ כמו פתק עדין, שנכתב והודבק ליום שהתעייף מישיבה ארוכה: \"אפשר להישען כאן קצת\"."},"ICON-2536":{"nm":"חצובה זוויתית לתמיכת גב תחתון","de":"נשענת על שלוש רגליים, ומחזיקה בשקט את הזווית שעליה יישען הגב התחתון. תמיכה שמתגנבת ליציבה העומדת לקרוס. כדי להחזיק במשהו מתנדנד, שלוש נקודות מספיקות, למרבה ההפתעה."},"ICON-2537":{"nm":"אטב יציבה למשיכת סנטר","de":"מושכים את הסנטר קלות ותומכים בו, וקו הצוואר שהשתבש מוצא את מקומו. הנזיפה של אטב בגודל אצבע היא עדינה איכשהו. איך להחזיק את הראש ישר - הכלי הקטן הזה מלמד."},"ICON-2538":{"nm":"רצועת סולם לצעדים","de":"הרצועה הפרושה על הרצפה מציירת בזה אחר זה את המשבצות שבהן ידרכו הרגליים. דורכים במשבצת אחר משבצת ביושר, ומבלי משים הצעדים נחרתים בגוף. דרך מתבהרת ככל שדורכים עליה יותר."},"ICON-2539":{"nm":"שבב חרוט לשינוי כיוון","de":"כשמציבים אותו, הוא סימן קטן שאומר \"פנה כאן\". הוא מעניק פינה לרגליים שרק ידעו לרוץ ישר. גם בדרך של הפנייה מסתתר קצב משלה."},"ICON-2540":{"nm":"לוח תנודה לעמידה על רגל אחת","de":"ברגע שעולים על רגל אחת, הלוח נוטה קלות. אותן כמה שניות של מאמץ להתגבר על הרעידה הן השיעור הכן ביותר בשיווי משקל. קצות האצבעות שמנסים לא ליפול מספרות הכל."},"ICON-2541":{"nm":"נורית הבזק למהירות תגובה","de":"ברגע שהאות נדלק, היד והעין מתחרות מי מהן ראשונה. האור המהבהב לא נותן זמן להסס. יד מהירה תמיד נעה חצי פעימה לפני המחשבה."},"ICON-2542":{"nm":"סמן רצפה לצעדי זיגזג","de":"נקודות קטנות מודבקות באלכסון על הרצפה, מובילות את הרגליים לרקוד בזיגזג. מה שקשה יותר מקו ישר הוא תמיד ההצטלבות. משוטטים בעקבות הנקודות, ותנועות הרגליים המהירות מבשילות בזריזות."},"ICON-2543":{"nm":"מוט שטוח ללכת על חבל","de":"מניחים את הרגליים על המוט הדק והעולם מצטמצם לחבל בודד. כמו הלכי חבל שצועדים על האוויר, טוענים את כל הריכוז על רוחב זרת אחת. שיווי המשקל, ככל שהוא מצטמצם, הופך דווקא לברור יותר."},"ICON-2544":{"nm":"צמיד כדור קפיצה לזריזות","de":"עוטים על פרק כף היד, וכדור קטן קופץ בחזרה בתנודה. ברגע הזריקה והתפיסה נחרתת מהירות התגובה בקצות האצבעות. מהירות היא, בסופו של דבר, לא לפספס את מה שחוזר."},"ICON-2545":{"nm":"חישוק הולה קפיצה לרגליים זריזות","de":"תולים על הרגל ומסובבים, וחישוק ההולה ממשיך לדחוף את השוק. ברגע שעוצרים הוא נופל, כך שהרגל מנענעת ללא הפוגה. תוך תנועה כמו במשחק, תנועות הרגליים מבשילות זריזות ומהירות."},"ICON-2546":{"nm":"סביבון עץ למרכז כובד בקצות האצבעות","de":"סביבון המסתובב על כף היד נעצר במקום ברגע שהוא מאבד את מרכזו. כמו ימי הילדות של הצלפת סביבון בחצר, שיווי משקל הוא דבר שיכול לעמוד רק כשהוא מסתובב ללא הרף."},"ICON-2547":{"nm":"שרוך הידוק להגנת קרסול","de":"עוטפים ומהדקים את הקרסול, והדריכה המתנדנדת נעשית הרבה יותר בטוחה. ככל שמקום פגיע יותר לפציעה, כך יש להחזיק בו בעדינות רבה יותר. חוט אחד הופך להיות הביטחון של צעד אחד."},"ICON-2548":{"nm":"רצועה מחממת לברך","de":"כורכים סביב ברך קרה והחום חודר בין המפרקים. מפרק נוקשה מתרכך רק כשמחממים אותו. לפני התנועה, זוהי ברכת הבוקר הכי חמה שנותנים לגוף שלנו."},"ICON-2549":{"nm":"כדורי לחיצה לשחרור שרירים","de":"לוחצים בעדינות על נקודה קשורה, והגרגירים מלטפים בשקט את הקשר. הנחמה המוזרה שמשתחררים בדיוק כמידת הכאב. אפילו נוקשות שהיד לא הגיעה אליה, הכדור הקטן הזה מלטף במקומה."},"ICON-2550":{"nm":"גלגל סדר לחימום","de":"מעוררים את הגוף מהמשבצת שבה הגלגל עוצר. צוואר, כתפיים, קרסוליים - את הסדר מפקידים במזל ואת הלב משאירים קליל. כשמשחק מתגנב לחימום, הגוף הנוקשה מחייך בשקט ראשון."},"ICON-2551":{"nm":"כרית חימום למפרקים","de":"מניחים כרית חימום לוהטת על המפרק, ורוגע כמו רצפה חמה בחורף מתפשט. זהו הזמן שבו מפרקים נוקשים משתחררים לרפיון נמנם. רק אחרי שהתחמם, הגוף מתכונן סוף סוף לנוע לאט."},"ICON-2552":{"nm":"לולאת אחיזה למתיחות","de":"אוחזים בלולאה ומושכים, והשרירים הנוקשים נמתחים לאורך. שיחה מתוחה עוברת בין היד האוחזת לגוף הנפתח. ככל שהמתיחה גדולה יותר, כך תנועות המחר יהיו קלות יותר."},"ICON-2553":{"nm":"לוח בליטות לגירוי כף הרגל","de":"עומדים יחפים על הבליטות וכפות הרגליים הרדומות מתעוררות בבהלה. כמו העקצוץ החד של הליכה יחפה על שביל חצץ, תחושת הקרקע עולה מקצות האצבעות."},"ICON-2554":{"nm":"סיכת מגנט לתזכורת פציעה","de":"כותבים \"אל תגזים\" ומדביקים בקלות על לוח המתכת. זיכרונות כואבים נשכחים בקלות, לכן תולים אותם לנגד העיניים במגנט. גם הדאגה לגוף מתחילה, בסופו של דבר, משורה אחת של פתק."},"ICON-2555":{"nm":"מוט מפרקים לשחרור פאשיה","de":"מגלגלים לאט את המוט המפורק, והפאשיה הדבוקה משתחררת קטע אחר קטע. מגע שדוחף בעדינות את הקשרים הצידה. גם יום מכווץ, כשמיישרים אותו כך פרק אחר פרק, נעשה קל בהרבה יותר."},"ICON-2556":{"nm":"רצועת רצפה לקו הליכה","de":"פרושה ישר על הרצפה, היא נותנת לרגליים קו אחד לעקוב אחריו. אפילו הליכה מפוזרת, כשמניחים אותה על הקו הזה, מתיישרת מבלי משים. כשמציירים את הדרך, הרגליים כבר לא תועות."},"ICON-2557":{"nm":"מוט איזון לכתפיים","de":"מונח לרוחב על הכתפיים, הוא חושף בשקט איזון שנטה לצד אחד. להיות אופקי משמעו תמיד להנמיך צד אחד ולהרים את השני. מוט אחד מצביע בעדינות על הרגל עקומה."},"ICON-2558":{"nm":"משקולת איזון לקודקוד","de":"כדי שהמשקולת על הקודקוד לא תיפול, כל הגוף חייב לעמוד ישר כמו קו אחד. כמו התמונה הישנה של הליכה עם כד מים על הראש, המרכז נתפס מהנקודה הגבוהה ביותר ויורד למטה."},"ICON-2559":{"nm":"משענת זווית לסנטר","de":"תומכים בסנטר בעדינות, והראש שהמשיך להישמט מוצא מחדש את זוויתו הנכונה. מנוחה קצרה שנשענת על תמיכה אחת. קו ישר שלם רק כשמישהו תומך בו מלמטה."},"ICON-2560":{"nm":"יתד למרווח צעדים","de":"היתד הנעוץ ברצפה מודד מראש איפה יינחתו הרגליים. צעד אחד, לא רחב מדי ולא צר מדי - המרחק הישר הזה. שיווי המשקל של ההליכה מתחיל בשקט מהסימן הקטן הזה."},"ICON-2561":{"nm":"טריז כיוון לקצות האצבעות","de":"צעד ראשון מהוסס - קצות האצבעות מססים ראשונות לאן ללכת. כשהטריז הקטן הזה קובע כיוון, גם הלב נוטה בעדינות לאותו צד. לקבוע דרך אינו החלטה נשגבת, אלא הזרת שאליה מצביעות האצבעות."},"ICON-2562":{"nm":"חגורה ליישור גב","de":"הקול שכל הזמן אמר \"תתיישר, תתיישר\" כאילו חי בתוך החגורה הזאת. כשמיישרים בעדינות יום כפוף, גם המשקל המונח על הכתפיים נעשה, באורח פלא, קצת יותר קל. יציבה טובה אחת מרימה גם את הלב."},"ICON-2563":{"nm":"משטח לחלוקת משקל","de":"שבע ברגל שמאל, שלוש בימין. איפה שמפקידים את המשקל קובע את שיווי המשקל. המשטח שואל בשקט - לאיזה צד אתה נוטה עכשיו? לעמוד ישר, מתברר, זו התאמה בלתי פוסקת."},"ICON-2564":{"nm":"מוט מטרה לגובה מבט","de":"העיניים כל הזמן צונחות לקצות האצבעות. באותם רגעים, מוט בודד המוצב הרחק מרים לאט את המבט. תרגול להסתכל רחוק הוא תרגול ללכת רחוק, כך שברגע שמרימים את הראש, אפילו מקום שנראה בלתי מושג מתקרב."},"ICON-2565":{"nm":"אטב כרטיס לזווית קידה","de":"חמש עשרה מעלות, שלושים מעלות, ארבעים וחמש מעלות. הלב קד עמוק כמו שהמותניים מתקפלות. הזווית הכתובה על הכרטיס אינה סתם מספר, אלא סקאלה קטנה שמודדת את הכנות שמופנית לזולת."},"ICON-2566":{"nm":"לולאת נימוס לצירוף ידיים","de":"מצרפים את שתי הידיים יחד, והלב הנרגש שוקע בשלווה למקום אחד. הלולאה הקטנה הזאת תופסת בעדינות קצות אצבעות מבולבלות וחסרות מנוחה, ומעצבת בשקט את היציבה הראשונה של ברכה."},"ICON-2567":{"nm":"מגנט חץ למסלול","de":"מה שרגליים אבודות מחפשות ראשון, כשהן מביטות סביב, הוא חץ. כיוון אחד שנדבק במגנט קוטע את ההיסוס, ומושך בעדינות את הצעדים לעבר המקום שאליו צריך להגיע. גם לב תועה מוצא סוף סוף כיוון אחד."},"ICON-2568":{"nm":"סיכת סימון כיוון יציאה","de":"הדרך החוצה קשה יותר מהדרך פנימה. אפילו בחשכה שבה כובו האורות, הסיכה הזוהרת בבירור הזה מצביעה בשקט על המסלול האחרון. שגם לצאת יפה זו חלק מהבמה - לומדים זאת רק בסוף."},"ICON-2569":{"nm":"רצועת כרטיס לסדר קידה רשמית","de":"היה זמן שבו הסדר של מי קד ראשון ומי קד אחרון היה ברור. משפילים את הגוף לפי הסדר הכתוב על הרצועה, וגם לנימוס נוצר גרעין, וגם לנימוסים יש זרימה. זו שמירה על סדר הלב."},"ICON-2570":{"nm":"שבב מגנט ליישור צעדים","de":"אם אדם אחד יוצא מהקצב, כל השורה מתנדנדת. כמו שבב שנצמד בקליק כשקצות האצבעות מיושרים, לעמוד יחד משמעו לוותר בעדינות על הצעד שלי לטובת מי שלצדי. צעדים הנופלים באותה פעימה הם המרגיעים ביותר."},"ICON-2571":{"nm":"פרסת עמידה לקידת במה","de":"גם לקידת במה אחת יש מקום לעמוד בו. מניחים את הרגליים על הסימנים הפרושים בעיגול כמו פרסה, וברכה ראשונה שכל הזמן השתבשה מרוב עצבים מוצאת סוף סוף את צורתה. כשיודעים את המקום, גם הרעד שוכך מעט."},"ICON-2572":{"nm":"כרטיס מחוות תודה","de":"תודה שהמילים לא הצליחו להכיל זורמת החוצה דרך קצות האצבעות. מציירים לב, מניחים יד על החזה - כל מחווה הכתובה על הכרטיס הופכת לתרגום של הלב שנכתב בתנועה. לכנות שרוצה להגיע יש תמיד צורה."},"ICON-2573":{"nm":"יתד כרטיס למרווח תור","de":"גם בעמידה בתור יש נימוס עדין. כמו יתד ששומרת בדיוק על מרחק זרת מהאדם שלפניו, ההמתנה מתחילה מהתחשבות קטנה שלא לדחוף זה את זה. לעמוד קצת בצד זו גם דאגה לזולת."},"ICON-2574":{"nm":"טבעת הפיכת כרטיסי קריינות","de":"כשהמשפט הבא ממשיך לרחף על השפתיים, אצבע הופכת בשקט דף אחד. הניירות הקטנים המושחלים על הטבעת לוחצים בעדינות על הלב הדופק, ופותחים בשלווה את המשבצת של מה שיש להגיד הלאה. גם כשרועדים, הזרימה לא נשברת."},"ICON-2575":{"nm":"שעון חול לסדר תוכנית","de":"מביטים בשקט בגרגירים הזורמים לאט, והסדר הבא מתארגן ברוגע בלב. עד שהגרגיר האחרון נופל, השעון הקטן הזה מלמד לקרוא זמן בעיניים, ללא חיפזון."},"ICON-2576":{"nm":"מוט תרגול לאחיזת מיקרופון","de":"לפני שזה נעשה טבעי, מוט ריק אחד שוקל כאלף ליטרה. זווית האחיזה, המרחק מהפה, הכוח בפרק כף היד - תרגול של אחיזה ושחרור אינספור פעמים, פורח יום אחד לפתע לתנועה אחת טבעית."},"ICON-2577":{"nm":"מקל לשון לדיבור ברור","de":"גה, נה, דה, רה. מחזיקים את המקל בפה ומגלגלים את ההגייה עד שקצה הלשון מתבהר. מילה שעברה בבירור וצלילות היא כמו פרח שפורח בשקט מעל מאות שעות של מלמול מטושטש."},"ICON-2578":{"nm":"דגל יד לאות תזמון","de":"התחלה, עצירה, נוח פעימה אחת. דגל בודד חסר מילים מנצח על נשימת הבמה. ממקום שהקהל לא רואה, יד שמתנופפת בשקט אוחזת בכל פעימה ללא רווח."},"ICON-2579":{"nm":"פעמון למעבר בין קטעים","de":"צלצול צלול, קלינג, והסצנה מתחלפת. כמו קול פעמון שהתפשט בשוק בשעת דמדומים, צליל קטן זה נושא בקלילות לב מהוסס אל הקטע הבא. מעבר תמיד מתחיל מקול."},"ICON-2580":{"nm":"מטוטלת פעימה לנשימת דיבור","de":"שואפים אוויר - אחת, שתיים - ונושפים לאט. מיישרים את הנשימה בעקבות המטוטלת המתנדנדת ימינה ושמאלה, ומילים שנשפכו בחיפזון מוצאות מחדש את פעימתן. קצב הדיבור, מתברר, היה תמיד קצב הנשימה."},"ICON-2581":{"nm":"לוח מתקפל לתסריט הנחיה","de":"בתנועה אחת בלבד של קיפול ופתיחה טמון סדר היום כולו. ברגע שפורשים את הלוח השחוק מרוב שימוש, לב שהתבלבל לגבי מה להעלות ראשון מתיישר ברוגע. פתיחה אחת מסדרת יום שלם."},"ICON-2582":{"nm":"שעון חול לקצב נשימה","de":"שאיפה שלוש, עצירה ארבע, נשיפה שש. בזמן שהחול זורם, גם הנשימה שלי זורמת בשקט אחריו. לספור נשימה אחר נשימה היא הדרך הישנה והחמה ביותר לטפל לאט ב\"אני\" הטרוד."},"ICON-2583":{"nm":"ציצית לכרית מדיטציה","de":"הציצית התלויה בקצה הכרית מתנדנדת בשקט גם בלי רוח. יושבים בישיבה מוצלבת, והשלווה של איש עתיק ששיכך את לבו על מרפסת עץ מגיעה בעדינות לצד, נשארת קצת, וממשיכה הלאה."},"ICON-2584":{"nm":"פעמון יד להרגעת נשימה","de":"כשמשב רוח אחד עובר, קול צלול בוכה בשקט. תלוי כמו פעמון רוח בקצה גג, הוא מטפטף טיפה אחת קרה ומרעננת מעל לב שרתח בבלבול. גם לצליל יש כוח קירור."},"ICON-2585":{"nm":"צלחת לקליטת עשן קטורת","de":"העשן שנותר משריפת הקטורת שוקע לאט על הצלחת. כמו ריח הקטורת שעלה מול שולחן החג בבוקר, פס עשן בודד משכיך בעדינות אוויר סוער וממלא את החדר בשקט."},"ICON-2586":{"nm":"מטוטלת נדנוד לשאיפה ונשיפה","de":"הנשימה שלי רוכבת על משקולת בודדת העולה לאט ושוב יורדת. צפה כלפי מעלה כשאני שואף, שוקעת כשאני נושף - ביום שבו הגוף שכח איך לנשום, שעון קטן זה מלמד הכל מחדש מההתחלה."},"ICON-2587":{"nm":"מקל הקשה לפעמון מדיטציה","de":"מקישים על הפעמון פעם אחת, בעדינות, וההד מתפשט למרחוק. כמו צליל פעמון רוח שמהדהד במקדש הררי, פשוט להקשיב בדממה עד שהצליל נעלם כליל באוויר, שוטף פינה אחת בלב."},"ICON-2588":{"nm":"נוצה למדריך נתיב נשימה","de":"מניחים את הנוצה בשקט מול האף, ונתיב הנשימה הבלתי נראה הופך סוף סוף לגלוי. תנודה קלה פירושה שנושמים היטב; דממה פירושה שהחזיקו יותר מדי זמן. הדבר הקל ביותר הוא לפעמים המדריך הכן ביותר."},"ICON-2589":{"nm":"חלוק אבן להרגעת הלב","de":"החלוק האחוז בכף היד קר וחלק. כמו אבן שהתגלגלה זמן רב בגדת נהר עד שוויתרה על כל הפינות שלה, ממשיכים למשש אותו בקצות האצבעות, והחלקים החדים של לב סוער נשחקים בהדרגה לעגולים."},"ICON-2590":{"nm":"אטב טמפרטורה לנשימת אף","de":"הטמפרטורה בקצה האף אומרת בשקט את עומק הנשימה. האטב קורא בדממה את האוויר הנכנס קר והיוצא חם, ומראה בבירור את הנשימה שבדרך כלל אפילו לא מרגישים. גם לנשימה יש הבעה."},"ICON-2591":{"nm":"לוח מדבקות למזג אוויר של מצב רוח","de":"הלב שלי היום בהיר או מעונן? ברגע שבוחרים מדבקה קטנה ומדביקים אותה קלות על הלוח, גם מצב רוח שקשה להוציא במילים הופך לסוג של מזג אוויר ומקבל צורה ברורה. גם ללב דרוש תחזית."},"ICON-2592":{"nm":"חותמת יד לצבע רגש","de":"שמחה היא צהוב, עצב הוא כחול. בוחרים צבע ולוחצים אותו חזק על הנייר, וגוון הלב נשאר כסימן. גם רגש שקשה מדי לתת לו שם - הצבע מגיע ראשון ומזהה אותו בעדינות."},"ICON-2593":{"nm":"שבב עלה כותרת ללב היום","de":"מניחים בעדינות את כל לב היום על עלה כותרת בודד. כמו פרחי אזלאה מרחפים ביום אביבי, שבב אחד קל ורך שואל בקול נמוך, בסוף יום דועך, איך היה עלייך."},"ICON-2594":{"nm":"מגנט בלון דיבור לעידוד","de":"המילים שרוצים לומר ממשיכות לרחף על השפתיים. ברגע שמדביקים את מגנט בלון הדיבור, מילת עידוד שלא הצליחו להשמיע בקול מגיעה בשקט אל יומו העייף של מישהו. כך הלב מועבר."},"ICON-2595":{"nm":"חותם מעטפה לרגשות פנימיים","de":"מילים שלא הצליחו להוציא נארזות בעדינות במעטפה ונחתמות. כמו איש עתיק שאטם מכתב בדבק בקצות האצבעות, חותם אחד שומר על הלב הפנימי בבטחה. ממתין בשקט ליום שיוציאו ויפרשו אותו."},"ICON-2596":{"nm":"ניצן פרח לטמפרטורת רגש","de":"ניצן קפוץ, כשהוא נוגע בחום, נפתח שכבה אחר שכבה בזהירות. פורח כשטמפרטורת הלב עולה - כמה התחממתי היום, הפרח הזה יודע לפני המילים. גם ללב מגיע אביב."},"ICON-2597":{"nm":"רצועת מראת יד לשבח עצמי","de":"מרימים את המראה ופוגשים בשקט את העיניים שלך המשתקפות בה. מה שהפנים הקטנות התלויות ברצועה מראות אינו הפנים שלך, אלא ה\"אתה\" של אתמול, שמגיעה לו מילה על שהחזיק מעמד היטב. הנחמה מעולם לא הייתה רחוקה."},"ICON-2598":{"nm":"סט חותמות פנים למצב רוח","de":"חיוך בהיר, דמעות גדושות, שפתיים זעופות. לוחצים חזק את חותמות ההבעה וכותבים את יומן הלב. ביום עמוס מכדי לכתוב במילים, פרצוף קטן אחד מדבר בשקט במקומי את מצב הרוח של אותו היום."},"ICON-2599":{"nm":"לולאת מיון לפקעת רגשות","de":"פקעת חוטים סבוכה ככל שתהיה, כשמתירים אותה בזהירות חוט אחר חוט, היא חוזרת בסוף לחוט אחד. תולים על הלולאה, אחד אחד, רגשות מעורבבים ומחניקים, וגם ללב שלא הבנת לגמרי נתפס חוט דק להמשיך בעקבותיו."},"ICON-2600":{"nm":"חוט שקית ריח לשינה","de":"משקית הריח התלויה ליד הכרית מתפשט בשקט ריח עשבים עדין. כמו ריחה של סבתא שהחביאה ריח עמוק בארון הבגדים, בזמן שממששים את החוט, המתח שהיה נטוי כל היום נרדם לאט לאט."},"ICON-2601":{"nm":"לוח היפוך תנוחת שינה","de":"לילה שבו התהפכת ממקום למקום ורק לפנות בוקר נרדמת בקושי. כשמהפכים בעדינות את תנוחת השכיבה, ההתהפכות של אתמול חומקת בשקט אל הרעננות של הבוקר הזה. גם המנוחה היא תרגול, אומר הלוח הקטן הזה בלי מילים."},"ICON-2602":{"nm":"תלייה לאור ירח ליד הכרית","de":"תולים פיסת אור שחדרה דרך סדק הווילון, לצד הכרית. נהר עדין זורם מעל הפנים הישנות, וגם לילותיה של המתלמדת, שהחושך הפחיד אותה, התרככו סוף סוף. זו הייתה הנחמה הקטנה הראשונה שהכירה."},"ICON-2603":{"nm":"שבב ניצן למצב הגוף","de":"מצב הגוף היום סגור כמו ניצן פרח. לוחצים קלות על השבב והוא נפתח לאט - הגוף יודע ראשון אם ישנת טוב או לא. אפילו ההיסוס הזה, לפני שהוא נפתח לגמרי, חמוד בשקט."},"ICON-2604":{"nm":"מכסה פתיל למנורת לילה","de":"\"אל תכבו את האור.\" בשביל הצעירה ביותר, שפחדה מהחושך, מישהו הניח בעדינות מכסה על הפתיל. לא בהיר מדי ולא חשוך מדי, הבטחה קטנה ורכה לשמור עליה רק עד שתירדם."},"ICON-2605":{"nm":"סיכת חמנייה להשכמת בוקר","de":"תוחבים אותה ליד הכרית, והיא מטה את ראשה בעדינות, כמו חמנייה, לעבר קרן השמש הראשונה. גם בימים שלא בא לך לקום, יש סיבה לקריאת האור, והיא לוקחת את הבוקר לכיוון אחד."},"ICON-2606":{"nm":"מברשת עשבי תיבול לכרית","de":"טובלים לבנדר ובבונג בקצה המברשת ומעבירים אותה פעם אחת על הכרית. בזמן שהניחוח חודר לציפית, המתח של היום כולו משתחרר לאט מהכתפיים. שינה טובה מתחילה בניחוח הקטן הזה."},"ICON-2607":{"nm":"קליפס לפינת שמיכה","de":"עם עלות השחר, קצות האצבעות נמלטות שוב ושוב מתחת לשמיכה. תופסים את הפינה בחוזקה עם הקליפס, והחום לא יכול לברוח כל הלילה. זו סגירה קטנה ששמים במקום \"לילה טוב\"."},"ICON-2608":{"nm":"סלסלת חלוקי מצב-רוח","de":"דבר טוב אחד ביום, חלוק נחל אחד בגודל כף יד. ככל שהאבנים שנאספות בסלסלה נעשות כבדות יותר, כך הלב מתמלא ביטחון בשקט. לאסוף רגעים פשוטים אל תוך כף היד - כך תמיד נספר האושר."},"ICON-2609":{"nm":"צנצנת איסוף כוכבי הבטחה","de":"בכל לילה, מעצבים את ההחלטה של היום לצורת כוכב ומטילים אותה לצנצנת. כשהיא מתמלאת עד הסוף, הצנצנת הופכת לשמי לילה קטנים. הפה הריק שהיה פעם יודע: הבטחות זוהרות רק כשאוספים אותן יחד."},"ICON-2610":{"nm":"תלייה לסוכריית פרס קטנה","de":"סוכרייה אחת שמעניקים לעצמכם בסוף יום מתיש. ברגע שמוציאים אחת מהתלייה ושמים בפה, הכול בסדר גם אם אף אחד לא שם לב. פרס קטן הוא העידוד הכן ביותר שיש."},"ICON-2611":{"nm":"חותמת \"עשיתי זאת היום\"","de":"טובלים בדיו ולוחצים בחוזקה על המחברת. \"עשיתי זאת היום.\" יום שעבר טוב ויום שרק שרדת ממלאים משבצת אחת באותה מידה. לא כל יום צריך להיות מושלם, רק שלא תפסיקו להטביע את החותמת."},"ICON-2612":{"nm":"בסיס תמיכה לדגל עידוד","de":"תוקעים אותו חזק באדמה, וככל שהרוח חזקה יותר, הדגל מתנופף בעוצמה רבה יותר. גם למה שמתנדנד דרושה יד תומכת. כך הלב שמעודד מישהו מחזיק מלמטה."},"ICON-2613":{"nm":"עציץ לזריעת זרע המטרה","de":"מטרה לא משננים במילים, אלא קוברים באדמה. בזמן שנוטעים זרע, משקים אותו ומחכים, חוסר הסבלנות הופך לאט לשורשים. מה שגדל בתוך העציץ הוא לא רק הנבט."},"ICON-2614":{"nm":"לוח מדבקות שבח","de":"מדבקה אחת על כל דבר טוב שנעשה. ככל שהלוח מתמלא בצבעוניות, כך הימים שחלפו בלי משים חוזרים לחיים בצבע. בילדותנו ידענו: השבח מתבהר ככל שמדביקים אותו יותר."},"ICON-2615":{"nm":"לולאת קשירה לסרט ההבטחה","de":"יד שמשחילה את הסרט דרך הלולאה וקושרת אותו. חזק כדי שלא יתפרק, אבל לא חזק מדי. הבטחה דומה בדיוק לקשר הזה - מהדקים אותו יותר מדי והוא נקרע, משאירים אותו רופף והוא מחליק בשקט."},"ICON-2616":{"nm":"שבב צדפה להישג קטן","de":"כותבים הישג קטן על צדפה שנאספה בחוף הים. כמו שבר שהגיע עד הלום, מלוטש ומעוגל בידי הגלים, גם היום שלך התגלגל זמן רב וכעת מבריק ומצוחצח. כל מה ששרד את הזמן זוהר בסופו של דבר."},"ICON-2617":{"nm":"וו תלייה למדליית פרס","de":"מדליה שהושגה בעמל תולים לא במגירה אלא בגובה העיניים. המשקל שעל הווו מיישר את הכתפיים בכל בוקר מחדש. פרס לא נועד להסתתר, אלא להיתלות שם כדי שיביטו בו."},"ICON-2618":{"nm":"כוס טפטוף למטריית מונסון","de":"גשם המונסון מטפטף ויורד לאורך קצה המטרייה. שמים כוס מתחתיו והכניסה נשארת יבשה. אי אפשר לעצור את מה שניגר, אבל אפשר לקבוע היכן הוא ינחת."},"ICON-2619":{"nm":"שקית קרח לקירור מהחום","de":"מאחורי הקלעים באמצע הקיץ, שקית קרה מונחת קלות על העורף. החום הלוהט והעולה שוקע לרגע אחד. \"קחי נשימה.\" יד שדואגת לי לפני שהחום מספיק, מרגיעה."},"ICON-2620":{"nm":"קליפס קיבוע ללהב מאוורר","de":"גם להבים שהסתובבו בעוצמה נעצרים בשקט בעזרת קליפס אחד. ככל שהרוח עזה יותר, כך יש צורך במשהו שיאחז בה חזק. דברים שמסתובבים במהירות נעשים בטוחים בסופו של דבר בזכות מי שמחזיק אותם יציבים."},"ICON-2621":{"nm":"מוט ייבוש לנעליים רטובות","de":"נעליים שספגו גשם משאירות אפילו את הלב לח עד הבוקר. תוחבים את המוט פנימה, ועד הבוקר הן יבשות דיין לנעילה מחדש. מה שרטוב לא זורקים, אלא מייבשים בעדינות."},"ICON-2622":{"nm":"משטח ניקוי בוץ למגפיים","de":"מגפיים שדבק בהם בוץ מרוב שדות האורז. רק אחרי שמשפשפים אותם היטב על המשטח עולים אל הרצפה. להשאיר את הרפש שבחוץ ליד הדלת לפני שנכנסים - זהו נימוס עתיק ששומר על ניקיון הבית."},"ICON-2623":{"nm":"אריח קירור לרצפת קיץ","de":"כפות הרגליים היחפות יודעות ראשונות. מניחים כף רגל על שבר האריח שהונח על רצפת הקיץ, וחום היום פוחת בחופן צינה עדין. אפילו קור קטן אחד הופך עונה ארוכה לנסבלת."},"ICON-2624":{"nm":"רצועת חסימת גשם לסף הדלת","de":"רק רצועה אחת סביב הסף, ומי הגשם כבר לא יכולים לחלחל פנימה. קו דק המפריד בין פנים לחוץ. מקום ששווה להגן עליו הולם יותר גבול צנוע ומדויק מקיר מפואר."},"ICON-2625":{"nm":"צלחת מעמד לספירלת יתושים","de":"בליל קיץ, מניחים את ספירלת היתושים על המעמד, ועשן חריף אך מוכר עולה. כמו הקטורת שדועכת במעגלים הולכים וקטנים, כך גם הלילה מתעמק לאט. זהו ניחוח אותם ימים של שכיבה על ספסל העץ וספירת כוכבים."},"ICON-2626":{"nm":"לולאה לשרוול קירור מהחום","de":"מכסים את הזרוע הכואבת מהשמש בשרוול. מהדקים אותו בעזרת הלולאה לשרוול החולצה, וגם עבודת הצהריים נעשית נסבלת. הצינה היא החסד הקטן של הצללת פס אחד קטן במקום המגע."},"ICON-2627":{"nm":"מטאטא יד לאיסוף עלים","de":"אוספים את העלים שנפלו על החצר במטאטא היד, בטאטוא קל. עונה שלמה מרשרשת מתחת לרגליים. לסדר משהו זה גם ללוות בעדינות את מה שצריך לשחרר."},"ICON-2628":{"nm":"מוט תמיכה לאוורור חלון","de":"תוחבים מוט בחדר מחניק ומשאירים את החלון פתוח קלות. רוח הסתיו מחלחלת פנימה בשקט ולוקחת איתה את האוויר המעופש. אוורור הוא נקב הנשימה הקטן שמחליף בעדינות את מה שנערם בפנים בחוץ."},"ICON-2629":{"nm":"פקק לשקית בלוטים","de":"כמו סנאי, ממלאים את השקית בבלוטים וסותמים את פיה בפקק. חזק, שלא יתגלגל אף אחד החוצה. הרצון להגן על מה שנאסף הוא היצר העתיק של הדברים הקטנים שחורפים."},"ICON-2630":{"nm":"מטרקע אבק לשמיכת סתיו","de":"תולים את השמיכה ששימשה כל הקיץ בחצר וחובטים בה בעזרת המטרקע. ריח השמש מתפשט בין גרגרי האבק. שצריך לחבוט את העונה הישנה כדי לכסות בעונה החדשה - שורש כף היד יודע זאת ראשון."},"ICON-2631":{"nm":"חוט חסימת פרצים לסדק החלון","de":"חוסמים את הרוח הקרה שחודרת דרך סדק החלון בחוט אחד, בחוזקה. קו דק אחד שומר על החום שבחדר עד הסוף. קור גדול תמיד מתחיל בסדק קטן - ההיערכות לחורף יודעת זאת."},"ICON-2632":{"nm":"מכסה מסננת עלים","de":"מסננת המונחת מעל מרזב הגשם. היא מסננת את העלים בעדינות ומעבירה רק את המים. כדי לזרום בלי חסימה צריך להחליט מה מעבירים ומה עוצרים, אומרות מרזבי הסתיו."},"ICON-2633":{"nm":"קליפס לצרור עשב יבש","de":"קושרים חבילת עשב יבש כעצם בחוזקה בעזרת הקליפס. יד שאוגדת יחד את מה שנוטה להתפזר. גם במקום שממנו נעלם לגמרי הירוק של הקיץ, כשאוספים - התועלת נשארת שלמה."},"ICON-2634":{"nm":"מטוטלת מדידת חום לרוח הסתיו","de":"כשהרוח נושבת, המטוטלת מתנדנדת בעדינות. לפי רוחב הנדנוד מודדים כמה עמוק הסתיו הגיע היום. הטמפרטורה איננה מספר, היא נוגעת ביד לראשונה כדבר-מה שמתנדנד ברכות."},"ICON-2635":{"nm":"מעטפת חממן ידיים לכיס המעיל","de":"\"הידיים קרות.\" מעטפת חממן הידיים שמונחת בכיס המעיל מחממת בעדינות אצבעות קפואות. הלב שחושב על הקור של מישהו אחר לפני הכול, יושב תמיד בשקט בתוך הכיס."},"ICON-2636":{"nm":"מדף איסוף עיבוי לחלון","de":"המדף קולט בשקט את הדמעות שהחלון הקפוא הזיל כל הלילה. נתיב מים קטן שנוצר מהפרש הטמפרטורה בין פנים לחוץ. במקום שבו ההבדל גדול, זורם יותר - חלון השחר מוכיח זאת בכל יום מחדש."},"ICON-2637":{"nm":"רשת מגן לאח בוערת","de":"מציבים רשת מגן מול האח הבוערת. חום קרוב, סכנה רחוקה בדיוק זרת אחת. לשמור על האש בקרבת מקום מבלי להיכוות היא המרחק הבסיסי ביותר בטיפול במישהו."},"ICON-2638":{"nm":"קליפס הידוק לשמיכת חורף","de":"כשהשמיכה העבה של החורף מחליקה שוב ושוב, הקליפס לוחץ עליה ומחזיק אותה במקומה בשקט. חום כבד צריך להיאחז בו בחוזקה כדי שיצדיק את שמו. הנעימות של ליל חורף נשמרת כך, בקפידה."},"ICON-2639":{"nm":"מגרדת כפור","de":"מגרדים בעדינות את הכפור שפרח לבן על שמשת הרכב עם שחר, בעזרת המגרדת. השדה המטושטש מתבהר קו אחר קו. אפילו מה שקפוא אפשר בסוף לגרד ולהסיר, מלמדות קצות האצבעות של בוקר חורפי."},"ICON-2640":{"nm":"כיסוי חימום לבקבוק מים חמים","de":"עוטפים כיסוי חם על הכד שבו מים חמים. שלא יתקרר במהלך הלילה, עוד שכבה עוטפת את החום. הדרך לשמור על חום לאורך זמן היא, בסופו של דבר, לחבק אותו בקפידה במשהו."},"ICON-2641":{"nm":"מוט לחיצה לנייר האטימה בדלת","de":"הרוח הקרה כלהב סכין, שחדרה בין סדקי הדלת, נעצרת ברגע שהיא פוגשת בך. מוט אחד שלוחץ על שולי נייר המסך. חום החדר סוף סוף שומר על בני משפחתו שלו - כך מתחמם החורף בעקשנות קטנה כזו."},"ICON-2642":{"nm":"צלחת מעמד לחממן רגליים","de":"הצלחת העגולה המונחת מתחת לחממן הרגליים. היא קולטת את כל החום לבדה ולא משאירה כתם כהה אחד על הרצפה. כשקצות אצבעות רגליו של מישהו מתחממות בעצלתיים, החלק שלי ביום מסתיים בשקט."},"ICON-2643":{"nm":"לולאת תלייה למטלית עיבוי","de":"כדי שהמטלית שניגבה את טיפות הטל על החלון עם השחר לא תאבד את מקומה, לולאה אחת תלויה על הקיר וממתינה. יותר מלהרטיב לגמרי, לחכות שוב יבשה לבוקר המחר - זהו הלב האמיתי של הספיגה."},"ICON-2644":{"nm":"מתלה ייבוש לכפפות חורף","de":"כפפות שסיימו סבב קרב כדורי שלג פורשות את אצבעותיהן לרווחה ליד הרדיאטור. המראה של כפפות תלויות במתלה, מעלות אדים קלות. בסוף אחר צהריים עם אף אדום, זוהי הכביסה השלווה ביותר של החורף."},"ICON-2645":{"nm":"נוצת חילוף למטאטא אבק","de":"כשהנוצות מתבלות, מחליפים אותן בנוצות חדשות. הרגע שבו קצה מגרש-האבק חוזר להיות רך ותפוח. שגם לכלי ניקיון יש עונות מעבר משלו - החילוף הקטן הזה מספר לך את זה בשקט, על כף היד."},"ICON-2646":{"nm":"ידית סחיטת סמרטוט","de":"ידית שהותקנה כדי לחסוך במאמץ פרק כף היד. סיבוב אחד, והסמרטוט פולט את המים מעצמו. שלום לימים של מאמץ מול לוח הכביסה. בניהול הבית, קורטוב של תושייה הוא בעצמו חביבות."},"ICON-2647":{"nm":"ראש חילוף למברשת רצפה","de":"כשמברשת הרצפה מתבלה, מחליפים רק את הראש. הידית נשארת כמו שהיא, וגם המשקל שהיד הכירה נשאר. בחפצים שמשתמשים בהם זמן רב שוכנת עדינות קטנה ומוצקה שמסרבת לזרוק הכול בבת אחת."},"ICON-2648":{"nm":"גליל חילוף לגלגלת ניקוי מוך","de":"אחרי שקורעים את הדף האחרון של הגלגלת, יש תחושת ריקנות מוזרה. אז מכניסים גליל חדש. זו הבטחה עקשנית ואדיבה של חילוף, לדאוג עד הסוף אפילו לפלומה אחת שנדבקה לסוודר."},"ICON-2649":{"nm":"מגרד אבק לפינות","de":"גם בפינות שהמטאטא לא מגיע אליהן, האבק מקים לו בית בשקט. לגרד את הפינה נקייה בקצה דק. הלב שדואג אפילו למה שלא נראה הוא בדיוק הגאווה של ניהול הבית."},"ICON-2650":{"nm":"מסרק ניקוי למטאטא","de":"גם מטאטא שטאטא צריך יד שמעניקה לו מנוחה. מסרקים בעדינות את השיער שהסתבך בין הזיפים במסרק הזה, והמטאטא, לאחר שסיים את מלאכתו, מתכונן סוף סוף לטאטוא הבא."},"ICON-2651":{"nm":"פד שעווה למרקם הפרקט","de":"מורחים שכבת שעווה לאורך סיבי העץ, והעץ נזכר לאט בברק ששכח מזמן. כפות הרגליים כמעט מחליקות, כמעט לא - אחר צהריים שבו הבית כולו מחייך, מבריק ושבע רצון."},"ICON-2652":{"nm":"מטאטא זעיר לסדק הדלת","de":"אני צד את האבק שחי בסדק הדלת. את מה שנערם בכל פעם שהדלת נפתחת ונסגרת, אני אוסף בגוף הדק שלי. ככל שהסדק צר ועמוק יותר, כך בטוח יגיע תורי."},"ICON-2653":{"nm":"כובע רשת אבק לשטיח כניסה","de":"כדי שהאבק שבלע שטיח הכניסה לא יזלוג שוב החוצה, כובע רשת אחד עומד כשוער אחרון. האבק שהביאו נעליים מבוצות מהעולם שבחוץ מורשה להיכנס עד כאן בלבד ולא הלאה."},"ICON-2654":{"nm":"מברשת אבנית לברז","de":"מברשת קטנה מסתובבת ומקלפת את משקעי האבנית שהתמקמו בשקט על צוואר הברז. ככל שמקום נוגעים בו ידיים יותר בכל יום, כך עליו לזהור יותר. זה נימוס חדר האמבטיה ששומרת עליו המברשת הקטנה הזו."},"ICON-2655":{"nm":"כובע רשת שיער לניקוז","de":"אני תופס בשקט את השיער שנסחף לעבר הניקוז. עוצר את האסון הקטן של סתימה בכובע אחד. יומו של גיבור קטן, עגול ואיתן, זורם תמיד בשקט מתחת לרגליים."},"ICON-2656":{"nm":"מגרד רובה לאריחים","de":"את הרובה שהוכתמה בכהה בין האריחים הלבנים, מגרדים בעדינות בקצה, ומסיימים את השנים הישנות. כשהרווחים הצרים מתנקים, כל חדר האמבטיה שואף לרווחה, קליל כמו חדש."},"ICON-2657":{"nm":"סיכת ניקוי לראש מקלחת","de":"פותחים בעדינות עם קצה הסיכה את הנקבים הסתומים בראש המקלחת, והמים שרק טפטפו לנצח ניגרים שוב בעוצמה. קול המים המנצח של הבוקר, כשסתימה קטנה אחת נפתחת."},"ICON-2658":{"nm":"כוס אחסון למברשת אסלה","de":"גם מברשת אסלה נעשית היגיינית באמת רק כשהיא נחה במקום יבש. מונחת בסדר בתוך כוס קטנה שקולטת את הטיפות, היא ממתינה לתורה הבא. כבודו של כלי ניכר לא בשימוש, אלא באחסון."},"ICON-2659":{"nm":"ספוג לניקוי עובש","de":"לעובש שהתפשט שחור בפינות האריחים, האורח העיקש הזה, הספוג מציע ביציאה מנומסת. עם ניגוב אחד, חדר האמבטיה שב בהירות אל לובנו המקורי."},"ICON-2660":{"nm":"מגב לאדים על מראה","de":"מול מראה שנעכרה אחרי מקלחת, המגב מושך קו אחד ופניך הברורות חוזרות. הרגע שבו פוגשים שוב את הבעת היום שהתחבאה לרגע מאחורי האדים."},"ICON-2661":{"nm":"מתלה לכפכפי מקלחת","de":"תולים כפכפים רטובים הפוך והמים מטפטפים החוצה, הפנים מתייבשות בנוחות. שלא יהיו הרגליים של הבא בתור קרות. תשומת הלב של המתלה הקטן תמיד צעד אחד לפנים, יוצאת לקראתך."},"ICON-2662":{"nm":"נרתיק למברשת ציפורניים","de":"גם למברשת הקטנה שמנקה מתחת לציפורניים יש בית משלה. נכנסת בדיוק לתוך הנרתיק, מתייבשת ללא לחות, ומחכה לכיור הבא. הניקיון תמיד מתחיל בשקט מסידור."},"ICON-2663":{"nm":"מכסה כוס עיקור למברשת שיניים","de":"גם למברשת שיניים, שפוגשת את הפה פעמיים ביום, דרוש מקלט קטן. ברגע שמכסה כוס העיקור נסגר בנקישה, מידה אחת של ניקיון נשמרת בשקט מהלחות שנודדת בחדר האמבטיה."},"ICON-2664":{"nm":"קפסולת נסיעות לצמרי אוזניים","de":"כדי שצמרי האוזניים בתיק הנסיעות לא יישברו או יתפזרו, קפסולה אחת מחבקת אותם בעדינות. ככל שהדבר קטן יותר, כך צריך לארוז אותו מראש, כדי לא להיתפס בהפתעה בדרך זרה."},"ICON-2665":{"nm":"לוחית בדיקת אדים לנשימה","de":"נושפים \"הא\" על כף היד ומצמידים אותה קלות ללוחית הקטנה, ונשימתך נוגעת בה ומעכירה אותה בלבן חלבי. את ההוכחה החמודה ביותר שאני חי כאן ביום קר, הלוחית הקטנה הזו רושמת בלי מילים."},"ICON-2666":{"nm":"בית אחסון למקלון אוזניים","de":"כשמקלון האוזניים יוצא לטיול בתיק, הקצה שלו נוטה להתקהות בקלות. אז הוכן לו בית זעיר משלו. בפנים, שם הקצה לא ייפגע גם כשנישא, הכלי העדין ישן שנתו בשלווה."},"ICON-2667":{"nm":"קליפס קיפול למטפחת","de":"הקליפס נוגס בעדינות במטפחת שקופלה בקפידה בארבע פינותיה, ומונע ממנה להתפרק בתיק. דף אחד מקופל בסדר מעניק חן שקט בכל רגע שמוציאים אותו."},"ICON-2668":{"nm":"נרתיק פלסטרים","de":"ביום ששרטת את הברך, פותחים את הנרתיק ופלסטרים מכל מיני סוגים עומדים בשורה ומחכים לך. העדינות של להתרגש גם מפצע קטן. ערכת עזרה ראשונה תמיד צריכה להיות קרובה ליד."},"ICON-2669":{"nm":"מגבון טביעות אצבעות","de":"מנגבים את טביעות האצבעות שנשארו על הזכוכית, ועקבות היד המהוססת נעלמות. קסם קטן בגודל כף יד, שבו העולם שמעבר לחלון, שהיה מטושטש בכל מגע, נהיה שוב שקוף."},"ICON-2670":{"nm":"מחיצת מיון למחזור","de":"נייר בצד הזה, פחיות בצד ההוא. מחיצה אחת מפרידה גורל שכמעט התערבב. מחזור הוא, בסופו של דבר, לב שמפריד בקפידה, וזהו הקטע המדויק שמושך את הקו הראשון שלו בבירור."},"ICON-2671":{"nm":"את קילוף מדבקות","de":"גם מדבקה שנדבקה בעקשנות נכנעת בשקט מולי. דוחפים בעדינות את להב האת השטוח מתחת לפינה, והיא מתקלפת נקייה בלי סימן, פרידה מנצחת."},"ICON-2672":{"nm":"שיני חיתוך לנייר דבק קישוט","de":"אין צורך לחפש מספריים רק כדי להשתמש בנייר דבק. מצמידים לשיניים ומושכים, וזה נקרע נקי לאורך הסיב. החברה הכי טובה, הקטנה והזריזה, האהובה ביותר על קצות אצבעות אוהבי הקישוט."},"ICON-2673":{"nm":"תושבת מתכת לחיזוק פינה","de":"תושבת קטנה שאוחזת בחוזקה מבפנים בפינה שהתרוממה. ממקום בלתי נראה, היא שומרת בשקט על הזווית ישרה. מאחורי דברים שנראים ישרים מבחוץ מסתתר לרוב תומך נסתר כזה."},"ICON-2674":{"nm":"צינור הגנה לגיליונות מדבקות","de":"כדי שגיליונות המדבקות היקרים לא יתקמטו או ילחלחו, הם ישנים בתוך הצינור לצד קרום הגנה. לצד השמחה של האיסוף, מלווה תמיד המסירות לשמור עליו בעדינות."},"ICON-2675":{"nm":"מברשת ניקוי לחותמת דיו","de":"המברשת מטאטאת בעדינות לאורך הסיב את סדקי החותמת הרוויה בדיו, ומקלפת את הצבע הישן. יד קטנה וחרוצה שמנקה מראש, כדי שההטבעה הבאה תצא ברורה."},"ICON-2676":{"nm":"כנף אחיזה לדפי כריכה שקופים","de":"כדי שדפי הכריכה לא יחליקו החוצה, הכנפיים אוחזות בחוזקה בשני הצדדים. בזכות כל דף שנשאר במקומו, קצה האצבע שהופך עמודים לא נכנס לבלבול."},"ICON-2677":{"nm":"כף איסוף לחלקיקי קישוט","de":"אוספים בתנועה אחת את פיסות הקישוט הזעירות והמפוזרות בעזרת הכף הקטנה. כשהטרחה של ללקט אותן אחת אחת נעלמת, זמן היצירה בקפידה נעשה משמח עוד יותר."},"ICON-2678":{"nm":"מהדק ציצית לסימנייה","de":"כדי שהציצית בקצה הסימנייה לא תתרופף, המהדק קושר אותה בחוזקה. גם מדריך שמוביל בחזרה לעמוד שנקטע באמצע, נרגע רק כשמראהו שלו מסודר."},"ICON-2679":{"nm":"קליפס מכסה לעט קישוט","de":"קליפס שסוגר בחוזקה את המכסה כדי שקצה עט הקישוט לא יתייבש. הוא מונע את התקלה של עט שנשאר פתוח בהיסח הדעת ומתקשה, כך שהצבע תמיד זורם רענן כמו בפעם הראשונה."},"ICON-2680":{"nm":"ראש חילוף למברג","de":"משאירים את ידית המברג כמו שהיא, ומחליפים רק את הראש בקצה. פיליפס או שטוח, בלי בעיה. הפיקחות של לבצע משימות רבות עם כלי אחד ארוזה בקפידה בקצה הראש הקטן הזה."},"ICON-2681":{"nm":"עטיפת נייר זכוכית לפינה","de":"עוטפים את המשטח המחוספס בעיגול ואוחזים בו, וכף היד הופכת לכלי עבודה. חריקה, חריקה - עם כל דחיפה לאורך הסיב, הפינה הדוקרנית מתעגלת, וההחלקה האחרונה תמיד מזוהה על ידי קצות אצבעות האדם."},"ICON-2682":{"nm":"משפך למיון ברגים","de":"ברגים מפוזרים עוברים דרך הצוואר הצר ומתאספים, מתגלגלים, למקום אחד. הצליל של דברים קטנים שהתגלגלו על השולחן ומוצאים את מקומם - זו תחושה שגם לב מבולגן מסתדר בסדר מחדש."},"ICON-2683":{"nm":"וו קצה לסרט מדידה","de":"הווו בקצה סרט המדידה הוא היד השנייה של מי שעובד לבד. תולים אותו על פינה, והסרט לא מתנודד, ובאורך שנמדד היד - והלב - נעשים ישרים יותר."},"ICON-2684":{"nm":"כיסוי לידית מפתח ברגים","de":"שכבה שנוספה על ידית המתכת הקרה. ברגע שאוחזים בה, במקום קור נוגע חום רך. כלי עבודה נשאר לאורך זמן לצד מי שמחזיק בו כשהוא חושב עליו קודם כול."},"ICON-2685":{"nm":"כובע הגנה למרצע","de":"כובע קטן מולבש על כל קצה חד. ההקלה של לחפש במגירה בלי להידקר - ככל שדבר חד יותר, כך עוטפים אותו בקפידה רבה יותר, ואף אחד לא נפגע."},"ICON-2686":{"nm":"להב קילוף בידוד לחוט","de":"מקלפים רק את הבידוד הדק, בלי לפגוע בחוט הפנימי. ברגע שמשחררים בעדינות שכבה אחת וגדיל הנחושת מבריק לעין, להב טוב יודע בדיוק היכן לעצור."},"ICON-2687":{"nm":"מנגב לחלון בועה של פלס","de":"רק כשבועה אחת נעצרת בדיוק במרכז, יש אופקיות אמיתית. לנגב את החלון הקטן צלול דומה להכנה השקטה של איזון הנשימה לפני משיכת קו."},"ICON-2688":{"nm":"שרוול הגנה לאצבע במסמור","de":"שרוול קטן שעוטף בחוזקה את האצבע האוחזת במסמר. גם אם הפטיש יחטיא זה בסדר, אז הכה בלי פחד - הוא הכין את עצמו בקפידה לקבל את המכה במקום האצבע."},"ICON-2689":{"nm":"משטח נגד החלקה לקערת האכלה","de":"שכבת גומי שתומכת בקערה שלא תחליק על הרצפה. בלי שהקערה תברח באמצע ארוחה נלהבת, שלוות הארוחה מתחילה במקום שלא מתנדנד."},"ICON-2690":{"nm":"מתלה לכף מזון","de":"תולים על הקיר את הכף שמגישים בה את המזון, לייבוש קליל. סדר קטן שמקבל את היד באותו מקום בכל ארוחה - שיש פה לדאוג לו, זה דבר כה חם."},"ICON-2691":{"nm":"צלחת גלישה לקערת מים","de":"קולטת בשקט את הלגימה שגלשה מעל שולי קערת המים. בזכות הצלחת הרחבה שמחבקת מראש שהרצפה לא תירטב, הקרקע מתחת לרגליים תמיד יבשה ונוחה."},"ICON-2692":{"nm":"מלקחיים לחלוקת חטיפים","de":"מלקחיים שמרימים בדיוק חטיף אחד ומגישים אותו. גם מול פה קטן שממתין באף שלוח קדימה, יש בחלוקה קצה אצבע עדין שאינו יוצא משליטה."},"ICON-2693":{"nm":"קליפס גלגול לשקית מזון","de":"מלחציים קטנים שגוללים ונוגסים בפתח שקית מזון שנפתחה. עם נקישה אחת של סגירה, הלחות נחסמת, וחופן הפריכות של מחר בבוקר נשמר בשלמותו."},"ICON-2694":{"nm":"פקק זרבובית לבקבוק מים","de":"פקק שמתאים בדיוק לזרבובית הבקבוק. טיפה, טיפה - הטפטוף נעצר וההיקף מתייבש. מה שנסתם היטב לא דולף, ונשאר צלול לאורך זמן."},"ICON-2695":{"nm":"כוס מידה למנת מזון","de":"מודדים בדיוק כוס אחת לפי הסימון. לא יותר מדי ולא מעט מדי - ביד ששוקלת את הארוחה של היום בהגינות, היום של בן המשפחה הקטן ארוז בדיוק כמו שצריך."},"ICON-2696":{"nm":"שוליים למחצלת שפיכת מזון","de":"שוליים שמונעים מהמזון שנשפך לחצות את המחצלת. שפה אחת שהורמה מעט אוספת בקפידה את הפירורים שכמעט התפזרו."},"ICON-2697":{"nm":"טבעת הפרדה לקערות מוערמות","de":"טבעת קטנה שמפרידה בעדינות שתי קערות שנדבקו זו לזו. היד שהתאמצה מולן, דבוקות חזק, נעשית קלה. גם להפריד היטב, מתברר, הוא סוג של טיפול עדין."},"ICON-2698":{"nm":"משפך איסוף כדורים לחצר","de":"משפך שאוסף למקום אחד את הכדורים שהתגלגלו ברחבי החצר. בערב אחרי סבב משחקים סוער, היד שמכנסת את מה שהתפזר כאן ושם עולה מאליה בזיכרון."},"ICON-2699":{"nm":"כובע לעמוד גדר","de":"מלבישים כובע עגול על כל עמוד גדר. שלא ייבקעו הקצוות ברוח ובגשם, לב שדואג ומכסה אפילו את הדבר הקטן ביותר חילחל לכל רחבי החצר."},"ICON-2700":{"nm":"וו קיפול למנהרת משחק","de":"וו לקיפול מסודר של מנהרת המשחק ולתלייתה. מקפלים היטב יום שהתלכלך באדמה ותולים אותו, ומשחק שמסודר היטב מבטיח בלי כשל את המחר."},"ICON-2701":{"nm":"כרית לאחיזת חבל משיכה","de":"כרית שעוטפת ברכות את ידית חבל המשיכה. גם כשמושכים בכל הכוח, כף היד לא נשרטת. ככל שאוחזים בה זמן רב יותר, כך היד נשארת נוחה - וזאת בזכות תשומת לב קטנה של מישהו."},"ICON-2702":{"nm":"אבזם ליריעת צל בחצר","de":"אבזם שמחזיק חזק את יריעת הצל הפרושה בחצר. גם צינת הצהריים צריכה להיאחז במקום כדי להישאר. מתחת לצל שהאבזם שומר מתוח, אחר צהריים עצל נמתח ונח לאורך זמן."},"ICON-2703":{"nm":"נרתיק ללהב את","de":"נרתיק שמחליקים בעדינות על להב את החפירה. תנו לו לנוח אחרי יום עבודה קשה, והוא יישאר חד - מוכן לפגוש שוב את אדמת האביב הבא."},"ICON-2704":{"nm":"מדרון לגלגול כדור","de":"מדרון קטן שכדור מתגלגל בו למטה בעליזות. לאורך השיפוע העדין, הכדור דוהר בהתלהבות. שיפוע קטן אחד יוצר יום שלם של שמחה."},"ICON-2705":{"nm":"טבעת בריח לשער הגדר","de":"טבעת בריח שנועלת את שער הגדר. בקליק הקטן של הנעילה, הלב נרגע. שער אחד שנסגר היטב שומר על חצר קטנה כעל עולם שלם בפני עצמו."},"ICON-2706":{"nm":"חוט עם פעמון משחק","de":"נענעו בעדינות את החוט עם הפעמון התלוי, וקול צלול מתפשט. צלצול, צלצול - חדר שקט מתעורר לפתע, ומצליל קטן אחד הלב כולו זוקף אוזניים."},"ICON-2707":{"nm":"מגש ניקוז לעציץ","de":"צלוחית שקולטת בשקט את המים שחלחלו מתחת לעציץ. היא סופגת את העודף כדי שאדן החלון יישאר יבש. גם מסירות, כשהיא גולשת על גדותיה, זקוקה למקום שיקלוט אותה."},"ICON-2708":{"nm":"את קטן לשתילת נבטים","de":"את קטנה להעברת נבטים רכים אל האדמה ולנעיצתם בעדינות. בקצות אצבעות שמיישבות כל נבט בזהירות, אביב ירוק מרים ראש אפילו בערוגה בגודל כף יד."},"ICON-2709":{"nm":"סיכת סימון לערוגה","de":"סיכת סימון שכותבים עליה ונועצים בכל ערוגה כדי לציין מה נשתל. מעל אדמה שעדיין לא נבט בה דבר, תווית שם קטנה זוכרת בשקט מה עתיד לצמוח."},"ICON-2710":{"nm":"רשת לפיית משפך השקיה","de":"רשת עדינה המותקנת על פי משפך ההשקיה. המים שנשפכו פעם בזרם אחד מתפזרים כעת לגוונים רבים כמו טפטוף עדין. רק זרם רך שומר על עלים רכים מפגיעה."},"ICON-2711":{"nm":"מהדק לקיבוע גבעול לתמיכה","de":"מהדק שמצמיד בעדינות גבעול מתנדנד אל מוט התמיכה שלו. סיוע שאול לרגע, עד שהדבר הרך עדיין יוכל לעמוד זקוף - לצמיחה דרוש משען כזה."},"ICON-2712":{"nm":"קליפס לאיטום שקית זרעים","de":"קליפס שנועל היטב שקית זרעים שנותרה. סוגרים בקליק, ואף גרגר לא נמלט. הבטחה קטנה לאביב הבא שוכנת בלחיצה אחת קטנה זו."},"ICON-2713":{"nm":"כפית מדידה לאדמה ולדשן","de":"כפית קטנה למדידת הכמות המדויקת של אדמה ודשן. לא יותר מדי ולא פחות מדי - כפית אחת מדודה. רק בכמות מדויקת האדמה סוף סוף עושה את עבודתה."},"ICON-2714":{"nm":"וו תלייה לעציץ","de":"וו תלייה שמרחף בעדינות עציץ באוויר. הירוק המורם קרוב יותר טפח אל השמש והרוח. גינה קטנה צפה לה ליד החלון."},"ICON-2715":{"nm":"רשת מגן לנבטים","de":"רשת כיסוי שמצלה בעדינות על נבטים שזה עתה נבטו. עד שהעלים הרכים עוד יוכלו לשרוד את הקור הראשון ואת השמש החזקה, הדבר השביר ביותר הוא הראשון לזכות בטיפול."},"ICON-2716":{"nm":"תלייה למסרק טיפוח","de":"מקום שבו מנערים בעדינות שיער תלוש מהמסרק ותולים אותו מסודר. המסרק המסודר והריק ממתין למגע הבא. סדר תמיד מתחיל בהרגל הקטן של הטיפול בכלים."},"ICON-2717":{"nm":"טבעת אנטי-החלקה לקערת רחצת רגליים","de":"טבעת שתומכת בקערת רחיצת הרגליים כדי שלא תחליק. כשהקערה יציבה מתחת לרגליים קטנות ומתיזות, גם ידיים רוחצות וגם לב רוחץ אינם מתנדנדים."},"ICON-2718":{"nm":"וו לרצועת טיולים","de":"וו יחיד לתלות עליו את רצועת הטיול ליד הכניסה. במקומו לצד הדלת, ההיכון ליציאה תמיד ממתין. ברגע שהרצועה יורדת, צעד קטן נרגש יוצא איתה לדרך."},"ICON-2719":{"nm":"כיסוי מגן לגזיזת ציפורניים","de":"כיסוי מגן ששומר על הבשר הרך בזמן גזיזת הציפורניים. רק כשיש גבול בטוח שמסומן בדיוק עד כאן, גם היד האוחזת במספריים נשארת רגועה ויציבה."},"ICON-2720":{"nm":"רצועת מדידת חום למי אמבטיה","de":"רצועה שצפה במי האמבטיה ומודיעה על הטמפרטורה שלהם. ההרגל הישן של טבילת גב היד כדי לאמוד את החום המתאים, צף שם כעת, מתורגם בבירור לפס צבע אחד."},"ICON-2721":{"nm":"מגלגלת סרט דביק להסרת שיער","de":"שערה לבנה אחת על בגד שחור נראית הכי גדולה רגע לפני העלייה לבמה. בעקבות קול הגלגול, שברירי היום עוברים אחד אחד אל הנייר הדביק. ניקיון מושלם כך, פס אחר פס, בדיוק כמה שמקלפים."},"ICON-2722":{"nm":"מלקחיים לשקית פסולת בטיול","de":"בסוף שביל הטיול, יש רגע עדין של רכינה. אוחזים שקית בקצה המלקחיים, והידיים נשארות נקיות והלב קליל. בהליכה משותפת טמון גם נימוס קטן של דאגה למה שנשאר מאחור - והמלקחיים האלה יודעים זאת ראשונים."},"ICON-2723":{"nm":"שולי שטיחון הכניסה","de":"קצה שטיחון הכניסה הוא ברכת השלום הראשונה שהרגל פוגשת. עצרו כאן את בהונות הרגל הרטובות פעם אחת, והרצפה בפנים נשארת יבשה. המקום הנמוך מכולם, שמנגב ומקבל בברכה בלי מילה כל מי שנכנס."},"ICON-2724":{"nm":"חוט קשירה לפעמון טיפוח","de":"אפילו לחיבור פעמון אחד יש סדר. כרכו את החוט פעמיים והעבירו פעם אחת, וקול צלול מתגלגל אחרי כל צעד. טיפוח, בסופו של דבר, הוא הלב שלעולם לא מדלג על נגיעת סיום קטנה זו."},"ICON-2725":{"nm":"כיס ניקוז למטריה מתקפלת","de":"בלובי אחרי שהגשם נפסק, טיפות מים מנקדות את הרצפה מקצה מטרייה מקופלת. כיס אחד קולט אותן בשקט, ורגליים של איש אינן מחליקות. אדיבות בדרך כלל שומרת קרוב כך, בלי קול."},"ICON-2726":{"nm":"מהדק רצועה לתיק","de":"תיק שתלוי על כיסא ממשיך לגלוש למטה לאט לאט. תפסו אותו פעם אחת עם מהדק הרצועה, ושתי הידיים משתחררות מהדאגה שהוא ייפול. הנחת היציאה מתחילה כשאפשר לשכוח את המשא לרגע."},"ICON-2727":{"nm":"כיס בד לחממן ידיים","de":"בסמטה שרוח קרה נושבת בה, שקית בד בכיס מעבירה בשקט חום אל כף היד. שכבה רכה שעוטפת את הדבר החם ומחממת אותו במידה בדיוק הנכונה. חום החורף תמיד מגיע דרך יריעת בד אחת."},"ICON-2728":{"nm":"מעמד למראה מתקפלת","de":"פותחים, ומראה קטנה נוטה ומוצאת את זווית שלה. כדי שתוכלו להביט בפניכם בלי להחזיק אותה, המעמד עומד במקומכם. גם ברגע הקצר של תיקון המראה החיצונית, שחקן משנה נאמן אחד נמצא לצדכם."},"ICON-2729":{"nm":"מכסה למגבונים לחים לנסיעה","de":"הדף הראשון של המגבונים הלחים תמיד היה בתהליך התייבשות. סגרו את המכסה בקליק, והלחות נשארת עד הדף האחרון ממש. לשמור שתמשיכו להשתמש עד הסוף - סוד משק בית שמחזיק מעמד זמן רב מסתתר בדברים קטנים כאלה."},"ICON-2730":{"nm":"מחיצה למטבעות בארנק","de":"כשמטבעות מתפזרים בין השטרות, תור הקופה תמיד נעשה עמוס. מחיצה אחת אוספת את העגולים לצד אחד, וקצות האצבעות מפסיקים לגשש. סידור הוא מלאכת הענקת מקום ושם לכל דבר."},"ICON-2731":{"nm":"נרתיק מתקפל למסכה לנסיעה","de":"כשמקפלים אותה פנימה, המסכה לא מתקמטת גם בתוך התיק. נרתיק שמחזיק בנקיון דף אחד שהוסר לרגע. הרגל עדין אחד של שמירה מסודרת לשימוש הבא נאסף כאן."},"ICON-2732":{"nm":"כיסוי שיניים למסרק נסיעות","de":"שיני מסרק בתוך תיק היו נוטות לשרוט חפצים אחרים. כשחובשים את כיסוי השיניים, גם המסרק בטוח וגם החפצים שנארזו לצדו שלמים. מי שדאג פעם לחפציו יודע ששכבת הגנה קטנה אחת שומרת על שני הצדדים."},"ICON-2733":{"nm":"קליפס לחלוקת מגירה","de":"בכל פעם שהמגירה נפתחה, חפצים מעורבבים נשפכו כמו אנחה. חלקו אותה למדורים עם קליפס אחד, והדברים הקטנים סוף סוף מוצאים את אזורם שלהם. מגירה מסודרת משנה בשקט את מצב הרוח של כל בוקר."},"ICON-2734":{"nm":"מעמד תצוגה למטבע","de":"העמידו מטבע ישן אחד, והוא הופך בעצמו לתערוכה קטנה. המעמד תומך בו באלכסון ומציג בבירור את תבליט הפנים. להעלות זמן שחוק לגובה העיניים - כאן מתעמק עונג האספנות."},"ICON-2735":{"nm":"סליל לכריכת אוזניות","de":"היו בקרים שחצי מהם התבזבז על התרת חוטי אוזניות מסובכים. כרכו אותם מסודר סביב סליל הכריכה, ובפעם הבאה שתוציאו אותם הם יהיו חלקים. סידור קטן הופך למתנה שקטה שמעניקים בחשאי לעצמכם של מחר."},"ICON-2736":{"nm":"וו קיר לכבל טעינה","de":"כבל טעינה שהשתרך על הרצפה נדרך שוב ושוב. הדביקו וו אחד לקיר לתלות אותו, והשולחן נראה מרווח בהרבה. לרסן בלגן זה לא עניין גדול - זה מקום קטן, לא גדול מציפורן אחת."},"ICON-2737":{"nm":"מעמד לשלט רחוק","de":"לשלט שנעלם שוב ושוב בין כריות הספה יש סוף סוף בית לחזור אליו. העמידו אותו במעמד, ואין עוד חיפוש נואש, ואין עוד ישיבה עליו בטעות. שיהיה מקום קבוע הופך למנוחה קטנה גם עבור חפץ."},"ICON-2738":{"nm":"מהדק תלייה לזרוע משקפיים","de":"משקפיים שהונחו תמיד החליקו בשקט למקום כלשהו. תלו זרוע אחת בעדינות על המהדק, והעדשות לעולם לא נוגעות ברצפה. הרצון לשמור עליהן ללא שריטות עד מחר טמון בתלייה קטנה זו."},"ICON-2739":{"nm":"מהדק מיון למחזיק מפתחות","de":"ככל שצרור המפתחות מכביד, כך מיטשטש איזה מפתח שייך לאיזו דלת. אגדו אותם עם מהדק מיון, וקצות האצבעות לבדם יודעים לזהות כל זוג. מדריך שקט שמעניק סדר בלי מילים לדלתות שנפתחות ונסגרות בכל יום."},"ICON-2740":{"nm":"מהדק מעמד לפתקים","de":"פתקים שנכתבו נטו להתהפך על השולחן. כשהמהדק מחזיק את הנייר זקוף, האותיות מביטות ישר בעיניים. דרך לגרום לשורה אחת שאסור לשכוח לחיות במקום שתמיד נראה."},"ICON-2741":{"nm":"מעמד לעט זקוף","de":"כמה פעמים כפפתם את הגב כדי להרים עט שהתגלגל? נעצו את קצהו במעמד והעמידוהו, והמרחק עד השורה הבאה מתקצר בטפח. תחנת המתנה קטנה, תמיד ערה, לצד מי שכותב."},"ICON-2742":{"nm":"בסיס היפוך לשעון חול","de":"כשהחול בשעון החול נגמר, מישהו צריך להפוך אותו כדי שיחיה מחדש. הבסיס קולט את רגע הגרגר האחרון ההוא ומעמיד אותו מחדש בחלקה. המגע שמחזיר את הזמן להתחלה שוכן כאן, על פיסת עץ קטנה."},"ICON-2743":{"nm":"תפוח אדמה אפוי בחמאה","de":"חמאה נמסה לאט מעל תפוח אדמה שנאפה עם קליפתו. כשהגרגיר הזהוב חודר עם האדים, הבשר התפוח קולט בשקט את הטעם העשיר. הרגע שבו ירק שורש ספוג ריח אדמה נהיה החם ביותר."},"ICON-2744":{"nm":"תירס צלוי בחמאה","de":"גרגרים צהובים שורה אחר שורה מצליפים על הגריל. פיסת חמאה מחליקה מעליהם וניחוח מתוק מיד עולה. מתיקות שדה קיץ מועברת ישירות אל ביס אחד."},"ICON-2745":{"nm":"וופל","de":"בכל משבצת קטנה במרקם, סירופ ממתין בשקט להצטבר. פריך בחוץ, תפוח בפנים - נגסים ביס אחד ואד חם משתחרר. המשבצות המרובעות כמו כלי שמחלק אושר קטן."},"ICON-2746":{"nm":"פנקייק","de":"אני זוכר את הריח ההוא של בצק שתופח זהוב על המחבת. מעל העוגות העגולות שנערמו שכבה על שכבה, החמאה שוקעת ונמסה. צלחת רכה שמותרת בחשאי רק בבוקר רגוע."},"ICON-2747":{"nm":"שוקולד","de":"פיסה אחת בפה נמסה לאט במגע חום הגוף. המתיקות שמתפשטת בסוף המרירות משחררת בעדינות את מתח הלב. ביום מייגע, פיסה חומה קטנה של נחמה שמוציאים מהכיס."},"ICON-2748":{"nm":"עוגת תות","de":"תותים אדומים יושבים על קצפת לבנה ומבשרים את האביב ראשונים. כשהמזלג חוצה את החתך הרך, ניחוח חמצמץ פורח בעדינות. ביום שיש בו סיבה לחגוג, הכוכב העדין שמוצב במרכז השולחן."},"ICON-2749":{"nm":"עוגת גבינה","de":"פרוסה כבדה מתמוטטת בעושר על הלשון. הטעם המלוח בסוף אוחז ביד את המתיקות ומזמין ביס נוסף שוב ושוב. קינוח שאוהבי עושר סמיך מטעימים בשקט."},"ICON-2750":{"nm":"עוגיות בננה","de":"ריח בננה מרוסקת מבשיל לצבע זהוב בתוך התנור. נגסים ביס אחד ומתיקות רכה מתפשטת בכל הפה. הרגע החם שבו פרי בשל היטב נולד מחדש כעוגייה."},"ICON-2751":{"nm":"עוגיות שוקולד צ'יפס","de":"שבבי השוקולד בבצק נמסים בעושר בזמן האפייה. שוברים אותה בעודה חמה וחום כהה נמרח על קצות האצבעות. עם כוס חלב, הפיסה שהופכת אחר צהריים לעדין קצת יותר."},"ICON-2752":{"nm":"עוגיות פירורי קקאו","de":"פירורי קקאו כתושים דק פוצחים בין הבצק. מרירות עמוקה ולא מתוקה מרגיעה בשקט חך של מבוגר. עוגייה קצת רצינית ששומרת על הניחוח הגולמי בדיוק כפי שהיה לפני העיבוד."},"ICON-2753":{"nm":"טוסט גבינה","de":"הגבינה נמתחת ארוכה כחוט מעל לחם קלוי לזהוב. הפריכות מבחוץ והעושר מבפנים מתקפלים יחד בביס אחד. הארוחה הפשוטה והעדינה ביותר, שממלאת בוקר מאוחר בשובע חם."},"ICON-2754":{"nm":"כריך","de":"בין שתי פרוסות לחם, מסירות של יום שלם נדחסת שכבה אחר שכבה. נגסים, והטעמים הערומים זה על זה מברכים לשלום בבת אחת. שולחן אוכל קטן על כף היד, מוכן להילקח לכל מקום."},"ICON-2755":{"nm":"טוסט צרפתי","de":"לחם שהושרה היטב בביצה טרופה מזהיב על המחבת. הקצוות שתפחו עם ריח החמאה מתקשים לפריכות ראשונים. הוסיפו קו סירופ אחד ואפילו לחם רגיל הופך למותרות של יום חופש."},"ICON-2756":{"nm":"ראמן פטריות","de":"ניחוח פטריות עמוק עולה עם האד מעל המרק הרותח. מרימים כובע פטרייה סמיך אחד ומתיקות ספוגת אדמה מתפשטת בפה. קערה קצת מיוחדת שממלאת את הבטן בניחוח לפני האטריות."},"ICON-2757":{"nm":"ראמן מוקפץ","de":"על אטריות ללא מרק, תיבול חריף עוטף בברק שמנוני. מרימים במקלות אכילה וניחוח מעושן ועשיר מתפשט בין האדים. כשמתגעגעים לארוחה מהירה ועשירה, החבר האמין ביותר."},"ICON-2758":{"nm":"ראמן גבינה","de":"מניחים פרוסת גבינה מעל אטריות חמות והיא מתמוטטת ונמסה לאט. מרק חריף פוגש עושר רך והקצוות מתעגלים. קערה שמתאימה בדיוק לערב שרוצים בו לרכך קצת את העוקצנות."},"ICON-2759":{"nm":"ראמן קארי","de":"ניחוח קארי עשיר מתלפף סביב האטריות ושולח אד צהוב מעלה. לוגמים ביס רועש אחד וחום חריף מחמם מבפנים. אטריות של גיוון משמח, שמוסיפות ניחוח קצת זר למרק מוכר."},"ICON-2760":{"nm":"ראמן פירות ים","de":"מעל מרק ספוג ניחוח ים, שרימפס וצדפות צפים שמנמנים למעלה. עושר רענן ועמוק כאחד חודר בין האטריות. קסם קטן שמביא ריח מלוחית לתוך קערה אחת בלי ללכת רחוק."},"ICON-2761":{"nm":"קימבאפ צנון כבוש","de":"כשצנון כבוש צהוב במרכז ואורז מקיף אותו בעיגול, יריעת חצילית ים אחת קושרת את כולם באהבה לגליל אחד. עם שחר יציאה לטיול, הארוחה הכנה ביותר שנולדת על קרש החיתוך."},"ICON-2762":{"nm":"קימבאפ טונה","de":"ברגע שכפית טונה מעורבבת במיונז מחלחלת בין גרגרי האורז, ארוחה נעשית חמה דיה גם תחת אור ניאון מאוחר של חנות נוחות. הנחמה שידיים עסוקות שולפות הכי הרבה."},"ICON-2763":{"nm":"סלט פירות","de":"צבעים שנאספו בעונתם נפגשים לראשונה בקערה אחת. איך אדום, ירוק וצהוב מסתדרים בלי לריב - הפרי מראה זאת רק אחרי שנחתך ונאסף יחד."},"ICON-2764":{"nm":"סלט עוף","de":"חזה עוף צלוי בפשטות מונח מסודר מעל ירקות עלים ירוקים. על שולחנו של מי שמתכונן לבמה של מחר, תמיד מונחת צלחת מסודרת כזו."},"ICON-2765":{"nm":"סלט עגבניות ומלפפונים","de":"עגבניות בשלות ומלפפונים פריכים מתובלים חמצמצים ורעננים. בצהריים עמוס בקול צרצרים, ביס אחד במקלות אכילה, והקיץ מתקרר בו בקצב אחד."},"ICON-2766":{"nm":"סלט חסה","de":"שוטפים עלים שזה עתה נקטפו מהגינה במים קרים, וקצות האצבעות מתעוררים צוננים. הרגע שבו הירק הכי שכיח תופס את המושב הירוק והרענן ביותר על השולחן."},"ICON-2767":{"nm":"סלט תירס","de":"בכל פעם שגרגר מתוק מתפוצץ, שדה קיץ שטוף שמש נפרש לנגד העיניים. גם בתוך קערת סלט, התירס הצהוב לעולם לא שוכח את השמש שלו."},"ICON-2768":{"nm":"קולסלו","de":"כשכרוב קצוץ סופג רוטב חמוץ-מתוק, הפריכות שלו מתרככת מעט. מעלת התוספת: מוצבת לצד כל מנה עיקרית, לעולם לא מתחרה על תשומת הלב וממלאת את חלקה בנאמנות."},"ICON-2769":{"nm":"סלט שרימפס בליים","de":"סוחטים מעט ליים, ומתיקות השרימפס מתעוררת חדה יותר. טיפה חמוצה אחת נופחת חיים בכל הצלחת - נגיעת סיום קטנה אך מכרעת."},"ICON-2770":{"nm":"המבורג סטייק","de":"קציצת בשר עבה מתבשלת לזהוב על פלטה לוהטת. המיץ שנוזל ברגע שסכין נוגעת בה - הארוחה האהובה ביותר לאורך זמן, בין בישול ביתי לאוכל מערבי."},"ICON-2771":{"nm":"פיצה","de":"את הביס ההוא שהגבינה נמתחת בו ארוכה, חולקים מיד ליד בין רבים שיושבים סביב. רק כשפורסים פשטידה עגולה יחד, מפגש הופך סוף סוף למפגש אמיתי."},"ICON-2772":{"nm":"פסטה קרם פטריות","de":"ריח האדמה העמוק של הפטריות ורכות הקרם מחבקים כל חוט אטריות בנפרד. בערב עם קול גשם עדין, הניחוח העשיר מתפשט לאט עד תחתית הצלחת."},"ICON-2773":{"nm":"פסטה שרימפס","de":"שרימפס שמנמן מוקפץ קלות בשמן זית ומעורבב עם האטריות. כשמליחות הים פוגשת פשטות האטריות, ערב שגרתי הופך קצת מיוחד."},"ICON-2774":{"nm":"פסטה בשמן","de":"שום, שמן ואטריות - שלושה דברים בלבד. יש טעם שנהיה בהיר יותר ככל שמורידים ממנו, ואליו אוליו מוכיחה זאת בשקט, בלי שום עודף."},"ICON-2775":{"nm":"פסטה צדפות","de":"המרק שהצדפות משחררות כשהן פותחות את קונכייתן חודר עמוק לכל חוט אטריות. ניחוח לגימת יין לבן אחת נשאר על הצלחת זמן רב, כמו יום אביב שלא דוהה."},"ICON-2776":{"nm":"פסטה קרם","de":"כשקרם עשיר מחבק בשקט את האטריות, פינה בלב מתחממת כבר מהביס הראשון. הנחמה שהרכות מציעה, שמתעמקת עוד יותר ביום סוער."},"ICON-2777":{"nm":"פסטה עגבניות","de":"רוטב עגבניות שהתבשל זמן רב מתפשט אדום מעל האטריות. כשהמתיקות והחמיצות מצטמצמות לאט ומוצאות סוף סוף איזון, הצלחת הבסיסית ביותר היא גם הכי אמינה."},"ICON-2778":{"nm":"אומוריסו","de":"ביצה רכה מכסה בעדינות אורז חם כמו שמיכה. אם רושמים אפילו שם אחד עליו בקטשופ, שולחן היום ההוא הופך למכתב קטן שמישהו מסר."},"ICON-2779":{"nm":"סלמון צלוי","de":"צולים לאט מול האש עד שהעור נהיה פריך. חוט אד עולה כשהבשר הוורוד מתפרק לאורך סיביו - סבלנות תמיד זוכה לגמול כן מהסלמון."},"ICON-2780":{"nm":"ברוסקטה","de":"ערמים עגבניות קצוצות ובזיליקום בשפע על לחם קלוי פריך. הקלילות של להרים ביד ולנגוס ביס אחד פותחת בחום את ברכת השלום הראשונה של מפגש."},"ICON-2781":{"nm":"שייק מנגו","de":"טוחנים מנגו בשל למרקם עדין ומערבבים קריר עם קרח. כשטיפות מים מתעבות על הכוס הצהובה, אחר צהריים עייף של אמצע קיץ מתמלא עד קצה הקשית."},"ICON-2782":{"nm":"לימונדה","de":"מוסיפים לימון סחוט טרי, סוכר ומים קרים, ומנערים בכוס. כשהחמיצות הצהובה גולשת קרירה במורד הגרון, אפילו החום העז נכנע לרגע."},"ICON-2783":{"nm":"חלב תות","de":"כשמערבבים תות מרוסק בחלב, ענן ורוד שוקע לאט בתוך הכוס. ההתרגשות בקצות האצבעות של פתיחת דלת המקרר בילדות נשמרת שלמה בכוס אחת."},"ICON-2784":{"nm":"חלב בננה","de":"משקה שהוא כבר תקופה שלמה של זיכרון רק בצורתו העגולה של הצנצנת הקטנה. הזיכרון הצהוב של תקיעת קשית על ספסל בבית מרחץ שב לחיים בחום עם כל לגימה."},"ICON-2785":{"nm":"חלב אוכמניות","de":"מכניסים גרגרים סגולים ומועכים אותם, והחלב הלבן נצבע לתכלת עדינה. חופן אחד קטן של אותו פרי משנה כוס שלמה לצבע חדש לגמרי."},"ICON-2786":{"nm":"מיץ פירות","de":"סוחטים כמה פירות יחד, וזה הופך לטעם שאי אפשר לקרוא לו בשם אחד בלבד. מקהלה קטנה של מתיקויות, שמתערבבות ותופחות לעושר רב יותר."},"ICON-2787":{"nm":"קקאו","de":"ליד חלון מושלג, אוחזים ספל חם בשתי ידיים בשקט. ספל חום עם אדים מיתמרים מחמם לאט, מקצות האצבעות ועד הלב."},"ICON-2788":{"nm":"קפה","de":"תמיד הכוס הזאת היא שמדליקה את האור בחדר החזרות של השחר. כשהניחוח המריר דוחק בשקט את הנמנום, עוד יום של במה מתחיל, כך, בשקט."},"ICON-2789":{"nm":"סושי סלמון","de":"אוחזים את האורז ביד, אומדים את הקו העדין ההוא בין נוקשות לרכות. ברגע שפרוסת סלמון דקה שוכבת בעדינות מעליו, ביס אחד הופך להשלמת מסירות קטנה."},"ICON-2790":{"nm":"דייסת דלעת מתוקה","de":"מבשלים דלעת צהובה עד שהיא רכה ומועכים אותה חלק. עם כל כפית שנכנסת, שמש הסתיו נמסה חמה בפה. הדייסה שעולה ראשונה במחשבה כשחולים."},"ICON-2791":{"nm":"קארי דגים","de":"בשר דגים שהתבשל קלות בתבלינים מתפורר רך בתוך הקארי. הוסיפו את מרקם הים לקערה מוכרת, וערב שגרתי יוצא למסע רחוק טפח נוסף."},"ICON-2792":{"nm":"שרימפס מטוגן","de":"הרגע הקצר של אחיזה בזנב, ציפוי בבלילה והשלכה לשמן רותח הוא שם ההכרעה. שרימפס לבוש בבלילה זהוב זורח הכי בהיר כשאוכלים אותו לפני שהפריכות מתקררת."},"ICON-2793":{"nm":"קלמארי מטוגן","de":"טבעות עגולות תופחות שמנמנות בתוך השמן הלוהט. הביס ההוא, שבו הפריכות עוטפת את הלעיסות, מתאים ביותר תחת האור הצהוב של דוכן רחוב."},"ICON-2794":{"nm":"עוף צלוי","de":"מורחים תיבול וצולים לאט מול האש עד שהעור נוצץ בברק. מנה שהטעם שלה נקבע בכוונון אחד של האש - הפשוטה ביותר, ודווקא בגלל זה הכנה ביותר."},"ICON-2795":{"nm":"חזיר מוקפץ עם קימצ'י","de":"מקפיצים יחד קימצ'י בשל ובשר חזיר, והחמיצות מבשילה למתיקות. מנה שקוראת מעצמה לקערת אורז לבן - השותפה האמינה ביותר על השולחן הקוריאני."},"ICON-2796":{"nm":"חזיר מוקפץ","de":"מקפיצים מהר על אש חזקה עד שהחוץ נצלה פריך. כשריח שמן עשיר ממלא את המטבח, תפריט הערב כבר הוכרע בלי לשאול פעם נוספת."},"ICON-2797":{"nm":"בקר מוקפץ עם פטריות","de":"מקפיצים יחד פטריות ריחניות ובשר בקר, וטעמו של כל אחד מתעמק. ארוחת סתיו מסודרת שבה אדמה ושדה לוחצים ידיים בשקט על צלחת אחת."},"ICON-2798":{"nm":"דאק-גלבי בגבינה","de":"ממיסים גבינה בשפע מעל דאק-גלבי חריף ומותחים אותה ארוכה. כשרבים מתיישבים סביב פלטה לוהטת במרכז, אפילו החריפות העוקצנית מתפוגגת בצחוק."},"ICON-2799":{"nm":"תבשיל קימצ'י","de":"ככל שהקימצ'י מיושן יותר, כך הוא מעניק מרק עמוק ועשיר יותר. יושבים פנים אל פנים מול סיר חרס רותח, ומילה כמו \"משפחה\" מתחממת שוב."},"ICON-2800":{"nm":"תבשיל דובנג'אנג","de":"ממיסים דובנג'אנג ריחני, מוסיפים טופו וקישוא, ומבשלים לאט וקבוע. הקול המבעבע הזה בסיר החרס עד הרגע האחרון ממש הוא הסימן הבטוח ביותר שחזרת הביתה."},"ICON-2801":{"nm":"מרק בקר וצנון","de":"חצי יום שלם המתנת בשקט מול להבה נמוכה, עד שהצנון הפך לשקוף. כשכף מרק צלול נוגעת בשפתיים, עולה בזיכרון שולחן פשוט מאותם ימים, בלי שום קישוט. הדברים הפשוטים ביותר הם אלה שנשארים הכי הרבה זמן."},"ICON-2802":{"nm":"מרק צדפות","de":"ברגע שהצדפה פותחת את פיה, האביב מעמיק בתוך הסיר. כאשר ניחוח ים עולה עם האדים, מצטיירת מטבח שחר בכפר דייגים. בכל צדף פתוח מצטברת מעט מהמלוחות של הים."},"ICON-2803":{"nm":"בטטה מסוכרת","de":"בדרך הביתה מבית הספר, גוש צהוב מוחזק בכוס נייר כמו חממן ידיים. נשיכה בקליפה הזהובה ואדים פורצים מבפנים. הקליפה המתוקה המסוכרת והפְּנים החם - טעמו העדין ביותר של החורף."},"ICON-2804":{"nm":"חצילים מוקפצים","de":"הרגע שבו הסגול פוגש את השמן ומתרכך לאיטו. הירק שגינו על היותו רך מדי, דווקא סופג תיבול טוב מכל האחרים. נשיכה אחת, ומגע היד הרך של הטבחית מגיע אליך ראשון."},"ICON-2805":{"nm":"תפוחי אדמה מבושלים ברוטב סויה","de":"ערב שבו ריח מתוק התפשט בכל המטבח בזמן שרוטב הסויה הצטמצם. היד שמילאה תא בקופסת האוכל בחתיכה חומה ומבריקה אחת. תשומת לב שלא כתובה באף מתכון, ספוגה בכל חתיכה קטנה."},"ICON-2806":{"nm":"עלי פרילה כבושים","de":"המלאכה של כבישת ניחוח הקיץ כולו והבאתו אל שולחן החורף. קלפו עלה אחד והניחו על האורז, והעונה החולפת פורחת מחדש בפה. בין העלים הערוכים שכבה על שכבה, ישנה השמש של אותה שנה."},"ICON-2807":{"nm":"קימצ'י כרוב טרי","de":"ידיים שלא יכלו לחכות לעונת הכבישה הגדולה, לשות אותו באותו יום ממש. הרעננות שאפשר ליהנות ממנה רק ברגע שהתיבול רק החל לחלחל אל העלים הפריכים. הירוקות שלפני התסיסה היא מותרות של היום הזה בלבד."},"ICON-2808":{"nm":"פטריות מוקפצות","de":"דברים שצמחו בשקט בצל היער אחרי שהגשם חלף. בזמן שהן מטוגנות בשמן שומשום פרילה, ריח האדמה הופך לניחוח עשיר. ככל שדבר גדל בשקט רב יותר בחשיכה, כך הניחוח שלו עמוק וסמיך יותר."},"ICON-2809":{"nm":"תרד מתובל","de":"ירק עלים שמצטמצם לחופן קטן כשמרתיחים אותו, מעורבב בעדינות בקצות האצבעות. הנפח הצנוע הזה הוא סגולת ירקות האביב. צלחת ירוקה אחת מכניסה לשולחן עוד טפח של אור שמש אביבי."},"ICON-2810":{"nm":"אצות ים מתובלות","de":"גדילים חלקלקים שזה עתה נדלו מהים, מתמזגים עם רוטב חמצמץ חריף. פרץ מלוח שמתפוצץ בכל לעיסה. צלחת אחת שמעבירה היישר אל הקערה את המרקם הגלי המתנדנד של הים."},"ICON-2811":{"nm":"קישואים מוקפצים","de":"יש ירקות שהמתיקות שלהם עולה ככל שהם מבשילים. פרוסים דק ומוקפצים עם שרימפס מלוח, אפילו הקישוא חסר הטעם חושף בשקט את מתיקותו. צהוב שנמס בעדינות בפה עד הסוף."},"ICON-2812":{"nm":"אורז מוקפץ עם קימצ'י","de":"כשהקימצ'י הישן מעמיק בטעמו, הוא נפגש עם אורז קר במחבת אחת. קערה שנעשית הכי מזינה כשמה שנותר ומה שנותר מתאחדים. הישועה העדינה ביותר תחת אור מאוחר בלילה בחדר שכור."},"ICON-2813":{"nm":"קארי עוף","de":"כשהמרק הצהוב מכסה את האורז הלבן, השולחן מתבהר. בתקופה שבה תבלינים היו זרים, זה היה הטעם הראשון של העולם החיצון שהתקרבנו אליו. יום ראשון בצהריים שבו בשר העוף נמס רך ותפוח."},"ICON-2814":{"nm":"אורז מוקפץ","de":"שאריות שנשארו בקצה המקרר מתמזגות בידידות במחבת אחת. נדיבות שמקבלת הכול בסלחנות. לאסוף את המפוזר למקום אחד - זו ההתחלה של ניהול בית."},"ICON-2815":{"nm":"קערת אורז בולגוגי","de":"בשר שהושרה ברוטב מתוק מחליק בעדינות מעל אורז מהביל. כשכוכב שולחן האורחים מתיישב בקערה יומיומית אחת, המיוחד הופך לעוד יותר רך ומחבק."},"ICON-2816":{"nm":"ביבימבאפ","de":"מעל אורז תפוח, יושבים במעגל חמישה ירקות בצבעים. בקצות האצבעות שמסדרות את הצבעים זורמת אסתטיקה עתיקה של טיפוח קפדני. טעם ההרמוניה, שמושלם רק ברגע שמערבבים הכול יחד."},"ICON-2817":{"nm":"אורז מוקפץ עם שרימפס","de":"שרימפס שמנמנים בולטים בוורוד בין גרגירי האורז. מקפיצים חופן של הים פנימה, וארוחה רגילה מחקה סעודת חג. המתיקות שמתפרצת ברגע שהוא נפצח בין השיניים היא ברוכת הבאים."},"ICON-2818":{"nm":"קערת אורז עם חזיר חריף","de":"בשר חזיר ספוג עמוקות ברוטב חריף נפגש עם אורז מהביל. הקערה שהתרוקנה ראשונה בשעת הצהריים. נחמה של ארוחה אחת שמלטפת ומרגיעה יום עמוס."},"ICON-2819":{"nm":"אורז טונה ומיונז","de":"קופסת שימורים אחת, פס מיונז, וקערת אורז חם. המרכיבים דלים אך הנחמה שופעת. טעמה של אותו לילה, שעורבב בחשאי על שולחן הכיתה אחרי שיעורי הערב."},"ICON-2820":{"nm":"אורז קארי","de":"גוון זהוב סמיך ממלא את הצלחת כולה. תשומת הלב של בחישה ארוכה עד שתפוחי האדמה והגזר מתרככים לגמרי. עולה בזיכרון החום המשפחתי של הערב שבו כל המשפחה הציצה יחד לתוך אותו סיר."},"ICON-2821":{"nm":"ביבימבאפ אצות ים","de":"גדילים בניחוח ים נפגשים עם גוצ'וג'אנג ומתערבבים במעגלים. כשהמרקם החלקלק והחמצמץ עוטף את גרגירי האורז, הים שצוללת עצרה נשימה כדי להעלות נפרש בתוך קערה אחת."},"ICON-2822":{"nm":"מקרל צלוי","de":"גב כסוף מתבשל לזהוב מעל הגריל. היד שהוציאה את העצמות והניחה את הבשר על האורז. בפרוסה אחת של דג גב-כחול ספוגה אהבה שקטה שהאכילה וגידלה."},"ICON-2823":{"nm":"לביבת תפוחי אדמה","de":"בימי גשם, הדבר שנטחן ונטגן במטבח כפרי הררי בגאנגוון. הקצוות הדביקים והקצוות הפריכים חיים זה לצד זה בעוגה אחת. הבצק שמתאים ביותר לצליל הגשם המקיש על החלון."},"ICON-2824":{"nm":"לביבת קימצ'י","de":"ברגע שקימצ'י חמוץ נוגע במחבת משומנת, כל הבית מתמלא בקול פצפוץ. עיגול זהוב שקורא לכוס מקולי מעצמו. תפריט קבוע שמזדווג עם קול הגשם מתחת לגגון."},"ICON-2825":{"nm":"לביבת בצל ירוק","de":"משכיבים את הבצל הירוק בשורה מסודרת, יוצקים את הבצק ומטגנים לאט. עוגה שנעה בין פריכות לרכות. בדיוק כמו אותו נוף חמים של אדים מיתמרים מדוכן ביום שוק."},"ICON-2826":{"nm":"לביבת קישוא","de":"מציפים פרוסות דקות של קישוא בציפוי ומטגנים לזהוב. עיגול ירוק-בהיר ששמר בקפדנות על פינתו בשולחן טקס האבות. הפורמליות המסורה הזו, שמתגבשת רק כשמשקיעים המון עבודת יד."},"ICON-2827":{"nm":"קלמארי מוקפץ חריף","de":"זרועות עטופות ברוטב אדום נוצצות ומבריקות בברק. גם כשטיפות זיעה מצטברות על המצח מהחריפות, המקלות לא מפסיקות. הצלחת האחת שבה זיעה והנאה משתלבות זו בזו."},"ICON-2828":{"nm":"טוקבוקי","de":"עוגיות אורז ועוגות דגים שוקעות עמוק ברוטב גוצ'וג'אנג אדום ומצומצם. אחר צהריים שלם בדוכן חטיפים, שנחלק בין שניים על מטבעות שנאספו, טמון בו כולו. טעם של זיכרון שגורם לרוק לזלוג רק משמיעת השם."},"ICON-2829":{"nm":"מרק עוגות דגים","de":"דוכן רחוב שבו עוגות הדגים מתנדנדות במרק, האדים מערפלים את הזכוכית בלובן. אוחזים בשיפוד אחד, אוספים מעט מרק בכוס נייר ולוגמים, ולילה חורפי צונן נעשה הרבה יותר חם."},"ICON-2830":{"nm":"טופו וקימצ'י","de":"לצד טופו רך יושב קימצ'י מוקפץ חריף, זה לצד זה. קור וחום, עדינות ועוצמה, מתמזגים בצלחת אחת. בן זוג שליווה במשך שנים ארוכות את לילות המבוגרים."},"ICON-2831":{"nm":"נקניקיות וירקות מוקפצים","de":"נקניקיות אדומות וירקות מתערבלים יחד בגוון קטשופ. התא שהתרוקן ראשון כשפתחו את מכסה קופסת האוכל ביום ספורט. הצבע של אותו יום נשאר חי גם כשעובר הזמן."},"ICON-2832":{"nm":"לאטה בטטה","de":"בטטה מרוסקת בעדינות נמסה ברכות בתוך חלב חם. מתיקות מקומית כתובה בקוריאנית על לוח התפריט. ביום שקצות האצבעות קפואות, אוחזים בשתי כפות ידיים והחום מתפשט לאיטו בכוס."},"ICON-2833":{"nm":"מיונז","de":"רוטב שעדיין לא הגיע למטבח של האי הנוצץ. בקרוב הוא יצויר כאייקון בגוון קרם. (בהכנה)"}};